export const recipes=[{"id":1,"servings":4,"tipType":"pasta","pairingsType":"pasta","nutrition":{"cal":784,"prot":33,"carb":76,"fat":38,"fib":3},"origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"意式培根蛋面","en":"Spaghetti Carbonara","ro":"Spaghete Carbonara"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["意大利面400克","猪脸颊肉（关查莱）或意大利培根200克，切1厘米丁","4个大蛋黄 + 1个全蛋","罗马佩科里诺干酪80克，细磨","帕尔玛芝士40克，细磨","现磨黑胡椒1小勺","细海盐（煮面用）"],"en":["400g spaghetti","200g guanciale (or pancetta), cut into 1cm cubes","4 large egg yolks + 1 whole egg","80g Pecorino Romano, finely grated","40g Parmigiano Reggiano, finely grated","1 tsp freshly cracked black pepper","Fine sea salt for pasta water"],"ro":["400g spaghete","200g guanciale (sau pancetta), tăiat cuburi de 1 cm","4 gălbenușuri de ou mari + 1 ou întreg","80g Pecorino Romano, ras fin","40g Parmigiano Reggiano, ras fin","1 linguriță piper negru proaspăt măcinat","Sare de mare fină pentru apa de fiert"]},"howIsMade":{"zh":"将4升水煮沸，加入足量盐直到水尝起来像淡海水一样令人愉悦，然后将意大利面比包装上标注的al dente时间少煮2分钟——面会在酱汁中完成最后的烹饪。与此同时，将关查莱放入冷的宽口锅中，用中小火慢慢煸炒8–10分钟，直到猪油变成金黄色，边缘变得酥脆；从冷锅开始可以防止焦糊并充分释放风味。在关查莱煸炒的同时，将蛋黄和全蛋与两种奶酪和大量粗磨黑胡椒搅打成浓稠、奶油色的糊——这就是酱汁。捞面前，舀出至少250毫升浑浊的面汤备用；溶解的淀粉是实现顺滑乳化的关键。将关查莱锅完全离火——这一步至关重要——把沥干但仍冒热气的意大利面直接倒入锅中，翻拌30秒让每根面条吸收猪油。将蛋液淋在面上，然后每次加入少量面汤，不断翻拌折叠；余热将鸡蛋变成光滑亮泽的酱汁——当酱汁裹住面条而不积在锅底时停止加水。尝盐味——关查莱和佩科里诺本身就咸——若摆盘时酱汁变稠则再加少量面汤。立即盛入温热碗中，撒上额外的佩科里诺擦丝和几大圈现磨黑胡椒享用。","en":"Bring 4 litres of water to a rolling boil, salt it generously until it tastes pleasantly of the sea, then cook the spaghetti for 2 minutes less than the packet's al dente time — it will finish in the sauce. Meanwhile, place the guanciale in a cold, wide pan over medium-low heat and let the fat render slowly for 8–10 minutes until it turns golden and the edges crisp; starting from cold prevents burning and draws out maximum flavour. While the guanciale renders, beat the egg yolks and whole egg with both cheeses and a generous amount of coarsely cracked pepper until you have a thick, pale, creamy paste — this is the sauce. Just before draining, scoop out at least 250 ml of the cloudy pasta water and keep it within reach; the dissolved starch is what makes a smooth emulsion possible. Take the guanciale pan completely off the heat — this step is non-negotiable — then add the drained, steaming spaghetti directly into it and toss for 30 seconds so every strand absorbs the rendered fat. Pour the egg cream over the pasta, then add pasta water a small splash at a time, tossing and folding constantly; the residual heat sets the egg into a smooth, glossy sauce — stop adding water when the sauce coats the pasta without pooling. Taste and adjust salt — the guanciale and Pecorino are already salty — then add a little more pasta water if the sauce tightens as you plate. Serve immediately in warm bowls, finish with an extra shaving of Pecorino and several confident turns of the pepper mill."}},{"id":2,"origin":{"zh":"罗马尼亚","en":"Romania","ro":"România"},"name":{"zh":"牛肚汤","en":"Tripe Soup","ro":"Ciorbă de burtă"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":27,"carb":8,"fat":20,"fib":1},"ingredients":{"zh":["预处理牛肚800克，切成5×1厘米条状","中等胡萝卜2根（约200克）","欧芹根1根","块根芹1块（约150克）","大洋葱1个","大蒜4瓣，捣碎","大鸡蛋蛋黄3个","全脂酸奶油300毫升（含脂量至少20%）","白葡萄酒醋3大勺","盐和白胡椒适量","新鲜欧当归叶（可选）"],"en":["800g pre-cleaned beef tripe, cut into 5×1 cm strips","2 medium carrots (about 200g)","1 parsley root","1 piece celeriac (about 150g)","1 large onion","4 garlic cloves, crushed","3 large eggs, yolks only","300ml full-fat sour cream (min. 20%)","3 tbsp white wine vinegar","salt and white pepper to taste","fresh lovage leaves (optional)"],"ro":["800g burtă de vită (precurățată și fiartă), tăiată fâșii de 5×1 cm","2 morcovi medii (aprox. 200g)","1 rădăcină de pătrunjel","1 bucată țelină rădăcină (aprox. 150g)","1 ceapă mare","4 căței de usturoi, pisați","3 ouă mari, gălbenușurile separate","300ml smântână grasă (min. 20%)","3 linguri oțet de vin alb","sare și piper alb după gust","frunze de leuștean proaspăt (opțional)"]},"howIsMade":{"zh":"如果牛肚未预处理，先用粗盐在冷水下反复揉搓3–4次。在盐水中小火炖牛肚2–3小时至可以用叉子轻松穿透（高压锅40–50分钟）。捞出切成5×1厘米条。将胡萝卜、欧芹根、块根芹和洋葱在2升盐水中煮40分钟，捞出蔬菜。将牛肚条放入汤中再炖15分钟。将蛋黄和酸奶油搅拌均匀。回火处理：用汤勺将几勺热汤慢慢加入酸奶油混合物中边加边搅，然后倒回锅中——防止结块。加入捣碎的蒜、醋、盐和白胡椒。加入后不可再煮沸。趁热上桌。","en":"If tripe is not pre-cleaned, rub thoroughly with coarse salt under cold running water and rinse 3–4 times. Boil tripe in salted water for 2–3 hours on low heat until easily pierced with a fork — or 40–50 minutes in a pressure cooker. Drain and cut into 5×1 cm strips. Simmer carrots, parsley root, celeriac, and onion in 2L salted water for 40 minutes, then discard the vegetables (or blend and return for a thicker soup). Add the tripe strips to the broth and simmer 15 minutes. Whisk egg yolks with sour cream until smooth. Temper the mixture: ladle several spoonfuls of hot broth into the cream gradually, whisking constantly before pouring it back into the pot — this prevents curdling. Stir in crushed garlic, vinegar, salt, and white pepper. Do not boil again after adding the liaison — it will curdle. Serve piping hot with chilli and garlic sauce on the side."}},{"id":3,"servings":6,"tipType":"def","pairingsType":"def","nutrition":{"cal":770,"prot":21,"carb":27,"fat":62,"fib":1},"origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"洛林咸派","en":"Quiche Lorraine","ro":"Quiche Lorraine"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"zh":["酥皮面团200克（1张），先行空烤","烟熏培根丁或烟熏五花肉丁200克","大鸡蛋3个","双倍奶油300毫升（含脂量至少35%）","格鲁耶尔奶酪60克，细磨","现磨肉豆蔻1/4茶匙","盐和白胡椒适量","黄油用于涂模具"],"en":["200g shortcrust pastry (1 sheet), blind-baked","200g smoked lardons or diced smoked bacon","3 large eggs","300ml double cream (min. 35% fat)","60g Gruyère cheese, finely grated","1/4 tsp freshly grated nutmeg","salt and white pepper to taste","butter for greasing"],"ro":["200g aluat scurt (1 foaie), copt în alb","200g lardon afumat sau bacon afumat, tocat cuburi","3 ouă mari","300ml smântână grasă (min. 35%)","60g Gruyère, ras fin","1/4 linguriță nucșoară rasă proaspăt","sare și piper alb după gust","unt pentru uns forma"]},"howIsMade":{"zh":"将面团擀开铺入23厘米挞模，边缘用力按压贴合。冷藏20分钟。空烤：铺烘焙纸、填入压烤石，180°C烤15分钟；去掉石子和纸，再烤5分钟至淡金色。同时，将培根丁放干锅中煎至金黄、油脂逸出，约5分钟；沥油。将鸡蛋、双倍奶油、肉豆蔻、盐和白胡椒搅打均匀。将培根丁均匀铺在挞底，倒入蛋液，撒上格鲁耶尔奶酪。180°C烤25–30分钟至刚刚凝固——轻摇模具时，中心仍应微微颤动。冷却10分钟后切片。正宗Quiche Lorraine不含洋葱或蔬菜，只有培根和经典蛋奶液。","en":"Roll out the pastry and line a 23cm tart tin, pressing firmly into the edges. Chill 20 minutes. Blind-bake at 180°C: line with baking paper, fill with baking beans, bake 15 minutes; remove beans and paper and bake a further 5 minutes until pale golden. Meanwhile, cook the lardons in a dry pan until golden and the fat is rendered, about 5 minutes; drain on paper. Whisk together eggs, cream, nutmeg, salt and white pepper. Scatter the lardons evenly over the base, pour the egg mixture over, and sprinkle with Gruyère. Bake 25–30 minutes at 180°C until just set — the centre should tremble slightly when you shake the tin. Cool 10 minutes before slicing. A true Quiche Lorraine contains no onion or vegetables, only lardons and the classic custard."}},{"id":4,"origin":{"zh":"西班牙","en":"Spain","ro":"Spania"},"name":{"zh":"西班牙冷汤","en":"Gazpacho","ro":"Gazpacho"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":260,"prot":4,"carb":24,"fat":16,"fib":3},"ingredients":{"zh":["熟透番茄（圣马扎诺或李形）800克，粗切","红椒1个（约200克），去籽切块","中等黄瓜1根（约200克），去皮切块","大蒜2瓣","隔夜白面包（去边）100克","特级初榨橄榄油60毫升","红葡萄酒醋2大勺","细盐1小勺","冷水200毫升"],"en":["800g ripe tomatoes (San Marzano or plum), roughly chopped","1 red bell pepper (about 200g), deseeded and chopped","1 medium cucumber (about 200g), peeled and chopped","2 garlic cloves","100g day-old white bread, crusts removed","60ml extra-virgin olive oil","2 tbsp red wine vinegar","1 tsp fine salt","200ml cold water"],"ro":["800g roșii coapte (San Marzano sau roșii de câmp), tăiate cuburi","1 ardei gras roșu (aprox. 200g), curățat de semințe și tocat","1 castravete mediu (aprox. 200g), curățat și tocat","2 căței de usturoi","100g pâine albă veche de o zi, fără coajă","60ml ulei de măsline extravirgin","2 linguri oțet de vin roșu","1 linguriță sare fină","200ml apă rece"]},"howIsMade":{"zh":"将面包撕碎，在200ml冷水中浸泡10分钟。将番茄、辣椒、黄瓜、大蒜放入搅拌机高速打1分钟。加入浸泡的面包及面包水、醋和盐，再次搅打。搅拌机运转时细细淋入橄榄油——乳化使汤口感丝滑。调整盐和醋的量。可过细筛获得更细腻质地，或保留粗糙口感。至少冷藏2小时——6–8°C的冷汤风味远胜室温。盛入冷藏的碗中，表面淋一线橄榄油上桌。","en":"Tear the bread into pieces and soak in 200ml cold water for 10 minutes. Put tomatoes, pepper, cucumber, and garlic into a blender and blitz for 1 minute on high. Add the soaked bread along with its soaking water, vinegar, and salt; blitz again. With the motor running, pour olive oil in a thin stream — this emulsification gives the soup its silky texture. Taste and adjust salt and vinegar. Pass through a fine-mesh sieve for a smoother result, or leave it rustic. Chill at least 2 hours — gazpacho at 6–8°C is vastly more flavourful than at room temperature. Serve in chilled bowls with a drizzle of olive oil on top."}},{"id":5,"origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"寿司","en":"Sushi","ro":"Sushi"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":430,"prot":15,"carb":51,"fat":14,"fib":3},"ingredients":{"zh":["日本短粒寿司米2杯","水2½杯","米醋60毫升","糖1大勺","盐1小勺","海苔4张（20×18厘米）","刺身级三文鱼片200克，切薄片","成熟牛油果1个，切片","小黄瓜半根，切细丝","酱油用于蘸食","山葵酱和腌姜（甘利）用于搭配"],"en":["2 cups Japanese short-grain sushi rice","2½ cups water","60ml rice vinegar","1 tbsp sugar","1 tsp salt","4 nori sheets (20×18 cm)","200g sashimi-grade salmon fillet, thinly sliced","1 ripe avocado, sliced","½ small cucumber, julienned","soy sauce to serve","wasabi and pickled ginger (gari) to serve"],"ro":["2 căni orez japonez pentru sushi (bob scurt)","2½ căni apă","60ml oțet de orez","1 lingură zahăr","1 linguriță sare","4 foi nori (20×18 cm)","200g file de somon sashimi-grade, feliat subțire","1 avocado copt, feliat","½ castravete mic, julienizat","sos de soia pentru servire","wasabi și ghimbir murat (gari) pentru servire"]},"howIsMade":{"zh":"煮饭：在冷水下冲洗4–5次至水清澈。米和2½杯水大火烧开，盖锅转最小火12分钟，离火焖10分钟。在小碗中溶化米醋、糖和盐。将米饭铺在大盘上，用木铲以切拌动作拌入调味料——不要画圈搅拌否则米饭变糊。盖上湿布，冷却至室温（不要放冰箱）。将海苔光面朝下铺在竹帘上。将调味饭均匀铺在海苔的¾处（远端留3厘米）。靠近端摆一排三文鱼、牛油果和黄瓜丝。提起竹帘从近端卷紧，用几粒米封口。用蘸湿的快刀切成8片。配酱油、山葵和腌姜上桌。","en":"Cook the rice: rinse under cold water until the water runs clear (4–5 washes). Bring rice and 2½ cups water to a boil, cover, reduce to lowest heat for 12 minutes, then rest off heat 10 minutes. Dissolve vinegar, sugar, and salt in a small bowl. Spread cooked rice onto a large tray and fold the dressing in using a wooden paddle with cutting motions — do not stir in circles or the rice turns mushy. Cover with a damp cloth and cool to room temperature (not fridge). Lay a nori sheet shiny-side down on the bamboo mat. Spread seasoned rice over ¾ of the nori (leaving a 3 cm gap at the far edge). Arrange salmon, avocado, and cucumber along the near edge in a single row. Roll firmly from the near edge, pressing as you go; seal the bare nori with a few rice grains. Slice with a sharp, lightly wet knife into 8 rounds. Serve at once with soy sauce, wasabi, and pickled ginger."}},{"id":7,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":775,"prot":40,"carb":39,"fat":49,"fib":1},"origin":{"zh":"美国","en":"USA","ro":"SUA"},"name":{"zh":"芝士汉堡","en":"Cheeseburger","ro":"Cheeseburger"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["500克碎牛肉（八成瘦二成肥）","4个布里欧修汉堡胚，切半烤香","4片美式切达奶酪","2个熟番茄，切厚片","4片冰山生菜叶","1个中等洋葱，切薄圆圈","2汤匙汉堡酱（蛋黄酱、番茄酱、芥末酱、切碎泡菜）","盐和现磨黑胡椒"],"en":["500g ground beef (80% lean, 20% fat)","4 brioche buns, halved and toasted","4 slices American cheddar","2 ripe tomatoes, thickly sliced","4 large iceberg lettuce leaves","1 medium onion, thinly sliced into rings","2 tbsp burger sauce (mayo, ketchup, mustard, diced pickles)","salt and freshly ground black pepper"],"ro":["500g carne de vită tocată (80% carne / 20% grăsime)","4 chifle brioche, tăiate și prăjite","4 felii cheddar american","2 roșii coapte, tăiate felii groase","4 frunze de salată iceberg","1 ceapă medie, tăiată rondele subțiri","2 linguri sos de burger (maioneză, ketchup, muștar, castraveți murați tocați)","sare și piper negru proaspăt măcinat"]},"howIsMade":{"zh":"将牛肉馅用盐和黑胡椒调味，分成四个125克的肉球。将铸铁平底锅用大火烧至冒烟。用硬铲将每个肉球直接按压在锅中——smash技术能在90秒内形成酥脆焦壳。翻面，放上一片切达奶酪，盖锅30秒融化。将面包切面朝下煎烤1分钟。组装：底部面包、汉堡酱、生菜、番茄、带融化奶酪的肉饼、洋葱圈、顶部面包。立刻上桌。","en":"Season the ground beef with salt and pepper and divide into four 125g balls. Heat a cast-iron skillet over high heat until smoking. Press each ball flat on the pan with a firm spatula — the smash technique creates a crisp, lacy crust in about 90 seconds. Flip, add a slice of cheddar, and cover for 30 seconds to melt. Toast the buns cut-side down for 1 minute. Assemble: bottom bun, burger sauce, lettuce, tomato, patty with melted cheese, onion rings, top bun. Serve immediately — the crust fades fast."}},{"id":8,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":390,"prot":26,"carb":32,"fat":18,"fib":4},"origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"玉米卷","en":"Tacos","ro":"Tacos"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["猪牛混合碎肉500克（八成瘦）","小玉米饼8张（15厘米）","孜然粉1茶匙","烟熏辣椒粉1茶匙","熟番茄2个，细切丁（用于莎莎酱）","小白洋葱1个，细切丁","新鲜香菜、青柠角、莎莎酱和酸奶油用于上桌","盐和黑胡椒"],"en":["500g ground beef (80% lean)","8 small corn tortillas (15cm)","1 tsp ground cumin","1 tsp smoked paprika","2 ripe tomatoes, finely diced (for pico de gallo)","1 small white onion, finely diced","fresh cilantro, lime wedges, salsa, and sour cream for serving","salt and black pepper"],"ro":["500g carne de vită tocată (80% carne)","8 tortilla mici din porumb (15cm)","1 linguriță chimion măcinat","1 linguriță boia afumată","2 roșii coapte, tocate mărunt (pico de gallo)","1 ceapă albă mică, tocată mărunt","coriandru proaspăt, felii de lime, sos salsa și smântână pentru servit","sare și piper negru"]},"howIsMade":{"zh":"在干锅中大火将碎牛肉炒至焦香，边炒边将肉打散——不要一开始就频繁翻动，让肉接触锅底产生焦色。倒掉多余油脂。加入孜然粉、烟熏辣椒粉、盐和黑胡椒，再炒2分钟。加热玉米饼：直接放在燃气灶火焰上每面烤15秒至出现气泡微焦，或在热平锅上干烤。快速莎莎：将切丁番茄与切丁洋葱、少许盐、青柠汁拌匀。每个塔可叠两张玉米饼防裂。盛上调味碎牛肉，放上莎莎、香菜叶、挤上青柠汁，再配莎莎酱或酸奶油。","en":"Brown the ground beef in a dry skillet over high heat, breaking it into fine crumbles — do not stir too much at first so the meat develops colour. Drain excess fat. Add cumin, paprika, salt and pepper; cook 2 more minutes. Warm the corn tortillas: hold them directly over a gas flame for 15 seconds per side until they blister and char lightly, or dry-toast in a hot pan. For quick pico de gallo: toss diced tomato with diced onion, a pinch of salt, and a squeeze of lime. Double-stack two tortillas per taco to prevent splitting. Spoon on the seasoned beef, then top with pico de gallo, cilantro leaves, a squeeze of lime, and salsa or sour cream to taste."}},{"id":9,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":375,"prot":23,"carb":11,"fat":19,"fib":3},"origin":{"zh":"印度","en":"India","ro":"India"},"name":{"zh":"鸡肉咖喱","en":"Chicken Curry","ro":"Curry de pui"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["带骨鸡大腿和鸡腿800克，去皮","大洋葱2个（约350克），细丁","罐装碎番茄400克","姜蓉1大勺（3厘米姜块磨成）","蒜蓉1大勺（5瓣大蒜磨成）","葵花油3大勺","孜然籽1小勺","香菜粉2小勺","印度综合香料（garam masala）1小勺","姜黄粉½小勺","克什米尔辣椒粉1小勺（或甜椒粉）","全脂酸奶200毫升，搅匀","盐适量","新鲜香菜叶（装饰）"],"en":["800g bone-in chicken thighs and drumsticks, skin removed","2 large onions (about 350g), finely diced","400g canned crushed tomatoes","1 tbsp ginger paste (from a 3cm piece)","1 tbsp garlic paste (from 5 cloves)","3 tbsp sunflower oil","1 tsp cumin seeds","2 tsp ground coriander","1 tsp garam masala","½ tsp turmeric","1 tsp Kashmiri chili powder (or mild paprika)","200ml full-fat yogurt, whisked","Salt to taste","Fresh coriander leaves to finish"],"ro":["800g pulpe de pui cu os, fără piele","2 cepe mari (aprox. 350g), tăiate mărunt","400g roșii tocate din conservă","1 lingură pastă de ghimbir (bucată de 3 cm)","1 lingură pastă de usturoi (5 căței)","3 linguri ulei de floarea-soarelui","1 linguriță semințe de chimen","2 lingurițe coriandru măcinat","1 linguriță garam masala","½ linguriță turmeric","1 linguriță praf de ardei Kashmiri (sau boia dulce)","200ml iaurt gras, bătut","Sare după gust","Frunze de coriandru proaspăt pentru finisare"]},"howIsMade":{"zh":"厚底锅中用中大火加热油，放入孜然籽爆香30秒。加入洋葱丁频繁翻炒15–18分钟，炒至深金黄色——焦化的洋葱是风味基础。放入姜蓉和蒜蓉，翻炒2分钟至生味消失。加入香菜粉、姜黄粉和辣椒粉，翻炒1分钟。倒入番茄，中火边搅边煮10分钟，直至油脂从玛莎拉两侧析出。放入鸡块裹匀玛莎拉，煎5分钟。离火，将打匀的酸奶每次加一大勺慢慢搅入（防止凝固）。转中小火盖锅焖煮25–30分钟，直至鸡肉轻松脱骨。加入印度综合香料，调盐，撒新鲜香菜。搭配香米饭或烤馕享用。","en":"Heat oil in a heavy-bottomed pot over medium-high heat. Add cumin seeds and let sizzle 30 seconds. Add diced onions and fry, stirring often, for 15–18 minutes until deep golden — this caramelisation builds the flavour base. Stir in ginger and garlic paste; cook 2 minutes until the raw smell disappears. Add ground coriander, turmeric, and Kashmiri chili; stir 1 minute. Pour in crushed tomatoes and cook over medium heat, stirring often, for 10 minutes until the oil separates to the sides. Add chicken pieces, coat in masala, and sear 5 minutes. Remove from heat; stir in whisked yogurt one tablespoon at a time to prevent curdling. Return to medium-low heat, cover, and simmer 25–30 minutes until the chicken falls easily from the bone. Stir in garam masala, adjust salt, finish with fresh coriander. Serve with basmati rice or naan."}},{"id":10,"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":215,"prot":4,"carb":19,"fat":13,"fib":4},"origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"普罗旺斯杂烩","en":"Ratatouille","ro":"Ratatouille"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["1个中等茄子（约300克），切成2厘米方块","2根中等西葫芦（约400克），切成2厘米圆片","1个红灯笼椒，去籽切丁","1个黄灯笼椒，去籽切丁","4个熟李子番茄（约400克），粗略切碎","1个大洋葱，切丁","4瓣大蒜，切薄片","4汤匙特级初榨橄榄油","1茶匙干普罗旺斯香草","盐和黑胡椒适量"],"en":["1 medium aubergine (about 300g), cut into 2cm cubes","2 medium courgettes (about 400g), cut into 2cm rounds","1 red bell pepper, deseeded and diced","1 yellow bell pepper, deseeded and diced","4 ripe plum tomatoes (about 400g), roughly chopped","1 large onion, diced","4 garlic cloves, thinly sliced","4 tbsp extra-virgin olive oil","1 tsp dried herbes de Provence","salt and black pepper to taste"],"ro":["1 vânătă medie (aprox. 300g), cuburi de 2cm","2 dovlecei medii (aprox. 400g), rondele de 2cm","1 ardei gras roșu, curățat și tocat","1 ardei gras galben, curățat și tocat","4 roșii prune coapte (aprox. 400g), tocate grosier","1 ceapă mare, tocată","4 căței de usturoi, feliați subțire","4 linguri ulei de măsline extravirgin","1 linguriță herbes de Provence uscate","sare și piper negru după gust"]},"howIsMade":{"zh":"轻撒盐在茄子块上，静置15分钟逼出苦水，然后用厨房纸吸干。在宽口锅中用中大火热1汤匙橄榄油。将茄子炒至微微金黄，约5分钟；取出备用。同法翻炒西葫芦3分钟，再炒甜椒4分钟；分别取出备用。锅中加入剩余橄榄油，将洋葱炒软透明约5分钟。加蒜瓣炒1分钟。加入番茄和香草；煮10分钟直至番茄化为酱汁。将所有蔬菜倒回锅中，轻轻翻拌，调味后不盖锅盖小火煮15–20分钟至所有蔬菜软嫩飘香。温热或室温享用皆可——隔夜更美味。","en":"Lightly salt the aubergine cubes and set aside for 15 minutes to draw out bitterness, then pat dry. Heat 1 tbsp oil in a wide pan over medium-high heat. Saute the aubergine until lightly golden, about 5 minutes; remove and set aside. Saute the courgettes 3 minutes, then the peppers 4 minutes; remove each in turn. In the same pan, heat the remaining oil and sweat the onion until soft and translucent, 5 minutes. Add garlic and cook 1 minute. Add the tomatoes and herbes de Provence; cook 10 minutes until the tomatoes collapse into a sauce. Return all vegetables, stir gently, season with salt and pepper, and simmer uncovered 15–20 minutes until everything is tender and fragrant. Serve warm or at room temperature — ratatouille tastes even better the next day."}},{"id":11,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"希腊烤肉串","en":"Souvlaki","ro":"Souvlaki"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["700克猪肩肉，切成3厘米方块","3汤匙特级初榨橄榄油","1个柠檬的汁","3瓣大蒜，压碎","2茶匙干希腊牛至","1茶匙干百里香","盐和现磨黑胡椒","木签或金属签"],"en":["700g pork shoulder, cut into 3cm cubes","3 tbsp extra-virgin olive oil","juice of 1 lemon","3 garlic cloves, crushed","2 tsp dried Greek oregano","1 tsp dried thyme","salt and freshly ground black pepper","wooden or metal skewers"],"ro":["700g ceafă de porc, tăiată cuburi de 3 cm","3 linguri ulei de măsline extravirgin","sucul de la 1 lămâie","3 căței de usturoi, zdrobiți","2 linguriță oregano grecesc uscat","1 linguriță cimbru uscat","sare și piper negru proaspăt măcinat","frigărui de lemn sau metal"]},"howIsMade":{"zh":"将橄榄油、柠檬汁、压碎的大蒜、牛至和百里香混合在碗中。加入猪肉块，充分搅拌，加盖冷藏至少1小时，最好隔夜腌制。如果使用木签，提前30分钟用水浸泡。每根签穿5-6块肉，留出小间隙。大火烤（木炭最佳）8-10分钟，每2分钟翻一次，直到外表焦香，肉汁清澈。立即在温热的皮塔饼中配上沙兹奇、番茄和红洋葱一起上桌。","en":"Combine olive oil, lemon juice, crushed garlic, oregano and thyme in a bowl. Add the pork cubes, toss to coat thoroughly, cover and refrigerate for at least 1 hour — overnight is better. If using wooden skewers, soak them in water for 30 minutes. Thread 5-6 cubes per skewer, leaving small gaps between pieces. Grill over high heat (charcoal is ideal) for 8-10 minutes total, turning every 2 minutes, until the outside is charred and the juices run clear. The meat should be firm but not dry — pull it at 70°C internal. Serve immediately in warm pita with tzatziki, sliced tomatoes and red onion."},"nutrition":{"cal":420,"prot":35,"carb":3,"fat":29,"fib":0}},{"id":12,"origin":{"zh":"印度","en":"India","ro":"India"},"name":{"zh":"印度扁豆汤","en":"Dhal","ro":"Dhal"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"veg","ingredients":{"zh":["红扁豆（masoor dal）300克","酥油（或植物油）2大勺","大洋葱1个，切碎","大蒜4瓣，切末","新鲜生姜2厘米，磨碎","罐头碎番茄400克（或新鲜大番茄3个）","姜黄粉1小勺","孜然粉1小勺","香菜粉1小勺","马萨拉综合香料½小勺","红辣椒粉½小勺","椰浆400毫升（或水）","盐适量","新鲜香菜和柠檬角上桌用"],"en":["300g dried red lentils (masoor dal)","2 tbsp ghee (or vegetable oil)","1 large onion, finely chopped","4 garlic cloves, minced","2 cm fresh ginger, grated","400g canned chopped tomatoes (or 3 large fresh tomatoes)","1 tsp ground turmeric","1 tsp ground cumin","1 tsp ground coriander","½ tsp garam masala","½ tsp ground red chilli","400ml coconut milk (or water)","salt to taste","fresh coriander and lemon wedges to serve"],"ro":["300g linte roșie uscată (masoor dal)","2 linguri ghee (sau ulei vegetal)","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","2 cm ghimbir proaspăt, ras","400g roșii din conservă, tăiate cuburi (sau 3 roșii mari proaspete)","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","1 linguriță coriandru măcinat","½ linguriță garam masala","½ linguriță ardei iute roșu măcinat","400ml lapte de nucă de cocos (sau apă)","sare după gust","coriandru proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"zh":"将红扁豆在冷水下冲洗3–4次至水清澈。大锅中火融化酥油。加入洋葱频繁翻炒10–12分钟至金黄软化——这步不能省，焦糖洋葱是风味底座。加大蒜和生姜炒1分钟。加姜黄、孜然、香菜粉和辣椒粉，翻炒30秒至香气溢出。加番茄煮3–4分钟至略稠。加入沥水红扁豆和椰浆（或水），小火不盖锅炖20–25分钟，偶尔搅拌，直到扁豆完全软化、汤汁浓稠如奶油。加入马萨拉综合香料调味，调整盐量。配米饭或馕饼，撒香菜末、挤柠檬汁上桌。","en":"Rinse the red lentils under cold water 3–4 times until the water runs clear. In a large pan melt ghee over medium heat. Add the onion and cook, stirring often, for 10–12 minutes until golden and soft — do not skip this step, the caramelised base is the backbone of flavour. Add garlic and ginger, fry 1 minute. Add turmeric, cumin, coriander, and red chilli, stir 30 seconds until fragrant. Add tomatoes, simmer 3–4 minutes until slightly thickened. Add the rinsed lentils and coconut milk (or water), reduce to a gentle simmer and cook uncovered for 20–25 minutes, stirring occasionally, until lentils collapse and the dhal is thick and creamy. Stir in garam masala and adjust salt. Thin with a little hot water if needed. Serve with rice or naan, topped with fresh coriander and a squeeze of lemon."},"nutrition":{"cal":490,"prot":21,"carb":56,"fat":19,"fib":13}},{"id":13,"timeMins":{"total":20,"active":20},"servings":4,"tipType":"def","pairingsType":"veg","origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"鳄梨酱","en":"Guacamole","ro":"Guacamole"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["3个熟哈斯鳄梨","2个青柠的汁（约3汤匙）","1个小红洋葱，细细切丁","2个熟罗马番茄，去籽切丁","1个小墨西哥辣椒，细细切碎（去籽降辣）","15克新鲜香菜，粗略切碎","半茶匙细海盐，可按口味增加"],"en":["3 ripe Hass avocados","juice of 2 limes (about 3 tbsp)","1 small red onion, finely diced","2 ripe Roma tomatoes, deseeded and diced","1 small jalapeño, finely chopped (seeds removed for mild heat)","15g fresh cilantro, roughly chopped","1/2 tsp fine sea salt, plus more to taste"],"ro":["3 avocado Hass coapte","sucul a 2 lime (aprox. 3 linguri)","1 ceapă roșie mică, tocată mărunt","2 roșii Roma coapte, curățate de semințe și tocate","1 ardei jalapeno mic, tocat fin (fără semințe pentru mai puțin iute)","15g coriandru proaspăt, tocat grosier","1/2 linguriță sare fină de mare"]},"howIsMade":{"zh":"将鳄梨纵向对半切开，去核，用勺子挖出果肉放入碗中。立即加入青柠汁——酸性防止氧化变棕。用叉子按喜好捣压：可以留有颗粒感，也可以捣至顺滑。拌入切丁洋葱、番茄、墨西哥辣椒和香菜。用盐调味。品尝后按口味调整青柠汁和盐。保存时将保鲜膜直接贴在表面压紧以隔绝空气——青柠汁比果核更能防止变色。在2小时内食用口感和颜色最佳。","en":"Halve and stone the avocados. Scoop the flesh into a bowl and add the lime juice immediately — the acid slows browning. Mash with a fork to your preferred texture: very chunky or almost smooth. Fold in the diced onion, tomato, jalapeño, and cilantro. Season with salt. Taste and adjust lime and salt. To store, press cling film directly onto the surface of the guacamole to exclude air — the lime juice prevents browning far better than the avocado stone. Serve within 2 hours for best colour and flavour."},"nutrition":{"cal":200,"prot":3,"carb":13,"fat":17,"fib":9}},{"id":14,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"zh":"俄罗斯","en":"Russia","ro":"Rusia"},"name":{"zh":"罗宋汤","en":"Borscht","ro":"Bors"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["生甜菜根500克，去皮粗磨","白卷心菜300克，细切丝","腊质土豆300克，切2厘米丁","中等胡萝卜2根，切丝","大洋葱1个，切丁","大蒜3瓣，切末","番茄酱2大勺","牛肉或蔬菜高汤1.5升","葵花油2大勺","苹果醋1大勺（固定深红色）","盐和黑胡椒适量","酸奶油和新鲜莳萝（上桌用）"],"en":["500g raw beetroot, peeled and coarsely grated","300g white cabbage, thinly shredded","300g waxy potatoes, cut into 2cm cubes","2 medium carrots, julienned","1 large onion, diced","3 garlic cloves, minced","2 tbsp tomato paste","1.5 litres beef or vegetable broth","2 tbsp sunflower oil","1 tbsp apple cider vinegar (to fix the deep red colour)","Salt and black pepper to taste","Sour cream and fresh dill to serve"],"ro":["500g sfeclă roșie crudă, curățată și rasă grosier","300g varză albă, feliată subțire","300g cartofi waxy, cuburi de 2 cm","2 morcovi medii, julien","1 ceapă mare, tocată","3 căței de usturoi, tocați","2 linguri pastă de roșii","1,5 litri supă de vită sau legume","2 linguri ulei de floarea-soarelui","1 lingură oțet de mere (pentru culoare vie)","Sare și piper după gust","Smântână și mărar proaspăt pentru servire"]},"howIsMade":{"zh":"中火热油，加入洋葱和胡萝卜翻炒7–8分钟至软化。加入番茄酱和蒜末，翻炒2分钟。加入磨好的甜菜根和苹果醋，煮5分钟——醋能固定深红色。倒入热高汤，加入土豆丁。大火烧开后转小火焖煮15分钟。加入卷心菜再煮10分钟，直至菜叶嫩软但不烂糊。调盐和胡椒，视情况加醋提酸。盛入深碗，舀一大勺酸奶油，撒上新鲜莳萝享用。","en":"Heat oil over medium heat, add onion and carrots, and sauté 7–8 minutes until softened. Stir in tomato paste and garlic; cook 2 minutes. Add the grated beetroot and apple cider vinegar; cook 5 minutes — the vinegar fixes the deep red colour. Pour in the hot broth and add potatoes. Bring to a boil, reduce heat and simmer 15 minutes. Add shredded cabbage and simmer another 10 minutes until the cabbage is just tender and the potatoes are soft but not falling apart. Taste for salt, add pepper and extra vinegar if the soup needs brightness. Ladle into deep bowls and top with a generous spoonful of sour cream and fresh chopped dill."},"nutrition":{"cal":260,"prot":5,"carb":28,"fat":9,"fib":7}},{"id":15,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"zh":"美国","en":"USA","ro":"SUA"},"name":{"zh":"美式煎饼","en":"Pancakes","ro":"Clătite americane"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"zh":["200克中筋面粉","2茶匙泡打粉","1汤匙糖","1/2茶匙盐","240毫升全脂牛奶","2个大鸡蛋","30克融化的黄油，另备少许用于煎锅","1茶匙香草精"],"en":["200g plain flour","2 tsp baking powder","1 tbsp sugar","1/2 tsp salt","240ml whole milk","2 large eggs","30g melted butter, plus extra for the pan","1 tsp vanilla extract"],"ro":["200g făină albă","2 linguriță praf de copt","1 lingură zahăr","1/2 linguriță sare","240ml lapte integral","2 ouă mari","30g unt topit, plus extra pentru tigaie","1 linguriță extract de vanilie"]},"howIsMade":{"zh":"在大碗中将面粉、泡打粉、糖和盐混合。在另一个碗中，打散牛奶、鸡蛋、融化的黄油和香草精。将液体倒入干料中，用刮刀轻轻翻拌——有几个面粉块是正常且理想的；过度搅拌会激活面筋，使煎饼变韧。面糊静置5分钟。将不粘锅以中火加热，加少量黄油并用纸巾擦去多余的。每次倒约80毫升面糊。煎2-3分钟直至表面出现气泡、边缘看起来干燥定型。翻面再煎1-2分钟直至底部金黄。立即搭配真正的枫糖浆、黄油和新鲜水果上桌。","en":"In a large bowl, whisk together flour, baking powder, sugar and salt. In a second bowl, whisk milk, eggs, melted butter and vanilla. Pour the wet ingredients into the dry and fold gently with a spatula — a few lumps are fine and even desirable; over-mixing develops gluten and makes the pancakes tough. Rest the batter 5 minutes: the baking powder bubbles will rise to the surface. Heat a non-stick pan over medium heat, add a small knob of butter and wipe away the excess. Pour one ladle (about 80ml) of batter per pancake. Cook 2-3 minutes until bubbles break on the surface and the edges look set and dry. Flip and cook 1-2 minutes more until golden on the underside. Serve immediately — pancakes deflate as they cool. Top with real maple syrup, fresh butter and seasonal fruit."},"nutrition":{"cal":340,"prot":10,"carb":45,"fat":13,"fib":1}},{"id":16,"servings":4,"tipType":"def","pairingsType":"fish","origin":{"zh":"泰国","en":"Thailand","ro":"Thailanda"},"name":{"zh":"泰式炒河粉","en":"Pad Thai","ro":"Pad Thai"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["扁米粉200克（泡发30分钟）","生中虾200克，剥壳去虾线","鸡蛋2个","罗望子酱2大勺","鱼露2大勺","蚝油1大勺","棕榈糖或红糖1小勺","淡味油2大勺","蒜末2瓣","红葱头1个，切薄片","豆芽100克","葱3根，切3厘米段","烤花生3大勺，粗碎","青柠1个，切瓣","干辣椒碎适量"],"en":["200g dried flat rice noodles (soaked 30 min)","200g raw medium prawns, peeled and deveined","2 eggs","2 tbsp tamarind paste","2 tbsp fish sauce","1 tbsp oyster sauce","1 tsp palm sugar or brown sugar","2 tbsp neutral oil","2 cloves garlic, minced","1 shallot, thinly sliced","100g bean sprouts","3 spring onions, cut into 3cm pieces","3 tbsp roasted peanuts, roughly crushed","1 lime, cut into wedges","Dried chili flakes to serve"],"ro":["200g tăiței lat de orez (înmuiați 30 min)","200g creveți cruzi, curățați","2 ouă","2 linguri pastă de tamarind","2 linguri sos de pește","1 lingură sos de stridii","1 linguriță zahăr de palmier","2 linguri ulei neutru","2 căței de usturoi, tocați","1 șalotă, feliată","100g germeni de fasole","3 cepe verzi, tăiate 3cm","3 linguri alune prăjite, zdrobite","1 lime, pentru servire","Fulgi de ardei iute, după gust"]},"howIsMade":{"zh":"米粉在冷水中泡30分钟后沥干。将罗望子酱、鱼露、蚝油和糖在小碗里混合成酱汁。中式炒锅大火烧至轻微冒烟，加油，下蒜末和红葱头炒30秒，放入虾仁炒2分钟至变红。将食材拨到一边，打入鸡蛋迅速炒散30秒，然后与虾仁混合。加入沥干的米粉，淋上酱汁，不断翻炒2–3分钟至米粉充分吸收酱汁并边缘微焦。离火，拌入豆芽和葱段；立即盛出，撒花生碎，配青柠角和干辣椒碎即可。","en":"Soak rice noodles in cold water for 30 minutes, then drain. Mix tamarind paste, fish sauce, oyster sauce and sugar in a small bowl to make the sauce. Heat oil in a wok over very high heat until just smoking; fry garlic and shallot for 30 seconds, add prawns and cook 2 minutes until just pink. Push everything to the side, crack in eggs and scramble lightly for 30 seconds, then toss everything together. Add drained noodles and pour the sauce over; toss constantly for 2–3 minutes until the noodles absorb the sauce and begin to caramelise at the edges. Remove from heat, fold in bean sprouts and spring onions; serve immediately topped with crushed peanuts, a lime wedge and chili flakes to taste."},"nutrition":{"cal":380,"prot":18,"carb":40,"fat":13,"fib":2}},{"id":17,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"德国","en":"Germany","ro":"Germania"},"name":{"zh":"炸肉排","en":"Schnitzel","ro":"Schnitzel"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["4块去骨猪里脊肉（每块约150克），去除多余脂肪","80克普通面粉，用盐和胡椒调味","2个大鸡蛋，打散","150克细干面包屑（Semmelbrösel）","200毫升中性油（葵花籽油或菜籽油）用于煎炸","1个柠檬，切成楔形用于上桌","盐和白胡椒"],"en":["4 boneless pork loin chops (about 150g each), trimmed","80g plain flour, seasoned with salt and pepper","2 large eggs, beaten","150g fine dry breadcrumbs (Semmelbrösel)","200ml neutral oil (sunflower or rapeseed) for frying","1 lemon, cut into wedges for serving","salt and white pepper"],"ro":["4 cotlete de porc din spată (aprox. 150g fiecare), dezosate și degresate","80g făină simplă, condimentată cu sare și piper","2 ouă mari, bătute","150g pesmet fin uscat (Semmelbrösel)","200ml ulei neutru (floarea-soarelui sau rapiță) pentru prăjit","1 lămâie, tăiată fâșii pentru servit","sare și piper alb"]},"howIsMade":{"zh":"将每块猪肉放在两张保鲜膜之间，用肉锤或擀面杖敲打至均匀4–5毫米厚——薄而均匀是正宗炸肉排的关键。拍干后用盐和白胡椒调味。准备三个浅盘：调味面粉、打散的鸡蛋、面包屑。将每块肉排裹上面粉（抖去多余）、浸入蛋液，然后用力按入面包屑均匀裹覆——不要按太紧，面包屑需保持蓬松以便在热油中膨胀起泡。在宽口平底锅中倒入1厘米深的油，加热至170–180°C。每面煎炸2–3分钟至深金黄色且酥脆。放在铁架上沥油——绝不要放在纸巾上，那会困住蒸汽并破坏酥壳。立即配柠檬角上桌。","en":"Place each pork chop between two sheets of cling film and beat with a meat mallet or rolling pin until evenly 4–5mm thick — the thin, even cut is the defining feature of a proper schnitzel. Pat dry and season with salt and white pepper. Set up three shallow dishes: seasoned flour, beaten eggs, breadcrumbs. Coat each schnitzel in flour (shake off the excess), dip in egg, then press firmly into breadcrumbs to coat evenly — do not press the crumb down too hard; it should stay airy so it puffs and blisters in hot oil. Pour oil into a wide pan to a depth of 1cm and heat to 170–180°C. Fry 2–3 minutes per side until deep golden and crisp. Drain on a wire rack — never on paper towel, which traps steam and kills the crust. Serve immediately with lemon wedges."},"nutrition":{"cal":570,"prot":45,"carb":15,"fat":35,"fib":1}},{"id":18,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"巴西","en":"Brazil","ro":"Brazilia"},"name":{"zh":"巴西黑豆炖肉","en":"Feijoada","ro":"Feijoada"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["400克干黑豆，提前浸泡一夜","400克烟熏猪排骨","200克辣香肠或烟熏香肠，切片","200克烟熏培根，切丁","1个大洋葱，切碎","4瓣大蒜，切末","2片月桂叶","3汤匙橄榄油","盐、胡椒和辣椒片适量"],"en":["400g dried black beans, soaked overnight","400g smoked pork ribs","200g chourico or smoked sausage, sliced","200g smoked bacon, diced","1 large onion, chopped","4 garlic cloves, minced","2 bay leaves","3 tbsp olive oil","salt, pepper and chilli flakes to taste"],"ro":["400g fasole neagră uscată, înmuiată 12 ore","400g coaste de porc afumate","200g chouriço sau cârnați afumați, feliați","200g bacon afumat, tăiat cuburi","1 ceapă mare, tocată","4 căței de usturoi, tocați","2 foi de dafin","3 linguri ulei de măsline","sare, piper și fulgi de ardei iute după gust"]},"howIsMade":{"zh":"将泡好的黑豆沥干，放入大锅中加入高出豆子5厘米的冷水。加入烟熏排骨和月桂叶。大火烧开后转中火炖1小时，期间撇去浮沫。同时，在煎锅中用橄榄油炒洋葱8分钟至软化，加入大蒜再炒2分钟。加入辣香肠和培根，煎5分钟至上色。将所有食材倒入豆锅中，充分搅拌后转小火炖45-60分钟，直至黑豆完全软烂、汤汁浓稠。用木勺将一些豆子压碎在锅壁上，使汤汁自然增稠。调整盐和胡椒。配白米饭、新鲜橙子片和法罗法（木薯粉）一起盛碗上桌。","en":"Drain the soaked beans and place in a large pot with fresh cold water to cover by 5cm. Add the smoked ribs and bay leaves. Bring to a boil, then simmer over medium heat for 1 hour, skimming any foam. Meanwhile, heat olive oil in a skillet, saute onion 8 minutes until soft and golden, add garlic and cook 2 minutes more. Add chourico and bacon, brown for 5 minutes. Transfer everything to the bean pot, stir well and simmer on low heat for 45-60 minutes until the beans are completely tender and the broth has thickened. Crush a handful of beans against the pot side with a wooden spoon — this thickens the stew naturally. Adjust salt and pepper. Serve in deep bowls with white rice, fresh orange slices and farofa (toasted manioc flour)."},"nutrition":{"cal":620,"prot":38,"carb":45,"fat":32,"fib":14}},{"id":19,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"中国","en":"China","ro":"China"},"name":{"zh":"宫保鸡丁","en":"Kung Pao Chicken","ro":"Pui Gong Bao"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["鸡胸肉500克，切2厘米丁","无盐烤花生100克","干辣椒8–10根","大葱4根，切3厘米段","大蒜3瓣，薄片","生姜2厘米，薄片","四川辣椒油或葵花油2大勺","腌料：酱油1大勺、玉米淀粉1小勺、芝麻油1小勺","酱汁：酱油2大勺、镇江黑米醋1大勺、白糖1大勺、玉米淀粉1小勺、水2大勺"],"en":["500g chicken breast, cut into 2cm cubes","100g unsalted roasted peanuts","8–10 dried Chinese chili peppers (Sichuan or similar)","4 spring onions, cut into 3cm pieces","3 garlic cloves, thinly sliced","2cm piece of ginger, thinly sliced","2 tbsp Sichuan chili oil or sunflower oil","Marinade: 1 tbsp soy sauce, 1 tsp cornstarch, 1 tsp sesame oil","Sauce: 2 tbsp soy sauce, 1 tbsp black rice vinegar (Chinkiang), 1 tbsp sugar, 1 tsp cornstarch, 2 tbsp water"],"ro":["500g piept de pui, tăiat cuburi de 2 cm","100g arahide prăjite nesărate","8–10 ardei iuți uscați chinezești (chili Sichuan)","4 cepe verzi, tăiate bucăți de 3 cm","3 căței de usturoi, feliați subțire","1 bucată ghimbir de 2 cm, feliată subțire","2 linguri ulei cu ardei Sichuan sau ulei de floarea-soarelui","Marinată: 1 lingură sos de soia, 1 linguriță amidon de porumb, 1 linguriță ulei de susan","Sos: 2 linguri sos de soia, 1 lingură oțet de orez negru (Chinkiang), 1 lingură zahăr, 1 linguriță amidon de porumb, 2 linguri apă"]},"howIsMade":{"zh":"鸡肉裹上腌料静置15分钟。将酱汁材料在小碗中混合备用。铁锅大火烧至冒烟，下油，放干辣椒爆炒30秒至颜色变深但不焦黑——闻到烤香味即可。放入鸡肉块，不翻动煎3–4分钟至一面金黄；翻面再煎2分钟。加入蒜片、姜片和葱白，翻炒1分钟。倒入酱汁，大力翻炒1分钟至浓稠裹住鸡肉。加入花生和葱绿，翻炒30秒。立即搭配茉莉花香米饭享用。","en":"Toss chicken with marinade ingredients and leave for 15 minutes. Combine sauce ingredients in a small bowl. Heat wok over highest heat until smoking; add oil and fry dried chilis and Sichuan peppercorns 30 seconds until darkened but not black — they should smell toasted, not burnt. Add chicken pieces and sear 3–4 minutes without stirring, until golden on one side; toss and cook 2 more minutes. Add garlic, ginger, and the white parts of the spring onion; stir-fry 1 minute. Pour in the sauce, toss vigorously for 1 minute until thickened and clinging to the chicken. Throw in peanuts and green spring onion tops; toss 30 seconds. Serve immediately with jasmine rice."},"nutrition":{"cal":400,"prot":32,"carb":11,"fat":22,"fib":2}},{"id":20,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"zh":"英国","en":"United Kingdom","ro":"Marea Britanie"},"name":{"zh":"炸鱼薯条","en":"Fish and Chips","ro":"Fish and Chips"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["鳕鱼或黑线鳕鱼柳4片（每片约180克），去皮","面质土豆1公斤（宾杰或类似品种），切粗条","植物油（用于深炸，约2升）","面糊：中筋面粉180克（另备拍粉用）","泡打粉1小勺","细盐1小勺","冰镇淡啤酒（拉格或淡色艾尔）300毫升","盐和麦芽醋（上桌用）"],"en":["4 cod or haddock fillets (about 180g each), skin removed","1kg floury potatoes (Maris Piper or King Edward), cut into thick chips","Vegetable oil for deep-frying (about 2 litres)","Batter: 180g plain flour, plus extra for dusting","1 tsp baking powder","1 tsp fine salt","300ml ice-cold lager or pale ale","Salt and malt vinegar to serve"],"ro":["4 fileuri de cod sau haddock (aprox. 180g fiecare), fără piele","1 kg cartofi floury (Maris Piper sau King Edward), tăiați bețe groase","Ulei vegetal pentru prăjit (aprox. 2 litri)","Pentru aluat: 180g făină tip 550 + extra pentru tăvălit","1 linguriță praf de copt","1 linguriță sare fină","300ml bere blondă rece (lager sau ale)","Sare și oțet de malt pentru servire"]},"howIsMade":{"zh":"薯条分两次炸：先在140°C炸8分钟至软但不上色，捞出在架子上放凉。调面糊：将面粉、泡打粉、盐混匀，再逐渐倒入冰镇啤酒搅拌至浓稠奶油状——不要过度搅拌。用厨房纸巾将鱼柳彻底吸干。油温升至185°C。每片鱼柳先拍一层薄粉，抖去多余，裹入面糊，静置几秒让多余面糊滴落。炸6–8分钟——中途用勺舀热油浇在面糊上以均匀上色——至面糊呈深金黄色且酥脆。放在纸上吸油。升温至200°C，薯条复炸3–4分钟至金黄酥脆。立即配盐和麦芽醋享用。","en":"Cook chips in two stages: fry at 140°C for 8 minutes until soft but not coloured; drain and cool on a rack. Make the batter by whisking flour, baking powder, and salt together, then gradually whisk in ice-cold beer until the consistency of double cream — do not overmix. Pat fish fillets completely dry with paper towels. Heat oil to 185°C. Dust each fillet in the extra flour, shake off excess, dip into batter and let it drip for a few seconds. Fry 6–8 minutes — halfway through, spoon hot oil over the top for even crisping — until the batter is deep golden and crunchy. Drain on paper. Raise oil to 200°C and fry chips a second time for 3–4 minutes until golden and crisp all over. Serve immediately with salt and malt vinegar."},"nutrition":{"cal":850,"prot":35,"carb":85,"fat":42,"fib":5}},{"id":21,"origin":{"zh":"越南","en":"Vietnam","ro":"Vietnam"},"name":{"zh":"越南河粉","en":"Pho","ro":"Pho"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":225,"active":75},"pairingsType":"def","ingredients":{"zh":["干河粉（宽5毫米）400克","牛腩或牛腱500克（用于汤底）","牛骨（髓骨或膝骨）1千克","中等洋葱2个，对半切","新鲜生姜5厘米，纵向对半切","八角3颗","肉桂棒5厘米1根","丁香3颗","鱼露（nuoc mam）2大勺","糖1小勺","盐适量","新鲜绿豆芽200克","新鲜香菜和泰国罗勒","红辣椒2根，切圆片（桌上备用）","青柠2个，切四等分（桌上备用）","海鲜酱和是拉差辣椒酱（桌上备用）"],"en":["400g dried rice noodles (banh pho, 5mm width)","500g beef brisket or flank (for the broth)","1kg beef bones (marrow or knuckle)","2 medium onions, halved","5 cm fresh ginger, halved lengthways","3 star anise","1 cinnamon stick (5 cm)","3 cloves","2 tbsp fish sauce (nuoc mam)","1 tsp sugar","salt to taste","200g fresh bean sprouts","fresh coriander and Thai basil","2 red chillies, sliced (at the table)","2 limes, quartered (at the table)","hoisin sauce and sriracha (at the table)"],"ro":["400g tăiței de orez (banh pho, lățime 5mm), uscați","500g piept de vită sau flacără (pentru supă)","1kg oase de vită (măduvă sau coadă)","2 cepe medii, înjumătățite","5 cm ghimbir proaspăt, înjumătățit","3 anasoane stelate","1 baton de scorțișoară (5 cm)","3 cuișoare","2 linguri sos de pește (nuoc mam)","1 linguriță zahăr","sare după gust","200g muguri de soia proaspeți","coriandru proaspăt și busuioc thai","2 ardei iuți roșii, feliați (la masă)","2 lămâi verzi, tăiate în sferturi (la masă)","sos hoisin și sos sriracha (la masă)"]},"howIsMade":{"zh":"将牛骨在沸水中焯5分钟，倒掉水，冲洗干净——去除杂质保持汤清。将洋葱和生姜直接在燃气灶火焰上或烤架下烤至边缘轻微焦黑（每面2–3分钟）——这赋予汤底金黄色泽和深度。大锅中加3升冷水，放入牛骨、牛腩、烤过的洋葱和生姜、八角、肉桂、丁香。大火烧开转最小火，不盖锅炖3小时，定时撇去油脂。1.5小时后取出牛腩，放凉后切薄片。用细筛过滤汤底，用鱼露、糖和盐调味。河粉在冷水中浸泡20分钟，沸水煮30秒，捞出。将粉分入碗中，浇上沸腾的汤，放上牛肉片。配豆芽、香菜、泰国罗勒、辣椒、青柠和各种蘸料上桌。","en":"Blanch beef bones in boiling water for 5 minutes, discard water, rinse well — this removes impurities and keeps the broth clear. Char the onion halves and ginger directly over a gas flame or under the grill until lightly blackened on the edges (2–3 minutes per side) — this gives the broth its golden colour and depth. Fill a large pot with 3L cold water, add bones, brisket, charred onion, ginger, star anise, cinnamon, and cloves. Bring to a boil, reduce to a bare simmer, cook uncovered for 3 hours, skimming fat periodically. Remove the brisket after 1½ hours, let cool, slice thinly. Strain broth through a fine sieve, season with fish sauce, sugar, and salt. Soak noodles in cold water 20 minutes, boil 30 seconds, drain. Divide noodles into bowls, ladle boiling broth over, add meat slices. Serve with bean sprouts, coriander, basil, chilli, lime, and sauces at the table."},"nutrition":{"cal":380,"prot":28,"carb":42,"fat":10,"fib":2}},{"id":22,"origin":{"zh":"西班牙","en":"Spain","ro":"Spania"},"name":{"zh":"西班牙海鲜饭","en":"Paella","ro":"Paella"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"fish","ingredients":{"zh":["西班牙海鲜饭米（bomba）300克（或短粒米）","去骨鸡腿肉400克，切块","生虾300克（带壳或去壳均可）","淡菜（贻贝）400克，刷洗干净去须","大洋葱1个，切碎","大蒜4瓣，切末","红椒1个，切丁","罐头碎番茄400克","藏红花½小勺（浸入2大勺温水）","烟熏甜椒粉（pimentón de la Vera）1小勺","热鸡汤800毫升","橄榄油3大勺","盐和黑胡椒适量","新鲜欧芹和柠檬角用于搭配"],"en":["300g bomba rice (or short-grain rice)","400g boneless chicken thighs, cut into pieces","300g raw prawns (shell-on or peeled)","400g mussels, scrubbed and debearded","1 large onion, finely chopped","4 garlic cloves, minced","1 red bell pepper, diced","400g canned crushed tomatoes","½ tsp saffron threads (soaked in 2 tbsp warm water)","1 tsp smoked paprika (pimentón de la Vera)","800ml warm chicken stock","3 tbsp olive oil","salt and black pepper to taste","fresh parsley and lemon wedges to serve"],"ro":["300g orez bomba (sau orez cu bob scurt)","400g pulpe de pui dezosate, tăiate în bucăți","300g creveți crudi (cu coajă sau fără)","400g midii, spălate și curățate","1 ceapă mare, tocată","4 căței de usturoi, tocați","1 ardei gras roșu, tăiat cuburi","400g roșii din conservă, concasate","½ linguriță șofran (înmuiat în 2 linguri apă caldă)","1 linguriță boia de ardei afumată (pimentón de la Vera)","800ml fond de pui cald","3 linguri ulei de măsline","sare și piper negru după gust","pătrunjel proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"zh":"将藏红花浸入2大勺温水中、宽口浅锅（或帕埃利亚锅）中加热橄榄油至中大火。鸡肉调味，每面煎4–5分钟至深金色；取出备用、同一锅中炒洋葱5分钟，加蒜末和红椒再炒3分钟。加番茄和烟熏甜椒粉，煮3–4分钟至浓稠——这就是sofrito（爆香基底），帕埃利亚的灵魂、加米翻炒1分钟。倒入热鸡汤和藏红花水均匀分布、将鸡肉放回锅中。调至中火，此后不再搅拌——加入汤底后绝不搅拌、不盖锅煮10分钟。将虾和贻贝摆放在上面轻轻按入、再煮8–10分钟至虾变粉红色、贻贝张开（丢弃未开口的）。如需socarrat（焦脆底层），最后2分钟调大火，听到轻微的嘶嘶声即可、静置5分钟、撒欧芹，配柠檬角上桌。","en":"Soak saffron in 2 tbsp warm water; heat olive oil in a paella pan (or wide shallow pan) over medium-high heat. Season chicken, sear 4–5 minutes per side until deeply golden; remove and set aside; in the same pan fry onion 5 minutes, add garlic and red pepper, cook 3 more minutes. Add crushed tomatoes and smoked paprika, cook 3–4 minutes until thickened — this is the sofrito, the soul of the paella; add the rice, stir 1 minute to toast lightly. Pour in the warm stock with the saffron and its soaking water, spread evenly; return the chicken. Adjust to medium heat and do not stir again — never stir paella once the stock is added; cook uncovered for 10 minutes. Place prawns and mussels on top, pressing gently into the rice; cook 8–10 minutes more until prawns are pink and mussels open (discard any that stay shut). For socarrat (the coveted crispy bottom crust), raise to high heat the last 2 minutes — listen for a light crackling; rest 5 minutes; garnish with parsley and serve with lemon wedges."},"nutrition":{"cal":520,"prot":32,"carb":58,"fat":16,"fib":3}},{"id":23,"servings":4,"tipType":"def","pairingsType":"korean","origin":{"zh":"韩国","en":"South Korea","ro":"Coreea de Sud"},"name":{"zh":"拌饭","en":"Bibimbap","ro":"Bibimbap"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["短粒白米饭2杯","200克牛里脊，逆纹切薄片","1根中等西葫芦，切丝","1根中等胡萝卜，切丝","200克嫩菠菜","100克豆芽","4朵香菇，去蒂","4个鸡蛋","4大勺辣椒酱（韩式）","3大勺芝麻油","2大勺酱油","1小勺糖","3瓣大蒜，切末","芝麻适量"],"en":["2 cups short-grain white rice","200g beef sirloin, thinly sliced against the grain","1 medium courgette, julienned","1 medium carrot, julienned","200g baby spinach","100g bean sprouts","4 shiitake mushrooms, stems removed","4 eggs","4 tbsp gochujang (Korean chili paste)","3 tbsp sesame oil","2 tbsp soy sauce","1 tsp sugar","3 cloves garlic, minced","Sesame seeds to garnish"],"ro":["2 căni orez cu bob scurt","200g vită (antricot), felii subțiri","1 dovlecel mediu, julien","1 morcov mediu, julien","200g spanac baby","100g germeni de fasole","4 ciuperci shiitake, fără codiță","4 ouă","4 linguri gochujang (pastă de ardei coreean)","3 linguri ulei de susan","2 linguri sos de soia","1 linguriță zahăr","3 căței de usturoi, tocați","Semințe de susan, pentru decor"]},"howIsMade":{"zh":"将米饭加2.5杯水煮开，转最小火盖锅煮12分钟，离火焖10分钟。牛肉用1大勺酱油、1大勺芝麻油、1小勺糖和一半蒜末腌制15分钟。菠菜在盐水中焯30秒，挤干水分，用1小勺芝麻油和盐调味；豆芽加蒜和盐炒2分钟；胡萝卜和西葫芦分别用芝麻油各炒2分钟。腌好的牛肉大火煎3–4分钟至焦糖色；香菇加少量酱油炒2分钟；用芝麻油煎荷包蛋。将米饭分装4个碗，蔬菜和牛肉分区摆放，中间放鸡蛋，每碗加1大勺辣椒酱，淋芝麻油撒芝麻——吃前充分拌匀。","en":"Cook rice in 2.5 cups water: bring to a boil, cover and simmer on the lowest heat for 12 minutes, then rest off the heat for 10 minutes. Marinate beef with 1 tbsp soy sauce, 1 tbsp sesame oil, 1 tsp sugar and half the garlic for 15 minutes. Blanch spinach 30 seconds in boiling salted water, squeeze dry, season with 1 tsp sesame oil and salt; sauté bean sprouts 2 minutes with garlic and salt; stir-fry carrot and courgette separately for 2 minutes each with a drizzle of sesame oil. Sear marinated beef over high heat 3–4 minutes until caramelised; slice shiitake and sauté 2 minutes with a splash of soy sauce; fry eggs sunny-side up in sesame oil. Divide rice among 4 bowls, arrange vegetables and beef in sections, place an egg in the centre, add 1 tbsp gochujang per bowl, drizzle with sesame oil and scatter sesame seeds — mix everything together before eating."},"nutrition":{"cal":450,"prot":22,"carb":65,"fat":12,"fib":5}},{"id":24,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"zh":"叙利亚","en":"Syria","ro":"Siria"},"name":{"zh":"鹰嘴豆泥","en":"Hummus","ro":"Hummus"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["熟鹰嘴豆400克（1罐），去皮","优质芝麻酱80克，充分搅拌均匀","2个柠檬的汁（约4汤匙）","2瓣大蒜，磨成泥","细盐1/2茶匙","冰水3–5汤匙","特级初榨橄榄油2汤匙用于最后点缀"],"en":["400g (1 can) cooked chickpeas, skins removed","80g tahini (good quality, stirred well)","juice of 2 lemons (about 4 tbsp)","2 garlic cloves, grated","1/2 tsp fine salt","3–5 tbsp ice-cold water","2 tbsp extra-virgin olive oil for finishing"],"ro":["400g năut gătit (1 conservă), coaja îndepărtată","80g pastă de susan (tahini de calitate, bine amestecată)","sucul a 2 lămâi (aprox. 4 linguri)","2 căței de usturoi, rași","1/2 linguriță sare fină","3–5 linguri apă rece cu gheață","2 linguri ulei de măsline extravirgin pentru finalizare"]},"howIsMade":{"zh":"要获得最顺滑的鹰嘴豆泥，轻轻按压每颗鹰嘴豆去除外皮——这一小步意义重大。在食物料理机中，单独将芝麻酱和柠檬汁打1分钟至色泽变浅、质地顺滑。加入大蒜泥和盐，打30秒。加入鹰嘴豆，打1分钟。机器运转中，一汤匙一汤匙地加入冰水——冰水能使豆泥更蓬松轻盈。共打3–5分钟，期间刮下侧壁，直至完全顺滑。品尝后调整柠檬汁和盐。舀入盘中，淋上橄榄油，撒烟熏辣椒粉或漆树粉。冷藏可保存5天。","en":"For the smoothest hummus, pop the skins off the chickpeas by gently squeezing each one — a small step that makes a big difference. In a food processor, blitz tahini and lemon juice alone for 1 minute until pale and creamy. Add garlic and salt; blitz 30 seconds. Add the chickpeas and process 1 minute. With the machine running, drizzle in ice-cold water tablespoon by tablespoon — the cold water aerates and lightens the hummus. Process 3–5 minutes total, scraping down the sides, until completely smooth. Taste and adjust lemon and salt. Spread in a bowl, drizzle with olive oil, and finish with smoked paprika or sumac. Keeps refrigerated up to 5 days."},"nutrition":{"cal":220,"prot":8,"carb":22,"fat":12,"fib":6}},{"id":25,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"zh":"黎巴嫩","en":"Lebanon","ro":"Liban"},"name":{"zh":"塔布勒沙拉","en":"Tabbouleh","ro":"Tabbouleh"},"category":{"zh":"沙拉","en":"Salad","ro":"Salate"},"ingredients":{"zh":["200克意大利扁叶欧芹，只取叶子，切碎","50克细粒布格麦，冷水浸泡20分钟后拧干","3个熟番茄（约300克），切小丁","4根葱，切细","20克新鲜薄荷叶，切碎","2个柠檬的汁（约80毫升）","4汤匙特级初榨橄榄油，盐和黑胡椒适量"],"en":["200g flat-leaf parsley, leaves only, finely chopped","50g fine bulgur wheat, soaked in cold water 20 min then squeezed dry","3 ripe tomatoes (about 300g), finely diced","4 spring onions, finely sliced","20g fresh mint leaves, finely chopped","juice of 2 lemons (about 80ml)","4 tbsp extra-virgin olive oil, salt and black pepper to taste"],"ro":["200g pătrunjel plat, frunze tocate mărunt","50g bulgur fin, înmuiat 20 min în apă rece, stors bine","3 roșii coapte (cca 300g), tăiate cuburi mici","4 cepe verzi, tocate fin","20g frunze de mentă proaspătă, tocate mărunt","sucul de la 2 lămâi (cca 80ml)","4 linguri ulei de măsline extravirgin, sare și piper negru după gust"]},"howIsMade":{"zh":"将布格麦在冷水中浸泡20分钟，捞出后用手尽量拧干——应该干而不湿。将欧芹切得尽可能细碎；正宗的塔布勒沙拉是以香草为主的沙拉，而非谷物沙拉。将欧芹、薄荷、葱、番茄和拧干的布格麦放入大碗中混合。加入柠檬汁和橄榄油，充分搅拌后静置10分钟——柠檬汁会继续软化布格麦并使香草风味绽放。调整盐和胡椒。室温上桌。","en":"Soak the bulgur in cold water for 20 minutes, then drain and squeeze out as much water as possible with your hands — it should be dry, not wet. Chop the parsley as finely as you can; authentic tabbouleh is herb-forward, not grain-forward. Combine parsley, mint, spring onions, tomatoes and squeezed bulgur in a large bowl. Add lemon juice and olive oil, toss well and let rest 10 minutes — the lemon juice continues to soften the bulgur and blooms the herbs. Adjust salt and pepper. Serve at room temperature. True tabbouleh is a parsley salad with bulgur, not a bulgur salad with a little parsley."},"nutrition":{"cal":180,"prot":4,"carb":20,"fat":10,"fib":4}},{"id":26,"servings":4,"tipType":"pasta","pairingsType":"pasta","origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"烩饭","en":"Risotto","ro":"Risotto"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["阿博里奥或卡纳罗利米320克","大葱头1个或小洋葱，细切丁","无盐黄油50克，分成两份","干白葡萄酒100毫升","温热鸡汤或蔬菜高汤1.2升","帕尔米贾诺-雷贾诺奶酪40克，现磨","特级初榨橄榄油1汤匙","盐和白胡椒适量"],"en":["320g Arborio or Carnaroli rice","1 large shallot or small onion, finely diced","50g unsalted butter, divided","100ml dry white wine","1.2L warm chicken or vegetable stock","40g Parmigiano-Reggiano, freshly grated","1 tbsp extra-virgin olive oil","salt and white pepper to taste"],"ro":["320g orez Arborio sau Carnaroli","1 șalotă sau ceapă mică, tocată fin","50g unt nesărat, împărțit","100ml vin alb sec","1,2L supă caldă de pui sau legume","40g Parmigiano-Reggiano, ras proaspăt","1 lingură ulei de măsline extravirgin","sare și piper alb după gust"]},"howIsMade":{"zh":"整个烹饪过程中，保持高汤始终温热——加入冷高汤会中断烹饪并破坏奶油质地。在一口宽厚底锅中，以中火加热橄榄油和一半黄油。将葱头炒软，约3分钟。加入大米翻炒2分钟，至米粒边缘微微透明。倒入白葡萄酒，不断翻炒至完全吸收。每次加入一勺温热高汤，持续翻炒，等每勺完全吸收后再加下一勺——这是关键步骤，需16–18分钟。米饭应达到al dente（芯有嚼劲）。离火后，用力将剩余冷黄油和帕尔米贾诺奶酪拌入——油脂与淀粉乳化形成光亮酱汁（称为mantecatura）。静置1分钟后立即盛入温热碗中享用。","en":"Keep the stock warm over low heat throughout cooking — adding cold stock stops the cooking and ruins the creaminess. Heat oil and half the butter in a wide, heavy pan over medium heat. Sweat the shallot until soft, 3 minutes. Add the rice and toast, stirring, for 2 minutes until grains are slightly translucent at the edges. Pour in the wine and stir until completely absorbed. Add warm stock one ladleful at a time, stirring constantly and waiting for each ladleful to be absorbed before adding the next — this is the essential step and takes 16–18 minutes. The rice should be al dente with a creamy coating. Off the heat, beat in the remaining cold butter and the Parmigiano vigorously — the fat emulsifies into the starches creating a glossy sauce (this is called mantecatura). Rest 1 minute, then serve immediately in warm bowls."}},{"id":27,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"瑞典","en":"Sweden","ro":"Suedia"},"name":{"zh":"瑞典肉丸","en":"Swedish Meatballs","ro":"Chifteluțe suedeze"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["猪牛混合碎肉500克（各半）","中等洋葱1个，磨碎","白吐司1片去边，用3汤匙牛奶浸泡","大鸡蛋1个","多香果粉1/4茶匙","现磨肉豆蔻1/4茶匙","黄油2汤匙用于煎炸","牛肉高汤250毫升","重奶油150毫升"],"en":["500g mixed ground pork and beef (50/50)","1 medium onion, grated","1 slice white bread, crusts removed, soaked in 3 tbsp milk","1 large egg","1/4 tsp ground allspice","1/4 tsp freshly grated nutmeg","2 tbsp butter for frying","250ml beef stock","150ml double cream"],"ro":["500g carne tocată amestecată porc și vită (50/50)","1 ceapă medie, rasă","1 felie de pâine albă fără coajă, înmuiată în 3 linguri lapte","1 ou mare","1/4 linguriță ienibahar măcinat","1/4 linguriță nucșoară rasă","2 linguri unt pentru prăjit","250ml supă de vită","150ml smântână pentru frișcă"]},"howIsMade":{"zh":"将浸泡的面包挤去多余牛奶，与碎肉、磨碎的洋葱（挤去水分）、鸡蛋、多香果粉、肉豆蔻、盐和胡椒混合。充分搅拌但不要过度——过度搅拌会使肉丸变硬。用湿手搓成约3厘米直径的丸子（约20–24个）。在宽口平底锅中用中火融化黄油。分批煎丸子，轻轻滚动使各面均匀上色，每批6–8分钟。取出备用。同一锅中加入牛肉高汤，刮起锅底焦香，煮沸。加入奶油煮5分钟至略微浓稠。将丸子放回酱汁，小火再煮5分钟。配越橘果酱、水煮或土豆泥，以及腌黄瓜上桌。","en":"Squeeze the soaked bread to remove excess milk, then mix with the ground meat, grated onion (squeeze out excess liquid), egg, allspice, nutmeg, salt and pepper. Mix well but do not overwork — overworking makes the meatballs tough. With wet hands, roll into balls about 3cm in diameter, yielding about 20–24 meatballs. Melt butter in a wide skillet over medium heat. Fry the meatballs in batches, rolling gently to brown all sides evenly, 6–8 minutes per batch. Remove and set aside. In the same pan, stir in the beef stock, scraping up the fond, and bring to a simmer. Add the cream and simmer 5 minutes until slightly thickened. Return the meatballs to the sauce and cook on low heat 5 more minutes. Serve with lingonberry jam, boiled or mashed potatoes, and pickled cucumber."}},{"id":28,"servings":4,"tipType":"meat","timeMins":{"total":720,"active":75},"pairingsType":"japanese","origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"经典日式拉面","en":"Classic Japanese Ramen","ro":"Ramen clasic japonez"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["新鲜或干拉面4份（共约400克）","鸡汤或猪骨高汤1升","生抽100毫升（按口味）","味醂2汤匙","五花肉或猪肩肉200克，切薄片（叉烧）","溏心鸡蛋4个（提前一晚在酱油和味醂中腌制）","干海苔2张，各切一半","笋干4汤匙（笋干）","春葱2根，切薄圈","芝麻油1汤匙"],"en":["4 portions fresh or dried ramen noodles (about 400g total)","1L chicken or pork bone broth","100ml soy sauce (or to taste)","2 tbsp mirin","200g pork belly or shoulder, thinly sliced (chashu)","4 soft-boiled eggs (marinated overnight in soy sauce and mirin)","2 sheets nori (dried seaweed), halved","4 tbsp bamboo shoots (menma)","2 spring onions, thinly sliced","1 tbsp sesame oil"],"ro":["4 porții tăiței ramen proaspeți sau uscați (aprox. 400g total)","1L supă de pui sau os de porc","100ml sos de soia (sau după gust)","2 linguri mirin","200g burtă de porc sau pulpă, feliată subțire (chashu)","4 ouă fierte moi (marinate în soia și mirin peste noapte)","2 foi nori (alge uscate), tăiate în jumătate","4 linguri mlădițe de bambus (menma)","2 cepe verzi, feliați subțire","1 lingură ulei de susan"]},"howIsMade":{"zh":"将高汤与酱油和味醂混合，小火煮10分钟后品尝——汤头应该鲜味浓郁、略咸、带有一丝甜味。溏心拉面蛋（最好提前一晚准备）：鸡蛋精确煮6分30秒，迅速放入冰水，去壳后在3汤匙酱油、2汤匙味醂和50毫升水的腌汁中浸泡一夜。叉烧：将五花肉卷紧，用厨房棉线扎好，在酱油、味醂、清酒和糖中以小火炖2小时至软烂。冷却后切片。按照包装说明煮面（通常2–3分钟），沥干后分入温热的碗中。浇上滚烫的汤头。依次摆上2–3片叉烧、对切的溏心蛋、一片竖起的海苔、笋干、葱花，最后滴几滴芝麻油。立即上桌。","en":"Combine the broth with soy sauce and mirin; simmer 10 minutes and taste — the broth should be deeply savoury, slightly salty, with a hint of sweetness. Ramen eggs (best made the night before): boil eggs for exactly 6 minutes 30 seconds, shock in ice water, peel, and marinate overnight in 3 tbsp soy sauce, 2 tbsp mirin, and 50ml water. Chashu pork: roll pork belly tightly, tie with kitchen string, and braise in soy sauce, mirin, sake, and sugar over a gentle simmer for 2 hours until tender. Slice when cool. Cook noodles per package directions (usually 2–3 minutes), drain, and portion into warmed bowls. Ladle hot broth over. Top with 2–3 slices of chashu pork, a halved ramen egg, a piece of nori standing upright, bamboo shoots, spring onions, and a drop of sesame oil. Serve immediately."}},{"id":29,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"zh":"阿根廷","en":"Argentina","ro":"Argentina"},"name":{"zh":"阿根廷馅饼","en":"Empanadas","ro":"Empanadas"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["400克中筋面粉","100克猪油或冷黄油，切丁","150毫升温水","1茶匙盐","300克牛肉馅","1个中等洋葱，切碎","2个熟鸡蛋，切碎","12颗绿橄榄，去核切片","1茶匙孜然粉","1茶匙甜辣椒粉"],"en":["400g plain flour","100g lard or cold butter, diced","150ml warm water","1 tsp salt","300g ground beef","1 medium onion, finely chopped","2 hard-boiled eggs, chopped","12 green olives, pitted and sliced","1 tsp ground cumin","1 tsp sweet paprika"],"ro":["400g făină albă","100g untură sau unt rece, cuburi","150ml apă caldă","1 linguriță sare","300g carne de vită tocată","1 ceapă medie, tocată fin","2 ouă fierte tari, tăiate","12 măsline verzi, fără sâmburi și tăiate","1 linguriță chimen măcinat","1 linguriță boia dulce"]},"howIsMade":{"zh":"制作面团：将面粉和盐混合，用指尖把猪油或冷黄油揉搓成面包屑状，逐渐加入温水揉捏5分钟至光滑有弹性。包好，静置30分钟。制作馅料：用少量油炒洋葱8分钟，加入牛肉馅以中火炒10分钟并打散。用孜然、甜椒粉、盐和胡椒调味。完全放凉后拌入切碎的鸡蛋和橄榄。将面团擀至3毫米厚，切出12厘米的圆形面皮。在中间放一勺馅料，湿润边缘，对折成半月形并用扭拧的边缘封口。在200摄氏度烤20-25分钟至金黄，或在180摄氏度油炸每面3-4分钟。","en":"Make the dough: combine flour and salt, rub in the lard or cold butter with your fingertips until the mixture resembles breadcrumbs, then add warm water gradually and knead 5 minutes to a smooth, elastic dough. Wrap and rest 30 minutes. For the filling, saute onion in a little oil for 8 minutes, add ground beef and cook 10 minutes over medium heat, breaking it up well. Season with cumin, paprika, salt and pepper. Cool completely, then fold in the chopped boiled eggs and olives. Roll dough to 3mm thick and cut 12cm circles. Place a tablespoon of filling in the centre, moisten the edges, fold into a half-moon and seal with a twisted rope border (repulge). Bake at 200 degrees C for 20-25 minutes until golden, or deep-fry at 180 degrees C for 3-4 minutes per side."}},{"id":30,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"黄瓜酸奶酱","en":"Tzatziki","ro":"Tzatziki"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["全脂希腊酸奶500克（如有可能提前一夜过滤）","大黄瓜1根（约300克），磨碎后充分拧干","大蒜2瓣，磨碎","特级初榨橄榄油2汤匙，另备少许用于上桌","新鲜莳萝1汤匙，切碎","半个柠檬的汁","细海盐适量"],"en":["500g full-fat Greek yogurt (strained overnight if possible)","1 large cucumber (about 300g), grated and well squeezed","2 garlic cloves, finely grated","2 tbsp extra-virgin olive oil, plus a drizzle to serve","1 tbsp fresh dill, finely chopped","juice of half a lemon","fine sea salt to taste"],"ro":["500g iaurt grecesc integral (scurs peste noapte dacă e posibil)","1 castravete mare (cca 300g), ras și bine stors","2 căței de usturoi, rași fin","2 linguri ulei de măsline extravirgin, plus un pic pentru servit","1 lingură mărar proaspăt, tocat mărunt","sucul de la jumătate de lămâie","sare fină după gust"]},"howIsMade":{"zh":"最重要的步骤：将黄瓜用刨丝器粗磨，放入干净的厨房布或滤网中，撒少许盐，静置10分钟后用力拧干——黄瓜会失去将近一半的重量（水分）。多余水分会使黄瓜酸奶酱变得水水的。将酸奶与拧干的黄瓜、磨碎的大蒜、橄榄油、柠檬汁和莳萝混合，调整盐分。盖上保鲜膜冷藏至少30分钟——静置后味道会更浓郁。上桌时淋上橄榄油，摆上新鲜莳萝，搭配温热的皮塔饼。","en":"The most important step: grate the cucumber on the coarse side of a box grater and place in a clean tea towel or colander. Sprinkle with a little salt, leave 10 minutes, then squeeze out hard — the cucumber will shed almost half its weight in water. Excess moisture is what makes tzatziki watery and weak. Combine the yogurt with the well-squeezed cucumber, grated garlic, olive oil, lemon juice and dill. Taste and adjust salt. Cover and refrigerate at least 30 minutes before serving — the flavours deepen as it rests. Serve drizzled with olive oil and a few fresh dill sprigs, alongside warm pita bread or souvlaki."}},{"id":31,"servings":4,"tipType":"soup","pairingsType":"french","origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"法式洋葱汤","en":"French Onion Soup","ro":"Supă de ceapă franțuzească"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["黄洋葱1公斤，切细丝","无盐黄油60克","中筋面粉1汤匙","干白葡萄酒200毫升","优质牛高汤1.2升","法棍面包4片，较厚，烤过","格吕耶尔奶酪150克，磨碎","盐、黑胡椒和新鲜百里香枝"],"en":["1kg yellow onions, thinly sliced","60g unsalted butter","1 tbsp plain flour","200ml dry white wine","1.2 litres good beef stock","4 thick slices baguette, toasted","150g Gruyere, grated","salt, black pepper and fresh thyme sprigs"],"ro":["1kg ceapă galbenă, tăiată julienne","60g unt nesărat","1 lingură făină","200ml vin alb sec","1,2 litri supă bună de vită","4 felii groase de baghetă, prăjite","150g Gruyère, ras","sare, piper negru și crenguțe de cimbru proaspăt"]},"howIsMade":{"zh":"在厚底锅中以中低火融化黄油。加入洋葱和一小撮盐，每5分钟搅拌一次，炒45-60分钟——耐心是关键。洋葱必须变成焦糖色，而不是焦糊。加入百里香和面粉，搅拌1分钟。倒入白葡萄酒，大火煮3分钟。加入牛高汤，煮沸后转小火再炖20分钟。调整盐和胡椒。倒入可入烤箱的碗中，每碗放一片烤过的法棍，铺上厚厚的格吕耶尔奶酪，用烤炉（上火）烤3-4分钟直到奶酪起泡变金黄。立即上桌。","en":"Melt the butter in a heavy-bottomed pot over medium-low heat. Add the onions with a pinch of salt and cook for 45-60 minutes, stirring every 5 minutes — patience is everything here. The onions must turn the colour of caramel, not burnt. Add a splash of water whenever they stick. Add the thyme and flour, stir for 1 minute. Pour in the wine and let it bubble for 3 minutes. Add the beef stock, bring to a simmer and cook 20 minutes. Taste and adjust salt and pepper. Ladle into oven-safe bowls, float a slice of toasted baguette in each, pile on the Gruyere and grill (broil) for 3-4 minutes until the cheese is bubbling and golden brown. Serve immediately — the cheese will set as it cools."}},{"id":32,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"匈牙利","en":"Hungary","ro":"Ungaria"},"name":{"zh":"匈牙利炖牛肉","en":"Goulash","ro":"Gulaș"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["牛肩肉或牛腱700克，切3厘米方块","蜡质土豆400克，去皮切丁","大洋葱2个，切碎","红甜椒2个，切丁","匈牙利甜椒粉3汤匙","罐头番茄碎400克","牛高汤1升","猪油或植物油3汤匙","葛缕子2茶匙，盐和黑胡椒适量"],"en":["700g beef chuck or shin, cut into 3cm cubes","400g waxy potatoes, peeled and diced","2 large onions, finely chopped","2 red bell peppers, diced","3 tbsp sweet Hungarian paprika","400g canned chopped tomatoes","1 litre beef stock","3 tbsp lard or vegetable oil","2 tsp caraway seeds, salt and black pepper to taste"],"ro":["700g carne de vită (spată sau greabăn), cuburi de 3 cm","400g cartofi cerosi, curățați și tăiați cuburi","2 cepe mari, tocate mărunt","2 ardei grași roșii, tăiați cuburi","3 linguri boia ungurească dulce","400g roșii tocate la conservă","1 litru supă de vită","3 linguri untură sau ulei vegetal","2 linguriță semințe de chimen, sare și piper negru după gust"]},"howIsMade":{"zh":"将牛肉块擦干，用盐和胡椒调味。在厚底锅中以大火加热猪油，分批将牛肉煎至金黄——不要频繁翻动，要形成焦壳而非蒸熟。取出备用。转中火，炒洋葱10分钟。加入甜椒粉翻炒1分钟——不要烧焦，否则会变苦。加入甜椒、番茄碎、葛缕子和牛高汤。放回牛肉，煮沸后盖上锅盖，小火炖60-75分钟。加入土豆再炖25分钟，直到软烂、用力按压牛肉能轻松分开。调整盐分。配松脆面包，盛入深碗上桌。","en":"Pat the beef cubes dry and season with salt and pepper. Heat the lard or oil in a heavy pot over high heat and brown the meat in batches — do not stir too much; you want a crust, not steamed meat. Remove and set aside. Reduce heat to medium, add the onions and cook 10 minutes. Add the paprika and stir for 1 minute — do not let it burn or it turns bitter. Add the peppers, tomatoes, caraway seeds and beef stock. Return the beef, bring to a boil, cover and simmer on low heat for 60-75 minutes. Add the potatoes and simmer 25 more minutes until tender and the beef flakes easily under pressure. Taste and adjust salt. Serve in deep bowls with crusty bread to mop up the rich broth."}},{"id":33,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"zh":"埃及","en":"Egypt","ro":"Egipt"},"name":{"zh":"埃及杂粮饭","en":"Koshari","ro":"Koshari"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["长粒白米200克","绿扁豆200克","小通心粉或贝壳粉150克","罐头鹰嘴豆400克，沥干","罐头碎番茄800克","大洋葱3个（2个做酱，1个做酥脆配料）","植物油4汤匙","大蒜3瓣切末，盐、孜然、醋适量"],"en":["200g long-grain white rice","200g green lentils","150g small macaroni or ditalini","400g canned chickpeas, drained","800g canned crushed tomatoes","3 large onions (2 for sauce, 1 for crispy topping)","4 tbsp vegetable oil","3 garlic cloves, minced, salt, cumin and vinegar to taste"],"ro":["200g orez cu bob lung","200g linte verde","150g macaroane mici sau ditalini","400g năut la conservă, scurs","800g roșii tocate la conservă","3 cepe mari (2 pentru sos, 1 pentru topping crocant)","4 linguri ulei vegetal","3 căței de usturoi, tocați, sare, chimen și oțet după gust"]},"howIsMade":{"zh":"将绿扁豆在无盐水中煮20分钟至弹牙，捞出沥干。白米在盐水中煮15分钟。将小通心粉煮至弹牙，沥干。第三个洋葱切薄圈，用油以中大火炸15-20分钟，频繁翻炒，至深金黄色且酥脆——这是点睛之笔的配料。放在厨房纸上吸油。用同样的油将剩余切碎的洋葱炒10分钟，加入大蒜、孜然、罐头番茄、少许醋和盐。番茄酱炖20-25分钟至浓稠。加入鹰嘴豆再炖5分钟。将扁豆拌入米饭中。分层装盘：米饭+扁豆、通心粉、番茄鹰嘴豆酱，最上面撒酥脆洋葱圈。","en":"Cook the lentils in unsalted water for 20 minutes until al dente, then drain. Cook the rice in salted water for 15 minutes. Cook the pasta al dente and drain. Slice the third onion into thin rings and fry in oil over medium-high heat for 15-20 minutes, stirring often, until deep golden brown and crispy — this is the prized topping. Drain on paper towels. In the same oil, saute the remaining chopped onions 10 minutes, add garlic, cumin, canned tomatoes, a splash of vinegar and salt. Simmer the sauce 20-25 minutes until thick. Add the chickpeas and simmer 5 more minutes. Mix lentils into the rice. To serve, layer rice-lentil mixture, pasta, tomato-chickpea sauce, and top with the crispy onion rings. Koshari is eaten at room temperature."}},{"id":35,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"zh":"土耳其","en":"Turkey","ro":"Turcia"},"name":{"zh":"果仁蜜饼","en":"Baklava","ro":"Baklava"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["费罗酥皮500克，解冻","无盐黄油200克，融化","核桃200克，切碎","开心果100克，切碎","肉桂粉1茶匙","糖300克","水200毫升","蜂蜜2汤匙加柠檬汁1汤匙"],"en":["500g phyllo pastry sheets, thawed","200g unsalted butter, melted","200g walnuts, finely chopped","100g pistachios, finely chopped","1 tsp ground cinnamon","300g sugar","200ml water","2 tbsp honey plus 1 tbsp lemon juice"],"ro":["500g foi de plăcintă (phyllo), dezghețate","200g unt nesărat, topit","200g nuci, tocate mărunt","100g fistic, tocat mărunt","1 linguriță scorțișoară măcinată","300g zahăr","200ml apă","2 linguri miere plus 1 lingură suc de lămâie"]},"howIsMade":{"zh":"先制作糖浆：将糖溶于水中，煮5分钟，加入蜂蜜和柠檬汁，再煮5分钟、完全冷却——糖浆必须是凉的才能倒在热的果仁蜜饼上。将核桃、开心果和肉桂粉混合、在33x23厘米的烤盘上刷融化的黄油。铺上8张费罗酥皮，每张刷黄油、撒上厚厚一层坚果馅。用4张刷油的酥皮盖上，再撒一层坚果馅、重复直至坚果馅用完，最后盖上8张刷油的酥皮。烤之前切成菱形或方形、160摄氏度烤45-50分钟至浅金黄色。从烤箱取出的瞬间，将凉的糖浆倒在上面——温差有助于完全吸收、静置2-3小时后食用。","en":"Make the syrup first: dissolve sugar in water, boil 5 minutes, add honey and lemon juice, boil 5 more minutes; leave to cool completely — the syrup must be cold when poured over hot baklava. Mix the walnuts with pistachios and cinnamon; grease a 33x23cm baking tray with melted butter. Layer 8 phyllo sheets, brushing each with butter; scatter a generous layer of nut mixture. Cover with 4 buttered phyllo sheets, then another nut layer; repeat until the nuts are used up, finishing with 8 buttered phyllo sheets. Cut into diamonds or squares before baking; bake at 160 degrees C for 45-50 minutes until pale golden. The moment it comes out of the oven, pour the cold syrup all over — the temperature contrast helps the baklava absorb every drop; leave to rest 2-3 hours before serving."}},{"id":36,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"辣椒牛肉","en":"Chili con carne","ro":"Chili con carne"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["牛肉馅500克（脂肪含量至少20%）","红腰豆罐头400克，沥干","切碎番茄罐头400克","大洋葱2个，切碎","大蒜3瓣，切末","奇波特雷辣椒酱2汤匙或干奇波特雷辣椒2个","孜然粉1汤匙和烟熏甜椒粉1汤匙","植物油2汤匙","盐和黑胡椒"],"en":["500g beef mince (min. 20% fat)","400g canned red kidney beans, drained","400g canned chopped tomatoes","2 large onions, chopped","3 garlic cloves, minced","2 tbsp chipotle paste or 2 dried chipotle chillies, rehydrated","1 tbsp ground cumin and 1 tbsp smoked paprika","2 tbsp vegetable oil","salt and black pepper"],"ro":["500g carne de vită tocată (min. 20% grăsime)","400g fasole roșie kidney la conservă, scursă","400g roșii tocate la conservă","2 cepe mari, tocate","3 căței de usturoi, tocați","2 linguri pastă de chipotle sau 2 ardei iuți uscați","1 lingură chimen măcinat și 1 lingură boia afumată","2 linguri ulei vegetal","sare și piper negru"]},"howIsMade":{"zh":"在大锅中以大火加热油。分两批将牛肉馅炒至焦香，用锅铲将其分散——要的是小块焦糖化的肉，而非一大块灰色的蒸肉。取出备用。用同样的油炒洋葱8分钟。加入大蒜、孜然和烟熏甜椒粉，翻炒1分钟。加入奇波特雷辣椒酱、番茄、豆类、炒好的肉和200毫升水。煮沸后转小火，半盖锅盖炖45-60分钟。如果太稀，最后15分钟敞盖收汁。调整盐分。配酸奶油、切达奶酪丝、墨西哥辣椒、新鲜香菜和玉米片一起上桌。","en":"Heat the oil in a large pot over high heat. Brown the mince in two batches, breaking it up well — you want small caramelised pieces, not a grey steamed mass. Remove the meat and in the same oil, saute the onion for 8 minutes. Add garlic, cumin and smoked paprika, stir for 1 minute. Add chipotle paste, canned tomatoes, drained beans, the browned meat and 200ml water. Bring to a boil, reduce to low, partially cover and simmer 45-60 minutes, stirring occasionally. Chili should be thick, not watery — uncover for the last 15 minutes if too thin. Taste and adjust salt. Serve in bowls with sour cream, grated cheddar, sliced jalapeños, fresh coriander and tortilla chips."}},{"id":37,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"中国","en":"China","ro":"China"},"name":{"zh":"糖醋鸡","en":"Sweet and Sour Chicken","ro":"Pui dulce-acrișor"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["鸡胸肉500克，切3厘米块","玉米淀粉1汤匙（用于裹粉）","菠萝罐头200克，保留汁水","红甜椒1个和绿甜椒1个，切丁","小洋葱1个，切丁","米醋3汤匙","糖2汤匙、酱油2汤匙、番茄酱1汤匙","植物油2汤匙加香油1茶匙"],"en":["500g chicken breast, cut into 3cm pieces","1 tbsp cornstarch (for coating)","200g canned pineapple chunks, juice reserved","1 red and 1 green bell pepper, diced","1 small onion, diced","3 tbsp rice vinegar","2 tbsp sugar, 2 tbsp soy sauce, 1 tbsp ketchup","2 tbsp vegetable oil plus 1 tsp sesame oil"],"ro":["500g piept de pui, tăiat cuburi de 3 cm","1 lingură amidon de porumb (pentru acoperire)","200g bucăți de ananas la conservă, sucul rezervat","1 ardei roșu și 1 ardei verde, tăiați cuburi","1 ceapă mică, tăiată cuburi","3 linguri oțet de orez","2 linguri zahăr, 2 linguri sos de soia, 1 lingură ketchup","2 linguri ulei vegetal plus 1 linguriță ulei de susan"]},"howIsMade":{"zh":"先调酱汁：将米醋、糖、酱油、番茄酱和3汤匙菠萝汁混合。将鸡肉裹上玉米淀粉，抖去多余。在炒锅或大平底锅中以大火加热植物油。分批将鸡肉炒4-5分钟至金黄酥脆。取出备用。同一炒锅中再加少许油，大火炒洋葱2分钟，加入彩椒再炒2分钟——保持爽脆。加入菠萝和酱汁，大火烧沸1-2分钟至浓稠发亮。放回鸡肉，全部翻炒均匀。淋上香油。立即配白米饭上桌。","en":"Make the sauce first: mix rice vinegar, sugar, soy sauce, ketchup and 3 tbsp of the pineapple juice. Toss the chicken pieces in cornstarch and shake off excess. Heat vegetable oil in a wok or large skillet over high heat. Fry the chicken in batches for 4-5 minutes until crisp and golden — do not crowd the pan. Set aside. In the same wok, add a little more oil and stir-fry the onion 2 minutes, add the peppers and cook 2 more minutes on high — they should stay crisp. Add the pineapple, pour in the sauce and bubble for 1-2 minutes until thick and glossy. Return the chicken and toss everything together. Finish with sesame oil. Serve immediately over steamed rice."}},{"id":38,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"zh":"澳大利亚","en":"Australia","ro":"Australia"},"name":{"zh":"帕夫洛娃蛋糕","en":"Pavlova","ro":"Pavlova"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["4个大蛋清，室温","220克细砂糖","2茶匙玉米淀粉","1茶匙白葡萄酒醋","1茶匙香草精","300毫升淡奶油（至少35%脂肪），打发用","200克新鲜草莓，切片","2个百香果，挖出果肉"],"en":["4 large egg whites, room temperature","220g caster sugar","2 tsp cornstarch","1 tsp white wine vinegar","1 tsp vanilla extract","300ml double cream, for whipping","200g fresh strawberries, sliced","2 passion fruits, pulp scooped"],"ro":["4 albușuri mari, la temperatura camerei","220g zahăr fin (caster sugar)","2 lingurițe amidon de porumb","1 linguriță oțet de vin alb","1 linguriță extract de vanilie","300ml smântână pentru frișcă (min. 35% grăsime)","200g căpșuni proaspete, feliate","2 fructe ale pasiunii, pulpă"]},"howIsMade":{"zh":"烤箱预热至120°C，在烘焙纸上画一个22厘米的圆。将蛋清加一撮盐打发至软性发泡。逐勺加入细砂糖，每次都要充分打发——需要8-10分钟，直到蛋白霜光亮坚挺、手指捻捏无糖粒感。用橡皮刮刀轻轻拌入玉米淀粉、醋和香草精。将蛋白霜堆在圆形区域上，边缘略高于中心。烤90分钟，外壳应干燥且呈淡奶油色。关掉烤箱，将帕夫洛娃留在炉内开一条缝冷却至少2小时。上桌前将淡奶油打发至软性发泡，抹在蛋白霜上，放上草莓和百香果果肉即可。","en":"Preheat oven to 120°C and trace a 22cm circle on baking paper. Whisk egg whites with a pinch of salt to soft peaks. Add caster sugar one tablespoon at a time, whisking well after each addition — takes 8-10 minutes until the meringue is glossy, stiff, and has no sugar grains when rubbed between fingers. Fold in cornstarch, vinegar, and vanilla with a spatula. Mound the meringue onto the paper circle, building the sides slightly higher than the centre. Bake 90 minutes — the shell should be dry and faintly cream-coloured. Turn off oven and leave the pavlova to cool completely inside with the door ajar, at least 2 hours. Just before serving, whip cream to soft peaks and spread over the meringue. Top with strawberries and passion fruit pulp."}},{"id":39,"servings":4,"tipType":"def","pairingsType":"def","origin":{"zh":"加拿大","en":"Canada","ro":"Canada"},"name":{"zh":"肉汁芝士薯条","en":"Poutine","ro":"Poutine"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["800克赤褐色马铃薯或类似品种，去皮","150克新鲜奶酪凝块（cheese curds），室温","2汤匙无盐黄油","2汤匙中筋面粉","500毫升牛肉高汤，热","1茶匙伍斯特酱","植物油适量，用于炸制","盐和黑胡椒"],"en":["800g Russet or Maris Piper potatoes, peeled","150g fresh cheese curds, room temperature","2 tbsp unsalted butter","2 tbsp plain flour","500ml beef stock, hot","1 tsp Worcestershire sauce","vegetable oil for frying","salt and black pepper"],"ro":["800g cartofi Russet sau Desiree, curatati","150g cas proaspat (cheese curds), la temperatura camerei","2 linguri unt nesarat","2 linguri făină alba","500ml supa de vita, fierbinte","1 lingurita sos Worcestershire","ulei vegetal pentru prajit","sare si piper negru"]},"howIsMade":{"zh":"将土豆切成1厘米厚的条状，在冷水中浸泡30分钟去除淀粉——这是让薯条酥脆的关键。彻底擦干。第一次炸：油温加热至150°C，炸5-6分钟至熟透但不上色。沥油后静置10分钟。第二次炸：油温升至190°C，炸3-4分钟至金黄酥脆。立即撒盐调味。制作肉汁：中火融化黄油，加入面粉炒2分钟至微金黄色。逐步加入热牛肉高汤，持续搅拌至浓稠，约3-4分钟。加入伍斯特酱，调味。将热薯条堆入深碗，撒上室温奶酪凝块，立即浇上热肉汁——高温会部分融化奶酪同时保留其特有的嚼劲。","en":"Cut potatoes into 1cm batons and soak in cold water for 30 minutes to remove starch — this is what makes them crispy. Dry thoroughly. First fry: heat oil to 150°C and fry potatoes 5-6 minutes until cooked through but without colour. Drain and rest 10 minutes. Second fry: heat oil to 190°C and fry 3-4 minutes until golden and very crispy. Season immediately with salt. For the gravy: melt butter over medium heat, add flour and cook 2 minutes stirring — it should turn pale golden. Add hot stock gradually, whisking constantly until thickened, 3-4 minutes. Add Worcestershire, season. Pile hot fries into a deep bowl, scatter room-temperature cheese curds over, and immediately pour the hot gravy on top — the heat partially melts the curds while keeping their signature squeak."}},{"id":40,"servings":4,"tipType":"def","pairingsType":"def","origin":{"zh":"波兰","en":"Poland","ro":"Polonia"},"name":{"zh":"波兰饺子","en":"Pierogi","ro":"Pierogi"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cina"},"ingredients":{"zh":["中筋面粉300克，另备撒粉用","大鸡蛋1个加温水150毫升（和面用）","粉质土豆500克，煮熟捣泥","农场奶酪（twaróg）或干茅屋奶酪200克","中等洋葱2个，切细丁","无盐黄油40克","熏培根丁100克","盐、白胡椒及新鲜细香葱适量，供上桌用"],"en":["300g plain flour, plus extra for dusting","1 large egg plus 150ml warm water (for dough)","500g floury potatoes, boiled and mashed","200g farmer's cheese (twarog) or dry cottage cheese","2 medium onions, finely diced","40g unsalted butter","100g smoked bacon lardons","salt, white pepper and fresh chives to serve"],"ro":["300g făină alba, plus extra pentru intins","1 ou mare plus 150ml apa calda (pentru aluat)","500g cartofi fainosi, fierti si zdrobiti","200g branza de vaci (twarog) sau branza proaspata","2 cepe medii, taiate marunt","40g unt nesarat","100g bacon afumat, taiat cubulete","sare, piper alb si ceapa verde proaspata pentru servit"]},"howIsMade":{"zh":"面粉与鸡蛋和温水混合，揉5分钟至光滑有弹性，盖上保鲜膜静置30分钟。土豆煮软后与农场奶酪、盐、白胡椒一起捣泥。平底锅中用黄油将一半洋葱炒至金黄（10分钟），拌入馅料。面团擀至3毫米厚，切出8厘米圆片。每片放一茶匙馅料，对折后用手指或叉子将边缘压紧密封。放入盐水中煮3-4分钟，浮起即熟。同时将培根煎至酥脆，加入剩余洋葱煸香。将煮好的饺子放入黄油锅中，每面煎2-3分钟至金黄。配培根、煎洋葱和酸奶油上桌。","en":"Mix flour with egg and warm water, knead 5 minutes to a smooth, elastic dough, cover and rest 30 minutes. Boil potatoes until tender, mash with farmer's cheese, salt and white pepper. In a pan, fry half the onion in butter until golden (10 min), stir into filling. Roll dough to 3mm, cut 8cm circles. Place a teaspoon of filling on each disc, fold in half and seal the edges firmly by pressing with fingers or a fork. Boil in salted water 3-4 minutes — they float when done. Meanwhile, fry bacon until crisp, add remaining onion and brown. Pan-fry the boiled pierogi in butter 2-3 minutes per side until golden patches appear. Serve with bacon, fried onion and sour cream."}},{"id":41,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"印度尼西亚","en":"Indonesia","ro":"Indonezia"},"name":{"zh":"印尼炒饭","en":"Nasi Goreng","ro":"Nasi Goreng"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["4杯隔夜茉莉香米饭","鸡腿肉300克，切成1厘米小块，去骨","鸡蛋4个","小葱头（沙葱）4个，切薄片","大蒜4瓣，切末","红色朝天椒2个，切薄片","甜酱油（kecap manis）2汤匙","普通酱油1汤匙","虾膏（terasi）1茶匙，烤香","植物油3汤匙","盐和白胡椒粉适量","黄瓜片和油炸小葱头，用于上桌"],"en":["4 cups day-old cooked jasmine rice","300 g boneless chicken thigh, cut into 1 cm cubes","4 eggs","4 shallots, thinly sliced","4 garlic cloves, minced","2 red bird's eye chillies, thinly sliced","2 tbsp kecap manis (sweet soy sauce)","1 tbsp soy sauce","1 tsp shrimp paste (terasi), toasted","3 tbsp vegetable oil","salt and white pepper to taste","cucumber slices and fried shallots to serve"],"ro":["4 căni orez jasmin fiert în ziua precedentă","300 g pulpă de pui dezosată, tăiată cubulețe de 1 cm","4 ouă","4 eșalote, feliate subțire","4 căței de usturoi, tocați","2 ardei iuți roșii, feliați subțire","2 linguri kecap manis (sos de soia dulce)","1 lingură sos de soia","1 linguriță pastă de creveți (terasi), prăjită","3 linguri ulei vegetal","sare și piper alb după gust","felii de castravete și eșalote prăjite pentru servire"]},"howIsMade":{"zh":"用手将冷饭揉散，打散结块。在炒锅中用大火热1汤匙油至冒烟。加入鸡肉翻炒3–4分钟至熟透微金黄色，取出备用。锅中加入剩余2汤匙油。加入小葱头翻炒2分钟至变软。加入大蒜、辣椒和虾膏，翻炒1分钟至香味浓郁。加入米饭铺成均匀一层，静置1分钟让底部微微结焦，然后大力翻炒2–3分钟。将鸡肉回锅，加入甜酱油和普通酱油翻拌均匀。用盐和白胡椒粉调味。将米饭拨到一侧，打入鸡蛋轻轻炒散，然后与米饭混合再炒1分钟至蛋刚刚凝固。盛入碗中，摆上黄瓜片和油炸小葱头即可上桌。","en":"Break up the cold rice with your hands to separate any clumps. Heat 1 tbsp of oil in a wok over high heat until smoking. Add the chicken cubes and stir-fry for 3–4 minutes until cooked through and lightly golden; remove and set aside. Add the remaining 2 tbsp of oil to the wok. Add the shallots and stir-fry for 2 minutes until softened. Add the garlic, chilli, and shrimp paste and stir-fry for 1 minute until fragrant. Add the rice, spread into an even layer, and leave untouched for 1 minute to form a slight crust, then toss vigorously for 2–3 minutes. Return the chicken, add the kecap manis and soy sauce, and toss to coat evenly. Season with salt and white pepper. Push the rice to the side, crack in the eggs, scramble briefly, then fold into the rice and cook for 1 minute until just set. Serve in bowls topped with cucumber slices and fried shallots."}},{"id":42,"servings":4,"tipType":"def","pairingsType":"def","origin":{"zh":"瑞士","en":"Switzerland","ro":"Elveția"},"name":{"zh":"奶酪火锅","en":"Fondue","ro":"Fondue"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["格律耶尔奶酪400克，粗磨碎","埃曼塔尔奶酪200克，粗磨碎","大蒜1瓣，切两半","干白葡萄酒（芬达或沙斯拉品种）300毫升","玉米淀粉1汤匙","樱桃白兰地（基尔希酒）2汤匙","新鲜磨碎的肉豆蔻一小撮","现磨黑胡椒粉适量","大法棍1条（约500克），切成2厘米小块","小腌黄瓜和新煮小土豆用于蘸食"],"en":["400 g Gruyère, coarsely grated","200 g Emmental, coarsely grated","1 garlic clove, halved","300 ml dry white wine (Fendant or Chasselas)","1 tbsp cornstarch","2 tbsp kirsch (cherry brandy)","a pinch of freshly grated nutmeg","freshly ground black pepper to taste","1 large crusty baguette (about 500 g), cut into 2 cm cubes","cornichons and boiled new potatoes to serve"],"ro":["400 g Gruyère, ras grosier","200 g Emmental, ras grosier","1 cățel de usturoi, tăiat pe jumătate","300 ml vin alb sec (Fendant sau Chasselas)","1 lingură amidon de porumb","2 linguri kirsch (rachiu de cireșe)","un praf de nucșoară rasă proaspăt","piper negru proaspăt măcinat după gust","1 baghetă mare crocantă (cca. 500 g), tăiată cubulețe de 2 cm","cornișoni și cartofi noi fierți pentru servire"]},"howIsMade":{"zh":"用大蒜的切面摩擦奶酪火锅锅内壁；丢掉大蒜。将葡萄酒倒入锅中，用中火加热至接近沸腾。将磨好的格律耶尔和埃曼塔尔奶酪与玉米淀粉混合均匀。分三批将奶酪加入温热葡萄酒中，每次加入后用画8字的方式搅拌至完全融化顺滑，总共约8–10分钟。加入基尔希酒、肉豆蔻和黑胡椒；奶酪火锅应达到能裹住勺子的浓稠度。将锅放在奶酪火锅炉上调至最小火，保持轻微沸腾。用长叉串上面包块，旋转着浸入奶酪中，确保叉子触及锅底以防止底部结焦。搭配小腌黄瓜和新煮小土豆上桌。","en":"Rub the inside of a fondue pot with the cut sides of the garlic clove; discard the garlic. Pour the wine into the pot and heat over medium heat until just below simmering. Toss the grated Gruyère and Emmental with the cornstarch until evenly coated. Add the cheese to the warm wine in three batches, stirring in a figure-eight motion after each addition until fully melted and smooth, about 8–10 minutes total. Stir in the kirsch, nutmeg, and a grind of black pepper; the fondue should be thick enough to coat a spoon. Place the pot over a fondue burner set to low to keep it gently bubbling. Spear bread cubes on fondue forks and swirl into the cheese, reaching the bottom of the pot to prevent a crust from forming. Serve with cornichons and boiled new potatoes."}},{"id":43,"servings":4,"tipType":"fish","pairingsType":"middle-eastern","origin":{"zh":"伊拉克","en":"Iraq","ro":"Irak"},"name":{"zh":"烤鱼","en":"Masgouf","ro":"Masgouf"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["整条鲤鱼或鲈鱼1条（约1.5千克），去内脏清洗干净","橄榄油4汤匙","盐1茶匙","姜黄粉1茶匙","孜然粉1茶匙","番茄2个，粗略切碎","柠檬1个，切片","大蒜4瓣，切末","小洋葱1个，粗略切碎","番茄酱2汤匙","现磨黑胡椒粉适量","薄饼4张，用于上桌","切片洋葱、番茄和腌菜，用于上桌"],"en":["1 whole carp or sea bass (about 1.5 kg), gutted and cleaned","4 tbsp olive oil","1 tsp salt","1 tsp ground turmeric","1 tsp ground cumin","2 tomatoes, roughly chopped","1 lemon, sliced","4 garlic cloves, minced","1 small onion, roughly chopped","2 tbsp tomato paste","freshly ground black pepper to taste","4 flatbreads to serve","sliced onion, tomato, and pickles to serve"],"ro":["1 crap sau biban întreg (cca. 1,5 kg), curățat și eviscerat","4 linguri ulei de măsline","1 linguriță sare","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","2 roșii, tăiate grosier","1 lămâie, feliată","4 căței de usturoi, tocați","1 ceapă mică, tocată grosier","2 linguri pastă de roșii","piper negru proaspăt măcinat după gust","4 pâini plate pentru servire","ceapă feliată, roșii și murături pentru servire"]},"howIsMade":{"zh":"用锋利的刀沿着脊骨深切，将鱼展开铺平。在鱼肉上每隔4厘米斜划一刀。将橄榄油、姜黄粉、孜然粉、盐和胡椒混合，涂抹在鱼肉两面和腹腔内部。在室温下腌制20分钟。同时，将番茄、洋葱、大蒜、柠檬片和番茄酱混合制成刷抹酱。将鱼串在两根长签子上保持展开状态。在燃烧的木炭余烬上（避免直接明火）烤30–40分钟：先肉面朝下烤20分钟，直到鱼肉变白并与骨头分离，再翻面鱼皮朝下烤10–15分钟至皮脆。每5分钟刷一次酱料。配薄饼、切片洋葱、番茄和腌菜立即上桌。","en":"Using a sharp knife, make a deep cut along the backbone to butterfly the fish open flat. Score the flesh diagonally every 4 cm. Mix the olive oil, turmeric, cumin, salt, and pepper; rub all over the flesh and inside the cavity. Leave to marinate for 20 minutes at room temperature. Meanwhile, combine the tomatoes, onion, garlic, lemon slices, and tomato paste to make the basting sauce. Thread the fish onto two long skewers (or use a fish grill basket) to hold it flat. Grill over glowing wood embers or charcoal (not open flames) for 30–40 minutes: flesh side down for the first 20 minutes until the flesh is opaque and pulls away from the bone, then skin side down for 10–15 minutes until the skin is crisp. Baste with the sauce every 5 minutes. Serve immediately with flatbread, sliced onion, tomato, and pickles."}},{"id":44,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"zh":"以色列","en":"Israel","ro":"Israel"},"name":{"zh":"莎克舒卡","en":"Shakshuka","ro":"Shakshuka"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"zh":["橄榄油2汤匙","大洋葱1个，细切","红甜椒1个，细切","大蒜4瓣，切末","孜然粉1茶匙","甜椒粉1茶匙","烟熏辣椒粉½茶匙","辣椒片¼茶匙","碎番茄罐头2罐（每罐400克）","糖1茶匙","盐和现磨黑胡椒粉适量","鸡蛋6个","新鲜欧芹或香菜一小把，粗略切碎","脆皮面包或皮塔饼，用于上桌"],"en":["2 tbsp olive oil","1 large onion, finely diced","1 red bell pepper, finely diced","4 garlic cloves, minced","1 tsp ground cumin","1 tsp sweet paprika","½ tsp smoked paprika","¼ tsp chilli flakes","2 x 400 g cans crushed tomatoes","1 tsp sugar","salt and freshly ground black pepper to taste","6 eggs","a small handful of fresh flat-leaf parsley or coriander, roughly chopped","crusty bread or pita to serve"],"ro":["2 linguri ulei de măsline","1 ceapă mare, tăiată mărunt","1 ardei kapia roșu, tăiat mărunt","4 căței de usturoi, tocați","1 linguriță chimen măcinat","1 linguriță boia dulce","½ linguriță boia afumată","¼ linguriță fulgi de ardei iute","2 x 400 g roșii zdrobite la conservă","1 linguriță zahăr","sare și piper negru proaspăt măcinat după gust","6 ouă","o mână de frunze de pătrunjel sau coriandru, tocate grosier","pâine crocantă sau pita pentru servire"]},"howIsMade":{"zh":"在宽深煎锅中用中火加热橄榄油。加入洋葱和红甜椒，偶尔搅拌，煮8分钟至变软并开始上色。加入大蒜、孜然粉、两种椒粉和辣椒片，翻炒1分钟至香味溢出。倒入碎番茄，加入糖，用盐和黑胡椒大方调味。小火炖10分钟至酱汁变浓。用勺子在酱汁中挖出6个小窝。将每个鸡蛋打入一个小窝，盖上锅盖，煮8–10分钟至蛋白刚凝固但蛋黄仍流动。撒上欧芹或香菜，配脆皮面包或皮塔饼立即上桌。","en":"Heat the olive oil in a wide, deep frying pan over medium heat. Add the onion and red pepper and cook, stirring occasionally, for 8 minutes until softened and beginning to colour. Add the garlic, cumin, sweet paprika, smoked paprika, and chilli flakes and stir for 1 minute until fragrant. Pour in the crushed tomatoes, add the sugar, and season generously with salt and pepper. Simmer for 10 minutes, stirring occasionally, until the sauce thickens and deepens in colour. Make 6 wells in the sauce with a spoon. Crack one egg into each well, then cover the pan with a lid and cook for 8–10 minutes until the whites are just set but the yolks are still runny. Scatter the parsley or coriander over the top and serve immediately from the pan with crusty bread or pita."}},{"id":45,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"zh":"芬兰","en":"Finland","ro":"Finlanda"},"name":{"zh":"三文鱼汤","en":"Salmon Soup","ro":"Lohikeitto"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["新鲜三文鱼柳600克，去皮，切成3厘米块","蜡质土豆500克（夏洛特品种或类似），去皮切2厘米方块","大韭葱1根，白色和浅绿色部分，切细圈","中等胡萝卜2根，去皮切5毫米厚圆片","优质鱼汤1升","淡奶油200毫升","月桂叶1片","完整多香果5粒","细海盐1茶匙，可酌量增加","白胡椒粉¼茶匙","新鲜莳萝1大把（约30克），粗略切碎"],"en":["600 g fresh salmon fillet, skin removed, cut into 3 cm chunks","500 g waxy potatoes (Charlotte or similar), peeled and cut into 2 cm cubes","1 large leek, white and pale-green parts, thinly sliced into rings","2 medium carrots, peeled and sliced 5 mm thick","1 litre good-quality fish stock","200 ml double cream","1 bay leaf","5 whole allspice berries","1 tsp fine sea salt, plus more to taste","¼ tsp ground white pepper","1 large bunch fresh dill (about 30 g), roughly chopped"],"ro":["600 g file de somon proaspăt, fără piele, tăiat cuburi de 3 cm","500 g cartofi cu pulpă fermă (Charlotte sau similari), curățați, cuburi de 2 cm","1 praz mare, partea albă și verde deschis, tăiat rondele subțiri","2 morcovi medii, curățați, rondele de 5 mm","1 litru supă de pește bine aromatizată","200 ml smântână dulce pentru gătit","1 frunză de dafin","5 boabe de ienibahar","1 linguriță sare fină, plus după gust","¼ linguriță piper alb măcinat","1 mănunchi mare de mărar proaspăt (cca 30 g), tocat grosier"]},"howIsMade":{"zh":"将鱼汤倒入大锅中，用中火烧至轻微沸腾。加入土豆、胡萝卜、韭葱、月桂叶和多香果。用小火炖12–15分钟，直至土豆用刀刺入时刚好变软。将火调至最低——汤汁应微微颤动，不要沸腾。加入三文鱼块，煮4–5分钟，直至鱼肉刚变不透明，轻轻触碰即可剥落成片。倒入奶油，加热2分钟，不要沸腾。用盐和白胡椒粉调味。取出月桂叶和多香果。盛入温热的碗中，在每份上堆上大量新鲜莳萝。配黑麦面包享用。","en":"Pour the fish stock into a large pot and bring to a gentle simmer over medium heat. Add the potatoes, carrots, leek, bay leaf, and allspice berries. Cook at a gentle simmer for 12–15 minutes until the potatoes are just tender when pierced with a knife. Lower the heat so the stock barely trembles — do not boil. Add the salmon chunks and cook for 4–5 minutes until the fish is just opaque and flakes easily when nudged. Stir in the cream and heat for 2 minutes without letting it boil. Season with salt and white pepper. Remove the bay leaf and allspice berries. Ladle into warmed bowls and heap each portion with a generous amount of fresh dill. Serve with dark rye bread alongside."}},{"id":46,"servings":4,"tipType":"meat","timeMins":{"total":300,"active":60},"pairingsType":"middle-eastern","origin":{"zh":"伊朗","en":"Iran","ro":"Iran"},"name":{"zh":"波斯香草炖牛肉","en":"Ghormeh Sabzi","ro":"Ghormeh Sabzi"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["无骨羊肩肉（或炖用牛肉）700克，切成4厘米方块","干红腰豆200克，隔夜浸泡后沥干（或400克罐装，沥干）","大洋葱1个，细切","新鲜胡芦巴叶80克（或干胡芦巴粉3汤匙 / 葫芦巴）","新鲜扁叶香菜100克，细切","新鲜香菜80克，细切","新鲜菠菜50克，细切","波斯干青柠（Limoo Amani）4个，用竹签扎孔","姜黄粉1茶匙","黑胡椒粉½茶匙","细海盐1茶匙，可酌量增加","植物油3汤匙，分开使用"],"en":["700 g boneless lamb shoulder (or beef chuck), cut into 4 cm cubes","200 g dried red kidney beans, soaked overnight and drained (or 400 g canned, drained)","1 large onion, finely diced","80 g fresh fenugreek leaves (or 3 tbsp dried fenugreek / kasuri methi)","100 g fresh flat-leaf parsley, finely chopped","80 g fresh coriander (cilantro), finely chopped","50 g fresh spinach, finely chopped","4 dried Persian limes (limoo amani), pierced with a skewer","1 tsp ground turmeric","½ tsp ground black pepper","1 tsp fine sea salt, plus more to taste","3 tbsp vegetable oil, divided"],"ro":["700 g carne de miel fără os (spată) sau vită pentru tocăniță, tăiată cuburi de 4 cm","200 g fasole boabe roșie uscată, hidratată peste noapte și scursă (sau 400 g la conservă, scursă)","1 ceapă mare, tăiată mărunt","80 g frunze proaspete de schinduf (sau 3 linguri schinduf uscat / kasoori methi)","100 g pătrunjel frunze plate proaspăt, tocat mărunt","80 g coriandru proaspăt, tocat mărunt","50 g spanac proaspăt, tocat mărunt","4 lămâi persane uscate (limoo amani), înțepate cu un frigărui","1 linguriță turmeric măcinat","½ linguriță piper negru măcinat","1 linguriță sare fină, plus după gust","3 linguri ulei vegetal, separat"]},"howIsMade":{"zh":"大重锅中用中大火加热1汤匙油、分两批将肉块煎至四面深棕色，每批3–4分钟。取出备用、同锅用中火炒洋葱8分钟至金黄。加入姜黄粉和黑胡椒翻炒1分钟、肉块归锅，加入沥干的腰豆和扎孔的青柠。倒水刚好盖过食材、大火烧开，撇去浮沫，转最小火。同时，在另一口大煎锅中用剩余油，大火翻炒所有香草（葫芦巴、香菜、香菜叶、菠菜）15–20分钟，不断翻炒直至颜色变深绿色且所有水分蒸发——这是关键一步，奠定了这道菜浓郁的风味、将炒好的香草拌入炖锅。加盐调味、盖锅用最小火炖2–2.5小时（干豆）或1.5小时（罐装），中途偶尔搅拌，直至肉质酥烂、盛在蒸好的香米上享用。","en":"Heat 1 tbsp oil in a large heavy pot over medium-high heat; brown the meat in two batches, 3–4 minutes per batch, until deep brown on all sides. Remove and set aside; in the same pot, cook the onion over medium heat for 8 minutes until golden. Add the turmeric and black pepper; stir for 1 minute; return the meat to the pot. Add the drained kidney beans and pierced dried limes; pour over just enough water to barely cover. Bring to the boil, skim the foam, then reduce to the lowest possible simmer; meanwhile, heat the remaining 2 tbsp oil in a large frying pan over medium-high heat. Add all the herbs (fenugreek, parsley, coriander, spinach) and stir-fry for 15–20 minutes, until the herbs turn very dark green and all moisture has fully evaporated — this step is critical and builds the stew's characteristic deep flavour; stir the fried herbs into the stew. Season with salt; cover and simmer on the lowest heat for 2–2.5 hours (if using dried beans) or 1.5 hours (canned beans), stirring occasionally, until the meat is very tender and pulls apart easily. The stew should be thick and deeply coloured; serve over steamed basmati rice."}},{"id":47,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"zh":"葡萄牙","en":"Portugal","ro":"Portugalia"},"name":{"zh":"布拉什鳕鱼","en":"Bacalhau à Brás","ro":"Bacalhau à Brás"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["500克盐腌鳕鱼，冷水浸泡24–48小时并撕成鱼片","600克蜡质土豆，去皮切成极细的火柴棍条","6个大鸡蛋，轻轻打散","2个中等白洋葱，切薄片","4汤匙特级初榨橄榄油","3瓣大蒜，切薄片","一小束新鲜平叶欧芹，粗略切碎","80克去核黑橄榄","盐和白胡椒粉适量"],"en":["500g salted cod (bacalhau), soaked 24–48h in cold water and shredded into flakes","600g waxy potatoes, peeled and cut into very thin matchstick strips","6 large eggs, lightly beaten","2 medium white onions, thinly sliced","4 tbsp extra-virgin olive oil","3 garlic cloves, thinly sliced","Small bunch of fresh flat-leaf parsley, roughly chopped","80g black olives, pitted, to serve","Salt and white pepper to taste"],"ro":["500g cod sărat (bacalhau), înmuiat 24–48h și desfăcut în fâșii","600g cartofi cerați, curățați și tăiați în bețișoare foarte subțiri","6 ouă mari, ușor bătute","2 cepe medii albe, tăiate felii subțiri","4 linguri ulei de măsline extravirgin","3 căței de usturoi, tăiați felii subțiri","Legătură mică de pătrunjel proaspăt, tocat grosier","80g măsline negre, fără sâmburi","Sare și piper alb"]},"howIsMade":{"zh":"将鳕鱼碎在冷水中浸泡，24–48小时内换四次水，直到小块鱼肉有令人愉悦的咸鲜味、沥水擦干。将土豆切成极细的火柴棍条、中性油2厘米加热至170°C，分批炸薯条3–4分钟至淡金色。沥油置于厨房纸上，弃去炸油，擦净锅、中小火热橄榄油，翻炒洋葱和大蒜，频繁搅拌12–15分钟至软烂略金黄。加入鳕鱼翻炒2分钟、放入薯条轻轻翻匀。倒入用白胡椒调味的蛋液、小火持续以宽大缓慢的折叠动作搅拌2–3分钟——蛋液应形成柔软奶油质感，绝不干硬。蛋液看起来仍稍未熟时离火，余温完成最后加热、品尝盐分、撒上欧芹，配黑橄榄上桌。","en":"Soak the shredded cod in cold water, changing the water four times over 24–48 hours until a small piece tastes pleasantly savoury rather than sharp; drain and pat dry. Cut potatoes into very thin matchstick strips; heat 2cm of neutral oil in a deep frying pan to 170°C and fry the potato strips in batches for 3–4 minutes until pale golden; drain on paper. Discard the frying oil and wipe the pan; heat olive oil over medium-low heat and cook the onion and garlic, stirring often, for 12–15 minutes until very soft and lightly golden. Add the cod flakes and stir for 2 minutes until warmed through; tip in the potato strips and toss once. Pour in the beaten eggs seasoned with white pepper; stir continuously over low heat with slow, wide folds for 2–3 minutes — the eggs should set in soft, creamy layers, never dry or granular. Remove from heat while the eggs still look slightly underdone; residual heat finishes the dish; taste for salt before adding any — the cod may already hold enough; scatter with parsley and serve straight from the pan with black olives alongside."}},{"id":48,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"菲律宾","en":"Philippines","ro":"Filipine"},"name":{"zh":"阿多波炖肉","en":"Adobo","ro":"Adobo"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["带骨带皮鸡大腿和小腿1.2千克（或猪五花肉1千克，切4厘米方块）","大蒜6瓣，拍碎","甘蔗醋或白葡萄酒醋125毫升","酱油80毫升","月桂叶3片","完整黑胡椒粒1茶匙","水80毫升","植物油2汤匙"],"en":["1.2 kg chicken thighs and drumsticks, bone-in skin-on (or 1 kg pork belly cut into 4 cm cubes)","6 garlic cloves, crushed","125 ml cane vinegar or white wine vinegar","80 ml soy sauce","3 bay leaves","1 tsp whole black peppercorns","80 ml water","2 tbsp vegetable oil"],"ro":["1,2 kg pulpe și tobe de pui (cu os, cu piele) sau 1 kg burtă de porc tăiată cuburi de 4 cm","6 căței de usturoi, zdrobiți","125 ml oțet de trestie sau oțet alb de vin","80 ml sos de soia","3 frunze de dafin","1 linguriță boabe de piper negru","80 ml apă","2 linguri ulei vegetal"]},"howIsMade":{"zh":"将鸡肉（或猪肉）、大蒜、醋、酱油、月桂叶、黑胡椒粒和水放入大锅中。在室温下腌制30分钟。不要搅拌，中大火烧开。沸腾后转小火，盖锅炖30分钟（鸡肉）或45分钟（猪肉），直至肉质变软。揭盖，转中火。继续炖，偶尔翻动，15–20分钟直至酱汁浓缩成光亮浓稠的酱料，能挂在勺背上。另取一锅，大火热油。将鸡块皮朝下放入，煎3–4分钟至皮面金黄酥脆。放回酱汁中翻拌均匀。取出月桂叶。盛在白米饭上享用。","en":"Combine the chicken (or pork), garlic, vinegar, soy sauce, bay leaves, peppercorns, and water in a large pot. Marinate for 30 minutes at room temperature. Bring to the boil over medium-high heat without stirring. Once boiling, reduce heat to low, cover, and simmer for 30 minutes (chicken) or 45 minutes (pork) until the meat is tender. Uncover and increase heat to medium. Continue simmering, turning the meat occasionally, for 15–20 minutes until the sauce reduces to a glossy, thick glaze that coats the back of a spoon. In a separate pan, heat the oil over high heat. Add the cooked pieces skin-side down and fry for 3–4 minutes until the skin is golden brown and crisp. Return to the sauce and toss to coat. Discard bay leaves. Serve over steamed white rice."}},{"id":49,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"牙买加","en":"Jamaica","ro":"Jamaica"},"name":{"zh":"牙买加辣鸡","en":"Jerk Chicken","ro":"Jerk Chicken"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["鸡腿和鸡棒腿1.5公斤，带皮，用刀深深划花","葱6根，粗切","苏格兰帽椒或哈瓦那椒3个，去籽","大蒜5瓣","新鲜生姜2厘米段，去皮","深色酱油2汤匙","红糖2汤匙","多香果粉1汤匙","干百里香1茶匙","肉桂粉½茶匙","黑胡椒½茶匙","植物油2汤匙","2个青柠汁，外加青柠角上桌"],"en":["1.5kg chicken thighs and drumsticks, skin-on, scored deeply with a knife","6 spring onions, roughly chopped","3 Scotch bonnet chilies or habaneros, seeds removed for moderate heat","5 garlic cloves","2cm piece fresh ginger, peeled","2 tbsp dark soy sauce","2 tbsp brown sugar","1 tbsp ground allspice","1 tsp dried thyme","½ tsp ground cinnamon","½ tsp black pepper","2 tbsp vegetable oil","Juice of 2 limes, plus wedges to serve"],"ro":["1,5 kg pulpe și copane de pui, cu piele, crestați adânc","6 fire ceapă verde, tăiate grosier","3 ardei Scotch bonnet (sau habanero), semințele îndepărtate","5 căței de usturoi","Bucată de 2cm ghimbir proaspăt, curățat","2 linguri sos de soia închis la culoare","2 linguri zahăr brun","1 lingură ienibahar măcinat","1 linguriță cimbru uscat","½ linguriță scorțișoară măcinată","½ linguriță piper negru","2 linguri ulei vegetal","Suc de la 2 lămi verzi, plus felii pentru servire"]},"howIsMade":{"zh":"将葱、苏格兰帽椒、大蒜、生姜、酱油、红糖、多香果、百里香、肉桂、黑胡椒、油和青柠汁放入食品处理机，打成粗糙的酱料。在每块鸡肉上深划至骨，让腌料渗入——杰克风味只有在腌料进入肉中才有效。将酱料全面涂抹并压入每个切口。冷藏腌制至少4小时，最好过夜。烹饪前30分钟取出。炭火烤制：在中高温炭火上烤35–45分钟，每10分钟翻面一次，直到汁液清澈，表面部分焦黑。烤箱烤制：200°C架上烤盘烤40分钟，再在热烤架上烤5分钟使皮焦香。静置5分钟。配豆饭、炸大蕉和青柠角上桌。","en":"Blend spring onions, Scotch bonnets, garlic, ginger, soy sauce, brown sugar, allspice, thyme, cinnamon, black pepper, oil, and lime juice in a food processor until a rough paste forms. Score the chicken pieces deeply down to the bone — jerk only works if the marinade penetrates inside the meat. Rub the paste all over and into every cut. Cover and marinate in the refrigerator for at least 4 hours, ideally overnight. Remove from the fridge 30 minutes before cooking. To grill over charcoal: cook over medium-hot coals for 35–45 minutes, turning every 10 minutes, until the juices run clear and the exterior is deeply charred in places. To oven-roast: place on a rack over a baking tray at 200°C for 40 minutes, then finish under a hot grill for 5 minutes to char the skin. Allspice is the defining spice — do not substitute with mixed spice. Rest 5 minutes before serving. Serve with rice and peas, fried plantain, and lime wedges."}},{"id":50,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"埃塞俄比亚","en":"Ethiopia","ro":"Etiopia"},"name":{"zh":"埃塞俄比亚辣鸡","en":"Doro Wat","ro":"Doro Wat"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["鸡肉（大腿和小腿，带骨）1.2千克","柠檬汁3汤匙","大洋葱4个（约800克），极细切碎","埃塞俄比亚香草黄油尼特尔基比（Niter Kibbeh）或澄清黄油80克","大蒜6瓣，切末","新鲜生姜2汤匙，细擦丝（约3厘米一块）","伯贝雷香料混合4汤匙","豆蔻粉1茶匙","胡芦巴粉½茶匙","水或鸡汤250毫升","煮熟的鸡蛋4个，去壳后用叉子在表面刺孔","盐适量"],"en":["1.2 kg chicken pieces (thighs and drumsticks, bone-in)","3 tbsp lemon juice","4 large onions (about 800 g), very finely diced","80 g niter kibbeh (Ethiopian spiced butter) or clarified butter","6 garlic cloves, minced","2 tbsp fresh ginger, finely grated (about 3 cm piece)","4 tbsp berbere spice blend","1 tsp ground cardamom","½ tsp ground fenugreek","250 ml water or chicken stock","4 hard-boiled eggs, shelled and scored all over with a fork","salt to taste"],"ro":["1,2 kg piese de pui (pulpe și tobe cu os)","3 linguri suc de lămâie","4 cepe mari (cca 800 g), tăiate mărunt fin","80 g unt etiopian niter kibbeh (sau unt clarificat)","6 căței de usturoi, tocați mărunt","2 linguri ghimbir proaspăt ras (cca 3 cm bucată)","4 linguri amestec de condimente berbere","1 linguriță cardamom măcinat","½ linguriță schinduf măcinat","250 ml apă sau supă de pui","4 ouă fierte tari, curățate, înțepate cu furculița","sare după gust"]},"howIsMade":{"zh":"用叉子在鸡肉上刺满小孔，用柠檬汁擦遍全身、将细切洋葱放入大重锅，不放任何油脂，调至小火。频繁搅拌，煮25–30分钟，直至洋葱变得非常软烂、深金棕色并散发出焦糖香气——这道长时间的干炒是炖菜风味的基础、加入尼特尔基比并搅拌。加入大蒜、生姜、伯贝雷香料、豆蔻粉和胡芦巴粉、不断搅拌，煮5分钟，直至香料开放、黄油变成深红橙色。放入鸡块，翻匀裹满香料黄油、翻炒5分钟至各面封住。倒入水或鸡汤、大火烧开，转最小火。盖锅煮40–45分钟，中途翻动鸡肉，至肉质非常嫩滑、将鸡蛋用叉子刺满小孔，放入炖锅中。开盖再煮10分钟，直至鸡蛋被酱汁染红、汤汁变浓、盛在恩杰拉（埃塞俄比亚扁面包）或白米饭上享用。","en":"Prick the chicken all over with a fork and rub with lemon juice; put the finely diced onions into a large heavy pot over low heat with no oil or fat. Cook, stirring often, for 25–30 minutes until the onions are very soft, deep golden-brown, and smell caramel-like — this long dry fry builds the stew's flavour base; add the niter kibbeh and stir to coat. Add the garlic, ginger, berbere, cardamom, and fenugreek; cook for 5 minutes, stirring constantly, until the spices bloom and the butter turns deep red-orange. Add the chicken pieces and turn to coat completely; cook 5 minutes, turning, until sealed on all sides. Pour in the water or stock; bring to the boil, then reduce to the lowest simmer. Cover and cook for 40–45 minutes, turning the chicken halfway through, until the meat is very tender and nearly falling off the bone; score the eggs all over with a fork and nestle them into the sauce. Simmer uncovered for 10 more minutes until the eggs are stained red from the sauce and the sauce has thickened; season with salt; serve on injera flatbread or steamed rice."}},{"id":51,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"zh":"叙利亚","en":"Syria","ro":"Siria"},"name":{"zh":"碎肉小麦球","en":"Kibbeh","ro":"Kibbeh"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["外壳：细碎小麦（#1级）300克，洗净沥干","极瘦羊肉（或牛肉）末400克，冷藏","中等洋葱1个，细擦丝","多香果粉1茶匙","肉桂粉1茶匙","细海盐1茶匙","黑胡椒粉½茶匙","馅料：羊肉（或牛肉）末300克","中等洋葱1个，细切","松子（或腰果）80克","多香果粉1茶匙","肉桂粉½茶匙","植物油1汤匙","深炸用植物油约1升"],"en":["Shell: 300 g fine bulgur wheat (#1 grade), rinsed and drained","400 g very lean lamb (or beef) mince, chilled","1 medium onion, finely grated","1 tsp ground allspice","1 tsp ground cinnamon","1 tsp fine salt","½ tsp ground black pepper","Filling: 300 g lamb (or beef) mince","1 medium onion, finely diced","80 g pine nuts (or cashews)","1 tsp ground allspice","½ tsp ground cinnamon","1 tbsp vegetable oil","Vegetable oil for deep-frying (about 1 litre)"],"ro":["Coajă: 300 g bulgur fin (#1), clătit și scurs bine","400 g carne de miel sau vită slabă, tocată fin și răcită","1 ceapă medie, rasă sau blenderizată","1 linguriță condiment allspice (ienibahar măcinat)","1 linguriță scorțișoară măcinată","1 linguriță sare fină","½ linguriță piper negru măcinat","Umplutură: 300 g carne de miel sau vită tocată","1 ceapă medie, tăiată mărunt","80 g nuci de pin (sau nuci caju)","1 linguriță allspice","½ linguriță scorțișoară","1 lingură ulei vegetal","Ulei vegetal pentru prăjit adânc (cca 1 litru)"]},"howIsMade":{"zh":"将粗麦粉在冷水中浸泡15分钟，沥干后用手用力挤出全部水分、与冰镇精瘦肉末、擦碎的洋葱、多香果粉、肉桂粉、盐和黑胡椒放入料理机中。搅打3–4分钟，必要时每次加一汤匙冰水，直至形成紧实均匀的面团、冷藏30分钟。制作馅料：中火热油，炒洋葱5分钟至变软、加肉末，不断翻炒6–8分钟至熟透。拌入多香果粉、肉桂粉、黑胡椒和松子，炒2分钟、完全放凉。塑形：将手用冷水打湿、取60克面团，用食指撑起，塑成壁厚5毫米的中空鱼雷形。填入约1汤匙馅料、将开口端捏合成尖端密封。重复操作、冷藏至少30分钟。炸制：将油加热至175°C、每批4–5个，轻轻翻动，炸4–5分钟至全面深金黄色。吸油纸吸油、配酸奶或蒜酱及皮塔饼，趁热上桌。","en":"Soak the bulgur in cold water for 15 minutes, then drain and squeeze out all moisture firmly with your hands; combine with the chilled lean mince, grated onion, allspice, cinnamon, salt, and pepper in a food processor. Process for 3–4 minutes, adding ice water a tablespoon at a time if needed, until you have a smooth, stiff dough; refrigerate for 30 minutes. Make the filling: heat the oil over medium heat; cook the onion for 5 minutes until soft. Add the mince and brown, breaking it up, for 6–8 minutes; stir in allspice, cinnamon, pepper, and pine nuts; cook 2 minutes. Cool completely; shape: wet your hands with cold water. Take a 60 g piece of dough and mould it around your index finger into a hollow torpedo shape with 5 mm thick walls; fill the hollow with about 1 tablespoon of filling. Pinch the open end firmly to seal it into a pointed torpedo; repeat with the remaining dough and filling. Refrigerate for at least 30 minutes; fry: heat oil to 175°C. Fry in batches of 4–5 for 4–5 minutes, turning gently, until deep golden brown all over; drain on paper; serve warm with yoghurt or garlic sauce and pita bread."}},{"id":52,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"zh":"荷兰","en":"Netherlands","ro":"Olanda"},"name":{"zh":"荷兰杂烩土豆泥","en":"Stamppot","ro":"Stamppot"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["粉质土豆（如马里斯派珀品种）1千克，去皮切四块","羽衣甘蓝（荷兰甘蓝）400克，去掉硬茎，叶子粗切","烟熏猪肉香肠（鲁克沃斯特）或德式香肠400克","无盐黄油80克，切小块","全脂牛奶100毫升，加热至温热","新鲜磨碎肉豆蔻1/4茶匙","细海盐1又1/2茶匙，分次使用","现磨黑胡椒1/2茶匙"],"en":["1 kg floury potatoes (such as Maris Piper or Russet), peeled and quartered","400 g curly kale (boerenkool), tough stems removed, leaves roughly chopped","400 g smoked pork sausage (rookworst) or bratwurst","80 g unsalted butter, cut into cubes","100 ml whole milk, warmed","1/4 tsp freshly grated nutmeg","1 1/2 tsp fine sea salt, divided","1/2 tsp freshly ground black pepper"],"ro":["1 kg cartofi făinoși (tip Maris Piper sau Russet), curățați și tăiați în sferturi","400 g varză creață (boerenkool), tulpini dure îndepărtate, frunze tocate grosier","400 g cârnați afumați din porc (rookworst) sau bratwurst","80 g unt nesărat, tăiat cubulețe","100 ml lapte integral, încălzit","1/4 linguriță nucșoară proaspăt rasă","1 1/2 linguriță sare fină de mare, împărțită","1/2 linguriță piper negru proaspăt măcinat"]},"howIsMade":{"zh":"将一大锅水加1茶匙盐烧开，加入土豆煮18-20分钟至用刀可轻松穿透。土豆煮的同时，另取一锅盐水烧开，加入羽衣甘蓝焯水5-6分钟至软烂；充分沥干，挤去多余水分，粗切备用。将烟熏香肠放入平底锅，加水刚好覆盖，中火煨20分钟至热透——或在少许油中以中火煎8-10分钟，中途翻面，至各面金黄。将土豆沥水，放回热锅中小火加热1-2分钟，晃动锅子使其蒸干，防止土豆泥出水。加入黄油和温热牛奶，用土豆捣碎器用力捣压至细腻顺滑。将沥干的羽衣甘蓝拌入，加入剩余盐、黑胡椒和肉豆蔻，搅拌均匀。立即盛入深碗，将切片香肠摆在上面即可享用。","en":"Bring a large pot of water with 1 tsp salt to the boil, add the potatoes, and cook for 18-20 minutes until completely tender when pierced with a knife. While the potatoes cook, bring a separate pot of salted water to the boil, add the kale, and blanch for 5-6 minutes until wilted and tender; drain well, squeeze out excess water, and chop roughly. Place the smoked sausage in a pan, add enough water to just cover, and simmer over medium heat for 20 minutes until heated through — or pan-fry in a little oil over medium heat for 8-10 minutes, turning halfway, until browned on all sides. Drain the potatoes and return them to the hot pot over low heat for 1-2 minutes, shaking the pot to steam-dry them and prevent a watery mash. Add the butter and warm milk and mash vigorously with a potato masher until smooth and creamy. Fold in the drained kale, season with the remaining salt, black pepper, and nutmeg, and stir until evenly combined. Serve immediately in deep bowls with the sliced sausage on top."}},{"id":53,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"新西兰","en":"New Zealand","ro":"Noua Zeelandă"},"name":{"zh":"新西兰地窖烹饪","en":"Hangi","ro":"Hangi"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["带骨羊肩或排骨600克，切成4厘米块","鸡腿4个（约600克），带皮","蜡质土豆500克，去皮对半切","库玛拉（橙色甜薯）300克，去皮切4厘米块","奶油南瓜300克，去皮切4厘米块","皱叶甘蓝1/4个（约300克），切成4瓣","植物油3大勺","细盐1又1/2茶匙","黑胡椒粉1/2茶匙"],"en":["600 g bone-in lamb shoulder or ribs, cut into 4 cm pieces","4 chicken drumsticks (about 600 g total), skin-on","500 g waxy potatoes, peeled and halved","300 g kumara (orange sweet potato), peeled and cut into 4 cm cubes","300 g butternut pumpkin, peeled and cut into 4 cm cubes","1/4 head savoy cabbage (about 300 g), cut into 4 wedges","3 tbsp vegetable oil","1 1/2 tsp fine salt","1/2 tsp ground black pepper"],"ro":["600 g carne de miel cu os (spată sau coaste), tăiată în bucăți de 4 cm","4 pulpe inferioare de pui (cca 600 g total), cu os și piele","500 g cartofi waxy, curățați și tăiați în jumătăți","300 g kumara (batată portocalie), curățată și tăiată cubulețe de 4 cm","300 g dovleac butternut, curățat și tăiat cubulețe de 4 cm","1/4 dintr-un cap de varză Savoy (cca 300 g), tăiată în 4 sferturi","3 linguri ulei vegetal","1 1/2 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"zh":"将烤箱预热至180°C（风扇模式160°C）。用盐和黑胡椒为羊肉和鸡腿全面调味。在一个大的耐热砂锅中大火热油，将羊肉每面煎3-4分钟至深度上色，然后移到盘中。在同一砂锅中，将鸡腿皮面朝下煎4-5分钟至皮肤金黄酥脆，然后取出备用。将所有煎好的肉放回砂锅，将土豆、库玛拉、南瓜和卷心菜瓣紧紧塞在肉块之间。加入200毫升水，用双层铝箔纸紧压边缘密封砂锅，再盖上盖子。放入烤箱烤2小时，直至羊肉完全软烂、轻易脱骨，所有蔬菜用叉子刺入时变软——如果还不够软，重新盖好再烤30分钟。揭掉盖子和铝箔，将烤箱升温至220°C，不盖盖烤15分钟至鸡皮变脆。静置10分钟后，将所有食材转移到大盘中，将汇集的汁水浇在上面即可享用。","en":"Heat the oven to 180°C (160°C fan). Season the lamb and chicken all over with salt and pepper. Heat the oil in a large flameproof casserole over high heat and brown the lamb pieces for 3-4 minutes per side until deeply coloured, then transfer to a plate. In the same pot, brown the chicken drumsticks skin-side down for 4-5 minutes until the skin is golden and crisp, then set aside. Arrange all the browned meat in the casserole and tuck the potatoes, kumara, pumpkin, and cabbage wedges snugly around and between the pieces. Pour in 200 ml of water, then seal the casserole very tightly with a double layer of foil pressed against the rim and put the lid on. Cook in the oven for 2 hours until the lamb is completely tender and pulls away from the bone easily, and all the vegetables are soft when pierced with a fork — if not quite done, cover again and cook for 30 minutes more. Remove the lid and foil, raise the oven to 220°C, and roast uncovered for 15 minutes until the skin crisps. Rest for 10 minutes before transferring everything to a large platter and spooning the collected juices over the top."}},{"id":54,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"zh":"比利时","en":"Belgium","ro":"Belgia"},"name":{"zh":"贻贝薯条","en":"Moules-frites","ro":"Moules-frites"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["新鲜活贻贝2公斤，刷洗干净，去除足丝","粉质土豆800g，去皮切成厚条","无盐黄油50g","小葱头4个，切细末","大蒜4瓣，切薄片","干白葡萄酒200ml","芹菜2根，切薄片","一小束新鲜欧芹，切细末","植物油或牛油，用于油炸","盐和黑胡椒"],"en":["2kg fresh live mussels, scrubbed and beards removed","800g floury potatoes, peeled and cut into thick batons","50g unsalted butter","4 shallots, finely diced","4 garlic cloves, thinly sliced","200ml dry white wine","2 celery stalks, finely sliced","Small bunch of fresh parsley, finely chopped","Vegetable oil or beef dripping, for deep-frying","Salt and black pepper"],"ro":["2 kg midii proaspete vii, curățate și cu beard-ul îndepărtat","800g cartofi făinoși, curățați și tăiați bețe groase","50g unt nesărat","4 șalote, tocate mărunt","4 căței de usturoi, felii subțiri","200ml vin alb sec","2 tulpini de țelină, feliate subțire","Legătură mică de pătrunjel proaspăt, tocat mărunt","Ulei vegetal sau grăsime de vită, pentru prăjit","Sare și piper negru"]},"howIsMade":{"zh":"制作薯条：将土豆切成厚条，在冷水中浸泡30分钟去除表面淀粉，沥干彻底擦干、第一次油炸：140°C炸6–8分钟至全熟但不上色，沥干完全冷却。将每个张开的贻贝在台面上轻敲——不合上的扔掉、大锅中以中高火融化黄油。加入小葱头和芹菜煮3分钟、加入大蒜煮1分钟。倒入白葡萄酒煮沸，加入贻贝，盖紧锅盖、大火蒸4–5分钟，期间摇锅一两次，直到贝壳全部张开。扔掉不开口的、拌入大部分欧芹并调味汤汁。油温升至190°C，分批炸预炸薯条2–3分钟至金黄酥脆、立即沥油撒盐、贻贝连汤装在大碗里，薯条放旁边，剩余欧芹撒上，配蛋黄酱上桌。","en":"For the frites: cut potatoes into thick batons and soak in cold water for 30 minutes to remove surface starch, then drain and dry thoroughly; first fry at 140°C for 6–8 minutes until cooked through but uncoloured; drain and cool completely. Tap each open mussel on the counter — discard any that do not close; melt butter in a large heavy pot over medium-high heat. Add shallots and celery and cook for 3 minutes until softened; add garlic and cook for 1 minute. Pour in the white wine, bring to a boil, then add the mussels and cover tightly; steam for 4–5 minutes, shaking the pot once or twice, until the shells have opened wide. Discard any that remain shut; stir in most of the parsley and season the broth. Raise the frying oil to 190°C and fry the blanched batons in batches for 2–3 minutes until golden and very crisp; drain and season immediately with salt; serve the mussels in wide bowls in their broth, the frites alongside, with the remaining parsley and mayonnaise on the side."}},{"id":55,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"慕萨卡","en":"Moussaka","ro":"Moussaka"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["2个大茄子（共约1公斤），切成1厘米厚的圆片","羊肉末500克（或牛肉末）","大洋葱1个，切细丁","大蒜3瓣，剁碎","罐装碎番茄400克（1罐）","番茄酱2汤匙","红葡萄酒100毫升","干牛至1茶匙","肉桂粉1/2茶匙","黄油60克（做白酱用）","中筋面粉60克（做白酱用）","温牛奶700毫升","蛋黄2个","卡法洛蒂里干酪80克，磨碎（或帕玛森奶酪）","橄榄油3汤匙","盐和现磨黑胡椒"],"en":["2 large eggplants (about 1 kg total), sliced 1 cm thick","500 g lamb mince (or beef mince)","1 large onion, finely diced","3 garlic cloves, minced","400 g chopped tomatoes (1 can)","2 tbsp tomato paste","100 ml red wine","1 tsp dried oregano","1/2 tsp ground cinnamon","60 g butter (for the bechamel)","60 g plain flour (for the bechamel)","700 ml warm milk","2 egg yolks","80 g grated kefalotyri (or parmesan)","3 tbsp olive oil","Salt and freshly ground black pepper"],"ro":["2 vinete mari (aproximativ 1 kg in total), feliate de 1 cm grosime","500 g carne tocata de miel (sau de vita)","1 ceapa mare, tocata marunt","3 căței de usturoi, zdrobiti","400 g rosii tocate in conserva (1 conserva)","2 linguri pasta de rosii","100 ml vin rosu","1 lingurita oregano uscat","1/2 lingurita scortisoara macinata","60 g unt (pentru bechamel)","60 g făină alba (pentru bechamel)","700 ml lapte cald","2 galbenusuri de ou","80 g kefalotyri ras (sau parmezan)","3 linguri ulei de masline","Sare si piper negru proaspat macinat"]},"howIsMade":{"zh":"将2个大茄子切成1厘米厚的圆片、大量撒盐、放在滤网中静置30分钟以排出苦水、用厨房纸吸干。 在茄子片上刷橄榄油、放入200度烤箱烤20-25分钟、中途翻面一次、烤至金黄柔软。 在宽锅中以中大火加热2汤匙橄榄油、放入500克羊肉末、一个切碎的洋葱和3瓣大蒜煸炒8-10分钟、然后倒入100毫升红酒去渣并收汁。 加入400克切碎的番茄、2汤匙番茄酱、半茶匙肉桂粉和1茶匙牛至、小火炖煮20分钟至酱汁浓稠、边缘不再有多余汤汁。 做白酱：在小锅中融化60克黄油、加入60克面粉炒2分钟至浅金色、再分次倒入700毫升温牛奶、不停搅拌至浓稠；离火静置30秒、拌入2个蛋黄和80克磨碎的卡法洛蒂里或帕玛森奶酪。 在30x20厘米的烤盘中铺一层茄子、倒入一半肉酱、再铺一层茄子、倒入剩余肉酱、最后将白酱浇在最上面并用刮刀抹平。 送入180度烤箱烤40-45分钟、直到表面呈深金色、边缘酱汁咕嘟冒泡。 出炉后让木沙卡静置15-20分钟再切块；这一步不可省略、能让各层定型、切出的方块保持形状。","en":"Slice 2 large eggplants into 1 cm rounds, salt them generously and let them sit in a colander for 30 minutes to draw out the bitter water; pat dry with paper towels. Brush the slices with olive oil and roast at 200 C for 20-25 minutes, turning once, until golden and tender. In a wide pan heat 2 tbsp oil over medium-high and brown 500 g minced lamb with one chopped onion and 3 garlic cloves for 8-10 minutes, then deglaze with 100 ml red wine and let it reduce. Add 400 g chopped tomatoes, 2 tbsp tomato paste, half a tsp cinnamon and 1 tsp oregano; simmer 20 minutes until thick and no excess liquid pools at the edge. For the bechamel melt 60 g butter in a saucepan, whisk in 60 g flour and cook 2 minutes until blond, then gradually add 700 ml warm milk whisking constantly until thick; off the heat, let it cool 30 seconds and beat in 2 egg yolks with 80 g grated kefalotyri or parmesan. In a 30x20 cm baking dish layer half the eggplant, all the lamb sauce, the remaining eggplant, then pour the bechamel on top and level it with a spatula. Bake at 180 C for 40-45 minutes until the top is deeply golden and the sauce bubbles at the edges. Rest the moussaka for 15-20 minutes before cutting; this step is non-negotiable so the layers set and the slices hold their shape."},"timeMins":{"total":105,"active":35}},{"id":56,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"捷克","en":"Czech Republic","ro":"Republica Cehă"},"name":{"zh":"捷克奶油炖牛肉","en":"Svíčková","ro":"Svíčková"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["牛里脊 1.2 公斤（上后腿或腿肉）","烟熏培根 100 克，切细条用于穿油（可选）","黄油 30 克","中性食用油 1 汤匙","大洋葱 1 个，切丁","大胡萝卜 2 根，切丁","欧防风 1 根，切丁","块根芹 150 克，切丁","月桂叶 2 片","多香果 6 粒","黑胡椒粒 10 粒","半个柠檬的皮屑","第戎芥末 1 汤匙","番茄膏 2 汤匙","干白葡萄酒 200 毫升","牛肉高汤 500 毫升","浓奶油 200 毫升（脂肪含量 33%）","面粉 1 汤匙（可选，用于增稠）","白砂糖 1 茶匙","半个柠檬的汁","盐，适量","搭配：打发奶油、蔓越莓酱、柠檬片、knedliky（捷克面包团子）"],"en":["1.2 kg beef sirloin (top round or topside)","100 g smoked bacon, cut in thin strips for larding (optional)","30 g butter","1 tbsp neutral oil","1 large onion, diced","2 large carrots, diced","1 parsnip, diced","150 g celeriac, diced","2 bay leaves","6 allspice berries","10 black peppercorns","Zest of 1/2 lemon","1 tbsp Dijon mustard","2 tbsp tomato paste","200 ml dry white wine","500 ml beef stock","200 ml heavy cream (33% fat)","1 tbsp plain flour (optional, for thickening)","1 tsp sugar","Juice of 1/2 lemon","Salt, to taste","To serve: whipped cream, cranberry compote, lemon slice, knedliky"],"ro":["1,2 kg mușchi de vită (vrabia sau pulpă top)","100 g bacon afumat, tăiat fâșii subțiri pentru lardonare (opțional)","30 g unt","1 lingură ulei neutru","1 ceapă mare, tăiată cuburi","2 morcovi mari, tăiați cuburi","1 rădăcină de păstârnac, tăiată cuburi","150 g țelină rădăcină, tăiată cuburi","2 foi de dafin","6 boabe de ienibahar","10 boabe de piper negru","Coaja de la 1/2 lămâie","1 lingură de muștar Dijon","2 linguri de pastă de roșii","200 ml vin alb sec","500 ml supă de vită","200 ml smântână grasă (33% grăsime)","1 lingură de făină albă (opțional, pentru îngroșare)","1 linguriță de zahăr","Zeama de la 1/2 lămâie","Sare, după gust","Pentru servire: frișcă bătută, dulceață de merișoare, felie de lămâie, knedlíky"]},"howIsMade":{"zh":"将1.2公斤牛里脊用细长的烟熏培根条穿插塞入肉中，或用厨房棉绳紧紧捆扎好、四面用盐和现磨黑胡椒充分调味。在厚重的荷兰锅中以中大火加热30克黄油和1汤匙油、将牛肉每面煎8-10分钟至形成深褐色焦壳后取出放盘备用。同一锅中加入切丁的米尔普瓦（1根大胡萝卜、1根欧防风根、150克块根芹、1个大洋葱）煸炒10-12分钟至边缘焦糖化、再加入2片月桂叶、6粒多香果、10粒黑胡椒、半个柠檬皮屑和1汤匙芥末。拌入2汤匙番茄膏煮2分钟至颜色加深、倒入200毫升干白葡萄酒和500毫升牛肉高汤刮起锅底、把牛肉放回蔬菜上方。盖紧盖子放入160度烤箱炖1.5-2小时、每30分钟翻面一次、直至叉子可毫无阻力插入肉中。将牛肉取出放在砧板上用锡纸覆盖静置、用手持搅拌棒把汤汁与蔬菜打成顺滑酱汁后过细筛回锅。加入200毫升浓奶油、若需要加1汤匙用少量冷水调匀的面粉、小火煮5分钟至酱汁能光亮地挂在勺背上、再用盐、1茶匙糖和少许柠檬汁调出甜酸平衡。将牛肉逆纹切成1厘米厚片、淋上温热酱汁、点缀一勺打发奶油、蔓越莓酱和一片柠檬、搭配knedliky（捷克面包团子）享用。","en":"Lard the beef sirloin (1.2 kg) with thin strips of smoked bacon, or truss it tightly with kitchen twine; season generously with salt and freshly ground pepper on all sides. Heat 30 g butter and 1 tbsp oil in a heavy Dutch oven over medium-high and sear the beef on every side for 8-10 minutes until a deep brown crust forms, then transfer to a plate. In the same pot brown the mirepoix (1 large carrot, 1 parsnip, 150 g celeriac, 1 large onion, all diced) for 10-12 minutes until caramelised at the edges; add 2 bay leaves, 6 allspice berries, 10 whole black peppercorns, the zest of half a lemon and 1 tbsp mustard. Stir in 2 tbsp tomato paste and cook 2 minutes until it darkens, then deglaze with 200 ml dry white wine and 500 ml beef stock, scraping the bottom, and nestle the beef back in on top of the vegetables. Cover and braise at 160°C for 1.5 to 2 hours, turning the beef every 30 minutes, until a fork slides in with no resistance. Lift the beef onto a board and tent with foil to rest; blend the cooking liquid and vegetables with a stick blender until smooth and pass the sauce through a fine sieve back into the pot. Stir in 200 ml heavy cream and, if needed, 1 tbsp flour slaked in a little cold water; simmer 5 minutes until the sauce coats the back of a spoon glossily, then adjust with salt, 1 tsp sugar and a squeeze of lemon to balance the sweet-sour. Slice the beef against the grain into 1 cm slices, ladle the warm sauce over the top and garnish with a spoon of whipped cream, cranberry compote and a lemon slice; serve with houskove knedliky (bread dumplings)."}},{"id":57,"servings":4,"tipType":"meat","timeMins":{"total":195,"active":45},"pairingsType":"meat","origin":{"zh":"挪威","en":"Norway","ro":"Norvegia"},"name":{"zh":"挪威羊肉炖菜","en":"Fårikål","ro":"Fårikål"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["带骨羊肩或颈肉1.2千克，切成5厘米块","白卷心菜1.2千克（约1个大头），去芯切成8个厚瓣","整粒黑胡椒1大勺","冷水600毫升","细盐1又1/2茶匙"],"en":["1.2 kg bone-in lamb shoulder or neck, cut into 5 cm pieces","1.2 kg white cabbage (about 1 large head), cored and cut into 8 thick wedges","1 tbsp whole black peppercorns","600 ml cold water","1 1/2 tsp fine salt"],"ro":["1,2 kg carne de miel cu os (spata sau gat), taiata in bucati de 5 cm","1,2 kg varza alba (1 cap mare), miezul indepartat, taiata in 8 sferturi groase","1 lingura boabe intregi de piper negru","600 ml apa rece","1 1/2 lingurita sare fina"]},"howIsMade":{"zh":"将羊肉块用1茶匙盐全面调味。将一半卷心菜瓣均匀铺在大厚底锅底部。将羊肉放在上面，撒上胡椒粒和剩余的1/2茶匙盐，然后将剩余的卷心菜铺在最上面。将冷水小心地沿锅内壁倒入——不要搅拌。盖紧锅盖，用中火煮至轻微沸腾，约8-10分钟。将火调至最低，不搅拌地慢炖2至2.5小时，直至羊肉完全软烂、轻易脱骨，卷心菜完全塌缩并充分吸收肉汁。2小时后检查羊肉是否无阻力地脱骨，汤汁是否浓郁芳香——若尚未完全软烂，盖好再炖30分钟。尝味并调整盐量。盛入深碗中，连汤汁一起，确保每份都有羊肉和卷心菜。","en":"Season the lamb pieces all over with 1 tsp of the salt. Arrange half the cabbage wedges in an even layer at the bottom of a large, heavy pot. Lay the lamb pieces on top, scatter over the peppercorns and the remaining 1/2 tsp salt, then arrange the remaining cabbage on top. Pour the cold water carefully down the inside wall of the pot — do not stir. Cover tightly and bring to a gentle boil over medium heat, about 8-10 minutes. Reduce the heat to the lowest possible simmer and cook undisturbed for 2 to 2.5 hours until the lamb is completely tender and falls off the bone, and the cabbage has collapsed and fully absorbed the meat juices. After 2 hours check that the lamb pulls away from the bone with no resistance and the broth is rich and fragrant — if not quite done, cover and simmer for 30 minutes more. Taste and adjust salt. Ladle into deep bowls with the broth, ensuring each serving has both lamb and cabbage."}},{"id":58,"servings":4,"tipType":"veg","pairingsType":"middle-eastern","origin":{"zh":"苏丹","en":"Sudan","ro":"Sudan"},"name":{"zh":"炖蚕豆","en":"Ful Medames","ro":"Ful Medames"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"zh":["干小蚕豆400克，在冷水中浸泡一夜（或罐装蚕豆800克，冲洗沥干）","大蒜4瓣，切碎","新鲜柠檬汁60毫升（约1个大柠檬），可按口味加量","特级初榨橄榄油4大勺，分次使用","孜然粉1茶匙","香菜粉1/2茶匙","细海盐1/2茶匙，可按口味加量","辣椒粉或红辣椒粉1/4茶匙","中等大小成熟番茄2个（约250克），切碎","小红洋葱1个（约100克），切碎","扁叶欧芹20克，叶子粗切"],"en":["400 g dried small fava beans, soaked overnight in cold water (or 800 g canned fava beans, rinsed and drained)","4 garlic cloves, finely minced","60 ml fresh lemon juice (about 1 large lemon), plus more to taste","4 tbsp extra-virgin olive oil, divided","1 tsp ground cumin","1/2 tsp ground coriander","1/2 tsp fine sea salt, plus more to taste","1/4 tsp cayenne pepper or hot paprika","2 medium ripe tomatoes (about 250 g), finely diced","1 small red onion (about 100 g), finely diced","20 g flat-leaf parsley, leaves roughly chopped"],"ro":["400 g fasole fava uscata, inmuiata peste noapte in apa rece (sau 800 g fasole fava la conserva, clatita si scursa)","4 căței de usturoi, tocati marunt","60 ml suc proaspat de lamaie (cca 1 lamaie mare), plus dupa gust","4 linguri ulei de masline extravirgin, impartit","1 lingurita chimen macinat","1/2 lingurita coriandru macinat","1/2 lingurita sare fina de mare, plus dupa gust","1/4 lingurita ardei iute macinat sau boia picanta","2 rosii mijlocii coapte (cca 250 g), taiate marunt","1 ceapa rosie mica (cca 100 g), taiata marunt","20 g patrunjel plat, frunzele tocate grosier"]},"howIsMade":{"zh":"如果使用干豆，将浸泡的豆子沥干，加入新鲜冷水至高出豆面4-5厘米；烧开后转小火煮1.5至2小时，至豆子用手指按压完全松软；沥干，保留100毫升煮豆水。如果使用罐装豆，冲洗沥干，以100毫升清水代替煮豆水。将豆子放回小火上的锅中，加入大蒜、柠檬汁、3大勺橄榄油、孜然、香菜粉、盐和辣椒粉。煮3-4分钟，用叉子将约一半的豆子捣碎，做出顺滑但略有颗粒感的质地，若太稠则少量添加保留的豆水。尝味并调整柠檬汁、盐和辛辣度——富尔应该口味酸爽、香料味浓郁。盛入浅碗，将切碎的番茄、红洋葱和欧芹撒在上面。淋上剩余的1大勺橄榄油，立即配热皮塔饼享用。","en":"If using dried beans, drain the soaked beans and cover with fresh cold water by 4-5 cm; bring to the boil and simmer for 1.5 to 2 hours until the beans are completely soft when pressed between fingers, then drain, reserving 100 ml of cooking liquid. If using canned beans, rinse, drain, and use 100 ml of water as the liquid. Return the beans to the pot over low heat and add the garlic, lemon juice, 3 tbsp of the olive oil, cumin, coriander, salt, and cayenne. Cook for 3-4 minutes, mashing about half the beans with a fork to create a creamy, partly chunky texture, adding reserved cooking liquid a splash at a time if too thick. Taste and adjust lemon, salt, and spice — the ful should be tangy and warmly spiced. Divide into shallow bowls and scatter the diced tomatoes, red onion, and parsley over the top. Drizzle the remaining 1 tbsp olive oil over each serving and serve immediately with warm pita bread."}},{"id":59,"servings":4,"tipType":"fish","timeMins":{"total":50,"active":40},"pairingsType":"mediterranean","origin":{"zh":"克罗地亚","en":"Croatia","ro":"Croația"},"name":{"zh":"克尔尼里索托","en":"Crni Rizot","ro":"Crni Rižot"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["新鲜或解冻鱿鱼500克，清洗干净，保留2-3个墨囊","阿尔伯里奥米或卡纳罗利米300克","中等洋葱1个（约150克），切碎","大蒜3瓣，切碎","干白达尔马提亚葡萄酒（或Pošip）100毫升","温热鱼高汤1升（或水加1块鱼汤块）","特级初榨橄榄油60毫升","冷黄油30克，切丁","新鲜欧芹2大勺，切碎","1/2个柠檬，只用汁","细海盐1茶匙","黑胡椒粉1/2茶匙"],"en":["500 g fresh or thawed squid, cleaned, with 2-3 ink sacs reserved","300 g arborio or carnaroli rice","1 medium onion (about 150 g), finely chopped","3 garlic cloves, finely minced","100 ml dry Dalmatian white wine (or Pošip)","1 litre warm fish stock (or water with 1 fish stock cube)","60 ml extra-virgin olive oil","30 g cold butter, cubed","2 tbsp fresh parsley, chopped","1/2 lemon, juice only","1 tsp fine sea salt","1/2 tsp ground black pepper"],"ro":["500 g calmari proaspeti sau decongelati, curatati, cu 2-3 saculeti de cerneala separati","300 g orez arborio sau carnaroli","1 ceapa medie (cca 150 g), tocata marunt","3 căței de usturoi, tocati marunt","100 ml vin alb sec dalmatian (sau Pošip)","1 litru fond de peste cald (sau apa cu 1 cub de fond de peste)","60 ml ulei de masline extravirgin","30 g unt rece, taiat cubulete","2 linguri patrunjel proaspat, tocat","1/2 lamaie, doar zeama","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat"]},"howIsMade":{"zh":"仔细清洗鱿鱼：将墨囊完整地取出放入装有少量水的小碗，把身体切成1厘米的圈，触手对半切。在宽底厚锅中以中火加热4大勺橄榄油，将洋葱炒4-5分钟至软，再加大蒜炒1分钟。加入鱿鱼圈和触手，翻炒2-3分钟至刚变白，倒入白葡萄酒并让其完全蒸发（约2分钟）。加米翻炒1分钟使其裹油，然后开始一勺一勺地加入热鱼汤，持续搅拌共16-18分钟。中途，将墨囊在剩余的汤中捏破并倒入——烩饭瞬间变为深邃的墨黑色，海洋风味更浓郁。当米饭达到al dente且呈奶油状，汤汁还剩一点时，关火加入冷黄油、剩余2大勺橄榄油、柠檬汁和欧芹。用力搅拌30秒完成mantecatura，盖上盖子静置2分钟。立即在深盘中上桌，顶部撒上更多欧芹，旁边配一片柠檬。","en":"Clean the squid carefully: lift out the ink sacs intact into a small bowl with a splash of water, then cut the bodies into 1 cm rings and halve the tentacles. In a wide heavy pan, heat 4 tbsp olive oil over medium heat and sauté the onion for 4-5 minutes until soft, then add the garlic for 1 minute more. Add the squid rings and tentacles, sauté for 2-3 minutes until just opaque, then pour in the wine and let it evaporate completely (about 2 minutes). Add the rice and stir for 1 minute to coat with fat, then begin adding the hot fish stock one ladle at a time, stirring constantly for 16-18 minutes total. Halfway through, break the ink sacs into the remaining stock and pour it in — the risotto turns deep jet black instantly and gains a profound oceanic depth. When the rice is al dente and creamy with a little stock still pooling, kill the heat and add the cold butter, the remaining 2 tbsp olive oil, the lemon juice, and the parsley. Stir vigorously for 30 seconds for the mantecatura, then cover and rest for 2 minutes. Serve immediately in shallow bowls with extra parsley on top and a wedge of lemon alongside."}},{"id":60,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"蒙古","en":"Mongolia","ro":"Mongolia"},"name":{"zh":"蒙古包子","en":"Buuz","ro":"Buuz"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["面团：中筋面粉300克，另备少许用于撒粉","温水150毫升（约50°C）","细盐1/2茶匙","馅料：羊肉末400克（或羊牛各半）","中等洋葱1个（约150克），切碎","大蒜3瓣，切碎","葵花籽油2大勺","孜然粉1茶匙","细海盐1茶匙","黑胡椒粉1/2茶匙","冷水50毫升"],"en":["Dough: 300 g all-purpose flour, plus extra for dusting","150 ml warm water (about 50 C)","1/2 tsp fine salt","Filling: 400 g ground lamb (or half lamb, half beef)","1 medium onion (about 150 g), finely diced","3 garlic cloves, finely minced","2 tbsp sunflower oil","1 tsp ground cumin","1 tsp fine sea salt","1/2 tsp ground black pepper","50 ml cold water"],"ro":["Aluat: 300 g făină alba, plus extra pentru intins","150 ml apa calda (cca 50 C)","1/2 lingurita sare fina","Umplutura: 400 g carne de miel tocata (sau amestec miel-vita)","1 ceapa medie (cca 150 g), taiata marunt","3 căței de usturoi, tocati marunt","2 linguri ulei de floarea-soarelui","1 lingurita chimen macinat","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat","50 ml apa rece"]},"howIsMade":{"zh":"制作面团：将面粉和盐混合，倒入温水揉5-6分钟直至面团光滑且有弹性。用湿布盖好，静置30分钟。制作馅料：将羊肉末、洋葱、大蒜、油、孜然、盐、黑胡椒和冷水放入碗中，用手充分混合至均匀且略带粘性。将面团分成20-24等份（每份约20克），将每份擀成约10厘米的薄圆形，中心稍厚于边缘。在每个面皮中央放1满汤匙（约25克）馅料。将边缘向上折起包住馅料，在顶部捏合并留一小蒸气孔——这是蒙古传统造型。蒸笼内铺烘焙纸或白菜叶，将包子摆放成单层，间距2厘米。在锅中烧开水，放上蒸笼，蒸20-22分钟至面皮熟透且馅料不再呈粉红色。立即上桌。","en":"Make the dough: mix flour and salt, pour in the warm water, and knead for 5-6 minutes until smooth and elastic. Cover with a damp cloth and rest for 30 minutes. Make the filling: combine the lamb, onion, garlic, oil, cumin, salt, pepper, and cold water in a bowl and mix well with your hands until evenly combined and slightly sticky. Divide the dough into 20-24 equal pieces (about 20 g each) and roll each into a thin round about 10 cm across, keeping the centre slightly thicker than the edges. Place 1 heaped tablespoon (about 25 g) of filling in the centre of each round. Lift the edges up around the filling and pleat them together at the top, leaving a small steam hole in the centre — the classic Mongolian shape. Line a bamboo steamer with parchment paper or cabbage leaves and arrange the buuz in a single layer with 2 cm between each. Fill a wok or wide pot with water and bring to a rolling boil; set the steamer basket over the boiling water and steam for 20-22 minutes until the dough is cooked through and the filling is no longer pink inside. Serve immediately."}},{"id":61,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"巴基斯坦","en":"Pakistan","ro":"Pakistan"},"name":{"zh":"印度香饭","en":"Biryani","ro":"Biryani"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["去骨鸡腿肉800克（或羊肩肉），切大块，尽量带骨","全脂原味酸奶200克，搅打均匀","姜蒜泥2汤匙","印度综合香料（garam masala）1茶匙","辣椒粉1茶匙","姜黄1/2茶匙","盐1茶匙","温牛奶3汤匙 + 一小撮藏红花丝","巴斯马蒂米400克","清水2.5升（用于半煮米）","酥油4汤匙","绿豆蔻4颗","黑豆蔻2颗","肉桂1根","丁香6粒","香叶2片","大洋葱2颗，切细丝","中等大小番茄2颗，擦丝","新鲜薄荷碎2汤匙","新鲜香菜碎2汤匙","额外酥油1汤匙，融化（淋面用）","上桌配：冰凉酸奶蘸酱、柠檬角"],"en":["800g boneless chicken thighs (or lamb shoulder), cut into large pieces, bone-in if possible","200g plain whole-milk yoghurt, whisked","2 tbsp ginger-garlic paste","1 tsp garam masala","1 tsp chilli powder","1/2 tsp turmeric","1 tsp salt","3 tbsp warm milk + a pinch of saffron threads","400g basmati rice","2.5 litres water (for par-boiling the rice)","4 tbsp ghee","4 green cardamom pods","2 black cardamom pods","1 cinnamon stick","6 cloves","2 bay leaves","2 large onions, thinly sliced","2 medium tomatoes, grated","2 tbsp chopped fresh mint","2 tbsp chopped fresh coriander","1 tbsp extra ghee, melted (to drizzle)","To serve: cold yoghurt raita, lemon wedges"],"ro":["800 g pulpe de pui dezosate (sau spata de miel), taiate cuburi mari, cu os daca este posibil","200 g iaurt gras de vaca, batut","2 linguri pasta de ghimbir-usturoi","1 lingurita garam masala","1 lingurita pudra de chili","1/2 lingurita turmeric","1 lingurita sare","3 linguri lapte cald + un varf de fire de sofran","400 g orez basmati","2,5 l apa (pentru fierberea partiala a orezului)","4 linguri ghee","4 capsule cardamom verde","2 capsule cardamom negru","1 bat de scortisoara","6 cuișoare","2 foi de dafin","2 cepe mari, taiate solzi subtiri","2 rosii medii, rase","2 linguri menta proaspata, tocata","2 linguri coriandru proaspat, tocat","1 lingura ghee suplimentar, topit (pentru stropit)","Pentru servit: raita de iaurt rece, felii de lamaie"]},"howIsMade":{"zh":"将800克鸡肉（或羊肉）与200克搅打过的酸奶、2汤匙姜蒜泥、1茶匙印度综合香料、1茶匙辣椒粉、1/2茶匙姜黄、1茶匙盐以及一小撮泡在3汤匙温牛奶中的藏红花丝混合、盖好至少腌制1小时、最好冷藏4小时。 在厚底锅中以中火融化4汤匙酥油或植物油、待油光亮时下4颗绿豆蔻、2颗黑豆蔻、1根肉桂、4粒丁香和1片香叶、煸炒30秒至轻微噼啪作响释出香气。 加入2颗切薄丝的大洋葱、中火翻炒12-15分钟至深棕色酥脆、捞出一半放厨房纸吸油作装饰、剩余的留在锅中与香料油同煮。 倒入腌好的肉与2颗去皮擦丝的番茄、中火翻炒8-10分钟至酸奶散开、油从锅边渗出、转小火加盖再焖15分钟至肉接近软嫩而酱汁仍浓稠。 同时将400克巴斯马蒂米淘洗至水清、浸泡30分钟、另起锅煮沸2.5升水加2茶匙盐、3颗豆蔻、1根肉桂和2片香叶、放入米和几滴油煮5-6分钟整、至米粒七成熟、芯部仍硬、立即沥干。 在肉酱上铺一半沥干的米饭、撒上一半炸洋葱、2汤匙切碎薄荷和2汤匙香菜、再铺上剩余的米饭、淋上4汤匙温热的藏红花牛奶和2汤匙融化酥油、最后撒上剩余的洋葱、薄荷和香菜。 用密封锅盖封紧锅（或盖锡纸再压上锅盖）、放在最小火上、最好垫上隔热板或铸铁板、焖煮（dum）25分钟期间不要开盖、被困蒸汽会同时焖熟米饭与肉。 关火让密封的锅静置10分钟、打开后用叉子从边缘往中央轻轻翻松、将肉与米的层次拌匀、立即配上冰凉的酸奶蘸酱和柠檬角上桌。","en":"Mix 800 g chicken (or lamb) with 200 g whisked yoghurt, 2 tbsp ginger-garlic paste, 1 tsp garam masala, 1 tsp chilli powder, 1/2 tsp turmeric, 1 tsp salt and a pinch of saffron threads soaked in 3 tbsp warm milk; cover and marinate at least 1 hour, ideally 4 hours in the fridge. Melt 4 tbsp ghee or oil in a heavy-bottomed pot over medium heat; when it shimmers, add 4 green cardamom pods, 2 black cardamom pods, 1 cinnamon stick, 4 cloves and 1 bay leaf and let them bloom for 30 seconds until they crackle lightly. Add 2 large onions sliced thin and fry for 12-15 minutes, stirring often, until deep brown and crisp; lift out half onto kitchen paper for garnish and leave the rest in the pot with the aromatic oil. Slide the marinated meat into the pot with 2 grated tomatoes and cook 8-10 minutes over medium heat, stirring until the yoghurt breaks and the oil rises to the edges; lower the heat and simmer covered another 15 minutes until the meat is almost tender but the sauce stays thick. Meanwhile rinse 400 g basmati rice until the water runs clear and soak for 30 minutes; bring 2.5 litres of water to the boil with 2 tsp salt, 3 cardamom pods, 1 cinnamon stick and 2 bay leaves, slip in the rice with a few drops of oil and cook for exactly 5-6 minutes until the grains are 70% done — still firm in the centre; drain at once. Spread half of the drained rice over the meat masala, scatter half of the fried onions, 2 tbsp chopped mint and 2 tbsp coriander, then layer the remaining rice on top; drizzle with 4 tbsp warm saffron milk and 2 tbsp melted ghee, and finish with the remaining onions, mint and coriander. Seal the pot with a tight lid (or cover with foil and press the lid down), set it on the lowest possible flame, ideally over a heat diffuser or a cast-iron tava, and dum cook for 25 minutes without lifting the lid — the trapped steam finishes the rice and meat together. Turn off the heat and let the sealed pot rest for 10 minutes; open, gently fluff from the side inwards to fold the meat and rice layers, and serve straight away with cold yoghurt raita and lemon wedges."},"timeMins":{"total":105,"active":50}},{"id":62,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"zh":"突尼斯","en":"Tunisia","ro":"Tunisia"},"name":{"zh":"突尼斯蛋饼","en":"Brik","ro":"Brik"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["薄饼皮(brik/malsouka/ouarka)4张，直径约30厘米（可用春卷皮代替）","大鸡蛋4个（每个brik用1个）","橄榄油浸金枪鱼罐头160克，沥干","小洋葱1个（约80克），切碎","小刺山柑3大勺，冲洗后粗切","扁叶欧芹20克，切碎","孜然粉1/2茶匙","细海盐1/2茶匙","辣椒粉或哈里萨辣椒酱1/4茶匙","炸油（植物油）500毫升","柠檬1个，切成4瓣，上菜用"],"en":["4 sheets of brik pastry (or malsouka/ouarka), about 30 cm in diameter (or spring roll wrappers as substitute)","4 large eggs (1 per brik)","160 g canned tuna in olive oil, well drained","1 small onion (about 80 g), finely diced","3 tbsp small capers, rinsed and roughly chopped","20 g flat-leaf parsley, finely chopped","1/2 tsp ground cumin","1/2 tsp fine sea salt","1/4 tsp cayenne pepper or harissa paste","500 ml vegetable oil for deep-frying","1 lemon, cut into 4 wedges, to serve"],"ro":["4 foi de brik (sau malsouka/ouarka), cca 30 cm diametru (sau foi de spring roll ca substitut)","4 oua mari (1 pe brik)","160 g ton la conserva in ulei de masline, bine scurs","1 ceapa mica (cca 80 g), taiata marunt","3 linguri capere mici, clatite si tocate grosier","20 g patrunjel plat, tocat marunt","1/2 lingurita chimen macinat","1/2 lingurita sare fina de mare","1/4 lingurita ardei iute macinat sau harissa","500 ml ulei vegetal pentru prajit adanc","1 lamaie, taiata in 4, pentru servire"]},"howIsMade":{"zh":"将沥干的金枪鱼、洋葱、刺山柑、欧芹、孜然、盐和辣椒粉放入碗中充分混合，制成馅料。将植物油倒入深而宽的平底锅中，至3-4厘米深度，加热至175°C。将一张饼皮平铺在干净的台面上，将四分之一金枪鱼馅料舀到饼皮下半部分，在中央做一个小凹陷。在凹陷中打入1个鸡蛋。迅速将饼皮对折成半月形，边缘用力压合，防止蛋液外流。小心将饼滑入热油中，每面炸1.5-2分钟，用宽锅铲翻面一次，至整体深金黄色且酥脆。用漏勺取出，在厨房纸上吸油30秒。立即上桌——蛋黄应呈流质至微凝固状态，饼皮酥脆作响。挤上一瓣柠檬汁即可。","en":"Combine the drained tuna, onion, capers, parsley, cumin, salt, and cayenne in a bowl and mix well to make the filling. Pour the vegetable oil into a deep, wide pan to a depth of 3-4 cm and heat to 175°C. Lay a brik pastry sheet flat on a clean surface and spoon a quarter of the tuna filling onto the lower half, creating a slight hollow in the centre. Crack 1 egg into the hollow. Working quickly, fold the pastry in half to form a half-moon, pressing the edges firmly together to seal and prevent the egg from escaping. Carefully slide the brik into the hot oil and fry for 1.5-2 minutes per side until deep golden and crisp all over, flipping once with a wide spatula. Lift out with a slotted spoon and drain on paper towels for 30 seconds. Serve immediately — the yolk should be runny to lightly set and the pastry crackling crisp. Squeeze a lemon wedge over the top."}},{"id":63,"servings":4,"tipType":"def","pairingsType":"def","origin":{"zh":"格鲁吉亚","en":"Georgia","ro":"Georgia"},"name":{"zh":"乔治亚奶酪面包","en":"Khachapuri","ro":"Khachapuri"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"zh":["500克普通面粉，另备少量防粘","7克速溶酵母（1小包）","1茶匙糖","1茶匙细海盐","250毫升温水（约40°C）","2汤匙橄榄油","400克苏鲁古尼奶酪或马苏里拉，粗略磨碎","200克菲达奶酪，捏碎","4个大鸡蛋（每个哈恰普里1个）","40克无盐黄油，切成4等份"],"en":["500 g plain flour (all-purpose), plus extra for dusting","7 g instant yeast (1 sachet)","1 tsp caster sugar","1 tsp fine sea salt","250 ml warm water (about 40°C / 105°F)","2 tbsp olive oil","400 g sulguni or mozzarella, coarsely grated","200 g feta cheese, crumbled","4 large eggs (1 per khachapuri)","40 g unsalted butter, cut into 4 equal pieces"],"ro":["500 g făină albă, plus extra pentru pudrare","7 g drojdie instant (1 plic)","1 linguriță zahăr","1 linguriță sare fină de mare","250 ml apă caldă (aproximativ 40°C)","2 linguri ulei de măsline","400 g suluguni sau mozzarella, ras grosier","200 g brânză feta, sfărâmată","4 ouă mari (câte 1 pentru fiecare khachapuri)","40 g unt nesărat, tăiat în 4 bucăți egale"]},"howIsMade":{"zh":"将面粉、酵母、糖和盐放入大碗中混合，加入温水和橄榄油搅拌成粗面团，然后在轻撒面粉的台面上揉搓8-10分钟，直至面团光滑略带粘性。揉成球状，放入涂油的碗中，盖上湿布，放在温暖处静置1小时至体积翻倍。面团发酵时，将磨碎的苏鲁古尼（或马苏里拉）和捏碎的菲达奶酪在碗中混合；将烤箱预热至250°C，同时将厚重烤盘或披萨石放入预热。将发酵好的面团均分为4份，在轻撒面粉的台面上将每份擀成约25x15厘米的椭圆形。将长边向内折入3厘米并卷起形成高起的边框，然后将两短端紧紧捏合，做成船形。将面团船放在烘焙纸上，每艘均匀铺入四分之一奶酪混合物至填满，滑入热烤盘中烤12-14分钟，直至饼皮金黄、奶酪沸腾冒泡并微微上色。取出烤箱，在每块奶酪馅中央按出小窝，各打入1个鸡蛋，放回烤箱烤3-4分钟至蛋白刚刚凝固但蛋黄仍流动。每个蛋上放一小块黄油，立即上桌——撕下面包边条蘸着融化的奶酪和蛋黄食用。","en":"Mix the flour, yeast, sugar, and salt in a large bowl, add the warm water and olive oil and stir to a rough dough, then knead on a lightly floured surface for 8-10 minutes until smooth and slightly tacky. Shape into a ball, place in an oiled bowl, cover with a damp cloth, and leave in a warm place for 1 hour until doubled in size. While the dough rises, mix the grated sulguni (or mozzarella) and crumbled feta together in a bowl; heat the oven to 250°C (230°C fan) with a heavy baking tray or pizza stone inside. Divide the risen dough into 4 equal pieces and roll each on a lightly floured surface into an oval about 25 x 15 cm. Fold the long edges inward by 3 cm and roll them up into a thick raised border, then pinch both short ends firmly together to form a boat shape. Arrange the boats on baking parchment, fill each cavity completely with a quarter of the cheese mixture, then slide onto the hot tray and bake for 12-14 minutes until the crust is golden and the cheese is bubbling and lightly browned. Remove from the oven, press a small hollow in the centre of each cheese filling, crack 1 egg into each hollow, and return to the oven for 3-4 minutes until the white is just set but the yolk remains runny. Place a piece of butter on top of each egg and serve immediately — tear strips of the border and dip into the melted cheese and yolk."}},{"id":64,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"南非","en":"South Africa","ro":"Africa de Sud"},"name":{"zh":"博博提肉饼","en":"Bobotie","ro":"Bobotie"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["750克瘦牛肉末或羊肉末","2个中等洋葱（约300克），细切","2片白面包（约60克），去边","125毫升全脂牛奶，分开使用","2个大鸡蛋","50克苏丹娜葡萄干","30克干杏（约6个），细切","2汤匙杏子果酱或甜酸辣酱","2汤匙温和咖喱粉","1茶匙姜黄粉","2汤匙植物油","1茶匙细海盐","1/2茶匙黑胡椒粉","4片新鲜或干月桂叶"],"en":["750 g lean beef or lamb mince","2 medium onions (about 300 g total), finely diced","2 slices white bread (about 60 g), crusts removed","125 ml whole milk, divided","2 large eggs","50 g sultanas (golden raisins)","30 g dried apricots (about 6), finely chopped","2 tbsp apricot jam or sweet chutney","2 tbsp mild curry powder","1 tsp ground turmeric","2 tbsp vegetable oil","1 tsp fine sea salt","1/2 tsp ground black pepper","4 fresh or dried bay leaves"],"ro":["750 g carne tocată de vită sau miel, slabă","2 cepe medii (aproximativ 300 g), fin tocate","2 felii pâine albă (aproximativ 60 g), fără coajă","125 ml lapte integral, împărțit","2 ouă mari","50 g stafide galbene (sultane)","30 g caise uscate (aproximativ 6 bucăți), fin tocate","2 linguri gem de caise sau chutney dulce-picant","2 linguri pudră de curry blând","1 linguriță turmeric măcinat","2 linguri ulei vegetal","1 linguriță sare fină de mare","1/2 linguriță piper negru măcinat","4 foi de dafin proaspete sau uscate"]},"howIsMade":{"zh":"将面包在60毫升牛奶中浸泡5分钟，然后挤出多余水分放入小碗中弄碎。大平底锅倒油，中大火加热，加入洋葱翻炒8-10分钟至软化金黄。加入咖喱粉和姜黄粉翻炒1分钟至香气飘出，然后加入肉末炒8-10分钟，边炒边将肉打散，直至上色且水分蒸发。离火，拌入泡软的面包、葡萄干、干杏、果酱、盐和胡椒，搅拌均匀。将烤箱预热至180°C，在中号烤盘（约25x20厘米）上涂油。将肉馅转入烤盘，压成均匀一层，把月桂叶插入表面。将鸡蛋和剩余65毫升牛奶加一撮盐打散至顺滑，均匀浇在肉馅上。烤35-40分钟至蛋奶层凝固、表面金黄，中央不再晃动。静置5分钟后与黄米饭和酸辣酱一同上桌。","en":"Soak the bread in 60 ml of the milk for 5 minutes, then squeeze out the excess liquid and crumble into a small bowl. Heat the oil in a large frying pan over medium-high heat, add the onions and cook, stirring, for 8-10 minutes until soft and golden. Add the curry powder and turmeric and stir for 1 minute until fragrant, then add the mince and cook for 8-10 minutes, breaking up any lumps, until browned and all liquid has evaporated. Remove from the heat and mix in the soaked bread, sultanas, dried apricots, apricot jam, salt, and pepper until evenly combined. Heat the oven to 180°C (160°C fan) and lightly grease a medium baking dish (about 25 x 20 cm). Transfer the meat mixture into the dish, press it into an even layer, and tuck the bay leaves into the surface. Beat the eggs with the remaining 65 ml milk and a pinch of salt until smooth, then pour evenly over the meat. Bake for 35-40 minutes until the custard topping is set and golden brown with no wobble in the centre. Rest for 5 minutes before serving with yellow rice, chutney, and sambals."}},{"id":65,"servings":4,"tipType":"fish","pairingsType":"latin","origin":{"zh":"秘鲁","en":"Peru","ro":"Peru"},"name":{"zh":"酸橘汁腌鱼","en":"Ceviche","ro":"Ceviche"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["700克极新鲜的白鱼片（鲈鱼、比目鱼或大比目鱼），去皮去骨","180毫升新鲜青柠汁（约8-10个青柠），可按口味增加","1个小红洋葱（约150克），对半切开后切细薄半月形","1-2个黄辣椒或1个墨西哥辣椒，去籽切细","1瓣大蒜，磨细","1茶匙新鲜姜（约1厘米），磨细","30克新鲜香菜，叶和细茎粗切","1茶匙细海盐","1/4茶匙白胡椒粉","2根玉米棒，煮熟后切成5厘米厚的圆段","2个小红薯（约400克），煮至软烂，去皮切片"],"en":["700 g very fresh white fish fillets (sea bass, sole, or halibut), skin and bones removed","180 ml fresh lime juice (about 8-10 limes), plus more to taste","1 small red onion (about 150 g), halved and thinly sliced into half-moons","1-2 ají amarillo chillies or 1 jalapeño, deseeded and finely diced","1 garlic clove, finely grated","1 tsp fresh ginger (about 1 cm piece), finely grated","30 g fresh coriander (cilantro), leaves and fine stems, roughly chopped","1 tsp fine sea salt","1/4 tsp ground white pepper","2 ears of corn, boiled and cut into 5 cm rounds","2 small sweet potatoes (about 400 g), boiled until tender, peeled and sliced"],"ro":["700 g file de pește alb foarte proaspăt (biban de mare, limbă sau halibut), fără piele și oase","180 ml suc proaspăt de lime (aproximativ 8-10 lime-uri), plus extra după gust","1 ceapă roșie mică (aproximativ 150 g), tăiată felii subțiri în jumătate de lună","1-2 ardei ají amarillo sau 1 jalapeño, fără semințe, fin tocați","1 căței de usturoi, fin ras","1 linguriță ghimbir proaspăt (aproximativ 1 cm), fin ras","30 g coriandru proaspăt, frunze și tulpini subțiri, grosier tocat","1 linguriță sare fină de mare","1/4 linguriță piper alb măcinat","2 știuleți de porumb, fierți și tăiați în rondele de 5 cm","2 cartofi dulci mici (aproximativ 400 g), fierți, curățați și feliați"]},"howIsMade":{"zh":"用厨房纸巾擦干鱼片，切成2厘米的方块，去除残留鱼刺，放入非反应性容器（玻璃或陶瓷）中。加入盐和白胡椒粉拌匀。加入红洋葱、辣椒、大蒜和姜轻轻翻拌。倒入青柠汁——应几乎没过鱼块——轻轻搅拌，将鱼块按入汁中尽量浸没。覆盖保鲜膜冷藏10-15分钟，中途翻拌一次，直到每块鱼外表变成不透明并轻按略有弹性，中心仍微微透明——这是秘鲁经典做法，并非完全熟透。按口味调整盐和青柠汁。拌入大部分香菜，留少量作装饰。立即装入冷藏的碗中，搭配玉米段和红薯片上桌，点缀剩余香菜。","en":"Pat the fish dry with paper towels and cut into 2 cm cubes, removing any remaining pin bones, then place in a non-reactive bowl (glass or ceramic). Season with the salt and white pepper and toss to coat. Add the red onion, chilli, garlic, and ginger and mix gently. Pour over the lime juice — it should nearly cover the fish — then stir gently and press the fish down to submerge it as much as possible. Cover and refrigerate for 10-15 minutes, stirring once halfway through, until the outside of each cube is opaque and just firm to the touch while the very centre remains slightly translucent — the classic Peruvian style, not fully cooked through. Taste and adjust salt and lime juice. Stir in most of the coriander, reserving a little for garnish. Serve immediately in chilled bowls alongside the corn rounds and sweet potato slices, with the remaining coriander scattered over the top."}},{"id":66,"servings":8,"tipType":"korean","pairingsType":"korean","origin":{"zh":"韩国","en":"South Korea","ro":"Coreea de Sud"},"name":{"zh":"泡菜","en":"Kimchi","ro":"Kimchi"},"category":{"zh":"配菜","en":"Side dish","ro":"Garnitură"},"ingredients":{"zh":["大白菜1棵（约2公斤）","无碘海盐3大勺","韩式辣椒粉（고추가루）4大勺","大蒜5瓣，细末","新鲜姜末1小勺","鱼露1大勺（素食用酱油）","糖1小勺","葱6根，切3厘米段","中等胡萝卜1根，切丝"],"en":["1 large napa cabbage (about 2 kg)","3 tbsp sea salt (non-iodised)","4 tbsp gochugaru (Korean red pepper flakes)","5 cloves garlic, finely minced","1 tsp fresh ginger, grated","1 tbsp fish sauce (or soy sauce for vegan)","1 tsp sugar","6 spring onions, cut into 3cm pieces","1 medium carrot, julienned"],"ro":["1 varză napa mare (aprox. 2 kg)","3 linguri sare de mare (fără iod)","4 linguri gochugaru (fulgi de ardei coreean)","5 căței de usturoi, tocați mărunt","1 linguriță ghimbir proaspăt, ras","1 lingură sos de pește (sau sos de soia pentru variantă vegană)","1 linguriță zahăr","6 cepe verzi, tăiate în bucăți de 3 cm","1 morcov mediu, julien"]},"howIsMade":{"zh":"将白菜纵向切成四等份，再横切成5厘米的小块。撒上海盐，用手搓揉2–3分钟，静置1–2小时（偶尔翻动）直至蔫软出水。用冷水冲洗2–3遍，沥干并用力挤去多余水分；尝起来应是适度的咸味。将고추가루（辣椒粉）、大蒜、姜、鱼露和糖在碗中混合；加入葱和胡萝卜。将沥干的白菜加入辣酱中，戴手套充分拌匀，确保每片白菜均匀裹上红酱。紧实地装入1升洁净玻璃罐中，用力按压排出气泡，留出3–4厘米顶空；在室温下发酵1–2天后放入冰箱——3–5天后可食用，1周后风味最佳。","en":"Quarter the napa cabbage lengthwise, then cut crosswise into 5cm pieces. Toss with sea salt and massage 2–3 minutes, let sit 1–2 hours turning occasionally until the cabbage has wilted and released water. Rinse the cabbage thoroughly in cold water 2–3 times, drain and squeeze firmly to remove excess moisture; it should taste pleasantly salty — rinse once more if too salty. Mix gochugaru, garlic, ginger, fish sauce and sugar in a bowl; add spring onions and carrot. Add drained cabbage to the paste and mix thoroughly with your hands (wear gloves) — every piece should be evenly coated in red paste. Pack tightly into clean 1-litre jars, press down firmly to eliminate air pockets, leaving 3–4 cm of headspace; leave at room temperature for 1–2 days, then refrigerate — kimchi is ready in 3–5 days and best after 1 week."}},{"id":67,"servings":4,"tipType":"meat","timeMins":{"total":285,"active":60},"pairingsType":"vietnamese","origin":{"zh":"越南","en":"Vietnam","ro":"Vietnam"},"name":{"zh":"越南三明治","en":"Banh Mi","ro":"Banh Mi"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["4个小法棍（约20厘米），纵向对半切开","猪里脊400克，切薄片（约5毫米厚）","生抽2汤匙","鱼露1汤匙","芝麻油1茶匙+糖1茶匙+黑胡椒粉1/4茶匙（腌料）","中等胡萝卜2根（约200克），去皮切细条（朱利安切法）","白萝卜100克，去皮切细条（或用胡萝卜代替）","米醋3汤匙","糖1汤匙+细海盐1/2茶匙（腌泡汁）","鸡肝酱60克","蛋黄酱4汤匙","大黄瓜1根，切细条","墨西哥辣椒或红辣椒2个，切薄片","新鲜香菜20克，取叶"],"en":["4 small baguettes or demi-baguettes (about 20 cm each), halved lengthwise","400 g pork tenderloin, thinly sliced (about 5 mm)","2 tbsp soy sauce","1 tbsp fish sauce","1 tsp sesame oil + 1 tsp sugar + 1/4 tsp black pepper (marinade)","2 medium carrots (about 200 g), peeled and julienned","100 g daikon, peeled and julienned (or extra carrot)","3 tbsp rice vinegar","1 tbsp sugar + 1/2 tsp fine salt (for pickling)","60 g chicken liver pâté","4 tbsp mayonnaise","1 large cucumber, cut into thin batons","2 jalapeños or red chillies, thinly sliced","20 g fresh coriander, sprigs"],"ro":["4 baghetele mici (de circa 20 cm), tăiate pe lungime","400 g mușchi de porc, tăiat felii subțiri (circa 5 mm)","2 linguri sos de soia","1 lingură sos de pește","1 linguriță ulei de susan + 1 linguriță zahăr + 1/4 linguriță piper negru (pentru marinadă)","2 morcovi medii (aproximativ 200 g), curățați și tăiați julienne","100 g daikon (ridiche asiatică), curățat și juliennat (sau morcov în plus)","3 linguri oțet de orez","1 lingură zahăr + 1/2 linguriță sare (pentru murat)","60 g pate de ficat de pui","4 linguri maioneză","1 castravete mare, tăiat bețe subțiri","2 jalapeño sau ardei roșii, tăiați rondele","20 g coriandru proaspăt, crenguțe"]},"howIsMade":{"zh":"将胡萝卜和白萝卜与米醋、糖和盐拌匀，腌制至少20分钟（或冷藏最多4小时），直至略软但仍清脆。将生抽、鱼露、芝麻油、糖和黑胡椒混合，加入猪肉片搅拌均匀，在室温下腌15-20分钟。厚底锅大火烧至冒烟，分2-3批将猪肉片单层铺入，每面煎1-2分钟至焦糖化、边缘金黄。将法棍放入200°C烤箱烤4-5分钟至外皮酥脆。在切面上慷慨涂抹鸡肝酱和蛋黄酱。铺上热猪肉片，放上沥干的腌胡萝卜萝卜、黄瓜条、墨西哥辣椒片和大量香菜枝。轻压后立即食用。","en":"Combine the carrots and daikon with the rice vinegar, sugar, and salt, toss well, and leave to pickle for at least 20 minutes (or up to 4 hours in the fridge) until slightly softened but still crunchy. Mix the soy sauce, fish sauce, sesame oil, sugar, and black pepper in a bowl, add the sliced pork, and toss to coat; marinate for 15-20 minutes at room temperature. Heat a heavy frying pan or griddle over high heat until smoking, add the pork in a single layer in 2-3 batches, and cook for 1-2 minutes per side until caramelised and golden brown at the edges. Toast the baguettes in a 200°C oven for 4-5 minutes until the crust is crisp. Spread the cut sides generously with pâté and mayonnaise. Layer in the warm pork slices, the drained pickled carrots and daikon, cucumber batons, jalapeño slices, and generous sprigs of coriander. Press gently and serve immediately."}},{"id":68,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"印度尼西亚","en":"Indonesia","ro":"Indonezia"},"name":{"zh":"沙嗲串","en":"Satay","ro":"Satay"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["无皮无骨鸡腿肉700克，切成2厘米方块","生抽3汤匙","椰浆2汤匙","浅红糖1汤匙","香菜粉2茶匙","孜然粉1茶匙","姜黄粉1茶匙","大蒜2瓣，磨细","香茅1根，白色部分，切末","花生酱（顺滑）200克","椰浆200毫升（用于花生酱汁）","甜酱油（kecap manis）2汤匙","青柠汁1汤匙","三巴酱或辣椒酱1茶匙","竹签20根，冷水浸泡30分钟"],"en":["700 g boneless skinless chicken thighs, cut into 2 cm cubes","3 tbsp soy sauce","2 tbsp coconut milk","1 tbsp light brown sugar","2 tsp ground coriander","1 tsp ground cumin","1 tsp ground turmeric","2 garlic cloves, finely grated","1 lemongrass stalk, pale part only, finely minced","200 g smooth peanut butter","200 ml coconut milk (for sauce)","2 tbsp kecap manis (sweet soy sauce)","1 tbsp lime juice","1 tsp sambal oelek or sriracha","20 bamboo skewers, soaked in cold water for 30 minutes"],"ro":["700 g pulpe de pui dezosate și fără piele, tăiate cubulețe de 2 cm","3 linguri sos de soia","2 linguri lapte de cocos","1 lingură zahăr brun pal","2 lingurițe coriandru măcinat","1 linguriță chimen măcinat","1 linguriță turmeric măcinat","2 căței de usturoi, fin rași","1 tulpină lemongrass, partea palidă, fin tocată","200 g unt de arahide cremos","200 ml lapte de cocos (pentru sos)","2 linguri kecap manis (sos de soia dulce)","1 lingură suc de lime","1 linguriță sambal oelek sau sriracha","20 bețișoare de bambus, înmuiate în apă rece 30 de minute"]},"howIsMade":{"zh":"将生抽、椰浆、红糖、香菜粉、孜然粉、姜黄粉、大蒜和香茅混合成腌料。加入鸡肉块翻拌均匀，在室温下腌至少30分钟或冷藏最多4小时。制作花生酱汁：将花生酱、椰浆、甜酱油、青柠汁和三巴酱放入小锅，小火加热搅拌3-4分钟至顺滑如丝；太稠则加少量水稀释。将4-5块鸡肉紧密地串在泡好的竹签上。将炭火烤架或铸铁烤盘大火加热，轻刷油。每面烤3-4分钟，翻一次，直至鸡肉局部焦糊且能轻松从签上脱落——内部温度应达到75°C。立即搭配热花生酱和黄瓜片上桌。","en":"Mix the soy sauce, coconut milk, brown sugar, ground coriander, cumin, turmeric, garlic, and lemongrass in a bowl to make the marinade. Add the chicken cubes, toss to coat, and marinate for at least 30 minutes at room temperature or up to 4 hours in the refrigerator. Make the peanut sauce: combine the peanut butter, coconut milk, kecap manis, lime juice, and sambal in a small saucepan over low heat and stir for 3-4 minutes until smooth and silky; thin with a splash of water if too thick. Thread 4-5 chicken pieces onto each soaked skewer, pressing them close together. Heat a charcoal grill, cast-iron griddle, or grill pan over high heat and brush lightly with oil. Grill the skewers for 3-4 minutes per side, turning once, until deeply charred in spots and the chicken pulls away from the skewer easily — internal temperature should reach 75°C. Serve immediately with the warm peanut sauce for dipping and sliced cucumber alongside."}},{"id":69,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"zh":"马来西亚","en":"Malaysia","ro":"Malaysia"},"name":{"zh":"叻沙","en":"Laksa","ro":"Laksa"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["叻沙酱3汤匙（或红咖喱酱加1茶匙虾酱）","植物油2汤匙","椰浆800毫升（2罐，各400毫升）","鸡汤或水600毫升","鱼露2汤匙","糖1茶匙","生虾400克（中等大小），去壳去肠","老豆腐200克，沥干切2厘米方块","新鲜豆芽200克","米粉200克，沸水浸泡3分钟后沥干","大鸡蛋4个，煮熟（7分钟），去壳对半切","四季豆100克，去尾对半切","青柠2个，切瓣","新鲜香菜20克，只取叶","葱2根，切细"],"en":["3 tbsp laksa paste (or red curry paste with 1 tsp shrimp paste added)","2 tbsp vegetable oil","800 ml coconut milk (2 x 400 ml cans)","600 ml chicken stock or water","2 tbsp fish sauce","1 tsp sugar","400 g raw medium prawns, peeled and deveined","200 g firm tofu, drained and cut into 2 cm cubes","200 g fresh bean sprouts","200 g rice vermicelli noodles, soaked in boiling water 3 minutes and drained","4 large eggs, hard-boiled (7 minutes), peeled and halved","100 g green beans, trimmed and halved","2 limes, cut into wedges","20 g fresh coriander, leaves only","2 spring onions, thinly sliced"],"ro":["3 linguri pastă laksa (sau pastă de curry roșu cu 1 linguriță pastă de creveți)","2 linguri ulei vegetal","800 ml lapte de cocos (2 conserve de 400 ml)","600 ml supă de pui sau apă","2 linguri sos de pește","1 linguriță zahăr","400 g creveți cruzi medii, curățați și devenați","200 g tofu ferm, scurs și tăiat cuburi de 2 cm","200 g muguri de soia proaspeți","200 g vermicelli de orez, înmuiați în apă clocotită 3 minute și scurși","4 ouă mari, fierte tari (7 minute), decojite și tăiate jumătate","100 g fasole verde, curățată și tăiată în jumătăți","2 lime, tăiate felii","20 g coriandru proaspăt, frunze","2 cepe verzi, feliate subțire"]},"howIsMade":{"zh":"将米粉放入沸水中浸泡3分钟，沥干，用冷水冲洗，备用。鸡蛋煮7分钟至全熟，放入冰水中冷却，去壳对半切开。大锅或炒锅倒油，中火加热，加入叻沙酱不断翻炒2-3分钟，直至香气四溢、油开始分离。倒入椰浆和鸡汤，煮至平稳沸腾。加入鱼露和糖，尝味调整——汤头应浓郁、略咸。加入四季豆煮3分钟，再加入虾和豆腐煮2-3分钟，直至虾变粉红色熟透。将米粉分入4个深碗，舀入热汤、虾、豆腐和豆角。每碗放上豆芽、两半熟蛋、葱和香菜叶。立即配青柠角上桌。","en":"Soak the rice vermicelli in boiling water for 3 minutes, drain, rinse under cold water, and set aside. Hard-boil the eggs for 7 minutes, cool in iced water, peel, and halve. Heat the oil in a large wok or saucepan over medium heat, add the laksa paste, and fry, stirring constantly, for 2-3 minutes until fragrant and the oil begins to separate. Pour in the coconut milk and chicken stock and bring to a steady simmer. Add the fish sauce and sugar, taste, and adjust — the broth should be rich and slightly salty. Add the green beans and cook for 3 minutes, then add the prawns and tofu and cook for 2-3 minutes until the prawns are pink and just cooked through. Divide the noodles between 4 deep bowls and ladle the hot broth with prawns, tofu, and beans on top. Finish each bowl with bean sprouts, 2 halved eggs, spring onions, and coriander. Serve immediately with lime wedges on the side."}},{"id":70,"servings":4,"tipType":"def","pairingsType":"mexican","origin":{"zh":"萨尔瓦多","en":"El Salvador","ro":"El Salvador"},"name":{"zh":"玉米饼","en":"Pupusa","ro":"Pupusa"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["马萨哈里纳（如Maseca牌，nixtamalized玉米粉）400克，另备少量","温水350毫升（约40°C），必要时追加","细海盐1茶匙","罐装炒黑豆或斑豆200克，加热备用","奇索奶酪或马苏里拉200克，粗略磨碎","植物油2汤匙（用于煎饼）","白卷心菜300克（约四分之一棵），极细切丝","小胡萝卜1根（约80克），去皮粗磨","小白洋葱半个（约60克），切薄片","苹果醋或白醋100毫升","水100毫升（用于柯蒂多腌菜）","细盐1茶匙 + 糖1茶匙（用于柯蒂多）","干牛至1/2茶匙","番茄莎莎酱200毫升，上桌用"],"en":["400 g masa harina (nixtamalized corn flour, such as Maseca), plus extra","350 ml warm water (about 40°C), plus more if needed","1 tsp fine sea salt","200 g canned refried black or pinto beans, warmed","200 g queso quesillo or mozzarella, coarsely grated","2 tbsp vegetable oil (for cooking)","300 g white cabbage (about 1/4 head), very finely shredded","1 small carrot (about 80 g), peeled and coarsely grated","1/2 small white onion (about 60 g), thinly sliced","100 ml apple cider vinegar or white vinegar","100 ml water (for curtido)","1 tsp fine salt + 1 tsp sugar (for curtido)","1/2 tsp dried oregano","200 ml tomato salsa, to serve"],"ro":["400 g masa harina (făină de porumb nixtamalizată, ex. Maseca), plus extra","350 ml apă caldă (circa 40°C), plus dacă e nevoie","1 linguriță sare fină de mare","200 g fasole neagră sau pinto refulată (din conservă, încălzită)","200 g queso quesillo sau mozzarella, ras grosier","2 linguri ulei vegetal (pentru prăjit)","300 g varză albă (aprox. 1/4 căpățână), fin feliată","1 morcov mic (aprox. 80 g), curățat și ras","1/2 ceapă albă mică (aprox. 60 g), felii subțiri","100 ml oțet de mere sau oțet alb","100 ml apă (pentru curtido)","1 linguriță sare fină + 1 linguriță zahăr (pentru curtido)","1/2 linguriță oregano uscat","200 ml salsa de roșii pentru servit"]},"howIsMade":{"zh":"先做柯蒂多腌菜：将卷心菜、胡萝卜和洋葱放入碗中，混合醋、水、盐、糖和牛至浇在上面，翻拌均匀，腌制至少30分钟（或冷藏过夜）。做面团：将马萨哈里纳和盐放入大碗，逐渐加入温水，用手揉成光滑有弹性的面团——不应开裂；如有需要每次加一汤匙水。将炒豆和奶酪混合成馅料。将面团分成8等份（每份约90克）。在湿润的手掌中将一份面团压成约12厘米的圆饼，在中央放2大勺馅料，将边缘折叠包住馅料，用力捏紧密封；轻轻整形成约1厘米厚、12厘米宽的圆饼，修补裂缝。将厚铁锅或铸铁平底锅用中大火加热，刷薄油。分批煎饼，每面3-4分钟，直至出现深金棕色斑点、面饼摸上去干爽不粘。搭配柯蒂多和莎莎酱趁热上桌。","en":"Make the curtido first: combine the cabbage, carrot, and onion in a bowl, mix the vinegar, water, salt, sugar, and oregano, pour over the vegetables, toss well, and set aside to pickle for at least 30 minutes (or overnight in the fridge). Make the dough: combine the masa harina and salt in a large bowl, pour in the warm water gradually, and mix with your hands until a smooth, pliable dough forms — it should hold together without cracking; add a tablespoon of water at a time if needed. Mix the refried beans and grated cheese together to make the filling. Divide the dough into 8 equal balls (about 90 g each). Press a ball flat in your damp palm into a disc about 12 cm across, place 2 heaped tablespoons of filling in the centre, then fold the edges up over the filling and pinch firmly to seal; gently re-flatten into a disc about 1 cm thick and 12 cm wide, patching any cracks. Heat a heavy griddle or cast-iron skillet over medium-high heat and brush with oil. Cook the pupusas in batches for 3-4 minutes per side until dark golden-brown patches appear and the dough feels dry rather than tacky. Serve hot with the curtido piled on top and salsa alongside."}},{"id":72,"servings":4,"tipType":"fish","pairingsType":"vietnamese","origin":{"zh":"柬埔寨","en":"Cambodia","ro":"Cambodgia"},"name":{"zh":"阿莫克咖喱鱼","en":"Amok","ro":"Amok"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["白鱼片600克（罗非鱼、鲷鱼或鲶鱼），去皮切成3厘米块","椰浆400毫升（1罐400毫升）","大鸡蛋2个，轻轻打散","鱼露3汤匙","细砂糖1茶匙","香茅2根，只取白色部分，极细切末","大蒜3瓣，切细末","小葱3个（约100克），切细末","南姜酱1茶匙（或1厘米新鲜南姜，磨碎）","姜黄粉1/2茶匙","干辣椒碎1/2茶匙或新鲜红辣椒1个，切细","卡菲尔青柠叶4片，去茎，极细切丝","大张香蕉叶4张（30x30厘米），用火软化，或用小碗代替","新鲜罗勒或泰式罗勒20克，用于装饰"],"en":["600 g white fish fillets (tilapia, snapper, or catfish), skin removed, cut into 3 cm pieces","400 ml coconut milk (1 x 400 ml can)","2 large eggs, lightly beaten","3 tbsp fish sauce","1 tsp caster sugar","2 lemongrass stalks, pale parts only, very finely minced","3 garlic cloves, finely minced","3 shallots (about 100 g), finely minced","1 tsp galangal paste (or 1 cm fresh galangal, grated)","1/2 tsp ground turmeric","1/2 tsp dried chilli flakes or 1 fresh red chilli, finely sliced","4 kaffir lime leaves, stems removed, very finely shredded","4 large banana leaf squares (30 x 30 cm), softened over a flame, or 4 ramekins","20 g fresh basil or Thai basil leaves, to garnish"],"ro":["600 g file de pește alb (tilapia, biban sau somn), fără piele, tăiat bucăți de 3 cm","400 ml lapte de cocos (1 conservă de 400 ml)","2 ouă mari, ușor bătute","3 linguri sos de pește","1 linguriță zahăr","2 tulpini lemongrass, doar partea palidă, fin tocate","3 căței de usturoi, fin tocați","3 șalote (aproximativ 100 g), fin tocate","1 linguriță pastă de galangal (sau 1 cm galangal proaspăt, ras)","1/2 linguriță turmeric măcinat","1/2 linguriță fulgi de ardei iute uscat sau 1 ardei roșu, fin tocat","4 frunze de kaffir lime, cotoare îndepărtate, fin feliate","4 pătrate mari de frunze de bananier (30 x 30 cm), înmuiate, sau ramekine","20 g frunze de busuioc proaspăt sau busuioc thai, pentru garnitură"]},"howIsMade":{"zh":"将香茅、大蒜、小葱、南姜、姜黄和辣椒捣碎或打成光滑的酱。在大碗里将椰浆、打散的鸡蛋、鱼露和糖搅拌均匀。拌入香料酱和一半的卡菲尔青柠叶丝。加入鱼块轻轻翻拌裹匀，腌制15分钟。将香蕉叶在煤气灶火焰上或热水中软化30秒，折叠成约12厘米宽、4厘米深的碗形，用牙签固定。将鱼肉混合物均匀分入4个香蕉叶碗中，每个填约三分之二，撒上剩余的卡菲尔青柠叶丝。将碗放入竹制蒸笼中放在沸水上，盖紧，蒸18-20分钟，直到阿莫克刚刚凝固（轻倾碗时不再流动）、表面轻按有弹性。用新鲜罗勒叶点缀，立即与清蒸茉莉香米一同上桌。","en":"Pound or blend the lemongrass, garlic, shallots, galangal, turmeric, and chilli into a smooth paste. In a large bowl, whisk together the coconut milk, beaten eggs, fish sauce, and sugar until combined. Stir in the spice paste and half the shredded kaffir lime leaves. Add the fish pieces and fold gently to coat; marinate for 15 minutes. Soften the banana leaf squares over a gas flame or in hot water for 30 seconds until pliable. Fold each into a cup shape about 12 cm across and 4 cm deep, securing with a toothpick. Divide the fish mixture evenly among the 4 banana leaf cups, filling each about two-thirds full, then scatter the remaining kaffir lime leaves on top. Set the cups in a bamboo steamer over boiling water, cover tightly, and steam for 18-20 minutes until the amok is just set — no longer liquid when the cup is gently tilted — and the top is slightly firm to the touch. Garnish with fresh basil leaves and serve immediately with steamed jasmine rice."}},{"id":73,"servings":4,"tipType":"meat","pairingsType":"indian","origin":{"zh":"尼泊尔","en":"Nepal","ro":"Nepal"},"name":{"zh":"尼泊尔饺子","en":"Momo","ro":"Momo"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["300克普通面粉（中筋粉），另备少量用于撒粉","150毫升温水","500克鸡肉或猪肉馅","1个中等洋葱（约120克），切成极细的碎末","3瓣大蒜，切细末","1汤匙新鲜生姜（约2厘米），磨成细泥","30克新鲜香菜，切碎","1茶匙孜然粉","1/2茶匙香菜粉","1/4茶匙姜黄粉","1茶匙细盐，分量使用","4个中等番茄（约400克），对半切开","2个干红辣椒或1/2茶匙辣椒片","1汤匙植物油"],"en":["300 g plain flour (all-purpose), plus extra for dusting","150 ml warm water","500 g ground chicken or pork","1 medium onion (about 120 g), very finely diced","3 garlic cloves, finely minced","1 tbsp fresh ginger (about 2 cm piece), finely grated","30 g fresh coriander (cilantro), finely chopped","1 tsp ground cumin","1/2 tsp ground coriander","1/4 tsp ground turmeric","1 tsp fine sea salt, divided","4 medium tomatoes (about 400 g), halved","2 dried red chillies or 1/2 tsp chilli flakes","1 tbsp vegetable oil"],"ro":["300 g făină albă (tip 550), plus extra pentru pudrat","150 ml apă caldă","500 g carne tocată de pui sau porc","1 ceapă medie (circa 120 g), tocată mărunt","3 căței de usturoi, tocați mărunt","1 lingură ghimbir proaspăt (circa 2 cm), ras fin","30 g coriandru proaspăt, tocat mărunt","1 linguriță chimen măcinat","1/2 linguriță coriandru măcinat","1/4 linguriță turmeric","1 linguriță sare fină, împărțită","4 roșii medii (circa 400 g), tăiate în jumătăți","2 ardei iuți uscați sau 1/2 linguriță fulgi de ardei iute","1 lingură ulei vegetal"]},"howIsMade":{"zh":"将面粉和半茶匙盐混合，分次加入温水，揉面5-6分钟至面团光滑、紧实、不粘手；用湿布盖好，醒发30分钟。另取一碗，将肉馅、洋葱、大蒜、生姜、香菜、孜然、香菜粉、姜黄、剩余半茶匙盐和植物油充分混合；放入冰箱冷藏15分钟。制作蘸酱：将番茄和干辣椒放入干锅大火烤4-5分钟至变软并带有焦斑，然后与大蒜和盐一起搅打成细滑的酱汁。将面团分成24等份（每份约15克），分别擀成直径约8厘米的薄圆形。将一满茶匙馅料放在面皮中央，提起边缘，用小叠褶的方式逐步捏合，顶部捏紧封口。将莫莫摆放在涂了油的烘焙纸上，间距至少1厘米，放入蒸锅。大火蒸12-15分钟，直至面皮变得半透明，轻轻按压莫莫能回弹，不感觉生粘。立即搭配番茄辣椒酱上桌。","en":"Combine flour and 1/2 tsp of the salt in a bowl, then add warm water a little at a time, mixing until a rough dough forms; knead for 5-6 minutes until smooth, firm, and no longer sticky, then cover with a damp cloth and rest for 30 minutes. In a separate bowl, mix the ground meat, onion, garlic, ginger, coriander leaves, cumin, ground coriander, turmeric, the remaining 1/2 tsp salt, and oil until well combined; refrigerate for 15 minutes to let the flavours meld. Meanwhile, make the dipping sauce: char the tomato halves and dried chillies in a dry heavy skillet over high heat for 4-5 minutes until softened and blackened in spots, then blend with the garlic and remaining salt until smooth. Divide the rested dough into 24 equal pieces (about 15 g each) and roll each into a thin round about 8 cm across. Place a heaped teaspoon of filling in the centre of each round, then gather the edges and pleat them together with small overlapping folds, pinching firmly at the top to seal. Line a bamboo or metal steamer with lightly oiled parchment paper and arrange the momo at least 1 cm apart. Set over a pot of vigorously boiling water, cover tightly, and steam for 12-15 minutes until the wrappers turn translucent and a gently pressed momo springs back without feeling doughy inside. Serve immediately with the tomato-chilli sauce."}},{"id":74,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"zh":"厄瓜多尔","en":"Ecuador","ro":"Ecuador"},"name":{"zh":"洋葱炖鱼汤","en":"Encebollado","ro":"Encebollado"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["700克新鲜金枪鱼或2罐水浸金枪鱼（共400克），沥干","600克木薯（yuca），去皮切成4厘米的块","1个大红洋葱（约200克），切成薄半圆形","4个中等番茄（约400克），粗切","4瓣大蒜，粗切","1茶匙孜然粉","1茶匙阿希奥特酱或1/2茶匙甜椒粉","1.5升鱼汤或清水","3汤匙青柠汁（约2个青柠）","2汤匙植物油","1茶匙细盐","30克新鲜香菜，分两份——一半烹饪用，一半装饰用","1个墨西哥辣椒或阿希辣椒，去籽，切薄片","2根小葱，切薄片（用于点缀）"],"en":["700 g fresh tuna or 2 cans tuna in water (400 g total), drained","600 g cassava (yuca), peeled and cut into 4 cm chunks","1 large red onion (about 200 g), thinly sliced into half-moons","4 medium tomatoes (about 400 g), roughly chopped","4 garlic cloves, roughly chopped","1 tsp ground cumin","1 tsp achiote paste or 1/2 tsp sweet paprika","1.5 litres fish stock or water","3 tbsp fresh lime juice (about 2 limes)","2 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), divided — half to cook, half to garnish","1 jalapeño or aji pepper, deseeded and finely sliced","2 spring onions, thinly sliced (to garnish)"],"ro":["700 g ton proaspăt sau 2 conserve ton în apă (400 g total), scurse","600 g yuca (manioc), curățată și tăiată bucăți de 4 cm","1 ceapă roșie mare (circa 200 g), tăiată în felii subțiri","4 roșii medii (circa 400 g), tăiate grosier","4 căței de usturoi, tăiați grosier","1 linguriță chimen măcinat","1 linguriță pastă de achiote sau 1/2 linguriță paprika dulce","1,5 litri supă de pește sau apă","3 linguri zeamă de lămâie verde (circa 2 lămâi)","2 linguri ulei vegetal","1 linguriță sare fină","30 g coriandru proaspăt, împărțit — jumătate pentru gătit, jumătate pentru servit","1 jalapeno sau ardei iute, fără semințe, feliat subțire","2 fire ceapă verde, tăiate subțire (pentru decor)"]},"howIsMade":{"zh":"在大锅中用中火加热植物油，加入洋葱、大蒜、番茄、墨西哥辣椒和孜然，不时搅拌，翻炒8-10分钟直至洋葱非常软烂、番茄化成浓稠的酱汁。加入阿希奥特酱，翻炒1分钟直至油脂变成深橙色。倒入鱼汤，煮沸后加入木薯，继续煮20-25分钟直至完全软透、边缘开始脱落。如使用新鲜金枪鱼，在轻盐的慢沸水中煮5-6分钟至熟透，稍凉后用手撕成大块。将撕碎的金枪鱼（或沥干的罐装金枪鱼）、一半香菜和青柠汁加入锅中，小火再煮3-4分钟使味道融合。按口味调盐，然后盛入深碗。撒上剩余香菜和小葱，搭配玉米脆片或炸芭蕉片上桌。","en":"Heat the oil in a large pot over medium heat, add the onion, garlic, tomatoes, jalapeño, and cumin, and cook for 8-10 minutes, stirring occasionally, until the onion is very soft and the tomatoes have broken down into a thick paste. Stir in the achiote paste and cook for 1 minute until the oil turns a deep orange. Pour in the stock, bring to a boil, then add the cassava and cook for 20-25 minutes until completely tender and just beginning to break apart at the edges. If using fresh tuna, poach the steaks in lightly salted simmering water for 5-6 minutes until just cooked through, cool slightly, and flake into large chunks. Add the flaked tuna (or drained canned tuna), half the coriander, and the lime juice to the pot; simmer for 3-4 minutes to marry the flavours. Season with salt to taste, then ladle the soup into deep bowls. Top with the remaining coriander and spring onions, and serve with tostadas or plantain chips on the side."}},{"id":75,"servings":4,"tipType":"soup","pairingsType":"middle-eastern","origin":{"zh":"摩洛哥","en":"Morocco","ro":"Maroc"},"name":{"zh":"摩洛哥汤","en":"Harira","ro":"Harira"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["400克羊肩肉，切成3厘米的块","400克鹰嘴豆罐头（1罐400克），沥干洗净","150克绿色或棕色扁豆，洗净","4个中等番茄（约400克），粗切","1个大洋葱（约200克），切成极细的碎末","3根芹菜茎带叶（约150克），切薄片","3瓣大蒜，切细末","1茶匙孜然粉","1茶匙肉桂粉 + 1茶匙姜粉","1/2茶匙姜黄粉 + 1茶匙细盐","2汤匙橄榄油","1.5升水或羊肉高汤","60克细粉丝，折成2厘米的段","30克新鲜香菜和意大利欧芹，粗切"],"en":["400 g lamb shoulder, cut into 3 cm chunks","400 g canned chickpeas (1 x 400 g can), rinsed and drained","150 g green or brown lentils, rinsed","4 medium tomatoes (about 400 g), roughly chopped","1 large onion (about 200 g), finely diced","3 celery stalks with leaves (about 150 g), finely sliced","3 garlic cloves, finely minced","1 tsp ground cumin","1 tsp ground cinnamon + 1 tsp ground ginger","1/2 tsp ground turmeric + 1 tsp fine sea salt","2 tbsp olive oil","1.5 litres water or lamb stock","60 g thin vermicelli, broken into 2 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped"],"ro":["400 g spata de miel, taiata bucati de 3 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","150 g linte verde sau bruna, clatita","4 rosii medii (circa 400 g), taiate grosier","1 ceapa mare (circa 200 g), tocata marunt","3 tulpini de telina cu frunze (circa 150 g), feliate subtire","3 căței de usturoi, tocati marunt","1 lingurita chimen macinat","1 lingurita scortisoara + 1 lingurita ghimbir macinat","1/2 lingurita turmeric + 1 lingurita sare fina","2 linguri ulei de masline","1,5 litri apa sau supa de miel","60 g vermicelli subtire, rupt in bucati de 2 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier"]},"howIsMade":{"zh":"在大锅中用中高火加热油，加入羊肉块翻炒4-5分钟至各面均匀上色。加入洋葱、芹菜和大蒜，翻炒5分钟至变软。加入孜然、肉桂、姜粉、姜黄和盐，炒1分钟至香味飘出。加入番茄、鹰嘴豆、扁豆，倒入水或高汤；烧开后撇去浮沫。调小火，半盖锅盖，小火炖煮45-50分钟，直至羊肉软烂、扁豆融入汤汁使汤略微浓稠。加入细粉丝，煮5-6分钟至熟软。离火，拌入香菜和欧芹，按口味挤入柠檬汁。盛入碗中，搭配面包和椰枣上桌。","en":"Heat the oil in a large pot over medium-high heat, add the lamb chunks and sear for 4-5 minutes, turning occasionally, until browned on all sides. Add the onion, celery, and garlic and cook for 5 minutes until softened. Stir in the cumin, cinnamon, ginger, turmeric, and salt and cook for 1 minute until fragrant. Add the tomatoes, chickpeas, and lentils, pour in the water or stock, and bring to a boil; skim any foam from the surface. Reduce the heat to low, cover partially, and simmer for 45-50 minutes until the lamb is tender and the lentils have dissolved into the broth, thickening it slightly. Stir in the vermicelli and cook for 5-6 minutes until tender. Remove from the heat, stir in the coriander and parsley, and squeeze in lemon juice to taste. Ladle into bowls and serve immediately with crusty bread and dates."}},{"id":76,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"zh":"格鲁吉亚","en":"Georgia","ro":"Georgia"},"name":{"zh":"格鲁吉亚豆炖菜","en":"Lobio","ro":"Lobio"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["500克干红腰豆（或2罐400克装，洗净）","1个大洋葱（约200克），切成极细的碎末","4瓣大蒜，切细末","100克核桃仁，磨细或切极细末","1茶匙香菜粉","1/2茶匙葫芦巴粉（utsho suneli）","1/2茶匙肉桂粉","1/2茶匙辣椒片或1个小红辣椒去籽切碎","2汤匙白葡萄酒醋或红葡萄酒醋","3汤匙植物油","1茶匙细盐","30克新鲜香菜，切碎","4汤匙石榴籽（约半个石榴）","4根小葱，切薄片"],"en":["500 g dried red kidney beans (or 2 x 400 g cans, rinsed)","1 large onion (about 200 g), finely diced","4 garlic cloves, finely minced","100 g walnut halves, finely ground or very finely chopped","1 tsp ground coriander","1/2 tsp ground fenugreek (utsho suneli)","1/2 tsp ground cinnamon","1/2 tsp dried chilli flakes or 1 small red chilli, deseeded and minced","2 tbsp white wine vinegar or red wine vinegar","3 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), finely chopped","4 tbsp pomegranate seeds (about 1/2 pomegranate)","4 spring onions, thinly sliced"],"ro":["500 g fasole rosie uscata (sau 2 x 400 g conserve, clatite)","1 ceapa mare (circa 200 g), tocata marunt","4 căței de usturoi, tocati marunt","100 g miez de nuca, macinat fin sau tocat marunt","1 lingurita coriandru macinat","1/2 lingurita schinduf macinat (utsho suneli)","1/2 lingurita scortisoara","1/2 lingurita fulgi de ardei iute sau 1 ardei iute mic, fara seminte, tocat","2 linguri otet alb sau de vin rosu","3 linguri ulei vegetal","1 lingurita sare fina","30 g coriandru proaspat, tocat marunt","4 linguri boabe de rodie (circa 1/2 rodie)","4 fire ceapa verde, taiate subtire"]},"howIsMade":{"zh":"如使用干豆，将其在冷水中浸泡一夜，沥干后置于大锅中用新鲜冷水盖过，大火煮开，撇去浮沫，转小火煮45-60分钟至完全软透、开始散裂，汤汁呈深红色且浓稠。平底锅中火加热植物油，加入洋葱翻炒10-12分钟至深金黄色且非常软烂。加入大蒜、香菜粉、葫芦巴、肉桂和辣椒，炒2分钟至香味飘出。将洋葱混合物、磨碎的核桃和醋拌入豆中，小火炖10分钟，不时搅拌，至味道融合、豆子极软且酱汁浓稠——用铲子将几粒豆子压在锅边以帮助增稠。按口味调盐和醋。离火，拌入一半新鲜香菜。盛入浅盘，撒上小葱、石榴籽和剩余香菜，温热配面包上桌。","en":"If using dried beans, soak them overnight in cold water, then drain, cover with fresh cold water in a large pot, bring to a boil, skim any foam, and simmer for 45-60 minutes until completely tender and starting to break apart, with a thick dark-red cooking liquid. Heat the oil in a frying pan over medium heat, add the onion and cook for 10-12 minutes, stirring occasionally, until deep golden and very soft. Add the garlic, ground coriander, fenugreek, cinnamon, and chilli and cook for 2 minutes until fragrant. Stir the onion mixture, ground walnuts, and vinegar into the cooked beans and simmer over low heat for 10 minutes, stirring occasionally, until the flavours meld and the beans are very soft with a thick sauce — mash a few beans against the side of the pot to help thicken. Season with salt and more vinegar to taste. Remove from the heat and stir in half the fresh coriander. Transfer to a shallow dish and top with the spring onions, pomegranate seeds, and remaining coriander. Serve warm with flatbread."}},{"id":77,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"zh":"阿尔及利亚","en":"Algeria","ro":"Algeria"},"name":{"zh":"阿尔及利亚炖肉饼","en":"Chakhchoukha","ro":"Chakhchoukha"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["600克带骨羊肩肉或颈肉，切成4厘米的块","400克鹰嘴豆罐头（1罐400克），沥干洗净","4个中等番茄（约400克），粗切","2个中等洋葱（约300克），切成极细的碎末","4瓣大蒜，切细末","2汤匙植物油","1茶匙孜然粉","1茶匙香菜粉","1茶匙甜椒粉","1/2茶匙肉桂粉 + 1/2茶匙黑胡椒粉","1茶匙细盐","600毫升水或羊肉高汤","4张大片鲁加格饼（阿尔及利亚薄饼）或大张玉米饼，撕成5厘米的块","30克新鲜香菜和意大利欧芹，粗切（用于点缀）"],"en":["600 g bone-in lamb shoulder or neck, cut into 4 cm pieces","400 g canned chickpeas (1 x 400 g can), rinsed and drained","4 medium tomatoes (about 400 g), roughly chopped","2 medium onions (about 300 g), finely diced","4 garlic cloves, finely minced","2 tbsp vegetable oil","1 tsp ground cumin","1 tsp ground coriander","1 tsp sweet paprika","1/2 tsp ground cinnamon + 1/2 tsp ground black pepper","1 tsp fine sea salt","600 ml water or lamb stock","4 large sheets of rougag (Algerian flatbread) or large tortillas, torn into 5 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped (to garnish)"],"ro":["600 g spata de miel cu os sau gat, taiata bucati de 4 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","4 rosii medii (circa 400 g), taiate grosier","2 cepe medii (circa 300 g), tocate marunt","4 căței de usturoi, tocati marunt","2 linguri ulei vegetal","1 lingurita chimen macinat","1 lingurita coriandru macinat","1 lingurita boia dulce","1/2 lingurita scortisoara + 1/2 lingurita piper negru","1 lingurita sare fina","600 ml apa sau supa de miel","4 foi mari de rougag (lipie algeriana) sau 4 tortilla mari, rupte bucati de 5 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier (pentru decor)"]},"howIsMade":{"zh":"大锅中大火加热植物油，分批加入羊肉块，每面煎4-5分钟至全面上色。加入洋葱和大蒜翻炒5分钟至变软金黄。加入孜然、香菜粉、辣椒粉、肉桂、盐和黑胡椒，翻炒1分钟至香料香气飘出。加入番茄，不时搅拌，煮8-10分钟至形成浓稠酱汁。倒入水或高汤，加入鹰嘴豆，烧开后调至小火，盖锅炖煮50-60分钟至羊肉完全软烂、骨肉分离。将撕碎的薄饼铺在大盘底部，将热腾腾的肉和酱汁大量盛在上面，轻轻向下压让饼充分吸收汁液软化。撒上新鲜香菜和欧芹，立即上桌。","en":"Heat the oil in a large heavy pot over medium-high heat, add the lamb in batches and sear for 4-5 minutes until browned on all sides. Add the onion and garlic and cook for 5 minutes until softened and golden. Stir in the cumin, coriander, paprika, cinnamon, salt, and pepper and cook for 1 minute until the spices smell toasted. Add the tomatoes and cook for 8-10 minutes, stirring occasionally, until they break down into a thick sauce. Pour in the water or stock, add the chickpeas, and bring to a boil; reduce the heat to low, cover, and simmer for 50-60 minutes until the lamb is completely tender and falling off the bone. Scatter the torn flatbread pieces over the bottom of a large serving dish and ladle the hot meat and sauce generously on top, pressing the bread down gently so it absorbs the liquid and softens — it should be soaked through but not dissolving. Garnish with the fresh coriander and parsley and serve immediately."}},{"id":78,"servings":4,"tipType":"meat","timeMins":{"total":330,"active":60},"pairingsType":"meat","origin":{"zh":"印度尼西亚","en":"Indonesia","ro":"Indonezia"},"name":{"zh":"仁当牛肉","en":"Rendang","ro":"Rendang"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["1千克牛肩肉或牛腩，切成5厘米的块","800毫升全脂椰奶（2罐400毫升）","5个葱头（约150克），粗切","4瓣大蒜，粗切","2汤匙新鲜生姜（约3厘米），粗切","1汤匙新鲜高良姜（约2厘米）或1茶匙高良姜酱","3根香茅茎，白色部分，粗切","4-6个干红辣椒，用温水浸泡15分钟，沥干","4片卡菲尔青柠叶，去梗，切极细","1茶匙姜黄粉","1茶匙香菜粉","1茶匙孜然粉","1茶匙细盐","1汤匙植物油"],"en":["1 kg beef chuck or brisket, cut into 5 cm cubes","800 ml full-fat coconut milk (2 x 400 ml cans)","5 shallots (about 150 g), roughly chopped","4 garlic cloves, roughly chopped","2 tbsp fresh ginger (about 3 cm piece), roughly chopped","1 tbsp fresh galangal (about 2 cm) or 1 tsp galangal paste","3 lemongrass stalks, pale parts only, roughly sliced","4-6 dried red chillies, soaked in warm water 15 minutes and drained","4 kaffir lime leaves, stems removed, very finely shredded","1 tsp ground turmeric","1 tsp ground coriander","1 tsp ground cumin","1 tsp fine sea salt","1 tbsp vegetable oil"],"ro":["1 kg muschi de vita sau piept, taiat cuburi de 5 cm","800 ml lapte de cocos integral (2 x 400 ml)","5 esalote (circa 150 g), taiate grosier","4 căței de usturoi, tăiați grosier","2 linguri ghimbir proaspat (circa 3 cm), taiat grosier","1 lingura galangal proaspat (circa 2 cm) sau 1 lingurita pasta galangal","3 tulpini de lemongrass, partile palide, feliate grosier","4-6 ardei iuti rosii uscati, înmuiați in apa calda 15 minute, scursi","4 frunze de kafir lime, coada indepartata, maruntite fin","1 lingurita turmeric macinat","1 lingurita coriandru macinat","1 lingurita chimen macinat","1 lingurita sare fina","1 lingura ulei vegetal"]},"howIsMade":{"zh":"将葱头、大蒜、生姜、高良姜、香茅和泡发的辣椒加入2汤匙椰奶，搅打至完全细滑的酱泥，约需2分钟。大锅中火加热植物油，加入香料酱，不断搅拌翻炒5-6分钟至深金黄色且生辣味消散。加入牛肉块翻炒使其均匀裹上酱料，煎3-4分钟至略微上色。倒入剩余椰奶，加入卡菲尔青柠叶、姜黄、香菜粉、孜然和盐搅拌均匀。大火烧开后调至中低火，不加盖炖煮1.5小时，每隔15-20分钟搅拌一次，直至椰奶明显浓稠并变成浅棕色。继续烹煮，更频繁地搅拌（每5-10分钟），再煮30-45分钟直至酱汁几乎收干、油脂析出；牛肉此时开始在自身油脂中炸制，颜色转为深棕色。搭配蒸白饭上桌。","en":"Blend the shallots, garlic, ginger, galangal, lemongrass, and soaked chillies with 2 tbsp of the coconut milk until completely smooth — about 2 minutes in a food processor. Heat the oil in a large heavy pot over medium heat, add the spice paste and cook for 5-6 minutes, stirring constantly, until deep golden and the raw smell has gone. Add the beef cubes and stir to coat with the paste; cook for 3-4 minutes until lightly coloured. Pour in the remaining coconut milk, add the kaffir lime leaves, turmeric, coriander, cumin, and salt, and stir to combine. Bring to a boil, then reduce to medium-low and simmer uncovered for 1.5 hours, stirring every 15-20 minutes, until the coconut milk thickens significantly and turns light brown. Continue cooking, stirring more frequently (every 5-10 minutes), for another 30-45 minutes as the sauce reduces to almost nothing and the oil splits from the coconut; the beef will begin to fry in its own fat and turn deep mahogany brown — this is when rendang is ready. Serve with steamed white rice."}},{"id":79,"servings":4,"tipType":"fish","timeMins":{"total":4380,"active":45},"pairingsType":"fish","origin":{"zh":"瑞典","en":"Sweden","ro":"Suedia"},"name":{"zh":"腌三文鱼","en":"Gravlax","ro":"Gravlax"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["600克三文鱼片，带皮去刺","3汤匙粗海盐","2汤匙细砂糖","1茶匙白胡椒粒，粗磨碎","60克新鲜莳萝（1大束），粗切碎","2汤匙北欧烈酒或伏特加（可选）"],"en":["600 g salmon fillet, skin-on and pin-boned","3 tbsp coarse sea salt","2 tbsp caster sugar","1 tsp white peppercorns, coarsely crushed","60 g fresh dill (1 large bunch), roughly chopped","2 tbsp aquavit or vodka (optional)"],"ro":["600 g file de somon cu piele, cu oasele îndepărtate","3 linguri sare grunjoasă de mare","2 linguri zahăr tos","1 linguriță boabe de piper alb, zdrobite grosier","60 g mărar proaspăt (1 legătură mare), tocat grosier","2 linguri aquavit sau vodcă (opțional)"]},"howIsMade":{"zh":"将粗盐、砂糖和磨碎的白胡椒粒混合于小碗中。将三文鱼鱼皮朝下放在一大张保鲜膜上；将一半莳萝均匀按压在鱼肉上，将腌制混合物均匀撒在上面，如使用可淋上北欧烈酒，再用剩余莳萝覆盖。用保鲜膜紧密包裹，放入深盘中，上面压一个重盘以挤压鱼肉。冷藏48-72小时，每12小时翻转一次让鱼腌制入味——盐水会积在盘中。拆开保鲜膜，在冷水下冲洗并用厨房纸巾擦干。用锋利的薄刃刀斜切成非常薄的片，配深色黑麦面包和芥末莳萝酱享用。","en":"Mix the coarse salt, sugar, and crushed peppercorns in a small bowl. Lay the salmon skin-side down on a large piece of cling film; press half the dill evenly over the flesh, spread the cure uniformly over the top, drizzle with aquavit if using, then cover with the remaining dill. Wrap tightly in the cling film and place in a deep dish, setting a heavy plate on top to press the fish. Refrigerate for 48-72 hours, turning the parcel every 12 hours as it cures — brine will pool in the dish. Unwrap, rinse under cold water, and pat dry with paper towels. Slice very thinly on the diagonal with a sharp flexible knife and serve on dark rye bread with a mustard-dill sauce."}},{"id":80,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"比利时","en":"Belgium","ro":"Belgia"},"name":{"zh":"比利时啤酒炖牛肉","en":"Stoofvlees","ro":"Stoofvlees"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["1千克炖牛肉（肩肉或胸肉），切成4厘米方块","330毫升比利时深色啤酒（Leffe Brune或同类）","500克洋葱（约3个中等大小），切成薄片","2汤匙第戎芥末酱","2片厚切（约80克）隔夜棕色面包，去皮","2汤匙中性油","2片月桂叶","3枝新鲜百里香","1汤匙红糖","1汤匙红葡萄酒醋","1茶匙细盐","半茶匙黑胡椒粉"],"en":["1 kg beef stew meat (chuck or brisket), cut into 4 cm cubes","330 ml dark Belgian ale (Leffe Brune or similar)","500 g onions (about 3 medium), thinly sliced","2 tbsp Dijon mustard","2 thick slices (about 80 g) stale brown bread, crusts removed","2 tbsp neutral oil","2 bay leaves","3 fresh thyme sprigs","1 tbsp brown sugar","1 tbsp red wine vinegar","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["1 kg carne de vită pentru tocăniță (capac sau piept), tăiată cuburi de 4 cm","330 ml bere belgiană brună (Leffe Brune sau similară)","500 g ceapă (circa 3 medii), feliată subțire","2 linguri muștar Dijon","2 felii groase (circa 80 g) pâine brună veche, fără coajă","2 linguri ulei neutru","2 foi de dafin","3 crenguțe de cimbru proaspăt","1 lingură zahăr brun","1 lingură oțet de vin roșu","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"zh":"牛肉用盐和黑胡椒调味。在大号厚底锅中以中高火加热油，分批将牛肉煎3-4分钟至每面深金棕色，然后取出备用。转中火，在同锅中加入洋葱，翻炒12-15分钟至柔软金黄。将牛肉放回锅中，加入月桂叶和百里香，倒入啤酒——啤酒应几乎没过牛肉。在每片面包一面涂厚厚的芥末酱，芥末面朝下放在炖肉上；面包会溶解并使汤汁变稠。加入红糖和醋搅匀，煮至微沸，半掩锅盖以小火慢炖2小时，每30分钟搅拌一次，直至牛肉非常酥烂。最后20-30分钟取下锅盖，收汁至光亮浓稠、能挂在勺背的深色肉汁；取出月桂叶和百里香，配炸薯条或土豆泥食用。","en":"Season the beef with salt and pepper. Heat the oil in a large heavy casserole over medium-high and brown the beef in batches for 3-4 minutes per side until deeply golden; transfer to a plate. Reduce heat to medium, add the onions to the same pot and cook for 12-15 minutes, stirring occasionally, until soft and golden. Return the beef to the pot, tuck in the bay leaves and thyme, and pour in the beer — it should nearly cover the meat. Spread one side of each bread slice thickly with mustard and lay them mustard-side down on top of the stew; the bread will dissolve and thicken the sauce. Stir in the brown sugar and vinegar, bring to a gentle simmer, cover with the lid slightly ajar, and cook over low heat for 2 hours, stirring every 30 minutes, until the beef is very tender. Remove the lid for the final 20-30 minutes to reduce the sauce to a glossy dark gravy that coats the back of a spoon; discard the bay leaves and thyme and serve with frites or mashed potato."}},{"id":81,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"zh":"摩尔多瓦","en":"Moldova","ro":"Moldova"},"name":{"zh":"摩尔多瓦鸡汤","en":"Zeama","ro":"Zeamă"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["1千克带骨鸡块（鸡腿和大腿）","2根中等胡萝卜（约200克），去皮切半","1个中等洋葱，切半","2根芹菜（带叶）","150克细鸡蛋面条","200毫升borș或4汤匙新鲜柠檬汁","1小把新鲜香芹（约15克），粗切碎，或平叶欧芹","1茶匙细盐","半茶匙白胡椒"],"en":["1 kg bone-in chicken pieces (legs and thighs)","2 medium carrots (about 200 g), peeled and halved","1 medium onion, halved","2 celery stalks with leaves","150 g thin egg noodles","200 ml borș (fermented wheat bran liquid) or 4 tbsp fresh lemon juice","1 small bunch fresh lovage (about 15 g), roughly chopped, or flat-leaf parsley","1 tsp fine salt","1/2 tsp white pepper"],"ro":["1 kg bucăți de pui cu os (pulpe și coapse)","2 morcovi medii (circa 200 g), curățați și tăiați în jumătate","1 ceapă medie, tăiată în jumătate","2 tulpini de țelină cu frunze","150 g tăiței subțiri de ou","200 ml borș sau 4 linguri suc proaspăt de lămâie","1 legătură mică leuștean proaspăt (circa 15 g), tocat grosier, sau pătrunjel","1 linguriță sare fină","1/2 linguriță piper alb"]},"howIsMade":{"zh":"将鸡肉放入大锅中，加入2升冷水，中高火烧开；在最初5-10分钟内撇去浮沫，直至汤汁清澈。加入胡萝卜、洋葱和芹菜，转中小火，盖上盖子留一缝，小火炖45-50分钟，直至鸡肉完全熟透、容易脱骨。捞出鸡肉和蔬菜；丢弃洋葱，将胡萝卜切成圆片，将鸡肉撕成小块，去皮去骨。将撕好的鸡肉和胡萝卜片放回锅中，中火再次煮沸。加入面条，煮5-7分钟（或按包装指示）至刚好熟透。倒入borș或柠檬汁，搅拌并品尝——汤应有愉快的酸味；按需添加更多。用盐和白胡椒调味，加入香芹或欧芹，立即上桌。","en":"Place the chicken in a large pot, cover with 2 litres of cold water, and bring to a boil over medium-high heat; skim the foam that rises for the first 5-10 minutes until the broth runs clear. Add the carrots, onion, and celery, reduce heat to medium-low, partially cover, and simmer for 45-50 minutes until the chicken is cooked through and falling from the bone. Lift out the chicken and vegetables; discard the onion, slice the carrots into rounds, and shred the chicken into bite-sized pieces, discarding skin and bones. Return the shredded chicken and carrot rounds to the pot and bring back to a simmer over medium heat. Add the noodles and cook for 5-7 minutes (or per packet) until just tender. Pour in the borș or lemon juice, stir, and taste — the soup should have a pleasant sour edge; add more as needed. Season with salt and white pepper, stir in the lovage or parsley, and serve immediately."}},{"id":82,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"澳大利亚","en":"Australia","ro":"Australia"},"name":{"zh":"肉馅饼","en":"Meat Pie","ro":"Meat Pie"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["375克现成酥皮（底层用）","250克现成千层酥皮（盖层用）","500克精瘦牛肉末","1个中等洋葱（约150克），细切碎","2瓣大蒜，切末","250毫升牛肉汤","2汤匙番茄酱","1汤匙伍斯特沙司","2汤匙中筋面粉","1个鸡蛋，轻打散，用于刷面","1茶匙细盐","半茶匙黑胡椒粉"],"en":["375 g ready-made shortcrust pastry","250 g ready-made puff pastry","500 g lean beef mince","1 medium onion (about 150 g), finely diced","2 garlic cloves, minced","250 ml beef stock","2 tbsp tomato paste","1 tbsp Worcestershire sauce","2 tbsp plain flour","1 egg, lightly beaten, for brushing","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["375 g aluat fraged gata preparat","250 g aluat foietaj gata preparat","500 g carne de vită tocată (slabă)","1 ceapă medie (circa 150 g), tăiată mărunt","2 căței de usturoi, pisați","250 ml supă de vită","2 linguri pastă de roșii","1 lingură sos Worcestershire","2 linguri făină albă","1 ou, bătut ușor, pentru uns","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"zh":"烤箱预热至200°C（风扇180°C）。在大煎锅中加热少许油，以中高火将洋葱和蒜末炒3-4分钟至软化。加入牛肉馅，用勺子将其打散，翻炒6-8分钟至全部变色。加入面粉翻炒1分钟，再加入牛肉汤、番茄酱、伍斯特沙司、盐和黑胡椒搅匀。中火慢煮12-15分钟，偶尔搅拌，直到汤汁变稠能挂勺背——馅料应湿润但不稀；离火冷却15分钟。将酥皮擀开，切出4个圆形铺入4个单人派模（约12厘米直径），按压贴模并用叉子扎底。将馅料平均分入派模，盖上千层酥皮盖子，压紧边缘密封，刷上蛋液。烘烤25-30分钟，直至酥皮呈深金色、盖子鼓起酥脆；静置5分钟后搭配番茄酱享用。","en":"Preheat the oven to 200°C (180°C fan). Heat a drizzle of oil in a large frying pan over medium-high heat, add the onion and garlic and cook for 3-4 minutes until softened. Add the beef mince and cook, breaking it up with a spoon, for 6-8 minutes until browned all over. Stir in the flour, cook for 1 minute, then add the stock, tomato paste, Worcestershire sauce, salt, and pepper; stir to combine. Simmer over medium heat for 12-15 minutes, stirring occasionally, until the gravy thickens to coat the back of a spoon — the filling should be moist but not runny; remove from heat and cool for 15 minutes. Roll out the shortcrust pastry and cut 4 circles to line 4 individual pie tins (about 12 cm diameter); press into the tins and prick the bases with a fork. Divide the filling evenly between the tins, top with puff pastry lids, press the edges to seal, and brush with beaten egg. Bake for 25-30 minutes until deep golden and the lids are puffed and crisp; rest for 5 minutes then serve with tomato sauce."}},{"id":83,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"zh":"叙利亚","en":"Syria","ro":"Siria"},"name":{"zh":"法塔","en":"Fatteh","ro":"Fatteh"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"zh":["2个大皮塔饼（约200克），撕成一口大小的块","400克罐装鹰嘴豆（1罐400克），沥干冲洗","500克全脂原味酸奶","3瓣大蒜，切末","芝麻酱2汤匙","新鲜柠檬汁2汤匙","无盐黄油3汤匙","松子50克","孜然粉1茶匙","甜椒粉1茶匙","细盐1/2茶匙","新鲜香芹2汤匙，细切碎"],"en":["2 large pita breads (about 200 g), torn into bite-sized pieces","400 g canned chickpeas (1 x 400 g can), drained and rinsed","500 g full-fat plain yogurt","3 garlic cloves, minced","2 tbsp tahini","2 tbsp fresh lemon juice","3 tbsp unsalted butter","50 g pine nuts","1 tsp ground cumin","1 tsp sweet paprika","1/2 tsp fine salt","2 tbsp fresh parsley, finely chopped"],"ro":["2 pâini pita mari (circa 200 g), rupte în bucăți","400 g năut din conservă (1 x 400 g), scurs și clătit","500 g iaurt integral simplu","3 căței de usturoi, pisați","2 linguri tahini","2 linguri suc proaspăt de lămâie","3 linguri unt nesărat","50 g semințe de pin","1 linguriță chimion măcinat","1 linguriță boia dulce","1/2 linguriță sare fină","2 linguri pătrunjel proaspăt, tocat fin"]},"howIsMade":{"zh":"烤箱预热至200°C。将皮塔饼块与少许油混合，铺在烤盘上烤8-10分钟至金黄酥脆。沥干鹰嘴豆；在小锅中加入少量盐和孜然以中火加热3-4分钟至热透。将酸奶、蒜末、芝麻酱、柠檬汁和盐搅匀至顺滑；调整调味。将烤好的皮塔饼块均匀铺在大浅盘上。将温热的鹰嘴豆均匀铺在皮塔饼上。将酸奶酱汁大量浇在鹰嘴豆上充分覆盖。在小煎锅中以中火融化黄油；加入松子翻炒2-3分钟至金黄；加入甜椒粉后立即将热黄油和松子淋在酸奶上。撒上切碎的香芹，趁皮塔饼变软前立即上桌。","en":"Preheat the oven to 200°C. Toss the pita pieces with a drizzle of oil, spread on a baking tray and bake for 8-10 minutes until golden and crisp. Drain the chickpeas; heat in a small saucepan with a pinch of salt and cumin over medium heat for 3-4 minutes until warmed through. Whisk the yogurt, garlic, tahini, lemon juice, and salt until smooth; taste and adjust seasoning. Spread the toasted pita pieces in an even layer on a large serving platter. Spoon the warm chickpeas evenly over the pita. Pour the yogurt sauce over the chickpeas, covering everything generously. Melt the butter in a small pan over medium heat; add the pine nuts and cook for 2-3 minutes, stirring, until golden; stir in the paprika and immediately drizzle the hot butter and pine nuts over the yogurt. Scatter the chopped parsley on top and serve immediately before the pita softens."}},{"id":84,"servings":4,"tipType":"def","pairingsType":"def","origin":{"zh":"丹麦","en":"Denmark","ro":"Danemarca"},"name":{"zh":"丹麦开放式三明治","en":"Smørrebrød","ro":"Smørrebrød"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"zh":["8片丹麦黑麦面包（黑麦粗面包），约400克","无盐黄油100克，软化","腌鲱鱼片400克（8片），沥干","4个鸡蛋，水煮10分钟，去壳切成圆片","1个小红洋葱（约80克），切成极细的圆圈","4个小萝卜，切成薄圆片","刺山柑2汤匙，沥干","酸奶油或法式酸奶油4汤匙","第戎芥末酱1茶匙","新鲜莳萝小束（约15克）","细盐1/2茶匙"],"en":["8 slices dark rye bread (rugbrød), about 400 g","100 g unsalted butter, softened","400 g pickled herring fillets (8 fillets), drained","4 eggs, hard-boiled (10 minutes), peeled and sliced into rounds","1 small red onion (about 80 g), very finely sliced into rings","4 radishes, thinly sliced into rounds","2 tbsp capers, drained","4 tbsp soured cream or crème fraîche","1 tsp Dijon mustard","1 small bunch fresh dill (about 15 g)","1/2 tsp fine salt"],"ro":["8 felii de pâine daneză de secară (rugbrød), circa 400 g","100 g unt nesărat, înmuiat","400 g hering murat (8 fileuri), scurs","4 ouă fierte tari (10 minute), decojite și feliate în rondele","1 ceapă roșie mică (circa 80 g), feliată subțire în inele","4 ridichi, feliate subțire în rondele","2 linguri capere, scurse","4 linguri smântână sau crème fraîche","1 linguriță muștar Dijon","1 legătură mică de mărar proaspăt (circa 15 g)","1/2 linguriță sare fină"]},"howIsMade":{"zh":"将鸡蛋放入沸水中煮10分钟，再转入冷水浸5分钟；剥壳后切成圆片。在小碗中将酸奶油与第戎芥末酱和少许盐混合均匀。将软化黄油厚厚地涂抹在每片黑麦面包上直至边缘——每片约1汤匙。将1-2片腌鲱鱼片放在每片涂好黄油的面包上，让其自然弯曲。在鲱鱼上加一小勺芥末奶油，然后在旁边摆上2-3片煮蛋圆。在上面撒上红洋葱圈、萝卜片和刺山柑。最后放上新鲜莳萝枝，立即搭配冰镇啤酒或北欧烈酒享用。","en":"Hard-boil the eggs: lower into boiling water and cook for 10 minutes, then transfer to cold water for 5 minutes before peeling and slicing into rounds. Mix the soured cream with the Dijon mustard and a pinch of salt in a small bowl. Spread each slice of rye bread generously with softened butter right to the edges — about 1 tablespoon per slice. Lay 1-2 pickled herring fillets on each buttered slice, letting them curve naturally over the surface. Spoon a small dollop of mustard cream onto the herring, then arrange 2-3 egg rounds alongside. Scatter red onion rings, radish slices, and capers over the top. Finish with fresh dill sprigs and serve immediately with a cold beer or aquavit."}},{"id":85,"origin":{"zh":"朝鲜","en":"North Korea","ro":"Coreea de Nord"},"name":{"zh":"冷面","en":"Naengmyeon","ro":"Naengmyeon"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","timeMins":{"total":600,"active":60},"pairingsType":"korean","ingredients":{"zh":["荞麦干面条（memil-guksu）400克","牛腩300克，炖至软烂后冷藏，切薄片","牛腩汤1.5升，完全冷藏去油","韩国梨（nashi）1个，去皮切薄片","中等黄瓜1根，切细丝","白煮蛋4个，对半切","米醋2大勺","韩国芥末（芥子酱）1小勺或英式芥末","辣椒粉（gochugaru）1大勺（可选，作为桌上调味品）","盐和糖适量调汤","冰块适量"],"en":["400g dried buckwheat noodles (memil-guksu)","300g beef brisket, simmered until tender, chilled, thinly sliced","1.5L beef brisket broth, fully chilled and defatted","1 Korean pear (nashi), peeled, thinly sliced","1 medium cucumber, julienned","4 hard-boiled eggs, halved","2 tbsp rice vinegar","1 tsp Korean mustard (gyeoja) or English mustard","1 tbsp gochugaru (optional, as table condiment)","salt and sugar to taste for the broth","ice cubes as needed"],"ro":["400g tăiței de hrișcă uscați (memil-guksu)","300g piept de vită, fiert și refrigerat, feliat subțire","1.5L supă de piept de vită (răcită complet la frigider, degresată)","1 pară coreeană (nashi), curățată, feliată subțire","1 castravete mediu, feliat julien","4 ouă fierte tari, înjumătățite","2 linguri oțet de orez","1 linguriță muștar coreean (gyeoja) sau muștar englez","1 lingură gochugaru (opțional, pentru condiment la masă)","sare și zahăr după gust pentru supa de bază","cuburi de gheață — câte este necesar"]},"howIsMade":{"zh":"提前一天：将牛腩放入2升水中，加盐1小勺、2厘米姜块、3根葱，小火炖1.5–2小时。让肉在汤里冷却后放冰箱过夜。次日揭去凝固的油脂层。用米醋、糖、盐调味冷汤，要略酸略甜。需要时加冰进一步冷却。按包装说明煮面（通常3–4分钟），捞出立刻在冷水下搓洗30秒去除淀粉彻底冷却。将面条放入深碗，倒入冷汤没过面条。摆上牛腩片、梨片、黄瓜丝和半个鸡蛋。立即上桌，附上米醋和芥末。","en":"Day before: simmer beef brisket in 2L water with 1 tsp salt, a 2 cm piece of ginger, and 3 spring onions over low heat for 1.5–2 hours. Let meat cool in the broth, then refrigerate overnight. Next day, lift off the solidified fat layer. Season the cold broth with rice vinegar, sugar, and salt — it should be lightly tart and subtly sweet. Chill further with ice if needed. Cook noodles per packet (usually 3–4 minutes), drain and immediately rinse under cold running water for 30 seconds, rubbing with hands to remove starch and chill completely. Nest noodles in deep bowls. Ladle cold broth to cover. Top with sliced brisket, pear, julienned cucumber, and halved egg. Serve at once with vinegar and mustard on the side."}},{"id":86,"origin":{"zh":"巴基斯坦","en":"Pakistan","ro":"Pakistan"},"name":{"zh":"尼哈里炖肉","en":"Nihari","ro":"Nihari"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"zh":["1千克带骨牛腱子，切成5厘米的块","2根骨髓骨，每根约5厘米长","4汤匙酥油或澄清黄油","2个大洋葱（约300克），切薄片","2汤匙姜蒜泥","1.5茶匙红辣椒粉","1茶匙香菜粉","1/2茶匙姜黄粉","1.5茶匙盐","1茶匙尼哈里马萨拉或葛拉姆马萨拉","3汤匙面粉与100毫升冷水混合成浆","5厘米新鲜生姜，去皮切细丝，用于装盘","1个柠檬切角和一把新鲜香菜叶，用于装盘"],"en":["1 kg bone-in beef shanks, cut into 5 cm pieces","2 marrow bones, each about 5 cm long","4 tbsp ghee or clarified butter","2 large onions (~300 g), thinly sliced","2 tbsp ginger-garlic paste","1.5 tsp red chilli powder","1 tsp ground coriander","1/2 tsp ground turmeric","1.5 tsp salt","1 tsp nihari masala or garam masala","3 tbsp plain flour mixed with 100 ml cold water","5 cm piece of fresh ginger, peeled and julienned, to serve","1 lemon cut into wedges and a handful of fresh coriander leaves, to serve"],"ro":["1 kg rasol de vită cu os, tăiat în bucăți de 5 cm","2 oase cu măduvă, fiecare de aproximativ 5 cm","4 linguri unt clarificat (ghee) sau ulei","2 cepe mari (~300 g), feliate subțire","2 linguri pastă de ghimbir și usturoi","1,5 linguriță praf de ardei iute roșu","1 linguriță coriandru măcinat","1/2 linguriță turmeric măcinat","1,5 linguriță sare","1 linguriță masala nihari sau garam masala","3 linguri făină albă amestecate cu 100 ml apă rece","5 cm ghimbir proaspăt, curățat și juliennat, pentru servire","1 lămâie tăiată în felii și un mănunchi de frunze de coriandru, pentru servire"]},"howIsMade":{"zh":"取大铸铁锅，倒入3汤匙酥油，中高火加热，放入洋葱翻炒12–15分钟至深金棕色，用漏勺捞出备用。加入剩余酥油，大火将牛腱子和骨髓骨分批煎3–4分钟至各面褐色，取出备用。转中火，放入姜蒜泥炒1–2分钟至香气四溢，加入辣椒粉、香菜粉和姜黄粉翻炒30秒。将肉和炸洋葱回锅，加盐和足量清水（约1.2升）使水面高出肉5厘米，大火烧开撇去浮沫。转最小火，盖紧锅盖慢炖3–4小时，直至肉质酥烂、轻松脱骨。加入尼哈里马萨拉，边搅拌边细流倒入面粉浆，开盖再炖10–15分钟，直至肉汤浓稠、可裹在勺背上。盛入碗中，铺上姜丝、香菜叶，挤入柠檬汁，搭配馕饼或脆皮面包食用。","en":"Heat 3 tbsp ghee in a large heavy pot over medium-high heat and fry the onions for 12–15 minutes, stirring often, until deep golden brown, then remove with a slotted spoon and set aside. Add the remaining ghee, raise the heat to high, and sear the beef shanks and marrow bones in batches for 3–4 minutes per side until browned, then set aside. Reduce heat to medium, add the ginger-garlic paste and fry for 1–2 minutes until fragrant, then add the chilli powder, coriander, and turmeric and stir for 30 seconds. Return the meat and fried onions to the pot, add the salt and enough water to cover by 5 cm (about 1.2 litres), bring to a boil and skim any foam. Reduce heat to the lowest setting, cover tightly, and simmer for 3–4 hours until the beef is completely tender and falling from the bone. Stir in the nihari masala, pour in the flour slurry in a thin stream while stirring, and simmer uncovered for 10–15 minutes until the broth thickens to a glossy consistency that coats the back of a spoon. Ladle into bowls, top with julienned ginger, coriander leaves, and a squeeze of lemon, and serve with naan or crusty bread."}},{"id":87,"origin":{"zh":"越南","en":"Vietnam","ro":"Vietnam"},"name":{"zh":"顺化牛肉粉","en":"Bún bò Huế","ro":"Bún bò Huế"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":195,"active":75},"pairingsType":"vietnamese","ingredients":{"zh":["带骨猪蹄600克，切成4厘米的块","牛骨500克，焯水备用","牛腱子400克，切薄片","圆形干米线（bún）400克","香茅3根，拍扁并切成5厘米段","小葱头3个，对半切开后炙烤","大蒜4瓣，拍扁","发酵虾酱（mắm ruốc）2汤匙","鱼露3汤匙","辣椒油2汤匙或干辣椒片1茶匙","糖1茶匙","盐1茶匙","装盘用：豆芽200克、新鲜香草（薄荷或越南香菜）、2个青柠切角、2根红辣椒切片"],"en":["600 g bone-in pork hock, cut into 4 cm pieces","500 g beef bones, blanched","400 g beef shank, thinly sliced","400 g dried round rice vermicelli (bún)","3 lemongrass stalks, bruised and cut into 5 cm pieces","3 shallots, halved and charred","4 garlic cloves, bruised","2 tbsp fermented shrimp paste (mắm ruốc)","3 tbsp fish sauce","2 tbsp chilli oil or 1 tsp dried chilli flakes","1 tsp sugar","1 tsp salt","to serve: 200 g bean sprouts, fresh herbs (mint, perilla or Vietnamese coriander), 2 limes cut into wedges, and 2 red chillies sliced"],"ro":["600 g picior de porc cu os, tăiat în bucăți de 4 cm","500 g oase de vită, opărite","400 g rasol de vită, feliat subțire","400 g tăiței rotunzi de orez uscați (bún)","3 tulpini de lemongrass, zdrobite și tăiate în bucăți de 5 cm","3 șalote, tăiate pe jumătate și pârlite","4 căței de usturoi, zdrobiți","2 linguri pastă de creveți fermentați (mắm ruốc)","3 linguri sos de pește","2 linguri ulei de ardei iute sau 1 linguriță fulgi de ardei iute","1 linguriță zahăr","1 linguriță sare","pentru servit: 200 g muguri de fasole, ierburi proaspete (mentă sau coriandru vietnamez), 2 lămâi verzi în sferturi și 2 ardei iuți roșii felieți"]},"howIsMade":{"zh":"将猪蹄和牛骨放入沸水中焯5分钟，捞出用冷水冲洗干净。将葱头和大蒜切面朝下放在干锅中大火炙烤3–4分钟，至略微焦黑。将猪蹄、牛骨、香茅、炙烤葱头和大蒜放入大汤锅，加2.5升冷水，大火烧开撇去浮沫，转小火煲1小时。取100毫升热汤化开虾酱，倒入锅中，加入鱼露、糖、盐和辣椒油，调整至汤底咸鲜、微辣、香气浓郁。放入薄切牛腱子片，小火浸泡15–20分钟至熟透变嫩，捞出切薄片。按包装说明煮米线（通常3–5分钟），捞出沥干，分装在4个深碗中。舀入滚烫汤底，铺上猪蹄和牛肉片，立即与豆芽、新鲜香草、青柠角和辣椒片一同上桌。","en":"Blanch the pork hock and beef bones in boiling water for 5 minutes, drain and rinse under cold water. Char the shallots and garlic cut-side down in a dry pan over high heat for 3–4 minutes until lightly blackened. Place the pork hock, bones, lemongrass, charred shallots, and garlic in a large pot, add 2.5 litres of cold water, bring to a boil, skim well, then simmer over low heat for 1 hour. Dissolve the shrimp paste in 100 ml of hot broth, stir into the pot, then add fish sauce, sugar, salt, and chilli oil, adjusting until the broth is savoury, lightly spicy, and fragrant. Add the beef shank slices and poach over gentle heat for 15–20 minutes until just cooked through and tender, then remove and slice thinly. Cook the rice vermicelli according to packet instructions (usually 3–5 minutes), drain, and divide among 4 deep bowls. Ladle the hot broth over the noodles, top with slices of pork hock and beef shank, and serve immediately with bean sprouts, fresh herbs, lime wedges, and sliced chilli on the side."}},{"id":88,"origin":{"zh":"巴西","en":"Brazil","ro":"Brazilia"},"name":{"zh":"巴西鱼炖菜","en":"Moqueca","ro":"Moqueca"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"zh":["结实的白鱼片800克（鲈鱼、鳕鱼或安康鱼），切成5厘米的块","2个青柠，取汁","1茶匙盐","大洋葱1个（约180克），切薄片","大蒜4瓣，切碎","红甜椒1个（约150克），去籽切片","绿甜椒1个（约150克），去籽切片","成熟大番茄2个（约300克），切丁","椰奶400毫升（全脂）","红棕榈油（dendê）2汤匙","新鲜香菜20克，粗切，另备一些装盘用","1/2茶匙黑胡椒粉"],"en":["800 g firm white fish fillets (sea bass, cod, or monkfish), cut into 5 cm chunks","2 limes, juice only","1 tsp salt","1 large onion (~180 g), thinly sliced","4 garlic cloves, finely minced","1 red bell pepper (~150 g), deseeded and sliced","1 green bell pepper (~150 g), deseeded and sliced","2 large ripe tomatoes (~300 g), diced","400 ml full-fat coconut milk","2 tbsp dendê (red palm oil)","20 g fresh coriander, roughly chopped, plus extra to serve","1/2 tsp ground black pepper"],"ro":["800 g fileuri de pește alb ferm (biban de mare, cod sau merluciu), tăiate în bucăți de 5 cm","2 lămâi verzi (lime), sucul","1 linguriță sare","1 ceapă mare (~180 g), feliată subțire","4 căței de usturoi, tocați mărunt","1 ardei gras roșu (~150 g), curat și feliat","1 ardei gras verde (~150 g), curat și feliat","2 roșii coapte mari (~300 g), tocate cuburi","400 ml lapte de cocos integral","2 linguri ulei de palmier roșu (dendê)","20 g coriandru proaspăt, tocat grosier, plus extra pentru garnit","1/2 linguriță piper negru măcinat"]},"howIsMade":{"zh":"将鱼块与青柠汁、1/2茶匙盐和黑胡椒混合，腌制15–20分钟，同时准备蔬菜。取大平底锅，倒入1汤匙棕榈油中火加热，放入洋葱炒6–8分钟至软化略呈金黄色。加入大蒜、两色甜椒和番茄翻炒5分钟，直至番茄开始软烂。将腌好的鱼平铺在蔬菜上，倒入椰奶，轻轻将鱼压入液体中，不要搅拌。小火慢炖，盖上锅盖煮12–15分钟，直至鱼肉变白且轻压即碎。淋上剩余1汤匙棕榈油，撒上香菜，调整盐味。直接从锅中盛出，搭配白米饭或面包，附青柠角食用。","en":"Toss the fish chunks with the lime juice, 1/2 tsp salt, and the black pepper and leave to marinate for 15–20 minutes while you prepare the vegetables. Heat 1 tbsp dendê oil in a large wide pan over medium heat, add the onion slices, and cook for 6–8 minutes until softened and lightly golden. Add the garlic, bell peppers, and tomatoes, stir well, and cook for 5 minutes until the tomatoes begin to break down. Lay the marinated fish over the vegetables in a single layer, pour the coconut milk over the top, and gently push the fish down into the liquid without stirring. Bring to a gentle simmer, cover, and cook for 12–15 minutes until the fish is opaque and flakes easily when pressed. Drizzle the remaining 1 tbsp dendê oil over the surface, scatter the coriander on top, and taste for salt. Serve directly from the pan with white rice or crusty bread, with lime wedges on the side."}},{"id":89,"origin":{"zh":"以色列","en":"Israel","ro":"Israel"},"name":{"zh":"萨比奇三明治","en":"Sabich","ro":"Sabich"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"def","pairingsType":"middle-eastern","ingredients":{"zh":["大皮塔饼4个","大茄子1个（约400克），切成1厘米厚的圆片","煎炸用食用油4汤匙","鸡蛋4个","蜡质土豆300克，煮至软熟并切成1厘米厚片","芝麻酱（tahini）4汤匙","柠檬1个，只取汁","大蒜1瓣，压碎","安巴酱（mango pickle sauce）4汤匙","番茄2个（约200克），切碎","黄瓜1根（约150克），切碎","盐1茶匙","腌黄瓜4片和新鲜香菜，装盘用"],"en":["4 large pita breads","1 large aubergine (~400 g), cut into 1 cm rounds","4 tbsp oil for frying","4 eggs","300 g waxy potatoes, boiled until tender and sliced 1 cm thick","4 tbsp tahini paste","1 lemon, juice only","1 garlic clove, crushed","4 tbsp amba sauce (fermented mango pickle sauce)","2 tomatoes (~200 g), finely diced","1 cucumber (~150 g), finely diced","1 tsp salt","4 slices pickled cucumber and fresh parsley, to serve"],"ro":["4 lipii pita mari","1 vânătă mare (~400 g), tăiată în felii de 1 cm","4 linguri ulei pentru prăjit","4 ouă","300 g cartofi galbeni, fierți până sunt moi și feliați la 1 cm grosime","4 linguri pastă de tahini","1 lămâie, sucul","1 cățel de usturoi, zdrobit","4 linguri sos amba (sos din mango murat)","2 roșii (~200 g), tăiate mărunt","1 castravete (~150 g), tăiat mărunt","1 linguriță sare","4 felii castraveți murați și pătrunjel proaspăt, pentru servire"]},"howIsMade":{"zh":"将鸡蛋放入沸水中煮10分钟，捞出放入冷水中冷却5分钟，剥壳切成圆片备用。茄子片两面撒盐1/2茶匙，静置10分钟后用厨房纸吸干水分。平底锅倒油中高火加热，分批煎茄子片每面3–4分钟至深金棕色且全熟，捞出放在厨房纸上沥油。将芝麻酱与柠檬汁、大蒜和3–4汤匙冷水搅打至顺滑可流动的酱汁。将切碎的番茄和黄瓜加1/2茶匙盐和少许橄榄油拌成简单沙拉。干锅将每个皮塔饼两面各热1分钟，然后小心打开袋口。每个皮塔饼中依次夹入煎茄子、土豆片、鸡蛋片、蔬菜沙拉，淋上大量芝麻酱和一勺安巴酱，放上腌黄瓜和新鲜香菜，立即食用。","en":"Hard-boil the eggs: lower into boiling water, cook for 10 minutes, then transfer to cold water for 5 minutes, peel, and slice into rounds. Sprinkle the aubergine slices on both sides with 1/2 tsp salt and leave for 10 minutes, then pat dry with kitchen paper. Heat the oil in a large non-stick pan over medium-high heat and fry the aubergine in batches for 3–4 minutes per side until deep golden and tender throughout, then drain on kitchen paper. Whisk the tahini with the lemon juice, crushed garlic, and 3–4 tbsp cold water until creamy and pourable. Combine the diced tomatoes and cucumber with the remaining 1/2 tsp salt and a drizzle of olive oil. Warm each pita for 1 minute per side in a dry pan, then carefully open the pocket without tearing. Layer each pita with fried aubergine, sliced potato and egg, the tomato-cucumber salad, a generous drizzle of tahini sauce, a spoonful of amba sauce, pickled cucumber, and fresh parsley, and serve immediately."}},{"id":90,"origin":{"zh":"古巴","en":"Cuba","ro":"Cuba"},"name":{"zh":"古巴牛肉丝","en":"Ropa Vieja","ro":"Ropa Vieja"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"zh":["牛腹肉或牛胸肉700克","橄榄油2汤匙","大洋葱1个（约200克），切薄片","红甜椒和绿甜椒各1个（各约150克），去籽切片","大蒜4瓣，切碎","罐装碎番茄400克","番茄膏2汤匙","干白葡萄酒100毫升","孜然粉1茶匙","干牛至1茶匙","月桂叶2片","盐1茶匙、黑胡椒粉1/2茶匙"],"en":["700 g beef flank steak or brisket","2 tbsp olive oil","1 large onion (~200 g), thinly sliced","1 red bell pepper and 1 green bell pepper (~150 g each), deseeded and sliced","4 garlic cloves, finely minced","400 g canned crushed tomatoes","2 tbsp tomato paste","100 ml dry white wine","1 tsp ground cumin","1 tsp dried oregano","2 bay leaves","1 tsp salt and 1/2 tsp ground black pepper"],"ro":["700 g antricot sau piept de vită","2 linguri ulei de măsline","1 ceapă mare (~200 g), feliată subțire","1 ardei gras roșu și 1 ardei gras verde (~150 g fiecare), curățați și feliați","4 căței de usturoi, tocați mărunt","400 g roșii zdrobite la conservă","2 linguri pastă de roșii","100 ml vin alb sec","1 linguriță chimion măcinat","1 linguriță oregano uscat","2 foi de dafin","1 linguriță sare și 1/2 linguriță piper negru măcinat"]},"howIsMade":{"zh":"将牛肉放入锅中，用冷淡盐水没过，大火烧开撇去浮沫，转小火盖锅慢炖1.5–2小时至轻松撕开。取出牛肉，保留200毫升炖汤，将牛肉顺纹撕成长条。宽锅倒入橄榄油中火加热，放入洋葱和两种甜椒，翻炒8–10分钟至软化并略带焦色。加入大蒜、孜然和牛至炒1分钟至香味释放，倒入白葡萄酒煮2分钟至减半。加入碎番茄、番茄膏、保留的炖汤和月桂叶，用盐和胡椒调味，小火熬10分钟至汤汁略微收浓。放入撕好的牛肉，拌匀后再炖10–15分钟，至牛肉充分吸收汤汁、整体呈鲜嫩多汁状。捞出月桂叶，搭配白米饭和煎大蕉上桌。","en":"Place the beef in a pot, cover with cold salted water, bring to a boil, skim, reduce heat, and simmer covered for 1.5–2 hours until the meat pulls apart easily. Remove the beef, reserve 200 ml of the cooking liquid, and shred the meat into long strips. Heat the oil in a wide heavy pan over medium heat, add the onion and both bell peppers, and cook for 8–10 minutes until softened and beginning to colour. Add the garlic, cumin, and oregano and stir for 1 minute, then pour in the white wine and cook for 2 minutes until reduced by half. Stir in the crushed tomatoes, tomato paste, reserved cooking liquid, and bay leaves, season with salt and pepper, and simmer for 10 minutes until the sauce thickens slightly. Add the shredded beef, stir to combine, and simmer for 10–15 minutes more until the beef absorbs the sauce and the mixture is juicy but not soupy. Remove the bay leaves and serve with white rice and fried plantains."}},{"id":91,"origin":{"zh":"苏格兰","en":"Scotland","ro":"Scoția"},"name":{"zh":"卡伦鱼汤","en":"Cullen Skink","ro":"Cullen Skink"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"zh":["无染色熏黑线鳕鱼片600克","全脂牛奶700毫升","面粉质土豆500克，去皮切成2厘米小块","大洋葱1个（约200克），切碎","无盐黄油2汤匙","月桂叶2片","高脂肪淡奶油100毫升","新鲜欧芹10克，切碎","白胡椒粉1/2茶匙","盐1/2茶匙"],"en":["600 g undyed smoked haddock fillets","700 ml whole milk","500 g floury potatoes (such as Maris Piper), peeled and cut into 2 cm cubes","1 large onion (~200 g), finely diced","2 tbsp unsalted butter","2 bay leaves","100 ml double cream","10 g fresh parsley, finely chopped","1/2 tsp white pepper","1/2 tsp salt"],"ro":["600 g fileuri de eglefin afumat (de preferință necolorat)","700 ml lapte integral","500 g cartofi făinoși, curățați și tăiați cuburi de 2 cm","1 ceapă mare (~200 g), tăiată mărunt","2 linguri unt fără sare","2 foi de dafin","100 ml frișcă grasă","10 g pătrunjel proaspăt, tocat mărunt","1/2 linguriță piper alb","1/2 linguriță sare"]},"howIsMade":{"zh":"将熏鳕鱼片皮面朝下放入宽锅，倒入牛奶，放入月桂叶，中火加热至微沸；慢煮8–10分钟直至鱼肉变白且最厚处可轻松剥开。用漏勺取出鱼片，去除鱼皮和鱼骨，将鱼肉轻轻撕成大块，把煮鱼的牛奶用滤网过滤备用。用同一口锅融化黄油，放入洋葱碎中火翻炒8–10分钟，偶尔搅拌，直至完全软化但不上色。加入土豆块和过滤好的牛奶，小火加热至微沸，半盖锅盖煮15–18分钟，直至土豆用刀尖刺入完全松软。用勺子背面在锅边将约三分之一的土豆轻轻压碎以增稠汤汁，其余保持块状。倒入奶油，将撕好的鳕鱼片放回锅中，小火加热2–3分钟至热透；加白胡椒和少量盐调味，注意鱼本身已有咸味。盛入热碗，撒上欧芹，搭配脆皮面包上桌。","en":"Place the smoked haddock skin-side down in a wide pan, pour over the milk, add the bay leaves, and bring to a gentle simmer over medium heat; poach for 8–10 minutes until the fish is just opaque and flakes at the thickest part. Lift the fish out with a slotted spoon, remove the skin and any bones, break the flesh into large flakes, and strain the poaching milk through a sieve into a jug. Melt the butter in the same pan over medium heat, add the diced onion, and cook for 8–10 minutes, stirring occasionally, until completely soft but not coloured. Add the potato cubes and the strained milk, bring to a simmer, cover loosely, and cook for 15–18 minutes until the potatoes are completely tender when pierced with a knife. Lightly mash about one-third of the potatoes against the side of the pan with the back of a spoon to thicken the soup, leaving the rest in chunks. Stir in the double cream, return the flaked haddock to the pan, and simmer gently for 2–3 minutes until just heated through; season with white pepper and salt, tasting carefully as the haddock is already salty. Ladle into warmed bowls, scatter with chopped parsley, and serve with crusty bread."}},{"id":92,"origin":{"zh":"印度尼西亚","en":"Indonesia","ro":"Indonezia"},"name":{"zh":"印尼什锦蔬菜沙拉","en":"Gado-Gado","ro":"Gado-Gado"},"category":{"zh":"沙拉","en":"Salad","ro":"Salată"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"zh":["400克硬豆腐，压去水分，切成2厘米方块","150克天贝，切成2厘米方块","4个大鸡蛋","300克蜡质土豆，去皮切成四块","200克四季豆，去蒂","200克白卷心菜，切细丝","150克豆芽","1根黄瓜（约200克），切半月形","3汤匙植物油","200克顺滑花生酱","200毫升椰奶","2汤匙甜酱油（kecap manis）","2汤匙罗望子酱，溶于4汤匙温水中","1茶匙棕榈糖或红糖","2瓣大蒜，细磨成泥","1/2茶匙辣椒片","1/2茶匙盐","虾饼（krupuk）和青柠角佐餐"],"en":["400 g firm tofu, pressed and cut into 2 cm cubes","150 g tempeh, cut into 2 cm cubes","4 large eggs","300 g waxy potatoes, peeled and quartered","200 g green beans, trimmed","200 g white cabbage, thinly shredded","150 g bean sprouts","1 cucumber (~200 g), sliced into half-moons","3 tbsp vegetable oil","200 g smooth peanut butter","200 ml coconut milk","2 tbsp kecap manis (sweet soy sauce)","2 tbsp tamarind paste dissolved in 4 tbsp warm water","1 tsp palm sugar or soft brown sugar","2 garlic cloves, finely grated","1/2 tsp chilli flakes","1/2 tsp salt","prawn crackers (krupuk) and lime wedges to serve"],"ro":["400 g tofu ferm, presat și tăiat în cuburi de 2 cm","150 g tempeh, tăiat în cuburi de 2 cm","4 ouă mari","300 g cartofi cu coajă crocantă, curățați și tăiați în sferturi","200 g fasole verde, curățată de capete","200 g varză albă, feliată subțire","150 g germeni de soia","1 castravete (~200 g), tăiat în felii semilună","3 linguri ulei vegetal","200 g unt de arahide cremos","200 ml lapte de cocos","2 linguri kecap manis (sos de soia dulce)","2 linguri pastă de tamarind dizolvată în 4 linguri apă caldă","1 linguriță zahăr de palmier sau zahăr brun","2 căței de usturoi, rași fin","1/2 linguriță fulgi de ardei iute","1/2 linguriță sare","chipsuri de creveți (krupuk) și felii de lămâie verde pentru servit"]},"howIsMade":{"zh":"将鸡蛋放入微沸的水中煮9分钟，捞出放入冰水碗中，晾凉后剥壳对半切开。将土豆放入加足量盐的沸水中煮12–15分钟至戳透时刚好软熟；用漏勺捞出沥干，再将四季豆放入同一锅水中焯3分钟至颜色翠绿且仍有嚼劲，捞出沥干。将切细的卷心菜放在滤网中，倒入沸水烫30秒，挤去多余水分。平底锅中热油至中大火，将豆腐块煎3–4分钟每面至金黄酥脆；取出，再将天贝放入同一锅中煎2–3分钟每面至深金黄色。将花生酱、椰奶、甜酱油、罗望子水、棕榈糖、磨碎的大蒜和辣椒片放入小锅中，用小火不断搅拌煮5–7分钟至顺滑浓稠、能挂在勺背上——若太稠可加少许水稀释。将卷心菜、土豆、四季豆、豆芽和黄瓜摆在大盘或各人盘中，上面放豆腐、天贝和切半的鸡蛋。淋上温热的花生酱，配虾饼和青柠角上桌。","en":"Hard-boil the eggs in simmering water for 9 minutes, transfer to a bowl of ice water, then peel and halve when cool. Cook the potatoes in well-salted boiling water for 12–15 minutes until just tender when pierced; lift out with a slotted spoon and drain, then blanch the green beans in the same water for 3 minutes until bright green and still with some bite, and drain. Blanch the shredded cabbage by pouring boiling water over it in a colander, count 30 seconds, then press out excess water. Heat the oil in a non-stick frying pan over medium-high heat and fry the tofu cubes for 3–4 minutes per side until golden and crisp; remove, then fry the tempeh in the same pan for 2–3 minutes per side until deep golden. Combine the peanut butter, coconut milk, kecap manis, tamarind water, palm sugar, grated garlic, and chilli flakes in a small saucepan; cook over low heat, stirring constantly, for 5–7 minutes until smooth and thick enough to coat the back of a spoon — thin with a splash of water if needed. Arrange the cabbage, potatoes, green beans, bean sprouts, and cucumber slices on a large platter or individual plates; place the tofu, tempeh, and egg halves on top. Pour the warm peanut sauce over everything, and serve with prawn crackers and lime wedges on the side."}},{"id":93,"origin":{"zh":"瑞典","en":"Sweden","ro":"Suedia"},"name":{"zh":"肉桂卷","en":"Cinnamon Bun","ro":"Kanelbulle"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"servings":12,"tipType":"dessert","pairingsType":"dessert","ingredients":{"zh":["500克低筋面粉，另备扑粉用","250毫升全脂牛奶","7克快速干酵母（1包）","10克细砂糖（用于面团）","1个大鸡蛋","100克无盐黄油，软化","1茶匙豆蔻粉","1/2茶匙盐","75克无盐黄油，软化（馅料）","75克细砂糖（馅料）","1汤匙肉桂粉","1茶匙豆蔻粉（馅料）","1个鸡蛋，打散（用于蛋液）","2汤匙珍珠糖"],"en":["500 g plain flour, plus extra for dusting","250 ml whole milk","7 g fast-action dried yeast (1 sachet)","10 g caster sugar (for dough)","1 large egg","100 g unsalted butter, softened","1 tsp ground cardamom","1/2 tsp salt","75 g unsalted butter, softened (filling)","75 g caster sugar (filling)","1 tbsp ground cinnamon","1 tsp ground cardamom (filling)","1 egg, beaten (for egg wash)","2 tbsp pearl sugar"],"ro":["500 g făină albă, plus extra pentru presărat","250 ml lapte integral","7 g drojdie uscată instant (1 plic)","10 g zahăr tos (pentru aluat)","1 ou mare","100 g unt nesărat, la temperatura camerei","1 linguriță cardamom măcinat","1/2 linguriță sare","75 g unt nesărat, la temperatura camerei (umplutură)","75 g zahăr tos (umplutură)","1 lingură scorțișoară măcinată","1 linguriță cardamom măcinat (umplutură)","1 ou bătut (pentru uns)","2 linguri zahăr perle"]},"howIsMade":{"zh":"将牛奶加热至37°C，加入酵母和10克砂糖，静置5–10分钟至起泡。将面粉、豆蔻和盐混合在大碗中，挖井，倒入酵母液和鸡蛋，揉成粗糙面团。分次加入100克软化黄油，在略撒面粉的台面上揉8–10分钟，至面团光滑有弹性且不粘手；盖上保鲜膜，放温暖处发酵60–90分钟至体积翻倍。将75克黄油、75克砂糖、肉桂粉和第二茶匙豆蔻混合成均匀的馅料。将发酵好的面团在撒粉台面上擀成40×50厘米的长方形；均匀涂抹馅料，纵向三折，再次擀开，切成12条。每条扭转后卷成一个结，把末端塞到底部；放在铺纸的烤盘上留间距，松松盖好，醒发30–45分钟至明显膨胀，同时预热烤箱至200°C（风扇180°C）。刷上蛋液，撒上珍珠糖，烤12–15分钟至深金黄色；放在冷却架上盖上干净茶巾保持柔软。","en":"Warm the milk to 37°C, stir in the yeast and the 10 g of caster sugar, and leave for 5–10 minutes until frothy. Combine the flour, cardamom, and salt in a large bowl; make a well, pour in the yeast mixture and beaten egg, then bring together into a rough dough. Add the 100 g of softened butter a piece at a time and knead on a lightly floured surface for 8–10 minutes until the dough is smooth, elastic, and no longer sticks to your hands; cover and leave in a warm place for 60–90 minutes until doubled in size. Beat together the 75 g of butter, 75 g of caster sugar, cinnamon, and the second teaspoon of cardamom until smooth for the filling. Turn the risen dough onto a lightly floured surface and roll into a 40×50 cm rectangle; spread the filling evenly, fold the dough lengthways into thirds, roll again, and cut into 12 strips. Twist each strip and coil into a knot, tucking the end underneath, then space on lined baking trays; cover loosely and prove 30–45 minutes until noticeably puffed, while preheating the oven to 200°C (fan 180°C). Brush with beaten egg, scatter with pearl sugar, and bake for 12–15 minutes until deep golden brown; transfer to a wire rack and cover with a tea towel to keep them soft."}},{"id":94,"origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"胡桃辣椒酱","en":"Chiles en nogada","ro":"Chiles en nogada"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"zh":["4个大波布拉诺辣椒（约700克）","400克猪肉馅","2汤匙橄榄油或猪油","1个中等洋葱（约150克），细切碎","3瓣大蒜，切碎","2个成熟西红柿（约300克），去皮切丁","50克葡萄干","50克去皮杏仁，粗切","1个成熟桃子或梨（约150克），去皮切小丁","1茶匙肉桂粉、1/2茶匙丁香粉、1茶匙盐、1/2茶匙黑胡椒","150克核桃仁，在温牛奶中浸泡30分钟后沥干","150克奶油奶酪，软化","100毫升酸奶油","1个石榴的籽（约100克）","一把新鲜意大利扁叶欧芹"],"en":["4 large poblano chiles (~700 g total)","400 g ground pork","2 tbsp olive oil or lard","1 medium onion (~150 g), finely diced","3 garlic cloves, minced","2 ripe tomatoes (~300 g), peeled and diced","50 g raisins","50 g blanched almonds, roughly chopped","1 ripe peach or pear (~150 g), peeled and diced","1 tsp ground cinnamon, 1/2 tsp ground cloves, 1 tsp salt, 1/2 tsp black pepper","150 g walnut halves, soaked in warm milk 30 minutes then drained","150 g cream cheese, softened","100 ml soured cream","seeds of 1 pomegranate (~100 g)","small handful of fresh flat-leaf parsley leaves"],"ro":["4 ardei poblano mari (~700 g total)","400 g carne de porc tocată","2 linguri ulei de măsline sau untură","1 ceapă medie (~150 g), tăiată mărunt","3 căței de usturoi, tocați","2 roșii coapte (~300 g), curățate de coajă și tocate","50 g stafide","50 g migdale decojite, tocate grosier","1 piersică sau pară coaptă (~150 g), curățată și tăiată cubulețe","1 linguriță scorțișoară, 1/2 linguriță cuișoare, 1 linguriță sare, 1/2 linguriță piper negru","150 g miez de nucă, înmuiat 30 minute în lapte cald și scurs","150 g cremă de brânză, la temperatura camerei","100 ml smântână fermentată","semințele unui rodiu (~100 g)","o mână de frunze de pătrunjel plat proaspăt"]},"howIsMade":{"zh":"将波布拉诺辣椒直接放在燃气炉明火上或置于高温烧烤架下烤8–10分钟，用夹子翻转至四面完全焦黑；放入有盖碗中焖10分钟，然后摩擦去皮，沿一侧切一刀，用小勺挖去籽和脉络，保持辣椒完整。平底锅中倒油，中火热透，加入洋葱炒5–6分钟至完全软熟，加入大蒜再炒1分钟至出香。加入猪肉馅，用木勺边炒边切碎，炒8分钟至无粉红色残留；加入西红柿炒5分钟至汤汁收干。加入葡萄干、杏仁、桃子、肉桂、丁香、盐和黑胡椒，炒5分钟至果肉软烂、馅料较干，离火晾凉至室温。沥干泡好的核桃，与奶油奶酪和酸奶油一起用搅拌机打至完全顺滑；加少许盐调味。将冷却的肉馅紧紧塞入每根辣椒，轻轻捏合切口；摆入盘中。将核桃酱慷慨地淋在每根辣椒上，撒上石榴籽和欧芹叶，在室温下上桌。","en":"Char the poblano chiles over an open gas flame or under a hot grill for 8–10 minutes, turning with tongs until the skin is completely blackened on all sides; place in a covered bowl for 10 minutes, then rub off the skin, make a single lengthways slit, and remove the seeds and veins with a small spoon while keeping each chile intact. Heat the oil in a wide frying pan over medium heat, add the onion, and cook for 5–6 minutes until completely soft; add the garlic and cook 1 minute more until fragrant. Add the ground pork and cook, breaking it up with a wooden spoon, for 8 minutes until no pink remains; add the diced tomatoes and cook for 5 minutes until they collapse and the liquid reduces. Stir in the raisins, almonds, peach, cinnamon, cloves, salt, and pepper; cook for 5 minutes until the fruit softens and the mixture is fairly dry, then remove from heat and cool to room temperature. Drain the soaked walnuts and blend with the cream cheese and soured cream until completely smooth; season with a pinch of salt — the nogada should be thick enough to coat a spoon. Stuff each poblano firmly with the cooled meat filling, pressing gently to close the slit; arrange on individual plates or a large serving dish. Spoon the walnut sauce generously over each chile, scatter pomegranate seeds and parsley leaves on top, and serve at room temperature."}},{"id":95,"origin":{"zh":"黎巴嫩","en":"Lebanon","ro":"Liban"},"name":{"zh":"扁豆汤","en":"Lentil Soup","ro":"Supă de linte"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"zh":["300克红扁豆，冲洗至水变清澈","2汤匙橄榄油","1个大洋葱（约200克），细切碎","2根中等胡萝卜（约200克），去皮切丁","3瓣大蒜，切碎","2茶匙孜然粉","1茶匙香菜粉","1/2茶匙姜黄粉","1/4茶匙卡宴辣椒粉","1.2升蔬菜汤或鸡汤","1个柠檬的汁","2汤匙无盐黄油（点缀用）","1茶匙甜红椒粉（点缀用）","盐和黑胡椒适量","新鲜香菜或欧芹、柠檬角佐餐"],"en":["300 g red lentils, rinsed until water runs clear","2 tbsp olive oil","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), peeled and diced","3 garlic cloves, minced","2 tsp ground cumin","1 tsp ground coriander","1/2 tsp ground turmeric","1/4 tsp cayenne pepper","1.2 litres vegetable or chicken stock","juice of 1 lemon","2 tbsp unsalted butter (for topping)","1 tsp sweet paprika (for topping)","salt and black pepper to taste","fresh coriander or parsley and lemon wedges to serve"],"ro":["300 g linte roșie, clătită până apa devine limpede","2 linguri ulei de măsline","1 ceapă mare (~200 g), tăiată mărunt","2 morcovi medii (~200 g), curățați și tăiați cubulețe","3 căței de usturoi, tocați","2 lingurițe chimen măcinat","1 linguriță coriandru măcinat","1/2 linguriță turmeric","1/4 linguriță ardei cayenne","1,2 litri supă de legume sau pui","sucul de la 1 lămâie","2 linguri unt nesărat (pentru topping)","1 linguriță paprika dulce (pentru topping)","sare și piper negru după gust","coriandru proaspăt sau pătrunjel, felii de lămâie pentru servit"]},"howIsMade":{"zh":"将橄榄油在大汤锅中用中火加热，加入洋葱和胡萝卜，偶尔搅拌，炒8–10分钟至软熟、洋葱变透明。加入大蒜、孜然粉、香菜粉、姜黄粉和卡宴辣椒，搅拌1–2分钟至香料散发香味。加入洗净的扁豆和高汤，烧开后转小火，半盖锅盖，慢煮20–25分钟至扁豆完全软烂并开始溶解。用手持搅拌棒打约一半的汤，使其呈细腻但有质感的奶油状——或全部打匀；太稠可加少量高汤稀释。加入柠檬汁，用盐和黑胡椒充分调味。将黄油放入小锅中火融化，加入甜红椒粉，煎30秒至散发香味。将热汤盛入温热的碗中，淋上辣椒黄油，撒上新鲜香菜，配柠檬角和脆面包上桌。","en":"Heat the olive oil in a large saucepan over medium heat, add the onion and carrots, and cook for 8–10 minutes, stirring occasionally, until softened and the onion is translucent. Add the garlic, cumin, coriander, turmeric, and cayenne; stir for 1–2 minutes until the spices are fragrant and toasted. Add the rinsed lentils and stock, bring to a boil, then reduce the heat, partially cover, and simmer for 20–25 minutes until the lentils are completely tender and beginning to dissolve into the liquid. Use an immersion blender to puree about half the soup directly in the pot for a creamy yet textured finish — or blend it all smooth if you prefer; thin with a splash of extra stock or water if needed. Stir in the lemon juice and season generously with salt and black pepper. Melt the butter in a small pan over medium heat, add the sweet paprika, and let it sizzle for 30 seconds until fragrant and deep red. Ladle the hot soup into warmed bowls, drizzle the paprika butter over each portion, scatter fresh coriander on top, and serve with lemon wedges and crusty bread."}},{"id":96,"origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"希腊菠菜馅饼","en":"Spanakopita","ro":"Spanakopita"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"servings":6,"tipType":"veg","pairingsType":"veg","ingredients":{"zh":["500克千层酥皮，冷冻则先解冻","1公斤新鲜菠菜，洗净（或600克冷冻菠菜，解冻后挤干水分）","300克菲达奶酪，捏碎","2个中等洋葱，细切","4根青葱，细切","3个大鸡蛋，打散","30克新鲜莳萝，切碎","20克新鲜欧芹，切碎","150毫升特级初榨橄榄油","100克刨碎的克菲洛蒂里奶酪或佩科里诺奶酪（可选）","1/2茶匙现磨肉豆蔻","盐和现磨黑胡椒适量"],"en":["500g phyllo pastry, thawed if frozen","1kg fresh spinach, washed (or 600g frozen spinach, thawed and squeezed dry)","300g feta cheese, crumbled","2 medium onions, finely chopped","4 spring onions, finely sliced","3 large eggs, beaten","30g fresh dill, chopped","20g fresh parsley, chopped","150ml extra virgin olive oil","100g grated kefalotyri or pecorino (optional)","1/2 tsp freshly grated nutmeg","salt and freshly ground black pepper to taste"],"ro":["500g foi de plăcintă (phyllo), decongelate dacă sunt din congelator","1kg spanac proaspăt, spălat (sau 600g spanac congelat, decongelat și stors bine)","300g brânză feta, sfărâmată","2 cepe medii, tocate fin","4 cepe verzi, tăiate fin","3 ouă mari, bătute","30g mărar proaspăt, tocat","20g pătrunjel proaspăt, tocat","150ml ulei de măsline extravirgin","100g kefalotyri sau pecorino, ras (opțional)","1/2 linguriță nucșoară proaspăt rasă","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"zh":"烤箱预热至180°C（风扇模式160°C）、1公斤菠菜洗净，放入大锅中以中火翻炒4–5分钟，至刚刚塌下、倒入滤网中用勺背用力按压排水，再分小把用厨房纸巾用力挤干。锅中加入3汤匙橄榄油，中火炒洋葱碎8分钟，至软化呈半透明、加入青葱再炒2分钟。大碗中放入挤干的菠菜、洋葱混合物、300克碎菲达奶酪、可选的克菲洛蒂里、3个打散的鸡蛋、莳萝、欧芹、肉豆蔻、盐和胡椒、轻轻拌匀——拌得太过菠菜会再次出水。25×35厘米烤盘刷上橄榄油、铺一张菲洛酥皮，刷油，再铺一张、如此叠到8层作为底层、未使用的酥皮用微湿布盖好以免变干。将馅料均匀铺在菲洛底层上、再铺8张菲洛酥皮覆盖馅料，每层都慷慨地刷上橄榄油。将边缘内折、用锋利的刀在表面预切成6–8份，只切顶层——这样可避免上桌时酥皮碎裂、表面再洒几滴水以防酥皮卷起。烘烤40–45分钟，至表面深金黄色且轻敲发出酥脆声、出炉静置15分钟后再沿预切线切块。","en":"Preheat the oven to 180°C (fan 160°C); wash 1kg of spinach and wilt it in a large pot over medium heat for 4–5 minutes, until just collapsed; tip into a colander and press out as much water as possible, then squeeze handfuls dry between paper towels. Warm 3 tablespoons of olive oil in a pan and cook the chopped onions over medium heat for 8 minutes, until soft and translucent; add the spring onions and cook 2 more minutes. In a large bowl, combine the squeezed spinach, the onion mixture, 300g crumbled feta, the kefalotyri if using, 3 beaten eggs, dill, parsley, nutmeg, salt and pepper; mix gently — do not overwork or the spinach will release more water. Brush a 25×35 cm baking dish with olive oil; lay one sheet of phyllo, brush with olive oil, and top with another sheet; continue until you have 8 layers as the base; keep unused phyllo covered with a slightly damp cloth. Spread the filling evenly over the phyllo base; top with 8 more sheets of phyllo, brushing each layer generously with olive oil. Tuck the edges in; with a sharp knife, score the top into 6–8 portions, cutting only through the top layers — this prevents shattering when serving; sprinkle a few drops of water on top to stop the pastry curling. Bake for 40–45 minutes, until the top is deep golden brown and the pastry sounds crisp when tapped; rest 15 minutes before cutting along the scored lines."},"timeMins":{"total":90,"active":40}},{"id":97,"origin":{"zh":"尼日利亚","en":"Nigeria","ro":"Nigeria"},"name":{"zh":"尼日利亚炒饭","en":"Jollof Rice","ro":"Jollof Rice"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"def","ingredients":{"zh":["400克长粒parboiled米（或印度香米），冲洗至水清","6个成熟Roma番茄，粗切（或400克罐装碎番茄）","2个大红甜椒，去籽粗切","1个苏格兰帽辣椒或红辣椒，去籽","2个大洋葱（1个打泥，1个切片）","4瓣大蒜，去皮","30克新鲜生姜，去皮","3汤匙番茄酱","120毫升植物油（传统用花生油）","750毫升热鸡汤或蔬菜汤","2片月桂叶","1茶匙咖喱粉","1茶匙干百里香","1茶匙烟熏红椒粉","盐和现磨黑胡椒适量"],"en":["400g long-grain parboiled rice (or basmati), rinsed until water runs clear","6 ripe Roma tomatoes, roughly chopped (or 400g canned chopped tomatoes)","2 large red bell peppers, deseeded and roughly chopped","1 scotch bonnet or red chilli, deseeded","2 large onions (1 blended, 1 sliced)","4 garlic cloves, peeled","30g fresh ginger, peeled","3 tbsp tomato paste","120ml vegetable oil (groundnut oil is traditional)","750ml hot chicken or vegetable stock","2 bay leaves","1 tsp curry powder","1 tsp dried thyme","1 tsp smoked paprika","salt and freshly ground black pepper to taste"],"ro":["400g orez cu bob lung parboiled (sau basmati), spălat până apa rămâne limpede","6 roșii Roma coapte, tăiate grosier (sau 400g roșii din conservă)","2 ardei kapia roșii mari, fără semințe și tăiați grosier","1 ardei scotch bonnet sau ardei iute roșu, fără semințe","2 cepe mari (una mixată, una feliată)","4 căței de usturoi, curățați","30g ghimbir proaspăt, curățat","3 linguri pastă de roșii","120ml ulei vegetal (tradițional, ulei de arahide)","750ml supă fierbinte de pui sau legume","2 foi de dafin","1 linguriță pudră de curry","1 linguriță cimbru uscat","1 linguriță boia afumată","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"zh":"400克米用冷水冲洗至水清，沥干——此步骤可去除多余淀粉，使米粒粒分明。将番茄、红甜椒、辣椒、一个洋葱、大蒜和生姜放入搅拌机打成均匀的酱泥。厚底锅中加热120毫升油，中火，加入洋葱片煸炒5–6分钟，至略微金黄。加入3汤匙番茄酱，翻炒3分钟，至颜色变深、生味消失。倒入打好的椒酱，加入月桂叶、咖喱粉、百里香和烟熏红椒粉、中火不盖盖炖18–20分钟，频繁搅拌，直至酱汁收浓变深红、油浮至表面——这是关键步骤。加入沥干的米，翻炒至每粒米都裹满酱汁、倒入750毫升热高汤，用盐和胡椒调味，煮沸。转至最小火，将锅盖严实（为达地道效果，可先用锡纸密封锅沿再盖盖子），不开盖焖25–30分钟，至米饭熟软、汤汁完全吸收。关火再静置10分钟、用叉子轻轻松开——锅底应有一层轻微烟熏的焦壳、配炸大蕉、烤鸡或简单沙拉食用。","en":"Rinse 400g of rice in cold water until the water runs clear, then drain — this removes excess starch and keeps the grains separate. Blend the tomatoes, red bell peppers, chilli, one onion, garlic and ginger to a smooth paste in a blender. Heat 120ml oil in a heavy-bottomed pot over medium heat; add the sliced onion and fry for 5–6 minutes, until lightly golden. Stir in 3 tablespoons of tomato paste and cook for 3 minutes, until darkened and the raw aroma is gone. Pour in the blended pepper mixture, add the bay leaves, curry powder, thyme and smoked paprika; cook uncovered over medium heat for 18–20 minutes, stirring often, until the sauce reduces, deepens to a dark red and the oil rises to the surface — this is the critical step. Add the rinsed rice and stir until every grain is coated in sauce; pour in 750ml hot stock, season with salt and pepper, and bring back to a boil. Reduce the heat to the lowest setting, cover the pot tightly (seal the rim with foil before placing the lid for an authentic finish), and cook undisturbed for 25–30 minutes, until the rice is tender and the liquid is absorbed. Turn off the heat and leave covered for 10 more minutes; fluff gently with a fork — the bottom layer should have a slight smoky crust; serve with fried plantain, grilled chicken, or a simple salad."}},{"id":98,"origin":{"zh":"萨摩亚","en":"Samoa","ro":"Samoa"},"name":{"zh":"萨摩亚鱼沙拉","en":"Oka i'a","ro":"Oka i'a"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"zh":["500克刺身级金枪鱼或鲯鳅鱼，去皮去骨，切1.5厘米方块","120毫升新鲜青柠汁（约6个青柠）","200毫升全脂椰奶（新开或罐装）","1根中等黄瓜，去皮去籽切小丁","1个小红洋葱，切小丁","2个成熟番茄，去籽切小丁","1个小红辣椒，切碎（可选）","1根青葱，切细","1茶匙细海盐","现磨黑胡椒","新鲜香菜叶，用于装饰"],"en":["500g sashimi-grade tuna or mahi-mahi, skinned and boned, cut into 1.5 cm cubes","120ml fresh lime juice (about 6 limes)","200ml full-fat coconut milk (freshly opened or canned)","1 medium cucumber, peeled, deseeded, and finely diced","1 small red onion, finely diced","2 ripe tomatoes, deseeded and diced","1 small red chilli, finely chopped (optional)","1 spring onion, finely sliced","1 tsp fine sea salt","freshly ground black pepper","fresh coriander leaves, to garnish"],"ro":["500g ton sau mahi-mahi de calitate sashimi, fără piele și oase, tăiat cuburi de 1,5 cm","120ml suc proaspăt de lime (aproximativ 6 lime)","200ml lapte de cocos integral (proaspăt deschis sau din conservă)","1 castravete mediu, curățat, fără semințe, tăiat cuburi mici","1 ceapă roșie mică, tăiată cuburi mici","2 roșii coapte, fără semințe, tăiate cuburi","1 ardei iute roșu mic, tocat fin (opțional)","1 ceapă verde, tăiată fin","1 linguriță sare fină de mare","piper negru proaspăt măcinat","frunze de coriandru proaspăt, pentru ornat"]},"howIsMade":{"zh":"将切块的鱼放入非反应性碗（玻璃或陶瓷）中、倒入120毫升新鲜青柠汁，翻拌使每块都裹上汁、冷藏15–20分钟——表面应转为不透明，中心仍保持半透明。鱼腌制时，把切丁的红洋葱浸入冷水中10分钟再沥干、此步骤可减弱生洋葱的辛辣，同时保留脆度。用细网将鱼彻底沥干、倒掉大部分青柠汁，但保留2汤匙。把鱼放回干净的碗、加入黄瓜、沥干的红洋葱、番茄、辣椒和青葱、轻轻翻拌，让鱼块保持完整。倒入200毫升椰奶和保留的2汤匙青柠汁、加入盐和几下现磨黑胡椒、轻轻翻拌——椰奶应裹住鱼块而不应使其碎裂。尝味并调整盐或青柠汁、立刻盛入浅碗，趁极冷食用、上面撒上新鲜香菜叶。","en":"Place the cubed fish in a non-reactive (glass or ceramic) bowl; pour over 120ml fresh lime juice and toss until every piece is coated; refrigerate for 15–20 minutes — the surface should turn opaque while the centre stays translucent. While the fish marinates, soak the diced red onion in cold water for 10 minutes, then drain; this softens its raw bite without losing the crunch. Drain the fish thoroughly through a fine sieve; discard most of the lime juice but reserve 2 tablespoons. Return the fish to a clean bowl; add the cucumber, drained red onion, tomatoes, chilli and spring onion; toss gently so the fish stays intact. Pour in 200ml coconut milk and the reserved 2 tbsp lime juice; add the salt and a few grinds of pepper; fold everything together gently — the coconut milk should coat without breaking the fish. Taste and adjust salt or lime; serve immediately, very cold, in shallow bowls; scatter fresh coriander leaves on top."}},{"id":99,"origin":{"zh":"亚美尼亚","en":"Armenia","ro":"Armenia"},"name":{"zh":"亚美尼亚烤肉","en":"Khorovats","ro":"Khorovats"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["800克猪肩肉或牛里脊，切4厘米方块","2个大红洋葱（1个切片用于腌制，1个切瓣用于串烤）","1个红甜椒，切4厘米块","1个青甜椒，切4厘米块","1个中等茄子，切3厘米厚圆片","4个成熟番茄（整个烧烤）","3汤匙葵花籽油","1茶匙现磨黑胡椒","2茶匙粗盐","一小把新鲜罗勒和欧芹，用于装盘","亚美尼亚薄饼（lavash）或其他扁面包，用于搭配"],"en":["800g pork shoulder or beef tenderloin, cut into 4 cm cubes","2 large red onions (1 sliced for the marinade, 1 cut into wedges for skewering)","1 red bell pepper, cut into 4 cm pieces","1 green bell pepper, cut into 4 cm pieces","1 medium aubergine, cut into 3 cm rounds","4 ripe tomatoes (to be grilled whole alongside)","3 tbsp sunflower oil","1 tsp freshly ground black pepper","2 tsp coarse salt","a small handful of fresh basil and parsley, to serve","lavash or another flatbread, to serve"],"ro":["800g pulpă de porc sau mușchi de vită, tăiat cuburi de 4 cm","2 cepe roșii mari (una feliată pentru marinadă, una tăiată felii pentru frigărui)","1 ardei gras roșu, tăiat bucăți de 4 cm","1 ardei gras verde, tăiat bucăți de 4 cm","1 vânătă medie, tăiată rondele de 3 cm","4 roșii coapte (pentru grătar întregi)","3 linguri ulei de floarea-soarelui","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare grunjoasă","un mănunchi de busuioc și pătrunjel proaspăt, pentru servit","lavaș sau alt tip de pâine plată"]},"howIsMade":{"zh":"1个洋葱切薄片、在大碗中放入800克切丁的肉、洋葱片、2茶匙盐、1茶匙黑胡椒和3汤匙葵花籽油、用手仔细按摩，冷藏4–8小时或过夜。升起炭火，让木炭烧到红亮带白边——约30–40分钟、烤架架在炭火上方15厘米处。将腌好的肉串到金属串签上，与洋葱瓣交替穿插，肉块之间留小空隙以便热空气流通。将整个甜椒、茄子片和番茄直接放在烤架上，远离肉、频繁翻动，直到表皮各面发黑——共12–15分钟。把肉串置于炭火最热的部位、烤10–14分钟，每2分钟翻一次，至外表深度焦糖化但中心仍微微发粉——猪肉中心温度60°C。把烤好的蔬菜放到盘子里，盖锡纸焖5分钟，再剥掉焦黑外皮、粗切后与析出的汁、盐和切碎的欧芹拌成质朴的酱汁。趁热与蔬菜酱、新鲜罗勒、柠檬角和温热的lavash薄饼一起上桌，可包卷食用。","en":"Thinly slice one onion; in a large bowl, combine 800g cubed meat, the sliced onion, 2 tsp salt, 1 tsp black pepper, and 3 tbsp sunflower oil; massage well by hand and refrigerate 4–8 hours, or overnight. Light a charcoal fire and let it burn down to glowing red embers with white edges — about 30–40 minutes; position the grill 15 cm above the coals. Thread the marinated meat onto metal skewers, alternating with wedges of onion and leaving small gaps between pieces so the hot air can circulate. Lay the whole peppers, aubergine slices and tomatoes directly on the grill, away from the meat; char them rotating frequently, until the skins blacken on every side — about 12–15 minutes total. Place the meat skewers over the hottest part of the embers; grill 10–14 minutes, turning every 2 minutes, until the meat is deeply caramelised outside but still pink in the centre — internal temperature 60°C for pork. Transfer the grilled vegetables to a plate, cover with foil for 5 minutes, then strip off the blackened skins; roughly chop and mix with the resting juices, salt, and chopped parsley to make a rustic relish. Serve the skewers hot with the vegetable relish, fresh basil, lemon wedges, and warm lavash for wrapping."}},{"id":100,"origin":{"zh":"爱沙尼亚","en":"Estonia","ro":"Estonia"},"name":{"zh":"爱沙尼亚血肠","en":"Verivorst","ro":"Verivorst"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["500克猪血（新鲜或解冻）","200克猪油或肥猪腩，切小丁","200克珍珠大麦，煮熟后放凉","2个大洋葱，细切碎","1茶匙干马郁兰","1茶匙多香果粉","1茶匙黑胡椒粉","2茶匙粗盐","1.5米清洁过的天然肠衣","2汤匙猪油，用于煎制","越橘果酱和腌黄瓜，用于搭配"],"en":["500g pig's blood (fresh or thawed)","200g pork fat or fatty pork belly, finely diced","200g pearl barley, cooked and cooled","2 large onions, finely chopped","1 tsp dried marjoram","1 tsp ground allspice","1 tsp ground black pepper","2 tsp coarse salt","1.5m cleaned natural sausage casing","2 tbsp pork lard, for cooking","lingonberry jam and pickled cucumbers, to serve"],"ro":["500g sânge de porc (proaspăt sau decongelat)","200g slănină sau piept de porc gras, tăiat cuburi mici","200g orz perlat, fiert și răcit","2 cepe mari, tocate fin","1 linguriță maghiran uscat","1 linguriță ienibahar măcinat","1 linguriță piper negru măcinat","2 lingurițe sare grunjoasă","1,5m maț natural curățat","2 linguri untură de porc, pentru gătit","gem de lingonberry și castraveți murați, pentru servit"]},"howIsMade":{"zh":"在大平底锅中以小火煎肥肉丁8–10分钟，至大部分脂肪渗出、丁块呈金黄色、加入切碎的洋葱再炒6–8分钟，至软化呈半透明、完全放凉。大碗中放入煮熟的大麦、煎好的洋葱与肥肉丁（连同所有油脂）、马郁兰、多香果、盐和黑胡椒、充分拌匀。用打蛋器快速搅打猪血以打散凝块，然后逐量拌入大麦混合物中、馅料应有光泽，可流动但不过稀。用冷流水冲洗肠衣5分钟、将一端用厨用棉绳扎紧。把肠衣的开口端套在宽口漏斗或灌肠器上、慢慢灌入混合物，只灌至肠衣的三分之二满，留出膨胀空间、每12–15厘米打结，并用针在每根肠衣上扎几下排气。一锅大水加热至80°C——不要煮沸、轻轻放入血肠，温煮30–40分钟，至触感紧实、扎下去汁液清澈。将血肠捞出静置10分钟、预热烤箱至200°C。在血肠表面刷上融化的猪油，放入烤盘烤12–15分钟，中途翻面一次，至肠衣酥脆光亮、趁热搭配越橘果酱和腌黄瓜上桌。","en":"In a large pan, fry the diced pork fat over low heat for 8–10 minutes, until most of its fat has rendered and the cubes are golden; add the chopped onions and cook 6–8 minutes more, until soft and translucent; set aside to cool completely. In a large bowl, combine the cooked pearl barley, the fried onions and pork fat (with all their fat), the marjoram, allspice, salt and pepper; mix well. Whisk the blood briefly to break up any clots, then stir it gradually into the barley mixture; the filling should look glossy and pourable, but not too liquid. Rinse the sausage casing under cold running water for 5 minutes; tie off one end with kitchen twine. Slide the open end of the casing onto a wide funnel or sausage stuffer; pipe the mixture in gradually, leaving the casing two-thirds full to allow expansion during cooking; tie off into 12–15 cm sausages and prick each with a needle in several places. Bring a large pot of water to 80°C — not boiling; slip the sausages in and poach gently for 30–40 minutes, until they feel firm to the touch and the juices run clear when pricked. Lift the sausages out and let them rest 10 minutes; preheat the oven to 200°C. Brush the sausages with melted lard and roast on a tray for 12–15 minutes, turning once, until the skins are crisp and burnished; serve hot with lingonberry jam and pickled cucumbers."}},{"id":102,"origin":{"zh":"韩国","en":"South Korea","ro":"Coreea de Sud"},"name":{"zh":"辣炒年糕","en":"Tteokbokki","ro":"Tteokbokki"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"zh":["圆柱形年糕（garae-tteok）500克，新鲜或解冻","韩式鱼糕（eomuk）150克，切成三角形","辣椒酱（gochujang）3大勺","韩式辣椒粉（gochugaru）1大勺","糖1大勺","酱油1小勺","鳀鱼汤（或水加鲣鱼包）500毫升","大葱2根，切5厘米段","去壳白煮蛋2个","芝麻油1小勺","烤芝麻1小勺"],"en":["500g cylindrical rice cakes (garae-tteok), fresh or thawed","150g eomuk (Korean fish cake), cut into triangles","3 tbsp gochujang (fermented red chili paste)","1 tbsp gochugaru (Korean red pepper flakes)","1 tbsp sugar","1 tsp soy sauce","500ml anchovy stock (or water with a dashi packet)","2 spring onions, cut into 5 cm pieces","2 hard-boiled eggs, peeled","1 tsp sesame oil","1 tsp toasted sesame seeds"],"ro":["500g tteok cilindric (garae-tteok) proaspăt sau dezghețat","150g eomuk (prăjitură de pește coreeană), tăiat în triunghiuri","3 linguri gochujang (pastă de ardei iute fermentat)","1 lingură gochugaru (fulgi de ardei iute coreean)","1 lingură zahăr","1 linguriță sos de soia","500ml supă de hamsii (sau apă cu dashi)","2 cepe verzi, tăiate în bucăți de 5 cm","2 ouă fierte tari, decojite","1 linguriță ulei de susan","1 linguriță semințe de susan prăjite"]},"howIsMade":{"zh":"年糕若硬或冷藏，先用温水浸泡20–30分钟至软、沥干。在宽口浅锅中以中大火将500毫升鳀鱼汤煮沸。加入3汤匙辣椒酱、1汤匙辣椒粉、1汤匙糖和1茶匙酱油、打散搅拌至辣椒酱完全溶化、汤汁变成有光泽的红色。加入沥干的年糕、轻轻翻拌使每块都裹上汁液，转中火慢煮8–10分钟，频繁搅动，直到年糕变软、汤汁收浓挂勺。加入鱼糕块，再煮3–4分钟，至吸收汤汁变成鲜红色。把2个煮鸡蛋放入加热、试味，必要时加少许糖或几滴酱油调整。淋芝麻油，撒上大葱段和烤芝麻、立即趁热从锅中盛出食用。","en":"If the rice cakes are hard or refrigerated, soak them in warm water for 20–30 minutes until pliable; drain. In a wide shallow pan, bring 500ml of anchovy stock to a boil over medium-high heat. Stir in 3 tbsp gochujang, 1 tbsp gochugaru, 1 tbsp sugar and 1 tsp soy sauce; whisk until the paste fully dissolves and the sauce turns glossy red. Add the drained rice cakes; stir gently to coat every piece, then simmer over medium heat for 8–10 minutes, stirring often, until the rice cakes are tender and the sauce has thickened to a syrupy consistency that coats the back of a spoon. Add the eomuk pieces and cook for another 3–4 minutes, until they have absorbed the sauce and turned bright red. Slip in the 2 hard-boiled eggs to warm through; taste and adjust with a pinch of sugar or a splash of soy if needed. Drizzle with sesame oil, sprinkle with the spring onions and sesame seeds; serve immediately, very hot, straight from the pan."}},{"id":103,"origin":{"zh":"厄瓜多尔","en":"Ecuador","ro":"Ecuador"},"name":{"zh":"厄瓜多尔虾酸橘汁腌","en":"Shrimp Ceviche","ro":"Ceviche de camarón"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"zh":["600克中虾，去壳去虾线","180毫升新鲜青柠汁（约8个青柠）","120毫升新鲜橙汁","1个大红洋葱，切小丁","3个成熟番茄，去籽切丁","1个红辣椒（ají），切碎（可选）","30克新鲜香菜叶，切碎","3汤匙橄榄油","1茶匙细海盐","现磨黑胡椒","chifles（炸香蕉片）或烤玉米，搭配食用"],"en":["600g medium shrimp, peeled and deveined","180ml fresh lime juice (about 8 limes)","120ml fresh orange juice","1 large red onion, finely diced","3 ripe tomatoes, deseeded and diced","1 red chili (ají), finely chopped (optional)","30g fresh coriander leaves, chopped","3 tbsp olive oil","1 tsp fine sea salt","freshly ground black pepper","chifles (plantain chips) or toasted corn, to serve"],"ro":["600g creveți medii, decojiți și fără vene","180ml suc proaspăt de lime (aproximativ 8 lime)","120ml suc proaspăt de portocale","1 ceapă roșie mare, tăiată cuburi mici","3 roșii coapte, fără semințe și tăiate cuburi","1 ardei iute roșu (ají), tocat fin (opțional)","30g frunze de coriandru proaspăt, tocate","3 linguri ulei de măsline","1 linguriță sare fină de mare","piper negru proaspăt măcinat","chifles (chipsuri de plantain) sau porumb prăjit, pentru servit"]},"howIsMade":{"zh":"大锅烧开盐水、放入虾煮60–90秒，至变粉红、肉质不透明、立即捞出，放入冰水中冷却。虾沥干，按喜好切半或保留整只，放入非反应性的碗（玻璃或陶瓷）。在虾上倒入180毫升青柠汁和120毫升橙汁、拌匀，盖好，冷藏15–20分钟。虾腌制期间，把切丁的红洋葱用加盐冰水浸泡10分钟再沥干——可减轻生洋葱的辛辣，同时保持脆度。把沥干的洋葱、番茄、辣椒、香菜、3汤匙橄榄油和1茶匙盐加入虾碗、轻轻拌匀。尝味后用盐、青柠或辣椒微调、静置5分钟让风味融合。在浅口碗中冰镇上桌，搭配chifles或烤玉米带来酥脆口感。","en":"Bring a large pot of salted water to a boil; add the shrimp and boil for 60–90 seconds, until pink and opaque; drain immediately and shock in a bowl of ice water. Drain the shrimp, halve them or leave them whole as you prefer, and place in a non-reactive (glass or ceramic) bowl. Pour 180ml lime juice and 120ml orange juice over the shrimp; toss, cover, and refrigerate for 15–20 minutes. While the shrimp marinates, soak the diced red onion in salted ice water for 10 minutes, then drain — this softens the harsh bite without losing crunch. Add the drained onion, tomatoes, chili, coriander, 3 tbsp olive oil and 1 tsp salt to the shrimp bowl; toss gently. Taste and adjust salt, lime, or chili; let rest for 5 minutes so the flavours settle. Serve very cold in shallow bowls, with chifles or toasted corn alongside for crisp contrast."}},{"id":104,"origin":{"zh":"多米尼加","en":"Dominican Republic","ro":"Republica Dominicană"},"name":{"zh":"多米尼加国旗餐","en":"La Bandera","ro":"La Bandera"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"zh":["400克长粒白米","250克干红芸豆（或800克煮熟/罐装，沥干）","600克带骨鸡腿或牛肩肉，切4厘米方块","2根大青香蕉（plantain），去皮切1厘米厚片","1个中等青甜椒，切小丁","1个小红甜椒，切小丁","1个大洋葱，细切碎","4瓣大蒜，切末","30克新鲜香菜，切碎（或culantro，如有）","2个成熟番茄，切丁（或200克罐装碎番茄）","2汤匙番茄酱","60毫升植物油（另备炸香蕉用油）","1茶匙干牛至","1个青柠的汁","盐和现磨黑胡椒"],"en":["400g long-grain white rice","250g dried red kidney beans (or 800g cooked/canned, drained)","600g bone-in chicken thighs or beef chuck, cut into 4 cm cubes","2 large green plantains, peeled and sliced 1 cm thick","1 medium green bell pepper, finely diced","1 small red bell pepper, finely diced","1 large onion, finely chopped","4 garlic cloves, minced","30g fresh coriander, chopped (or culantro if available)","2 ripe tomatoes, diced (or 200g canned chopped tomatoes)","2 tbsp tomato paste","60ml vegetable oil (plus more for frying plantains)","1 tsp dried oregano","juice of 1 lime","salt and freshly ground black pepper"],"ro":["400g orez cu bob lung alb","250g fasole roșie uscată (sau 800g fasole gătită)","600g pulpe de pui cu os sau pulpă de vită, tăiată cuburi de 4 cm","2 banane plantain verzi mari, decojite, tăiate rondele de 1 cm","1 ardei gras verde mediu, tăiat cuburi mici","1 ardei gras roșu mic, tăiat cuburi mici","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","30g coriandru proaspăt, tocat (sau culantro)","2 roșii coapte, tăiate cuburi (sau 200g roșii din conservă)","2 linguri pastă de roșii","60ml ulei vegetal (plus mai mult pentru prăjit)","1 linguriță oregano uscat","zeamă de la 1 lime","sare și piper negru proaspăt măcinat"]},"howIsMade":{"zh":"干豆使用前一晚浸泡、沥干，加入1升清水和少许盐，小火煮60–75分钟至完全软烂、保留250毫升煮汁。用盐、胡椒、牛至和青柠汁腌制肉，静置15分钟，同时准备sofrito酱底。厚底锅加热2汤匙油、做sofrito：洋葱炒5分钟，加入大蒜、两种甜椒和一半香菜，炒4分钟至软。把sofrito推到一旁、在空出的位置放肉，每面煎3–4分钟、加入2汤匙番茄酱和番茄丁，炒3分钟、倒入500毫升水，盖盖小火炖35–40分钟，至肉用叉子能轻易戳穿、汤汁收浓。同时煮饭：400克米洗到水清、宽锅中加热1汤匙油和1茶匙盐，下米，加700毫升水，煮开后转最小火，盖盖焖18–20分钟、离火再静置10分钟。收尾豆子：小锅加热1汤匙油和步骤3留出的一勺sofrito、倒入沥干的豆子，加250毫升保留的煮汁和1茶匙盐、煮12–15分钟，将一把豆子压在锅壁上以增稠成酱状。平底锅加热5厘米油至175°C、炸大蕉片3–4分钟至金黄、捞出沥油，用压具或杯底压扁，再炸1–2分钟至酥脆、趁热撒盐。摆盘：米饭做底，一勺豆子在旁，丰盛的炖肉浇汁，配4–5片炸大蕉、撒上剩余香菜、青柠角和简单的绿叶沙拉。","en":"Soak the dried beans overnight if using; drain, cover with 1L fresh water and a pinch of salt, and simmer for 60–75 minutes, until fully tender; reserve 250ml of the cooking liquid. Season the meat with salt, pepper, oregano, and lime juice; rest for 15 minutes while you prepare the sofrito. Heat 2 tbsp oil in a heavy pot; make a sofrito: sauté the onion for 5 minutes, then add the garlic, both peppers, and half the coriander; cook 4 minutes until soft. Push the sofrito to one side; add the meat to the empty space and brown for 3–4 minutes per side; stir in 2 tbsp tomato paste and the diced tomatoes, cook for 3 minutes; pour in 500ml water, cover, and simmer for 35–40 minutes, until the meat is fork-tender and the sauce has thickened. Meanwhile cook the rice: rinse 400g of rice until the water runs clear; in a wide pot, heat 1 tbsp oil and 1 tsp salt, add the rice, cover with 700ml water, bring to a boil, then reduce to the lowest heat and steam, covered, for 18–20 minutes; rest 10 minutes off heat. Finish the beans: in a small pot, heat 1 tbsp oil and a spoonful of the sofrito set aside in step 3; add the drained beans plus 250ml reserved cooking liquid and 1 tsp salt; simmer for 12–15 minutes, mashing a handful against the side of the pot to thicken to a saucy consistency. Heat 5 cm of oil in a frying pan to 175°C; fry the plantain slices for 3–4 minutes until golden; drain on paper, flatten with a press or the back of a cup, and refry for 1–2 minutes until crisp; salt while hot. Plate each portion with rice as the base, a ladle of beans alongside, a generous portion of braised meat with its sauce, and 4–5 plantain rounds; finish with the remaining coriander, lime wedges, and a simple green salad."}},{"id":105,"origin":{"zh":"伊朗","en":"Iran","ro":"Iran"},"name":{"zh":"伊朗核桃石榴炖鸡","en":"Fesenjan","ro":"Fesenjan"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"zh":["800克去骨鸡腿，或1只小鸭子（1.5公斤）切块","300克核桃仁，烤香并细磨","120毫升石榴糖浆","2个大洋葱，细切碎","3汤匙植物油","1茶匙姜黄粉","1茶匙肉桂粉","1/2茶匙现磨肉豆蔻","1汤匙红糖（或按口味）","1升热鸡汤或水","新鲜石榴籽，用于装饰","盐和现磨黑胡椒","巴斯马蒂米，用于搭配"],"en":["800g boneless chicken thighs, or 1 small duck (1.5kg) jointed","300g shelled walnuts, toasted and finely ground","120ml pomegranate molasses","2 large onions, finely chopped","3 tbsp vegetable oil","1 tsp ground turmeric","1 tsp ground cinnamon","1/2 tsp freshly grated nutmeg","1 tbsp brown sugar (or to taste)","1 litre hot chicken stock or water","fresh pomegranate seeds, to garnish","salt and freshly ground black pepper","basmati rice, to serve"],"ro":["800g pulpe de pui dezosate, sau 1 rață mică (1,5kg) tăiată","300g miez de nucă, prăjit și măcinat fin","120ml melasă de rodie","2 cepe mari, tocate fin","3 linguri ulei vegetal","1 linguriță turmeric măcinat","1 linguriță scorțișoară măcinată","1/2 linguriță nucșoară proaspăt rasă","1 lingură zahăr brun (sau după gust)","1 litru supă de pui sau apă fierbinte","semințe de rodie proaspete, pentru ornat","sare și piper negru proaspăt măcinat","orez basmati pentru servit"]},"howIsMade":{"zh":"干锅中将300克核桃以中火烘烤4–5分钟，持续翻动至香气四溢、颜色略深、冷却后，用料理机磨成尽可能细的酱泥。厚底锅中加热3汤匙油，中火、加入切碎洋葱炒12–15分钟至深金黄色且带甜味、加入姜黄、肉桂和肉豆蔻炒1分钟。肉用盐和胡椒调味、放入锅中每面煎4–5分钟，只为上色、盛出到盘中。加入核桃酱，用木勺搅拌3分钟，直到开始出油、散发烤香——这一步建立酱汁的深度。倒入1升热高汤，把肉连汁倒回锅中，不盖盖小火炖30–40分钟，频繁搅拌防止核桃酱粘底。加入石榴糖浆和红糖、试味：酱汁应酸甜浓郁、继续小火炖30–40分钟，直到肉完全软嫩，酱汁颜色近黑，核桃油浮上表面。用盐、更多糖浆（增酸）或糖（圆润）调整、配温热的巴斯马蒂米饭，撒上新鲜石榴籽。","en":"Toast 300g of walnuts in a dry pan over medium heat for 4–5 minutes, tossing constantly, until fragrant and slightly darker; cool, then grind to as fine a paste as possible in a food processor. In a heavy pot, heat 3 tbsp oil over medium heat; add the chopped onions and cook for 12–15 minutes, until deeply golden and sweet; stir in the turmeric, cinnamon, and nutmeg and cook for 1 minute. Season the meat with salt and pepper; add to the pot and brown for 4–5 minutes per side, just for colour; lift onto a plate. Add the walnut paste to the pot and stir with a wooden spoon for 3 minutes, until it starts releasing oil and smells toasted — this is the step that builds the sauce's depth. Pour in 1 litre of hot stock, return the meat with its juices, and simmer uncovered over low heat for 30–40 minutes, stirring often so the nut paste does not scorch. Add the pomegranate molasses and brown sugar; taste: the sauce should be tart-sweet and deeply savoury; continue to simmer over low heat for another 30–40 minutes, until the meat is fully tender, the sauce has darkened to almost black, and walnut oil rises to the surface. Adjust with salt, more molasses (for tartness) or sugar (to round it); serve over warm basmati rice, scattered with fresh pomegranate seeds."}},{"id":106,"origin":{"zh":"菲律宾","en":"Philippines","ro":"Filipine"},"name":{"zh":"菲式花生炖牛肉","en":"Kare-Kare","ro":"Kare-Kare"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["1.2公斤牛尾，沿关节切块（或带骨牛腱）","200克无糖花生酱（或250克烤花生研磨）","2汤匙胭脂树种子（annatto/achuete）——或1汤匙胭脂树粉","4汤匙生米，干锅焙香后磨粉","1个大洋葱，细切碎","6瓣大蒜，切末","1个大茄子，切四等分","200克长豆角（sitaw），切7厘米段","1棵大白菜或200克小白菜，纵向对半","1.5升水（或牛骨高汤）","60毫升植物油","盐适量","巴贡虾酱（bagoong，菲律宾发酵虾酱），用于搭配","蒸米饭，用于搭配"],"en":["1.2kg oxtail, cut at the joints (or bone-in beef shank)","200g unsweetened peanut butter (or 250g roasted peanuts, ground)","2 tbsp annatto (achuete) seeds — or 1 tbsp annatto powder","4 tbsp raw rice, toasted in a dry pan and ground","1 large onion, finely chopped","6 garlic cloves, minced","1 large eggplant, cut into quarters","200g long green beans (sitaw), cut into 7 cm lengths","1 large bok choy or 200g pechay, halved lengthwise","1.5L water (or beef stock)","60ml vegetable oil","salt to taste","bagoong (Filipino shrimp paste), to serve","steamed rice, to serve"],"ro":["1,2kg coadă de vită, tăiată în bucăți la articulație (sau pulpă de vită cu os)","200g pastă de arahide neîndulcită (sau 250g arahide prăjite, măcinate)","2 linguri semințe de annatto (achiote) — sau 1 lingură pudră de annatto","4 linguri orez crud, prăjit într-o tigaie uscată și măcinat","1 ceapă mare, tocată fin","6 căței de usturoi, tocați","1 vânătă mare, tăiată sferturi","200g fasole verde lungă, tăiată în bucăți de 7 cm","1 bok choy mare sau 200g pak choi, tăiat pe lungime","1,5L apă (sau supă de vită)","60ml ulei vegetal","sare după gust","bagoong (pastă de creveți filipineză) pentru servit","orez fiert, pentru servit"]},"howIsMade":{"zh":"牛尾放入大锅，加1.5升水、煮沸撇沫煮5分钟、捞出沥干并冲洗牛尾，以获得清澈高汤。牛尾回锅，加1.5升清水或牛骨高汤，小火慢炖2.5–3小时，至肉几乎脱骨、捞出肉，留1升汤备用。胭脂树种子用3汤匙热水浸泡10分钟，过滤得深红橙色液体（或直接将胭脂树粉溶入）。干净锅中加热60毫升油、洋葱炒5分钟，加大蒜炒1分钟。加入花生酱、胭脂树水和1升保留高汤、用打蛋器搅打使其顺滑、煮5分钟，加入烤米粉——酱汁开始明显变浓。把牛尾放回酱汁，小火炖10–15分钟，若过浓可加汤稀释、少量盐调味——桌上的虾酱很咸。加入茄子块和豆角，煮5分钟、上面铺上小白菜，盖盖再煮3分钟，至蔬菜变软仍鲜亮。盛入深碗，浇在蒸米饭上，桌边放一小碗bagoong虾酱——食客按口味自行拌入。","en":"Put the oxtail in a large pot with 1.5L water; bring to a boil, skim the foam, and boil for 5 minutes; drain and rinse the meat for a clear broth. Return the meat to the pot with 1.5L fresh water (or beef stock) and simmer gently for 2.5–3 hours, until the meat falls almost off the bone; lift out the meat and reserve 1L of the broth. Steep the annatto seeds in 3 tbsp hot water for 10 minutes, then strain to a deep red-orange liquid (or dissolve the annatto powder directly). In a clean pot, heat 60ml oil; sauté the onion for 5 minutes, add the garlic and cook 1 minute more. Stir in the peanut butter, annatto liquid, and 1L of the reserved broth; whisk to keep it smooth; simmer 5 minutes, then add the toasted ground rice — the sauce will begin to thicken visibly. Return the meat to the sauce and simmer over low heat for 10–15 minutes, loosening with more broth if it becomes too thick; season with salt (sparingly — the bagoong at the table is very salty). Add the eggplant quarters and long beans, simmer 5 minutes; lay the bok choy on top, cover, and cook for another 3 minutes, until the vegetables are tender but still vibrant. Serve in deep bowls over steamed rice, with bagoong in a small bowl alongside — each diner stirs in as much as they like."}},{"id":107,"origin":{"zh":"葡萄牙","en":"Portugal","ro":"Portugalia"},"name":{"zh":"葡式法兰西三明治","en":"Francesinha","ro":"Francesinha"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["8片厚白吐司面包","400克肋眼或西冷牛排，切成4片薄片","4根linguiça或熏香肠，纵切两半","8片熟火腿","8片辣味萨拉米或chouriço香肠","12片切达或高达奶酪（融化用）","4个鸡蛋，置顶","30克黄油","煎蛋用油","酱汁：","400毫升淡啤酒","200毫升牛骨高汤","200克番茄酱","60毫升威士忌或白兰地","1个小洋葱，细切碎","2瓣大蒜，切末","1片月桂叶","1/2茶匙辣椒片（或piri-piri）","1汤匙面粉","盐、胡椒、糖适量","炸薯条，搭配食用"],"en":["8 thick slices white bread (sandwich loaf)","400g rib-eye or sirloin steak, cut into 4 thin slices","4 linguiça or smoked sausage links, halved lengthwise","8 slices cooked ham","8 slices spicy salami or chouriço","12 slices Cheddar or Gouda, melting type","4 eggs, for topping","30g butter","oil for frying eggs","For the sauce:","400ml lager beer","200ml beef stock","200g tomato paste","60ml whisky or brandy","1 small onion, finely chopped","2 garlic cloves, minced","1 bay leaf","1/2 tsp chili flakes (or piri-piri)","1 tbsp flour","salt, pepper, sugar to taste","fries, to serve"],"ro":["8 felii groase de pâine albă (tip toast)","400g antricot sau mușchi de vită, în 4 felii subțiri","4 cârnați linguiça (sau cabanos afumat), tăiați pe lungime","8 felii de șuncă (presunto) fiartă","8 felii salami picant (chouriço)","12 felii brânză cheddar sau Gouda topit","4 ouă (pentru deasupra)","30g unt","ulei pentru prăjit ouăle","Pentru sos:","400ml bere blondă","200ml bulion de vită","200g pastă de roșii","60ml whisky sau brandy","1 ceapă mică, tocată","2 căței de usturoi, tocați","1 frunză de dafin","1/2 linguriță fulgi de chili (sau piri-piri)","1 lingură făină","sare, piper, zahăr după gust","cartofi prăjiți, pentru servit"]},"howIsMade":{"zh":"先做酱汁：小锅中融化1汤匙黄油，洋葱炒5分钟，加入大蒜和1汤匙面粉炒1分钟、加入番茄酱炒2分钟。倒入啤酒和威士忌，煮2分钟以挥发酒精、加入牛骨高汤、月桂叶、辣椒片、少许盐和糖、小火炖25–30分钟至酱汁浓稠有光泽、过滤获得顺滑口感。牛排切片用盐和胡椒调味、剩余黄油在平底锅中融化，将牛排每面煎1.5分钟至上色，取出。同锅煎linguiça，每面2–3分钟至上色。每个三明治取2片面包，用黄油或油在两面各煎1分钟、叠层：1片面包、2片火腿、1片牛排、2片萨拉米、2半linguiça，再盖上第二片面包、轻轻按压。三明治放入抹油烤盘、每个盖3片奶酪，220°C上火烤3–4分钟，至奶酪融化起泡并局部上色。每个三明治煎1个鸡蛋，保留蛋黄半流心。把三明治放入深盘，将煎蛋放在奶酪上，热酱汁大量倒在三明治周围——应在盘底积成一汪、立即配薯条上桌。","en":"Make the sauce first: heat 1 tbsp of the butter in a saucepan, sauté the onion for 5 minutes, add the garlic and 1 tbsp flour, cook for 1 minute; stir in the tomato paste and cook for 2 minutes. Pour in the beer and whisky, simmer 2 minutes to burn off the alcohol; add the beef stock, bay leaf, chili flakes, a pinch each of salt and sugar; simmer over low heat for 25–30 minutes, until the sauce is thick and glossy; strain for a smooth finish. Season the steak slices with salt and pepper; melt the remaining butter in a frying pan and sear the steak for 1.5 minutes per side, until browned; lift out. In the same pan, fry the linguiça halves for 2–3 minutes per side, until coloured. For each sandwich, toast 2 slices of bread in butter or oil on both sides (1 minute per side); layer: 1 slice bread, 2 slices ham, 1 slice steak, 2 slices salami, 2 linguiça halves, top with second slice of bread; press gently. Place the sandwiches in a greased baking dish; cover each with 3 slices of cheese and slide under a grill at 220°C for 3–4 minutes, until the cheese melts, bubbles and browns in spots. Fry 1 egg per sandwich in oil, leaving the yolk runny. Set each sandwich in a deep plate, place a fried egg on top of the cheese, and pour the hot sauce generously around the sandwich — it should pool at the base of the plate; serve immediately with fries on the side."}},{"id":109,"origin":{"zh":"秘鲁","en":"Peru","ro":"Peru"},"name":{"zh":"秘鲁炒饭","en":"Arroz Chaufa","ro":"Arroz Chaufa"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"zh":["500克长粒米饭，已煮熟并冷却（最好是隔夜饭）","300克鸡胸或猪里脊，切1.5厘米方块","3个大鸡蛋，打散","1个红甜椒，切小丁","6根青葱，葱白细切，葱绿留用","3瓣大蒜，切末","20克新鲜生姜，切细末","60毫升酱油","1汤匙耗油","1汤匙烘焙芝麻油","60毫升中性植物油","1茶匙黄辣椒酱（ají amarillo）（或1/2茶匙辣椒粉）","盐和白胡椒适量"],"en":["500g long-grain rice, cooked and cooled (preferably day-old)","300g chicken breast or pork loin, cut into 1.5 cm cubes","3 large eggs, beaten","1 red bell pepper, finely diced","6 spring onions, white parts finely sliced, green parts reserved","3 garlic cloves, minced","20g fresh ginger, finely minced","60ml soy sauce","1 tbsp oyster sauce","1 tbsp toasted sesame oil","60ml neutral vegetable oil","1 tsp ají amarillo paste (or 1/2 tsp chili powder)","salt and white pepper to taste"],"ro":["500g orez cu bob lung fiert și răcit (preferabil de o zi)","300g piept de pui sau pulpă de porc, tăiat cuburi de 1,5 cm","3 ouă mari, bătute","1 ardei kapia roșu, tăiat cuburi mici","6 cepe verzi, partea albă tăiată fin, verdele păstrat","3 căței de usturoi, tocați","20g ghimbir proaspăt, tocat fin","60ml sos de soia","1 lingură sos de stridii","1 lingură ulei de susan","60ml ulei vegetal neutru","1 linguriță aji amarillo pastă (sau 1/2 linguriță pudră de chili)","sare și piper alb după gust"]},"howIsMade":{"zh":"鸡蛋加少许盐打散、中火热1汤匙油，倒入蛋液，快速翻炒成薄煎蛋皮、盛出切成小丁，备用。锅烧得很热，再加1汤匙油、肉加少许盐爆炒3–4分钟，至边缘焦黄、内里熟透、取出和蛋一起放盘。把剩余植物油倒入锅中烧至微微冒烟、加入蒜末、姜末和甜椒丁炒30秒至香气出来。加入葱白和黄辣椒酱（ají amarillo）、再炒30秒让油吸足香气。倒入冷米饭、用锅铲将饭团打散，反复将米压向锅底再翻动3–4分钟，至每粒米都散开并发出轻微的滋滋声。把酱油和耗油浇在饭上，翻炒1分钟使颜色均匀渗入、把肉和蛋倒回锅中。关火、淋上芝麻油，撒上葱绿、用白胡椒调味、立即从锅中盛出热食。","en":"Beat the eggs with a pinch of salt; heat 1 tbsp of vegetable oil in a wok over medium heat, pour in the eggs, and quickly make a thin omelette by stirring; tip onto a plate and cut into small cubes; set aside. With the wok very hot, add another 1 tbsp oil; stir-fry the meat with a pinch of salt for 3–4 minutes, until browned at the edges and cooked through; move to the plate with the eggs. Pour the remaining vegetable oil into the wok and heat until it just begins to smoke; add the garlic, ginger, and bell pepper, and stir-fry for 30 seconds, until fragrant. Add the white parts of the spring onions and the ají amarillo paste; stir-fry for 30 seconds, letting the flavours infuse the oil. Add the cold rice; use a spatula to break it into small pieces, pressing it against the bottom of the wok between tosses for 3–4 minutes, until every grain is separate and you hear a slight sizzle. Pour the soy sauce and oyster sauce over the rice, tossing for 1 minute to distribute evenly and pick up colour; return the meat and egg to the wok. Turn off the heat; drizzle with the sesame oil and add the green parts of the spring onions; season with white pepper; serve immediately, hot, straight from the wok."}},{"id":110,"origin":{"zh":"新加坡","en":"Singapore","ro":"Singapore"},"name":{"zh":"辣椒蟹","en":"Chili Crab","ro":"Chili Crab"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"zh":["2只活泥蟹（共1.5公斤），清理后沿关节切两半","番茄酱4汤匙","参巴酱（sambal oelek）3汤匙（或辣椒酱）","甜辣酱2汤匙","番茄沙司60毫升","新鲜生姜30克，磨碎","6瓣大蒜，切末","2个大鸡蛋，打散","3根青葱，切碎","米醋1汤匙","糖2茶匙","盐1茶匙","鸡汤500毫升（或水）","植物油60毫升","玉米淀粉1汤匙与2汤匙水混合","炸馒头（中式包子），搭配食用"],"en":["2 live mud crabs (1.5kg total), cleaned and halved at the joints","4 tbsp tomato paste","3 tbsp sambal oelek (or chili paste)","2 tbsp sweet chili sauce","60ml ketchup","30g fresh ginger, grated","6 garlic cloves, minced","2 large eggs, beaten","3 spring onions, chopped","1 tbsp rice vinegar","2 tsp sugar","1 tsp salt","500ml chicken stock (or water)","60ml vegetable oil","1 tbsp cornstarch mixed with 2 tbsp water","fried mantou (Chinese buns), to serve"],"ro":["2 crabi de noroi vii (1,5kg în total), curățați și tăiați în jumătăți la articulații","4 linguri pastă de roșii","3 linguri sos sambal oelek (sau pastă de chili)","2 linguri sos dulce de chili","60ml ketchup","30g ghimbir proaspăt, ras","6 căței de usturoi, tocați","2 ouă mari, bătute","3 cepe verzi, tocate","1 lingură oțet de orez","2 lingurițe zahăr","1 linguriță sare","500ml supă de pui (sau apă)","60ml ulei vegetal","1 lingură amidon de porumb amestecat cu 2 linguri apă","mantou prăjit (chifle chinezești), pentru servit"]},"howIsMade":{"zh":"将活蟹放入冷冻室30分钟，让其无痛麻醉、清理，掀开上盖壳，去除柔软内脏，沿关节将蟹切两半、用刀背敲裂蟹钳，让味道渗入。鸡蛋打入小碗、另一碗中混合番茄酱、参巴酱、甜辣酱、番茄沙司、醋、糖和盐——这是酱底。大火热60毫升油于大炒锅或深锅、下蟹块煎炒3–4分钟，翻面，至蟹壳变红、盛出备用。同样的油里炒姜末和蒜末30秒，至香气浓郁。倒入番茄基底酱和500毫升鸡汤、煮沸，按需加更多参巴酱增辣。蟹块下锅，盖盖小火炖8–10分钟，中途翻面一次，至蟹肉熟透变嫩。细流倒入水淀粉勾芡，使酱汁浓稠光亮、打散的蛋液沿炒锅边缘螺旋倒入但不要搅拌——蛋液会凝成丝绸般细丝、等30秒后再翻动一次。撒上葱花、立即装大盘上桌，旁边配炸馒头蘸吸酱汁。","en":"Place the crabs in the freezer for 30 minutes to humanely stun them; clean them, lift off the top shell, remove the soft inner organs, and chop the crab in half at the joints; crack the claws with the back of a knife so the flavour penetrates. Beat the eggs in a small bowl; in another bowl, stir together the tomato paste, sambal, sweet chili sauce, ketchup, vinegar, sugar and salt — this is the sauce base. Heat 60ml of oil in a large wok or deep pot over high heat; add the crab pieces and stir-fry for 3–4 minutes, turning, until the shells turn red; lift onto a plate. In the same oil, sauté the grated ginger and garlic for 30 seconds, until very fragrant. Pour in the tomato-paste mixture and 500ml chicken stock; bring to a boil, adjust with more sambal for more heat. Return the crab pieces, cover the wok and simmer for 8–10 minutes, turning once halfway, until the meat is fully cooked and tender. Stir the cornstarch slurry into the sauce in a thin stream so the sauce thickens to a glossy coat; pour the beaten eggs around the wok in a spiral without stirring — they will set as silky ribbons; wait 30 seconds, then fold once. Scatter with the chopped spring onions; serve immediately on a large platter with fried mantou alongside to soak up the sauce."}},{"id":111,"origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"玉米粽","en":"Tamale","ro":"Tamale"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"mexican","ingredients":{"zh":["20–24片干玉米叶","500克玛萨哈里娜（masa harina，碱化玉米面粉）","250克猪油，室温","500毫升温鸡汤","1汤匙泡打粉","2茶匙盐","馅料：","500克去骨猪肩肉，水煮后撕丝","4个干瓜希约辣椒（guajillo），去蒂去籽","2个干安丘辣椒（ancho），去蒂去籽","1个小洋葱，切四等分","3瓣大蒜","1茶匙孜然粉","1茶匙墨西哥牛至","2汤匙植物油","盐适量","红或绿莎莎酱，搭配食用"],"en":["20–24 dried corn husks","500g masa harina (nixtamalized corn flour)","250g pork lard, at room temperature","500ml warm chicken stock","1 tbsp baking powder","2 tsp salt","For the filling:","500g boneless pork shoulder, simmered and shredded","4 dried guajillo chilies, stems and seeds removed","2 dried ancho chilies, stems and seeds removed","1 small onion, quartered","3 garlic cloves","1 tsp ground cumin","1 tsp Mexican oregano","2 tbsp vegetable oil","salt to taste","red or green salsa, to serve"],"ro":["20–24 foi de porumb uscate (chiote)","500g masa harina (făină de porumb nixtamalizată)","250g untură de porc, la temperatura camerei","500ml supă de pui caldă","1 lingură praf de copt","2 lingurițe sare","Pentru umplutură:","500g pulpă de porc dezosată, fiartă și mărunțită","4 ardei iuți guajillo uscați, fără semințe","2 ardei iuți ancho uscați, fără semințe","1 ceapă mică, tăiată sferturi","3 căței de usturoi","1 linguriță chimion măcinat","1 linguriță oregano mexican","2 linguri ulei vegetal","sare după gust","salsă roșie sau verde, pentru servit"]},"howIsMade":{"zh":"玉米叶在温水中浸泡30分钟至柔软、用盘子压住保持浸没。制作酱汁：瓜希约和安丘辣椒在干锅中每面烤1分钟至香、用热水浸泡15分钟、将泡好的辣椒、洋葱、大蒜、孜然、牛至和250毫升泡椒水放入搅拌机打成酱、过滤。锅中加热2汤匙油，倒入辣椒酱煮8–10分钟至浓稠、加入撕碎的猪肉，用盐调味，再煮5分钟、放凉。用电动搅拌器搅打猪油3分钟至蓬松发白、加入泡打粉和盐再搅打30秒。交替加入玛萨哈里娜和温鸡汤，持续搅打、面团应轻盈蓬松，能挂在抹刀上、测试方法：取小球放冷水中，应浮起来。沥干玉米叶、每个玉米粽：在叶子上抹3汤匙面团成薄层，两侧留2厘米，上方留5厘米、中央放2汤匙馅料。将叶子两侧折叠覆盖馅料，再将窄端向上折叠，留顶部敞开、垂直摆放在蒸笼中，开口朝上。蒸60–75分钟，至打开一个时面团能干净地脱离叶子、静置10分钟后再上桌、配红或绿莎莎酱热食。","en":"Soak the corn husks in warm water for 30 minutes, until pliable; weight them down with a plate so they stay submerged. Make the sauce: toast the guajillo and ancho chilies in a dry pan for 1 minute per side, until fragrant; cover with hot water for 15 minutes; blend the rehydrated chilies with the onion, garlic, cumin, oregano and 250ml of the soaking liquid; strain the sauce. Heat 2 tbsp oil in a pan, pour in the chili sauce and simmer for 8–10 minutes, until thickened; add the shredded pork, season with salt and cook another 5 minutes; let it cool. Beat the lard with a mixer for 3 minutes, until fluffy and pale; add the baking powder and salt, mix 30 seconds more. Add the masa harina alternately with warm chicken stock, beating continuously; the dough should be light, fluffy, and cling to the spatula; test by dropping a small ball into cold water — it should float. Drain the corn husks; for each tamale, spread 3 tbsp of dough in a thin layer on a husk, leaving a 2 cm border on the sides and 5 cm at the top; place 2 tbsp filling down the centre. Fold the sides of the husk over the filling, then fold the narrow end up, leaving the top open; stand the tamales vertically in a steamer basket, open ends up. Steam for 60–75 minutes, until the dough peels cleanly away from the husk when you open one; let them rest 10 minutes before serving; serve warm with red or green salsa alongside."}},{"id":112,"origin":{"zh":"泰国","en":"Thailand","ro":"Thailanda"},"name":{"zh":"冬阴功汤","en":"Tom Yum","ro":"Tom Yum"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"thai","ingredients":{"zh":["鸡汤或海鲜汤1升","生虾300克，剥壳去肠线","香茅2根，切3厘米段并拍扁","南姜（或生姜）30克，切薄片","卡菲尔柠檬叶6片","泰式红辣椒3–4根，对切","蚝菇或口蘑200克，切片","鱼露3大勺","新鲜青柠汁2大勺","棕榈糖1大勺","冬阴功酱2大勺（可选）","葱1根，装饰用","新鲜香菜上桌用"],"en":["1L chicken or seafood stock","300g raw prawns, peeled and deveined","2 stalks lemongrass, cut into 3cm pieces and bruised","30g galangal (or ginger), thinly sliced","6 kaffir lime leaves","3–4 Thai red chillies, halved","200g oyster or button mushrooms, sliced","3 tbsp fish sauce","2 tbsp fresh lime juice","1 tbsp palm sugar","2 tbsp tom yum paste (optional)","1 spring onion stalk, to garnish","Fresh coriander to serve"],"ro":["1 L supă de pui sau stoc de fructe de mare","300g creveți cruzi, curățați","2 tulpini lemongrass, secționate în bucăți de 3 cm și zdrobite","30g galangal (sau ghimbir), felii subțiri","6 frunze de kaffir lime","3–4 ardei iuți roșii thailandezi, tăiați pe jumătate","200g ciuperci pleurotus sau champignon, feliate","3 linguri sos de pește","2 linguri suc proaspăt de lime","1 lingură zahăr de palmier","2 linguri pastă tom yum (opțional)","1 tulpină ceapă verde, pentru servire","Coriandru proaspăt, pentru servire"]},"howIsMade":{"zh":"大锅中将1升高汤煮至轻微沸腾。加入拍碎的香茅、南姜片和卡菲尔柠檬叶、小火煮10分钟，让香料充分释放进汤中。加入冬阴功酱（如使用）、对半切的辣椒和切片的蘑菇，煮3–4分钟至蘑菇略软。加入虾，精确煮2–3分钟——虾应变粉红色并卷曲、切勿煮过，否则会变橡皮。离火、加入3汤匙鱼露、2汤匙鲜青柠汁和1汤匙棕榈糖。试味并调整：汤应同时呈现酸、咸、辣、微甜四重味道、加更多青柠为酸度，加更多鱼露为咸味。立即盛入深碗，撒葱花和新鲜香菜、香茅、南姜和柠檬叶是提香的，不可食用。","en":"Bring 1L of stock to a gentle simmer in a large pot. Add the bruised lemongrass stalks, sliced galangal, and kaffir lime leaves; simmer for 10 minutes to infuse the aromatics and turn the broth deeply fragrant. Stir in the tom yum paste (if using), halved chillies, and sliced mushrooms; cook for 3–4 minutes, until the mushrooms soften slightly. Add the prawns and cook for exactly 2–3 minutes — they should turn pink and curl; do not overcook or they will become rubbery. Take the pot off the heat; stir in 3 tbsp fish sauce, 2 tbsp fresh lime juice, and 1 tbsp palm sugar. Taste and adjust the balance: the soup should be sour, salty, spicy, and lightly sweet all at once; add more lime for sharpness or more fish sauce for salt. Serve immediately in deep bowls, scattered with spring onion and fresh coriander; the lemongrass, galangal, and lime leaves are aromatics and are not meant to be eaten."}},{"id":113,"origin":{"zh":"阿根廷","en":"Argentina","ro":"Argentina"},"name":{"zh":"阿根廷炸牛排","en":"Milanesa","ro":"Milanesa"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"zh":["4片薄牛肉（上后腿或西冷），每片约150克","2个大鸡蛋","2瓣大蒜，切末","20克新鲜欧芹，切碎","150克干面包糠（用panko可获得更轻盈的外壳）","100克普通面粉","1茶匙盐","1/2茶匙现磨黑胡椒","500毫升植物油，用于油炸","1个柠檬，切角，搭配食用"],"en":["4 thin beef steaks (top round or sirloin), about 150g each","2 large eggs","2 garlic cloves, finely minced","20g fresh parsley, finely chopped","150g dried breadcrumbs (panko works for a lighter crust)","100g plain flour","1 tsp salt","1/2 tsp freshly ground black pepper","500ml vegetable oil, for frying","1 lemon, cut into wedges, to serve"],"ro":["4 felii subțiri de vită (vrăbioară sau pulpă), aproximativ 150g fiecare","2 ouă mari","2 căței de usturoi, tocați fin","20g pătrunjel proaspăt, tocat","150g pesmet uscat (eventual panko pentru o crustă mai aerată)","100g făină simplă","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","500ml ulei vegetal, pentru prăjit","1 lămâie, tăiată felii, pentru servit"]},"howIsMade":{"zh":"牛肉片夹在两张保鲜膜之间，用肉锤拍至5毫米厚、两面均匀撒上一半的盐和胡椒。鸡蛋打入浅碗，加入蒜末、欧芹末和余下的盐与胡椒。准备两个浅盘：一个装面粉、另一个装面包糠、裹粉顺序：面粉 → 蛋液 → 面包糠。每片肉先沾面粉抖掉多余的，再蘸蛋液（让多余蛋液滴落2秒），最后两面按入面包糠，确保面包糠完全覆盖肉。沾好的肉片放在网架上静置10分钟，让面衣更服帖。大平底锅中加热1厘米深的油至175°C（用温度计，或扔入一块小面包测试，应30秒变金黄）。一次煎1–2片，每面煎2分钟至外壳深金黄、内里鲜嫩、捞出放在烤盘上的网架上沥油（不要放纸上——会软）。立即上桌，配柠檬角在咬下之前挤汁于外壳上。","en":"Place the beef slices between two sheets of cling film; pound with a meat mallet until 5 mm thick; season with half the salt and pepper on both sides. Beat the eggs in a wide shallow bowl with the minced garlic, parsley, and the remaining salt and pepper. Set up two shallow plates: one with the flour, one with the breadcrumbs; breading line: flour → beaten egg → breadcrumbs. Dip each slice in flour, shaking off the excess, then in the egg mixture (let it drip for 2 seconds), then press into the breadcrumbs on both sides; the crumbs should fully coat the meat. Let the breaded slices rest on a wire rack for 10 minutes — the breading adheres better this way. Heat 1 cm of oil in a large frying pan to 175°C (use a thermometer or test with a bread cube — it should brown in 30 seconds). Fry the slices one or two at a time for 2 minutes per side, until the crust is deep golden and the meat is tender; drain on a rack over a tray (not on paper — it steams the crust). Serve immediately with lemon wedges to squeeze over the crust just before eating."}},{"id":114,"origin":{"zh":"柬埔寨","en":"Cambodia","ro":"Cambodgia"},"name":{"zh":"柬埔寨牛肉","en":"Lok Lak","ro":"Lok Lak"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"vietnamese","ingredients":{"zh":["牛里脊或西冷600克，切2.5厘米方块","蚝油3汤匙","酱油2汤匙","棕榈糖1汤匙（或红糖）","番茄酱1汤匙","大蒜6瓣，切末","现磨黑胡椒2茶匙（足量）","植物油3汤匙","1个大洋葱，切薄片","鸡蛋4个（煎蛋用）","1棵小生菜（结球生菜或罗马），叶子分开","番茄2个，切片","黄瓜1根，切片","蘸料：","青柠2个的汁","粗盐1茶匙","现磨黑胡椒1/2茶匙","蒸米饭，搭配食用"],"en":["600g beef tenderloin or sirloin, cut into 2.5 cm cubes","3 tbsp oyster sauce","2 tbsp soy sauce","1 tbsp palm sugar (or brown sugar)","1 tbsp tomato paste","6 garlic cloves, minced","2 tsp freshly ground black pepper (generous)","3 tbsp vegetable oil","1 large onion, thinly sliced","4 eggs (for frying)","1 small head of lettuce (iceberg or romaine), leaves separated","2 tomatoes, sliced","1 cucumber, sliced","For the dipping sauce:","juice of 2 limes","1 tsp coarse salt","1/2 tsp freshly ground black pepper","steamed rice, to serve"],"ro":["600g vrăbioară sau mușchi de vită, tăiată cuburi de 2,5 cm","3 linguri sos de stridii","2 linguri sos de soia","1 lingură zahăr de palmier (sau zahăr brun)","1 lingură pastă de roșii","6 căței de usturoi, tocați","2 lingurițe piper negru proaspăt măcinat (din belșug)","3 linguri ulei vegetal","1 ceapă mare, tăiată felii subțiri","4 ouă (pentru ochiuri)","1 cap mic de salată verde (iceberg sau romană), frunzele separate","2 roșii, feliate","1 castravete, feliat","Pentru sos:","zeama de la 2 lime","1 linguriță sare grunjoasă","1/2 linguriță piper negru proaspăt măcinat","orez fiert, pentru servit"]},"howIsMade":{"zh":"大碗中将牛肉与蚝油、酱油、棕榈糖、番茄酱、一半蒜末和1茶匙黑胡椒混合、室温下腌制30分钟。制作蘸料：小碗中混合青柠汁、粗盐和剩余的黑胡椒。摆盘：大盘子上铺好生菜叶、番茄片和黄瓜片。平底锅加少许油，煎4个鸡蛋，保留半流心蛋黄、盛出放温盘备用。大炒锅中加热3汤匙油至冒烟。加入洋葱片和剩余蒜末，翻炒30秒至香气出来。把腌好的牛肉单层倒入锅中，先不动1分钟让一面焦化，然后大火快速翻炒2分钟、牛肉应该外焦内粉嫩——不要煮过头。将热牛肉盛在生菜盘上，每份配一个煎蛋、立即与青柠蘸料和米饭一起上桌，每人一碗饭。","en":"In a bowl, combine the beef with oyster sauce, soy sauce, palm sugar, tomato paste, half the garlic, and 1 tsp black pepper; let it marinate at room temperature for 30 minutes. Make the dipping sauce: stir lime juice, coarse salt, and the remaining pepper in a small bowl; set aside. Arrange the serving platter: lettuce leaves, tomato slices, and cucumber slices laid out on a large platter. Fry 4 eggs in a pan with a little oil, leaving the yolks runny; set them aside on a warm plate. Heat 3 tbsp oil in a large wok over very high heat until it just begins to smoke. Add the sliced onion and remaining garlic, stir-fry for 30 seconds, until fragrant. Add the marinated beef in a single layer; leave it untouched for 1 minute to sear, then stir-fry vigorously for 2 more minutes; the beef should be charred outside and pink inside — do not overcook. Spoon the hot beef over the salad platter, place a fried egg on each portion; serve immediately with the lime dipping sauce alongside and steamed rice for each diner."}},{"id":115,"origin":{"zh":"乌兹别克斯坦","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"zh":"乌兹别克馄饨","en":"Manti","ro":"Manti"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["面团：","500克通用面粉","250毫升温水","1个鸡蛋","1茶匙盐","馅料：","600克牛肉或羊肉，刀切粗末（不要用绞肉机）","3个大洋葱，细切碎（洋葱与肉体积比1:1 — 关键）","1茶匙孜然粉","1茶匙现磨黑胡椒","2茶匙盐","100克羊尾油或腌培根切小丁（可选，传统）","搭配：","100克黄油","200克全脂酸奶（或酸奶油）","1汤匙甜红椒粉","新鲜香菜或欧芹，切碎"],"en":["For the dough:","500g all-purpose flour","250ml warm water","1 egg","1 tsp salt","For the filling:","600g coarsely chopped beef or lamb (knife-cut, not ground)","3 large onions, finely chopped (use a 1:1 onion-to-meat ratio by volume — essential)","1 tsp ground cumin","1 tsp freshly ground black pepper","2 tsp salt","100g lamb-tail fat or pork lardons in tiny cubes (optional, traditional)","To serve:","100g butter","200g full-fat yogurt (or sour cream)","1 tbsp sweet paprika","fresh coriander or parsley leaves, chopped"],"ro":["Pentru aluat:","500g făină","250ml apă caldă","1 ou","1 linguriță sare","Pentru umplutură:","600g carne tocată grosier de vită sau miel","3 cepe mari, tăiate fin (foarte importantă proporția 1:1 cu carnea după volum)","1 linguriță chimion măcinat","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare","100g grăsime de coadă de oaie sau slănină tăiată cuburi mici (opțional, dar tradițional)","Pentru servit:","100g unt","200g iaurt gras (sau smântână)","1 lingură boia dulce","frunze de coriandru sau pătrunjel proaspăt, tocate"]},"howIsMade":{"zh":"制作面团：大碗中将面粉和盐混合、鸡蛋与温水打散后倒入面粉中、揉10分钟至面团光滑有弹性、盖上保鲜膜静置30分钟。制作馅料：将刀切肉、洋葱、孜然、盐、胡椒和羊尾油（如使用）混合、用手拌匀、洋葱会出水——保留在馅中。面团分成4份、每份擀得尽可能薄（1–2毫米）、切成10x10厘米的正方形。每个正方形中央放一大勺馅料、提起面皮的四个角覆盖馅料，在顶部捏合，然后将四条侧边逐一捏紧，形成密封的小包。蒸笼刷油、将manti单层排列，互不接触（蒸熟时会膨胀）。中火蒸35–40分钟，水保持沸腾、面皮变得半透明、略带光泽即熟。小锅中融化黄油，加入甜红椒粉搅匀、离火静置1分钟。将manti装入大盘，撒上欧芹，淋上红椒黄油、配酸奶单独装小碗一起上桌。","en":"Make the dough: in a large bowl, combine the flour with salt; beat the egg with warm water and pour over the flour; knead for 10 minutes until smooth and elastic; cover with cling film and rest for 30 minutes. Make the filling: combine the knife-cut meat, onions, cumin, salt, pepper, and lamb-tail fat (if using); mix by hand until uniform; the onions will release liquid — keep it in. Divide the dough into 4 pieces; roll each as thin as possible (1–2 mm); cut into 10x10 cm squares. Place a generous tablespoon of filling in the centre of each square; lift the four corners of the dough up over the filling and pinch them together at the top, then pinch the four side edges closed to form a sealed parcel. Brush a steamer basket with oil; arrange the manti in a single layer, not touching (they will swell as they cook). Steam for 35–40 minutes over medium heat with the water at a steady boil; the dough should become translucent and slightly glossy when done. Melt the butter in a small saucepan, stir in the sweet paprika; let it rest 1 minute off the heat. Arrange the manti on a large platter, scatter with chopped parsley, and spoon the paprika butter over the top; serve with yogurt in a small bowl alongside."}},{"id":116,"origin":{"zh":"格鲁吉亚","en":"Georgia","ro":"Georgia"},"name":{"zh":"格鲁吉亚炖鸡","en":"Chakhokhbili","ro":"Chakhokhbili"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["1.2公斤带骨鸡腿和鸡小腿","4个大洋葱（约600克），切薄片——传统上洋葱与鸡肉的重量比为1:1","6个成熟番茄（约700克），去皮粗切","1个红甜椒，去籽切丁","6瓣大蒜，切末","2汤匙番茄酱","1茶匙khmeli-suneli（格鲁吉亚混合香料）","1/2茶匙磨碎的蓝葫芦巴（utskho suneli）","1茶匙干风轮菜或牛至","30克新鲜香菜，叶和茎分开切碎","20克新鲜欧芹，切碎","1茶匙盐","现磨黑胡椒","1汤匙白葡萄酒醋（可选，提鲜）","格鲁吉亚薄饼或乡村面包，搭配食用"],"en":["1.2kg bone-in chicken thighs and drumsticks","4 large onions (about 600g), thinly sliced — a 1:1 onion-to-chicken ratio by weight is traditional","6 ripe tomatoes (about 700g), peeled and roughly chopped","1 red bell pepper, deseeded and diced","6 garlic cloves, minced","2 tbsp tomato paste","1 tsp khmeli-suneli (Georgian spice blend)","1/2 tsp ground blue fenugreek (utskho suneli)","1 tsp dried savory or marjoram","30g fresh coriander, leaves and stems separated, both chopped","20g fresh parsley, chopped","1 tsp salt","freshly ground black pepper","1 tbsp white wine vinegar (optional, for brightness)","Georgian flatbread or any sturdy bread, to serve"],"ro":["1,2kg pulpe de pui cu os (pulpe superioare și ciocănele)","4 cepe mari (aproximativ 600g), feliate subțire — raportul 1:1 ceapă:pui după greutate este tradițional","6 roșii coapte (aproximativ 700g), decojite și tăiate grosier","1 ardei kapia roșu, fără semințe, tăiat cuburi","6 căței de usturoi, tocați","2 linguri pastă de roșii","1 linguriță khmeli-suneli (amestec de condimente georgian)","1/2 linguriță schinduf albastru măcinat (utskho suneli)","1 linguriță cimbru de iarnă uscat (sau maghiran)","30g coriandru proaspăt, frunze și tulpini separate, ambele tocate","20g pătrunjel proaspăt, tocat","1 linguriță sare","piper negru proaspăt măcinat","1 lingură oțet de vin alb (opțional, pentru prospețime)","pâine georgiană sau alt tip de pâine rustică, pentru servit"]},"howIsMade":{"zh":"厚底锅干烧至中大火，不放油、鸡块带皮一面朝下排入锅中，每面煎6–8分钟至深金黄色、鸡肉自身的油会渗出——这是定义chakhokhbili的干煸步骤。将鸡块取出放盘中、锅内应残留3–4汤匙油脂，保留备用。将洋葱片倒入锅中、中火翻炒12–15分钟，至深金黄软糯。加入红甜椒、一半蒜末、香菜茎、khmeli-suneli、蓝葫芦巴和干风轮菜、炒2分钟至香气四溢。加番茄酱再炒2分钟至颜色变深、加入切碎的番茄，并将鸡块连同肉汁倒回锅中。转小火盖盖炖35–45分钟，中途翻一次鸡块、鸡肉应该即将脱骨，番茄化成浓稠光亮的酱汁。打开盖子，若酱汁需要再收稠，敞口再煮5分钟、加入剩余蒜末、白醋（如使用）和大部分切碎的香菜和欧芹。试味，用盐和胡椒调整、盛入浅碗中趁热享用，配格鲁吉亚薄饼（或任何耐嚼的面包）蘸汁、剩余香草撒在上面。","en":"Heat a heavy dry pot over medium-high heat — no oil; lay the chicken pieces skin-side down and cook for 6–8 minutes per side, until deeply golden; the chicken renders its own fat — this is the dry-brown step that defines chakhokhbili. Lift the chicken onto a plate; the pot should hold 3–4 tbsp of rendered fat — keep it. Add the sliced onions to the rendered fat; cook over medium heat for 12–15 minutes, stirring often, until deeply golden and soft. Stir in the bell pepper, half the garlic, the chopped coriander stems, khmeli-suneli, blue fenugreek, and savory; cook 2 minutes, until fragrant. Add the tomato paste and cook 2 more minutes, until it darkens; add the chopped tomatoes and return the chicken with its juices to the pot. Reduce the heat to low, cover, and braise for 35–45 minutes, turning the chicken once halfway; the chicken should be falling off the bone and the tomatoes broken down into a thick, glossy sauce. Lift the lid and simmer uncovered 5 more minutes to thicken the sauce if needed; stir in the remaining garlic, the vinegar (if using), and most of the chopped coriander leaves and parsley. Taste, adjust salt and pepper; serve hot in shallow bowls with Georgian flatbread (or any sturdy bread) to mop up the sauce; scatter the remaining herbs on top."}},{"id":117,"origin":{"zh":"秘鲁","en":"Peru","ro":"Peru"},"name":{"zh":"秘鲁牛肉炒薯条","en":"Lomo Saltado","ro":"Lomo Saltado"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"zh":["600克牛里脊或西冷，切1厘米厚的条","3个大土豆（约700克），切粗薯条","1个大红洋葱，切1厘米厚的瓣","2个中等罗马番茄，切瓣（或厚片）","1个黄色ají amarillo辣椒（或1个红甜椒+1茶匙ají amarillo酱）","4瓣大蒜，切末","2汤匙新鲜生姜，磨碎","3汤匙酱油","2汤匙红酒醋","30克新鲜香菜，粗切","3汤匙植物油（另备500毫升炸薯条用）","1茶匙盐","1/2茶匙现磨黑胡椒","400克白色巴斯马蒂米，煮好","1个青柠，切瓣（可选）"],"en":["600g beef sirloin or tenderloin, cut into 1 cm strips","3 large potatoes (about 700g), cut into thick fries","1 large red onion, cut into 1 cm-thick wedges","2 medium Roma tomatoes, cut into wedges (or thick slices)","1 yellow ají amarillo pepper (or 1 red bell pepper + 1 tsp ají amarillo paste)","4 garlic cloves, minced","2 tbsp fresh ginger, grated","3 tbsp soy sauce","2 tbsp red wine vinegar","30g fresh coriander, roughly chopped","3 tbsp vegetable oil (plus 500ml for frying potatoes)","1 tsp salt","1/2 tsp freshly ground black pepper","400g white basmati rice, cooked","1 lime, cut into wedges (optional)"],"ro":["600g vrăbioară sau mușchi de vită, tăiată fâșii de 1 cm grosime","3 cartofi mari (aproximativ 700g), tăiați cartofi prăjiți groși","1 ceapă roșie mare, feliată în pene groase de 1 cm","2 roșii Roma medii, tăiate sferturi (sau felii groase)","1 ardei aji amarillo galben (sau 1 ardei kapia + 1 linguriță pastă aji amarillo)","4 căței de usturoi, tocați","2 linguri ghimbir proaspăt, ras","3 linguri sos de soia","2 linguri oțet de vin roșu","30g coriandru proaspăt, tocat grosier","3 linguri ulei vegetal (plus 500ml pentru cartofi)","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","400g orez basmati alb, gătit","1 lime, tăiat felii (opțional)"]},"howIsMade":{"zh":"牛肉条用盐和胡椒调味，室温下静置10分钟——大火时更易上色。深锅中加热500毫升油至175°C、土豆条入锅炸6–7分钟至金黄酥脆，捞出沥油，趁热撒少许盐。大炒锅或铸铁锅大火加热，加2汤匙植物油至冒微烟、这是关键一步：锅必须很热才能产生秘鲁式的wok hei镬气。牛肉单层下锅，先不动30秒让一面焦化，再大火快速翻炒90秒——牛肉外焦内粉嫩、盛出待用。同锅加1汤匙油、下洋葱瓣和ají amarillo辣椒，翻炒90秒——洋葱要保持脆度，不可炒软。加入蒜末和姜末翻炒30秒至香、加入番茄翻炒1分钟——番茄稍软但不可化掉。沿锅边淋入酱油和红酒醋（会蒸发产生芳香烟气）、倒回牛肉连汁和炸薯条、猛火翻炒30秒，让所有食材均匀挂汁。关火，撒上切碎的香菜，翻拌一次、立即配热米饭，旁边附青柠角上桌。","en":"Season the beef strips with salt and pepper; let them rest for 10 minutes at room temperature — they will sear better at high heat. Heat 500ml of oil in a deep pan to 175°C; fry the potatoes for 6–7 minutes until golden and crisp; drain on a rack and salt lightly while hot. Heat a large wok or cast-iron pan over very high heat with 2 tbsp of vegetable oil — the oil should just begin to smoke; this is the critical step: the pan must be very hot for the Peruvian \"wok hei\" effect. Add the beef in a single layer; leave untouched for 30 seconds to sear, then stir-fry vigorously for 90 seconds — the beef should be browned outside but still pink in the centre; lift onto a plate. In the same wok, add 1 tbsp more oil; stir-fry the onion wedges and ají amarillo for 90 seconds — the onion should stay crisp, not soft. Add the garlic and ginger, stir-fry for 30 seconds until fragrant; add the tomatoes and cook for 1 minute — they should soften slightly but not break down. Pour the soy sauce and red wine vinegar around the edge of the pan (they will steam and create aromatic smoke); return the beef with its juices and add the fries; toss vigorously for 30 seconds, until everything is coated. Turn off the heat, scatter the chopped coriander, and toss once; serve immediately over warm basmati rice with lime wedges on the side."}},{"id":118,"origin":{"zh":"摩洛哥","en":"Morocco","ro":"Maroc"},"name":{"zh":"鸡肉塔吉锅","en":"Chicken Tagine","ro":"Chicken Tagine"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"zh":["1.2 公斤带骨带皮鸡腿（约 8 块），去除多余的皮","2 个大黄洋葱（~400 克），一个磨细用于腌料，一个切薄片用作炖菜底料","6 瓣大蒜，切碎","4 厘米鲜姜，磨细","1 茶匙孜然 + 1 茶匙姜粉 + 1 茶匙香菜籽粉 + 0.5 茶匙姜黄 + 0.5 茶匙甜辣椒粉 + 0.5 茶匙白胡椒 + 一大撮藏红花丝（8-10 根，用 2 汤匙热水浸泡）","1 小把新鲜香菜叶，约 25 克，切细（一半用于腌料，一半用于装饰）","1 小把欧芹叶，约 25 克，切细（一半用于腌料，一半用于装饰）","1.5 茶匙盐 + 0.5 茶匙现磨黑胡椒","3 汤匙橄榄油 + 1 汤匙无盐黄油（或 smen 摩洛哥发酵黄油，最传统）","2 个腌柠檬，洗净，去除果肉，皮切细条（共约 80 克皮）","150 克摩洛哥绿橄榄（或 Castelvetrano 品种），洗净，较大的去核","400 毫升热水或低盐鸡汤","半个鲜柠檬的汁（最后加入，增鲜）","上桌：温热的摩洛哥薄饼 khobz 用来蘸酱汁，或蒸古斯米"],"en":["1.2 kg bone-in skin-on chicken thighs (about 8 pieces), trimmed of excess skin","2 large yellow onions (~400 g), one finely grated for the marinade, one thinly sliced for the stew base","6 garlic cloves, minced","4 cm fresh ginger, finely grated","1 tsp ground cumin + 1 tsp ground ginger + 1 tsp ground coriander + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground white pepper + a generous pinch of saffron threads (8-10 strands, bloomed in 2 tbsp hot water)","1 small bunch fresh coriander (cilantro), about 25 g, finely chopped (half for the marinade, half for garnish)","1 small bunch flat-leaf parsley, about 25 g, finely chopped (half for the marinade, half for garnish)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","3 tbsp olive oil + 1 tbsp unsalted butter (or smen for the most traditional flavour)","2 preserved lemons, rinsed, flesh discarded, peel cut into thin strips (about 80 g of peel total)","150 g green Moroccan olives (or Castelvetrano), rinsed, pitted if large","400 ml hot water or low-salt chicken stock","Juice of half a fresh lemon (added at the end, to brighten)","To serve: warm khobz flatbread to mop up the sauce, or steamed couscous"],"ro":["1.2 kg pulpe de pui cu os și piele (aproximativ 8 bucăți), curățate de pielea în exces","2 cepe galbene mari (~400 g), una rasă fin pentru marinadă, una tăiată felii subțiri pentru baza tocăniței","6 căței de usturoi, tocați","4 cm ghimbir proaspăt, ras fin","1 linguriță chimion măcinat + 1 linguriță ghimbir măcinat + 1 linguriță coriandru măcinat + 0.5 linguriță turmeric + 0.5 linguriță boia dulce + 0.5 linguriță piper alb măcinat + un vârf generos de șofran (8-10 fire, înflorite în 2 linguri apă fierbinte)","1 legătură mică de coriandru proaspăt (cilantro), ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1 legătură mică de pătrunjel cu frunza lată, ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1.5 linguriță sare + 0.5 linguriță piper negru proaspăt măcinat","3 linguri ulei de măsline + 1 lingură unt nesărat (sau smen pentru aroma cea mai tradițională)","2 lămâi conservate, clătite, pulpa îndepărtată, coaja tăiată fâșii subțiri (aproximativ 80 g de coajă)","150 g măsline verzi marocane (sau Castelvetrano), clătite, fără sâmburi dacă sunt mari","400 ml apă fierbinte sau supă de pui cu puțină sare","Zeama de la jumătate de lămâie proaspătă (adăugată la final, pentru prospețime)","Pentru servit: pâine plată khobz caldă pentru a culege sosul, sau couscous aburit"]},"howIsMade":{"zh":"腌制鸡肉：在一个大碗中混合磨碎的洋葱、大蒜、姜、所有干香料、浸泡好的藏红花及其水、一半切碎的香菜、一半欧芹、1.5 茶匙盐、0.5 茶匙黑胡椒和 1.5 汤匙橄榄油。加入鸡腿，将腌料充分按摩进鸡皮内外。盖好放入冰箱冷藏至少 1 小时；4 小时明显更好，过夜最佳。\n\n煎封并搭建底料：在塔吉锅或厚底深锅中以中火加热剩余的 1.5 汤匙橄榄油和黄油。加入洋葱片炒 8 分钟，期间不断翻搅，直至变软并微微金黄。将洋葱推向一侧，鸡皮朝下放入鸡腿，煎 3-4 分钟至鸡皮深金色，然后翻面。\n\n慢炖：将碗中所有腌料一滴不剩地刮入锅中。倒入 400 毫升热水或鸡汤。烧至小火慢沸，盖上锅盖并将火调至最小。炖煮 30 分钟——锥形锅盖锁住蒸汽，这正是塔吉锅的核心。\n\n加入腌柠檬和橄榄：揭开锅盖，把腌柠檬皮条和绿橄榄分别塞在鸡块周围（不要放在上面）——两者都会释出盐水，因此不要剧烈搅拌。重新盖好再煮 10-15 分钟，直到鸡肉最厚处达到 75 °C，酱汁收至光亮、轻盈，能挂在勺背上。\n\n收尾并上桌：揭盖，将半个鲜柠檬的汁挤在菜肴上，撒上保留的香菜和欧芹。加盐前先尝一下——腌柠檬和橄榄本身就带盐味。直接连塔吉锅一起上桌，搭配温热的摩洛哥薄饼 khobz 蘸酱汁，或搭配蒸古斯米。","en":"MARINATE THE CHICKEN: in a large bowl combine the grated onion, garlic, ginger, all the dry spices, the bloomed saffron with its water, half the chopped coriander, half the parsley, 1.5 tsp salt, 0.5 tsp black pepper and 1.5 tbsp olive oil. Add the chicken thighs and massage the marinade thoroughly into and under the skin. Cover and refrigerate at least 1 hour; 4 hours is markedly better, overnight is best.\n\nSEAR AND BUILD THE BASE: heat the remaining 1.5 tbsp olive oil and the butter in a tagine vessel or wide heavy-bottomed pot over medium heat. Add the sliced onion and cook 8 minutes, stirring, until soft and lightly golden. Push the onions to one side, lay the marinated chicken skin-side down and sear 3-4 minutes until the skin is deep golden, then flip.\n\nSIMMER: scrape every drop of marinade from the bowl into the pot. Pour in the 400 ml hot water or stock. Bring to a gentle simmer, then cover and reduce the heat to its lowest setting. Cook 30 minutes — the conical lid traps the steam that defines a tagine.\n\nADD PRESERVED LEMON AND OLIVES: lift the lid, tuck the preserved-lemon strips and green olives around (not on top of) the chicken — both release brine, so resist the urge to stir vigorously. Re-cover and cook 10-15 minutes more, until the chicken reads 75 °C / 170 °F at the thickest part and the sauce has reduced to a glossy, brothy consistency that coats the back of a spoon.\n\nFINISH AND SERVE: uncover, squeeze the half-lemon juice over the dish, and scatter the reserved coriander and parsley on top. Taste before salting — preserved lemons and olives both contribute salt, so the dish often needs nothing more. Serve straight from the tagine with warm khobz flatbread to mop up the sauce, or alongside steamed couscous."}},{"id":120,"origin":{"zh":"委内瑞拉","en":"Venezuela","ro":"Venezuela"},"name":{"zh":"委内瑞拉玉米饼","en":"Arepa","ro":"Arepa"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"latin","ingredients":{"zh":["面团：","400克harina P.A.N.（预煮白玉米粉）","500毫升温水","1茶匙盐","2汤匙植物油","Reina pepiada（经典鸡肉牛油果馅）：","2个鸡胸（约500克），水煮后撕丝","1个成熟牛油果，切丁","3汤匙蛋黄酱","1汤匙青柠汁","1根青葱，切细","10克新鲜香菜，切碎","盐和胡椒","其他流行馅料：","200克新鲜白奶酪（queso fresco），切片","100克碎牛肉（carne mechada）","煎烤用植物油"],"en":["For the dough:","400g harina P.A.N. (pre-cooked white corn flour)","500ml warm water","1 tsp salt","2 tbsp vegetable oil","For reina pepiada (classic chicken-avocado filling):","2 chicken breasts (about 500g), poached and shredded","1 ripe avocado, diced","3 tbsp mayonnaise","1 tbsp lime juice","1 spring onion, finely sliced","10g fresh coriander, chopped","salt and pepper","Other popular fillings:","200g fresh white cheese (queso fresco), sliced","100g shredded beef (carne mechada)","vegetable oil for griddle"],"ro":["Pentru aluat:","400g harina P.A.N. (făină de porumb pre-fiartă)","500ml apă caldă","1 linguriță sare","2 linguri ulei vegetal","Pentru reina pepiada (umplutura clasică):","2 piepți de pui (aproximativ 500g), fierți și mărunțiți","1 avocado copt, tăiat cuburi","3 linguri maioneză","1 lingură zeamă de lime","1 ceapă verde, tăiată fin","10g coriandru proaspăt, tocat","sare și piper","Alte umpluturi populare:","200g brânză albă proaspătă (queso fresco), feliată","100g carne de vită mărunțită (carne mechada)","ulei vegetal pentru prăjit pe plită"]},"howIsMade":{"zh":"大碗中将500毫升温水与盐和油混合、逐渐加入400克harina P.A.N.，用手或刮刀搅拌。揉3–4分钟，直到面团光滑可塑、盖布静置5分钟——面粉吸水后更易塑形。测试面团：应略微粘手但不生、如果塑形时开裂，再加1汤匙水。分成8个等大的面团（每个约100克）、每个用手掌压成直径8厘米、厚1.5厘米的圆饼，用湿手指抚平边缘。厚底锅或铸铁烤板中火加热，加少许油、放入arepa，每面煎4–5分钟至形成带深色斑点的金黄外皮。移至烤盘，180°C预热烤箱中烤10–15分钟，用手指轻敲发出空响——这就是熟度测试。等arepa静置时，准备reina pepiada：将撕碎的鸡肉与牛油果、蛋黄酱、青柠汁、青葱、香菜、盐和胡椒拌匀。用锋利的刀将每个arepa横向切开（像皮塔口袋），不切断、塞入reina pepiada（或其他馅料）、趁arepa温热外脆时立即上桌。","en":"In a large bowl, combine 500ml warm water with salt and oil; gradually add 400g harina P.A.N., mixing with your hand or a spatula. Knead for 3–4 minutes until the dough is smooth and pliable; cover with a cloth and let it rest for 5 minutes — the flour absorbs the water and the dough becomes easier to shape. Test the dough: it should be slightly sticky but not raw; if it cracks while shaping, add a tablespoon more water. Divide into 8 equal balls (about 100g each); flatten each between your palms into a 8 cm wide, 1.5 cm thick disc, smoothing the edges with damp fingers. Heat a heavy pan or griddle over medium heat with a little oil; add the arepas and cook for 4–5 minutes per side, until a golden crust with darker spots forms. Transfer to a baking tray and finish in a preheated 180°C oven for 10–15 minutes, until they sound hollow when tapped lightly; this is the doneness test. While the arepas rest, make the reina pepiada: mix the shredded chicken with avocado, mayonnaise, lime juice, spring onion, coriander, salt, and pepper. Slice each arepa horizontally with a sharp knife (like a pita pocket), without cutting all the way through; stuff with reina pepiada (or your chosen filling); serve immediately while the arepa is warm and crisp on the outside."}},{"id":121,"origin":{"zh":"芬兰","en":"Finland","ro":"Finlanda"},"name":{"zh":"卡累利阿馅饼","en":"Karelian Pie","ro":"Karjalanpiirakka"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"zh":["面团：","150克黑麦面粉","100克普通白面粉","150毫升冷水","1/2茶匙盐","1汤匙植物油","米饭馅料：","200克圆粒米（布丁米）","1升全脂牛奶","1/2茶匙盐","20克黄油","Muna voi（鸡蛋黄油，传统配料）：","100克软化无盐黄油","2个煮鸡蛋，去壳切碎","1/4茶匙盐","1/4茶匙白胡椒"],"en":["For the dough:","150g rye flour","100g plain white flour","150ml cold water","1/2 tsp salt","1 tbsp vegetable oil","For the rice porridge filling:","200g short-grain rice (pudding rice)","1 litre whole milk","1/2 tsp salt","20g butter","For muna voi (egg butter, classic topping):","100g soft unsalted butter","2 hard-boiled eggs, peeled and finely chopped","1/4 tsp salt","1/4 tsp white pepper"],"ro":["Pentru aluat:","150g făină de secară","100g făină albă","150ml apă rece","1/2 linguriță sare","1 lingură ulei vegetal","Pentru umplutura de orez:","200g orez cu bob rotund (orez pudding)","1 litru lapte integral","1/2 linguriță sare","20g unt","Pentru muna voi (untul de ouă pentru servire):","100g unt moale","2 ouă fierte tari, decojite și tocate fin","1/4 linguriță sare","1/4 linguriță piper alb"]},"howIsMade":{"zh":"制作米粥（可提前一天做）：锅中放200克米和250毫升热水、中火煮8分钟至水分吸收。加入1升牛奶和1/2茶匙盐、小火慢煮，频繁搅拌35–45分钟至米粥非常浓稠奶香、加入20克黄油搅匀，完全放凉。面团：碗中混合黑麦面、白面粉和盐、加入冷水和油，揉5分钟至面团结实而有弹性。面团分成16等份搓成球、在撒了黑麦面的台面上，将每个球擀成极薄椭圆（厚1毫米、长12厘米）。每个椭圆面皮中央放1–2汤匙冷米粥，留2厘米边缘。将长边的面皮折向馅料上方，留出中央米粥外露、用手指捏出特征性的Z字形褶皱——这是传统的卡累利阿手工封口。将派排在铺烘焙纸的烤盘上、250°C预热烤箱烤15–20分钟至边缘金黄。烤的时候做muna voi：将软黄油与切碎的鸡蛋、盐和白胡椒拌匀、派趁温热上桌，在外露的米粥表面慷慨涂抹muna voi。","en":"Make the rice porridge (can be made a day ahead): combine 200g rice with 250ml hot water in a pot; cook 8 minutes over medium heat, until the water is absorbed. Add 1 litre milk and 1/2 tsp salt; simmer over low heat, stirring often, for 35–45 minutes, until the porridge is very creamy and thick; stir in 20g butter and cool completely. For the dough: combine rye flour, white flour, and salt in a bowl; add cold water and oil, knead for 5 minutes until firm but elastic. Divide the dough into 16 equal pieces and roll into balls; on a rye-floured surface, roll each ball into a very thin oval (1 mm thick, 12 cm long). Spoon 1–2 tbsp cold rice porridge into the centre of each oval, leaving a 2 cm border. Lift the dough over the filling on both long sides, leaving the centre exposed; pinch the dough with your fingers to create the characteristic zigzag pleats — this is the traditional Karelian seal. Arrange the pies on a lined baking tray; bake in a preheated 250°C oven for 15–20 minutes, until the edges are golden brown. While the pies bake, make muna voi: mash the soft butter with the chopped eggs, salt, and white pepper; serve the pies warm, generously spread with muna voi over the exposed rice surface."}},{"id":123,"origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"意式豆子面","en":"Pasta e fagioli","ro":"Pasta e fagioli"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"zh":["200克短意面（ditalini、tubetti或orecchiette）","400克罐装博洛蒂豆或白腰豆，沥干（或200克干豆，浸泡一夜后煮熟）","1个大洋葱，细切碎","2根胡萝卜，切小丁","2根芹菜，切小丁","3瓣大蒜，切末","100克意式培根或培根，切丁（可选）","400克罐装碎番茄","2汤匙番茄酱","1片月桂叶","1枝新鲜迷迭香","1枝新鲜百里香","1.2升热鸡汤或蔬菜汤","4汤匙特级初榨橄榄油","1块帕玛森奶酪皮（可选，提味）","盐和现磨黑胡椒","刨碎的帕玛森奶酪和特级初榨橄榄油，搭配上桌"],"en":["200g short pasta (ditalini, tubetti, or orecchiette)","400g canned borlotti or cannellini beans, drained (or 200g dried, soaked overnight and cooked)","1 large onion, finely chopped","2 carrots, finely diced","2 celery stalks, finely diced","3 garlic cloves, minced","100g pancetta or bacon, diced (optional)","400g canned chopped tomatoes","2 tbsp tomato paste","1 bay leaf","1 sprig fresh rosemary","1 sprig fresh thyme","1.2L hot chicken or vegetable stock","4 tbsp extra-virgin olive oil","1 piece Parmigiano rind (optional, for flavour)","salt and freshly ground black pepper","grated Parmigiano and extra-virgin olive oil, to serve"],"ro":["200g paste scurte (ditalini, tubetti sau orecchiette)","400g fasole borlotti sau cannellini din conservă, scurse (sau 200g fasole uscată înmuiată peste noapte și fiartă)","1 ceapă mare, tocată fin","2 morcovi, tăiați cuburi mici","2 tulpini de țelină, tăiate cuburi mici","3 căței de usturoi, tocați","100g pancetta sau bacon, tăiat cuburi (opțional)","400g roșii sfărâmate din conservă","2 linguri pastă de roșii","1 frunză de dafin","1 crenguță de rozmarin proaspăt","1 crenguță de cimbru proaspăt","1,2 litri supă de pui sau legume fierbinte","4 linguri ulei de măsline extravirgin","1 bucată coajă de Parmigiano (opțional, pentru aromă)","sare și piper negru proaspăt măcinat","Parmigiano ras și ulei de măsline extravirgin, pentru servit"]},"howIsMade":{"zh":"厚底大锅中以中火加热3汤匙橄榄油、加入意式培根丁（如使用），煎5分钟至上色出油。加入洋葱、胡萝卜、芹菜和一撮盐、炒10–12分钟至软化微焦——这是意式soffritto，香气基底。加入蒜末、番茄酱、迷迭香和百里香、炒2分钟至番茄酱颜色变深。加入碎番茄、月桂叶和帕玛森奶酪皮（如使用）、中火煮5分钟。一半豆子整粒加入，另一半用叉子或手持打蛋器压成泥后加入（传统口感要求两种）、倒入1.2升热高汤、煮沸。加入意面，中火煮8–10分钟，频繁搅拌至al dente、意面释放淀粉，液体会变浓稠。试味并调整盐量、取出帕玛森奶酪皮、迷迭香和百里香、让汤静置5分钟——它会进一步浓稠成厚重奶香的炖菜。深碗热食、慷慨撒上现磨黑胡椒和大量刨碎帕玛森奶酪，淋上特级初榨橄榄油完成。","en":"In a large heavy-bottomed pot, heat 3 tbsp olive oil over medium heat; add the diced pancetta (if using) and cook for 5 minutes, until browned and the fat has rendered. Add the onion, carrots, celery and a pinch of salt; sauté for 10–12 minutes, until soft and lightly caramelised — this is the soffritto, the aromatic foundation. Stir in the garlic, tomato paste, rosemary, and thyme; cook for 2 minutes, until the paste darkens. Add the chopped tomatoes, bay leaf, and Parmigiano rind (if using); simmer for 5 minutes over medium heat. Add half the beans whole and the other half mashed with a fork or hand whisk (the traditional texture calls for both); pour in 1.2L hot stock; bring to a boil. Add the pasta and cook for 8–10 minutes over medium heat, stirring often, until al dente; the liquid will thicken as the pasta releases starch. Taste and adjust salt; remove the Parmigiano rind, rosemary, and thyme stems; let the soup rest 5 minutes — it will thicken further into a dense, creamy stew. Serve hot in deep bowls; crown with generous fresh black pepper, a heavy drift of grated Parmigiano, and a final drizzle of extra-virgin olive oil."}},{"id":124,"origin":{"zh":"斯里兰卡","en":"Sri Lanka","ro":"Sri Lanka"},"name":{"zh":"斯里兰卡炒饼","en":"Kottu","ro":"Kottu"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"zh":["8张戈达姆巴罗提或帕拉塔（共约640克），切成1厘米宽的细条","600克去骨去皮鸡腿肉，切成1.5厘米的块","5个大鸡蛋，加少许盐打散","2个中等红洋葱（约240克），切薄片","1根大葱韭（约200克），修剪后切薄片并洗净","2根小胡萝卜（约140克），切丝","3个新鲜青辣椒，切薄片（去籽口感更温和）","2汤匙新鲜生姜，细磨","5瓣大蒜，切细末","2茶匙斯里兰卡咖喱粉","1茶匙姜黄粉","2茶匙克什米尔辣椒粉或甜红椒粉","15片新鲜咖喱叶","400毫升温热的鸡肉或椰子咖喱酱","3汤匙酱油","4汤匙椰子油或植物油","1.5茶匙盐，按需调味","2汤匙青柠汁，最后淋入"],"en":["8 godhamba roti or paratha (about 640 g total), thinly sliced into 1 cm-wide strips","600 g boneless, skinless chicken thigh, cut into 1.5 cm pieces","5 large eggs, lightly beaten with a pinch of salt","2 medium red onions (about 240 g), thinly sliced","1 large leek (about 200 g), trimmed, thinly sliced, and washed","2 small carrots (about 140 g), julienned","3 fresh green chillies, finely sliced (seeded for a milder finish)","2 tbsp finely grated fresh ginger","5 garlic cloves, finely chopped","2 tsp Sri Lankan curry powder","1 tsp ground turmeric","2 tsp Kashmiri chilli powder or sweet paprika","15 fresh curry leaves","400 ml warm chicken or coconut curry sauce","3 tbsp soy sauce","4 tbsp coconut or vegetable oil","1.5 tsp salt, plus more to taste","2 tbsp lime juice, to finish"],"ro":["8 lipii godhamba sau paratha (aproximativ 640 g în total), tăiate în fâșii subțiri de 1 cm lățime","600 g pulpă de pui dezosată, fără piele, tăiată în bucăți de 1,5 cm","5 ouă mari, bătute ușor cu un praf de sare","2 cepe roșii medii (aproximativ 240 g), feliate subțire","1 praz mare (aproximativ 200 g), curățat, feliat subțire și spălat","2 morcovi mici (aproximativ 140 g), tăiați julienne","3 ardei iuți verzi proaspeți, feliați subțire (fără semințe pentru un gust mai blând)","2 linguri ghimbir proaspăt, ras fin","5 căței de usturoi, tocați fin","2 lingurițe pudră de curry srilankez","1 linguriță turmeric măcinat","2 lingurițe pudră de ardei iute Kashmiri sau boia dulce","15 frunze de curry proaspete","400 ml sos de curry de pui sau de cocos, cald","3 linguri sos de soia","4 linguri ulei de cocos sau vegetal","1,5 lingurițe sare, plus după gust","2 linguri suc de lime, pentru finisare"]},"howIsMade":{"zh":"大平底锅或炒锅中火至中大火热1汤匙油、鸡肉用0.5茶匙盐和少量咖喱粉调味，下锅炒7–8分钟，期间偶尔翻动，直到表面微金黄、内部刚熟（中心无粉红色）、盛出备用。同锅再加入剩余3汤匙油、油光发亮时下咖喱叶——会噼啪作响5–10秒、下红洋葱片，翻炒3–4分钟至变软、边缘呈半透明但仍保持挺立。加入大葱韭、胡萝卜和青辣椒，翻炒2–3分钟——蔬菜需保持脆嫩，不可炒软。将蔬菜推到锅一侧、空出的位置下姜末和蒜末，炒30秒至飘香但不上色、倒入剩余咖喱粉、姜黄粉和克什米尔辣椒粉，炒20–30秒释放香气。把打散的鸡蛋倒入锅中心，温柔翻炒60–90秒，至蛋液凝固但仍油亮——用锅铲将蛋块切成小块。把鸡肉与切条的罗提一起回锅、整体翻炒1–2分钟，让罗提吸收香料和鸡汁的颜色。沿锅边淋入酱油和热咖喱酱、用两把金属铲（或重木铲背面）剁切式翻拌3–4分钟——不断从堆上切下，让罗提条断成不规则的小碎片并吸入酱汁、最终应呈现油亮、融为一体的状态，而非汤状。尝味，按需加盐、挤入青柠汁，再翻拌一次，趁kottu还冒热气时立即上桌，旁边附额外的一勺咖喱酱。","en":"Heat 1 tbsp of the oil in a large skillet or wok over medium-high heat; season the chicken with 0.5 tsp of the salt and a pinch of the curry powder; cook for 7–8 minutes, stirring occasionally, until lightly golden and just cooked through (no pink in the centre); transfer to a plate. Add the remaining 3 tbsp of oil to the same pan; when shimmering, add the curry leaves — they will crackle for 5–10 seconds; add the sliced red onions and cook for 3–4 minutes until softened and translucent at the edges but still firm. Add the leek, carrots, and green chillies and stir-fry for 2–3 minutes — the vegetables should remain crisp-tender, not soft. Push the vegetables to one side of the pan; add the ginger and garlic to the open space and cook for 30 seconds, until fragrant but not browned; stir in the remaining curry powder, the turmeric, and the Kashmiri chilli powder; toast for 20–30 seconds until aromatic. Pour the beaten eggs into the centre of the pan and gently scramble for 60–90 seconds until set but still glossy — break the curd into small pieces with the spatula. Return the chicken to the pan along with the sliced roti; toss everything together for 1–2 minutes so the roti picks up colour from the spices and chicken juices. Pour the soy sauce and warm curry sauce around the edge of the pan; use two metal spatulas (or the back of a heavy wooden spoon) and chop-and-toss the mixture vigorously for 3–4 minutes — keep cutting through the pile so the roti strips break down into small irregular pieces and soak up the sauce; the mixture should look glossy and unified, not soupy. Taste and add more salt if needed; squeeze over the lime juice, toss once more, and serve immediately while the kottu still steams, with an extra ladle of curry sauce on the side."}},{"id":125,"origin":{"zh":"拉脱维亚","en":"Latvia","ro":"Letonia"},"name":{"zh":"拉脱维亚肉馅面包","en":"Piragi","ro":"Piragi"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"servings":8,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["500克高筋小麦面粉，另备少量撒粉用","250毫升全脂牛奶，温热至38°C","7克1包（2茶匙）速发干酵母","50克细砂糖","1茶匙细海盐","70克无盐黄油，融化后稍稍冷却","1个大鸡蛋，轻轻打散","350克烟熏五花培根（或烟熏speck），切成5毫米小丁","1个大洋葱（约180克），切非常细的末","1汤匙中性油（仅当培根很瘦时使用）","0.5茶匙现磨黑胡椒","1小撮葛缕子籽，轻轻压碎（可选）","1个大蛋黄加1汤匙牛奶打散，用于刷面","海盐片，撒面用（可选）"],"en":["500 g strong white bread flour, plus extra for dusting","250 ml whole milk, gently warmed to 38°C","7 g sachet (2 tsp) instant dry yeast","50 g caster sugar","1 tsp fine sea salt","70 g unsalted butter, melted and slightly cooled","1 large egg, lightly beaten","350 g smoked streaky bacon (or smoked speck), in small 5 mm dice","1 large onion (about 180 g), very finely diced","1 tbsp neutral oil (only if the bacon is very lean)","0.5 tsp freshly ground black pepper","Pinch of caraway seeds, lightly crushed (optional)","1 large egg yolk beaten with 1 tbsp milk, for glazing","Flaky sea salt, for sprinkling (optional)"],"ro":["500 g făină albă de pâine, plus pentru tăvălit","250 ml lapte integral, încălzit ușor la 38°C","1 plic de 7 g (2 lingurițe) drojdie instant uscată","50 g zahăr tos","1 linguriță sare fină de mare","70 g unt nesărat, topit și ușor răcit","1 ou mare, bătut ușor","350 g bacon afumat (sau speck afumat), tăiat cuburi mici de 5 mm","1 ceapă mare (aproximativ 180 g), tocată foarte fin","1 lingură ulei neutru (doar dacă baconul este foarte slab)","0,5 linguriță piper negru proaspăt măcinat","Un vârf de semințe de chimen, ușor zdrobite (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru glazură","Fulgi de sare de mare, pentru presărat (opțional)"]},"howIsMade":{"zh":"将温热的牛奶倒入大碗，把酵母和糖撒在上面，轻轻搅拌、静置5–10分钟，表面出现泡沫——这说明酵母是活的。将融化的黄油、打散的蛋液和盐加入牛奶、倒入面粉，用木勺搅拌至形成毛糙的面团、倒在撒了少量面粉的台面上，揉8–10分钟，直到面团光滑、有弹性、只是微微粘手。将面团整成球形，放入抹了少许油的碗中，盖湿布，在温暖处发酵1小时至1小时15分钟，直到体积翻倍。同时准备馅料、培根丁放入干锅，中火炒5–6分钟，频繁翻动，直到脂肪渗出、边缘刚开始上色，但培根不要炒脆、加入洋葱（培根太瘦时加油），再炒4–5分钟，直到洋葱变透明但不上色、用胡椒粉和葛缕子调味、完全冷却。把发酵好的面团排气，分成24等份（每份约35克）、每份揉成光滑小球，再用擀面杖擀成8厘米长的椭圆形，约4毫米厚。取1茶匙冷馅料放在每个椭圆面饼的一半上，把面团对折盖住馅料，将边缘紧紧捏合密封、轻轻将密封的两端往中间拉，形成经典的新月形，缝口朝下放在烤盘上。将派拉吉排在两张铺烘焙纸的烤盘上，间隔3厘米、轻轻盖上，再发酵20–25分钟，直到明显胀大、同时将烤箱预热至220°C（425°F / 风扇200°C）。表面刷上蛋黄液，按需撒海盐片，烤12–15分钟——当顶部深金黄、接缝牢固封住、底部敲起来发出空响时即为烤好、在网架上冷却5分钟后趁温热端上。","en":"Pour the warm milk into a large bowl, scatter the yeast and sugar over it, and stir lightly; let stand 5–10 minutes until foamy on the surface — this confirms the yeast is alive. Add the melted butter, beaten egg, and salt to the milk; pour in the flour and stir with a wooden spoon until a shaggy dough forms; tip onto a lightly floured surface and knead for 8–10 minutes, until smooth, elastic, and only slightly tacky to the touch. Shape the dough into a ball, place it in a lightly oiled bowl, cover with a damp cloth, and leave to rise in a warm spot for 1 hour to 1 hour 15 minutes, until doubled. Meanwhile, prepare the filling; cook the diced bacon in a dry frying pan over medium heat for 5–6 minutes, stirring often, until the fat has rendered and the edges just begin to colour but the bacon is not crisp; add the onion (and the oil if needed) and cook for another 4–5 minutes, until the onion is translucent but not browned; season with the pepper and caraway; cool completely. Knock back the risen dough and divide it into 24 equal pieces (about 35 g each); roll each piece into a smooth ball, then flatten with a rolling pin into an 8 cm oval, about 4 mm thick. Spoon 1 tsp of cold filling onto one half of each oval, fold the dough over to enclose, and pinch the edges firmly to seal; pull the sealed ends gently toward each other to form the classic crescent shape, with the seam facing down on the tray. Arrange the piragi on two parchment-lined trays, leaving 3 cm between them; cover lightly and let rise for another 20–25 minutes, until visibly puffy; meanwhile heat the oven to 220°C (425°F / fan 200°C). Brush the tops with the egg-yolk glaze, sprinkle with flaky salt if using, and bake for 12–15 minutes — they are ready when the tops are deep golden brown, the seams hold tight, and the bottoms sound hollow when tapped; cool on a rack for 5 minutes and serve warm."}},{"id":126,"origin":{"zh":"越南","en":"Vietnam","ro":"Vietnam"},"name":{"zh":"越南煎饼","en":"Banh Xeo","ro":"Bánh xèo"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"vietnamese","ingredients":{"zh":["250克米粉","30克玉米淀粉","1茶匙姜黄粉","0.5茶匙细海盐，再多备一些给猪肉","1茶匙细砂糖","400毫升全脂椰奶","350毫升冰镇气泡水（或冰镇白水）","4根葱，葱绿切薄片（约30克）","300克猪五花肉或猪肩肉，切5毫米厚的条","300克生剥壳虾（约24只中等大小），去虾线","200克新鲜绿豆芽","1个中等洋葱（约120克），切薄片","60毫升中性油（花生油或植物油），用于煎制","1汤匙鱼露，蘸料nuoc cham再用3汤匙","3汤匙新鲜青柠汁","2汤匙细砂糖（用于nuoc cham）","1瓣大蒜切细末和1根小红辣椒切薄片（用于nuoc cham）","1棵奶油生菜或罗马生菜，分开叶片，另备一大把新鲜香草（薄荷、紫苏、香菜、泰国罗勒）和1根黄瓜切丝，用于上桌"],"en":["250 g rice flour","30 g cornflour (cornstarch)","1 tsp ground turmeric","0.5 tsp fine sea salt, plus more for the pork","1 tsp caster sugar","400 ml full-fat coconut milk","350 ml cold sparkling water (or cold still water)","4 spring onions, green tops finely sliced (about 30 g)","300 g pork belly or shoulder, cut into 5 mm-thick strips","300 g raw peeled prawns (about 24 medium), deveined","200 g fresh mung bean sprouts","1 medium onion (about 120 g), thinly sliced","60 ml neutral oil (peanut or vegetable), for frying","1 tbsp fish sauce, plus 3 tbsp for the nuoc cham","3 tbsp fresh lime juice","2 tbsp caster sugar (for the nuoc cham)","1 garlic clove, finely minced, and 1 small red chilli, finely sliced (for the nuoc cham)","1 head butter lettuce or romaine, leaves separated, plus a large bunch of fresh herbs (mint, perilla, coriander, Thai basil) and 1 cucumber, julienned, to serve"],"ro":["250 g făină de orez","30 g amidon de porumb","1 linguriță turmeric măcinat","0,5 linguriță sare fină de mare, plus în plus pentru carnea de porc","1 linguriță zahăr tos","400 ml lapte de cocos integral","350 ml apă minerală rece (sau apă plată rece)","4 cepe verzi, părțile verzi feliate subțire (aproximativ 30 g)","300 g piept sau pulpă de porc, tăiat fâșii de 5 mm grosime","300 g creveți cruzi decojiți (aproximativ 24 medii), curățați de venă","200 g germeni proaspeți de fasole mung","1 ceapă medie (aproximativ 120 g), feliată subțire","60 ml ulei neutru (de arahide sau vegetal), pentru prăjit","1 lingură sos de pește, plus 3 linguri pentru nuoc cham","3 linguri suc de lime proaspăt","2 linguri zahăr tos (pentru nuoc cham)","1 cățel de usturoi tocat fin și 1 ardei iute roșu mic feliat subțire (pentru nuoc cham)","1 căpățână de salată verde de unt sau romană, frunze separate, plus o legătură mare de ierburi proaspete (mentă, perilla, coriandru, busuioc thailandez) și 1 castravete tăiat julienne, pentru servit"]},"howIsMade":{"zh":"至少提前30分钟准备米糊、在大碗中将米粉、玉米淀粉、姜黄粉、0.5茶匙盐和1茶匙糖搅匀、倒入椰奶和气泡水搅打至顺滑、拌入葱绿、盖好放入冰箱静置至少30分钟（最多4小时）——静置让面粉充分吸水，煎饼更脆。在面糊静置时调好nuoc cham、碗中混合3汤匙鱼露、3汤匙青柠汁、2汤匙糖和4汤匙温水，搅至糖完全溶解、加入蒜末和辣椒、备用。猪肉条用1汤匙鱼露和0.5茶匙黑胡椒拌匀、虾冲洗后拍干、豆芽冲洗后甩干、把生菜、香草和黄瓜摆好上桌。24厘米不粘锅中火至中大火加热、下1茶匙油转匀，加入2–3只虾和一把猪肉条、翻炒60–90秒，虾卷曲变粉、猪肉边缘金黄但中心未全熟即可。搅拌米糊后，舀约100毫升入锅，立即旋转使面糊薄薄铺满锅底并升到锅边一半高、在饼的一半上撒一小把洋葱片。盖盖60秒——蒸汽帮助上层定型、打开锅盖，沿边缘淋1茶匙油，继续煎2–3分钟，至边缘呈深金黄色，用薄铲能轻松整张取出。在猪肉和虾的一半上铺一把豆芽、把另一半空白面饼对折成半月形，滑到温过的盘子上、用剩余面糊、虾、猪肉和豆芽重复操作，应能做4–5个饼。立即上桌，趁还能听到清脆声响时享用、吃法：撕下一块，包入生菜配香草和黄瓜，蘸nuoc cham、卷起时饼应发出清脆响声——若变软，下一张要用更热的锅，倒得更薄。","en":"Make the batter at least 30 minutes ahead; whisk together the rice flour, cornflour, turmeric, 0.5 tsp salt, and 1 tsp sugar in a large bowl; pour in the coconut milk and sparkling water and whisk until smooth; stir in the sliced spring-onion greens; cover and rest in the fridge for at least 30 minutes (up to 4 hours) — the resting hydrates the flour for a crisper crepe. While the batter rests, mix the nuoc cham; stir 3 tbsp fish sauce, 3 tbsp lime juice, 2 tbsp sugar, and 4 tbsp warm water in a bowl until the sugar dissolves; add the minced garlic and sliced chilli; set aside. Toss the pork strips with 1 tbsp fish sauce and 0.5 tsp pepper; rinse and pat dry the prawns; wash the bean sprouts and shake dry; arrange the lettuce, herbs, and cucumber on a serving platter. Heat a 24 cm non-stick pan over medium-high heat; add 1 tsp oil, swirl to coat, then add 2–3 prawns and a handful of pork strips; stir-fry for 60–90 seconds until the prawns curl pink and the pork edges are golden but not fully cooked through. Stir the batter, then ladle about 100 ml into the pan, immediately swirling so the batter coats the base in a thin layer and reaches halfway up the sides; drop a small handful of sliced onion over one half of the crepe. Cover with a lid for 60 seconds — the steam helps cook the top; then uncover, drizzle 1 tsp oil around the edge, and cook for a further 2–3 minutes, until the edges turn deep golden and lift cleanly from the pan with a thin spatula. Pile a handful of bean sprouts onto the half topped with pork and prawns; fold the empty half over to form a half-moon, then slide onto a warmed plate; repeat with the remaining batter, prawns, pork, and bean sprouts; you should get 4–5 crepes. Serve immediately, while the crepes are still loud-crispy; to eat: tear a piece, wrap it in lettuce with herbs and cucumber, and dip into the nuoc cham; the crepe should crackle audibly as it bends — if it goes soft, the next one needs a hotter pan and a slightly thinner pour."}},{"id":127,"origin":{"zh":"秘鲁","en":"Peru","ro":"Peru"},"name":{"zh":"土豆鸡肉沙拉","en":"Causa Limeña","ro":"Causa Limeña"},"category":{"zh":"开胃菜","en":"Appetizer","ro":"Aperitiv"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"zh":["1公斤秘鲁黄色土豆（或Yukon Gold等蜡质黄色土豆），去皮切块","60毫升新鲜青柠汁（约2个青柠）","60毫升中性油（葵花籽油或橄榄油）","2汤匙ají amarillo酱（或1汤匙ají amarillo+1茶匙韩式辣酱作替代）","1.5茶匙细海盐，按需调味","0.5茶匙现磨白胡椒","2罐160克高品质橄榄油浸金枪鱼，沥干（或320克煮熟撕碎的鸡胸肉）","120克优质蛋黄酱","2根葱，切成极细的圈（约20克）","1根小芹菜茎，切细末（约30克，可选）","0.5茶匙细海盐","1个大熟牛油果（约200克），切5毫米厚片，与1茶匙青柠汁拌匀","12颗黑橄榄（botija或Kalamata），对半切去核","2个煮熟的鸡蛋，切半或四等分","新鲜香菜或欧芹小枝"],"en":["1 kg yellow Peruvian potatoes (or Yukon Gold or other waxy yellow potatoes), peeled and cut into chunks","60 ml fresh lime juice (about 2 limes)","60 ml neutral oil (sunflower or olive)","2 tbsp ají amarillo paste (or 1 tbsp ají amarillo + 1 tsp Korean gochujang as substitute)","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground white pepper","2 × 160 g tins of high-quality tuna in olive oil, drained (or 320 g cooked shredded chicken breast)","120 g good mayonnaise","2 spring onions, very finely sliced (about 20 g)","1 small celery stalk, finely diced (about 30 g, optional)","0.5 tsp fine sea salt","1 large ripe avocado (about 200 g), sliced 5 mm thick and tossed with 1 tsp lime juice","12 black olives (botija or kalamata), halved and pitted","2 hard-boiled eggs, halved or quartered","Sprigs of fresh coriander or parsley"],"ro":["1 kg cartofi galbeni peruvieni (sau Yukon Gold ori alți cartofi galbeni cu pastă fermă), curățați și tăiați în bucăți","60 ml suc proaspăt de lime (aproximativ 2 lime)","60 ml ulei neutru (de floarea-soarelui sau de măsline)","2 linguri pastă de ají amarillo (sau 1 lingură ají amarillo + 1 linguriță gochujang ca substitut)","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper alb proaspăt măcinat","2 conserve de 160 g de ton de calitate în ulei de măsline, scurse (sau 320 g piept de pui fiert și mărunțit)","120 g maioneză bună","2 cepe verzi, feliate foarte fin (aproximativ 20 g)","1 tulpină mică de țelină, tocată fin (aproximativ 30 g, opțional)","0,5 linguriță sare fină de mare","1 avocado mare copt (aproximativ 200 g), feliat la 5 mm și amestecat cu 1 linguriță suc de lime","12 măsline negre (botija sau Kalamata), tăiate în două și fără sâmburi","2 ouă fierte tare, tăiate în jumătăți sau sferturi","Crenguțe de coriandru sau pătrunjel proaspăt"]},"howIsMade":{"zh":"把土豆放入加足盐的水中（每升约1汤匙盐），煮18–20分钟，直到刀能毫无阻力插入但土豆不散开、沥水后放在网架上自然蒸发干燥5分钟。趁热将土豆通过土豆压泥器或细滤网过滤到大碗里、加入ají amarillo酱、青柠汁、油、1.5茶匙盐和白胡椒、用手轻轻揉捏2–3分钟——土豆泥应光滑、丝滑、略带弹性，捏起时能保持形状。尝味并按需加盐或青柠汁、盖好让其冷却至室温，然后冷藏20分钟使其稍微凝固。制作馅料、将沥干的金枪鱼（或撕碎的鸡肉）放入碗中、加入蛋黄酱、葱、芹菜（如有）和0.5茶匙盐、轻轻拌匀——保留可见的鱼肉碎块，不要打成顺滑泥糊、冷藏待用。用保鲜膜铺一个22 × 12厘米的吐司模（或18厘米圆形蛋糕圈），保鲜膜要留够边、将三分之一土豆泥压入底部，铺成均匀1.5厘米厚的层，用湿勺背抹平。把一半金枪鱼或鸡肉馅料铺在土豆层上，铺成1厘米厚，四周留5毫米边距、把牛油果片紧密重叠地铺一层在上面、再压入三分之一土豆泥盖住牛油果，铺上剩余馅料，最后再来一层土豆泥。把保鲜膜对折盖上顶部，用手掌或小板用力按压使其紧实、冷藏至少1小时（最长6小时），让分层定形。利用保鲜膜把整块脱模，剥去保鲜膜，用蘸过热水的刀切成8份（每切一次刀子要冲水）、每片上面放半颗橄榄、一块煮蛋和一段香菜枝、切后2小时内冷食。","en":"Boil the potatoes in well-salted water (about 1 tbsp salt per litre) for 18–20 minutes, until a knife slides in with no resistance but the potatoes are not falling apart; drain and leave to steam-dry on a rack for 5 minutes. While still warm, pass the potatoes through a ricer or fine sieve into a wide bowl; add the ají amarillo paste, lime juice, oil, 1.5 tsp salt, and white pepper; knead gently with your hands for 2–3 minutes — the mash should be smooth, silky, and slightly elastic, holding its shape when pinched. Taste and adjust with more salt or lime; cover and let cool to room temperature, then chill for 20 minutes to firm slightly. Make the filling; flake the drained tuna (or shred the chicken) into a bowl; add the mayonnaise, spring onions, celery (if using), and 0.5 tsp salt; fold gently — keep visible flakes of fish rather than a smooth purée; chill until needed. Line a 22 × 12 cm loaf tin (or a round 18 cm cake ring) with cling film, leaving a generous overhang; press one-third of the potato mash into the base in an even 1.5 cm layer, using the back of a damp spoon to smooth. Spread half the tuna or chicken filling over the potato in a 1 cm layer, leaving a 5 mm border; arrange the avocado slices on top in a tight overlapping single layer; press a second third of potato over the avocado, then top with the remaining filling and a final layer of potato. Fold the cling film over the top and press firmly with the flat of your hand or a small board to compact the terrine; refrigerate for at least 1 hour (or up to 6 hours) to set the layers. Lift the terrine out using the cling film, peel back, and slice into 8 generous portions with a hot wet knife (rinse the blade between cuts); top each slice with an olive half, a wedge of hard-boiled egg, and a sprig of coriander; serve cold, within 2 hours of slicing."}},{"id":129,"origin":{"zh":"吉尔吉斯斯坦","en":"Kyrgyzstan","ro":"Kârgâzstan"},"name":{"zh":"吉尔吉斯拌面","en":"Beshbarmak","ro":"Beshbarmak"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["1.2公斤带骨羊肩或牛胸肉（或混合），切成4大块","3升冷水","1汤匙细海盐，按需调味","1个洋葱，对半切开（炖汤用）","1根胡萝卜，对半切开（炖汤用）","2片月桂叶","10粒整粒黑胡椒","400克普通中筋面粉，另备少量撒粉用","2个大鸡蛋","150毫升温水","1茶匙细海盐","2个大洋葱（约350克），对半切并切成细长的半月形片","0.5茶匙现磨黑胡椒","1小撮糖","新鲜莳萝或欧芹，粗切"],"en":["1.2 kg bone-in lamb shoulder or beef brisket (or a mix), cut into 4 large pieces","3 litres cold water","1 tbsp fine sea salt, plus more to taste","1 onion, halved (for the broth)","1 carrot, halved (for the broth)","2 bay leaves","10 whole black peppercorns","400 g plain (all-purpose) flour, plus extra for dusting","2 large eggs","150 ml warm water","1 tsp fine sea salt","2 large onions (about 350 g), halved and thinly sliced into half-moons","0.5 tsp freshly ground black pepper","Pinch of sugar","Fresh dill or parsley, roughly chopped"],"ro":["1,2 kg umăr de miel sau piept de vită cu os (sau un amestec), tăiat în 4 bucăți mari","3 litri apă rece","1 lingură sare fină de mare, plus după gust","1 ceapă, tăiată în două (pentru bulion)","1 morcov, tăiat în două (pentru bulion)","2 frunze de dafin","10 boabe de piper negru întregi","400 g făină albă obișnuită, plus pentru tăvălit","2 ouă mari","150 ml apă caldă","1 linguriță sare fină de mare","2 cepe mari (aproximativ 350 g), tăiate în două și feliate subțire în semilune","0,5 linguriță piper negru proaspăt măcinat","Un vârf de zahăr","Mărar sau pătrunjel proaspăt, tocat grosier"]},"howIsMade":{"zh":"把肉放入大汤锅，加冷水没过，中火慢慢加热至沸腾——慢加热能让肉的鲜味最大限度地溶入汤中、前10分钟仔细撇去灰色浮沫，直到汤面变清。加入1汤匙盐、对半切的洋葱、胡萝卜、月桂叶和黑胡椒粒、火力调到几乎不冒泡的小火（汤面几乎不动），不盖盖子煮2–2.5小时，直到肉用叉子能轻松挑起、骨肉分离。肉炖煮的同时准备面团、在大碗中将面粉和1茶匙盐打匀，中间挖一个井，加入鸡蛋和温水、先用叉子搅拌，然后在撒了面粉的台面上揉8–10分钟，揉至面团结实、光滑、有弹性、盖保鲜膜，室温静置30分钟。把醒好的面团分成4份、一次只擀一份，其他用保鲜膜盖住，在撒了面粉的台面上擀至尽量薄——约1毫米厚、切成约8 × 8厘米的方块（或10 × 5厘米的菱形）、两面多撒面粉防粘，平铺在烤盘上。把肉从汤里捞到砧板上，松松盖一层锡纸醒着、汤汁用细滤网过滤到一个干净锅中，丢掉滤出的炖菜，汤保持微沸。舀500毫升热汤到另一个小锅中、加入切薄片的洋葱和一小撮糖，小火炖5–6分钟——洋葱保持半透明、刚好变软即可，不能炖烂、再拌入0.5茶匙黑胡椒。把过滤好的汤再次煮沸、分批下面片，轻轻搅动防粘，每批煮3–4分钟，到面片浮起且口感弹牙、用漏勺捞出，铺在温过的大盘上。肉块逆纹切成厚片，铺在面片上、慷慨地把洋葱和汤汁淋在肉上、撒上切碎的莳萝，另给每位食客单独盛一杯热清汤，配着面饼喝、趁热立即上桌。","en":"Place the meat in a large stockpot, cover with the cold water, and bring slowly to the boil over medium heat — slow heating draws maximum flavour into the broth; skim the grey foam carefully for the first 10 minutes until the surface runs clear. Add the 1 tbsp salt, halved onion, carrot, bay leaves, and peppercorns; reduce the heat to a bare simmer (the surface should barely move) and cook uncovered for 2–2.5 hours, until the meat is fork-tender and falling from the bone. While the meat simmers, make the dough; whisk the flour and 1 tsp salt in a wide bowl, make a well, and add the eggs and warm water; stir with a fork, then knead on a floured surface for 8–10 minutes until firm, smooth, and elastic; cover with cling film and rest at room temperature for 30 minutes. Divide the rested dough into 4 pieces; working with one piece at a time and keeping the rest covered, roll out as thinly as possible on a floured surface — about 1 mm thick; cut into rough 8 × 8 cm squares (or 10 × 5 cm diamonds); dust generously with flour and lay flat on a tray so they do not stick. Lift the meat out of the broth onto a board, cover loosely with foil, and rest; strain the broth into a clean pot through a fine sieve and discard the boiling vegetables; keep the broth at a gentle simmer. Ladle 500 ml of the hot broth into a separate small pot; add the thinly sliced onions and a pinch of sugar and simmer for 5–6 minutes — the onions should stay translucent and just tender, not collapsed; stir in 0.5 tsp black pepper. Bring the strained broth back to a vigorous boil; drop the dough squares in batches, stir gently to prevent sticking, and cook 3–4 minutes per batch until they float and are al dente; lift out with a slotted spoon onto a warmed serving platter. Slice the meat thickly against the grain and arrange over the noodles; spoon the onions and their broth liberally over the meat; scatter with chopped dill, then ladle a cup of the hot clear broth on the side for each diner to sip between bites; serve immediately while everything is steaming hot."}},{"id":130,"origin":{"zh":"泰国","en":"Thailand","ro":"Thailanda"},"name":{"zh":"椰浆饭","en":"Coconut Rice","ro":"Orez cu lapte de cocos"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"zh":["400克长粒米（泰国茉莉香米或巴斯马蒂米）","400毫升全脂椰奶（1标准罐）","250毫升冷水","1茶匙细海盐","1茶匙细砂糖","2片新鲜班兰叶，打结（或1茶匙班兰精——可选但更传统）","1个小红葱头（约30克），切薄片","1根香茅，轻拍出香（可选，增添东南亚香气）","3厘米青柠皮一条（可选，增加清新感）","1汤匙椰子油或中性油","30克无糖椰丝，轻烤（点缀用）","一小把新鲜香菜叶（点缀用）"],"en":["400 g long-grain rice (Thai jasmine or basmati)","400 ml full-fat coconut milk (1 standard tin)","250 ml cold water","1 tsp fine sea salt","1 tsp caster sugar","2 fresh pandan leaves, tied into a knot (or 1 tsp pandan extract — optional but traditional)","1 small shallot (about 30 g), finely sliced","1 stalk lemongrass, lightly bruised (optional, for Southeast Asian aroma)","3 cm strip lime zest (optional, for brightness)","1 tbsp coconut oil or neutral oil","30 g unsweetened desiccated coconut, lightly toasted (for garnish)","Small handful fresh coriander leaves (for garnish)"],"ro":["400 g orez cu bob lung (jasmine thailandez sau basmati)","400 ml lapte de cocos integral (1 conservă standard)","250 ml apă rece","1 linguriță sare fină de mare","1 linguriță zahăr tos","2 frunze de pandan proaspete, legate în nod (sau 1 linguriță extract de pandan — opțional, dar tradițional)","1 eșalotă mică (aproximativ 30 g), feliată fin","1 tulpină de lemongrass, ușor zdrobită (opțional, pentru aroma sud-est asiatică)","Coajă de lime de 3 cm, fâșie subțire (opțional, pentru prospețime)","1 lingură ulei de cocos sau ulei neutru","30 g cocos rasă neîndulcită, ușor prăjită (pentru garnitură)","Un pumn mic de frunze de coriandru proaspete (pentru garnitură)"]},"howIsMade":{"zh":"把米放入筛中，在冷水下边搅边冲洗约1分钟，直到水几乎清澈、沥净水分、这一步去除表面淀粉，保证米饭粒粒分明。厚底2升锅中以中火加热椰子油、下红葱片，翻炒90秒–2分钟，至变软、边缘微金黄但不上色。倒入沥干的米，搅炒30秒让每粒米裹上油、倒入椰奶和水，加入盐、糖、打结的班兰叶、拍过的香茅和青柠皮。搅一次让盐溶化，开中大火加热至微沸——继续轻轻搅拌约2分钟，防止椰奶粘锅底。转最小火，盖紧锅盖，焖煮12分钟不要搅动、中途不要揭盖——锅内蒸汽是均匀煮熟米饭的关键。关火（保持盖紧），让米饭再焖10分钟——最后的余热蒸汽让米粒干松不粘连。揭盖，取出并丢弃班兰叶、香茅和青柠皮、用叉子轻轻拨松米饭，撒上烤过的椰丝和香菜叶，立即配咖喱、参巴酱或烤鱼上桌。","en":"Rinse the rice thoroughly in a sieve under cold running water for about 1 minute, swirling with your hand, until the water runs almost clear; drain well; this removes surface starch and keeps the grains separate at the end. Heat the coconut oil in a heavy-based 2-litre pan over medium heat; add the sliced shallot and stir-fry for 90 seconds–2 minutes, until softened and lightly golden at the edges but not browned. Add the drained rice to the pan and stir for 30 seconds to coat each grain in oil; pour in the coconut milk and water, then add the salt, sugar, knotted pandan leaves, bruised lemongrass, and lime zest. Stir once to dissolve the salt and bring to a gentle boil over medium-high heat — keep stirring gently for about 2 minutes so the coconut milk does not catch on the base. Lower the heat to the lowest possible setting, cover with a tight-fitting lid, and cook undisturbed for 12 minutes; do not lift the lid — the trapped steam is what cooks the rice evenly. Turn off the heat (leave the pan covered) and rest the rice for 10 minutes — this finishing steam dries the grains and stops them clumping. Lift the lid, remove and discard the pandan, lemongrass, and lime zest; fluff the rice gently with a fork, scatter the toasted desiccated coconut and coriander leaves over the top, and serve immediately alongside curry, sambols, or grilled fish."}},{"id":131,"origin":{"zh":"马来西亚","en":"Malaysia","ro":"Malaezia"},"name":{"zh":"椰浆饭","en":"Nasi lemak","ro":"Nasi lemak"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"zh":["400克长粒茉莉香米","400毫升全脂椰奶","200毫升冷水","1茶匙细海盐","2片新鲜班兰叶打结，加1根拍碎的香茅和3片新鲜生姜薄片（煮饭用）","60克生去皮花生","60克ikan bilis（马来西亚干小鱼）","4个大鸡蛋","1根中等黄瓜（约200克），切成5毫米厚的圆片","10个干红辣椒，热水浸泡15分钟后沥干","4个新鲜红辣椒（温和的）","2个大葱头（约120克），去皮，加3瓣大蒜和一拇指大小的新鲜生姜（15克）","1汤匙belacan（烤虾酱）或1.5茶匙鱼露作替代","2汤匙罗望子膏加4汤匙温水稀释（或3汤匙青柠汁）","2汤匙棕榈糖或深色红糖","1个中等红洋葱（约120克），切薄圈","60毫升加250毫升中性油（60毫升用于sambal，其余用于炸小鱼和花生）","0.5茶匙细海盐用于sambal"],"en":["400 g long-grain jasmine rice","400 ml full-fat coconut milk","200 ml cold water","1 tsp fine sea salt","2 fresh pandan leaves tied into a knot, plus 1 bruised stalk of lemongrass and 3 thin slices of fresh ginger (for the rice)","60 g raw skinless peanuts","60 g ikan bilis (dried Malaysian anchovies)","4 large eggs","1 medium cucumber (about 200 g), sliced into 5 mm rounds","10 dried red chillies, soaked in hot water for 15 minutes and drained","4 fresh red chillies (mild)","2 large shallots (about 120 g), peeled, plus 3 garlic cloves and 1 thumb-sized piece of fresh ginger (15 g)","1 tbsp belacan (toasted shrimp paste), or 1.5 tsp fish sauce as a substitute","2 tbsp tamarind paste mixed with 4 tbsp warm water (or 3 tbsp lime juice)","2 tbsp palm sugar or dark brown sugar","1 medium red onion (about 120 g), sliced into thin rings","60 ml plus 250 ml neutral oil (split: 60 ml for the sambal, the rest for frying anchovies and peanuts)","0.5 tsp fine sea salt for the sambal"],"ro":["400 g orez jasmine cu bob lung","400 ml lapte de cocos integral","200 ml apă rece","1 linguriță sare fină de mare","2 frunze de pandan proaspete, legate în nod, plus 1 tulpină de lemongrass zdrobită și 3 felii subțiri de ghimbir proaspăt (pentru orez)","60 g arahide crude fără pieliță","60 g ikan bilis (anșoa malaezieni uscați)","4 ouă mari","1 castravete mediu (aproximativ 200 g), tăiat rondele de 5 mm","10 ardei iuți roșii uscați, înmuiați în apă fierbinte 15 minute și scurși","4 ardei iuți roșii proaspeți (blânzi)","2 eșalote mari (aproximativ 120 g), decojite, plus 3 căței de usturoi și o bucată de ghimbir cât degetul mare (15 g)","1 lingură belacan (pastă de creveți prăjită) sau 1,5 linguriță sos de pește ca substitut","2 linguri pastă de tamarin amestecată cu 4 linguri apă caldă (sau 3 linguri suc de lime)","2 linguri zahăr de palmier sau zahăr brun închis","1 ceapă roșie medie (aproximativ 120 g), feliată inele subțiri","60 ml plus 250 ml ulei neutru (împărțit: 60 ml pentru sambal, restul pentru prăjit anșoa și arahide)","0,5 linguriță sare fină de mare pentru sambal"]},"howIsMade":{"zh":"米饭：把米放入筛中，在冷水下冲洗1分钟至水几乎清澈，沥干、倒入2升厚底锅中，加入椰奶、水、1茶匙盐、班兰叶、香茅和姜片、中大火加热至微沸，轻搅一次、转最小火，盖紧锅盖，焖煮12分钟不要打开、关火，盖盖再焖10分钟——锅内蒸汽完成熟成并使米粒干松、开盖后取出香料丢弃。煮饭同时炸花生、小锅中加热250毫升油至160°C、下花生炸3–4分钟至浅金色（冷却后会变深），用漏勺捞至厨房纸上，撒少许盐。用纸巾擦干ikan bilis、同锅油中分两批炸，每批60–90秒，中途搅一次，至酥脆且深金色、捞到另一张纸上，油保留。煮蛋：把鸡蛋下入微沸水中，准确煮8分钟使蛋黄凝固（喜欢稍流心煮7分钟）、立刻放入冰水3分钟，剥壳并对半切开。制作sambal酱底、把泡软沥干的干辣椒、新鲜辣椒、葱头、大蒜、15克姜块和belacan放入搅拌机或石臼，加2汤匙保留的油，打成粗酱。大炒锅或宽口锅中火加热60毫升新油、下sambal酱，不停翻炒12–15分钟，直到油从酱边缘渗出，酱呈深砖红色、这一长时间的炒制是去除生味的关键。加入红洋葱圈、罗望子水、棕榈糖和0.5茶匙盐，继续小火煮6–8分钟，直到洋葱变软，sambal呈油亮如酱般的质地，用勺划过锅底能保持清晰的痕迹、尝味并平衡——应当辣、甜、酸、咸大致均衡。装盘：每个盘子上盛一份饭、周围依次摆上半个煮蛋、一大勺sambal、一小堆花生、一小堆酥脆ikan bilis和一扇黄瓜片、吃法是每口饭都从各堆里取少许混合在一起。","en":"Rinse the rice in a sieve under cold running water for 1 minute, until the water runs almost clear, then drain well; put it in a heavy 2-litre pan with the coconut milk, water, 1 tsp salt, pandan, lemongrass, and ginger; bring to a gentle boil over medium-high heat, stirring once; lower the heat to the lowest setting, cover with a tight lid, and cook undisturbed for 12 minutes; turn off the heat and rest, covered, for another 10 minutes — the trapped steam finishes cooking and dries the grains; discard the aromatics before serving. While the rice cooks, fry the peanuts; heat the 250 ml oil in a small pan to 160°C; fry the peanuts for 3–4 minutes until pale gold (they will darken as they cool), then lift onto paper towels with a slotted spoon; salt lightly. Pat the ikan bilis dry; in the same oil, fry them in two batches for 60–90 seconds per batch, stirring once, until crisp and deep gold; lift onto a separate sheet of paper; reserve the oil. Hard-boil the eggs: lower them into gently simmering water and cook for exactly 8 minutes for set yolks (or 7 minutes for slightly jammy); transfer immediately to iced water for 3 minutes, then peel and halve. Make the sambal paste; combine the drained dried chillies, fresh chillies, shallots, garlic, the 15 g ginger piece, and belacan in a blender or mortar with 2 tbsp of the reserved oil and process to a coarse paste. Heat 60 ml fresh oil in a wok or wide pan over medium heat; add the sambal paste and fry, stirring continuously, for 12–15 minutes, until the oil splits out around the edges and the paste turns deep brick-red; this long fry is what kills the raw bite of the aromatics. Stir in the red onion rings, tamarind water, palm sugar, and 0.5 tsp salt; simmer for 6–8 minutes more, until the onions are softened and the sambal has a glossy, jammy texture that holds a clean line when you drag a spoon across the pan; taste and balance — it should be hot, sweet, sour, and savoury in roughly equal measure. To serve: mound a portion of rice on each plate; surround with a hard-boiled egg half, a generous spoonful of sambal, a small heap of peanuts, a small heap of crispy anchovies, and a fan of cucumber slices; eat by mixing small amounts from each pile into each bite."}},{"id":132,"origin":{"zh":"瑞士","en":"Switzerland","ro":"Elveția"},"name":{"zh":"瑞士土豆饼","en":"Rösti","ro":"Rösti"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"zh":["1公斤蜡质土豆（Yukon Gold、Charlotte或类似品种），不去皮","60克无盐黄油，分成两份各30克","2汤匙中性油（葵花籽油或葡萄籽油），分成两份各1汤匙","1茶匙细海盐，按需调味","0.5茶匙现磨黑胡椒","一小撮现磨肉豆蔻（可选，伯恩传统版本）","1个小洋葱（约80克），切成极细的末（可选，常见变体）","60克陈年格鲁耶尔奶酪，粗擦丝（可选，更浓郁）","1汤匙细切新鲜虾夷葱，用于点缀"],"en":["1 kg waxy potatoes (Yukon Gold, Charlotte, or similar), unpeeled","60 g unsalted butter, in two 30 g portions","2 tbsp neutral oil (sunflower or grapeseed), in two 1 tbsp portions","1 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","Pinch of grated nutmeg (optional, traditional in Bernese versions)","1 small onion (about 80 g), very finely diced (optional, common variation)","60 g aged gruyère, coarsely grated (optional, for a richer finish)","1 tbsp finely chopped fresh chives, to garnish"],"ro":["1 kg cartofi cu pastă fermă (Yukon Gold, Charlotte sau similari), necurățați","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru (de floarea-soarelui sau de struguri), împărțit în două porții de 1 lingură","1 linguriță sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","Un vârf de nucșoară rasă (opțional, tradițional în versiunea berneză)","1 ceapă mică (aproximativ 80 g), tăiată foarte fin (opțional, variantă obișnuită)","60 g gruyère maturat, ras grosier (opțional, pentru finisare mai bogată)","1 lingură arpagic proaspăt tocat fin, pentru garnitură"]},"howIsMade":{"zh":"提前一天，把整颗带皮土豆放入加足盐的水中（每升约1汤匙盐），煮8–10分钟——刀插入应有一定阻力，中心还应是生的、沥干后完全冷却、不盖盖子放冰箱过夜，让表面变干、淀粉变实。第二天，把冷土豆剥皮——皮应轻松脱落、用粗孔擦丝器擦成长而均匀的丝，动作要快以免发热。在碗里，用盐、胡椒和肉豆蔻给擦丝的土豆调味，用指尖轻轻拌匀——不要用力压，否则土豆丝会变短。24厘米不粘锅或养好的铸铁锅中火加热1汤匙油和30克黄油，黄油起泡并变成榛子色时，下入切碎的洋葱（如果使用），煎90秒–2分钟，至变软并稍呈金黄。把调好味的土豆丝平铺入锅形成一层，用锅铲背面轻压，形成厚约1.5厘米、直径约22厘米的饼——不要压得太紧，里面的空隙才让中心保持酥松、不要翻动，煎8–10分钟，直到底面深金黄、用锅铲一推就能整块脱离。把平盘扣在锅口上，把rösti翻到盘中，再连烤好的一面朝上滑回锅里、沿边缘补入剩下的30克黄油和1汤匙油，让它们流到饼底、继续煎7–9分钟，直到第二面同样深金黄、中心热透软嫩（小刀插入中心应毫无阻力）。把rösti滑到砧板上，若用格鲁耶尔奶酪，趁热撒上（余温会让奶酪轻微融化），点缀虾夷葱碎，切成4块、立即上桌，可在上面盖一个煎蛋，或配烟熏火腿或Bratwurst香肠。","en":"The day before, parboil the potatoes whole and unpeeled in well-salted water (1 tbsp salt per litre) for 8–10 minutes — a knife should meet some resistance, the centre should still be raw; drain and cool completely; refrigerate uncovered overnight so the surface dries and the starches firm up. The next day, peel the cold potatoes — the skins should slip off easily; grate them on the large holes of a box grater into long, even shreds, working briskly so they do not warm. In a bowl, season the grated potatoes with the salt, pepper, and nutmeg, and toss gently to distribute — use your fingertips, not a heavy hand, so the strands stay long. Heat 1 tbsp oil and 30 g of the butter in a 24 cm non-stick or well-seasoned cast-iron pan over medium heat until the butter foams and just turns nut-brown; add the diced onion (if using) and cook for 90 seconds–2 minutes, until soft and lightly golden. Add the seasoned potato to the pan in one even layer, lightly pressing with the back of a spatula to form a 1.5 cm cake about 22 cm across — do not pack it down hard, the air gaps are what crisp the inside; cook undisturbed for 8–10 minutes, until the underside is deep golden brown and pulls cleanly from the pan when you slide a spatula under it. Hold a flat plate over the pan, invert the rösti onto it, then slide it back into the pan with the cooked side up; add the remaining 30 g butter and 1 tbsp oil around the edges so they run under the cake; cook for a further 7–9 minutes, until the second side is equally deep golden and the centre is hot and tender (a paring knife pushed into the middle should meet no resistance). Slide the rösti onto a board, scatter with the grated gruyère if using (the residual heat will melt it lightly), top with chopped chives, and cut into 4 wedges; serve immediately with a fried egg on top, smoked ham, or Bratwurst."}},{"id":133,"origin":{"zh":"罗马尼亚","en":"Romania","ro":"România"},"name":{"zh":"香肠炖豆","en":"Beans with Sausages","ro":"Fasole cu cârnați"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["500克干白豆（cannellini、navy或希腊大白豆），冷水浸泡过夜","4根烟熏猪肉肠（约500克；例如cârnați Pleșcoi或烟熏波兰肠）","150克烟熏五花培根（kaiser）或烟熏猪排，切2厘米块（可选，增加风味深度）","2个大洋葱（约350克），切细末","2根中等胡萝卜（约200克），切细末","1个中等红甜椒，切细末","4瓣大蒜，切细末","3汤匙番茄膏","200克罐装碎番茄（或2个新鲜番茄擦丝）","3片月桂叶","1茶匙甜红椒粉","0.5茶匙干百里香（或1根新鲜的）","0.5茶匙现磨黑胡椒","1.5茶匙细海盐，按需调味","60毫升葵花籽油（或30克猪油）","1.5–2升水（或无盐鸡高汤，风味更浓）","2汤匙切碎的新鲜莳萝或欧芹，最后撒入","1汤匙白葡萄酒醋（可选，最后平衡味道用）"],"en":["500 g dried white beans (cannellini, navy, or Greek elephant), soaked overnight in cold water","4 smoked pork sausages (about 500 g; e.g. cârnați Pleșcoi or smoked Polish sausage)","150 g smoked bacon (kaiser) or smoked pork ribs, cut into 2 cm pieces (optional, for extra depth)","2 large onions (about 350 g), finely diced","2 medium carrots (about 200 g), finely diced","1 medium red bell pepper, finely diced","4 garlic cloves, finely chopped","3 tbsp tomato paste","200 g canned crushed tomatoes (or 2 fresh tomatoes, grated)","3 bay leaves","1 tsp sweet paprika","0.5 tsp dried thyme (or 1 sprig fresh)","0.5 tsp freshly ground black pepper","1.5 tsp fine sea salt, plus more to taste","60 ml sunflower oil (or 30 g lard)","1.5–2 litres water (or unsalted chicken stock for richer flavour)","2 tbsp finely chopped fresh dill or parsley, to finish","1 tbsp white wine vinegar (optional, to balance at the end)"],"ro":["500 g fasole albă uscată (cannellini, navy sau fasole gigant grecească), înmuiată peste noapte în apă rece","4 cârnați afumați de porc (aproximativ 500 g, ex. cârnați Pleșcoi sau cârnați polonezi afumați)","150 g kaiser afumat sau coaste de porc afumate, tăiate bucăți de 2 cm (opțional, pentru profunzime)","2 cepe mari (aproximativ 350 g), tocate fin","2 morcovi medii (aproximativ 200 g), tocați mărunt","1 ardei kapia roșu mediu, tocat fin","4 căței de usturoi, tocați fin","3 linguri bulion (pastă de roșii)","200 g roșii sfărâmate din conservă (sau 2 roșii proaspete, date pe răzătoare)","3 foi de dafin","1 linguriță boia dulce","0,5 linguriță cimbru uscat (sau 1 crenguță proaspătă)","0,5 linguriță piper negru proaspăt măcinat","1,5 lingurițe sare fină de mare, plus după gust","60 ml ulei de floarea-soarelui (sau 30 g untură)","1,5–2 litri apă (sau supă neagră de pui pentru o aromă mai bogată)","2 linguri mărar sau pătrunjel proaspăt tocat fin, pentru finisare","1 lingură oțet de vin alb (opțional, pentru echilibru la final)"]},"howIsMade":{"zh":"前一晚，把干豆放入大碗中，加入至少2升冷水浸泡8–12小时、豆子大约会胀大一倍，并损失大部分容易产气的糖分。第二天沥水冲洗豆子、放入厚底锅中，加入足以没过豆子5厘米的清水，烧开后开盖煮10分钟、再次沥干——这次快速煮制能去豆腥并缩短最终炖煮时间。把豆子放回锅中，加入1.5升新鲜水（或高汤）、烟熏培根（如果使用）和2片月桂叶、小火煮至微沸，半盖煮50–60分钟——豆子应刚好软嫩但不会散开、此时不要加盐（此阶段加盐会让豆皮变硬）。豆子煮的同时，宽口深锅中火加热油、下切碎的洋葱和一大撮盐，频繁搅动煮8–10分钟，直到变软、边缘金黄、加入胡萝卜和红甜椒再煮5–6分钟，至软化。把蔬菜推到一边，空出位置放大蒜，煸30秒后加入甜红椒粉和百里香——焙20–30秒至飘香、加入番茄膏和碎番茄，边搅边煮3–4分钟，直到番茄颜色变深、油从边缘渗出。把2根烟熏肠切成2厘米的圆片；剩下2根整根留作最后摆盘用、把切好的肠片加入番茄底料，煎2–3分钟以渗出部分油脂。把豆锅及其汤汁倒入番茄底料，加入剩下的月桂叶、1.5茶匙盐和黑胡椒、把整根肠埋入炖菜中、开盖小火煮35–45分钟，偶尔搅动，直到豆子软烂、汤汁收成能挂在勺背的稀薄酱汁、如果太稠就加点水。尝味，按需加盐，使用时加入白葡萄酒醋（少许酸度能提亮烟熏味）、取出整根肠斜切成片、把豆子盛入深碗，每碗上面铺一扇肠片，撒上切碎的莳萝，配腌菜和乡村面包或玉米糊上桌。","en":"The night before, place the dried beans in a large bowl, cover with at least 2 litres of cold water, and leave to soak for 8–12 hours; they will roughly double in size and lose much of the gas-producing sugars. The next day, drain and rinse the beans; put them in a heavy pot with fresh water to cover by 5 cm, bring to a boil, and cook uncovered for 10 minutes; drain again — this first quick boil mellows the beans and shortens the final cooking time. Return the beans to the pot with 1.5 litres of fresh water (or stock), the smoked bacon (if using), and 2 of the bay leaves; bring to a gentle simmer and cook partially covered for 50–60 minutes — the beans should be just tender but not falling apart; do not salt yet (salt at this stage toughens the skins). While the beans simmer, heat the oil in a wide deep pan over medium heat; add the diced onions and a generous pinch of salt and cook for 8–10 minutes, stirring often, until soft and golden brown at the edges; add the carrots and red bell pepper and cook for another 5–6 minutes, until softened. Push the vegetables to one side, add the garlic to the empty space and cook for 30 seconds, then stir in the paprika and thyme — toast for 20–30 seconds until fragrant; add the tomato paste and crushed tomatoes and cook, stirring, for 3–4 minutes, until the tomato is deeper red and the oil splits out around the edges. Slice 2 of the smoked sausages into 2 cm rounds; keep the other 2 whole for the top; add the sliced sausage to the tomato base and cook for 2–3 minutes to render some fat. Tip the bean pot and its liquid into the tomato base, add the remaining bay leaf, the 1.5 tsp salt, and the black pepper; bury the whole sausages in the stew; simmer uncovered for 35–45 minutes, stirring occasionally, until the beans are soft and the liquid has thickened to a thin gravy that coats the back of a spoon; add a splash of water if it tightens too much. Taste, adjust with salt, and add the white wine vinegar if using (a touch of acid brightens the smoke); lift out the whole sausages and slice on the diagonal; ladle the beans into deep bowls, top each with a fan of sausage slices, scatter with chopped dill, and serve with pickles and crusty bread or polenta."}},{"id":134,"origin":{"zh":"匈牙利","en":"Hungary","ro":"Ungaria"},"name":{"zh":"红椒鸡","en":"Chicken Paprikash","ro":"Chicken Paprikash"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["1.5公斤带骨带皮的鸡腿和小腿（约8块）","2个大洋葱（约400克），切细末","3汤匙匈牙利甜红椒粉（Édesnemes，最好来自Kalocsa或Szeged），再加0.5茶匙匈牙利辣红椒粉（可选）","3瓣大蒜，切细末","1个中等红甜椒，切细末","1个中等番茄（约100克），去皮切细末（或2汤匙番茄膏）","60克猪油（或4汤匙中性油）","500毫升不加盐的热鸡高汤或清水","200克全脂酸奶油（脂肪含量至少20%——不要用低脂酸奶油，会分离）","1汤匙中筋面粉","1.5茶匙细海盐，按需调味","0.5茶匙现磨黑胡椒","1茶匙葛缕子籽（可选，部分地区传统）","新鲜莳萝或欧芹切碎，用于点缀"],"en":["1.5 kg bone-in, skin-on chicken thighs and drumsticks (about 8 pieces)","2 large onions (about 400 g), finely diced","3 tbsp sweet Hungarian paprika (Édesnemes, preferably from Kalocsa or Szeged), plus 0.5 tsp hot Hungarian paprika (optional)","3 garlic cloves, finely chopped","1 medium red bell pepper, finely diced","1 medium tomato (about 100 g), peeled and finely diced (or 2 tbsp tomato paste)","60 g lard (or 4 tbsp neutral oil)","500 ml hot unsalted chicken stock or water","200 g full-fat sour cream (at least 20% fat — do NOT use light sour cream, it will split)","1 tbsp plain (all-purpose) flour","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","1 tsp caraway seeds (optional, traditional in some regions)","Fresh dill or parsley, chopped, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","2 cepe mari (aproximativ 400 g), tocate fin","3 linguri paprika dulce maghiară (Édesnemes, de preferință din Kalocsa sau Szeged), plus 0,5 linguriță paprika iute maghiară (opțional)","3 căței de usturoi, tocați fin","1 ardei gras roșu mediu, tăiat cuburi mici","1 roșie medie (aproximativ 100 g), curățată și tăiată cuburi mici (sau 2 linguri pastă de roșii)","60 g untură (sau 4 linguri ulei neutru)","500 ml supă de pui fierbinte nesărată sau apă","200 g smântână grasă (cel puțin 20% grăsime — NU smântână ușoară, se taie)","1 lingură făină albă","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","1 linguriță semințe de chimen (opțional, tradițional în unele regiuni)","Mărar sau pătrunjel proaspăt tocat, pentru garnitură"]},"howIsMade":{"zh":"用厨房纸把鸡肉拍干，两面用1茶匙盐和黑胡椒调味，室温静置15分钟。28厘米厚重的铸铁锅或宽口深锅中火至中大火融化猪油、分两批，鸡皮朝下煎4–5分钟，另一面煎3分钟，至鸡皮深金黄——不要挤满锅子、盛到盘上。火力调到中火，把渗出的油倒掉，只留约3汤匙、加入洋葱和一小撮盐，频繁搅动炒12–15分钟，至洋葱柔软、油亮、完全金黄——这慢炒是paprikash风味的根基。加入大蒜、红甜椒以及葛缕子籽（如使用），再炒2–3分钟至甜椒刚刚变软。把锅完全离火、拌入甜红椒粉（以及辣红椒粉如使用）——红椒粉直接遇热会烧焦变苦，必须离火加入、搅动30秒，直到洋葱被染成深砖红色，香气温暖甜美。把锅放回中火、加入切碎的番茄（或番茄膏），搅1分钟、倒入热高汤和剩余0.5茶匙盐，把鸡肉鸡皮朝上放回酱汁中，烧至微沸。加盖，最小火焖煮35–45分钟，直到鸡肉能轻松脱骨，内部温度达75°C、把鸡肉夹到温过的盘子里，盖上锡纸保温，同时收尾酱汁。把面粉打入酸奶油至顺滑，再舀一勺热酱汁加入调温、离火状态下把调好的奶油倒回锅里搅至丝滑、鸡肉重新放入酱汁中只为加热，尝味调盐，配上nokedli面疙瘩、新鲜面或拌黄油面条上桌，撒上切碎的莳萝。","en":"Pat the chicken dry with paper towels and season both sides with 1 tsp of the salt and the black pepper; rest at room temperature for 15 minutes. Melt the lard in a heavy 28 cm Dutch oven or wide deep pan over medium-high heat; working in two batches, sear the chicken skin-side down for 4–5 minutes, then 3 minutes on the other side, until the skin is deep golden — do not crowd the pan; lift onto a plate. Reduce the heat to medium and pour off all but about 3 tbsp of the rendered fat; add the onions and a pinch of salt and cook for 12–15 minutes, stirring often, until soft, glossy, and fully golden — this slow sweat is the foundation of paprikash flavour. Add the garlic, red bell pepper, and caraway seeds (if using) and cook for another 2–3 minutes, until the pepper is just softened. Take the pan off the heat completely; stir in the sweet paprika (and hot paprika if using) — paprika scorches and turns bitter on direct heat, so the pan must be off when it goes in; stir for 30 seconds until the onions are stained a deep brick red and the spice smells warm and sweet. Return the pan to medium heat; add the diced tomato (or tomato paste) and stir for 1 minute; pour in the hot stock and the remaining 0.5 tsp salt, then nestle the chicken back into the sauce, skin-side up; bring to a gentle simmer. Cover and braise on the lowest heat for 35–45 minutes, until the chicken pulls easily from the bone and the internal temperature reads 75°C; lift the chicken onto a warm plate and tent with foil while you finish the sauce. Whisk the flour into the sour cream until smooth, then whisk in a ladle of the hot pan sauce to temper; off the heat, pour the tempered cream back into the pan and stir until silky; return the chicken to the sauce just to warm through, taste and adjust salt, then serve over nokedli, fresh pasta, or buttered noodles with chopped dill on top."}},{"id":135,"origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"诺尔玛意大利面","en":"Pasta alla Norma","ro":"Pasta alla Norma"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"zh":["2个中等茄子（约700克），不去皮，切成2厘米方块","1.5茶匙细海盐用于盐渍茄子，另加用于煮面的盐","300毫升特级初榨橄榄油用于浅炸茄子","400克rigatoni、penne rigate或maccheroni意面","3汤匙特级初榨橄榄油用于酱汁","3瓣大蒜，切薄片","0.5茶匙干辣椒片（可选）","800克整颗去皮罐装番茄（如有San Marzano），用手压碎，或700克番茄泥（passata）","1茶匙细砂糖（仅当番茄偏酸时）","0.5茶匙现磨黑胡椒","1大把新鲜罗勒（约30克），叶片摘下并撕碎","120克意大利咸味ricotta salata奶酪，细擦丝，另备少量用于上桌","1汤匙粗海盐用于煮面水"],"en":["2 medium aubergines (about 700 g total), unpeeled, cut into 2 cm cubes","1.5 tsp fine sea salt for salting the aubergine, plus more for the pasta water","300 ml extra-virgin olive oil for shallow-frying the aubergine","400 g rigatoni, penne rigate, or maccheroni","3 tbsp extra-virgin olive oil for the sauce","3 garlic cloves, sliced thin","0.5 tsp dried chilli flakes (optional)","800 g whole peeled tomatoes (San Marzano if available), crushed by hand, or 700 g passata","1 tsp caster sugar (only if the tomatoes are sharp)","0.5 tsp freshly ground black pepper","1 large bunch fresh basil (about 30 g), leaves picked and torn","120 g ricotta salata, finely grated, plus more to serve","1 tbsp coarse sea salt for the pasta water"],"ro":["2 vinete medii (aproximativ 700 g în total), necurățate, tăiate cuburi de 2 cm","1,5 lingurițe sare fină de mare pentru asezonarea vinetelor, plus mai multă pentru apa pastelor","300 ml ulei de măsline extravirgin pentru prăjit vinetele","400 g rigatoni, penne rigate sau maccheroni","3 linguri ulei de măsline extravirgin pentru sos","3 căței de usturoi, feliați subțire","0,5 linguriță fulgi de ardei iute uscat (opțional)","800 g roșii întregi, decojite (San Marzano dacă e posibil), zdrobite cu mâna, sau 700 g pasată","1 linguriță zahăr tos (doar dacă roșiile sunt acrișoare)","0,5 linguriță piper negru proaspăt măcinat","1 legătură mare de busuioc proaspăt (aproximativ 30 g), frunzele rupte","120 g ricotta salata, rasă fin, plus în plus pentru servit","1 lingură sare grunjoasă de mare pentru apa pastelor"]},"howIsMade":{"zh":"把茄子块和1.5茶匙细盐放入滤网中，下方放碗接水，静置30分钟——既能排出苦涩水分，也能防止茄子在油炸时吸入过多油、用厨房纸轻压并拍干。在宽口深锅中将300毫升橄榄油加热到170°C、用一颗茄子块测试油温——应迅速冒泡、分三批炸茄子，每批3–4分钟，频繁翻动，至各面深金黄、内部柔软（刀能轻松穿过）、用漏勺捞到厨房纸上沥油、备用。茄子炸的同时，大锅中加4升水和1汤匙粗盐，烧至大滚。宽口炒锅中将3汤匙橄榄油用中火加热、下蒜片和辣椒片（如使用）炒60–90秒——蒜片边缘刚刚变浅金，绝不能上色变深。加入压碎的番茄、糖（如使用）、0.5茶匙盐和黑胡椒、搅匀煮至微沸，12–15分钟，间或搅拌，至酱汁略微浓稠、油上浮表面、最后一分钟拌入一半撕碎的罗勒。把面条丢入沸水，按包装时间减1分钟，煮至al dente、预留250毫升淀粉煮面水，沥干面条。把炸好的茄子拌入番茄酱，再加入沥干的面条、中火大力翻炒1–2分钟，按需加几勺煮面水，让酱汁油亮地包裹每一根面条——倾斜锅子时应能流动，但不能稀薄。离火后撒入一半擦丝ricotta salata和大部分剩余罗勒，翻拌一次、分入四个温过的碗，每碗上面再放更多ricotta salata、剩下的罗勒叶和一些生橄榄油，立即上桌。","en":"Toss the aubergine cubes with the 1.5 tsp fine salt in a colander and leave to drain over a bowl for 30 minutes — this draws out bitter water and stops the aubergine from drinking too much oil during frying; press lightly with a paper towel and pat dry. Heat the 300 ml olive oil in a wide deep frying pan to 170°C; test with a single aubergine cube — it should sizzle briskly; fry the aubergine in three batches for 3–4 minutes per batch, turning often, until deeply golden on all sides and tender inside (a knife should pass through easily); lift onto paper towels with a slotted spoon to drain; reserve. While the aubergine fries, bring a large pot with 4 litres of water and 1 tbsp coarse salt to a rolling boil. In a wide sauté pan, heat the 3 tbsp olive oil over medium heat; add the sliced garlic and chilli flakes (if using) and cook for 60–90 seconds — the garlic should just turn pale gold around the edges, never brown. Add the crushed tomatoes, the sugar (if using), 0.5 tsp salt, and the black pepper; stir and bring to a simmer; cook for 12–15 minutes, stirring occasionally, until the sauce has thickened slightly and the oil rises to the surface; tear in half of the basil for the last minute. Drop the pasta into the boiling water and cook 1 minute less than the package says for al dente; reserve 250 ml of starchy pasta water, then drain. Fold the fried aubergine into the tomato sauce, then add the drained pasta; toss vigorously over medium heat for 1–2 minutes, adding splashes of pasta water as needed, until the sauce clings glossy to every piece — it should be loose enough to flow when you tilt the pan but not watery. Off the heat, scatter half the grated ricotta salata and most of the remaining basil and toss once; divide between four warmed bowls, finish each with more ricotta salata, the last basil leaves, and a drizzle of raw olive oil; serve immediately."}},{"id":137,"origin":{"zh":"土库曼斯坦","en":"Turkmenistan","ro":"Turkmenistan"},"name":{"zh":"土库曼馅饼","en":"Ichlekli","ro":"Ichlekli"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["500克中筋面粉，另备少量擀面用","1茶匙细海盐","240毫升温水","1汤匙中性油（葵花籽油或葡萄籽油）","500克羊肩肉或牛颈肉，细切（或切大块后用搅拌机点动打碎）","100克羊尾脂或牛板油，切细丁（或30克无盐黄油作替代）","2个大洋葱（约350克），切细末","200克蜡质土豆，去皮切成5毫米小丁（可选，但传统做法会用）","1.5茶匙细海盐","1茶匙现磨黑胡椒","1茶匙磨碎的孜然","0.5茶匙磨碎的香菜籽","0.5茶匙干红辣椒片（可选）","1个大蛋黄加1汤匙牛奶打散，刷面用"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","1 tsp fine sea salt","240 ml warm water","1 tbsp neutral oil (sunflower or grapeseed)","500 g lamb shoulder or beef chuck, finely minced (or coarsely diced and pulsed in a processor)","100 g lamb-tail fat or beef suet, finely diced (or 30 g unsalted butter as substitute)","2 large onions (about 350 g), finely diced","200 g waxy potatoes, peeled and diced into 5 mm cubes (optional but traditional)","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground coriander","0.5 tsp dried red pepper flakes (optional)","1 large egg yolk, beaten with 1 tbsp milk, for brushing"],"ro":["500 g făină albă obișnuită, plus pentru întins","1 linguriță sare fină de mare","240 ml apă caldă","1 lingură ulei neutru (de floarea-soarelui sau de struguri)","500 g umăr de miel sau pulpă de vită, tocate fin (sau cuburi mărunte pulsate într-un robot)","100 g grăsime de coadă de miel sau seu de vită, tăiate fin (sau 30 g unt nesărat ca substitut)","2 cepe mari (aproximativ 350 g), tocate fin","200 g cartofi cu pastă fermă, curățați și tăiați cuburi de 5 mm (opțional, dar tradițional)","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță coriandru măcinat","0,5 linguriță fulgi de ardei iute uscat (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru uns"]},"howIsMade":{"zh":"制作面团、在宽口大碗中将面粉和盐打匀，中间挖出一个井，倒入温水和油，用木勺搅拌至形成毛糙的面团、在撒了少量面粉的台面上揉6–8分钟，至光滑、紧实、有弹性——比面包面团略硬、用保鲜膜包好，在室温下静置30分钟，期间准备馅料。在大碗中将肉末、脂肪、洋葱、土豆丁（如使用）、盐、胡椒、孜然、香菜籽粉和辣椒片混合、用手搅拌1分钟，至混合物粘稠且充分结合、不要预先煮——馅料在面团内烤熟。烤箱预热至220°C（425°F / 风扇200°C），将一个厚重烤盘反过来放置或者放一块披萨石在中层架上，至少加热20分钟、这个高温表面会让底部变酥脆。把醒好的面团分成两等份、在撒了少许面粉的台面上，把一份擀成直径32厘米、厚约2毫米的圆盘——边缘要比中心薄，这样封口处不会太厚。将圆盘滑到一张烘焙纸上、把馅料均匀铺在圆盘上，留2厘米的边，轻轻压成1.5厘米厚的一层。把第二份面团擀成同样32厘米的圆盘盖在上面、沿边缘紧紧压合两层面皮，然后把边卷起向内捏成紧实的绳状边，防止汁水渗出。用蛋黄液刷面，并用叉子在中心扎6–8个孔让蒸汽逸出、把派连同烘焙纸滑入烤箱的高温烤盘上，烤30–35分钟，直到表面深金黄、底部敲击有空响。派在砧板上静置5分钟（蒸汽稳定、馅料定形），然后用锋利的刀切成8份、趁热配绿茶、原味酸奶或酸奶喝。","en":"Make the dough; whisk the flour and salt in a wide bowl; make a well, pour in the warm water and oil, and stir with a wooden spoon until a shaggy dough forms; knead on a lightly floured surface for 6–8 minutes until smooth, firm, and elastic — slightly stiffer than bread dough; wrap in cling film and rest at room temperature for 30 minutes while you prepare the filling. In a large bowl, combine the minced lamb, fat, onions, potato cubes (if using), salt, pepper, cumin, coriander, and pepper flakes; mix with your hands for 1 minute until the mixture is sticky and well bound; do not pre-cook — the filling cooks inside the dough. Heat the oven to 220°C (425°F / fan 200°C) and place an upturned heavy baking tray or pizza stone on the middle rack to heat through for at least 20 minutes; the hot surface is what crisps the bottom. Divide the rested dough into two equal pieces; on a lightly floured surface, roll one piece into a 32 cm round, about 2 mm thick — work the edges thinner than the centre so the seal will not be too thick. Slide the round onto a sheet of baking parchment; spread the filling evenly over the disc, leaving a 2 cm border, and press it down lightly into a 1.5 cm layer. Roll out the second piece of dough to the same 32 cm round and lay it on top; press the two layers together firmly around the edge, then roll and pinch the rim inward into a tight rope-like border so no juice can escape. Brush the top with the egg-yolk glaze and prick the centre in 6–8 places with a fork to let steam vent; slide the pie, on its parchment, onto the hot tray in the oven; bake for 30–35 minutes, until the top is deep golden brown and the bottom sounds hollow when you tap it. Rest the pie on a board for 5 minutes (the steam settles and the filling firms up), then cut into 8 wedges with a sharp knife; serve hot with green tea, plain yoghurt, or soured milk."}},{"id":138,"origin":{"zh":"乌克兰","en":"Ukraine","ro":"Ucraina"},"name":{"zh":"基辅鸡排","en":"Chicken Kiev","ro":"Pui Kiev"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["100克无盐黄油，室温软化","3瓣大蒜，切极细末（或1汤匙蒜泥）","30克平叶欧芹，切极细","1汤匙柠檬汁","0.5茶匙细海盐","0.25茶匙现磨黑胡椒","4块大去骨去皮鸡胸肉（每块约200克）","1茶匙细海盐用于鸡胸","0.5茶匙现磨黑胡椒用于鸡胸","80克中筋面粉","2个大鸡蛋，加1汤匙冷水打散","150克panko或细干面包屑","750毫升中性油（葵花籽或菜籽油），用于深炸","1汤匙无盐黄油，为油增香（可选，让外壳有焦黄油风味）","柠檬角和一小束欧芹，配菜用"],"en":["100 g unsalted butter, softened to room temperature","3 garlic cloves, very finely minced (or 1 tbsp garlic paste)","30 g flat-leaf parsley, very finely chopped","1 tbsp lemon juice","0.5 tsp fine sea salt","0.25 tsp freshly ground black pepper","4 large skinless chicken breasts (about 200 g each)","1 tsp fine sea salt for the breasts","0.5 tsp freshly ground black pepper for the breasts","80 g plain (all-purpose) flour","2 large eggs, beaten with 1 tbsp cold water","150 g panko or fine dry breadcrumbs","750 ml neutral oil (sunflower or rapeseed), for deep-frying","1 tbsp unsalted butter, for finishing the oil (optional, for a nuttier crust)","Lemon wedges and a small bunch of parsley, to serve"],"ro":["100 g unt nesărat, înmuiat la temperatura camerei","3 căței de usturoi, tocați foarte fin (sau 1 lingură pastă de usturoi)","30 g pătrunjel cu frunze plate, tocat foarte fin","1 lingură suc de lămâie","0,5 linguriță sare fină de mare","0,25 linguriță piper negru proaspăt măcinat","4 piepți mari de pui dezosați și fără piele (aproximativ 200 g fiecare)","1 linguriță sare fină de mare pentru piepți","0,5 linguriță piper negru proaspăt măcinat pentru piepți","80 g făină albă obișnuită","2 ouă mari, bătute cu 1 lingură apă rece","150 g panko sau pesmet fin uscat","750 ml ulei neutru (de floarea-soarelui sau de rapiță), pentru prăjire adâncă","1 lingură unt nesărat, pentru aromatizarea uleiului (opțional, pentru o crustă cu unt prăjit)","Felii de lămâie și o legătură mică de pătrunjel, pentru servit"]},"howIsMade":{"zh":"制作香草黄油、把软化的黄油放入碗中，加入大蒜末、欧芹末、柠檬汁、0.5茶匙盐和0.25茶匙胡椒，搅打至均匀、把黄油倒在保鲜膜上，整形成12厘米长、2厘米粗的圆柱体，紧紧包好，至少冷冻1小时，让它硬到可以切。把冷冻好的黄油卷切成4等份的小圆柱体、先放回冷冻室，等鸡肉准备好——黄油必须非常冷，否则油炸时会流出。用锋利的刀在每块鸡胸肉厚的一侧切一个深的水平口袋，离对面边缘约1厘米处停止——不要切断、像翻书一样把鸡胸肉打开，放在两张保鲜膜之间，用肉锤轻轻从中心向边缘敲打，敲到5毫米厚度均匀、内部撒1茶匙盐和0.5茶匙胡椒。在每块敲薄的鸡胸肉中央放一个冷的黄油圆柱、把两长边折到黄油上面，然后紧紧卷起鸡胸肉形成封口的圆柱，压出空气、把任何松散的边藏到下面、每个用保鲜膜包起来，冷藏30分钟。准备三个浅碗：一个放面粉、一个放蛋液和水、一个放面包屑、取一卷，先沾面粉抖掉多余，再沾蛋液（沥干），再沾面包屑——四面用力按压、再蘸一次蛋液和面包屑做第二层：这种双层裹粉能防止油炸时黄油喷出、其他三卷照做。把油加热至170°C的深锅中、用一颗面包屑测试——20秒内应噼啪作响并变浅金色、小心地放入两个Kiev，炸6–7分钟，翻一次面，直到整体外壳呈深金黄、捞到放在烤盘上的网架上沥油、剩下的两个重复操作。若需要可在烤箱完成、把炸好的Kiev放在烤盘上的架子上，180°C（350°F）烤8–10分钟，直到温度探针插入鸡肉（不是黄油）显示70°C、这样鸡肉熟透，外壳也不会烤过。在网架上静置2分钟后盛盘、上桌时刺破每个Kiev的顶部——熔化的香草黄油会喷出金色细流、立即配柠檬角和欧芹，搭配土豆泥或黄油米饭。","en":"Make the herb butter; beat the softened butter in a bowl with the minced garlic, chopped parsley, lemon juice, 0.5 tsp salt, and 0.25 tsp pepper until evenly combined; scrape onto cling film, shape into a 12 cm long, 2 cm thick log, wrap tightly, and freeze for at least 1 hour, until firm enough to slice. Slice the chilled butter log into 4 equal cylinders; return them to the freezer while you prepare the chicken — the butter must be very cold or it will leak out during frying. With a sharp knife, cut a deep horizontal pocket into the thick side of each chicken breast, stopping about 1 cm before the opposite edge — do not cut through; open the breast like a book, lay it between two sheets of cling film, and pound gently with a meat mallet to an even 5 mm thickness, working from the centre outwards; season the inside with 1 tsp salt and 0.5 tsp pepper. Place one cold butter cylinder along the centre of each pounded breast; fold the two long sides over the butter, then roll the breast tightly into a sealed cylinder, pressing to expel air; tuck any loose flaps underneath; wrap each parcel in cling film and refrigerate for 30 minutes. Set up three shallow bowls: one with the flour, one with the beaten eggs and water, one with the breadcrumbs; take a parcel, dip in flour and pat off excess, then egg, draining well, then breadcrumbs — press firmly on all sides; dip the egg and breadcrumbs again for a second coat: this double coat is what stops the butter from blowing out during frying; repeat with the other three. Heat the oil in a deep pan to 170°C; test with a breadcrumb — it should sizzle and turn pale gold in 20 seconds; lower two Kievs in carefully and fry for 6–7 minutes, turning once, until the crust is deeply golden brown all over; lift onto a wire rack set over a tray; repeat with the other two. Finish in the oven if needed; place the fried Kievs on a rack over a baking tray and bake at 180°C (350°F) for 8–10 minutes, until a temperature probe pushed into the chicken (not the butter) reads 70°C; this ensures the chicken is cooked through without overcooking the crust. Rest for 2 minutes on the rack, then plate; pierce the top of each Kiev at the table — the molten herb butter will spill out in a golden stream; serve immediately with lemon wedges and parsley, alongside mashed potatoes or buttered rice."}},{"id":139,"origin":{"zh":"立陶宛","en":"Lithuania","ro":"Lituania"},"name":{"zh":"立陶宛土豆团","en":"Cepelinai","ro":"Cepelinai"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["1.5公斤生蜡质土豆（Yukon Gold或类似品种），去皮后称重","500克粉质土豆（Russet或King Edward），去皮后称重","1汤匙柠檬汁或1茶匙柠檬酸（防止生擦丝土豆变灰）","1茶匙细海盐用于面团","2汤匙玉米淀粉——仅当生土豆太湿时使用","500克粗剁猪肩肉（或50%猪肉+50%牛肉）","1个中等洋葱（约150克），切极细末","1茶匙细海盐用于馅料","0.5茶匙现磨黑胡椒","1茶匙干马郁兰或干香薄荷","60毫升冷水用于馅料","200克烟熏五花培根，切丁","1个大洋葱（约200克），切薄片","200克全脂酸奶油","莳萝或欧芹，切细，用于点缀","1汤匙粗海盐用于煮面水"],"en":["1.5 kg raw waxy potatoes (Yukon Gold or similar), peeled and weighed","500 g floury potatoes (Russet or King Edward), peeled and weighed","1 tbsp lemon juice or 1 tsp citric acid (to prevent the raw grated potato from greying)","1 tsp fine sea salt for the dough","2 tbsp cornflour (cornstarch) — only if the raw potato is very wet","500 g coarsely minced pork shoulder (or 50% pork + 50% beef)","1 medium onion (about 150 g), very finely diced","1 tsp fine sea salt for the filling","0.5 tsp freshly ground black pepper","1 tsp dried marjoram or dried savory","60 ml cold water for the filling","200 g smoked streaky bacon, cubed","1 large onion (about 200 g), finely sliced","200 g full-fat sour cream","Dill or parsley, finely chopped, to garnish","1 tbsp coarse sea salt for the cooking water"],"ro":["1,5 kg cartofi cu pastă fermă (Yukon Gold sau similari), curățați și cântăriți după curățare","500 g cartofi făinoși (Russet sau King Edward), curățați și cântăriți după curățare","1 lingură suc de lămâie sau 1 linguriță acid citric (pentru a împiedica înnegrirea cartofului ras crud)","1 linguriță sare fină de mare pentru aluat","2 linguri amidon de porumb — doar dacă aluatul rămâne prea umed","500 g carne de porc tocată grosier (sau 50% porc + 50% vită)","1 ceapă medie (aproximativ 150 g), tocată foarte fin","1 linguriță sare fină de mare pentru umplutură","0,5 linguriță piper negru proaspăt măcinat","1 linguriță maghiran uscat sau cimbru de munte uscat","60 ml apă rece pentru umplutură","200 g bacon afumat striat, tăiat cuburi","1 ceapă mare (aproximativ 200 g), feliată fin","200 g smântână grasă","Mărar sau pătrunjel, tocat fin, pentru garnitură","1 lingură sare grunjoasă de mare pentru apa de fierbere"]},"howIsMade":{"zh":"先做馅料，让风味更融合、把猪肉末、切极细的洋葱末、1茶匙盐、胡椒、马郁兰和60毫升冷水放入碗中，用手揉1–2分钟，直到混合物粘稠并紧密结合、盖好放冰箱冷藏，同时准备土豆面团。把500克粉质土豆带皮整颗放入加盐的水中煮25–30分钟至非常软烂、沥水，趁热剥皮，用土豆压泥器压细、摊在烤盘上冷却至室温——热土豆泥会把下一步的生土豆煮熟。用四面擦丝器的细面在大碗中擦1.5公斤生土豆，碗里垫一块干净的厨房毛巾、把毛巾收拢，在第二个碗上方用力挤压，尽可能挤出液体、最终大约会有250毫升液体；让它静置5分钟。小心倒掉清水，保留沉淀在碗底的白色淀粉、把这些淀粉刮回挤干的土豆丝中——这是把cepelinai粘合在一起的天然黏合剂、加入冷却的土豆泥、柠檬汁和1茶匙盐、用手剧烈搅拌2–3分钟，直到形成粘稠有弹性的面团、仅当面团仍然太湿时加入玉米淀粉。用湿手把面团分成8等份（每份约220克）、在湿手掌上将一份压成12 × 8厘米的椭圆形，中央放约60克冷藏好的馅料，然后把面团包起将馅料完全包裹，捏紧边缘密封、整形成12厘米长的飞艇形状，表面不能有任何缝隙让水或蒸汽进入。在宽口深锅中将4升水和1汤匙粗盐烧至温和的微沸（不是大滚——猛烈的水会把cepelinai冲破）、分2批下入cepelinai，轻轻搅一次防粘底，最温柔的微沸下煮25–30分钟，直到表面由哑光变成半透明且cepelinai浮在水面上。同时制作酱汁、把培根丁放入干锅中火煎6–8分钟，至油脂渗出、培根丁酥脆、下切片洋葱再煮5–6分钟，至变软微金黄、离火搅拌好保温。用漏勺把煮好的cepelinai捞到温过的盘子上——每人2个、慷慨地撒上带油脂的培根洋葱混合物，淋上一大勺冷酸奶油，撒上切碎的莳萝、趁热端上桌，趁中心还多汁时享用。","en":"Make the filling first so the flavours marry; mix the minced pork, finely diced onion, 1 tsp salt, pepper, marjoram, and 60 ml cold water in a bowl with your hand for 1–2 minutes, until the mixture is sticky and well bound; cover and chill while you prepare the potato dough. Boil the 500 g floury potatoes whole and unpeeled in salted water for 25–30 minutes, until very tender; drain, peel while hot, and pass through a ricer or mash smoothly; spread out on a tray to cool to room temperature — hot mash would cook the raw potato in the next step. Grate the 1.5 kg waxy potatoes on the fine side of a box grater into a large bowl lined with a clean kitchen towel; gather the towel and squeeze hard over a second bowl to extract as much liquid as possible; you should end up with about 250 ml of liquid; leave it to settle for 5 minutes. Carefully pour off the clear water from the bowl of squeezed liquid, leaving the white starch settled at the bottom; scrape this starch back into the squeezed grated potato — it is the natural binder that holds the dumplings together; add the cooled mashed potato, the lemon juice, and 1 tsp salt; mix vigorously by hand for 2–3 minutes, until you have a sticky, elastic dough; add the cornflour only if the dough still feels wet. With wet hands, divide the dough into 8 equal pieces (about 220 g each); flatten one piece on a wet palm into a 12 × 8 cm oval, place about 60 g of the chilled filling in the centre, then wrap the dough up and around the filling, pinching to seal completely; smooth into a 12 cm zeppelin shape, with no cracks where steam or water could enter. Bring a wide deep pan with 4 litres of water and 1 tbsp coarse salt to a gentle simmer (not a rolling boil — vigorous water can break the dumplings); lower the cepelinai in 2 batches, stir gently once to keep them off the base, and cook for 25–30 minutes at the gentlest simmer, until the surface goes from matte to translucent and the dumplings float high. While they cook, make the sauce; cook the cubed bacon in a dry frying pan over medium heat for 6–8 minutes until the fat renders and the cubes are crisp; add the sliced onion and cook for another 5–6 minutes until soft and lightly golden; stir off the heat and keep warm. Lift the cooked cepelinai out with a slotted spoon onto warmed plates — 2 per person; scatter generously with the bacon-onion mixture and its fat, top with a heap of cold sour cream, and finish with chopped dill; serve immediately while everything is hot and the centres are juicy."}},{"id":140,"origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"法式炖鸡","en":"Chicken Fricassée","ro":"Fricassée de Poulet"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"french","ingredients":{"zh":["1.5公斤带骨带皮鸡腿和小腿（约8块），或1.5公斤整鸡分切为8块","1茶匙细海盐+0.5茶匙现磨白胡椒（黑胡椒可代用但会让酱汁有黑点）","60克无盐黄油，分成30克+30克","2汤匙中性油","250克珍珠洋葱或小红葱头，去皮（或1个中等洋葱切细末）","200克褐色或白色蘑菇，切半或切四瓣（如较大）","2根中等胡萝卜（约200克），去皮并切成5厘米长的条","2瓣大蒜，切细末","30克中筋面粉","150毫升干白葡萄酒（Riesling或Sauvignon Blanc）","500毫升无盐热鸡高汤","1小束香草束（1片月桂叶+4枝百里香+4根欧芹梗，用细绳捆好）","200毫升淡奶油（脂肪含量35%或以上），可选另加2个蛋黄使酱汁更浓郁","1汤匙新鲜柠檬汁","2汤匙切碎的新鲜平叶欧芹，用于点缀"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces), or a 1.5 kg whole chicken jointed into 8","1 tsp fine sea salt + 0.5 tsp freshly ground white pepper (black pepper works but speckles the sauce)","60 g unsalted butter, divided into 30 g + 30 g","2 tbsp neutral oil","250 g pearl onions or small shallots, peeled (or 1 medium onion finely diced)","200 g chestnut or button mushrooms, halved or quartered if large","2 medium carrots (about 200 g), peeled and cut into 5 cm batons","2 garlic cloves, finely minced","30 g plain (all-purpose) flour","150 ml dry white wine (Riesling or Sauvignon Blanc)","500 ml hot unsalted chicken stock","1 small bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks tied with string)","200 ml double cream (heavy cream, 35% fat or higher), plus 2 optional egg yolks for a richer liaison","1 tbsp fresh lemon juice","2 tbsp finely chopped fresh flat-leaf parsley, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți) sau 1,5 kg pui întreg dezasamblat în 8 bucăți","1 linguriță sare fină de mare + 0,5 linguriță piper alb proaspăt măcinat (piperul negru funcționează dar pătează sosul)","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru","250 g cepe de primăvară sau eșalote mici, decojite (sau 1 ceapă medie tocată fin)","200 g ciuperci champignon (albe sau brune), tăiate în jumătăți sau sferturi dacă sunt mari","2 morcovi medii (aproximativ 200 g), curățați și tăiați bastonașe de 5 cm","2 căței de usturoi, tocați fin","30 g făină albă obișnuită","150 ml vin alb sec (Riesling sau Sauvignon Blanc)","500 ml supă de pui fierbinte nesărată","1 bouquet garni mic (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel legate cu sfoară)","200 ml smântână grasă (cel puțin 35% grăsime), plus 2 gălbenușuri opționale pentru o legătură mai bogată","1 lingură suc de lămâie proaspăt","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură"]},"howIsMade":{"zh":"用厨房纸擦干鸡块，两面用1茶匙盐和白胡椒调味，室温静置15分钟。28厘米厚口锅或法式炖锅中火融化30克黄油和2汤匙油、黄油起泡时把鸡块带皮一面朝下平铺入锅（必要时分批），两面各煎5–6分钟——表面呈浅金色，绝不能上色变深褐、深色焦壳会让酱汁混浊、盛出备用。把火调到中小火、下入珍珠洋葱，搅拌煎5–6分钟，洋葱呈浅金色但仍偏白即可、盛到放鸡块的盘子里。加入胡萝卜和蘑菇，煎4–5分钟——蘑菇会先释放水分再吸回、加入大蒜搅拌30秒。把面粉撒在蔬菜上，不停搅拌2分钟去除生面粉味——蔬菜周围会形成浅色油糊、倒入白葡萄酒煮沸，刮起锅底沉淀，收汁至剩一半（1–2分钟）。把鸡块和珍珠洋葱铺回锅中、倒入热鸡汤几乎没过食材，放入香草束，调到最微弱的微沸、盖盖煮30–35分钟（鸡腿，鸡胸提前取出则25分钟），直到肉能轻松脱骨，内部温度达75°C。把鸡块和蔬菜捞到温过的盘子上，盖锡纸保温、丢弃香草束、把酱汁中火煮沸收汁3–5分钟，至挂在勺背（约350毫升）。制作liaison、小碗中将奶油和蛋黄打匀、先舀一勺热酱汁打入调温，然后离火把调温好的混合物倒回锅中、轻轻搅拌——不要再煮沸，否则蛋黄会凝结、加入柠檬汁，尝味并加盐调整、淋在鸡块上，撒切碎的欧芹，立即配米饭、黄油面或蒸土豆上桌。","en":"Pat the chicken pieces dry with paper towels and season both sides with 1 tsp salt and the white pepper; rest at room temperature for 15 minutes. Heat 30 g of the butter and 2 tbsp oil in a wide 28 cm heavy-based sauté pan or Dutch oven over medium heat; when the butter foams, add the chicken skin-side down in one layer (work in batches if needed) and cook 5–6 minutes per side — the surface should turn pale gold and gilded, NOT brown; a brown crust would muddy the sauce; lift onto a plate. Reduce the heat to medium-low; add the pearl onions to the same pan and cook for 5–6 minutes, stirring, until lightly gilded but still pale; lift onto the plate with the chicken. Add the carrots and mushrooms to the pan and cook for 4–5 minutes — the mushrooms will release their water and reabsorb it; add the garlic and stir for 30 seconds. Sprinkle the flour over the vegetables and stir constantly for 2 minutes to cook out the raw taste — a pale roux will form around the vegetables; pour in the wine and bring to a brisk simmer, scraping up any sediment from the pan base, until reduced by half (1–2 minutes). Return the chicken and pearl onions to the pan in a single layer; pour in the hot stock to nearly cover, tuck in the bouquet garni, and bring to the gentlest simmer; cover and cook for 30–35 minutes for thighs (or 25 minutes for breasts removed earlier), until the meat pulls easily from the bone and the internal temperature reads 75°C. Lift the chicken and vegetables to a warmed dish and cover with foil; discard the bouquet garni; bring the sauce to a brisk simmer over medium heat and reduce for 3–5 minutes, until it coats the back of a spoon (about 350 ml). Make the liaison; whisk the cream and egg yolks together in a small bowl; whisk in a ladle of hot sauce to temper, then pour the tempered mixture back into the pan off the heat; stir gently — DO NOT BOIL, or the yolks will scramble; add the lemon juice, taste and adjust the salt; pour over the chicken, scatter with chopped parsley, and serve immediately with rice, buttered noodles, or steamed potatoes."}},{"id":141,"origin":{"zh":"科威特","en":"Kuwait","ro":"Kuweit"},"name":{"zh":"科威特香料饭","en":"Machboos","ro":"Machboos"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"zh":["1.5公斤带骨带皮鸡腿和小腿（或1.2公斤带骨羊肩肉切成6厘米块）","400克巴斯马蒂米，洗净后冷水浸泡30分钟，沥干","60毫升中性油（或30克酥油+2汤匙油，风味更浓郁）","3个大洋葱（约600克），切薄片——留一小把生的用于点缀","6瓣大蒜，切细末","拇指大小的一块新鲜生姜（约30克），细擦","3个中等番茄（约300克），磨成泥（或200克罐装碎番茄）","2汤匙番茄膏","2个干酸橙(loomi)，用刀在3处扎孔（或2汤匙新鲜青柠汁作不那么传统的替代）","1汤匙baharat混合香料（或1茶匙肉桂粉+1茶匙孜然粉+1茶匙香菜籽粉+0.5茶匙小豆蔻粉+0.5茶匙黑胡椒粉）","0.5茶匙姜黄粉","4颗整粒绿小豆蔻，轻轻拍裂+1根肉桂棒（5厘米）+4颗整粒丁香+2片月桂叶","1小束新鲜香菜（约30克），梗部切细加入锅中，叶子留作点缀","2根新鲜青辣椒，纵向划开","1.2升热水（或无盐鸡高汤，让风味更浓）","1.5茶匙细海盐，按需调味","60克杏仁片和40克金黄葡萄干，用1茶匙酥油轻烤（撒在表面）","0.5茶匙藏红花丝，用2汤匙温水浸泡（可选，用于完成米饭）"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (or 1.2 kg bone-in lamb shoulder cut into 6 cm chunks)","400 g basmati rice, rinsed and soaked in cold water for 30 minutes, then drained","60 ml neutral oil (or 30 g ghee + 2 tbsp oil for a richer flavour)","3 large onions (about 600 g), finely sliced — reserve a small handful raw for serving","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 30 g), finely grated","3 medium tomatoes (about 300 g), grated (or 200 g canned chopped tomatoes)","2 tbsp tomato paste","2 dried limes (loomi), pierced with a knife in 3 places (or 2 tbsp fresh lime juice as a less-traditional substitute)","1 tbsp baharat (or 1 tsp ground cinnamon + 1 tsp ground cumin + 1 tsp ground coriander + 0.5 tsp ground cardamom + 0.5 tsp ground black pepper)","0.5 tsp ground turmeric","4 whole green cardamom pods, lightly cracked + 1 cinnamon stick (5 cm) + 4 whole cloves + 2 bay leaves","1 small bunch fresh coriander (about 30 g), stems chopped fine for the pot, leaves reserved for garnish","2 fresh green chillies, slit lengthwise","1.2 litres hot water (or unsalted chicken stock for more depth)","1.5 tsp fine sea salt, plus more to taste","60 g flaked almonds and 40 g sultanas, lightly toasted in 1 tsp ghee (to scatter on top)","0.5 tsp saffron threads soaked in 2 tbsp warm water (optional, for finishing the rice)"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (sau 1,2 kg umăr de miel cu os tăiat bucăți de 6 cm)","400 g orez basmati, clătit și înmuiat în apă rece 30 de minute, apoi scurs","60 ml ulei neutru (sau 30 g ghee + 2 linguri ulei pentru aromă mai bogată)","3 cepe mari (aproximativ 600 g), feliate fin — păstrează o mică parte crudă pentru servit","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 30 g), ras fin","3 roșii medii (aproximativ 300 g), date pe răzătoare (sau 200 g roșii sfărâmate din conservă)","2 linguri pastă de roșii","2 lămâi uscate (loomi), înțepate cu cuțitul în 3 locuri (sau 2 linguri suc proaspăt de lime ca substitut mai puțin tradițional)","1 lingură baharat (sau 1 linguriță scorțișoară măcinată + 1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 0,5 linguriță cardamom măcinat + 0,5 linguriță piper negru măcinat)","0,5 linguriță turmeric măcinat","4 capsule întregi de cardamom verde, ușor crăpate + 1 baton de scorțișoară (5 cm) + 4 cuișoare + 2 foi de dafin","1 legătură mică de coriandru proaspăt (aproximativ 30 g), tijele tocate fin pentru oală, frunzele păstrate pentru garnitură","2 ardei iuți verzi proaspeți, crestați pe lungime","1,2 litri apă fierbinte (sau supă de pui nesărată pentru profunzime)","1,5 lingurițe sare fină de mare, plus după gust","60 g migdale feliate și 40 g stafide blonde, ușor prăjite în 1 linguriță ghee (pentru deasupra)","0,5 linguriță fire de șofran înmuiate în 2 linguri apă caldă (opțional, pentru finisarea orezului)"]},"howIsMade":{"zh":"用冷水冲洗巴斯马蒂米至水几乎清澈，再用新冷水浸泡30分钟、这去除多余淀粉、缩短最后的煮饭时间、使用前再沥干。鸡肉用厨房纸擦干，撒0.5茶匙盐调味、28厘米厚口锅中火至中大火加热油（或酥油+油）、锅热到油光发亮时，鸡块带皮一面朝下放入，每面煎4–5分钟至深金黄、盛出备用。转中火、在同一锅中加入切片洋葱和一小撮盐，频繁搅动炒12–15分钟，至深金黄且非常软、下蒜末和姜末炒1分钟至飘香。加入小豆蔻、肉桂棒、丁香、月桂叶、baharat和姜黄粉、翻炒30秒——香料应飘香并颜色加深、加入番茄膏和擦碎的番茄，搅拌煮4–5分钟，至混合物呈深红色、油从边缘渗出。把鸡块铺回锅中一层、倒入热水（或高汤），加入干酸橙、剖开的青辣椒、切碎的香菜梗和剩余盐、烧至微沸，盖盖转最小火炖35–40分钟（鸡肉）或1小时30分钟（羊肉），至肉能轻松脱骨、汤汁风味浓郁。把鸡块捞到盘上，用锡纸轻盖保温、撇去汤面浮油。把沥干的米饭加入锅中，轻按使其刚刚被汤汁浸没（必要时加热水——米饭上方应保留约2.5厘米液体）、再次烧至微沸，盖紧盖子，转最小火，焖煮18分钟不要打开。关火、把藏红花水（如有使用）淋在米饭上，鸡块放回顶部，盖回盖子焖10分钟——蒸汽完成鸡肉的烹饪，米饭也会松散开、用叉子拨松米饭，盛到宽盘上，鸡块在上面，撒上烤过的杏仁片、葡萄干、生洋葱片和香菜叶、配deeba（罗望子酱）或酸奶上桌。","en":"Rinse the basmati rice under cold running water until the water runs almost clear, then soak in fresh cold water for 30 minutes; this removes excess starch and shortens the final cooking step; drain just before use. Pat the chicken pieces dry and season with 0.5 tsp of the salt; heat the oil (or ghee + oil) in a heavy 28 cm pot over medium-high heat; when shimmering, add the chicken skin-side down and sear for 4–5 minutes per side until deep golden; lift onto a plate. Reduce the heat to medium; add the sliced onions and a pinch of salt to the same pot and cook for 12–15 minutes, stirring often, until deeply golden and very soft; add the garlic and ginger and cook for 1 minute until fragrant. Stir in the cardamom pods, cinnamon stick, cloves, bay leaves, baharat, and turmeric; toast for 30 seconds — the spices should turn aromatic and deepen in colour; add the tomato paste and grated tomatoes and cook, stirring, for 4–5 minutes, until the mixture darkens to a rich red and the oil splits out around the edges. Return the chicken to the pot in a single layer; pour in the hot water (or stock), add the dried limes, slit chillies, chopped coriander stems, and remaining salt; bring to a gentle boil, then cover, reduce to the lowest simmer, and cook for 35–40 minutes (chicken) or 1 h 30 min (lamb), until the meat is fork-tender and the broth is deeply flavoured. Lift the chicken onto a plate and cover loosely with foil to keep warm; skim any excess fat from the broth. Add the drained rice to the pot, gently pushing it down so it is just covered by the broth (top up with hot water if needed — you want about 2.5 cm of liquid above the rice); bring back to a gentle boil, then cover with a tight lid, reduce to the lowest possible heat, and cook undisturbed for 18 minutes. Turn off the heat; drizzle the saffron water (if using) over the rice, place the chicken pieces on top, replace the lid, and rest for 10 minutes — the steam finishes cooking the chicken and the rice grains separate; fluff the rice with a fork, transfer to a wide platter with the chicken on top, and scatter with toasted almonds, sultanas, raw onion slices, and fresh coriander leaves; serve with deeba (tamarind sauce) or yoghurt on the side."}},{"id":142,"origin":{"zh":"刚果共和国","en":"Republic of the Congo","ro":"Republica Congo"},"name":{"zh":"花生酱炖鸡","en":"Moambe chicken","ro":"Pui Moambe"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["1.5公斤带骨带皮鸡腿和小腿（约8块）","1茶匙细海盐 + 0.5茶匙现磨黑胡椒（鸡肉用）","60毫升红棕榈油（或30毫升棕榈油 + 2汤匙中性油，如风味过重）","2个大洋葱（约400克），切细末","6瓣大蒜，切细末","拇指大小的一块新鲜生姜（约20克），细擦","400克熟番茄擦成泥，或1罐400克碎番茄","2汤匙番茄膏","100克无糖顺滑花生酱（或200克罐装moambe棕榈酱，如能买到）","2根新鲜scotch bonnet或habanero辣椒，纵向划开（或1茶匙干辣椒片；按口味调整——moambe偏辣）","2片月桂叶","500毫升无盐热鸡高汤或清水","1.5茶匙细海盐，按需调味","2汤匙切碎的平叶欧芹（或2汤匙柠檬罗勒），用于点缀","蒸白米饭、fufu或煮plantain，配菜用"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces)","1 tsp fine sea salt + 0.5 tsp freshly ground black pepper for the chicken","60 ml red palm oil (or 30 ml palm + 2 tbsp neutral oil if the flavour is too strong)","2 large onions (about 400 g), finely diced","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 20 g), finely grated","400 g ripe tomatoes, grated, or 1 × 400 g can chopped tomatoes","2 tbsp tomato paste","100 g unsweetened smooth peanut butter (or 200 g canned moambe palm paste when available)","2 fresh scotch bonnet or habanero chillies, slit lengthwise (or 1 tsp dried chilli flakes; adjust to taste — moambe is hot)","2 bay leaves","500 ml hot unsalted chicken stock or water","1.5 tsp fine sea salt, plus more to taste","2 tbsp finely chopped flat-leaf parsley (or 2 tbsp lemon basil), to garnish","Steamed white rice, fufu, or boiled plantains, to serve"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","1 linguriță sare fină de mare + 0,5 linguriță piper negru proaspăt măcinat pentru pui","60 ml ulei de palmier roșu (sau 30 ml palmier + 2 linguri ulei neutru dacă aroma e prea puternică)","2 cepe mari (aproximativ 400 g), tocate fin","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 20 g), ras fin","400 g roșii coapte, date pe răzătoare (sau 1 × 400 g conservă de roșii tocate)","2 linguri pastă de roșii","100 g unt de arahide neîndulcit, fin (sau 200 g pastă de moambe la conservă, când e disponibilă)","2 ardei iuți proaspeți scotch bonnet sau habanero, crestați pe lungime (sau 1 linguriță fulgi de ardei iute; ajustează după gust — muambe este picant)","2 foi de dafin","500 ml supă de pui fierbinte nesărată sau apă","1,5 lingurițe sare fină de mare, plus după gust","2 linguri pătrunjel cu frunze plate tocat fin (sau 2 linguri busuioc de lămâie), pentru garnitură","Orez alb fiert, fufu sau banane plantain fierte, pentru servit"]},"howIsMade":{"zh":"用厨房纸擦干鸡块，两面用1茶匙盐和0.5茶匙胡椒调味，室温静置15分钟。28厘米厚口锅中火至中大火加热棕榈油——棕榈油会融化成深橙红色液体、锅光发亮时把鸡块带皮一面朝下平铺入锅（必要时分两批），每面煎4–5分钟至鸡皮深金黄、盛出备用。火力调到中火、同锅下切碎洋葱和一小撮盐，频繁搅动炒8–10分钟，至洋葱柔软、油亮、微金黄但不上色。加入蒜末和姜末，炒1分钟至飘香、倒入番茄膏和擦碎的番茄，搅拌煮5–6分钟，至混合物呈深砖红色，棕榈油开始在边缘渗出——这种油渗是moambe的标志外观。小碗中将花生酱与200毫升热高汤搅匀至顺滑，再倒入锅中拌匀、加入剩余300毫升高汤、月桂叶、剖开的辣椒和剩余0.5茶匙盐。把鸡块铺回锅中一层，将鸡块按入酱汁中，鸡皮朝上让皮高于液面、烧至微沸。盖盖留小缝，最小火煮35–40分钟，中途搅一次，直到鸡肉能轻松脱骨，内部温度达75°C、酱汁应呈珊瑚橙色、浓到能挂在勺背——若太稠，可加少许热水稀释。尝味并按需加盐或辣椒、把鸡块捞到温过的盘子中，浇上大量酱汁，撒切碎的欧芹，立即配蒸米饭、fufu或煮plantain上桌，用以蘸取酱汁。","en":"Pat the chicken pieces dry and season both sides with 1 tsp salt and 0.5 tsp pepper; rest at room temperature for 15 minutes. Heat the palm oil in a heavy 28 cm pot over medium-high heat — palm oil melts into a deep orange-red liquid; when shimmering, add the chicken pieces skin-side down in one layer (work in two batches if needed) and sear for 4–5 minutes per side until the skin is deep golden; lift onto a plate. Reduce the heat to medium; add the diced onions and a pinch of salt to the same pot and cook for 8–10 minutes, stirring often, until soft, glossy, and lightly golden but not browned. Add the garlic and ginger and cook for 1 minute until fragrant; stir in the tomato paste and grated tomatoes and cook for 5–6 minutes, stirring, until the mixture darkens to a rich brick-red and the palm oil starts to separate around the edges — this oil split is the signature look of moambe. Whisk the peanut butter with 200 ml of the hot stock in a small bowl until smooth, then pour into the pot and stir to combine; add the remaining 300 ml stock, the bay leaves, slit chillies, and the remaining 0.5 tsp salt. Return the chicken to the pot in a single layer, nestling the pieces into the sauce skin-side up so the skin stays above the liquid; bring to a gentle simmer. Cover with a lid set slightly ajar and cook on the lowest heat for 35–40 minutes, stirring once at the halfway mark, until the chicken pulls easily from the bone and the internal temperature reads 75°C; the sauce should be coral-orange and thick enough to coat the back of a spoon — if it tightens too much, loosen with a splash of hot water. Taste and adjust with salt or extra chilli; lift the chicken into a warmed serving dish, spoon the sauce generously over the top, scatter with chopped parsley, and serve immediately with steamed rice, fufu, or boiled plantain to soak up the sauce."}},{"id":143,"origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"法式砂锅炖菜","en":"Cassoulet","ro":"Cassoulet"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["500克干白芸豆（haricot tarbais或cannellini），冷水浸泡过夜","4只油封鸭腿（cuisses de canard confites），室温，鸭油另留","400克猪肩肉，切成4厘米块","300克带皮猪五花，切成3厘米块","4根图卢兹香肠（约500克）——或烟熏猪肉肠作替代","1根大胡萝卜（约150克），去皮切成2厘米块","1个大洋葱（约200克），去皮并插入4颗整丁香","1头大蒜（约60克），横向对半切","1束香草束（1片月桂叶+4枝百里香+4根欧芹梗+一小块干橙皮，捆好）","1块猪肘骨或火腿肘（约400克，可选但传统做法用）","200克罐装碎番茄（或2个去皮切碎的熟番茄）","2汤匙番茄膏","1.5升无盐鸡或猪高汤（或清水）","60克白色粗面包屑","1.5茶匙细海盐，按需调味","1茶匙现磨黑胡椒","2汤匙切碎的平叶欧芹，用于点缀","2汤匙鸭油（从confit取），用于煎肉"],"en":["500 g dried white beans (haricot tarbais or cannellini), soaked in cold water overnight","4 confit duck legs (cuisses de canard confites), at room temperature, fat reserved","400 g pork shoulder, cut into 4 cm pieces","300 g pork belly with rind, cut into 3 cm pieces","4 Toulouse sausages (about 500 g) — or smoked pork sausages as a substitute","1 large carrot (about 150 g), peeled and cut into 2 cm chunks","1 large onion (about 200 g), peeled and studded with 4 whole cloves","1 head of garlic (about 60 g), halved horizontally","1 bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks + a piece of dried orange peel, tied)","1 pork knuckle bone or ham hock (about 400 g, optional but traditional)","200 g canned chopped tomatoes (or 2 ripe tomatoes, peeled and chopped)","2 tbsp tomato paste","1.5 litres unsalted chicken or pork stock (or water)","60 g coarse white breadcrumbs","1.5 tsp fine sea salt, plus more to taste","1 tsp freshly ground black pepper","2 tbsp finely chopped fresh flat-leaf parsley, to garnish","2 tbsp duck fat (from the confit), for browning the meats"],"ro":["500 g fasole albă uscată (haricot tarbais sau cannellini), înmuiată în apă rece peste noapte","4 pulpe de rață confit (cuisses de canard confites), la temperatura camerei, grăsimea păstrată","400 g umăr de porc, tăiat bucăți de 4 cm","300 g piept de porc cu șorici, tăiat bucăți de 3 cm","4 cârnați de Toulouse (aproximativ 500 g) — sau cârnați afumați de porc ca substitut","1 morcov mare (aproximativ 150 g), curățat și tăiat bucăți de 2 cm","1 ceapă mare (aproximativ 200 g), curățată și înfiptă cu 4 cuișoare întregi","1 căpățână de usturoi (aproximativ 60 g), tăiată orizontal","1 bouquet garni (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel + o bucată de coajă uscată de portocală, legate)","1 os de jambon afumat sau o ciolan de porc (aproximativ 400 g, opțional dar tradițional)","200 g roșii sfărâmate din conservă (sau 2 roșii coapte, decojite și tocate)","2 linguri pastă de roșii","1,5 litri supă de pui sau de porc nesărată (sau apă)","60 g pesmet alb grosier","1,5 lingurițe sare fină de mare, plus după gust","1 linguriță piper negru proaspăt măcinat","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură","2 linguri grăsime de rață (din confit), pentru rumenirea cărnurilor"]},"howIsMade":{"zh":"前一晚把豆子放入大碗，加入至少2升冷水浸泡10–12小时，豆子约会胀大一倍、第二天沥水冲洗。制作豆汤汁、把沥干的豆子放入5升厚底锅中，加入猪肘（如有）、插着丁香的洋葱、切半的蒜头、胡萝卜、香草束和1.5升冷高汤、烧至微沸，开盖煮50–60分钟，至豆子刚刚软嫩但未散开、此时不要加盐。同时煎香肉类、宽口煎锅中火至中大火融化2汤匙鸭油、猪肩和猪五花拍干后分批每面煎4–5分钟至深金黄，盛出、同油中煎图卢兹香肠每面2–3分钟，只为给肠衣上色、一起盛出。烤箱预热到160°C（320°F / 风扇140°C）、从豆锅中取出猪肘、洋葱、蒜头、胡萝卜和香草束，丢弃香料、把猪肘上的肉拆下、粗剁后留用、把番茄膏和碎番茄拌入豆汤，尝味并加入1.5茶匙盐和胡椒。在26厘米宽cassole（或任何宽口耐烤锅）中组合cassoulet、先铺三分之一豆子在底部，再依次铺上煎好的猪肩、猪五花、肘子肉和冷的油封鸭腿、盖上第二层三分之一豆子，铺上煎好的香肠，最后再用剩下的豆子覆盖、倒入足够的豆汤恰好没过顶层豆子——剩下的汤保温备用。表面均匀撒面包屑、把cassole放入烤箱，不盖盖子，烤1小时、面包屑会上色变成棕色硬壳。1小时后，用木勺背把硬壳压入cassoulet——不要搅拌、如果显干，舀入一勺保温的豆汤、重新放入烤箱再烤1小时，30分钟后再把新形成的硬壳压破，直到形成新的硬壳，边缘深深冒泡。再重复一次：压破硬壳、补加豆汤、最后烤30–40分钟、总烤箱时间约2小时30分钟——一共三层硬壳、出炉后让cassoulet静置10分钟，让豆子重新吸收汤汁、撒上切碎的欧芹，直接从cassole上桌，配脆皮面包和青绿沙拉。","en":"The night before, place the beans in a large bowl, cover with at least 2 litres of cold water, and soak for 10–12 hours; they will roughly double in size; drain and rinse the next day. Make the bean stock; put the drained beans in a heavy 5-litre pot with the pork knuckle (if using), the studded onion, the halved garlic head, the carrot chunks, the bouquet garni, and 1.5 litres of cold stock; bring to a gentle simmer and cook uncovered for 50–60 minutes, until the beans are just tender but not falling apart; do not salt yet. Meanwhile, brown the meats; heat 2 tbsp duck fat in a wide skillet over medium-high heat; pat the pork shoulder and pork belly dry and brown in batches for 4–5 minutes per side until deep golden; lift onto a plate; in the same fat, brown the Toulouse sausages for 2–3 minutes per side just to colour the casings; add to the plate. Heat the oven to 160°C (320°F / fan 140°C); lift the cooked knuckle, onion, garlic, carrot, and bouquet garni out of the bean pot and discard the aromatics; pull any meat from the knuckle bone, shred coarsely, and reserve; stir the tomato paste and chopped tomatoes into the bean liquid, then taste and add 1.5 tsp salt and the pepper. Assemble the cassoulet in a wide 26 cm cassole (or any wide oven-safe pot); spread one-third of the beans on the bottom, then arrange the browned pork shoulder, pork belly, knuckle meat, and the cold confit duck legs on top; cover with another third of the beans, lay the browned sausages on top, then finish with the remaining beans; pour over enough bean liquid to just cover the top layer of beans — keep the rest warm for topping up. Sprinkle the breadcrumbs evenly over the top; place the cassole in the oven, uncovered, and cook for 1 hour; the breadcrumbs will gild and form a brown crust. After 1 hour, break the crust by pressing it down into the cassoulet with the back of a wooden spoon — do not stir; top up with a ladle of reserved bean liquid if it looks dry; return to the oven and cook for another hour, breaking the crust again after 30 minutes, until a fresh crust has formed and the cassoulet is bubbling deeply around the edges. Repeat once more: break the crust, top up the liquid, and bake a final 30–40 minutes; the total oven time is about 2 h 30 m — three crusts in all; rest the cassoulet for 10 minutes out of the oven so the beans drink back the liquid; scatter with chopped parsley and serve straight from the pot, with crusty bread and a green salad."},"timeMins":{"total":240,"active":45}},{"id":144,"origin":{"zh":"克罗地亚","en":"Croatia","ro":"Croația"},"name":{"zh":"克罗地亚炖牛肉","en":"Pasticada","ro":"Pašticada"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["1.2公斤牛臀肉或牛后腿肉，整块","100克猪背膘或意大利pancetta，切成5毫米×5厘米的条用于嵌入","2根中等胡萝卜（约200克）：1根切成火柴棒状用于嵌入，1根切细丁用于酱汁","10颗整丁香（5颗嵌入肉中，5颗腌料用）+0.5茶匙丁香粉用于酱汁","6瓣大蒜，去皮——3瓣腌料用拍碎，3瓣酱汁用切细末","200毫升白葡萄酒醋+200毫升冷水+3片月桂叶+1茶匙黑胡椒粒+4颗杜松子（用于腌料）","2个大洋葱（约400克），切细末","200克去核西梅干（dried plums）","100毫升甜葡萄酒prošek（或甜Marsala或1汤匙红糖+80毫升波特酒）","500毫升干红葡萄酒（Plavac Mali、Merlot或其他浓郁干红）","300毫升无盐牛高汤","2汤匙番茄膏+200克罐装碎番茄","1茶匙肉桂粉+0.5茶匙现磨肉豆蔻","50克猪油（或3汤匙橄榄油），用于煎制","1.5茶匙细海盐，按需调味","0.5茶匙现磨黑胡椒，用于收尾","新鲜欧芹切细，用于点缀","意式gnocchi或新鲜意大利面（约500克），配菜用"],"en":["1.2 kg beef rump or topside, in one piece","100 g pork fat back or pancetta, cut into 5 mm × 5 cm strips for larding","2 medium carrots (about 200 g): 1 cut into matchsticks for larding, 1 finely diced for the sauce","10 whole cloves (5 for larding, 5 for the marinade) + 0.5 tsp ground cloves for the sauce","6 garlic cloves, peeled — 3 crushed for the marinade, 3 finely chopped for the sauce","200 ml white wine vinegar + 200 ml cold water + 3 bay leaves + 1 tsp black peppercorns + 4 juniper berries (for the marinade)","2 large onions (about 400 g), finely diced","200 g pitted prunes (dried plums)","100 ml prošek dessert wine (or sweet Marsala or 1 tbsp brown sugar + 80 ml port)","500 ml dry red wine (Plavac Mali, Merlot, or any robust dry red)","300 ml unsalted beef stock","2 tbsp tomato paste + 200 g canned chopped tomatoes","1 tsp ground cinnamon + 0.5 tsp freshly grated nutmeg","50 g lard (or 3 tbsp olive oil), for browning","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper, for finishing","Fresh parsley, finely chopped, to garnish","Gnocchi or fresh pasta (about 500 g), to serve"],"ro":["1,2 kg vrăbioară sau pulpă de vită, într-o singură bucată","100 g slană de porc sau pancetta, tăiată fâșii de 5 mm × 5 cm pentru împănat","2 morcovi medii (aproximativ 200 g): 1 tăiat fâșii subțiri pentru împănat, 1 tăiat cuburi mici pentru sos","10 cuișoare întregi (5 pentru împănat, 5 pentru marinadă) + 0,5 linguriță cuișoare măcinate pentru sos","6 căței de usturoi decojiți — 3 zdrobiți pentru marinadă, 3 tocați fin pentru sos","200 ml oțet de vin alb + 200 ml apă rece + 3 foi de dafin + 1 linguriță boabe de piper negru + 4 boabe de ienupăr (pentru marinadă)","2 cepe mari (aproximativ 400 g), tocate fin","200 g prune uscate fără sâmburi","100 ml vin dulce prošek (sau Marsala dulce, sau 1 lingură zahăr brun + 80 ml porto)","500 ml vin roșu sec (Plavac Mali, Merlot sau orice vin sec robust)","300 ml supă de vită nesărată","2 linguri pastă de roșii + 200 g roșii sfărâmate din conservă","1 linguriță scorțișoară măcinată + 0,5 linguriță nucșoară proaspăt rasă","50 g untură (sau 3 linguri ulei de măsline), pentru rumenire","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat, pentru finisare","Pătrunjel proaspăt tocat fin, pentru garnitură","Gnocchi sau paste proaspete (aproximativ 500 g), pentru servit"]},"howIsMade":{"zh":"第1天，给牛肉嵌肉、用锋利的小刀在牛肉表面切16个深口，每个深口里塞入一条猪背膘、一根胡萝卜火柴棒，再在每隔一个的深口里塞入半颗整丁香、膘从内部润肉，胡萝卜增甜酱汁，丁香赋香。制作腌料、在刚好能装下肉的不易反应的碗中，混合200毫升白葡萄酒醋、200毫升冷水、用于腌料的3瓣拍碎的蒜、3片月桂叶、黑胡椒粒、4颗杜松子和剩下的5颗整丁香、将牛肉浸入，盖好放冰箱腌24小时（最多48小时），中间翻面两次。第2天，取出牛肉，刮去黏在表面的香料，彻底拍干——湿肉无法上色、腌料弃用、用1茶匙盐和0.5茶匙黑胡椒为肉调味。28厘米厚铸铁锅或braiser中火至中大火融化猪油、将牛肉每面煎3–4分钟，总共12–15分钟，使所有表面呈均匀的红棕色、盛出备用。转中火、把切碎洋葱和一小撮盐加入融化的油脂中，频繁搅动炒10–12分钟，至深金棕色——这慢慢的焦糖化是酱汁的基础、加入胡萝卜末和蒜末再炒3–4分钟、拌入番茄膏、丁香粉、肉桂和肉豆蔻，再炒1分钟。倒入prošek搅拌1分钟并刮锅底、加入红葡萄酒，大火收至剩一半（约6–8分钟）、加入碎番茄、牛高汤、西梅干和剩下0.5茶匙盐、把牛肉放回锅中，使其陷入汤汁——酱汁应到达肉的约四分之三高度。盖紧锅盖，最小炉火（或150°C烤箱）炖2小时30分钟–3小时，每45分钟翻一次肉，直到刀子能毫无阻力地插入中心、把肉移到砧板，用锡纸轻盖静置15分钟。完成酱汁、把西梅干捞出，留一把做点缀；其余与酱汁用手持搅拌机打成浓稠光亮的酱汁（或过细筛得到更细的口感）、如需要进一步浓缩，开盖再煮5–8分钟——酱汁应能挂在勺背并有深度的甜酸香料味、把休息好的牛肉横切1厘米厚的片，扇形铺在温过的gnocchi或新鲜意大利面上，慷慨地浇上酱汁，撒上保留的西梅干和切碎的欧芹，立即上桌。","en":"Day 1, lard the beef; using a sharp paring knife, make 16 deep slits across the surface of the beef joint; slide a strip of pork fat, a carrot matchstick, and (in alternate slits) half of a whole clove into each slit; the fat will baste the meat from the inside, the carrot will sweeten the sauce, and the cloves perfume the meat. Make the marinade; in a non-reactive bowl just large enough to hold the beef, combine 200 ml wine vinegar, 200 ml cold water, the 3 crushed marinade garlic cloves, 3 bay leaves, peppercorns, juniper berries, and the remaining 5 whole cloves; submerge the beef, cover, and refrigerate 24 hours (up to 48 hours), turning twice. Day 2, lift the beef out, scrape off any clinging spices, and pat thoroughly dry — wet meat will not brown; discard the marinade; season the meat with 1 tsp salt and 0.5 tsp pepper. Heat the lard in a heavy Dutch oven or braiser (28 cm) over medium-high heat; sear the beef on all sides for 3–4 minutes per side, about 12–15 minutes total, until evenly mahogany brown all over; lift onto a plate. Reduce the heat to medium; add the diced onion and a pinch of salt to the rendered fat and cook for 10–12 minutes, stirring often, until deeply golden brown — this slow caramelisation builds the sauce; add the diced carrot and chopped garlic and cook for another 3–4 minutes; stir in the tomato paste, ground cloves, cinnamon, and nutmeg and toast for 1 minute. Pour in the prošek and stir for 1 minute, scraping the base; add the red wine, raise the heat, and reduce by half (about 6–8 minutes); add the chopped tomatoes, beef stock, prunes, and the remaining 0.5 tsp salt; return the beef to the pot, settling it into the liquid — the sauce should come about three-quarters of the way up the meat. Cover with a tight lid and braise on the lowest hob heat (or in a 150°C oven) for 2 h 30 m – 3 h, turning the beef every 45 minutes, until a knife slides into the centre with no resistance; lift the beef onto a board and rest, tented with foil, for 15 minutes. Finish the sauce; lift out the prunes and reserve a handful for garnish; blend the rest with the sauce using a stick blender to a thick, glossy gravy (or push through a sieve for a finer finish); reduce uncovered for 5–8 minutes if it needs thickening — it should coat the back of a spoon and taste deeply sweet-sour-spiced; slice the rested beef across the grain into 1 cm slices, fan over warm gnocchi or fresh pasta, spoon the sauce generously, scatter with reserved prunes and chopped parsley, and serve immediately."}},{"id":145,"origin":{"zh":"塞浦路斯","en":"Cyprus","ro":"Cipru"},"name":{"zh":"塞浦路斯烤肉卷","en":"Sheftalia","ro":"Sheftalia"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mediterranean","ingredients":{"zh":["400克粗剁猪肩肉（脂肪15–20%）","300克粗剁羊肩肉（如无羊肉，可全部用700克猪肉）","300克网油（羊或猪），用冷淡盐水浸泡30分钟后沥干——约30 × 30厘米的一片","1个大洋葱（约200克），擦丝后挤干多余水分","30克平叶欧芹，切细","20克新鲜薄荷（塞浦路斯dyosmos），切细（可选但传统）","4瓣大蒜，切细末","1.5茶匙细海盐","1茶匙现磨黑胡椒","1茶匙磨碎的孜然","0.5茶匙磨碎的肉桂","60毫升干白葡萄酒或2汤匙红酒醋（用于黏合和软化）","1汤匙橄榄油加入肉馅","1汤匙橄榄油用于刷烤架","柠檬角、紫洋葱片、番茄片，以及温热的pita或塞浦路斯柠檬面包（lemoni），用于配餐","Tzatziki或鹰嘴豆泥，用于配餐"],"en":["400 g coarsely minced pork shoulder (15–20% fat)","300 g coarsely minced lamb shoulder (or 700 g all pork if lamb is unavailable)","300 g caul fat (lamb or pork), soaked in cold lightly-salted water for 30 minutes then drained — about a 30 × 30 cm sheet","1 large onion (about 200 g), grated and squeezed of excess liquid","30 g flat-leaf parsley, finely chopped","20 g fresh mint (Cypriot dyosmos), finely chopped (optional but traditional)","4 garlic cloves, finely minced","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground cinnamon","60 ml dry white wine or 2 tbsp red wine vinegar (to bind and tenderise)","1 tbsp olive oil for the meat mixture","1 tbsp olive oil for brushing the grill","Lemon wedges, sliced red onion, sliced tomato, and warm pitta or Cypriot lemoni-bread, to serve","Tzatziki or hummus, to serve"],"ro":["400 g umăr de porc tocat grosier (15–20% grăsime)","300 g umăr de miel tocat grosier (sau 700 g doar porc, dacă mielul nu este disponibil)","300 g prapure (de porc sau miel), înmuiat în apă rece ușor sărată 30 de minute, apoi scurs — o foaie de aproximativ 30 × 30 cm","1 ceapă mare (aproximativ 200 g), dată pe răzătoare și stoarsă de lichidul în exces","30 g pătrunjel cu frunze plate, tocat fin","20 g mentă proaspătă (dyosmos cipriot), tocată fin (opțional, dar tradițional)","4 căței de usturoi, tocați fin","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță scorțișoară măcinată","60 ml vin alb sec sau 2 linguri oțet de vin roșu (pentru a lega și a frăgezi)","1 lingură ulei de măsline pentru compoziție","1 lingură ulei de măsline pentru uns grătarul","Felii de lămâie, ceapă roșie feliată, roșii feliate și pita caldă sau pâine cipriotă de lămâie (lemoni), pentru servit","Tzatziki sau hummus, pentru servit"]},"howIsMade":{"zh":"拌肉馅、在宽口碗中混合猪肉末、羊肉末、擦出的洋葱、欧芹、薄荷（如用）、大蒜、盐、胡椒、孜然、肉桂、葡萄酒（或醋）和1汤匙橄榄油、用手揉2–3分钟直到肉馅黏稠均匀、盖好放入冰箱冷藏至少1小时（最多12小时），让味道融合。准备网油、把浸泡并沥干的网油小心地铺在干净的板上——它非常容易撕裂、用剪刀剪成12块约12 × 12厘米的方块、如有破洞用其他片叠在一起遮盖。包sheftalia、取一汤匙大小的肉馅（约50–60克），搓成略带锥度的圆柱状，长7–8厘米、放在一块网油的边缘、把两边折到肉馅上，紧紧卷成香肠状，封口朝下、如有金属串可串穿——否则封口自身就能固定、剩下的肉和网油重复操作：共得12根sheftalia，每人3根。把卷好的sheftalia排在烤盘上，至少冷藏15分钟（最长4小时），让网油变硬——上烤架时更不易散开。把炭火烤架或厚重的有沟槽煎锅烧到中大火（表面约200°C）、用1汤匙橄榄油轻刷一层、sheftalia触到烤架时应当发出嘶嘶声但不能有强烈火焰——火太大网油会在肉熟前烧焦。烤sheftalia共12–15分钟，每3–4分钟翻面到另外的一面，共四面，直到网油融成薄薄的蕾丝状外壳，中心温度达70°C、它们应呈深金黄色，外感扎实但不僵硬。把sheftalia挪到砧板上，用锡纸轻盖静置5分钟、汁水回笼，余热让肉完成熟化。把pita或柠檬面包放在烤架上每面30秒加热、每位食客盘中放3根sheftalia、热面包、柠檬角、紫洋葱片和番茄片、一旁放tzatziki或鹰嘴豆泥、吃法是把sheftalia撕成小段塞进pita中和沙拉、酱料一起享用。","en":"Make the meat mixture; in a wide bowl combine the minced pork, minced lamb, grated onion, parsley, mint (if using), garlic, salt, pepper, cumin, cinnamon, wine (or vinegar), and 1 tbsp olive oil; knead with your hand for 2–3 minutes until sticky and homogeneous; cover and chill in the fridge for at least 1 hour (up to 12 hours) so the seasoning matures. Prepare the caul fat; spread the soaked and drained caul fat carefully on a clean board — it tears very easily; use scissors to cut it into 12 squares of about 12 × 12 cm; patch holes by overlapping pieces. Shape the sheftalia; take a tablespoon-sized portion of meat (about 50–60 g) and shape into a slightly tapered cylinder 7–8 cm long; place at the edge of one caul-fat square; fold the sides over the meat, then roll up tightly into a sausage shape, finishing with the seam underneath; pierce onto a metal skewer if you have one — otherwise the wrapped seam will hold; repeat with the remaining meat and caul fat: you should get 12 sheftalia, 3 per person. Rest the wrapped sausages on a tray and chill for at least 15 minutes (up to 4 hours) so the caul fat firms — they hold together better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 200°C / 390°F surface); brush lightly with 1 tbsp olive oil; the sheftalia should hiss when they touch the grill but not flare aggressively — too high and the caul fat will burn before the meat cooks through. Grill the sheftalia for 12–15 minutes total, turning every 3–4 minutes onto each of their four sides, until the caul fat has rendered down into a thin lacy crust and the meat reaches 70°C in the centre; they should be deep golden brown and feel firm but not hard. Lift the sheftalia onto a board and rest, loosely tented with foil, for 5 minutes; the juices settle and the meat finishes cooking from residual heat. Warm the pitta or Cypriot lemoni-bread on the grill for 30 seconds per side; pile 3 sheftalia per person on each plate with the warm bread, lemon wedges, sliced red onion, and tomato; spoon tzatziki or hummus to the side; eat by tearing pieces of sheftalia into the pitta with the salad and dip."}},{"id":146,"origin":{"zh":"波斯尼亚和黑塞哥维那","en":"Bosnia and Herzegovina","ro":"Bosnia și Herțegovina"},"name":{"zh":"烤肉卷","en":"Cevapi","ro":"Cevapi"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["500克粗剁牛肩肉（脂肪约15%）","300克粗剁羊肩肉（如无羊肉，可全部用800克牛肉）","4瓣大蒜，与0.5茶匙盐捣成细泥","60毫升冰镇气泡水","1茶匙小苏打——弹牙口感的关键","1.5茶匙细海盐","1茶匙现磨黑胡椒","1茶匙匈牙利甜红椒粉","0.5茶匙干马郁兰或干牛至（可选但传统）","1汤匙中性油，用于刷烤架","4块somun饼（或4块pita），每块约18厘米，用于配餐","1个大紫洋葱（约200克），切极细末","200克ajvar（烤红椒酱）","100克kajmak（巴尔干浓奶油）或浓厚crème fraîche作替代","1小束平叶欧芹，取叶用于撒面"],"en":["500 g coarsely minced beef chuck (about 15% fat)","300 g coarsely minced lamb shoulder (or 800 g all beef if lamb is unavailable)","4 garlic cloves, crushed with 0.5 tsp salt to a fine paste","60 ml chilled sparkling water","1 tsp baking soda (sodium bicarbonate) — the key to the springy texture","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp sweet Hungarian paprika","0.5 tsp dried marjoram or oregano (optional but traditional)","1 tbsp neutral oil for brushing","4 somun flatbreads (or 4 pittas), about 18 cm across each, to serve","1 large red onion (about 200 g), very finely diced","200 g ajvar (roasted red-pepper relish)","100 g kajmak (Balkan clotted cream) or thick crème fraîche, as a substitute","1 small bunch flat-leaf parsley, leaves picked, to scatter"],"ro":["500 g pulpă de vită tocată grosier (15% grăsime)","300 g umăr de miel tocat grosier (sau 800 g doar vită, dacă nu există miel)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă fină","60 ml apă minerală rece (carbogazoasă)","1 linguriță bicarbonat de sodiu — cheia texturii elastice","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță boia dulce maghiară","0,5 linguriță maghiran sau oregano uscat (opțional, dar tradițional)","1 lingură ulei neutru pentru uns","4 lipii somun (sau 4 pita) de aproximativ 18 cm fiecare, pentru servit","1 ceapă roșie mare (aproximativ 200 g), tocată foarte fin","200 g ajvar (pastă de ardei copți)","100 g kajmak (smântână groasă balcanică) sau crème fraîche groasă ca substitut","1 legătură mică de pătrunjel cu frunze plate, frunzele păstrate, pentru servit"]},"howIsMade":{"zh":"做肉馅、在宽口碗中混合牛肉末、羊肉末、蒜泥-盐糊、冰镇气泡水、小苏打、盐、胡椒、红椒粉和马郁兰、用手剧烈揉4–5分钟——混合物应明显发黏并紧密结合、这长时间的揉制和小苏打是赋予cevapi标志性弹牙口感的关键。用保鲜膜盖住碗，放入冰箱冷藏至少4小时，理想为12–24小时、风味成熟、蛋白质放松。用冷水把手沾湿、取一汤匙量的肉馅（约35–40克），在手掌间搓成手指形圆柱，长7–8厘米，粗约2厘米、重复操作，共得约24根cevapi（每人6根）、一边做一边码在烤盘上。把成型的cevapi冷藏至少20分钟（最多4小时）使其变硬——这样在烤架上更不易变形。把炭火烤架或厚重的有沟槽煎锅烧到中大火（表面约220°C）、给cevapi非常轻地刷一层油——只是薄薄一层、放上烤架时应嘶嘶作响但不冒大烟。烤cevapi共8–10分钟，每2分钟翻一次面，四面各烤2分钟，直到表面呈红棕色、边缘酥脆，中心温度达到65°C（它们会在盘中继续熟化）、不要按压；目标是多汁、弹牙的内芯。cevapi休息2分钟时，将somun（或pita）放在烤架上每面30秒加热，直到稍微膨胀并轻微焦黄、沿其接缝处切开形成口袋。把6根cevapi塞入每个温热的饼里（或6根放在饼旁的盘子里）、一旁放1–2汤匙ajvar，加一大勺kajmak（或crème fraîche），再放上小堆生紫洋葱碎、撒上欧芹叶立即上桌——cevapi的汁水应该浸透somun。","en":"Make the meat mixture; in a wide bowl combine the minced beef, minced lamb, garlic-salt paste, chilled sparkling water, baking soda, salt, pepper, paprika, and marjoram; knead vigorously with your hand for 4–5 minutes — the mixture should become noticeably sticky and start to pull together; this long knead and the bicarbonate are what give cevapi their characteristic springy bounce. Cover the bowl with cling film and rest the mixture in the fridge for at least 4 hours, ideally 12–24 hours; the flavour matures and the proteins relax. Wet your hands with cold water; take a tablespoon-sized portion of meat (about 35–40 g) and roll it between your palms into a finger-shaped cylinder about 7–8 cm long and 2 cm thick; repeat with the remaining meat to make about 24 cevapi (6 per person); arrange on a tray as you go. Chill the shaped cevapi for at least 20 minutes (up to 4 hours) to firm — they hold their shape better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 220°C surface); brush the cevapi very lightly with oil — barely a glaze; the grill should hiss but not smoke aggressively. Grill the cevapi for 8–10 minutes total, turning every 2 minutes onto all four sides, until the surface is mahogany brown with crisp edges and the centre reaches 65°C (they continue cooking on the plate); do not press them down; the goal is juicy, springy interiors. While the cevapi rest for 2 minutes, warm the somun (or pittas) on the grill 30 seconds per side until just puffed and lightly charred; split each one open along the seam to make a pocket. Pile 6 cevapi inside each warm flatbread (or arrange 6 on each plate beside the bread); spoon 1–2 tablespoons of ajvar to one side, add a generous knob of kajmak (or crème fraîche), and a small mound of diced raw red onion; scatter parsley leaves and serve immediately — the cevapi juices should soak into the somun."}},{"id":147,"origin":{"zh":"加纳","en":"Ghana","ro":"Ghana"},"name":{"zh":"富富","en":"Fufu","ro":"Fufu"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"zh":["700克新鲜木薯，去皮切成5厘米块（或500克预先去皮的冷冻木薯，化冻）","500克半熟大蕉，约3根大蕉，去皮切成5厘米块（黄皮带黑斑能在甜与淀粉之间取得平衡）","1汤匙细海盐用于煮水","2升冷水用于煮制","约150毫升保留的热煮水，盛在壶中保持温热","1汤匙中性油（棕榈油或葵花籽油），用来涂抹手和盛盘碗","一大锅热的西非汤（600毫升–1升 light soup、棕榈籽汤、花生汤或egusi汤），用于配餐","新鲜scotch bonnet辣椒切片，给想要更辣的人","烤花生或捣碎的花生，用于撒在汤上（可选）"],"en":["700 g fresh cassava root, peeled and cut into 5 cm chunks (or 500 g pre-peeled frozen cassava chunks, thawed)","500 g semi-ripe plantains, about 3 large, peeled and cut into 5 cm chunks (yellow skin streaked with black gives the right balance of sweet and starchy)","1 tbsp fine sea salt for the cooking water","2 litres cold water for boiling","About 150 ml hot cooking water reserved from the pot, kept warm in a jug","1 tbsp neutral oil (palm or sunflower), for oiling hands and the serving bowl","1 large pot of hot West African soup (600 ml–1 L of light soup, palmnut, groundnut, or egusi), for serving","Sliced fresh scotch bonnet chilli, for those who want extra heat","Roasted peanuts or crushed groundnuts, to scatter over the soup (optional)"],"ro":["700 g manioc proaspăt, curățat și tăiat bucăți de 5 cm (sau 500 g cassava decongelată, deja curățată)","500 g banane plantain semi-coapte, aproximativ 3 mari, decojite și tăiate bucăți de 5 cm (coaja galbenă cu pete negre dă echilibrul potrivit între dulce și amidonos)","1 lingură sare fină de mare pentru apa de fierbere","2 litri apă rece pentru fierbere","Aproximativ 150 ml apă fierbinte de fierbere păstrată separat, ținută caldă într-un vas","1 lingură ulei neutru (palmier sau floarea-soarelui), pentru a unge mâinile și bolul de servit","O cratiță mare cu supă vest-africană caldă (600 ml–1 L de light soup, palmnut, groundnut sau egusi), pentru servit","Ardei iute scotch bonnet feliat, pentru cei care vor mai mult picant","Arahide prăjite sau pisate, pentru presărat peste supă (opțional)"]},"howIsMade":{"zh":"处理木薯、在冷水下冲洗木薯块去除沙土、用刀沿长方向划开棕色厚皮，连同粉色内层一起剥下，露出白色芯、把每块中央的纤维芯切除丢弃。在5升厚锅中放入处理好的木薯块、大蕉块、1汤匙盐和2升冷水、中大火煮至微沸，转中小火煮30–40分钟，直到两者都用叉子轻松刺穿——木薯应像煮熟的土豆一样的口感。倒入滤网沥水，但留至少250毫升热煮水于壶中备用、挑出并丢弃任何可见的纤维。捣fufu、传统方法：把热的木薯和大蕉分批放入抹了几滴油的大木臼中、用长木杵有节奏地捣，另一人（手轻微抹油）在每次捣击之间翻动并聚拢糊状、每批工作8–10分钟，直到糊状致密、完美光滑、弹性明显——不含颗粒。无臼方法：把热木薯和大蕉放入坚固的厨师机搭配面团钩、低速1分钟把块状打碎，再调中速6–8分钟，每2分钟刮一次碗壁，直到面团在钩上聚成一个有弹性的整体、如太干，每次加一汤匙热煮水——目标是光亮、有弹性，但不湿。测试质地、掐一小块（约50克）在抹了油的手掌间搓成光滑的小球、表面应当光亮无裂纹，球体应能在盘上保持形状不塌陷不开裂、如开裂再加一勺热水；如塌陷再揉2分钟。用抹了油的手把fufu分成份：4个约250克的大球（或8个传统单人小球）、每个球放入轻抹油的宽口碗中以防粘连、用湿布盖住直到上桌——fufu接触空气会很快变硬。立即上桌、把热的西非汤（light soup、棕榈籽汤、花生汤或egusi）盛入宽碗，围绕每个fufu球、吃法：用右手掐一小块fufu，用拇指按出凹陷形成小杯，用它舀起汤汁——fufu不咀嚼，整个吞下，让汤的味道把它送下去、按口味撒切碎的scotch bonnet辣椒和烤花生。","en":"Prepare the cassava; wash the cassava chunks under cold water to remove any clinging grit; with a paring knife slit the thick brown skin lengthwise, then peel it away (along with the pink underlayer) to expose the white core; cut out the fibrous central string from each piece and discard. In a heavy 5-litre pot, combine the peeled cassava chunks, the plantain chunks, the 1 tbsp salt, and the 2 litres cold water; bring to a gentle boil over medium-high heat, then reduce to medium-low and cook for 30–40 minutes, until both cassava and plantain are fork-tender — the cassava should feel like a cooked potato when pierced. Drain into a colander but reserve at least 250 ml of the hot cooking liquid in a jug for later; pick out and discard any visible fibres or strings. Pound the fufu; traditional method: transfer the hot cassava-plantain mixture in batches to a heavy wooden mortar lubricated with a few drops of oil; with a long wooden pestle, pound rhythmically while a second person (lightly oiled hands) turns and gathers the mass between strokes; work for 8–10 minutes per batch until the paste is dense, perfectly smooth, and noticeably elastic — no lumps remain. Mortar-free method: place the hot cassava and plantain together in a sturdy stand mixer with the dough-hook attachment; run at low speed for 1 minute to break down the chunks, then increase to medium and beat for 6–8 minutes, scraping the bowl every 2 minutes, until the mass forms a single elastic dough around the hook; add a tablespoon of reserved hot cooking water at a time if it is too dry — the goal is glossy and elastic without being wet. Test the texture; pinch off a small piece (about 50 g) and roll it in lightly oiled palms into a smooth ball; the surface should be glossy and seamless, and the ball should hold its shape on a plate without sagging or cracking; if it cracks, work in another spoonful of hot water; if it slumps, knead for another 2 minutes. Shape the serving portions with lightly oiled hands: form 4 large balls of about 250 g each (or 8 smaller balls for traditional individual servings); place each ball in a slightly oiled wide bowl so it does not stick; cover with a damp cloth until ready to serve — fufu hardens quickly when exposed to air. Serve immediately; ladle hot West African soup (light soup, palmnut, groundnut, or egusi) into a wide soup bowl around each fufu ball; eat by pinching off a small piece of fufu with the right hand, pressing a depression into it with the thumb to form a cup, and using it to scoop up the soup — do not chew the fufu, swallow it whole so the flavour of the soup carries it down; scatter chopped scotch bonnet and roasted peanuts to taste."}},{"id":148,"origin":{"zh":"格鲁吉亚","en":"Georgia","ro":"Georgia"},"name":{"zh":"格鲁吉亚饺子","en":"Khinkali","ro":"Khinkali"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["500克中筋面粉，另备少量擀面用","250毫升冷水","1个大鸡蛋，轻轻打散（可选——一些格鲁吉亚家庭用鸡蛋让面团更软）","1茶匙细海盐用于面团","1汤匙中性油用于面团","500克粗剁牛肉（约15%脂肪）","200克粗剁猪肩肉（或全部用700克牛肉，结果更瘦）","1个大洋葱（约200克），切极细末——不要擦丝，质地很重要","3瓣大蒜，切细末","20克新鲜香菜，切细——梗和叶","1茶匙磨碎的孜然+1茶匙现磨黑胡椒+0.5茶匙khmeli suneli（或替代为0.25茶匙葛缕子+0.25茶匙磨碎的胡芦巴）","1.5茶匙细海盐用于馅料","200毫升冰镇牛高汤或冷水（煮制时缓慢释放蒸汽——这是著名汤汁口袋的秘密）","1汤匙粗海盐用于煮饺水","餐桌上撒用的足量现磨黑胡椒"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","250 ml cold water","1 large egg, lightly beaten (optional — some Georgian families use an egg for a softer dough)","1 tsp fine sea salt for the dough","1 tbsp neutral oil for the dough","500 g coarsely minced beef (around 15% fat)","200 g coarsely minced pork shoulder (or 700 g all beef for a leaner result)","1 large onion (about 200 g), very finely diced — do NOT grate, the texture matters","3 garlic cloves, finely minced","20 g fresh coriander, finely chopped — stems and leaves","1 tsp ground cumin + 1 tsp freshly ground black pepper + 0.5 tsp khmeli suneli (or 0.25 tsp caraway + 0.25 tsp ground fenugreek as substitute)","1.5 tsp fine sea salt for the filling","200 ml ice-cold beef stock or cold water (releases steam slowly during boiling — this is what creates the famous broth pocket)","1 tbsp coarse sea salt for the cooking water","Plenty of freshly cracked black pepper, to scatter at the table"],"ro":["500 g făină albă obișnuită, plus pentru întins","250 ml apă rece","1 ou mare, bătut ușor (opțional — unele familii georgiene folosesc un ou pentru un aluat mai moale)","1 linguriță sare fină de mare pentru aluat","1 lingură ulei neutru pentru aluat","500 g vită tocată grosier (în jur de 15% grăsime)","200 g umăr de porc tocat grosier (sau 700 g doar vită pentru un rezultat mai slab)","1 ceapă mare (aproximativ 200 g), tocată foarte fin — NU rasă, textura contează","3 căței de usturoi, tocați fin","20 g coriandru proaspăt, tocat fin — tulpini și frunze","1 linguriță chimion măcinat + 1 linguriță piper negru proaspăt măcinat + 0,5 linguriță khmeli suneli (sau 0,25 linguriță chimion negru + 0,25 linguriță schinduf măcinat ca substitut)","1,5 lingurițe sare fină de mare pentru umplutură","200 ml supă de vită rece ca gheața sau apă rece (eliberează aburi încet în timpul fierberii — acesta este secretul pungii de bulion)","1 lingură sare grunjoasă de mare pentru apa de fierbere","Mult piper negru proaspăt măcinat, pentru presărat la masă"]},"howIsMade":{"zh":"面团：在大碗中将500克面粉与1茶匙盐混合、逐渐倒入250毫升冷水（可选打入1个鸡蛋+1汤匙油），用叉子搅拌，然后在台面上揉8–10分钟，直到面团光滑、紧实、有弹性——要够硬才能擀薄不破、盖上保鲜膜，室温静置30分钟。馅料：在碗中用手将500克牛肉+200克粗剁猪肉与200克切极细末的洋葱、3瓣大蒜、20克切碎的香菜、1茶匙孜然、1茶匙胡椒、0.5茶匙khmeli suneli和1.5茶匙盐混合、慢慢倒入200毫升冰镇高汤，每次50毫升，每次加完搅拌——馅料应该松散湿润但不积液、盖好冷藏30分钟。擀皮：把面团分成4块、一次操作1块（其余盖好）、在轻撒面粉的台面上擀成2毫米薄片、用茶碟或大杯切出12–14厘米直径的圆片、收起边角料，简单揉一下重新擀开。包制：把圆片放在掌心，中间放约30毫升（2汤匙）馅料、用另一只手在馅料周围打18–20个褶，用拇指和食指捏住每个褶并轻轻向中心扭转、最后把所有褶在顶部聚拢，把尖端——尾巴——拧紧封口、把饺子放在撒了面粉的台面上。煮水：在大锅中将4升水煮至剧烈翻滚，加入1汤匙粗盐。煮制：每次往沸水中下5–6个饺子（不要拥挤）、一旦浮起（2–3分钟后），开始计时：再煮8–10分钟、总共12–14分钟、当面皮褶变得半透明、可以看到里面的汤汁在动时即熟。取出：用漏勺捞出，稍微沥水，摆在温热的盘中、立即在顶部撒上充足的现磨黑胡椒、不蘸任何蘸料——格鲁吉亚饺子就是这么吃。吃法：用手指捏住饺子的尾巴，稍微倾斜，在接缝处咬一个小口，先吸里面的热汤再咬开避免溢出、然后吃掉其余部分，把拧紧的尾巴留在盘子上、剩下的尾巴数量=吃了几个。","en":"DOUGH: mix 500 g flour with 1 tsp salt in a large bowl; gradually pour in 250 ml cold water (and optionally 1 beaten egg + 1 tbsp oil), stirring with a fork, then knead on the bench 8–10 minutes until the dough is smooth, firm and elastic — it needs to be tough enough to roll thin without tearing; cover with film and rest 30 minutes at room temperature. FILLING: in a bowl, mix by hand 500 g beef + 200 g pork coarse-mince with 200 g very finely diced onion, 3 garlic cloves, 20 g chopped coriander, 1 tsp cumin, 1 tsp black pepper, 0.5 tsp khmeli suneli and 1.5 tsp salt; slowly pour in 200 ml ice-cold stock, 50 ml at a time, mixing after each addition — the filling should be loose and wet but not soupy; cover and chill 30 minutes. ROLLING: divide the dough into 4 pieces; work one piece at a time (keep the rest covered); roll out to a 2 mm thin sheet on a lightly floured surface; cut 12–14 cm diameter circles with a saucer or large glass; gather scraps, knead briefly and roll again. SHAPING: place a circle in your palm, put about 30 ml (2 tbsp) of filling in the centre; with the other hand, form 18–20 pleats around the filling, pinching each pleat between thumb and forefinger and twisting it gently toward the centre; at the end, gather all pleats at the top and twist the tip — the tail — to seal; set the khinkali on a floured surface. COOKING WATER: bring 4 litres of water to a vigorous rolling boil in a large pot and add 1 tbsp coarse salt. BOILING: drop 5–6 khinkali at a time into the boiling water (do not crowd); the moment they float to the surface (after 2–3 minutes), start your timer: boil another 8–10 minutes; total 12–14 minutes; they are done when the pleats turn translucent and you can see the broth moving inside. REMOVING: lift them out with a slotted spoon, let drain briefly and arrange on a warm plate; immediately scatter plenty of freshly cracked black pepper over the top; no sauce — khinkali are eaten plain. HOW TO EAT: hold the khinkali by the tail with your fingers, tilt slightly and bite a small hole near the seam, then sip the hot broth from inside first before it spills; then eat the rest of the dumpling, leaving the twisted tail on the plate; the number of tails left = how many you ate."}},{"id":149,"origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"波佐列汤","en":"Pozole","ro":"Pozole"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":6,"tipType":"meat","pairingsType":"mexican","ingredients":{"zh":["1.2公斤去骨猪肩肉，切成4厘米方块","500克猪颈骨或猪尾骨（让汤更浓郁）","1个大白洋葱对半切开，带皮（为了上色）+1个小洋葱切细末用于上菜","8瓣大蒜（6瓣用于汤底，2瓣用于辣椒酱）","3片月桂叶","1汤匙粗盐用于汤底+按口味加盐","4升冷水用于汤底","800克罐装hominy玉米，沥干并冲洗（或250克干燥hominy，浸泡过夜并另外煮熟）","6个干瓜希略辣椒，去蒂去籽","4个干安乔辣椒，去蒂去籽","2个干阿尔波辣椒（可选，增加辣度）","1茶匙磨碎的孜然","1茶匙干燥的墨西哥牛至","200克绿卷心菜切细丝，上菜用","150克红萝卜切薄片","4–6个青柠切瓣","12片tostadas（脆玉米饼）","餐桌上撒用的新鲜或干燥牛至"],"en":["1.2 kg boneless pork shoulder, cut into 4 cm cubes","500 g pork neck bones or pork tail (for a richer broth)","1 large white onion halved, skin on (for color) + 1 small onion finely diced for serving","8 garlic cloves (6 for the broth, 2 for the chili sauce)","3 bay leaves","1 tbsp coarse salt for the broth + salt to taste","4 litres cold water for the broth","800 g canned hominy, drained and rinsed (or 250 g dried hominy soaked overnight and boiled separately)","6 dried guajillo chilies, stemmed and deseeded","4 dried ancho chilies, stemmed and deseeded","2 dried árbol chilies (optional, for heat)","1 tsp ground cumin","1 tsp dried Mexican oregano","200 g green cabbage, finely shredded for serving","150 g red radishes, thinly sliced","4–6 limes cut into wedges","12 tostadas (crisp corn tortillas)","Fresh or dried oregano to scatter at the table"],"ro":["1,2 kg umăr de porc dezosat, tăiat în cuburi de 4 cm","500 g oase de porc cu carne (gât sau coadă) pentru un bulion mai bogat","1 ceapă albă mare tăiată în jumătăți (cu coajă, pentru culoare) + 1 ceapă mică tocată fin pentru servire","8 căței de usturoi (6 pentru bulion, 2 pentru sosul de ardei)","3 frunze de dafin","1 lingură sare grunjoasă pentru bulion + sare după gust","4 litri apă rece pentru bulion","800 g hominy din conservă, scurs și clătit (sau 250 g hominy uscat înmuiat peste noapte și fiert separat)","6 ardei guajillo uscați, decotorați și fără semințe","4 ardei ancho uscați, decotorați și fără semințe","2 ardei de árbol uscați (opțional, pentru iuțeală)","1 linguriță chimion măcinat","1 linguriță oregano mexican uscat","200 g varză verde tocată mărunt, pentru servire","150 g ridichi roșii feliate subțire","4–6 lime tăiate în sferturi","12 tostadas (lipii de porumb crocante)","Oregano proaspăt sau uscat de presărat la masă"]},"howIsMade":{"zh":"汤底：在大汤锅里放入1.2公斤切块猪肩肉+500克猪骨、1个对半切开的洋葱（带皮）、6瓣大蒜、3片月桂叶和1汤匙盐、加4升冷水盖过、煮沸后前5分钟撇去浮沫，然后转小火慢炖。炖猪肉：不盖盖子炖1.5–2小时，直到肉用叉子可以撕开、捞出肉和骨头，用两把叉子粗略撕开肉，备用、过滤汤汁（约3.5升），其余丢弃。烘烤辣椒：用中火加热干燥的平底锅、烘烤6个瓜希略+4个安乔+2个阿尔波辣椒（可选），用锅铲压平，每面30秒，直到散发香味并稍微起泡——不要烤焦，否则汤会变苦、放入碗中，用沸水盖过，浸泡15分钟直到变软。辣椒酱：将浸泡好的辣椒倒入搅拌机，加入2瓣大蒜、1茶匙孜然、1茶匙牛至和500毫升温汤、高速搅打2–3分钟直到完全细滑、用细筛过滤到碗中，按压果肉过筛——丢弃残留的皮屑。合并：将过滤后的辣椒酱倒回汤锅、加入撕开的肉和800克沥干的hominy玉米、煮沸后不盖盖子炖30–40分钟，偶尔搅拌，直到汤汁略稠、味道融合、试味并调整盐——应该浓郁鲜美。准备配菜：当波佐列汤炖煮时，将200克卷心菜切细丝，将150克萝卜切薄片，将1个洋葱切细末，将4–6个青柠切瓣，准备牛至叶、每样分别放在桌上的小碗里。玉米饼：将12片tostadas在干锅中每面加热30秒，直到酥脆且微微烤色、放入桌上的篮子里。上菜：将波佐列汤舀入深碗里、每位客人自行搭配自己的碗：一把卷心菜、撒上萝卜片、一撮洋葱和牛至、挤一些青柠汁、tostadas放在旁边——掰碎放入汤中或用作勺子舀取、立刻趁热享用。","en":"BROTH BASE: place 1.2 kg cubed pork shoulder + 500 g pork bones, 1 halved onion (skin on), 6 garlic cloves, 3 bay leaves and 1 tbsp salt in a large stockpot; cover with 4 litres of cold water; bring to a boil, skim the foam for the first 5 minutes, then reduce to a gentle simmer. SIMMER THE PORK: simmer uncovered 1.5–2 hours until the pork is fork-tender; lift out meat and bones, shred the meat coarsely with two forks, set aside; strain the broth (~3.5 L) and discard the solids. TOAST THE CHILIES: heat a dry skillet over medium heat; toast 6 guajillo + 4 ancho + 2 árbol chilies (optional), pressing them down with a spatula, 30 seconds per side until fragrant and lightly blistered — do not burn or the broth will turn bitter; transfer to a bowl, cover with boiling water, and soak 15 minutes until softened. CHILI SAUCE: transfer the soaked chilies to a blender with 2 garlic cloves, 1 tsp cumin, 1 tsp oregano and 500 ml of the warm broth; blend on high 2–3 minutes until completely smooth; strain the puree through a fine sieve into a bowl, pressing the pulp through — discard the skin bits left behind. COMBINE: pour the strained chili sauce back into the broth pot; add the shredded pork and 800 g drained hominy; bring to a simmer and cook uncovered 30–40 minutes, stirring occasionally, until the broth thickens slightly and the flavours meld; taste and adjust salt — it should be deeply savoury. PREP THE GARNISHES: while the pozole simmers, finely shred 200 g cabbage, thinly slice 150 g radishes, finely dice 1 onion, cut 4–6 limes into wedges, prepare oregano; arrange each in small bowls on the table. TOSTADAS: warm 12 tostadas in a dry skillet 30 seconds per side until crisp and lightly toasted; place in a basket for the table. SERVE: ladle the pozole into deep bowls; each guest customises their bowl: a handful of cabbage, scattering of radish, pinch of onion and oregano, squeeze of lime; tostadas eaten alongside — broken into the broth or used to scoop; eaten immediately while piping hot."}},{"id":150,"origin":{"zh":"危地马拉","en":"Guatemala","ro":"Guatemala"},"name":{"zh":"瓜地马拉炖肉","en":"Pepian","ro":"Pepian"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"zh":["1.2公斤带骨鸡腿和小腿（约8块）","1.5升冷水+1茶匙盐用于焯鸡肉","100克生去壳南瓜籽（pepitas）","50克芝麻","4个干瓜希略辣椒，去蒂去籽","2个干安乔或帕西亚辣椒，去蒂去籽","1个干奇波特雷辣椒（可选，增加烟熏味）","4个中等大小番茄（约500克），对半切开","4个绿番茄tomatillos（约200克），去皮对半切开","1个中等洋葱（约150克），切成四瓣","5瓣未去皮大蒜","1根锡兰肉桂棒（约5厘米）","2粒整丁香","1茶匙黑胡椒粉+0.5茶匙多香果粉","1张玉米饼撕成碎片（用于增稠）","200克佛手瓜（güisquil）或西葫芦替代，去皮切2厘米方块","300克土豆，去皮切2厘米方块","2汤匙植物油用于炒酱料","2汤匙新鲜香菜末，用于装饰","盐调味","500克煮熟的白米饭+热玉米饼用于上菜"],"en":["1.2 kg bone-in chicken thighs and drumsticks (about 8 pieces)","1.5 L cold water + 1 tsp salt for poaching","100 g raw hulled pumpkin seeds (pepitas)","50 g sesame seeds","4 dried guajillo chilies, stemmed and deseeded","2 dried ancho or pasilla chilies, stemmed and deseeded","1 dried chipotle chili (optional, for smokiness)","4 medium tomatoes (~500 g), halved","4 tomatillos (~200 g), husked and halved","1 medium onion (~150 g), quartered","5 unpeeled garlic cloves","1 Ceylon cinnamon stick (~5 cm)","2 whole cloves","1 tsp ground black pepper + 0.5 tsp ground allspice","1 corn tortilla, torn into pieces (for thickening)","200 g güisquil (chayote squash) or zucchini, peeled and cubed 2 cm","300 g potatoes, peeled and cubed 2 cm","2 tbsp vegetable oil for cooking the paste","2 tbsp fresh cilantro, finely chopped, to garnish","Salt to taste","500 g cooked white rice + warm tortillas to serve"],"ro":["1,2 kg pulpe și pulpe inferioare de pui cu os (aproximativ 8 bucăți)","1,5 L apă rece + 1 linguriță sare pentru fierberea puiului","100 g semințe crude de dovleac decojite (pepitas)","50 g semințe de susan","4 ardei guajillo uscați, decotorați și fără semințe","2 ardei ancho sau pasilla uscați, decotorați și fără semințe","1 ardei chipotle (opțional, pentru afumare)","4 roșii medii (~500 g), tăiate în jumătăți","4 tomatillos (~200 g), curățați de coajă și tăiați în jumătăți","1 ceapă medie (~150 g), tăiată în sferturi","5 căței de usturoi, necurățați","1 batjoc de scorțișoară Ceylon (~5 cm)","2 cuișoare întregi","1 linguriță piper negru măcinat + 0,5 linguriță ienibahar măcinat","1 tortilla de porumb, ruptă în bucăți (pentru îngroșare)","200 g chayote (sau dovlecel ca substitut), curățat și tăiat cuburi de 2 cm","300 g cartofi, curățați și tăiați cuburi de 2 cm","2 linguri ulei vegetal pentru sotare","2 linguri coriandru proaspăt, tocat fin, pentru ornare","Sare după gust","500 g orez alb gătit + tortillas calde pentru servire"]},"howIsMade":{"zh":"焯鸡肉：将1.2公斤鸡肉放入大锅中，加1.5升冷水和1茶匙盐、煮沸后撇去浮沫，转小火慢炖、煮25–30分钟，直到鸡肉刚熟（流出清汁）、捞出鸡肉到盘中，保留汤汁（约1.2升）。烘烤种子：在中火上用干燥的平底锅烘烤100克南瓜籽，不停搅拌3–4分钟，直到膨胀变金棕色——不要烤焦、倒入碗中、在同一锅中烘烤50克芝麻1–2分钟，直到金黄飘香，不停搅拌、加入同一碗中。烧焦蔬菜：在中高火上用干平底锅或comal，烧焦4个切半番茄（先切口朝下）、4个切半tomatillos、1个切四瓣洋葱和5瓣未去皮大蒜、偶尔翻动8–10分钟，直到表皮局部发黑且蔬菜变软、冷却后剥蒜皮。烘烤辣椒和香料：在同一锅中，用锅铲压平4个瓜希略+2个安乔+1个奇波特雷（可选）辣椒，每面短暂烘烤20–30秒至香气出来——不要烤焦、倒入碗中，用沸水盖过，浸泡15分钟、在同一锅中，短暂烘烤1根肉桂、2粒丁香、1茶匙胡椒和0.5茶匙多香果30秒、把撕碎的玉米饼每面烘烤30秒至酥脆。搅打成酱：在搅拌机里，加入沥干的辣椒、烧焦的蔬菜、去皮蒜、烘烤过的种子、玉米饼碎片和500毫升鸡汤、高速搅打3–4分钟至完全细滑——如果想要丝滑口感，过细筛网。煮酱：在锅中以中火加热2汤匙油、倒入搅打好的酱料——小心，会溅、煮10分钟，用木勺频繁搅拌，直到酱料颜色加深、生味消失、酱料应能覆盖勺背。炖鸡肉：将鸡肉块放回锅中，倒入剩余的700毫升汤汁+200克佛手瓜+300克土豆块、半盖锅小火炖25–30分钟，直到土豆和佛手瓜软烂、鸡肉完全吸收酱料、偶尔搅拌以防粘锅、调整盐量。上菜：将pepian舀入深盘，铺在清蒸白米饭上、每份撒上新鲜香菜，可挤上青柠汁（可选）、配热玉米饼上桌，用饼蘸酱。","en":"POACH THE CHICKEN: place 1.2 kg chicken pieces in 1.5 L cold water with 1 tsp salt in a large pot; bring to a boil, skim the foam, then reduce to a gentle simmer; cook 25–30 minutes until the chicken is just cooked through (juices run clear); remove the chicken to a plate and reserve the broth (~1.2 L). TOAST THE SEEDS: in a dry skillet over medium heat, toast 100 g pumpkin seeds, stirring constantly, 3–4 minutes until they puff up and turn golden brown — do not burn; transfer to a bowl; in the same skillet, toast 50 g sesame seeds 1–2 minutes until golden and fragrant, stirring constantly; add to the same bowl. CHAR THE VEGETABLES: in a dry skillet or comal over medium-high heat, char 4 halved tomatoes (cut side down first), 4 halved tomatillos, 1 quartered onion, and 5 unpeeled garlic cloves; turn occasionally for 8–10 minutes until the skins are blackened in spots and the vegetables soften; peel the garlic after they cool. TOAST THE CHILIES AND SPICES: in the same skillet, briefly toast 4 guajillo + 2 ancho + 1 chipotle (optional) chilies, pressing them flat with a spatula, 20–30 seconds per side until fragrant — do not burn; transfer to a bowl and cover with boiling water; soak 15 minutes; in the same skillet, briefly toast 1 cinnamon stick, 2 cloves, 1 tsp pepper, and 0.5 tsp allspice for 30 seconds; toast the torn tortilla pieces 30 seconds per side until crisp. BLEND THE PASTE: in a blender, combine the drained chilies, the charred vegetables, peeled garlic, toasted seeds, toasted tortilla pieces, and 500 ml of the chicken broth; blend on high 3–4 minutes until the paste is completely smooth — strain through a fine sieve if you want it silky. COOK THE SAUCE: heat 2 tablespoons of oil in the pot over medium heat; pour in the blended paste — be careful, it will splutter; simmer 10 minutes, stirring frequently with a wooden spoon, until the sauce darkens and the rawness cooks off; the sauce should coat the back of the spoon. STEW THE CHICKEN: return the chicken pieces to the pot, then pour in the remaining 700 ml broth + 200 g chayote + 300 g potato cubes; simmer gently, partially covered, 25–30 minutes until the potatoes and chayote are fork-tender and the chicken is fully infused with the sauce; stir occasionally to prevent sticking; adjust salt to taste — the sauce should taste deeply spiced and slightly sweet. SERVE: spoon the pepian into deep plates over a bed of steamed white rice; top each serving with a sprinkle of fresh cilantro and a squeeze of lime (optional); serve with warm corn tortillas on the side for scooping up the sauce."}},{"id":151,"origin":{"zh":"俄罗斯","en":"Russia","ro":"Rusia"},"name":{"zh":"俄式冷汤","en":"Okroshka","ro":"Okroshka"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"zh":["1升原味克非尔（3.2%乳脂），冰镇好","500毫升不含气矿泉水或冷开水，冷却","500克中等大小淀粉土豆（4个），带皮煮熟后去皮切1厘米方块","4个大煮熟的鸡蛋，去壳切1厘米方块","400克黄瓜（3个中等大小），去皮，挖去大种子，切0.5厘米方块","300克煮熟的doktorskaya香肠或熟火腿，切0.5厘米方块","150克红萝卜，去蒂切0.5厘米方块","6根葱（白色和绿色部分分开），切薄片","30克新鲜莳萝，切碎（另外加1汤匙用于装饰）","1汤匙第戎芥末（可选但传统）","1.5茶匙细盐+0.5茶匙现磨黑胡椒","1茶匙糖（平衡克非尔的酸味）","1茶匙柠檬汁或白葡萄酒醋","酸奶油（smetana）用于上菜","冰块和新鲜黑麦面包用于上菜"],"en":["1 L plain kefir (3.2% fat), well chilled","500 ml cold still mineral water (or cold boiled water), chilled","500 g medium starchy potatoes (4 pieces), boiled in skins then peeled and diced 1 cm","4 large hard-boiled eggs, peeled and diced 1 cm","400 g cucumbers (3 medium), peeled, large seeds scooped out, diced 0.5 cm","300 g cooked doktorskaya sausage or boiled ham, diced 0.5 cm","150 g red radishes, trimmed and diced 0.5 cm","6 spring onions (whites and greens kept separate), thinly sliced","30 g fresh dill, finely chopped (plus 1 tbsp to garnish)","1 tbsp Dijon-style mustard (optional but traditional)","1.5 tsp fine salt + 0.5 tsp freshly ground black pepper","1 tsp sugar (balances the kefir tang)","1 tsp lemon juice or white-wine vinegar","Sour cream (smetana) to drizzle when serving","Ice cubes and fresh dark rye bread for serving"],"ro":["1 L chefir simplu 3,2% grăsime, bine răcit","500 ml apă minerală plată rece sau apă fiartă rece, răcită","500 g cartofi medii (4 bucăți) fierți în coajă, decojiți și tăiați cuburi de 1 cm","4 ouă mari fierte tari, decojite și tăiate cuburi de 1 cm","400 g castraveți (3 bucăți medii), decojiți, fără sâmburi mari și tăiați cuburi de 0,5 cm","300 g cârnați doktorskaya sau șuncă fiartă, tăiată cuburi de 0,5 cm","150 g ridichi roșii, tăiate cuburi de 0,5 cm","6 cepe verzi (cu părți albe și verzi separate), feliate subțire","30 g mărar proaspăt, tocat fin (plus 1 lingură pentru ornare)","1 lingură muștar Dijon (opțional, dar tradițional)","1,5 lingurițe sare fină + 0,5 linguriță piper negru proaspăt măcinat","1 linguriță zahăr (echilibrează aciditatea chefirului)","1 linguriță suc de lămâie sau oțet de vin alb","Smântână (smetana) pentru servire","Cuburi de gheață și pâine neagră proaspătă pentru servire"]},"howIsMade":{"zh":"煮土豆和鸡蛋：在一锅冷盐水中，将500克整颗土豆（带皮，刷净）煮20–25分钟至用叉子可轻松刺穿、在第二个锅中，将4个鸡蛋放入冷水，煮沸后再炖9分钟以煮熟、两者沥干，将土豆浸入冷水以便剥皮，将鸡蛋浸入冰水5分钟、剥皮并切成1厘米方块；铺在托盘上冷藏30分钟——混合前所有食材必须冷却。切黄瓜：将400克黄瓜削皮，纵向对半，用勺挖去大颗水分种子，然后切0.5厘米方块——均匀的小方块是关键，大块会下沉破坏汤的口感、用厨房纸吸去多余水分。切蛋白质：将300克熟香肠或熟火腿切成0.5厘米方块——与黄瓜大小相同，使每勺都平衡。切萝卜和葱：将150克萝卜切0.5厘米方块、切6根葱（白色和绿色部分分开）、将30克莳萝切碎，留1汤匙用于装饰、在一个小碗里，用勺背将2汤匙葱白和一小撮盐捣压——释放葱香入汤。调味汁：在大碗里搅匀1升冷克非尔+500毫升冷水+1汤匙芥末+1茶匙柠檬汁+1.5茶匙盐+0.5茶匙胡椒+1茶匙糖、搅打30秒直至均匀，尝味——底料应该酸而微甜，调味足够慷慨，因为切丁食材会稀释它。组合：将所有切丁食材（土豆、鸡蛋、黄瓜、香肠、萝卜、葱绿、葱白泥、莳萝）加入克非尔底料中、用大汤勺轻轻拌匀，均匀分布而不压碎食材。冷藏：盖好将俄式冷汤冷藏至少30分钟（理想1小时），让风味融合且汤冰凉、冷藏不超过3小时——黄瓜会开始出水使汤变稀。上菜：上桌前轻轻搅拌、盛入冰镇的深碗、每碗淋1汤匙酸奶油，加几枝额外莳萝，盛夏每碗加2块冰、立即配新鲜黑麦面包食用；桌上备芥末供喜欢更辛辣口味者使用。","en":"BOIL THE POTATOES AND EGGS: in a pot of cold salted water, boil 500 g whole potatoes (skins on, scrubbed) 20–25 min until fork-tender; in a second pot, place 4 eggs in cold water, bring to a boil, then simmer 9 min for hard-boiled; drain both, cover potatoes with cold water to peel easily, plunge eggs into ice water 5 min; peel and dice both 1 cm; spread on a tray and chill 30 min in the fridge — everything must be cold before mixing. DICE THE CUCUMBERS: peel 400 g cucumbers, halve lengthwise, scoop out any large watery seeds with a spoon, then dice 0.5 cm — the small even cube is essential, larger pieces sink and ruin the soup; pat with paper towel to remove excess water. DICE THE PROTEIN: dice 300 g cooked sausage or boiled ham into 0.5 cm cubes — the same size as the cucumbers so each spoonful balances. DICE RADISH AND ONIONS: trim and dice 150 g radishes 0.5 cm; slice 6 spring onions (whites and greens kept separate); finely chop 30 g dill, reserve 1 tbsp for garnish; in a small bowl, mash 2 tbsp of the spring-onion whites with a pinch of salt using the back of a spoon — this releases their aroma into the soup. THE DRESSING: in a large mixing bowl, whisk together 1 L cold kefir + 500 ml cold water + 1 tbsp mustard + 1 tsp lemon juice + 1.5 tsp salt + 0.5 tsp pepper + 1 tsp sugar; whisk 30 seconds until smooth, then taste — the base should be tangy and slightly sweet, generously seasoned because the diced ingredients will dilute it. ASSEMBLE: add all diced ingredients (potatoes, eggs, cucumbers, sausage, radish, spring-onion greens and mashed whites, dill) to the kefir base; stir gently with a ladle to distribute evenly without crushing anything. CHILL: cover and refrigerate the okroshka 30 minutes minimum (ideally 1 hour) so the flavours mingle and the soup becomes ice-cold; do not chill longer than 3 hours — the cucumbers will start to release water and the soup turns thin. SERVE: stir gently before serving; ladle into deep, well-chilled bowls; top each bowl with 1 tablespoon sour cream, a few extra dill fronds, and 2 ice cubes per bowl in summer heat; serve immediately with fresh dark rye bread on the side; mustard on the table for those who like it sharper."}},{"id":152,"origin":{"zh":"乌兹别克斯坦","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"zh":"抓饭","en":"Plov","ro":"Plov"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"zh":["600克带些脂肪的羊肩肉或牛颈肉，切3厘米方块","100克羊尾油（kurdyuk）以获得正宗风味——或150毫升中性葵花籽油作为替代","500克devzira米或长粒巴斯马蒂米","500克黄胡萝卜（或600克橙胡萝卜），切0.5 × 0.5 × 5厘米火柴粗细的条——不要擦丝","2个大黄洋葱（约300克），切薄片","2整头大蒜（去掉外层皮膜，但保持整头完整）","1汤匙整粒孜然籽（不要磨碎）","1汤匙干小檗果（zira/barbaris）——可选但传统","0.5茶匙姜黄粉（用于上色）","1根整根干红辣椒（可选）","1茶匙黑胡椒粉","1.5汤匙细盐+按口味额外加盐","1.2升沸水（备用）","100克鹰嘴豆，浸泡过夜（可选，塔什干传统风格）","上菜配菜：薄切红洋葱配醋、achichuk番茄黄瓜沙拉、馕饼（non）"],"en":["600 g lamb shoulder or beef chuck with some fat, cut into 3 cm cubes","100 g lamb-tail fat (kurdyuk) for authentic flavour — OR 150 ml neutral sunflower oil as a substitute","500 g devzira or long-grain basmati rice","500 g yellow carrots (or 600 g orange carrots), cut into julienne matchsticks 0.5 × 0.5 × 5 cm — do NOT grate","2 large yellow onions (~300 g), thinly sliced","2 whole heads of garlic (papery outer skins removed but heads intact)","1 tbsp whole cumin seeds (not ground)","1 tbsp dried barberries (zira/barbaris) — optional but traditional","0.5 tsp ground turmeric (for colour)","1 dried whole hot red chili (optional)","1 tsp ground black pepper","1.5 tbsp fine salt + extra to season","1.2 L boiling water (reserve)","100 g chickpeas, soaked overnight (optional, traditional Tashkent style)","To serve: thinly sliced red onion with vinegar, achichuk tomato-cucumber salad, flatbread (non)"],"ro":["600 g umăr de miel sau gulaș de vită cu puțină grăsime, tăiat cuburi de 3 cm","100 g grăsime de coadă de oaie (kurdyuk) — opțional pentru aromă autentică — SAU 150 ml ulei neutru de floarea-soarelui ca substitut","500 g orez devzira sau basmati cu bob lung","500 g morcovi galbeni (sau 600 g morcovi portocalii), tăiați julien în bețișoare de 0,5 × 0,5 × 5 cm — NU dați prin răzătoare","2 cepe galbene mari (~300 g), feliate subțire","2 căpățâni de usturoi întregi (cu coaja exterioară curățată, dar capul păstrat întreg)","1 lingură semințe de chimion întregi (nu măcinate)","1 lingură fructe uscate de cătină (zira/barbaris) — opțional, tradițional","0,5 linguriță turmeric măcinat (pentru culoare)","1 ardei roșu iute uscat întreg (opțional)","1 linguriță piper negru măcinat","1,5 linguri sare fină + sare după gust","1,2 L apă clocotită (rezerve)","100 g năut, înmuiat peste noapte (opțional, tradițional Tashkent)","Pentru servire: ceapă roșie feliată subțire cu oțet, salată de roșii cu castraveți (achichuk), pâine plată non"]},"howIsMade":{"zh":"浸泡米饭：用冷水洗500克米饭4–5次，直到水变清、然后在温盐水（每升1茶匙盐）中浸泡1小时、这一步对抓饭至关重要——米粒保持分离并均匀吸收汤汁、加入锅前才沥干。熬油：在重铁kazan或荷兰锅中以中火熬制100克羊尾油，直到油渣呈金黄色（约8分钟），然后用漏勺取出、如果用植物油：加热150毫升油直到闪光并轻微冒烟（高火约3分钟）——这对消除生味必不可少。煎肉：转大火，将600克肉块单层放入热油中、不要翻动，每面煎2–3分钟，总共8–10分钟，至各面深褐色、取出肉放在盘子上。洋葱+胡萝卜：在剩余的油中加入300克切片洋葱，搅拌煎5–6分钟至金黄色、把肉放回锅中，将500克切丝胡萝卜单层铺在顶部——前5分钟不要搅拌（让胡萝卜蒸熟）、然后轻轻搅拌，再煮8–10分钟，直到胡萝卜变软、变金黄、开始焦糖化。汤底（zirvak）：倒入1.2升沸水（应覆盖肉和胡萝卜1厘米）、加入1汤匙整粒孜然（先在掌心摩擦释放精油）、1汤匙小檗果、0.5茶匙姜黄、1根干辣椒、1茶匙胡椒、100克鹰嘴豆、1.5汤匙盐和2整头大蒜（推入中央）、煮沸后转小火，不盖锅煮30分钟——这是zirvak（汤底）、汤汁应该感觉稍微调味过重；米饭会平衡它。加米饭：小心沥干浸泡的米饭，均匀铺在zirvak上（不要拌入）、米饭应该刚刚浸没——如果没有，小心加沸水、转大火不盖锅煮10–12分钟，直到可见的水减少到米饭表面（用筷子检查）、用漏勺将米饭压平，但绝不与下面的肉层混合。盖上盖+蒸：当表面水蒸发，米饭表面出现小气孔时，将米饭堆成圆顶形，用木勺把手戳4–5个深至底部的孔（让蒸汽逸出），将火调至最低，盖上严密的锅盖（在锅盖下放一块干净厨房布吸收冷凝水），煮25分钟、然后离火，盖上盖静置15分钟——不要打开盖子。上菜：揭开锅盖，取出蒜头和辣椒、用勺子轻轻挖，把米饭抬起，将底部的肉和胡萝卜带到顶部，转移到大公盘时混合、把肉和蒜放在中央，米饭围绕周围、立即配薄切红洋葱（加醋）、新鲜番茄沙拉和馕饼一起上菜。","en":"SOAK THE RICE: wash 500 g rice in cold water 4–5 times until the water runs clear, then soak it in warm salted water (1 tsp salt per litre) for 1 hour; this step is non-negotiable for plov — the grains stay separate and absorb the broth evenly; drain just before adding to the pot. RENDER THE FAT: in a heavy cast-iron kazan or Dutch oven over medium heat, melt 100 g lamb-tail fat until the cracklings are golden brown (about 8 minutes), then remove them with a slotted spoon; if using oil: heat 150 ml oil until it shimmers and faintly smokes (about 3 minutes at high heat) — essential to neutralize the raw taste. SEAR THE MEAT: raise heat to high and add 600 g cubed meat in a single layer to the hot fat; sear undisturbed 2–3 minutes per side, total 8–10 minutes, until deeply browned on all sides; lift the meat out to a plate. ONION + CARROT: in the remaining fat, add 300 g sliced onion and fry, stirring, 5–6 minutes until golden brown; return the meat and add 500 g julienned carrots in a single layer on top — do NOT stir for the first 5 minutes (this lets the carrots steam); then stir gently and cook another 8–10 minutes until the carrots are wilted, golden, and just starting to caramelize. ZIRVAK (BROTH BASE): pour in 1.2 L boiling water (it should cover the meat and carrots by 1 cm); add 1 tbsp cumin seeds (first rubbed briefly between your palms to release the oils), 1 tbsp barberries, 0.5 tsp turmeric, 1 dried chili, 1 tsp black pepper, 100 g chickpeas, 1.5 tbsp salt, and the 2 whole garlic heads pushed into the centre; bring to a boil, reduce heat to low and simmer uncovered 30 minutes — this is the zirvak; the broth must taste slightly over-seasoned; the rice will tame it. ADD THE RICE: drain the soaked rice carefully and spread it evenly over the zirvak (do not stir it in); the rice should just be submerged — if not, add boiling water carefully; raise heat to high and cook uncovered 10–12 minutes until the visible water has reduced to the surface of the rice (poke with a chopstick to check); tap the rice flat with a slotted spoon but never mix it with the meat layer below. COVER + STEAM: once the surface water has evaporated and small steam holes appear on the rice surface, mound the rice into a dome, poke 4–5 deep holes through to the bottom with the handle of a wooden spoon (for steam to escape), reduce heat to the lowest setting, cover the pot with a tight lid (place a clean kitchen towel under the lid to absorb condensation), and cook 25 minutes; then remove from heat and let rest, covered, 15 minutes — do not lift the lid. SERVE: uncover and lift out the garlic heads and chili; gently dig down with a spoon, lifting the rice and bringing the meat and carrots from the bottom to the top, mixing as you transfer to a large communal platter; arrange the meat and garlic on top in the centre, surrounded by rice; serve immediately with sliced red onion sprinkled with vinegar, fresh tomato salad, and flatbread on the side."}},{"id":153,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"zh":"斯洛文尼亚","en":"Slovenia","ro":"Slovenia"},"name":{"zh":"斯洛文尼亚核桃卷","en":"Potica","ro":"Potica"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["面团：500克高筋面粉（或面包粉），另备少量用于揉面","7克即用干酵母或21克新鲜酵母","50克细砂糖（1茶匙喂养酵母，其余加入面团）","5克细盐","250毫升温全脂牛奶（38 °C）","100克无盐黄油，融化并冷却至微温","2个大蛋黄+1个全蛋用于面团","1汤匙深色朗姆酒（可选，传统）","1个未涂蜡柠檬的细擦皮","核桃馅：400克去壳核桃细磨（新鲜磨制——预磨的不行）","200毫升热全脂牛奶","150克金合欢蜂蜜（或柔和的花蜜）","100克无盐黄油融化（用于馅料）","100克细砂糖（用于馅料）","2个蛋黄+2个蛋白（分别打发到硬性发泡）","1汤匙深色朗姆酒、1茶匙肉桂粉、0.5茶匙丁香粉、1汤匙新鲜面包屑","完成：1个鸡蛋加1汤匙牛奶搅打（用作刷蛋液）、烘烤后撒糖粉"],"en":["For the dough: 500 g bread flour (or strong all-purpose), plus extra for kneading","7 g instant dry yeast OR 21 g fresh yeast","50 g caster sugar (1 tsp to feed the yeast, the rest in the dough)","5 g fine salt","250 ml warm whole milk (38 °C)","100 g unsalted butter, melted and cooled to lukewarm","2 large egg yolks + 1 whole egg for the dough","1 tbsp dark rum (optional, traditional)","Finely grated zest of 1 unwaxed lemon","For the walnut filling: 400 g finely ground shelled walnuts (freshly ground — pre-ground will not work)","200 ml hot whole milk","150 g acacia honey (or mild floral honey)","100 g unsalted butter, melted, for the filling","100 g caster sugar for the filling","2 large egg yolks + 2 egg whites (whipped to stiff peaks separately)","1 tbsp dark rum, 1 tsp ground cinnamon, 0.5 tsp ground cloves, 1 tbsp fresh breadcrumbs","For finishing: 1 egg beaten with 1 tbsp milk (egg wash), icing sugar to dust after baking"],"ro":["Pentru aluat: 500 g făină pentru pâine (T550), plus pentru frământare","7 g drojdie uscată instant SAU 21 g drojdie proaspătă","50 g zahăr fin (1 linguriță pentru a hrăni drojdia, restul în aluat)","5 g sare fină","250 ml lapte integral cald (38 °C)","100 g unt nesărat topit și răcit la călduț","2 gălbenușuri mari + 1 ou întreg pentru aluat","1 lingură rom întunecat (opțional, tradițional)","Coaja rasă fin de la 1 lămâie netratată","Pentru umplutură: 400 g miez de nucă măcinat fin (proaspăt măcinat, nu pre-măcinat — esențial)","200 ml lapte integral fierbinte","150 g miere de salcâm (sau miere florală blândă)","100 g unt nesărat topit pentru umplutură","100 g zahăr fin pentru umplutură","2 gălbenușuri + 2 albușuri (bătute spumă tare separat)","1 lingură rom întunecat, 1 linguriță scorțișoară măcinată, 0,5 linguriță cuișoare măcinate, 1 lingură pesmet proaspăt","Pentru finisare: 1 ou bătut cu 1 lingură lapte (spălătură), zahăr pudră pentru presărat după coacere"]},"howIsMade":{"zh":"激活酵母：在小碗中将7克即用干酵母（或21克新鲜酵母）溶解在250毫升温牛奶（约38 °C）中，加入1茶匙糖、静置10分钟，直到表面出现奶油状泡沫——如果不起泡，酵母已死，重新开始。面团：在装有面团钩的厨师机中（或手工），将500克面粉与剩余的47克糖、5克盐和柠檬皮屑混合、倒入起泡的酵母牛奶、2个蛋黄+1个全蛋、100克融化冷却的黄油和1汤匙朗姆酒、中速揉10分钟（或手工15分钟），直到面团光滑、有弹性且能干净地从碗壁脱落——应柔软但不粘手、盖上保鲜膜，在温暖处发酵1.5–2小时，直至体积翻倍。核桃馅：将400克新鲜磨碎的核桃放入大碗、倒入200毫升热牛奶、100克融化黄油、150克蜂蜜和100克糖、搅拌均匀以烫熟核桃并溶解糖、冷却10分钟，然后加入2个蛋黄、1汤匙朗姆酒、1茶匙肉桂、0.5茶匙丁香、1汤匙面包屑和一小撮盐、另一个碗中将2个蛋白打到硬性发泡，分3次轻轻拌入核桃混合物——馅料应该松软且可涂抹。擀面团：在干净的茶巾上轻撒面粉，将发酵好的面团倒在上面、轻轻排气，然后擀成60 × 40厘米、4–5毫米厚的薄长方形——从中心向外擀，提起并旋转防止粘连、面团必须足够薄，使烘焙后能看到螺旋，但又足够厚以容纳馅料。涂馅料：将核桃馅均匀铺在擀好的面团上，长边留2厘米的边、用刮刀轻轻铺平——不要过量，馅料应有5–6毫米厚、如果某处过薄，撒一些额外的磨碎核桃。卷起：借助茶巾，从长边将面团紧紧卷起，形成长卷、卷紧但不要紧到压扁馅料、捏住接口处使其密封并塞入两端、长卷应该约60厘米长。入模+二次发酵：将管状potica模具（或24厘米Bundt模或kugelhopf模）涂上黄油并撒上面粉、将卷面接缝向下放入模具，连接两端形成闭合环（捏紧）、盖松，在温暖处再次发酵45–60分钟，直到面团明显涨起，几乎填满模具、同时将烤箱预热至175 °C。烘焙：在顶部刷上蛋液、在175 °C烤箱的中层烤45–55分钟——如果30分钟后顶部上色太快，可松松地盖上铝箔、当签子干净抽出且内部温度达到92–95 °C时即熟、在模具中静置15分钟，然后小心翻到冷却架上完全冷却、切片前慷慨撒上糖粉、室温下与浓咖啡或浓茶一起食用。","en":"ACTIVATE THE YEAST: in a small bowl, dissolve 7 g instant dry yeast (or 21 g fresh yeast) into 250 ml warm milk (~38 °C) with 1 tsp sugar; let stand 10 minutes until a creamy foam appears on top — if it doesn't foam, the yeast is dead, start over. THE DOUGH: in a stand mixer with dough hook (or by hand), combine 500 g flour with the remaining 47 g sugar, 5 g salt, and lemon zest; pour in the foamed yeast-milk, 2 egg yolks + 1 whole egg, 100 g melted-and-cooled butter, and 1 tbsp rum; knead on medium speed 10 minutes (or 15 by hand) until the dough is smooth, elastic, and pulls cleanly from the bowl — it should be soft but not sticky; cover with film and proof in a warm place 1.5–2 hours until doubled. THE WALNUT FILLING: place 400 g freshly ground walnuts in a large bowl; pour over 200 ml hot milk, 100 g melted butter, 150 g honey, and 100 g sugar; stir well to scald the walnuts and dissolve the sugars; cool 10 minutes, then mix in 2 egg yolks, 1 tbsp rum, 1 tsp cinnamon, 0.5 tsp cloves, 1 tbsp breadcrumbs, and a pinch of salt; in a separate bowl, whip 2 egg whites to stiff peaks, then fold them gently into the walnut mixture in 3 additions — the filling should be airy and spreadable. ROLL THE DOUGH: lightly flour a clean tea towel and turn the proofed dough out onto it; punch down gently, then roll out into a thin rectangle 60 × 40 cm and 4–5 mm thick — work from the centre outward, lifting and rotating to prevent sticking; the dough must be thin enough that the spiral is visible after baking, but thick enough to hold the filling. SPREAD THE FILLING: spread the walnut filling evenly over the rolled dough, leaving a 2 cm border along the long edges; pat it gently with a spatula — do not overload, the filling should be 5–6 mm thick; sprinkle a few extra ground walnuts if any spot oozes thin. ROLL UP: using the tea towel to help, roll up the dough tightly from the long side, forming a long log; roll snug but not so tight you compress the filling; pinch the seam closed and tuck in the ends; the log should be about 60 cm long. SHAPE IN MOLD + SECOND PROOF: grease a tubular potica mold (or a 24 cm Bundt pan or a kugelhopf form) thoroughly with butter and dust with flour; lay the log in the mold, seam side down, joining the ends to form a closed ring (pinch them together); cover loosely and proof again in a warm place 45–60 minutes until the dough has risen visibly to almost fill the mold; meanwhile, preheat the oven to 175 °C. BAKE: brush the top with the egg wash; bake on the middle rack of the 175 °C oven 45–55 minutes — cover loosely with foil after 30 min if the top is browning too fast; the potica is done when a skewer comes out clean and the internal temperature reaches 92–95 °C; let it rest 15 minutes in the mold, then carefully invert onto a wire rack to cool completely; dust generously with icing sugar before slicing; serve at room temperature with strong coffee or tea."}},{"id":154,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"zh":"尼日利亚","en":"Nigeria","ro":"Nigeria"},"name":{"zh":"埃古西汤","en":"Egusi soup","ro":"Egusi soup"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["250克生埃古西籽，磨细（或200克预磨埃古西）","600克带骨山羊肉或牛颈肉，切4厘米块","200克烟熏鱼（青花鱼或鲶鱼）——清洗去骨，撕成块（可选，传统）","100克干虾或stockfish，浸泡30分钟撕碎（可选）","1个中等洋葱（约150克），粗切","2个苏格兰帽辣椒（或3个哈瓦那）——根据耐辣度调整","2个红甜椒（约300克），去籽","100毫升红棕榈油","3个新鲜大番茄（约400克）或200克番茄酱混合200毫升水","4瓣大蒜，切细","5厘米新鲜姜，去皮磨碎","2块汤料块（Maggi或类似，10克）","1汤匙磨碎的小龙虾（正宗风味必需）——替代：1汤匙磨碎的干虾","1片月桂叶（或1茶匙磨粉）","200克新鲜菠菜或ugu南瓜叶，洗净粗切","1.5茶匙盐+按口味添加","1汤匙locust beans（iru/dawadawa）——可选，传统约鲁巴","上菜配菜：杵山药、fufu、eba（gari）或煮熟白米饭"],"en":["250 g raw egusi seeds, finely ground (or 200 g pre-ground egusi)","600 g goat meat or beef chuck on the bone, cut into 4 cm pieces","200 g smoked fish (mackerel or catfish) — cleaned, boned, broken into chunks (optional, traditional)","100 g dried prawns or stockfish (panla), soaked 30 min and torn small (optional)","1 medium onion (~150 g), roughly chopped","2 Scotch bonnet peppers (or 3 habaneros) — adjust to heat tolerance","2 red bell peppers (~300 g), seeded","100 ml red palm oil","3 large fresh tomatoes (~400 g) OR 200 g tomato paste blended with 200 ml water","4 garlic cloves, finely minced","5 cm fresh ginger, peeled and grated","2 stock cubes (Maggi or similar, 10 g)","1 tbsp ground crayfish (essential for authentic flavour) — substitute: 1 tbsp ground dried shrimp","1 bay leaf (or 1 tsp ground bay)","200 g fresh spinach or ugu pumpkin leaves, washed and roughly chopped","1.5 tsp salt + more to taste","1 tbsp locust beans (iru/dawadawa) — optional, traditional Yoruba addition","To serve: pounded yam, fufu, eba (gari), or boiled white rice"],"ro":["250 g semințe egusi brute, măcinate fin (sau 200 g egusi pre-măcinat)","600 g carne de capră sau gulaș de vită cu os, tăiată în bucăți de 4 cm","200 g pește afumat (macrou sau somn) — curățat, dezosat, rupt în bucăți (opțional, tradițional)","100 g creveți uscați sau stockfish, înmuiat 30 minute și rupt mic (opțional)","1 ceapă medie (~150 g), tocată grosier","2 ardei iuți Scotch bonnet (sau 3 habanero) — ajustează după toleranța la iuțeală","2 ardei roșii grași (~300 g), fără semințe","100 ml ulei roșu de palmier","3 roșii mari proaspete (~400 g) sau 200 g pastă de roșii amestecată cu 200 ml apă","4 căței de usturoi, tocați fin","5 cm rădăcină de ghimbir proaspăt, curățată și rasă","2 cuburi Maggi sau pentru condimentare (10 g)","1 lingură crayfish măcinat (esențial pentru aroma autentică) — substitut: 1 lingură creveți uscați măcinați","1 frunză de dafin (sau 1 linguriță dafin măcinat)","200 g spanac proaspăt sau frunze de ugu (pumpkin leaves), spălate și tocate","1,5 lingurițe sare + sare după gust","1 lingură semințe de locust (iru/dawadawa) — opțional, tradițional Yoruba","Pentru servire: igname pisată, fufu, eba (gari) sau orez fiert"]},"howIsMade":{"zh":"埃古西籽糊：将250克埃古西籽放入香料研磨机或食品处理器中，搅打30秒至磨细但尚未成糊、在小碗中将其与200毫升温水混合成浓厚的鹰嘴豆泥状糊、静置10分钟充分水化——这是标志性口感的秘密：外部颗粒状，内部奶油状。煮肉：在重锅中，将600克切好的肉与1个切碎洋葱、4瓣大蒜末、磨碎的姜、2块汤料、1茶匙盐和1升水混合、煮沸后盖盖炖40–50分钟（山羊肉需更久），直到肉嫩但不散开、过滤并保留800毫升汤汁、肉放在一边。搅打辣椒酱底：在搅拌机中，将2个红甜椒、2个苏格兰帽辣椒和3个新鲜番茄（或番茄酱加水）混合、搅打1–2分钟至完全细滑、倒入宽底锅中，中火炖15分钟——混合物应减少一半，颜色加深至砖红色、这种浓缩是必不可少的，否则汤会变稀。棕榈油炒底料：在汤锅中以中火加热100毫升棕榈油2分钟至刚刚闪光（不要冒烟——过度加热会破坏风味）、加入浓缩的辣椒-番茄底料，搅拌煎炒8–10分钟，直到油浮上表面且混合物略变暗、这称为\"炒底料\"。加入埃古西：用汤匙取水化的埃古西糊，将其以丸子形式滴入沸腾的辣椒底料——不要搅拌、让丸子不受干扰地煮5分钟，然后轻轻翻动、一些会保持形状（块状），其他会散开并使酱汁变稠——这是理想的质地。高汤+肉+鱼：倒入800毫升保留的肉汤、加入煮好的肉、200克烟熏鱼（切成块）、100克浸泡的干虾/stockfish（可选）、1汤匙磨碎的小龙虾、1汤匙locust beans（可选）和1片月桂叶、轻轻搅拌，煮沸后不盖锅煮15–20分钟，直到汤汁减少至布丁状稠度——应该在勺子上形成堆，而不是像高汤一样流下来。加入绿叶蔬菜：将200克切碎的菠菜（或ugu/南瓜叶）拌入沸腾的汤中、不盖锅煮5–7分钟，直到绿叶变软但仍亮绿色、尝味并调整盐和辣度、汤应该深咸鲜，带轻微坚果味（来自埃古西），有干净的棕榈油尾韵和上升的辣味。休息和上菜：关火让汤静置5分钟——风味会戏剧性地融合、在深碗中上桌，旁边配上选择的\"吞食\"配菜（杵山药、fufu、eba或amala）、用右手吃：取一小块，蘸入汤中，不咀嚼直接吞下、煮熟的白米饭是较温和的选择。","en":"EGUSI PASTE: pulse 250 g egusi seeds in a spice grinder or food processor 30 seconds until finely ground but not yet pasty; in a small bowl, mix with 200 ml warm water into a thick, hummus-like paste; let it sit 10 minutes to hydrate fully — this is the secret to the signature lumpy-creamy texture. COOK THE MEAT: in a heavy pot, combine 600 g cut meat with 1 chopped onion, 4 minced garlic, grated ginger, 2 stock cubes, 1 tsp salt and 1 L water; bring to boil, then simmer covered 40–50 minutes (longer if using goat) until the meat is tender enough to bite easily but not falling apart; strain and reserve 800 ml of the broth; set the meat aside. BLEND THE PEPPER BASE: in a blender, combine 2 red bell peppers, 2 Scotch bonnet peppers, and 3 fresh tomatoes (or paste-and-water mix); blend 1–2 minutes until completely smooth; pour into a wide pan and simmer over medium heat 15 minutes — the mix should reduce by half and the colour deepen to a rich brick-red; this concentration is essential or the soup will be watery. FRY THE PALM-OIL BASE: in your soup pot over medium heat, warm 100 ml palm oil 2 minutes until it just shimmers (do NOT smoke it — over-smoking destroys the flavour); add the reduced pepper-tomato base and fry, stirring, 8–10 minutes until the oil floats to the surface and the mixture darkens slightly; this is called \"frying the base\". ADD THE EGUSI: take the hydrated egusi paste by tablespoons and drop dumpling-style into the simmering pepper base — do NOT stir; let the dumplings cook undisturbed 5 minutes, then gently fold them in; some will hold their shape (the lumps) while others break apart and thicken the sauce — this is the desired texture. ADD STOCK + MEAT + FISH: pour in 800 ml reserved meat broth; add the cooked meat, 200 g smoked fish (broken into chunks), 100 g soaked dried prawns/stockfish (optional), 1 tbsp ground crayfish, 1 tbsp locust beans (optional), and 1 bay leaf; stir gently, bring to a simmer and cook uncovered 15–20 minutes until the soup has reduced and thickened to a pudding-like consistency — it should mound on a spoon, not pour like broth. ADD GREENS: stir in 200 g chopped spinach (or ugu/pumpkin leaves) into the simmering soup; cook 5–7 minutes uncovered until the greens are wilted but still bright green; taste and adjust salt and heat; the soup should taste deeply savoury, slightly nutty (from the egusi), with a clean palm-oil finish and a building chili heat. REST AND SERVE: turn off the heat and let the soup rest 5 minutes — the flavours meld dramatically in this short rest; serve in deep bowls with the swallow of choice (pounded yam, fufu, eba, or amala) on the side; eat with the right hand: take a small lump of swallow, dip into the soup, and swallow without chewing; boiled white rice is a milder option."}},{"id":155,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"波兰","en":"Poland","ro":"Polonia"},"name":{"zh":"波兰炸猪排 (Kotlet schabowy)","en":"Kotlet schabowy","ro":"Kotlet schabowy"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["4块去骨猪里脊（每块约180–200克，约1.5–2厘米厚）——总计约800克","1茶匙细盐用于猪肉","0.5茶匙现磨白胡椒","200毫升全脂牛奶用于嫩化浸泡（波兰技巧）","80克通用面粉用于裹粉","3个大鸡蛋打散，加1汤匙牛奶和一小撮盐","200克新鲜细面包屑（自制隔夜面包最佳）或日式面包屑","80克猪油（传统）或100毫升中性葵花籽油用于油炸","30克无盐黄油用于最后浇淋","1个柠檬切瓣（现代装饰）","莳萝土豆：800克粉质土豆去皮+30克黄油+1小束切碎莳萝+煮水用盐","炒酸菜：400克沥干酸菜+1个切碎小洋葱+1汤匙猪油+100毫升水"],"en":["4 boneless pork loin chops (~180–200 g each, ~1.5–2 cm thick) — about 800 g total","1 tsp fine salt for the pork","0.5 tsp freshly ground white pepper","200 ml whole milk for the tenderizing soak (the Polish trick)","80 g all-purpose flour for breading","3 large eggs beaten with 1 tbsp milk and a pinch of salt","200 g fine fresh breadcrumbs (homemade from day-old bread is best) or panko","80 g lard (traditional) OR 100 ml neutral sunflower oil for frying","30 g unsalted butter for the finishing baste","1 lemon, cut into wedges (modern garnish)","For dill potatoes: 800 g floury potatoes peeled + 30 g butter + 1 small bunch chopped dill + salt for the cooking water","For sautéed sauerkraut: 400 g drained sauerkraut + 1 small onion finely chopped + 1 tbsp lard + 100 ml water"],"ro":["4 cotlete de porc din mușchi (~180–200 g fiecare, ~1,5–2 cm grosime) — aproximativ 800 g total","1 linguriță sare fină pentru carne","0,5 linguriță piper alb proaspăt măcinat","200 ml lapte integral pentru marinada de tendierare","80 g făină pentru panare","3 ouă mari bătute cu 1 lingură lapte și un vârf de sare","200 g pesmet fin proaspăt (de casă, din pâine de o zi) sau panko","80 g untură (tradițional) SAU 100 ml ulei neutru de floarea-soarelui pentru prăjit","30 g unt nesărat pentru finisare","1 lămâie tăiată în sferturi (garnitură modernă)","Pentru cartofi cu mărar: 800 g cartofi făinoși decojiți + 30 g unt + 1 bunch mic de mărar tocat + sare pentru apa de fierbere","Pentru varza murată: 400 g varză murată scursă + 1 ceapă mică tocată + 1 lingură untură + 100 ml apă"]},"howIsMade":{"zh":"拍打猪排：把每块猪排放在两层保鲜膜之间，用平肉锤从中心向外拍打，每面30秒，直到猪排厚6–7毫米，几乎扩大一倍——必须厚度均匀以使受热均匀、在脂肪边缘划3–4道刀痕以防卷曲。牛奶浸泡：将拍好的猪排擦干，每面抹上盐和白胡椒、放入浅盘，倒入200毫升牛奶让猪排几乎浸没，盖上后冷藏30分钟（最多2小时）——乳酸会使肉变嫩而不改变风味。设置裹粉站：三个浅盘排成一行：盘1装80克面粉；盘2装3个打散的鸡蛋+1汤匙牛奶+一小撮盐；盘3装200克细面包屑、顺序很重要：每块猪排必须经过面粉→鸡蛋→面包屑，不能跳步。给猪排裹粉：从牛奶中取出一块猪排，让多余的滴落，先在面粉中沾，抖掉多余的——面粉必须薄薄均匀地包裹，否则鸡蛋不会粘附、然后蘸蛋液，让多余的滴落2秒，再用力按入面包屑两面，轻拍使其附着、放在盘中、其余3块依此处理、静置5分钟——面包屑会水合并粘连。煮土豆：与此同时，将800克土豆去皮切成4厘米的块、放入冷盐水中，煮沸后炖15–18分钟至叉子可轻松刺穿、沥干，离火放回锅中2分钟让其干燥，然后拌入30克黄油和切碎的莳萝。炒酸菜：在另一个平底锅中，中火融化1汤匙猪油、加入1个切碎的小洋葱，煎5分钟至金黄、加入400克沥干的酸菜和100毫升水；盖盖炖15分钟，然后揭盖再煮5分钟，直到大部分液体蒸发、撒一撮胡椒调味。油炸炸猪排：在大型重平底锅中以中高火加热80克猪油（或100毫升油），直到闪光（175 °C，或一片面包屑接触时立即嘶嘶作响）、一次炸2块猪排以免锅子拥挤，每面3–4分钟不要动，直到深金黄色且酥脆；内部温度应达到70 °C、在最后30秒，将15克黄油加入锅中，倾斜锅以让黄油浇淋猪排——黄油会冒出棕色泡沫，赋予面包屑标志性的波兰星期天香气、转移到铺有厨房纸的网架上沥干（不要放在盘子上，会让底部变软）。立即上菜：每块炸猪排旁配上一堆莳萝土豆和一堆酸菜、如喜欢可配一片柠檬作装饰（挤汁可减腻）、用刀叉吃——绝不要只用叉子，这是尊重经典的菜肴、炸猪排应在油炸后5分钟内食用以获得最佳脆度。","en":"POUND THE PORK: place each pork chop between two sheets of cling film and pound with a flat meat mallet from the centre outward, 30 seconds per side, until the chops are 6–7 mm thick and almost doubled in size — they must be even thickness for uniform cooking; score the fatty rim 3–4 times to prevent curling. MILK SOAK: pat the pounded chops dry and rub each side with salt and white pepper; place in a shallow dish, pour over 200 ml milk so the chops are mostly submerged, cover and refrigerate 30 minutes (up to 2 hours) — the lactic acid tenderizes the meat without altering the flavour. SET UP THE BREADING STATION: three shallow plates in a row: plate 1 with 80 g flour; plate 2 with 3 beaten eggs + 1 tbsp milk + a pinch of salt; plate 3 with 200 g fine breadcrumbs; the line-up matters: every chop must travel flour → egg → breadcrumbs without skipping. BREAD THE CHOPS: lift one chop from the milk, let the excess drip off, and dredge in flour, shaking off the excess — the flour must coat thinly and evenly or the egg won't stick; then dip into the egg, letting it drip 2 seconds, then press firmly into the breadcrumbs on both sides, patting them on so they adhere; set on a plate; repeat for all 4 chops; let them rest 5 minutes — the breading hydrates and binds. BOIL THE POTATOES: meanwhile, peel 800 g potatoes and cut into 4 cm chunks; place in cold salted water, bring to boil, and simmer 15–18 minutes until fork-tender; drain, return to the pot off heat for 2 minutes to dry, then toss with 30 g butter and chopped dill. SAUTÉ THE SAUERKRAUT: in a separate pan, melt 1 tbsp lard over medium heat; add 1 finely chopped onion, fry 5 minutes until golden; add 400 g drained sauerkraut and 100 ml water; simmer covered 15 minutes, then uncover and cook 5 minutes more until most of the liquid has evaporated and the kraut is tender; season with a twist of pepper. FRY THE SCHNITZELS: heat 80 g lard (or 100 ml oil) in a large heavy skillet over medium-high heat until shimmering (175 °C, or a breadcrumb sizzles immediately on contact); fry the chops 2 at a time so the pan isn't crowded, 3–4 minutes per side undisturbed until deeply golden brown and crisp; the internal temperature should reach 70 °C; in the last 30 seconds, add 15 g butter to the pan and tilt to baste the schnitzels — the butter foams brown and gives the breading its iconic Polish-Sunday aroma; transfer to a rack lined with paper towels to drain (NOT a plate, which would steam the bottom soggy). SERVE IMMEDIATELY: plate each schnitzel alongside a mound of dill potatoes and a heap of sauerkraut; garnish with a lemon wedge if you like (the squeeze brightens the fat); eat with a knife and fork — never just a fork, this is a respect-the-classics dish; the schnitzel should be eaten within 5 minutes of frying for maximum crunch."}},{"id":156,"origin":{"zh":"韩国","en":"South Korea","ro":"Coreea de Sud"},"name":{"zh":"紫菜包饭","en":"Kimbap","ro":"Kimbap"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"zh":["短粒白米360克（2杯），未煮——约做4卷","煮米用冷水540毫升（2¼杯）","烤海苔4张（gim, 20 × 18厘米）","黄萝卜腌菜（danmuji）4条，切成与海苔等长，~1厘米厚","嫩菠菜100克（或1小束普通菠菜）","中等胡萝卜2根（~150克），切成0.5 × 0.5 × 8厘米的细丝","大鸡蛋3个","蟹肉棒200克（或熟火腿，或罐头金枪鱼拌蛋黄酱）","黄瓜100克（1根韩国小黄瓜或1/3英式黄瓜），去籽后切成长条","烤芝麻油3汤匙（1.5汤匙拌米，0.5茶匙拌菠菜，其余涂外层）","细盐1.5茶匙（1茶匙拌米，少许调味蔬菜和蛋）","烤芝麻2茶匙","中性油1汤匙用于煎蛋和炒胡萝卜","白胡椒粉0.5茶匙","竹帘（gimbal）+ 保鲜膜"],"en":["360 g (2 cups) short-grain white rice, uncooked — makes ~4 rolls","540 ml (2¼ cups) cold water for cooking the rice","4 sheets toasted nori (gim, 20 × 18 cm)","4 strips danmuji (yellow pickled radish), cut to nori length, ~1 cm thick","100 g baby spinach (or 1 small bunch regular spinach)","2 medium carrots (~150 g), julienned 0.5 × 0.5 × 8 cm matchsticks","3 large eggs","200 g imitation crab sticks (or cooked ham, or tuna mixed with mayo)","100 g cucumber (1 small Korean cucumber or 1/3 English cucumber), seeded and cut into long batons","3 tbsp toasted sesame oil (1.5 tbsp for the rice, 0.5 tsp for spinach, the rest for the outer rub)","1.5 tsp fine salt (1 tsp for the rice, pinches for veg and eggs)","2 tsp toasted sesame seeds","1 tbsp neutral oil for cooking the eggs and carrots","0.5 tsp ground white pepper","Bamboo rolling mat (gimbal) + plastic wrap"],"ro":["360 g (2 căni) orez cu bob scurt necopt, pentru ~4 rulouri","540 ml (2¼ căni) apă rece pentru fierberea orezului","4 foi de nori prăjit (gim, 20 × 18 cm)","4 fâșii de danmuji (ridiche galbenă murată), tăiate la lungimea norii, grosime ~1 cm","100 g spanac baby (sau 1 mănunchi mic de spanac obișnuit)","2 morcovi medii (~150 g), tăiați julien 0,5 × 0,5 × 8 cm","3 ouă mari, bătute","200 g bețe de crab imitație (sau șuncă fiartă sau ton conservat amestecat cu maioneză)","100 g castraveți (1 mic castravete coreean sau 1/3 castravete englezesc), fără sâmburi, tăiat fâșii lungi","3 linguri ulei de susan prăjit (1,5 lingură pentru orez, 0,5 linguriță pentru spanac, restul pentru exterior)","1,5 linguriță sare fină (1 linguriță pentru orez, restul pentru legume)","2 lingurițe semințe de susan prăjite","1 lingură ulei neutru pentru gătit ouăle și sotat morcovii","0,5 linguriță piper alb măcinat","Covoraș de bambus (kimbal) + folie alimentară"]},"howIsMade":{"zh":"米饭：用冷水冲洗360克米饭3–4次，直到水变清、沥干水分，然后放入厚底锅中加入540毫升新鲜冷水、中高火不盖锅烧开（3–4分钟），盖锅转最小火煮12分钟——不要揭盖、离火后盖锅静置10分钟、米饭应该柔软、略带粘性、米粒分离。调味米饭：趁热将米饭转到宽碗中、淋上1.5汤匙芝麻油、1茶匙盐和2茶匙烤芝麻、用饭勺以切的动作轻轻翻拌——绝对不要使劲搅拌，米粒会碎、盖上湿布让其冷却至温热（10–15分钟）。菠菜：将一小锅盐水烧开、焯100克菠菜30秒至刚刚变软、沥干水分立即用冷水冲洗以停止烹饪并保持鲜绿色、用拳头使劲挤压去除所有水分——湿菠菜会破坏卷、用0.5茶匙芝麻油和一小撮盐调味。胡萝卜：在小平底锅中以中火加热1茶匙中性油、加入150克切丝胡萝卜和一小撮盐，翻炒2分钟至刚刚变软但仍然脆爽、倒在盘子上冷却——软塌油腻的胡萝卜会让卷散开。鸡蛋：用一小撮盐和0.5茶匙白胡椒打散3个鸡蛋、在不粘锅中以中小火加热1茶匙中性油，倒入鸡蛋液并倾斜锅形成25 × 20厘米的薄均匀蛋皮、煮2分钟至顶部凝固，不要翻面、滑到砧板上冷却2分钟，然后切成与海苔同宽的4长条。准备馅料：将100克黄瓜纵向切成8根长条，用茶匙刮去带籽的核、将200克蟹肉棒纵向对半切开、将4条檀味（danmuji）切成海苔长度、按摆放顺序将所有东西放在托盘上：菠菜 → 胡萝卜 → 黄瓜 → 蟹肉棒 → 蛋皮 → 檀味。卷每个紫菜包饭：将竹帘的竹条横向放置；将海苔光面朝下铺好、用湿手指将~150克米饭薄薄均匀地铺在海苔的下3/4，远端留4厘米干净的空白、在近端3厘米处紧密排列一条：菠菜、胡萝卜、黄瓜、蟹肉棒、蛋皮和檀味、提起竹帘的近端紧紧向前卷，第一卷将馅料藏在米饭下方，然后继续紧紧卷到远端、沿接缝按压封口。切片上桌：在每卷外层轻轻涂抹0.5茶匙芝麻油，使海苔光亮且防止粘刀、在每次切之间用湿布擦拭锋利的刀、用一个果断的推动（不要拉锯）将每卷切成8片均匀的圆片——总共32块、摆在盘子上撒上芝麻、卷好后4小时内食用；切勿冷藏紫菜包饭（重新加热时米饭变硬，海苔变软）。","en":"Rinse 360 g rice in cold water 3–4 times until the water runs clear, drain well, then put in a heavy pot with 540 ml fresh cold water, bring to a boil uncovered over medium-high heat (3–4 min), cover, reduce to the lowest possible heat and cook 12 minutes without lifting the lid, then remove from heat and rest covered 10 minutes until the rice is tender, slightly sticky, with separate grains. While the rice is still hot, transfer it to a wide bowl, drizzle 1.5 tbsp sesame oil, 1 tsp salt and 2 tsp toasted sesame seeds over the top and fold gently with a rice paddle in cutting motions — never stir aggressively or the grains break and turn mushy — then cover with a damp cloth and let cool to lukewarm (10–15 min). Bring a small pot of salted water to a boil and blanch 100 g spinach for 30 seconds until just wilted, then drain and rinse under cold water immediately to stop the cooking and preserve the bright green colour, squeeze in your fist as hard as possible to remove all water (wet spinach ruins the roll) and season with 0.5 tsp sesame oil and a pinch of salt. Heat 1 tsp neutral oil in a small pan over medium heat, add 150 g julienned carrot and a pinch of salt and stir-fry 2 minutes until just softened but still crisp, then tip onto a plate to cool — limp, oily carrots will break the roll. Beat 3 eggs with a pinch of salt and 0.5 tsp white pepper, heat 1 tsp neutral oil in a non-stick pan over medium-low heat, pour in the eggs and tilt the pan to form a thin even sheet 25 × 20 cm, cook 2 minutes until set on top without flipping, then slide onto a board, let cool 2 minutes and cut into 4 long strips the width of the nori. Cut 100 g cucumber lengthwise into 8 long batons and scrape the seedy core out with a teaspoon, split 200 g crab sticks in half lengthwise and cut 4 strips of danmuji to nori length, then arrange everything on a tray in the order you'll lay them: spinach, carrot, cucumber, crab, egg, danmuji. Place the bamboo mat with the slats running horizontally and lay a sheet of nori shiny-side down, then with wet fingers spread ~150 g rice in a thin even layer over the bottom 3/4 of the nori while leaving a clean 4 cm strip at the far edge, and about 3 cm in from the near edge line up one strip each of spinach, carrot, cucumber, crab, egg and danmuji in a tight bundle, then lift the near edge of the mat and roll firmly forward, tucking the fillings under the rice with the first roll and continuing to roll tightly to the far edge, then press along the seam to seal. Brush the outside of each roll lightly with 0.5 tsp sesame oil to make the nori glossy and prevent it from sticking to the knife, wipe a sharp knife with a damp cloth between cuts, then slice each roll into 8 even rounds with one decisive push (no sawing) for 32 pieces total, arrange on a plate and sprinkle with sesame seeds — eat within 4 hours of rolling and never refrigerate kimbap."},"timeMins":{"total":60,"active":50}},{"id":157,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"zh":"智利","en":"Chile","ro":"Chile"},"name":{"zh":"智利玉米饼","en":"Pastel de Choclo","ro":"Pastel de Choclo"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["pino（肉馅）：600克牛肉碎（牛肩或腰肉，20%脂肪）","2个大洋葱（~400克），切细","4瓣大蒜，切细","炒制用2汤匙中性油","pino用1.5茶匙盐+1茶匙现磨黑胡椒","1茶匙磨碎的孜然+1茶匙甜红椒粉+1茶匙干牛至+1茶匙ají color（或熏制pimentón作替代）","60毫升牛肉高汤或水","80克黑葡萄干，在100毫升温水中浸泡15分钟后沥干","4只带骨带皮鸡腿（~600克）——煮熟撕碎（传统添加）","1片月桂叶+800毫升水煮鸡肉用","6个煮熟的鸡蛋，剥皮对半切（每份1个）","18–24粒去核黑橄榄（kalamata风格）","玉米糊（choclo）：1.2公斤新鲜白玉米粒（~6–8根玉米棒）或1公斤解冻冷冻玉米","80毫升全脂牛奶","60克无盐黄油","1汤匙新鲜罗勒叶，切细（智利标志）","玉米糊用1茶匙细盐+1汤匙白砂糖","烘焙前撒在表面用的2汤匙白砂糖（标志性焦糖外皮）"],"en":["For the pino (meat filling): 600 g ground beef (chuck or sirloin, 20% fat)","2 large onions (~400 g), finely diced","4 garlic cloves, finely minced","2 tbsp neutral oil for sautéing","1.5 tsp salt + 1 tsp freshly ground black pepper for the pino","1 tsp ground cumin + 1 tsp sweet paprika + 1 tsp dried oregano + 1 tsp aji color (or pimentón as substitute)","60 ml beef stock or water","80 g dark raisins, soaked 15 min in 100 ml warm water, then drained","4 bone-in skin-on chicken thighs (~600 g) — poached and pulled (traditional addition)","1 bay leaf + 800 ml water to poach the chicken","6 hard-boiled eggs, peeled and halved (1 per portion)","18–24 pitted black olives (kalamata-style)","For the corn paste (choclo): 1.2 kg fresh white corn kernels (~6–8 ears) OR 1 kg thawed frozen corn","80 ml whole milk","60 g unsalted butter","1 tbsp fresh basil leaves, finely chopped (the Chilean signature)","1 tsp fine salt + 1 tbsp granulated sugar for the corn paste","2 tbsp granulated sugar to sprinkle over the top before baking (for the iconic caramelized crust)"],"ro":["Pentru pino: 600 g vită tocată (gulaș sau pulpă, 20% grăsime)","2 cepe mari (~400 g), tăiate fin","4 căței de usturoi, tocați fin","2 linguri ulei neutru pentru sotat","1,5 lingurițe sare + 1 linguriță piper negru proaspăt măcinat (pentru pino)","1 linguriță chimion măcinat + 1 linguriță boia dulce + 1 linguriță oregano uscat + 1 linguriță aji color (sau pimentón pentru substitut)","60 ml supă de vită sau apă","80 g stafide negre, înmuiate 15 minute în 100 ml apă caldă, apoi scurse","4 pulpe de pui cu os și piele (~600 g) — fierte și destrămate (tradițional)","1 frunză de dafin + 800 ml apă pentru fiertul puiului","6 ouă tari, decojite și tăiate în jumătăți (1 per porție)","18–24 măsline negre cu sâmbure scos (stil kalamata)","Pentru pasta de porumb: 1,2 kg boabe proaspete de porumb alb (~6–8 știuleți) SAU 1 kg porumb congelat dezghețat","80 ml lapte integral","60 g unt nesărat","1 lingură busuioc proaspăt, tocat fin (semnătura chiliană)","1 linguriță sare fină + 1 lingură zahăr granulat pentru pasta de porumb","2 linguri zahăr granulat pentru presărat pe suprafață înainte de coacere (crusta caramelizată iconică)"]},"howIsMade":{"zh":"焦糖化洋葱：在重平底锅中以中火加热2汤匙油，加入400克切细的洋葱和0.5茶匙盐、煎炒12–15分钟，经常搅拌，直到深金黄色透明——不要赶时间，焦糖化洋葱是pino风味的基础、加入4瓣大蒜末，再炒1分钟直到飘香。煎牛肉：将火转中高、把600克牛肉碎加入洋葱中，用木勺打散、煎6–8分钟直到肉不再粉红、所有液体蒸发、加入1茶匙孜然、1茶匙红椒粉、1茶匙牛至、1茶匙ají color（如使用）、剩余1茶匙盐和1茶匙胡椒、搅拌1分钟让香料绽放。完成pino：倒入60毫升高汤和沥干的葡萄干、煮3–4分钟，直到混合物湿润但不汤汁——pino应该有光泽且能在勺子上保持形状、离火让其冷却15分钟——休息可加深风味并防止玉米topping滑动。煮鸡肉：在pino休息时，将4只鸡腿放入加1片月桂叶的800毫升淡盐水中煮25分钟至熟、沥干，稍微冷却，然后将肉从骨头上撕成大块（弃皮）、保留高汤与pastel一同上桌。玉米糊：在食品处理器或搅拌机中，将1.2公斤玉米粒、80毫升牛奶和1茶匙盐打30秒至粗粒糊状——保留质感，不要打成顺滑奶油、转移到加60克黄油的重锅中以中火煮、煮10–15分钟，用木勺不停搅拌，直到糊状物变稠至类似玉米粥的稠度并能从锅壁脱离、加入1汤匙切碎的罗勒，离火。组装：预热烤箱至200 °C，烤架放在上三分之一、将pino分到6个个人陶土paila（或一个28厘米烤盘）中、在每份上面放煮鸡肉块、1个煮蛋一半、3–4颗橄榄和一小堆装饰用的葡萄干、在上面均匀涂抹2厘米厚的温玉米糊，用勺背抹平至边缘密封。糖外皮：在玉米糊上均匀撒上2汤匙白砂糖、这一步不可商议——糖在烘焙过程中会焦糖化成标志性的深色、几乎烧焦的金黄外皮，区别于任何其他牧羊人派。烘焙：将pastels放在200 °C烤箱的上层架上烤25–30分钟，直到玉米糊呈金棕色，糖焦糖化成表面的深色斑点、边角可能起泡——这是正确的、上桌前静置10分钟（馅料需要凝固）、从paila直接上桌，配pebre莎莎酱和一杯智利Carmenère酒。","en":"CARAMELIZE THE ONIONS: in a heavy skillet over medium heat, warm 2 tbsp oil and add 400 g finely diced onion with 0.5 tsp salt; sauté 12–15 minutes, stirring often, until deeply golden and translucent — DO NOT rush this step, the caramelized onion is the foundation of pino flavour; add 4 minced garlic cloves and cook 1 minute more until fragrant. BROWN THE BEEF: raise the heat to medium-high; add 600 g ground beef to the onions, breaking it apart with a wooden spoon; cook 6–8 minutes until the meat is no longer pink and any liquid has evaporated; add 1 tsp cumin, 1 tsp paprika, 1 tsp oregano, 1 tsp aji color (if using), the remaining 1 tsp salt and 1 tsp pepper; stir 1 minute to bloom the spices. FINISH THE PINO: pour in 60 ml beef stock and the drained raisins; simmer 3–4 minutes until the mixture is moist but not soupy — the pino should be glossy and able to hold its shape on a spoon; remove from heat and let cool 15 minutes — letting it rest deepens the flavour and prevents the corn topping from sliding off. POACH THE CHICKEN: while the pino rests, simmer 4 chicken thighs in 800 ml lightly salted water with 1 bay leaf for 25 minutes until cooked through; drain, cool slightly, then pull the meat from the bones in large chunks (skin discarded); reserve the stock for serving alongside the pastel. CORN PASTE: in a food processor or blender, pulse 1.2 kg fresh corn kernels with 80 ml milk and 1 tsp salt 30 seconds until coarsely pureed — keep some texture, do not blend to a smooth cream; transfer to a heavy saucepan with 60 g butter over medium heat; cook 10–15 minutes, stirring constantly with a wooden spoon, until the puree thickens to a polenta-like consistency that pulls away from the sides of the pan; stir in 1 tbsp chopped basil and remove from heat. ASSEMBLE: preheat oven to 200 °C with a rack in the upper third; divide the pino between 6 individual earthenware pailas (or one 28 cm baking dish); top each portion with chunks of poached chicken, 1 hard-boiled egg half, 3–4 olives, and a small pile of raisins arranged decoratively; spoon the warm corn paste over the top in an even 2 cm layer, smoothing with the back of a spoon to seal all the way to the edges. SUGAR CRUST: sprinkle 2 tbsp granulated sugar evenly over the corn topping; this is non-negotiable — the sugar caramelizes during baking into the iconic dark, almost-burnt golden crust that distinguishes pastel de choclo from any other shepherd's pie. BAKE: place the pastels on the upper rack of the 200 °C oven and bake 25–30 minutes until the corn topping is golden brown and the sugar has caramelized into dark spots across the surface; the corners may bubble — that's correct; let rest 10 minutes before serving (the filling needs to set); serve straight from the paila with a side of pebre salsa and a glass of Chilean Carmenère."}},{"id":158,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"塞尔维亚","en":"Serbia","ro":"Serbia"},"name":{"zh":"塞尔维亚烤肉饼","en":"Pljeskavica","ro":"Pljeskavica"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["500克粗剁牛颈肉（~20%脂肪）","300克粗剁羊肩肉（或猪肩肉为更温和版本）","1个大洋葱（~200克），磨细并挤干水分（多汁肉饼的秘诀）","4瓣大蒜，用0.5茶匙盐捣成糊","1汤匙匈牙利甜红椒粉","1茶匙辣椒粉（烟熏或克什米尔，可选）","1.5茶匙细盐","1茶匙现磨黑胡椒","1茶匙小苏打（巴尔干技巧——保持肉饼多汁鲜嫩）","100毫升冰冻气泡水（蓬松弹性口感）","0.5茶匙干马郁兰或牛至","1汤匙植物油用于烤架或平底锅","上菜配菜：4个somun或pita饼（~18厘米）、1个中等紫洋葱（~150克）切薄片、200克ajvar、100克kajmak或酸奶油、新鲜欧芹、柠檬瓣（可选）"],"en":["500 g coarsely ground beef chuck (~20% fat)","300 g coarsely ground lamb shoulder (or pork shoulder for a milder version)","1 large onion (~200 g), finely grated and water squeezed out (the secret to juicy patties)","4 garlic cloves, crushed with 0.5 tsp salt into a paste","1 tbsp sweet Hungarian paprika","1 tsp hot paprika (smoked or Kashmiri, optional)","1.5 tsp fine salt","1 tsp freshly ground black pepper","1 tsp baking soda (the Balkan trick — helps keep them juicy and tender)","100 ml ice-cold sparkling water (for the fluffy springy texture)","0.5 tsp dried marjoram or oregano","1 tbsp vegetable oil for the grill or pan","To serve: 4 somun or pita breads (~18 cm rounds), 1 medium red onion (~150 g) thinly sliced, 200 g ajvar red-pepper relish, 100 g kajmak or sour cream, fresh parsley, lemon wedges (optional)"],"ro":["500 g vită tocată grosier (ceafă, ~20% grăsime)","300 g umăr de miel tocat grosier (sau umăr de porc pentru o versiune mai blândă)","1 ceapă mare (~200 g), rasă fin și stoarsă bine (secretul cărnurilor suculente)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă","1 lingură boia ungurească dulce","1 linguriță boia iute (afumată sau Kashmir, opțional)","1,5 lingurițe sare fină","1 linguriță piper negru proaspăt măcinat","1 linguriță bicarbonat de sodiu (trucul balcanic — păstrează carnea suculentă și frageda)","100 ml apă minerală carbogazoasă rece ca gheața (pentru textura pufoasă)","0,5 linguriță maghiran uscat sau oregano","1 lingură ulei vegetal pentru grătar sau tigaie","Pentru servire: 4 chifle somun sau pita (~18 cm), 1 ceapă roșie medie (~150 g) tăiată subțire, 200 g ajvar, 100 g kajmak sau smântână, pătrunjel proaspăt, lămâie (opțional)"]},"howIsMade":{"zh":"洋葱准备：将200克洋葱用刨丝器的细面磨碎、倒入干净的茶巾中，在水槽上方用力挤压尽可能多的液体——应该至少挤出80毫升的汁液、湿洋葱会让肉饼在烤架上散开、保留2汤匙挤出的洋葱浆用于肉中。混合肉：在大碗中混合500克牛肉+300克羊肉（或猪肉）、加入2汤匙挤出的洋葱浆、4瓣大蒜（用0.5茶匙盐捣成糊）、1汤匙甜红椒粉、1茶匙辣椒粉（如使用）、1茶匙盐、1茶匙胡椒、0.5茶匙马郁兰和1茶匙小苏打、用手用力揉4–5分钟——混合物应变得粘稠且明显紧实，这赋予pljeskavica标志性的弹性。加入气泡水：继续揉的同时慢慢倒入100毫升冰冻气泡水，分4次每次25毫升、水使肉碎充气，与小苏打结合保持肉饼多汁鲜嫩、盖上保鲜膜冷藏至少4小时，最好过夜——休息不可商议，对风味发展和粘合至关重要。塑形肉饼：将休息好的肉分成4份等份约225克每份、用湿手（防粘）将每份滚成球，然后压扁成直径18–20厘米、厚8毫米的平饼、饼的直径必须与上桌用的面包相同、用拇指轻轻按压中心创建一个凹痕——这能防止肉饼在烤架上隆起。二次冷藏：将塑形好的肉饼放在铺有烘焙纸的托盘上、盖松冷藏20分钟以变硬、同时点燃炭烤架至中高温（200 °C）或加热重底带槽烤盘+1汤匙油至刚冒烟。烧烤：在肉饼上轻轻刷油、每面烤4–5分钟不动——只翻一次、当内部温度达到65 °C（中度）且两面形成深桃花心木色外皮，有可见的烤痕时即可、抗拒按压它们——你会失去所有汁液并取消第3步的工作。加热面包：烧烤最后一分钟，将4个somun或pita放在烤架上每面30秒，直到加热并轻微烤色、沿一边切开每个pita，制作足够大的口袋装肉饼。上菜：将一个肉饼塞入每个温热的pita口袋、顶上加1汤匙ajvar、一团kajmak、一大堆切片生紫洋葱、一撮欧芹，如喜欢可挤上柠檬汁、趁面包温热时立即用手吃——热乎多汁的肉、凉爽的kajmak和烟熏的ajvar的对比是巴尔干街头美食的灵魂。","en":"ONION PREP: grate 200 g onion on the fine side of a box grater; transfer to a clean tea towel and squeeze HARD over the sink to remove as much liquid as possible — at least 80 ml of juice should come out; wet onion makes the patties fall apart on the grill; reserve 2 tbsp of the squeezed pulp for the meat. MIX THE MEAT: in a large bowl, combine 500 g beef + 300 g lamb (or pork); add 2 tbsp squeezed onion pulp, 4 garlic cloves crushed with 0.5 tsp salt, 1 tbsp sweet paprika, 1 tsp hot paprika (if using), 1 tsp salt, 1 tsp pepper, 0.5 tsp marjoram and 1 tsp baking soda; knead vigorously by hand 4–5 minutes — the mixture should become sticky and noticeably tightened, which gives pljeskavica its signature springy bounce. ADD SPARKLING WATER: slowly drizzle in 100 ml ice-cold sparkling water while continuing to knead, in 4 additions of 25 ml each; the water aerates the mince and combines with the baking soda to keep the patties juicy and tender; cover with film and refrigerate at least 4 hours, ideally overnight — the rest is non-negotiable for flavour development and binding. SHAPE THE PATTIES: divide the rested meat into 4 equal portions of ~225 g each; with wet hands (to prevent sticking), roll each portion into a ball, then flatten into a flat disc 18–20 cm in diameter and 8 mm thick; the disc must be the same diameter as the bread it will be served in; press the centre slightly with your thumb to create a dimple — this prevents the patty from doming up on the grill. SECOND CHILL: place the shaped patties on a parchment-lined tray; cover loosely and refrigerate 20 minutes to firm up; meanwhile, fire up a charcoal grill to medium-high (200 °C) or heat a heavy ridged griddle pan with 1 tbsp oil until just smoking. GRILL: brush the patties lightly with oil; grill 4–5 minutes per side without moving — turn ONCE only; the patties are done when the internal temperature reaches 65 °C (medium) and a deep mahogany crust has formed on both sides with visible grill marks; resist pressing them — you'll lose all the juice and undo the work you did in step 3. WARM THE BREAD: during the last minute of grilling, place 4 somun or pita on the grill for 30 seconds per side until warmed and lightly toasted; split each pita open at one edge to make a pocket large enough for the patty. SERVE: slip one patty into each warm pita pocket; top with 1 tbsp ajvar, a knob of kajmak, a generous mound of sliced raw red onion, a sprinkle of parsley, and a squeeze of lemon if you like; eat immediately with your hands while the bread is warm — the contrast of hot juicy meat, cool kajmak, and smoky ajvar is the soul of Balkan street food."}},{"id":159,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"zh":"荷兰","en":"Netherlands","ro":"Olanda"},"name":{"zh":"荷兰小松饼","en":"Poffertjes","ro":"Poffertjes"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["250克荞麦粉（传统，赋予标志性风味）——或100克荞麦+150克通用面粉作为更温和的替代","7克即用干酵母（或21克新鲜酵母）","1汤匙白砂糖（1茶匙喂养酵母，其余加入面糊）","0.5茶匙细盐","350毫升温全脂牛奶（38 °C）","2个大鸡蛋","面糊用30克融化温热的无盐黄油","锅和最后装饰用50克额外的无盐黄油","1汤匙深色朗姆酒或香草精（可选，传统）","上菜配菜：30克冷无盐黄油块用于顶端装饰、60克糖粉用于撒粉、stroopwafel糖浆或枫糖浆（可选）、新鲜浆果（可选）","设备：带24–30个凹坑的poffertjespan铸铁煎锅（或aebleskiver锅）；翻面用的小木签"],"en":["250 g buckwheat flour (traditional, gives the signature flavour) — OR 100 g buckwheat + 150 g all-purpose flour as a milder substitute","7 g instant dry yeast (or 21 g fresh yeast)","1 tbsp granulated sugar (1 tsp to feed the yeast, the rest in the batter)","0.5 tsp fine salt","350 ml warm whole milk (38 °C)","2 large eggs","30 g unsalted butter, melted and cooled to lukewarm for the batter","50 g additional unsalted butter for the pan + finishing","1 tbsp dark rum or vanilla extract (optional, traditional)","To serve: 30 g cold unsalted butter cubes for topping, 60 g icing sugar to dust, stroopwafel syrup or maple syrup (optional), fresh berries (optional)","Equipment: poffertjespan cast-iron pan with 24–30 dimples (or aebleskiver pan); small wooden skewer or chopstick for flipping"],"ro":["250 g făină de hrișcă (tradițional, dă aroma signature) — SAU 100 g hrișcă + 150 g făină albă ca substitut mai blând","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 lingură zahăr (1 linguriță pentru drojdie, restul în aluat)","0,5 linguriță sare fină","350 ml lapte integral cald (38 °C)","2 ouă mari","30 g unt nesărat topit și răcit la călduț pentru aluat","50 g unt nesărat suplimentar pentru tigaie și finisare","1 lingură rom întunecat sau extract de vanilie (opțional, tradițional)","Pentru servire: 30 g unt rece în cuburi pentru a pune deasupra, 60 g zahăr pudră pentru presărat, sirop stroopwafel sau de arțar (opțional), fructe de pădure proaspete (opțional)","Echipament: tigaie poffertjespan din fontă cu 24–30 adâncituri (sau tigaie aebleskiver); bețișoară de lemn pentru întors"]},"howIsMade":{"zh":"激活酵母：在锅中将350毫升牛奶加热至约38 °C（温热——手腕上感觉舒适）、倒入大碗中，在表面撒上7克即用干酵母和1茶匙糖，静置10分钟直到表面出现奶油状泡沫、如果没有泡沫，酵母已死——用新鲜酵母重新开始。制作面糊：将2个鸡蛋打入起泡的酵母牛奶中搅至光滑、在另一个碗中，将250克荞麦粉（或荞麦+通用面粉混合）、剩余2茶匙糖和0.5茶匙盐过筛混合、将干料分两次加入湿料，每次搅至光滑——无颗粒、搅入30克融化冷却的黄油和1汤匙朗姆酒（如使用）、面糊应该是稀奶油的稠度，能从打蛋器以带状滴落。第一次发酵：用干净的布盖住碗，置于温暖处60分钟，直到表面布满气泡，面糊明显涨起（约1.5倍体积）、酵母发展出真正poffertjes标志性的蓬松微酸风味。排气并静置：轻轻搅拌面糊使大气泡消散、倒入挤压瓶、量杯或裱花袋——这是精准分配到小坑里最简单的方法、让面糊静置10分钟，同时加热平底锅。加热poffertjespan：将带24或30个凹坑的铸铁poffertjespan置于中低火加热3分钟，直至均匀受热（用一滴水测试——应该立即嘶嘶响并在2秒内蒸发）、用蘸了融化黄油的折叠厨房纸大方地涂抹每个凹坑——每个凹坑都必须涂上，否则poffertjes会粘锅。填充凹坑：快速操作，将面糊挤入或倒入每个凹坑至3/4满（每个凹坑约1汤匙）、等待60–90秒，直到边缘凝固，每个周围形成金色环，表面有气泡。翻面：用木签从凹坑的侧面拉起每个半凝固的poffertje并翻转——未煮熟的上面面糊将流入凹坑，形成一个圆球、再煮60–90秒直到第二面深金棕色、每个poffertje应该是蓬松的圆球，两面金黄，约3厘米宽。立即上菜：将8–10个poffertjes滑到每个温热的盘子上、顶上放一小块冷黄油（它会融化并被吸收）和通过细筛大量撒上的糖粉、立即上菜——poffertjes在制作后5分钟内变得有橡胶感、可选：淋上stroopwafel糖浆或撒上新鲜浆果。","en":"ACTIVATE THE YEAST: warm 350 ml milk in a saucepan to about 38 °C (lukewarm — comfortable on your wrist); pour into a large bowl, sprinkle 7 g instant dry yeast and 1 tsp sugar over the surface, and let stand 10 minutes until a creamy foam appears on top; if no foam, the yeast is dead — start over with fresh yeast. MAKE THE BATTER: whisk 2 eggs into the foamed yeast-milk until smooth; in a separate bowl, sift together 250 g buckwheat flour (or the buckwheat+all-purpose mix), the remaining 2 tsp sugar and 0.5 tsp salt; add the dry to the wet in two additions, whisking each time until smooth — no lumps; whisk in 30 g melted cooled butter and 1 tbsp rum (if using); the batter should be the consistency of thin cream that ribbons off the whisk. FIRST PROOF: cover the bowl with a clean cloth and let rise in a warm spot for 60 minutes, until the surface is covered with bubbles and the batter has risen noticeably (about 1.5× volume); the yeast develops the signature airy, slightly sour flavour of true poffertjes. STIR DOWN AND REST: gently stir the risen batter to deflate large bubbles; transfer to a squeeze bottle, jug or piping bag — the easiest way to portion accurately into the small dimples; let rest 10 minutes while the pan heats. HEAT THE POFFERTJESPAN: place a 24- or 30-dimple cast-iron poffertjespan over medium-low heat for 3 minutes until evenly hot (test with a drop of water — it should sizzle and evaporate in 2 seconds); use a folded paper towel dipped in melted butter to grease each dimple generously — every dimple must be coated or the poffertjes will stick. FILL THE DIMPLES: working fast, squeeze or pour batter into each dimple until 3/4 full (about 1 tbsp per dimple); wait 60–90 seconds until the edges are set and a golden ring forms around each one, with bubbles forming on the surface. FLIP EACH ONE: using a wooden skewer, pull each half-set poffertje up the side of its dimple and flip it upside down — the uncooked top batter will flow into the dimple, filling out a round ball; cook another 60–90 seconds until the second side is deep golden brown; each poffertje should be a fluffy round ball, golden on both sides, about 3 cm wide. SERVE IMMEDIATELY: slide 8–10 poffertjes onto each warm plate; top with a small knob of cold butter (it will melt and soak in) and a generous dust of icing sugar through a fine sieve; serve immediately — poffertjes turn rubbery within 5 minutes of being made; optional: drizzle stroopwafel syrup or scatter fresh berries."}},{"id":160,"origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"日式咖喱饭","en":"Japanese Curry Rice","ro":"Curry japonez"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"zh":["短粒米2杯（干米）","去骨去皮鸡腿肉400克（或牛肩肉），切3厘米块","大洋葱2个，切中等丁","中等土豆2个，切3厘米块","中等胡萝卜2根，切1.5厘米圆片","植物油1大勺","水800毫升","日式咖喱块1盒（如S&B金牌咖喱中辣，约100克）","伍斯特酱1小勺","番茄酱1小勺（可选，增加层次感）","盐和黑胡椒适量"],"en":["2 cups short-grain rice (uncooked)","400g boneless skinless chicken thighs (or beef chuck), cut into 3 cm pieces","2 large onions, cut into medium dice","2 medium potatoes, cut into 3 cm cubes","2 medium carrots, cut into 1.5 cm rounds","1 tbsp vegetable oil","800ml water","1 pack Japanese curry roux blocks (e.g. S&B Golden Curry, medium, approx. 100g)","1 tsp Worcestershire sauce","1 tsp ketchup (optional, for depth)","salt and black pepper to taste"],"ro":["2 căni orez cu bob scurt (nepreparare)","400g pulpe de pui dezosate fără piele (sau vită pentru friptură), tăiate cuburi de 3 cm","2 cepe mari, tăiate cuburi medii","2 cartofi medii, tăiați cuburi de 3 cm","2 morcovi medii, tăiați rondele de 1,5 cm","1 lingură ulei vegetal","800ml apă","1 pachet blocuri de roux curry japonez (ex. S&B Golden Curry, mediu picant, aprox. 100g)","1 linguriță sos Worcestershire","1 linguriță ketchup (opțional, pentru rotunjimea gustului)","sare și piper negru după gust"]},"howIsMade":{"zh":"米饭：将360克（2杯）短粒米用冷水冲洗3–4次，直到水变清、放入锅中加540毫升（2½杯）冷水、盖锅前不盖大火烧开，盖锅转最小火煮13分钟、离火后盖锅焖10分钟、不要揭盖。焦糖化洋葱：大锅中1汤匙油烧至中火、加入2个切中等大小丁的洋葱，频繁搅拌15–20分钟至软烂金黄——不要省略此步；焦糖洋葱是风味的脊柱。煎肉：加入400克切3厘米块的去骨鸡腿或牛颈肉，加盐和胡椒调味，四面煎黄3–4分钟、肉必须有深金色外壳——额外风味。蔬菜：加入2根切1.5厘米厚胡萝卜片和2个切3厘米方块土豆、翻炒1分钟让蔬菜裹上油。炖煮底料：倒入800毫升水大火烧开，转小火不盖锅炖15分钟，或至土豆刚好软（用签子测试）。加入咖喱块：将锅离火、将100克日本咖喱块掰成小块加入锅中，搅拌至完全溶化——离火加入可防止结块。浓缩酱汁：将锅放回小火，频繁搅拌炖10分钟至酱汁变浓亮——应能覆盖勺背、加入1茶匙伍斯特酱和1茶匙番茄酱增加深度，尝味并调整盐量。上菜：在深盘中将咖喱慷慨地倒在热米饭上、传统配菜：炸猪排katsu、切丝卷心菜、腌红萝卜（福神渍）、一盘里同时装米饭和咖喱但不混合——在餐桌上用勺子混合起来。","en":"THE RICE: rinse 360 g (2 cups) short-grain rice in cold water 3–4 times until the water runs clear; place in a pot with 540 ml (2½ cups) cold water; bring to a boil uncovered, cover, reduce to lowest heat and cook 13 minutes; remove from heat and rest covered 10 minutes; do not lift the lid. CARAMELIZE THE ONIONS: in a large pot, heat 1 tbsp oil over medium heat; add 2 medium-diced onions and cook, stirring often, for 15–20 minutes until soft and golden — DO NOT skip this step; the caramelized onions are the backbone of flavour. BROWN THE MEAT: add 400 g boneless chicken thighs or beef chuck cut in 3 cm pieces, season with salt and pepper, sear on all sides 3–4 minutes; the meat must have a deep golden crust — extra flavour. VEGETABLES: add 2 carrots cut in 1.5 cm rounds and 2 potatoes cut in 3 cm cubes; stir 1 minute to coat the vegetables in the oil. SIMMER THE BASE: pour in 800 ml water, bring to a boil, reduce to a gentle simmer uncovered for 15 minutes, or until the potato is just tender (check with a skewer). ADD THE ROUX: remove the pot from the heat; break 100 g Japanese curry roux blocks into small pieces and stir into the pot until fully dissolved — adding off heat prevents lumps. THICKEN THE SAUCE: return the pot to low heat and simmer, stirring frequently, for 10 minutes until the sauce is thick and glossy — it should coat the back of a spoon; stir in 1 tsp Worcestershire sauce and 1 tsp ketchup for depth, taste and adjust salt. SERVE: spoon a generous portion of curry over hot rice in deep plates; traditional accompaniments: katsu schnitzel, shredded cabbage, pickled red radishes (fukujinzuke); a single plate holds both rice and curry without mixing them — you spoon them together at the table."}},{"id":161,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"希腊炖豆汤","en":"Fasolada","ro":"Fasolada"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["400克干白豆（cannellini、navy或希腊大白豆gigantes），在冷水中浸泡过夜","2根中等胡萝卜（~200克），去皮切1厘米方块","2根芹菜（~150克），切1厘米方块 + 30克芹菜叶切碎（可选，传统）","1个大洋葱（~200克），切细","4瓣大蒜，切细","400克成熟番茄（4个中等大小）——去皮磨碎，或1罐×400克碎番茄","1汤匙番茄酱","100毫升特级初榨橄榄油用于soffritto + 另外60毫升用于完成","2片月桂叶","1茶匙干牛至","1.5茶匙盐 + 按口味多加","0.5茶匙现磨黑胡椒","1汤匙红酒醋（可选，最后提亮）","1.5升水（或蔬菜高汤）","上菜配菜：脆乡村面包、Kalamata橄榄、碎feta奶酪、新鲜欧芹"],"en":["400 g dried white beans (cannellini, navy, or large Greek gigantes), soaked overnight in cold water","2 medium carrots (~200 g), peeled and diced 1 cm","2 celery stalks (~150 g), diced 1 cm + 30 g celery leaves chopped (optional, traditional)","1 large onion (~200 g), finely diced","4 garlic cloves, finely minced","400 g ripe tomatoes (4 medium) — peeled and grated OR 1 × 400 g can crushed tomatoes","1 tbsp tomato paste","100 ml extra-virgin olive oil for the soffritto + 60 ml more for finishing","2 bay leaves","1 tsp dried oregano","1.5 tsp salt + more to taste","0.5 tsp freshly ground black pepper","1 tbsp red wine vinegar (optional, brightens at the end)","1.5 L water (or vegetable stock)","To serve: crusty country bread, Kalamata olives, crumbled feta cheese, fresh parsley"],"ro":["400 g fasole albă uscată (cannellini, navy sau gigantes grecești), înmuiate peste noapte în apă rece","2 morcovi medii (~200 g), curățați și tăiați cuburi de 1 cm","2 tulpini de țelină (~150 g), tăiate cuburi de 1 cm + 30 g frunze de țelină tocate (opțional, tradițional)","1 ceapă mare (~200 g), tăiată fin","4 căței de usturoi, tocați fin","400 g roșii coapte (4 medii) — decojite și rase SAU 1 conservă × 400 g de roșii zdrobite","1 lingură pastă de roșii","100 ml ulei de măsline extravirgin pentru sotat + 60 ml suplimentar pentru finisare","2 frunze de dafin","1 linguriță oregano uscat","1,5 lingurițe sare + sare după gust","0,5 linguriță piper negru proaspăt măcinat","1 lingură oțet de vin roșu (opțional, dă luminozitate la final)","1,5 L apă (sau supă de legume)","Pentru servire: pâine de țară crocantă, măsline Kalamata, brânză feta sfărâmată, pătrunjel proaspăt"]},"howIsMade":{"zh":"浸泡白豆：将400克干白豆放入大碗中，加冷水高出5厘米，浸泡8小时或过夜、沥干冲洗——浸泡缩短烹饪时间，并帮助豆子均匀煮熟且保持完整。焯豆：将沥干的豆子放入大锅中，加冷水高出3厘米，烧开、猛火煮10分钟然后沥干——这步去除引起胀气的难消化化合物，让汤底更清爽。调味底：在5升重锅中，100毫升橄榄油中火加热、加200克洋葱+200克胡萝卜+150克芹菜丁，频繁搅拌12–15分钟至非常软并开始变金黄——这种慢炒蔬菜底是fasolada深度的基础、加4瓣大蒜末再煮1分钟至香气出来。让番茄绽放：加1汤匙番茄酱，搅拌煮2分钟至变深色、加400克磨碎番茄（或罐装碎番茄）煮5分钟至生酸味煮掉，混合物变深红。加白豆和水：将焯过的白豆放回锅中、加1.5升水（或蔬菜高汤）、2片月桂叶、1茶匙牛至、1.5茶匙盐和0.5茶匙胡椒、烧开后转小火慢炖。慢炖：不盖锅炖60–90分钟，偶尔搅拌，直到豆子完全软烂、中心奶油状但仍保持形状——1小时后每15分钟尝一颗豆、汤底应减少约一半并稠化至汤的稠度、如果减得太快加水。完成：取出月桂叶、加入30克切碎的芹菜叶（如使用）和1汤匙红酒醋提亮、尝味并调整盐量、离火，将60毫升新鲜特级初榨橄榄油淋在表面——这就是收尾油，让汤色亮油香气四溢、静置10分钟让风味稳定。上菜：盛入深碗，每份再淋一茶匙橄榄油，现磨黑胡椒撒在顶上、配脆乡村面包、一小碗Kalamata橄榄、碎feta奶酪和切碎的新鲜欧芹一起上桌、第二天更好吃。","en":"SOAK THE BEANS: place 400 g dried white beans in a large bowl, cover with cold water by 5 cm, and soak 8 hours or overnight; drain and rinse — the soak shortens the cooking time and helps even, intact beans. PARBOIL THE BEANS: place the drained beans in a large pot, cover with cold water by 3 cm, and bring to a boil; boil hard 10 minutes, then drain — this removes the indigestible compounds that cause gas and gives a cleaner-tasting broth. SOFFRITTO: in a heavy 5 L pot, heat 100 ml olive oil over medium heat; add 200 g diced onion + 200 g diced carrot + 150 g diced celery and cook, stirring often, 12–15 minutes until very soft and starting to gold — this slow vegetable base is the foundation of fasolada's depth; add 4 minced garlic cloves and cook 1 more minute until fragrant. BLOOM THE TOMATO: add 1 tbsp tomato paste and cook stirring 2 minutes until darkened; add 400 g grated tomato (or canned crushed) and simmer 5 minutes until the raw acidity cooks off and the mixture turns deep red. ADD BEANS AND WATER: return the parboiled beans to the pot; add 1.5 L water (or vegetable stock), 2 bay leaves, 1 tsp oregano, 1.5 tsp salt and 0.5 tsp pepper; bring to a boil, reduce to a gentle simmer. SLOW SIMMER: cook uncovered 60–90 minutes, stirring occasionally, until the beans are completely tender and creamy at the centre but still hold their shape — taste a bean every 15 minutes after the 1 hour mark; the broth should reduce by about half and thicken to a soupy consistency; add more water if it dries out too fast. FINISH: discard the bay leaves; stir in 30 g chopped celery leaves (if using) and 1 tbsp red wine vinegar for brightness; taste and adjust salt; off the heat, drizzle 60 ml fresh extra-virgin olive oil over the surface — this is the finishing oil that makes the soup glossy and aromatic; let rest 10 minutes for flavours to settle. SERVE: ladle into deep bowls, drizzle each portion with another teaspoon of olive oil, and grind fresh black pepper over the top; serve with crusty country bread, a small bowl of Kalamata olives, crumbled feta, and chopped fresh parsley on the table; even better the next day."}},{"id":162,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"墨西哥大玉米饼","en":"Tlayudas","ro":"Tlayudas"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["4张tlayuda玉米饼（~30厘米半干）或4张大麦面饼作替代","250克干黑豆，浸泡过夜（或1罐×400克）","100克猪油或100毫升植物油用于炒豆和烹饪","1个大洋葱（~200克）：一半切四瓣给豆子用，另一半切细末用于上菜","4瓣大蒜（2瓣给豆子，2瓣给肉）","豆子用：1茶匙磨碎的孜然+1茶匙干牛至+1茶匙盐","500克侧腹肉或裙带肉，逆纹切极薄片（tasajo风格）","200克新鲜墨西哥chorizo（或西班牙的），去肠衣","300克quesillo（瓦哈卡奶酪）或低水分马苏里拉，磨碎","200克切碎的iceberg生菜","2个成熟牛油果（~300克），切片","4个成熟番茄（~400克），切片","200克红或绿salsa（自制或商店购买）","1个青柠切瓣+新鲜香菜用于上菜"],"en":["4 tlayuda tortillas (~30 cm, semi-dried) or 4 large flour tortillas as substitute","250 g dried black beans soaked overnight (or 1 × 400 g can)","100 g lard or 100 ml vegetable oil for frying beans + cooking","1 large onion (~200 g): half quartered for the beans, the other half finely diced for serving","4 garlic cloves (2 for beans, 2 for meat)","1 tsp ground cumin + 1 tsp dried oregano + 1 tsp salt for the beans","500 g flank or skirt steak, sliced very thinly across the grain (tasajo-style)","200 g fresh Mexican chorizo (or Spanish), removed from casing","300 g quesillo (Oaxaca string cheese) or low-moisture mozzarella, shredded","200 g shredded iceberg lettuce","2 ripe avocados (~300 g), sliced","4 ripe tomatoes (~400 g), sliced","200 g salsa roja or salsa verde (homemade or store-bought)","1 lime cut into wedges + fresh cilantro for serving"],"ro":["4 tortillas tlayuda (~30 cm, semi-uscate) sau 4 tortillas mari de făină","250 g fasole neagră uscată înmuiată peste noapte (sau 1 conservă × 400 g)","100 g untură sau 100 ml ulei vegetal pentru prăjit fasolea + sotat","1 ceapă mare (~200 g): jumătate tăiată sferturi pentru fasole, cealaltă jumătate tocată fin pentru servire","4 căței de usturoi (2 pentru fasole, 2 pentru carne)","1 linguriță chimion măcinat + 1 linguriță oregano uscat + 1 linguriță sare pentru fasole","500 g flank steak sau skirt steak, feliat foarte subțire în diagonală (stil tasajo)","200 g chorizo proaspăt mexican (sau spaniol), scos din maț","300 g quesillo (brânză Oaxaca) sau mozzarella low-moisture, rasă","200 g salată iceberg, tocată","2 avocado coapte (~300 g), feliate","4 roșii coapte (~400 g), feliate","200 g salsa roja sau verde (de casă sau de la magazin)","1 lime tăiată sferturi + coriandru proaspăt pentru servire"]},"howIsMade":{"zh":"黑豆：沥干250克泡好的黑豆、加1.5升水，半个洋葱切四瓣、2瓣整大蒜、1茶匙孜然、1茶匙牛至和1茶匙盐煮60–90分钟至非常软、沥干，保留200毫升煮汁。炒豆泥（frijoles refritos）：平底锅中50克猪油用中火加热、加入煮好的豆子，用土豆压泥器或锅铲压碎，慢慢加入保留的煮汁直到形成浓稠奶油状糊、继续煮5–7分钟搅拌，直到略变黑并带烟熏香气。煎牛肉：大平底锅中1汤匙油用中高火加热、500克牛肉用盐和胡椒调味，单层每面煎2分钟（不要太满，分批煎）、装盘盖上锡纸保温。煎香肠：同一平底锅中加入200克去肠衣的chorizo，用木勺打散，中火煎5–7分钟直到红油析出且完全熟透、留在锅中连油。准备配菜：将2个牛油果、4个番茄和剩余半个洋葱（切细末）切片、切200克生菜、每样放入单独碗中以便快速组装。组装tlayuda：将plancha或大煎盘以中高火预热、在干燥表面上放一张tlayuda饼，涂上厚厚一层炒豆泥，留1厘米边缘、在豆上撒75克奶酪丝、加一份牛肉和chorizo。烤脆：在plancha上中火煮5–7分钟不翻面——饼底必须变金黄、酥脆、有轻微焦痕、奶酪必须完全融化、最后2分钟盖锅加速融化。上菜：用宽锅铲将tlayuda滑到盘子里、顶上加生菜、番茄片、牛油果、切碎洋葱、莎莎酱、挤上青柠汁，撒上香菜、对折或开口手吃、剩余3张tlayuda重复操作、立即上菜——放久了会发韧。","en":"THE BEANS: drain 250 g soaked black beans; boil in 1.5 L water with half an onion in quarters, 2 whole garlic cloves, 1 tsp cumin, 1 tsp oregano and 1 tsp salt for 60–90 minutes until very tender; drain, reserving 200 ml of the cooking liquid. REFRY THE BEANS (frijoles refritos): in a skillet, heat 50 g lard over medium heat; add the cooked beans and mash with a potato masher or spatula, adding the reserved liquid gradually until you have a thick creamy paste; cook 5–7 minutes, stirring, until slightly blackened and smoky. SEAR THE STEAK: heat 1 tbsp oil in a large skillet over medium-high; season 500 g beef with salt and pepper, sear 2 minutes per side in a single layer (do not crowd the pan, work in batches); rest the meat on a foil-tented plate. FRY THE CHORIZO: in the same skillet, add 200 g chorizo from its casing, break it up with a wooden spoon, and fry 5–7 minutes over medium heat until the red oil is released and the meat is fully cooked; leave it in the pan with its oil. PREP THE TOPPINGS: slice 2 avocados, 4 tomatoes and the remaining onion half (finely diced); shred 200 g lettuce; place each in a separate bowl for fast assembly. ASSEMBLE THE TLAYUDA: preheat a plancha or large griddle over medium-high heat; place a tlayuda tortilla on the dry surface and spread it with a generous layer of refried beans to within 1 cm of the edges; scatter 75 g shredded cheese over the beans; add a portion of seared steak and chorizo. CRISP IT UP: cook on the plancha over medium heat 5–7 minutes without flipping — the bottom of the tortilla must turn golden brown, crunchy, and show light scorch marks; the cheese must melt completely; cover with a lid for the last 2 minutes to speed melting. SERVE: slide the tlayuda onto a plate with a wide spatula; top with lettuce, tomato slices, avocado, diced onion, salsa; squeeze lime and scatter cilantro; fold in half or eat open with your hands; repeat for the remaining 3 tlayudas; serve immediately — it gets chewy if it sits."}},{"id":163,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"zh":"哥伦比亚","en":"Colombia","ro":"Columbia"},"name":{"zh":"哥伦比亚拼盘饭","en":"Bandeja Paisa","ro":"Bandeja Paisa"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["frijoles antioqueños所需：400克干红芸豆（cargamanto或kidney），泡过夜","1根中等胡萝卜（~100克）擦丝+2个中等番茄（~250克）擦丝+1个洋葱（~150克）切细末+4瓣大蒜用于hogao","豆类：2汤匙油+1汤匙番茄酱+1茶匙孜然+1茶匙盐","1根熟plantain（~150克）切丁加入豆中","arroz blanco所需：360克（2杯）中粒米+540毫升水+0.5茶匙盐","carne molida所需：500克牛肉碎+1个洋葱切细末+4瓣大蒜+2个擦丝番茄+2汤匙油+1茶匙孜然+1茶匙盐+0.5茶匙胡椒+50毫升牛肉高汤","chicharrón所需：800克带皮猪五花切8条~10厘米+1茶匙盐","4根生哥伦比亚chorizo（每根~80克）","4根morcilla（血肠，每根~80克）","4个小arepas所需：200克预煮白玉米粉（Harina P.A.N.）+240毫升温水+0.5茶匙盐+1汤匙油用于煎板","maduro所需：2根非常成熟的plantain（皮深黑色）+2汤匙油","4个大鸡蛋用于煎太阳蛋+1汤匙油+盐和胡椒","2个成熟牛油果，对半切开去核","4片脆白面包+4个青柠瓣+上菜用盐"],"en":["For frijoles antioqueños: 400 g dried red kidney or cargamanto beans, soaked overnight","1 medium carrot (~100 g) grated + 2 medium tomatoes (~250 g) grated + 1 onion (~150 g) finely diced + 4 garlic cloves for the hogao","2 tbsp oil + 1 tbsp tomato paste + 1 tsp ground cumin + 1 tsp salt for the beans","1 ripe plantain (~150 g) diced for the beans","For arroz blanco: 360 g (2 cups) medium-grain white rice + 540 ml water + 0.5 tsp salt","For carne molida: 500 g ground beef + 1 onion finely diced + 4 garlic cloves + 2 grated tomatoes + 2 tbsp oil + 1 tsp cumin + 1 tsp salt + 0.5 tsp pepper + 50 ml beef stock","For chicharrón: 800 g pork belly skin-on cut into 8 strips of ~10 cm + 1 tsp salt","4 raw Colombian chorizos (~80 g each)","4 morcillas (blood sausages, ~80 g each)","For 4 small arepas: 200 g precooked white corn flour (Harina P.A.N.) + 240 ml warm water + 0.5 tsp salt + 1 tbsp oil for the griddle","For maduro: 2 very ripe plantains (deep black skin) + 2 tbsp oil","4 large eggs for sunny-side up + 1 tbsp oil + salt and pepper","2 ripe avocados, halved and pitted","4 slices of crusty white bread + 4 lime wedges + salt to serve"],"ro":["Pentru frijoles antioqueños: 400 g fasole roșie uscată (cargamanto sau kidney) înmuiată peste noapte","1 morcov mediu (~100 g) ras + 2 roșii medii (~250 g) rase + 1 ceapă (~150 g) tocată fin + 4 căței usturoi pentru hogao","2 linguri ulei + 1 lingură pastă de roșii + 1 linguriță chimion + 1 linguriță sare pentru fasole","1 banană plantain coaptă (~150 g) tocată în cuburi pentru fasole","Pentru arroz blanco: 360 g (2 căni) orez cu bob mediu + 540 ml apă + 0,5 linguriță sare","Pentru carne molida: 500 g vită tocată + 1 ceapă tocată + 4 căței usturoi + 2 roșii rase + 2 linguri ulei + 1 linguriță chimion + 1 linguriță sare + 0,5 linguriță piper + 50 ml supă de vită","Pentru chicharrón: 800 g costiță de porc cu coajă tăiată în 8 fâșii lungi de 10 cm + 1 linguriță sare","4 chorizos columbieni cruzi (~80 g fiecare)","4 morcillas (cârnați de sânge, ~80 g fiecare)","Pentru arepas (4 mici): 200 g făină de porumb precoaptă (Harina P.A.N.) + 240 ml apă caldă + 0,5 linguriță sare + 1 lingură ulei pentru tigaie","Pentru maduro: 2 banane plantain foarte coapte (coaja neagră) + 2 linguri ulei","4 ouă mari pentru ochiuri + 1 lingură ulei + sare și piper","2 avocado coapte, jumătățite și fără sâmbure","4 felii pâine albă crocantă + 4 felii de lime + sare pentru servire"]},"howIsMade":{"zh":"浸泡和准备：将400克红芸豆浸泡过夜、bandeja paisa需要6个组件并行操作——开始前准备好所有食材和工具，加上3个锅和2个煎锅。红芸豆：沥干豆子，加1.5升水、擦丝胡萝卜+1个擦丝番茄+洋葱+2瓣大蒜+1茶匙孜然+1茶匙盐，煮60–90分钟至软烂、最后15分钟做hogao：2汤匙油中炒剩余洋葱+2瓣大蒜+1个擦丝番茄+1汤匙番茄酱5分钟、加入豆子和切块的plantain再煮10分钟。米饭：用冷水冲洗360克米3次、加540毫升水和0.5茶匙盐、烧开后盖锅转最小火12分钟，关火盖焖10分钟。carne molida：平底锅2汤匙油中高火加热、洋葱和大蒜炒5分钟至软、加500克牛肉碎，用勺打散煎8分钟、加2个擦丝番茄、1茶匙孜然、1茶匙盐和0.5茶匙胡椒煮5分钟、用50毫升高汤deglaze。chicharrón：将8条带皮猪五花放入锅中，加200毫升冷水和1茶匙盐、烧开后盖锅煮30分钟、完全沥干、同锅中将猪五花在自己的油中以中高火煎8–10分钟，经常翻面，直到皮金黄酥脆、（替代：200 °C烤箱40分钟放在烤架上、）。arepas：在碗中混合200克玉米粉、240毫升温水和0.5茶匙盐至湿润面团、静置5分钟、做成4个直径10厘米、厚1厘米的饼、在烧热的平底锅中加1汤匙油以中火煎4–5分钟每面，直到金黄带深色斑点。maduro+鸡蛋+香肠：将2个黑plantain切1厘米厚片、2汤匙油中以中火煎2分钟每面至焦糖化、另一平底锅中4根生chorizo每面煎5分钟，4根morcilla每面煎3分钟、然后用1茶匙油煎4个鸡蛋2分钟，至蛋白凝固但蛋黄流动。摆盘：在4个大盘子上按此顺序摆放：一堆米饭、一大勺豆子、一份carne molida、2块chicharrón、1根chorizo、1根morcilla、1个煎蛋放在肉上、2片maduro、1/2个牛油果、1个arepa、1片面包、1块青柠、立即上菜——bandeja paisa用刀叉吃，每一口都搭配几种食材。","en":"SOAK & PLAN: soak 400 g red beans overnight; bandeja paisa runs 6 parallel components — gather all ingredients and tools before starting, plus 3 pots and 2 skillets. THE BEANS: drain the beans, simmer in 1.5 L water with grated carrot + 1 grated tomato + onion + 2 garlic cloves + 1 tsp cumin + 1 tsp salt 60–90 minutes until tender; in the final 15 minutes make the hogao: sauté in 2 tbsp oil the remaining onion + 2 garlic + 1 grated tomato + 1 tbsp tomato paste 5 minutes; stir into the beans with the diced plantain and cook 10 more minutes. THE RICE: rinse 360 g rice in cold water 3 times; place with 540 ml water and 0.5 tsp salt; bring to a boil, cover, reduce to lowest heat 12 minutes, rest covered 10 minutes. CARNE MOLIDA: heat 2 tbsp oil in a skillet over medium-high; sauté onion and garlic 5 minutes until soft; add 500 g ground beef, break up with the spoon and brown 8 minutes; add 2 grated tomatoes, 1 tsp cumin, 1 tsp salt and 0.5 tsp pepper, cook 5 minutes; deglaze with 50 ml stock. CHICHARRÓN: place 8 strips of pork belly skin-on in a pot with 200 ml cold water and 1 tsp salt; bring to a boil, cover and simmer 30 minutes; drain completely; in the same pot, fry the pork in its own fat over medium-high heat 8–10 minutes turning often until the skin is golden and crackling; (Alternative: 200 °C oven 40 minutes on a rack.). AREPAS: mix 200 g corn flour with 240 ml warm water and 0.5 tsp salt in a bowl until a damp dough forms; rest 5 minutes; shape into 4 patties of 10 cm diameter and 1 cm thick; griddle in a hot pan with 1 tbsp oil over medium heat 4–5 minutes per side until golden with dark spots. MADURO + EGGS + SAUSAGES: slice 2 black plantains into 1 cm rounds; fry in 2 tbsp oil over medium heat 2 minutes per side until caramelized; in another skillet, fry 4 raw chorizos 5 minutes per side and 4 morcillas 3 minutes per side; then fry 4 eggs in 1 tsp oil 2 minutes until whites set but yolks runny. ASSEMBLY: on 4 large platters arrange in this order: a mound of rice, a generous ladle of beans, a portion of carne molida, 2 chicharrón pieces, 1 chorizo, 1 morcilla, 1 fried egg on top of the meat, 2 maduro slices, 1/2 avocado, 1 arepa, 1 bread slice, 1 lime wedge; serve immediately — bandeja paisa is eaten with knife and fork, each bite in combination with others."}},{"id":164,"servings":4,"tipType":"def","pairingsType":"def","origin":{"zh":"匈牙利","en":"Hungary","ro":"Ungaria"},"name":{"zh":"匈牙利油饼","en":"Lángos","ro":"Lángos"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["500克通用面粉或T550面包粉","7克即用干酵母（或21克鲜酵母）","1茶匙细砂糖（喂养酵母）","1.5茶匙细盐用于面团","300毫升温全脂牛奶（或水，传统）38°C","100克煮过捣碎的土豆（蓬松质地的秘诀）","2汤匙中性油用于面团","1升葵花籽油或中性油用于油炸","蒜涂层：4瓣大蒜与1茶匙盐+1汤匙水捣成糊","200克匈牙利酸奶油（tejföl）","200克浓味磨碎奶酪（cheddar/gouda/edam风格）","1小束新鲜虾夷葱，切细末（可选）","盐用于最终调味","设备：宽厚重锅用于油炸+漏勺+冷却架"],"en":["500 g all-purpose or T550 bread flour","7 g instant dry yeast (or 21 g fresh yeast)","1 tsp granulated sugar (to feed yeast)","1.5 tsp fine salt for the dough","300 ml warm whole milk (or water, traditional) at 38 °C","100 g boiled mashed potato (the secret to the fluffy texture)","2 tbsp neutral oil for the dough","1 L sunflower or neutral oil for deep-frying","For garlic rub: 4 garlic cloves crushed with 1 tsp salt + 1 tbsp water into a paste","200 g Hungarian sour cream (tejföl)","200 g sharp grated cheese (cheddar/gouda/edam-style)","1 small bunch fresh chives, finely chopped (optional)","Salt for finishing","Equipment: wide heavy pot for frying + slotted spoon + wire rack"],"ro":["500 g făină universală sau de pâine T550","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 linguriță zahăr granulat (pentru hrănirea drojdiei)","1,5 lingurițe sare fină pentru aluat","300 ml lapte integral cald (sau apă, tradițional) la 38 °C","100 g cartof fiert și pasat (secretul texturii pufoase)","2 linguri ulei neutru pentru aluat","1 L ulei de floarea-soarelui sau neutru pentru prăjit","Pentru ungerea cu usturoi: 4 căței de usturoi zdrobiți cu 1 linguriță sare + 1 lingură apă în pastă","200 g smântână ungurească (tejföl)","200 g brânză tare rasă (cheddar/gouda/edam)","1 legăturică mică de ceapă verde proaspătă (arpagic), tocată fin (opțional)","Sare pentru finisare","Echipament: oală grea și lată pentru prăjit + lingură cu fante + grătar de sârmă"]},"howIsMade":{"zh":"激活酵母：将100毫升牛奶加热至38°C，加7克酵母和1茶匙糖，搅拌后静置10分钟直到起泡沫、没有泡沫=酵母死了，重新开始。做面团：在大碗中将500克面粉与1.5茶匙盐混合、做一个井，加入起泡的酵母牛奶、剩下的200毫升温牛奶、100克细滑的土豆泥（无块）和2汤匙油、手揉或厨师机搅拌10分钟，直到光滑、柔软且略黏——比面包面团更软。第一次发酵：用干净毛巾盖住，在温暖处发酵1.5–2小时直到双倍大。整形：手和工作台抹少许油、分成4等份（每份~225克）、滚成球，盖上静置10分钟、用抹油的手将每个球伸展成25厘米的圆盘，约1厘米厚，边缘稍薄。第二次发酵：将整形好的圆盘放在抹油的烤盘上，松散盖住，发酵20分钟直到蓬松。加热油：将1升油倒入宽且厚重的锅中，深度5厘米、加热至175°C（中高火）——一小片面团应该在5秒内发出嘶嘶声并浮起。炸lángos：小心将一个lángos滑入热油中、30秒后用漏勺轻轻压入油下——它会戏剧性地膨胀、每面炸60–90秒至深金黄色、在金属架上沥干（不要用纸巾，蒸汽会使底部变软）。配料与上菜：在仍然热的表面刷上蒜泥（4瓣大蒜与1茶匙盐+1汤匙水捣碎）、涂50克酸奶油，撒50克磨碎奶酪，撒上切碎的虾夷葱和一撮盐、手持或装盘上菜，5分钟内吃完，趁着面包外脆内软。","en":"PROOF THE YEAST: warm 100 ml of the milk to 38 °C, add 7 g yeast and 1 tsp sugar, stir and let stand 10 minutes until foamy; no foam = dead yeast, start over. MAKE THE DOUGH: in a large bowl combine 500 g flour with 1.5 tsp salt; make a well, add the foamed yeast-milk, the remaining 200 ml warm milk, 100 g smooth mashed potato (no lumps), and 2 tbsp oil; knead by hand or stand mixer 10 minutes until smooth, soft and slightly sticky — softer than bread dough. FIRST PROOF: cover with a clean towel and rise in a warm place 1.5–2 hours until doubled. SHAPE: lightly oil hands and work surface; divide into 4 equal portions (~225 g each); roll into balls, rest 10 minutes covered; with oiled hands stretch each ball into a 25 cm disc about 1 cm thick, slightly thinner at the edges. SECOND PROOF: place shaped discs on an oiled tray, cover loosely and let rise 20 minutes until puffy. HEAT THE OIL: pour 1 L oil into a wide heavy pot to a 5 cm depth; heat to 175 °C (medium-high) — a small piece of dough should sizzle and rise within 5 seconds. FRY THE LÁNGOS: carefully slide one lángos into the hot oil; after 30 seconds, gently push under with a slotted spoon — it puffs dramatically; fry 60–90 seconds per side until deeply golden brown; drain on a wire rack (NOT paper towels which steam the base soft). TOPPING & SERVE: brush the still-hot top with garlic paste (4 garlic crushed with 1 tsp salt + 1 tbsp water); smear with 50 g sour cream, scatter 50 g grated cheese, sprinkle chopped chives and a pinch of salt; serve in hand or on a plate, eaten within 5 minutes while bread is crisp outside and pillowy inside."}},{"id":165,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"zh":"印度","en":"India","ro":"India"},"name":{"zh":"红豆咖喱","en":"Rajma","ro":"Rajma"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["350克干红芸豆（rajma）在冷水中浸泡8–12小时（或2×400克罐装红芸豆沥干作为捷径）","1.2升豆子煮水+1茶匙盐+2片月桂叶+4个黑豆蔻荚（用于高压锅煮豆子）","3汤匙酥油或中性油用于马萨拉","1茶匙完整孜然籽（jeera）","2个中等黄洋葱（~300克）切得非常细","6瓣大蒜+4厘米新鲜姜——与1汤匙水一起磨成糊","1个青辣椒（或按口味），切细","4个中等成熟番茄（~400克），用搅拌机打成细泥","1汤匙番茄酱（增加浓稠度）","1茶匙磨碎芫荽（dhania）+1茶匙磨碎孜然（jeera）+0.5茶匙姜黄（haldi）+1茶匙克什米尔红辣椒粉+1茶匙盐用于马萨拉","1茶匙印度什香粉garam masala（最后加入，不要煮）","1茶匙kasuri methi（干胡芦巴叶），手心搓碎（最后加入）","30克黄油切丁（餐厅式收尾）","1汤匙单一奶油或2汤匙全脂酸奶（可选，增加奶滑度）","新鲜香菜叶作为装饰+1个青柠切角；上菜：360克（2杯）巴斯马蒂米饭，用540毫升水加0.5茶匙盐煮，或如喜欢用naan或jeera rice"],"en":["350 g dried red kidney beans (rajma) soaked 8–12 h in cold water (OR 2 × 400 g cans drained as a shortcut)","1.2 L cooking water for the beans + 1 tsp salt + 2 bay leaves + 4 black cardamom pods (for pressure-cooking the beans)","3 tbsp ghee or neutral oil for the masala","1 tsp whole cumin seeds (jeera)","2 medium yellow onions (~300 g) very finely diced","6 garlic cloves + 4 cm fresh ginger — grated into a paste with 1 tbsp water","1 green chili (or to taste), finely chopped","4 medium ripe tomatoes (~400 g), pureed in a blender to a smooth pulp","1 tbsp tomato paste (for body)","1 tsp ground coriander (dhania) + 1 tsp ground cumin (jeera) + 0.5 tsp turmeric (haldi) + 1 tsp Kashmiri red chili powder + 1 tsp salt for the masala","1 tsp garam masala (added at end, not boiled)","1 tsp kasuri methi (dried fenugreek leaves), crushed in palm (added at end)","30 g butter cubed (the restaurant-style finish)","1 tbsp single cream or 2 tbsp full-fat yogurt (optional, for creaminess)","Fresh coriander (cilantro) leaves to garnish + 1 lime in wedges; to serve: 360 g (2 cups) basmati rice cooked in 540 ml water with 0.5 tsp salt, and naan or jeera rice if preferred"],"ro":["350 g fasole roșie uscată (rajma) înmuiată 8–12 h în apă rece (SAU 2 × 400 g cutii de fasole roșie scursă ca scurtătură)","1,2 L apă de fierbere pentru fasole + 1 linguriță sare + 2 foi de dafin + 4 păstăi de cardamom negru (pentru fierberea sub presiune)","3 linguri ghee sau ulei neutru pentru masala","1 linguriță semințe întregi de chimion (jeera)","2 cepe galbene medii (~300 g) tocate foarte fin","6 căței de usturoi + 4 cm de ghimbir proaspăt — răzuite în pastă cu 1 lingură de apă","1 ardei iute verde (sau după gust), tocat fin","4 roșii medii coapte (~400 g), pasate la blender până la o pulpă fină","1 lingură pastă de roșii (pentru corp)","1 linguriță coriandru măcinat (dhania) + 1 linguriță chimion măcinat (jeera) + 0,5 linguriță turmeric (haldi) + 1 linguriță Kashmiri chili pudră + 1 linguriță sare pentru masala","1 linguriță garam masala (adăugat la final, nu fiert)","1 linguriță kasuri methi (frunze uscate de schinduf), zdrobite în palmă (adăugat la final)","30 g unt cubulețe (finisajul în stil restaurant)","1 lingură smântână dulce single sau 2 linguri iaurt gras (opțional, pentru cremozitate)","Frunze proaspete de coriandru (cilantro) pentru garnitură + 1 lămâie verde feliată; pentru servire: 360 g (2 căni) orez basmati fiert în 540 ml apă cu 0,5 linguriță sare, plus naan sau jeera rice dacă preferi"]},"howIsMade":{"zh":"浸泡豆子：用冷水冲洗350克rajma 2–3次、用冷水盖过5厘米浸泡8–12小时（或过夜）、沥干冲洗、跳过浸泡会导致中心未煮熟和产生气体的口感。高压锅煮豆子：将浸泡好的rajma放入高压锅中，加1.2升水+1茶匙盐+2片月桂叶+4个黑豆蔻荚、大火高压煮4–5声哨音，然后转小火煮25分钟、让压力自然释放、豆子应完全软化——用拇指和食指按压一颗；应在轻压下变软、（替代方案：开放锅1.5–2小时炖煮、）沥干并保留500毫升豆汁。巴努奥（BHUNAO）——调温：在厚重的卡德海（kadhai）或深锅中用中火融化3汤匙酥油、当闪闪发亮时，加入1茶匙孜然籽——它们会在5秒内发出嘶嘶声并爆裂、不要让它们变黑。洋葱：加入300克切得非常细的洋葱、经常搅拌煮12–15分钟直到深金黄色——几乎焦糖化、这种长时间、缓慢的洋葱巴努奥是将餐厅rajma与业余尝试区分开的关键、不要急。姜-蒜-辣椒：加入姜蒜糊和青辣椒、搅拌1–2分钟直到生味消失。番茄底：加入打成泥的番茄+1汤匙番茄酱+1茶匙磨碎芫荽+1茶匙磨碎孜然+0.5茶匙姜黄+1茶匙克什米尔辣椒+1茶匙盐、经常搅拌煮8–10分钟，直到油从锅边的马萨拉中分离出来——这是巴努奥完成且生番茄已煮熟的视觉迹象。与豆子炖煮：倒入沥干的rajma和500毫升预留的豆汁、轻轻搅拌、煮沸然后开盖煮20–25分钟，用勺子将一些豆子部分压碎到锅边以增稠酱汁、酱汁应减少并裹住豆子——既不汤汤水水也不干燥，像浓稠的炖菜挂在勺子上。收尾与上桌：加入1茶匙garam masala+1茶匙压碎的kasuri methi+30克切丁黄油+1汤匙奶油（可选）、搅拌直到黄油融化、盖上盖子离火静置5分钟让味道融合、配蒸熟的巴斯马蒂米饭（或jeera rice或naan）热腾腾上桌，撒上切碎的新鲜香菜和挤上青柠、第二天更好吃。","en":"SOAK THE BEANS: rinse 350 g rajma in cold water 2–3 times; cover with cold water by 5 cm and soak 8–12 hours (or overnight); drain and rinse; skipping the soak gives undercooked centers and gassy texture. PRESSURE-COOK THE BEANS: place soaked rajma in a pressure cooker with 1.2 L water + 1 tsp salt + 2 bay leaves + 4 black cardamom pods; pressure-cook on high heat 4–5 whistles, then reduce to low and cook 25 minutes; let the pressure release naturally; beans should be completely tender — press one between thumb and forefinger; it should mash with light pressure; (Alternative: open pot 1.5–2 h simmer.) Drain reserving 500 ml bean cooking liquid. BHUNAO — TEMPER: in a heavy kadhai or deep pan over medium heat, melt 3 tbsp ghee; when shimmering, add 1 tsp cumin seeds — they will sizzle and pop within 5 seconds; do not let them blacken. ONIONS: add 300 g very finely diced onion; cook stirring often 12–15 minutes until deeply golden brown — almost caramelized; this long, slow onion bhunao is what separates restaurant rajma from amateur attempts; do not rush. GINGER-GARLIC-CHILI: add the ginger-garlic paste and green chili; stir 1–2 minutes until the raw smell disappears. TOMATO BASE: add the pureed tomato pulp + 1 tbsp tomato paste + 1 tsp ground coriander + 1 tsp ground cumin + 0.5 tsp turmeric + 1 tsp Kashmiri chili powder + 1 tsp salt; cook stirring frequently 8–10 minutes until the oil separates from the masala on the edges of the pan — this is the visual sign the bhunao is complete and the raw tomato has cooked off. SIMMER WITH BEANS: tip in the drained rajma and 500 ml of reserved bean liquid; stir gently; bring to a simmer and cook uncovered 20–25 minutes, partially mashing some beans against the side of the pan with a spoon to thicken the gravy; the gravy should reduce and coat the beans — neither soupy nor dry, like a thick stew that holds on a spoon. FINISH AND SERVE: stir in 1 tsp garam masala + 1 tsp crushed kasuri methi + 30 g butter cubed + 1 tbsp cream (optional); stir until butter melts; cover and let rest off heat 5 minutes for flavors to settle; serve hot over steamed basmati rice (or jeera rice or naan), topped with chopped fresh coriander and a squeeze of lime; better the next day."}},{"id":166,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"zh":"古巴","en":"Cuba","ro":"Cuba"},"name":{"zh":"古巴炖碎牛肉","en":"Picadillo","ro":"Picadillo"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["600克牛肉末（肩肉，约20%脂肪）","2汤匙橄榄油用于sofrito调味底","1个大黄洋葱（~200克），切细丁","1个大青椒（~200克），切细丁","6瓣大蒜，切碎","1茶匙磨碎孜然（comino）+ 1茶匙干牛至 + 0.5茶匙甜烟熏红椒粉（pimentón）+ 1片月桂叶","400克罐装碎番茄（或4个新鲜番茄去皮磨碎）+ 2汤匙番茄酱","100毫升干白葡萄酒或50毫升干雪利酒（古巴传统——烧掉生肉味）","100克去核绿橄榄（manzanilla），对半切","60克金色或黑色葡萄干，在100毫升热水中浸泡10分钟然后沥干","100克冷冻青豆，解冻","1汤匙刺山柑（酸豆），沥干（可选，传统）","1.5茶匙盐 + 0.5茶匙新鲜研磨黑胡椒","新鲜平叶欧芹用于装饰","上菜：360克（2杯）白米饭，用540毫升水加0.5茶匙盐煮 + 240克煮熟的黑豆 + 2根成熟大蕉切片油炸 + 青柠角"],"en":["600 g ground beef (chuck, ~20% fat)","2 tbsp olive oil for the sofrito","1 large yellow onion (~200 g), finely diced","1 large green bell pepper (~200 g), finely diced","6 garlic cloves, minced","1 tsp ground cumin (comino) + 1 tsp dried oregano + 0.5 tsp sweet smoked paprika (pimentón) + 1 bay leaf","400 g can crushed tomatoes (or 4 fresh tomatoes peeled and grated) + 2 tbsp tomato paste","100 ml dry white wine OR 50 ml dry sherry (Cuban traditional — burns off raw-meat smell)","100 g pitted green olives (manzanilla), halved","60 g golden or dark raisins, soaked 10 min in 100 ml hot water then drained","100 g frozen green peas, thawed","1 tbsp capers, drained (optional, traditional)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","Fresh flat-leaf parsley to garnish","To serve: 360 g (2 cups) white rice cooked in 540 ml water with 0.5 tsp salt + 240 g cooked black beans + 2 ripe plantains sliced and fried + lime wedges"],"ro":["600 g carne tocată de vită (gât/cap de piept, ~20% grăsime)","2 linguri ulei de măsline pentru sofrito","1 ceapă galbenă mare (~200 g), tăiată cubulețe fine","1 ardei gras verde mare (~200 g), tăiat cubulețe fine","6 căței de usturoi, tocați mărunt","1 linguriță chimion măcinat (comino) + 1 linguriță oregano uscat + 0,5 linguriță boia dulce afumată (pimentón) + 1 foaie de dafin","400 g roșii zdrobite la conservă (sau 4 roșii proaspete decojite și răzuite) + 2 linguri pastă de roșii","100 ml vin alb sec SAU 50 ml sherry sec (tradițional cubanez — arde mirosul de carne crudă)","100 g măsline verzi fără sâmburi (manzanilla), tăiate în jumătăți","60 g stafide aurii sau negre, înmuiate 10 minute în 100 ml apă caldă, apoi scurse","100 g mazăre verde congelată, dezghețată","1 lingură capere, scurse (opțional, tradițional)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","Pătrunjel verde proaspăt cu frunza lată pentru garnitură","Pentru servire: 360 g (2 căni) orez alb fiert în 540 ml apă cu 0,5 linguriță sare + 240 g fasole neagră fiartă + 2 banane plantain coapte feliate și prăjite + felii de lămâie verde"]},"howIsMade":{"zh":"SOFRITO底料：在重型5升锅中，用中火加热2汤匙橄榄油、加入200克切丁洋葱+200克切丁青椒和一撮盐、经常搅拌煮8–10分钟直到变软并开始变金黄——sofrito是古巴烹饪的灵魂、加入6瓣切碎的大蒜再煮1分钟直到香气四溢。香料绽放：将1茶匙孜然、1茶匙牛至、0.5茶匙烟熏红椒粉和1片月桂叶加入热的油和蔬菜底料中、搅拌30秒直到香料释放香气——不要烧焦。煎牛肉：将火调至中高、加入600克牛肉末成单层，不要触碰2–3分钟以形成焦壳、然后用木勺打散，再煎6–8分钟，直到不再有粉红色且释放的液体已经蒸发。去渍：倒入100毫升干白葡萄酒（或50毫升雪利酒），刮起任何粘在锅底的金黄碎屑、煮2–3分钟直到酒精味消失。番茄+构建：加入罐装碎番茄+2汤匙番茄酱、煮5分钟直到混合物颜色加深，油开始浮现在表面——番茄完全煮熟，无生酸味。加入橄榄、葡萄干和调味：加入100克对半切的绿橄榄+60克沥干的葡萄干+1汤匙刺山柑（如果使用）+1.5茶匙盐+0.5茶匙胡椒、甜咸对比是独特的古巴印记。慢炖：将火调至小火，部分盖盖，慢炖20–25分钟，每几分钟搅拌一次、混合物应浓稠成带酱汁的hash——既不干也不汤汤水水，能在勺子上保持、如果太干，加入60毫升水。青豆与上桌：在最后3分钟，加入100克解冻的青豆——只加热，保持鲜绿色、取出月桂叶、离火后撒上切碎的欧芹、配蒸熟的白米饭、旁边的黑豆、炸大蕉和青柠角一起上桌——经典的古巴comida criolla餐盘。","en":"SOFRITO BASE: in a heavy 5 L pot, heat 2 tbsp olive oil over medium heat; add 200 g diced onion + 200 g diced green pepper with a pinch of salt; cook stirring often 8–10 minutes until soft and beginning to gold — the sofrito is the soul of Cuban cooking; add 6 minced garlic cloves and cook 1 minute more until fragrant. BLOOM THE SPICES: add 1 tsp cumin, 1 tsp oregano, 0.5 tsp smoked paprika and 1 bay leaf to the hot oil-and-vegetable base; stir 30 seconds until the spices release their aroma — do not burn. BROWN THE BEEF: raise heat to medium-high; add 600 g ground beef in a single layer and let it sit undisturbed 2–3 minutes to develop a crust; then break it up with a wooden spoon and brown another 6–8 minutes until no pink remains and any released liquid has evaporated. DEGLAZE: pour in 100 ml dry white wine (or 50 ml sherry) and scrape any browned bits stuck to the bottom of the pot; simmer 2–3 minutes until the alcohol smell disappears. TOMATO + BUILD: stir in the can of crushed tomatoes + 2 tbsp tomato paste; cook 5 minutes until the mixture darkens and oil starts to appear on the surface — tomato fully cooked, no raw acidity. ADD OLIVES, RAISINS & SEASON: stir in 100 g halved green olives + 60 g drained raisins + 1 tbsp capers (if using) + 1.5 tsp salt + 0.5 tsp pepper; the sweet-salty contrast is the unique Cuban signature. SIMMER: reduce heat to low, cover partially, and simmer 20–25 minutes, stirring every few minutes; the mixture should thicken into a saucy hash — neither dry nor soupy, holding together on a spoon; add 60 ml water if it gets too dry. PEAS & SERVE: in the last 3 minutes, stir in 100 g thawed peas — just to warm through, keeping them bright green; remove the bay leaf; off the heat, scatter chopped parsley; serve over steamed white rice with black beans on the side, fried plantains, and lime wedges — the classic Cuban comida criolla plate."}},{"id":167,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"摩洛哥","en":"Morocco","ro":"Maroc"},"name":{"zh":"羊肉塔吉锅","en":"Lamb Tagine","ro":"Tagine cu miel"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["1公斤去骨羊肩肉，切成4厘米方块（带一些脂肪以增加丰腴）","2个大黄洋葱（~400克），一个切细丁作底料，另一个切厚瓣用于炖煮","6瓣大蒜，切碎","4厘米新鲜生姜，磨碎","3汤匙橄榄油（或2汤匙油+1汤匙黄油用于传统的丰腴感）","1茶匙磨碎孜然+1茶匙磨碎芫荽+1茶匙磨碎肉桂+0.5茶匙磨碎姜黄+0.5茶匙甜红椒粉+0.5茶匙磨碎生姜+一撮藏红花丝（5–6根，用2汤匙热水浸泡）","1.5茶匙ras el hanout（摩洛哥香料混合）","1.5茶匙盐+0.5茶匙新鲜研磨黑胡椒","2汤匙番茄酱","400克成熟番茄（4个中等），去皮磨碎，或1罐×400克","200克杏干，对半切（土耳其或加州——不要太甜）","60克去核西梅干或葡萄干（可选，增加深度）","600毫升热水或低盐鸡汤","1根肉桂棒+1片月桂叶","80克整粒去皮杏仁（或带皮，烤过）","1汤匙蜂蜜（最后加入以平衡甜味）","新鲜芫荽+平叶欧芹+1汤匙轻烤芝麻用于装饰","上菜：400克古斯米用400毫升水+1汤匙黄油+0.5茶匙盐蒸熟，或温暖的khobz扁面包"],"en":["1 kg boneless lamb shoulder, cut into 4 cm cubes (with some fat on for richness)","2 large yellow onions (~400 g), one finely diced for the base and one cut into thick wedges for the stew","6 garlic cloves, minced","4 cm fresh ginger, grated","3 tbsp olive oil (or 2 tbsp oil + 1 tbsp butter for traditional richness)","1 tsp ground cumin + 1 tsp ground coriander + 1 tsp ground cinnamon + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground ginger + a pinch of saffron threads (5–6 strands, bloomed in 2 tbsp hot water)","1.5 tsp ras el hanout (Moroccan spice blend)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","2 tbsp tomato paste","400 g ripe tomatoes (4 medium), peeled and grated, or 1 × 400 g can","200 g dried apricots, halved (use Turkish or California — not too sweet)","60 g pitted dried prunes or raisins (optional, for depth)","600 ml hot water or low-salt chicken stock","1 cinnamon stick + 1 bay leaf","80 g whole blanched almonds (or skin-on, toasted)","1 tbsp honey (added at the end to balance sweetness)","Fresh coriander + flat-leaf parsley + 1 tbsp lightly toasted sesame seeds to garnish","To serve: 400 g couscous steamed with 400 ml water + 1 tbsp butter + 0.5 tsp salt, OR warm khobz flatbread"],"ro":["1 kg pulpă de miel dezosată (spată), tăiată cuburi de 4 cm (cu puțină grăsime pentru bogăție)","2 cepe galbene mari (~400 g), una tăiată cubulețe fine pentru bază și una tăiată în felii groase pentru tocăniță","6 căței de usturoi, tocați mărunt","4 cm ghimbir proaspăt, ras","3 linguri ulei de măsline (sau 2 linguri ulei + 1 lingură unt pentru bogăție tradițională)","1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 1 linguriță scorțișoară măcinată + 0,5 linguriță turmeric măcinat + 0,5 linguriță boia dulce + 0,5 linguriță ghimbir măcinat + un vârf de șofran (5–6 fire, înflorit în 2 linguri apă caldă)","1,5 linguriță ras el hanout (amestec marocan de condimente)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","2 linguri pastă de roșii","400 g roșii coapte (4 medii), decojite și răzuite, sau 1 cutie × 400 g","200 g caise uscate, tăiate în jumătăți (turcești sau californiene — nu prea dulci)","60 g prune uscate fără sâmburi sau stafide (opțional, pentru profunzime)","600 ml apă fierbinte sau supă de pui cu puțină sare","1 baton de scorțișoară + 1 foaie de dafin","80 g migdale întregi blanșate (sau cu coajă, prăjite)","1 lingură miere (adăugată la final pentru a echilibra dulceața)","Coriandru proaspăt + pătrunjel cu frunza lată + 1 lingură semințe de susan ușor prăjite pentru garnitură","Pentru servire: 400 g couscous aburit cu 400 ml apă + 1 lingură unt + 0,5 linguriță sare, SAU pâine plată khobz caldă"]},"howIsMade":{"zh":"腌制羊肉：在一个大碗中将1公斤羊肉块与1茶匙孜然+1茶匙芫荽+1茶匙肉桂+0.5茶匙姜黄+0.5茶匙红椒粉+0.5茶匙生姜+1.5茶匙ras el hanout+1.5茶匙盐+0.5茶匙胡椒+3瓣切碎的大蒜和1汤匙橄榄油混合、用手将香料揉进肉中、盖好在室温下静置30分钟（或冰箱中最多24小时），让香料渗透。浸泡藏红花：将5–6根藏红花丝放入2汤匙热水中浸泡10分钟——这能释放风味和颜色、备用。构建底料：在厚底塔吉锅或荷兰锅中用中火加热剩余的2汤匙油（如果使用，加1汤匙黄油）、加入200克切细丁洋葱，经常搅拌煮8–10分钟直到变软透明、加入剩余3瓣切碎的大蒜+磨碎的生姜，搅拌1分钟。煎羊肉：将火调至中高、将洋葱推到锅边，把腌好的羊肉单层加入（需要时分2批）、每面煎3–4分钟，不要移动，直到各面深度焦黄——焦壳对炖菜的浓郁风味至关重要、羊肉煎好后将所有食材一起搅拌。番茄+液体：加入2汤匙番茄酱，煮1分钟直到颜色加深、加入400克磨碎的番茄、藏红花水、1根肉桂棒和1片月桂叶、倒入600毫升热水（或高汤）——液体应到达肉的一半左右，不要淹没、轻轻烧开。慢炖：将火调至小火，盖上塔吉锅盖（或荷兰锅的密封盖），炖1.5–2小时，每30分钟检查一次并轻轻搅拌、当叉子能轻松插入时，羊肉就好了、如果酱汁减少过快，加少许热水。加入杏干+洋葱：加入200克对半切的杏干+60克西梅干（如果使用）+200克洋葱瓣、盖好再炖25–30分钟，直到水果丰满，洋葱瓣嫩但仍保持形状、酱汁应该有光泽，能裹住勺背、最后加1汤匙蜂蜜，尝味，调整盐量。完成与上桌：在塔吉锅离火静置5分钟期间，将80克整粒杏仁放入干锅中用中火烤3–4分钟直到金黄——仔细观察，它们烧得很快、将羊肉塔吉锅舀到温暖的古斯米上（或配khobz），顶上撒烤过的杏仁、芝麻和新鲜的芫荽和欧芹、配面包蘸取酱汁享用。","en":"MARINATE THE LAMB: in a large bowl combine 1 kg lamb cubes with 1 tsp cumin + 1 tsp coriander + 1 tsp cinnamon + 0.5 tsp turmeric + 0.5 tsp paprika + 0.5 tsp ginger + 1.5 tsp ras el hanout + 1.5 tsp salt + 0.5 tsp pepper + 3 of the minced garlic cloves and 1 tbsp olive oil; rub the spices into the meat with your hands; cover and rest 30 minutes at room temperature (or up to 24 h in the fridge) so the spices penetrate. BLOOM SAFFRON: place 5–6 saffron threads in 2 tbsp hot water and let steep 10 minutes — this releases the flavour and colour; set aside. BUILD THE BASE: heat the remaining 2 tbsp oil (and 1 tbsp butter if using) in a heavy-bottomed tagine or Dutch oven over medium heat; add 200 g finely diced onion and cook stirring often 8–10 minutes until soft and translucent; add the remaining 3 minced garlic + grated ginger and stir 1 minute. SEAR THE LAMB: raise heat to medium-high; push the onions to the sides of the pot and add the marinated lamb in a single layer (work in 2 batches if needed); sear 3–4 minutes per side without moving until deeply browned on all sides — the crust is essential for the rich stew flavour; stir everything together once the lamb is browned. TOMATO + LIQUID: stir in 2 tbsp tomato paste and cook 1 minute until darkened; add the 400 g grated tomatoes, the saffron-water, 1 cinnamon stick and 1 bay leaf; pour in 600 ml hot water (or stock) — the liquid should come about halfway up the meat, not cover it; bring to a gentle simmer. SLOW COOK: reduce heat to low, cover with the tagine lid (or a tight Dutch-oven lid), and simmer 1.5–2 hours, checking every 30 minutes and stirring gently; the lamb is ready when a fork sinks in easily; add a splash of hot water if the sauce reduces too quickly. ADD APRICOTS + ONIONS: stir in 200 g halved dried apricots + 60 g prunes (if using) + the 200 g onion wedges; cover and simmer 25–30 minutes more until the fruit is plump and the onion wedges are tender but still holding shape; the sauce should be glossy, coating the back of a spoon; finish with 1 tbsp honey, taste, adjust salt. FINISH AND SERVE: while the tagine rests off the heat for 5 minutes, toast 80 g whole almonds in a dry pan over medium heat 3–4 minutes until golden — watch carefully, they burn fast; spoon the lamb tagine over warm couscous (or serve with khobz), top with toasted almonds, sesame seeds, and a scatter of fresh coriander and parsley; eat with bread to mop up the sauce."}},{"id":168,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"英国","en":"United Kingdom","ro":"Marea Britanie"},"name":{"zh":"牧羊人派","en":"Shepherd's Pie","ro":"Plăcintă a ciobanului"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["600克羊肉糜（~15%脂肪——比通常的牛肉糜更瘦但有足够的脂肪保持湿润）","1个大洋葱（~200克），切细丁","2根中等胡萝卜（~200克），切细丁0.5厘米（小切丁——它们应该融入馅料中）","4瓣大蒜，切碎","1汤匙番茄酱","1汤匙伍斯特郡酱（秘密的深度——不可妥协）","1茶匙干百里香（或2枝新鲜的）","1茶匙干迷迭香，切细","2汤匙普通面粉（用于增稠肉汁）","300毫升热羊肉或牛肉高汤（自制或低盐）","150克冷冻豌豆","1汤匙中性油","1茶匙盐+0.5茶匙新鲜研磨黑胡椒用于馅料","土豆泥顶部：1公斤粉质土豆（Maris Piper、King Edward或Yukon Gold），去皮切成4厘米块","60克无盐黄油+100毫升温全脂牛奶+2个大蛋黄（蛋黄赋予标志性的金黄酥脆顶部）+30克擦丝成熟切达奶酪（可选但传统）","0.5茶匙白胡椒+0.5茶匙盐用于土豆泥"],"en":["600 g minced lamb (~15% fat — leaner than usual ground beef but with enough fat for moisture)","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), finely diced 0.5 cm (small dice — they should disappear into the filling)","4 garlic cloves, minced","1 tbsp tomato paste","1 tbsp Worcestershire sauce (the secret depth — non-negotiable)","1 tsp dried thyme (or 2 sprigs fresh)","1 tsp dried rosemary, finely chopped","2 tbsp plain flour (to thicken the gravy)","300 ml hot lamb or beef stock (homemade or low-salt)","150 g frozen peas","1 tbsp neutral oil","1 tsp salt + 0.5 tsp freshly ground black pepper for the filling","For the mash topping: 1 kg floury potatoes (Maris Piper, King Edward, or Yukon Gold), peeled and cut into 4 cm chunks","60 g unsalted butter + 100 ml warm whole milk + 2 large egg yolks (the yolks give the iconic golden crisp top) + 30 g grated mature cheddar (optional but traditional)","0.5 tsp white pepper + 0.5 tsp salt for the mash"],"ro":["600 g carne tocată de miel (~15% grăsime — mai slabă decât vita tocată obișnuită, dar cu suficientă grăsime pentru umiditate)","1 ceapă mare (~200 g), tăiată cubulețe fine","2 morcovi medii (~200 g), tăiați cubulețe fine de 0,5 cm (cubulețe mici — trebuie să dispară în umplutură)","4 căței de usturoi, tocați","1 lingură pastă de roșii","1 lingură sos Worcestershire (profunzimea secretă — nenegociabil)","1 linguriță cimbru uscat (sau 2 crenguțe proaspete)","1 linguriță rozmarin uscat, tocat fin","2 linguri făină albă (pentru a îngroșa sosul)","300 ml supă fierbinte de miel sau vită (de casă sau cu sare redusă)","150 g mazăre congelată","1 lingură ulei neutru","1 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat pentru umplutură","Pentru piureul de deasupra: 1 kg cartofi făinoși (Maris Piper, King Edward sau Yukon Gold), curățați și tăiați bucăți de 4 cm","60 g unt nesărat + 100 ml lapte integral cald + 2 gălbenușuri mari (gălbenușurile dau crusta aurie iconică) + 30 g cheddar maturat ras (opțional dar tradițional)","0,5 linguriță piper alb + 0,5 linguriță sare pentru piure"]},"howIsMade":{"zh":"煮土豆：将1公斤去皮切块的土豆放入一大锅冷盐水中（每2升加1汤匙盐）、煮沸，转小火稳定慢煮15–18分钟，直到刀能轻松无阻地穿过、沥干，离火后放回锅中2分钟蒸发水分——湿土豆做出湿土豆泥、制作土豆泥：将干燥的土豆通过土豆压泥器（最适合蓬松土豆泥）或用手动捣泥器捣碎。趁热加入60克黄油搅打，然后分3次加入100毫升温牛奶，每次之间搅打、离火后加入2个蛋黄、0.5茶匙白胡椒、0.5茶匙盐搅打、土豆泥应该光泽、光滑，并足够硬以保持脊状——如果太松，顶部会下沉、盖上铝箔保温。软化蔬菜：在一个大的厚底锅中用中火加热1汤匙油、加入200克切丁洋葱+200克切丁胡萝卜和一撮盐、经常搅拌煮8–10分钟，直到非常软，胡萝卜失去脆感——一旦与肉混合，它们不会进一步软化、加入4瓣切碎的大蒜+百里香+迷迭香，再煮1分钟。煎羊肉：将火调至中高、加入600克羊肉糜，用木勺把它分开、煮8–10分钟，直到羊肉不再粉红色，并且释放的脂肪开始在锅底形成酥脆的小片——这种Maillard焦化是肉汁的基础、用勺子撇去超过1汤匙的积累脂肪（羊肉脱油很多——太多会使派变腻）。构建肉汁：将1汤匙番茄酱搅入羊肉中，煮1分钟直到颜色变深、撒上2汤匙面粉，搅拌1–2分钟以煮出生面味、倒入300毫升热高汤+1汤匙伍斯特郡酱+1茶匙盐+0.5茶匙胡椒，刮起锅底的焦黄物、慢煮+豌豆：将火调至小火，敞开盖煮15分钟，偶尔搅拌，直到肉汁变浓稠至厚而有光泽的状态，包裹住肉——它不应该是稀的，否则土豆泥会下沉。搅入150克冷冻豌豆（它们会在烤箱中加热）、尝味并调整调味料、组装：预热烤箱至200 °C、将羊肉馅料转移到23 × 30厘米的烤盘中（约2升容量）。在上面舀放土豆泥成团状，然后用刮刀小心地涂抹，密封到边缘、用叉子的齿在表面拉出长长的线条——这些脊状物在烤箱中会美丽地变脆、如果使用，撒上30克擦丝切达奶酪、烘烤和静置：将烤盘放在烘焙纸上（接住任何冒泡的滴液）。在中层烤架上烘烤25–30分钟，直到顶部深金黄色，脊状物酥脆，肉汁在边缘明显冒泡、上桌前静置10分钟——馅料会凝固，切片更干净、从烤盘直接上桌，配绿色沙拉或黄油卷心菜、第二天更好，重新加热至滚烫。","en":"1. BOIL THE POTATOES: place 1 kg peeled and cubed potatoes in a large pot of cold salted water (1 tbsp salt per 2 L), bring to a boil, then reduce to a steady simmer and cook 15–18 minutes until a knife slides through with no resistance; drain and return to the pot off the heat for 2 minutes to steam off, since wet potatoes make wet mash. 2. MAKE THE MASH: pass the dry potatoes through a ricer (best for fluffy mash) or mash with a hand masher, then beat in 60 g butter while still hot followed by 100 ml warm milk added in 3 stages, beating between each, and off the heat beat in 2 yolks, 0.5 tsp white pepper and 0.5 tsp salt until the mash is glossy, smooth and stiff enough to hold ridges (if it's too loose the topping will sink); cover with foil to keep warm. 3. SWEAT THE VEGETABLES: heat 1 tbsp oil in a large heavy skillet over medium heat, add 200 g diced onion and 200 g diced carrot with a pinch of salt, and cook, stirring often, 8–10 minutes until very soft and the carrots have lost their crunch (they will not soften further once mixed with meat), then stir in 4 minced garlic cloves, thyme and rosemary and cook 1 minute more. 4. BROWN THE LAMB: raise the heat to medium-high, add 600 g minced lamb and break it apart with a wooden spoon, then cook 8–10 minutes until the lamb is no longer pink and the released fat has begun to crisp small bits at the bottom of the pan (this Maillard browning is the foundation of the gravy), and spoon off any pooled fat over 1 tbsp, since lamb sheds a lot and too much makes the pie greasy. 5. BUILD THE GRAVY: stir 1 tbsp tomato paste into the lamb and cook 1 minute until darkened, sprinkle 2 tbsp flour over and stir 1–2 minutes to cook the raw taste out, then pour in 300 ml hot stock, 1 tbsp Worcestershire sauce, 1 tsp salt and 0.5 tsp pepper, scraping the bottom of the pan to lift the browned bits. 6. SIMMER + PEAS: reduce heat to low and simmer uncovered 15 minutes, stirring occasionally, until the gravy has thickened to a thick, glossy consistency that coats the meat (it should not be runny, or the mash will sink), then stir in 150 g frozen peas (they will warm through in the oven) and taste and adjust seasoning. 7. ASSEMBLE: preheat the oven to 200 °C and transfer the lamb filling to a 23 × 30 cm baking dish (about 2 L capacity), spoon the mash on top in dollops and spread carefully with a spatula sealing all the way to the edges, then drag the tines of a fork in long lines across the surface (these ridges crisp up beautifully in the oven) and scatter 30 g grated cheddar over the top if using. 8. BAKE & REST: place the dish on a baking sheet to catch any bubbling drips and bake on the middle rack 25–30 minutes until the top is deeply golden, the ridges are crisp, and the gravy is visibly bubbling around the edges, then rest 10 minutes before serving so the filling sets and slicing is cleaner, and serve straight from the dish with a green salad or buttered cabbage on the side (even better the next day, reheated until piping hot)."}},{"id":169,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"中国","en":"China","ro":"China"},"name":{"zh":"麻婆豆腐","en":"Mapo Tofu","ro":"Mapo Tofu"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["600克软（绢豆腐或中等软度）豆腐，切成2厘米方块——质地是这道菜的一部分，不要使用老豆腐","200克猪肉糜（~20%脂肪——少量添加鲜味而不占主导）","3汤匙中性油（菜籽油或花生油）","3汤匙郫县豆瓣酱（四川蚕豆辣椒酱）——这道菜的灵魂，不要省略或替代","1汤匙豆豉（发酵黑豆），冲洗后粗切","2茶匙四川辣豆瓣酱（辣豆瓣酱）或1茶匙韩国辣椒酱作为替代","4瓣大蒜，切细末","4厘米新鲜生姜，去皮磨碎","6根葱：白色部分切细炒制+绿色部分斜切作装饰（分开保存）","1.5汤匙老抽（老抽）","1茶匙白砂糖","300毫升热的无盐鸡汤或水","2茶匙四川花椒（花椒），干锅烘焙60秒并在臼中捣碎","1.5汤匙玉米淀粉（cornflour）与3汤匙冷水混合作最终勾芡","2茶匙辣椒油（辣油）用于收尾","1茶匙烤芝麻油用于最后一滴","上桌：320克（1.6杯干）熟茉莉香米或短粒米"],"en":["600 g soft (silken or medium-soft) tofu, cut into 2 cm cubes — the texture is part of the dish, do not use firm tofu","200 g ground pork (~20% fat — the small amount adds umami without dominating)","3 tbsp neutral oil (rapeseed or peanut)","3 tbsp Pixian doubanjiang (Sichuan broad-bean chili paste) — the SOUL of the dish, do not skip or substitute","1 tbsp douchi (fermented black beans), rinsed and roughly chopped","2 tsp Sichuan chili bean paste (la doubanjiang) OR 1 tsp Korean gochujang as substitute","4 garlic cloves, finely minced","4 cm fresh ginger, peeled and grated","6 spring onions: the white parts finely chopped for cooking + the green tops cut diagonally for garnish (keep separate)","1.5 tbsp dark soy sauce (laochou)","1 tsp granulated sugar","300 ml hot unsalted chicken stock or water","2 tsp Sichuan peppercorns (huajiao), toasted in a dry pan 60 sec and crushed in a mortar","1.5 tbsp cornstarch (cornflour) mixed with 3 tbsp cold water for the final slurry","2 tsp chili oil (la yu) for finishing","1 tsp toasted sesame oil for the last drizzle","To serve: 320 g (1.6 cups dry) cooked jasmine rice or short-grain rice"],"ro":["600 g tofu moale (mătăsos sau mediu-moale), tăiat în cuburi de 2 cm — textura face parte din preparat, nu folosi tofu ferm","200 g carne tocată de porc (~20% grăsime — cantitatea mică adaugă umami fără a domina)","3 linguri ulei neutru (rapiță sau arahide)","3 linguri doubanjiang Pixian (pastă de fasole-chili din Sichuan) — SUFLETUL preparatului, nu omite și nu substitui","1 lingură douchi (fasole neagră fermentată), clătită și tocată grosier","2 lingurițe pastă de fasole-chili Sichuan (la doubanjiang) SAU 1 linguriță gochujang coreean ca substitut","4 căței de usturoi, tocați fin","4 cm ghimbir proaspăt, curățat și ras","6 cepe verzi: părțile albe tocate fin pentru gătit + vârfurile verzi tăiate oblic pentru ornament (păstrează separat)","1,5 linguri sos de soia închis (laochou)","1 linguriță zahăr granulat","300 ml supă fierbinte de pui nesărată sau apă","2 lingurițe boabe de piper sichuan (huajiao), prăjite într-o tigaie uscată 60 sec și zdrobite în mojar","1,5 linguri amidon de porumb (cornflour) amestecat cu 3 linguri apă rece pentru slurry-ul final","2 lingurițe ulei de chili (la yu) pentru finisare","1 linguriță ulei de susan prăjit pentru ultima stropire","Pentru servire: 320 g (1,6 căni uscat) orez jasmine fiert sau orez cu bob scurt"]},"howIsMade":{"zh":"准备豆腐：将一小锅加1茶匙盐的水煮至轻微沸腾（不要大开）、小心将2厘米豆腐方块滑入，让它们温热2分钟——这会使表面变硬，以便在酱汁中保持形状、轻轻沥干，离火放在温暖的锅中备用。烘烤四川花椒：在干锅中用中火烘烤2茶匙四川花椒60秒，直到香气浓郁、倒入研钵中粗略捣碎、备用。渲染猪肉：在炒锅或厚重煎锅中用中高火加热2汤匙中性油、加入200克猪肉糜，用铲子打散、翻炒4–5分钟，直到猪肉不再粉红色，小碎块酥脆呈金黄色——脆猪肉与软豆腐之间的质地差异至关重要。激发豆瓣酱：将猪肉推到锅边，在空位中再加1汤匙油、在油中加入3汤匙豆瓣酱，搅拌60–90秒，直到油变深红色——这种油炸释放了酱料的颜色和鲜味、与猪肉混合、加入切碎的豆豉+蒜末+姜末+2茶匙辣豆瓣酱（或辣椒酱），翻炒60秒，直到香气浓郁。液体：倒入300毫升热高汤+1.5汤匙老抽+1茶匙糖、煮沸。加入豆腐：将温暖的豆腐方块轻轻滑入沸腾的酱汁中、不要搅拌——用勺子背面将它们压在下面，然后轻轻摇动锅子使其稳定、慢炖4–5分钟，偶尔将酱汁淋在豆腐顶部，让方块吸收风味而不破碎。勾芡：再搅拌一次玉米淀粉浆并倒入酱汁的一半，然后摇动锅子让其慢炖30秒、酱汁会变得有光泽并开始包裹豆腐、如果还稀，加入剩余的浆、完成的酱汁应该轻轻附着在豆腐上，而不是汤状。完成并上桌：离火，将2茶匙辣椒油+1茶匙烤芝麻油淋在表面，撒上绿色葱花+碾碎的四川花椒、不要搅拌——花椒必须未经稀释地接触舌头，才能产生麻的感觉、立即与热茉莉香米一起上桌、每一口：米饭+豆腐+酱+花椒=完整的麻辣体验。","en":"PREP THE TOFU: bring a small pot of water with 1 tsp salt to a gentle simmer (not boil); slip the 2 cm tofu cubes in carefully and let them warm 2 minutes — this firms the surface so they hold their shape in the sauce; drain gently and set aside in the warm pot off the heat. TOAST SICHUAN PEPPERCORNS: in a dry pan over medium heat, toast 2 tsp Sichuan peppercorns 60 seconds until intensely fragrant; tip into a mortar and crush coarsely; set aside. RENDER THE PORK: heat 2 tbsp neutral oil in a wok or heavy skillet over medium-high heat; add 200 g ground pork and break it apart with a spatula; stir-fry 4–5 minutes until the pork is no longer pink and the small bits are crispy and golden brown — the texture difference between crisp pork and soft tofu is essential. BLOOM THE DOUBANJIANG: push the pork to the side of the pan and add 1 tbsp more oil to the empty space; add 3 tbsp doubanjiang to the oil and stir 60–90 seconds until the oil turns deep red — this oil-frying releases the colour and umami of the paste; stir into the pork; add chopped douchi + minced garlic + grated ginger + 2 tsp la doubanjiang (or gochujang) and stir-fry 60 seconds until intensely aromatic. LIQUID: pour in 300 ml hot stock + 1.5 tbsp dark soy sauce + 1 tsp sugar; bring to a simmer. ADD THE TOFU: slide the warm tofu cubes gently into the simmering sauce; do NOT stir — use the back of a ladle to push them under, then shake the pan gently to settle; simmer 4–5 minutes, basting the tops of the tofu with sauce occasionally, so the cubes absorb flavour without breaking. THICKEN: stir the cornstarch slurry one more time and pour HALF into the sauce, then shake the pan and let it simmer 30 seconds; the sauce will turn glossy and start to coat the tofu; if still thin, add the rest of the slurry; the finished sauce should cling lightly to the tofu, not be soupy. FINISH AND SERVE: off the heat, drizzle 2 tsp chili oil + 1 tsp toasted sesame oil over the surface and scatter the green spring-onion tops + crushed Sichuan peppercorns; do NOT stir — the peppercorns must hit your tongue undiluted for the ma (numbing) sensation; serve immediately with hot jasmine rice; each bite: rice + tofu + sauce + peppercorn = the full ma-la experience."}},{"id":170,"servings":2,"tipType":"veg","pairingsType":"veg","origin":{"zh":"土耳其","en":"Turkey","ro":"Turcia"},"name":{"zh":"土耳其蛋炒番茄","en":"Menemen","ro":"Menemen"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"zh":["6个大鸡蛋，室温","3汤匙土耳其或特级初榨橄榄油","2根sivri biber（长青土耳其辣椒，微辣）或1个青甜椒+1个哈拉佩诺辣椒作为替代（约共150克），去籽切细丁","4个成熟番茄（约500克），去皮，用四面刨丝器粗刨（皮留在手中，只有果肉通过刨丝器——这是土耳其的技术）","1汤匙番茄酱（salça）——可选，加深红色","1茶匙pul biber（土耳其红椒片，阿勒颇或马拉什风格）——增加温暖感而无刺激性辣味","0.5茶匙干牛至","0.5茶匙盐+新鲜研磨黑胡椒","30克feta式beyaz peynir奶酪，弄碎（可选，爱琴海地区性添加物）","1小把平叶欧芹，切细，用于装饰","1小束香葱或大葱青色部分，切细（可选）","搭配：4片厚切新鲜ekmek乡村面包或2个simit（土耳其芝麻面包圈），浓泡土耳其红茶（çay）","关于地区争论的注释：此版本不加洋葱（伊斯坦布尔风格）；如果做爱琴海版本，加1个小洋葱切细丁，在辣椒之前煮4分钟"],"en":["6 large eggs, at room temperature","3 tbsp Turkish or extra-virgin olive oil","2 sivri biber (long green Turkish peppers, mildly hot) OR 1 green bell pepper + 1 jalapeño as substitute (~150 g total), seeds removed and finely diced","4 ripe tomatoes (~500 g), peeled and roughly grated on a box grater (the skin holds back, only the pulp grates through — this is the Turkish technique)","1 tbsp tomato paste (salça) — optional, deepens the red","1 tsp pul biber (Turkish red pepper flakes, Aleppo or Maraş-style) — adds warmth without harsh heat","0.5 tsp dried oregano","0.5 tsp salt + freshly ground black pepper","30 g feta-style beyaz peynir, crumbled (optional, regional Aegean addition)","1 small handful flat-leaf parsley, finely chopped, to finish","1 small bunch chives or spring onion green, finely chopped (optional)","To serve: 4 thick slices of fresh ekmek country bread OR 2 simit (Turkish sesame bagels), Turkish black tea (çay) brewed strong","Note on regional debate: this version is WITHOUT onion (Istanbul-style); if making the Aegean-style, add 1 small onion finely diced and cook 4 min before the peppers"],"ro":["6 ouă mari, la temperatura camerei","3 linguri ulei de măsline turcesc sau extravirgin","2 sivri biber (ardei lungi verzi turcești, ușor iuți) SAU 1 ardei gras verde + 1 jalapeño ca substitut (~150 g total), fără semințe și tocați fin","4 roșii coapte (~500 g), opărite și răzuite grosier pe răzătoarea cu găuri mari (coaja rămâne în mână, doar pulpa trece prin răzătoare — aceasta este tehnica turcească)","1 lingură pastă de roșii (salça) — opțional, adâncește roșul","1 linguriță pul biber (fulgi de ardei roșu turcesc, stil Aleppo sau Maraș) — adaugă căldură fără iuțeală agresivă","0,5 linguriță oregano uscat","0,5 linguriță sare + piper negru proaspăt măcinat","30 g beyaz peynir tip feta, fărâmițat (opțional, adaos regional egeean)","1 mână mică de pătrunjel cu frunza lată, tocat fin, pentru finisare","1 legătură mică de arpagic sau partea verde a cepei verzi, tocată fin (opțional)","Pentru servire: 4 felii groase de ekmek proaspăt (pâine de țară) SAU 2 simit (covrigi turcești cu susan), ceai negru turcesc (çay) preparat tare","Notă despre dezbaterea regională: această versiune este FĂRĂ ceapă (stil Istanbul); dacă faci versiunea egeeană, adaugă 1 ceapă mică tocată fin și gătește 4 minute înainte de ardei"]},"howIsMade":{"zh":"去皮和擦碎番茄：在4个成熟番茄的底部各切一个浅十字、放入沸水中30秒，然后转移到冰水中、皮很容易剥落、将每个番茄水平切成两半，将切面对着放在碗上的四面刨丝器的粗糙面摩擦——果肉通过刨丝器，空皮留在手中、这种土耳其技术提供了一个多汁、丰满的番茄基础，没有皮屑。烹饪辣椒：在24厘米厚煎锅中（铸铁或陶土sahan是传统的）用中火加热3汤匙橄榄油、加入150克切细丁的青椒，经常搅拌烹饪5–6分钟，直到变软并在边缘略微起泡但仍然鲜绿色——不要让它们变褐色。加入番茄酱：将1汤匙番茄酱搅拌到辣椒中并烹饪30秒——salça加深颜色和鲜味、（如果不使用番茄酱，跳过此步骤、）。加入擦碎的番茄：倒入擦碎的番茄果肉+1茶匙pul biber+0.5茶匙牛至+0.5茶匙盐和一大圈黑胡椒、煮至慢炖并烹饪6–8分钟，偶尔搅拌，直到番茄减少一半并看起来像果酱——铲子底部应该能在酱汁中拖出一条清晰的线，不会立即被填满。准备鸡蛋：在番茄烹饪的同时，将6个鸡蛋一次一个打入碗中——不要打散、鸡蛋整个或几乎不破裂地进入锅中，蛋黄一开始保持完整。加入鸡蛋：当番茄变成果酱状时，将火降至中低、将鸡蛋轻轻滑入锅中，分散在表面上、让它们静置30秒不要碰，以便在底部凝固。轻轻搅拌：用木勺，慢慢以8字形动作将鸡蛋轻轻穿过番茄——不要剧烈搅拌、蛋白应该凝固成丝带状，蛋黄应该破裂并以金色漩涡穿过酱汁、仅烹饪90秒–2分钟——menemen应保持有光泽且几乎未凝固，不要像炒蛋一样干燥、在仍然略湿时离火——它会在热锅中继续烹饪。从锅中上菜：撒上30克碎feta+切碎的欧芹（以及香葱如使用）、将锅直接端到桌子——menemen总是从锅中食用，将面包撕下蘸入酱汁中、配以浓烈的土耳其红茶、在烹饪后5分钟内享用最佳，趁着温暖且有光泽时。","en":"PEEL AND GRATE THE TOMATOES: cut a shallow cross in the bottom of each of 4 ripe tomatoes; drop into boiling water 30 seconds, then transfer to ice water; the skins peel off easily; halve each tomato horizontally and rub the cut sides against the coarse side of a box grater placed over a bowl — the flesh grates through and the empty skin remains in your hand; this Turkish technique gives a pulpy, juicy tomato base with no skin pieces. COOK THE PEPPERS: heat 3 tbsp olive oil in a heavy 24 cm skillet (cast iron or earthenware sahan is traditional) over medium heat; add 150 g finely diced green peppers and cook stirring often 5–6 minutes until softened and slightly blistered at the edges but still bright green — do not let them brown. ADD TOMATO PASTE: stir 1 tbsp tomato paste into the peppers and cook 30 seconds — the salça deepens the colour and umami; (Skip this step if not using paste.). ADD GRATED TOMATOES: pour in the grated tomato pulp + 1 tsp pul biber + 0.5 tsp oregano + 0.5 tsp salt and a generous twist of black pepper; bring to a simmer and cook 6–8 minutes, stirring occasionally, until the tomato has reduced by half and looks jammy — the bottom of the spatula should drag a clear line through the sauce that does not fill in immediately. PREP THE EGGS: while the tomatoes cook, crack 6 eggs into a bowl one at a time — DO NOT beat them; the eggs go into the pan whole or barely broken, with yolks intact at first. ADD THE EGGS: when the tomato is jammy, lower the heat to medium-low; slip the eggs gently into the pan, spaced around the surface; let them sit 30 seconds undisturbed to set on the bottom. SCRAMBLE LIGHTLY: with a wooden spoon, push the eggs gently through the tomato in slow figure-eight motions — DO NOT vigorously stir; the whites should set into ribbons and the yolks should break and streak through the sauce in golden swirls; cook 90 seconds–2 minutes only — the menemen should remain glossy and barely-set, NOT scrambled-egg-dry; take off the heat while still slightly wet — it continues cooking in the hot pan. SERVE FROM THE PAN: scatter 30 g crumbled feta + chopped parsley (and chives if using); bring the pan straight to the table — menemen is always eaten from the pan with bread torn and dipped into the sauce; serve with strong Turkish black tea; best eaten within 5 minutes of cooking, while warm and glossy."}},{"id":171,"servings":4,"tipType":"meat","pairingsType":"soup","origin":{"zh":"俄罗斯","en":"Russia","ro":"Rusia"},"name":{"zh":"罗宋汤","en":"Solyanka","ro":"Solyanka"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["500克牛胸肉或带骨牛腿肉（用于汤底）","2升冷水用于汤底+1个洋葱+1根胡萝卜+2片月桂叶+5粒黑胡椒+1茶匙盐用于高汤","200克烟熏波兰香肠或克拉科夫斯卡亚香肠，切5毫米厚片","150克熟火腿，切1厘米方块（或煮熟的舌头，传统做法）","100克意大利腊肠或猎人香肠，切薄片","2根大型腌黄瓜（约250克，半酸或全酸），切成细丝；保留100毫升腌黄瓜水","1个大洋葱（约200克），切细丁","1汤匙番茄酱","200克擦碎的番茄（或1罐200克罐装，沥干）","2汤匙黄油或30克炼制牛脂用于煸炒","80克去核黑橄榄（卡拉马塔风格）+80克去核绿橄榄","2汤匙刺山柑，沥干","1个柠檬，切成细的半月形片","1片月桂叶+0.5茶匙黑胡椒粉+1茶匙红椒粉（可选，用于上色）","1小束新鲜莳萝，切细","200克斯梅塔纳（酸奶油）用于上菜","搭配：4片厚切新鲜深色黑麦面包，可选1汤匙辣根（khren）"],"en":["500 g beef brisket or shin on the bone (for the broth)","2 L cold water for the broth + 1 onion + 1 carrot + 2 bay leaves + 5 black peppercorns + 1 tsp salt for the stock","200 g smoked kielbasa or krakovskaya, sliced 5 mm thick","150 g cooked ham, cut into 1 cm cubes (or boiled tongue, traditional)","100 g salami or hunting sausage, sliced thin","2 large pickled cucumbers (~250 g, half-sour or fully sour), cut into thin matchsticks; reserve 100 ml of the pickle brine","1 large onion (~200 g), finely diced","1 tbsp tomato paste","200 g grated tomatoes (or 1 × 200 g canned, drained)","2 tbsp butter or 30 g rendered beef fat for the soffritto","80 g pitted black olives (kalamata-style) + 80 g pitted green olives","2 tbsp capers, drained","1 lemon, sliced into thin half-moons","1 bay leaf + 0.5 tsp ground black pepper + 1 tsp paprika (optional, for color)","A small bunch fresh dill, finely chopped","200 g smetana (sour cream) for serving","To serve: 4 thick slices of fresh dark rye bread, optional 1 tbsp horseradish (khren)"],"ro":["500 g piept de vită sau rasol cu os (pentru supă)","2 L apă rece pentru supă + 1 ceapă + 1 morcov + 2 foi de dafin + 5 boabe de piper negru + 1 linguriță sare pentru bulion","200 g kielbasa afumată sau cracovskaya, tăiată felii de 5 mm","150 g șuncă fiartă, tăiată cuburi de 1 cm (sau limbă fiartă, tradițional)","100 g salam sau cârnați de vânătoare, tăiat felii subțiri","2 castraveți murați mari (~250 g, semi-acri sau acri complet), tăiați fâșii subțiri; păstrează 100 ml din zeama de murături","1 ceapă mare (~200 g), tocată fin","1 lingură pastă de roșii","200 g roșii răzuite (sau 1 × 200 g din conservă, scurse)","2 linguri unt sau 30 g grăsime de vită topită pentru sotă","80 g măsline negre fără sâmburi (gen kalamata) + 80 g măsline verzi fără sâmburi","2 linguri capere, scurse","1 lămâie, tăiată felii subțiri în formă de semilună","1 foaie de dafin + 0,5 linguriță piper negru măcinat + 1 linguriță boia (opțional, pentru culoare)","O legăturică mică de mărar proaspăt, tocat fin","200 g smetana (smântână) pentru servire","Pentru servire: 4 felii groase de pâine de secară neagră proaspătă, opțional 1 lingură hrean (khren)"]},"howIsMade":{"zh":"汤底：将500克牛胸肉放入大锅中，加入2升冷水、煮沸并在前5分钟彻底撇去浮沫——这样可以得到清澈的汤底、加入1个完整切成四份的洋葱+1根完整胡萝卜+2片月桂叶+5粒胡椒+1茶匙盐、降至温和慢炖，加盖煮1.5小时，直到肉完全软烂。过滤和撕碎：取出牛肉，让其稍微冷却、将汤底通过细筛过滤回干净的锅中——应该有大约1.5升清澈、美味的汤底、将牛肉沿纹理切成一口大小的条，去除任何坚硬的筋。煸炒：在宽煎锅中，用中火融化2汤匙黄油、加入200克切细丁的洋葱，煸炒6–8分钟，直到变软透明、搅入1汤匙番茄酱，煮1分钟直到变深、加入200克擦碎的番茄，煮4–5分钟，直到混合物收汁，油开始浮到表面。加入腌黄瓜：将黄瓜丝搅入煸炒中，煮3–4分钟、腌黄瓜应该加热但不要过分软化——它们需要保持一些脆度以形成质地对比。煎香肠：在另一个干燥的中火煎锅中，煎烟熏波兰香肠片、火腿块和意大利腊肠片4–5分钟，直到边缘略微变褐色，脂肪渗出、这一步是不可妥协的——在加入汤底之前先煎肉是让solyanka具有深沉烟熏特质的关键。组装汤：将煸炒倒入过滤后的汤底中，搅入煎过的香肠、火腿、腊肠和撕碎的牛肉、加入保留的100毫升腌黄瓜水+1片月桂叶+0.5茶匙黑胡椒粉+1茶匙红椒粉、煮至温和慢炖。慢炖：用低火煮15–20分钟，部分加盖，让风味融合、仅在最后5分钟加入橄榄+刺山柑——它们应该加热但保持形状、品尝并调整盐——大部分咸味来自腌黄瓜、刺山柑、橄榄和盐水，所以要谨慎行事。上菜：将热的solyanka舀入深碗中、每个碗加入1片薄柠檬片（完整带皮）、一大勺斯梅塔纳和一撒切碎的莳萝、黑胡椒调味、立即配以厚切新鲜深色黑麦面包——solyanka是主菜，不是开胃汤、在俄罗斯传统中，这是经典的庆祝后恢复菜肴。","en":"THE BROTH: place 500 g beef brisket in a large pot with 2 L cold water; bring to a boil and skim the foam thoroughly for the first 5 minutes — this gives a clear broth; add 1 whole quartered onion + 1 whole carrot + 2 bay leaves + 5 peppercorns + 1 tsp salt; reduce to a gentle simmer and cook covered 1.5 hours until the meat is fully tender. STRAIN AND SHRED: lift the beef out and let it cool slightly; strain the broth through a fine sieve back into a clean pot — you should have about 1.5 L of clear, savoury broth; cut the beef across the grain into bite-sized strips, discarding any tough sinew. SOFFRITTO: in a wide skillet, melt 2 tbsp butter over medium heat; add 200 g finely diced onion and sauté 6–8 minutes until soft and translucent; stir in 1 tbsp tomato paste and cook 1 minute until darkened; add the 200 g grated tomatoes and cook 4–5 minutes until the mixture has reduced and the oil starts to appear on the surface. ADD PICKLES: stir the cucumber matchsticks into the soffritto and cook 3–4 minutes; the pickles should be warmed through, not over-softened — they need to keep some crunch for texture contrast. FRY THE SAUSAGES: in a separate dry pan over medium heat, fry the smoked kielbasa slices, ham cubes, and salami slices 4–5 minutes until lightly browned at the edges and the fat has rendered; this step is non-negotiable — searing the meats before adding them to the broth is what gives solyanka its deep, smoky character. ASSEMBLE THE SOUP: pour the soffritto into the strained broth and stir in the seared sausages, ham, salami, and shredded beef; add the reserved 100 ml pickle brine + 1 bay leaf + 0.5 tsp ground pepper + 1 tsp paprika; bring to a gentle simmer. SIMMER: cook over low heat 15–20 minutes, partially covered, for the flavours to marry; add the olives + capers in the last 5 minutes only — they should warm through but keep their shape; taste and adjust salt — most of the saltiness comes from the pickles, capers, olives, and brine, so go cautiously. SERVE: ladle the hot solyanka into deep bowls; to each bowl add 1 thin lemon slice (whole, peel on), a generous spoonful of smetana, and a scatter of chopped dill; black pepper to taste; serve immediately with thick slices of fresh dark rye bread on the side — solyanka is a main course, not a starter; in Russian tradition, this is the classic post-celebration restorative."}},{"id":172,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"zh":"美国","en":"USA","ro":"SUA"},"name":{"zh":"蛤蜊浓汤","en":"Clam Chowder","ro":"Clam Chowder"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["1.5公斤新鲜littleneck或quahog蛤蜊带壳（或2罐200克整粒小蛤蜊浸于汁液中，作为远离海岸厨师的替代品）","500毫升新鲜蛤蜊汁或鱼高汤（如果使用新鲜蛤蜊，保留所有蒸煮液）","150克厚切烟熏培根，切0.5厘米丁","1个大黄洋葱（约250克），切细丁","2根中等芹菜茎（约120克），切细丁","4瓣大蒜，剁碎（可选——波士顿传统派皱眉但大多数现代食谱都包括）","30克无盐黄油","30克通用面粉（用于roux）","750克粉质土豆（Yukon Gold或russet），去皮切1.5厘米方块","250毫升全脂牛奶","250毫升重奶油（或对半奶用于更轻版本）","2片月桂叶+1茶匙干百里香+0.5茶匙新鲜磨黑胡椒","0.5茶匙盐（先尝尝——蛤蜊汁是咸的）","一撮辣椒粉或1滴辣酱（可选）","1小束新鲜细香葱，切细，和2汤匙新鲜扁叶欧芹用于装饰","搭配：4个挖空的小酸面包卷作为可食用面包碗，或牡蛎饼干（传统的新英格兰配菜）；1个柠檬，切成楔形"],"en":["1.5 kg fresh littleneck or quahog clams in shells (or 2 × 200 g cans whole baby clams in juice as substitute for landlocked cooks)","500 ml fresh clam juice or fish stock (reserve all the steaming liquid if using fresh clams)","150 g thick-cut smoked bacon, diced 0.5 cm","1 large yellow onion (~250 g), finely diced","2 medium celery stalks (~120 g), finely diced","4 garlic cloves, minced (optional — Boston purists frown but most modern recipes include)","30 g unsalted butter","30 g all-purpose flour (for the roux)","750 g floury potatoes (Yukon Gold or russet), peeled and cut into 1.5 cm cubes","250 ml whole milk","250 ml heavy cream (or half-and-half for a lighter version)","2 bay leaves + 1 tsp dried thyme + 0.5 tsp freshly ground black pepper","0.5 tsp salt (taste first — clam juice is salty)","A pinch of cayenne or 1 dash hot sauce (optional)","1 small bunch fresh chives, finely chopped, and 2 tbsp fresh flat-leaf parsley to garnish","To serve: 4 small hollowed-out sourdough rolls as edible bread bowls OR oyster crackers (a traditional New England side); 1 lemon, sliced into wedges"],"ro":["1,5 kg scoici proaspete (littleneck sau quahog) în cochilii (sau 2 × 200 g conserve de scoici mici întregi în suc, ca substitut pentru cei departe de mare)","500 ml suc de scoici proaspăt sau fond de pește (rezervă tot lichidul de aburire dacă folosești scoici proaspete)","150 g bacon afumat tăiat gros, cuburi de 0,5 cm","1 ceapă galbenă mare (~250 g), tăiată mărunt","2 tulpini medii de țelină (~120 g), tăiate mărunt","4 căței de usturoi, tocați (opțional — puriștii din Boston dezaprobă, dar majoritatea rețetelor moderne îi includ)","30 g unt nesărat","30 g făină universală (pentru roux)","750 g cartofi făinoși (Yukon Gold sau russet), curățați și tăiați cuburi de 1,5 cm","250 ml lapte integral","250 ml smântână grasă (sau jumătate-jumătate pentru o versiune mai ușoară)","2 foi de dafin + 1 linguriță cimbru uscat + 0,5 linguriță piper negru proaspăt măcinat","0,5 linguriță sare (gustă întâi — sucul de scoici este sărat)","Un vârf de cayenne sau 1 strop de sos iute (opțional)","O legăturică mică de arpagic proaspăt, tocat fin, și 2 linguri de pătrunjel proaspăt cu frunze plate pentru garnitură","Pentru servire: 4 chifle mici de sourdough scobite ca boluri comestibile SAU biscuiți pentru stridii (un acompaniament tradițional al Noii Anglii); 1 lămâie, tăiată felii pentru garnitură"]},"howIsMade":{"zh":"在冷水中冲洗1.5公斤新鲜蛤蜊2–3次以去除沙子、丢弃任何打开后敲击不闭合的蛤蜊、将它们放入宽锅中加250毫升水，盖盖在大火下蒸4–5分钟直到壳刚刚打开、丢弃任何保持关闭的。取出蛤蜊，留下蒸汽液体、将该液体通过铺有湿纱布的细筛过滤到量杯中——你应该有约400–500毫升清澈的蛤蜊汤、从壳中取出蛤蜊肉，粗略切碎并放置一旁、（如果使用罐装蛤蜊，只需沥干保留汁液，使用500毫升鱼高汤+罐装汁液。在中火下的5升重锅或荷兰锅中，加入150克切丁培根、经常搅拌6–8分钟直到培根深度变褐，大部分脂肪渗出、用漏勺将脆培根捞到纸巾上并放置一旁作为装饰、锅中留3汤匙培根油。将250克切丁洋葱+120克切丁芹菜加入培根油中并加一撮盐、经常搅拌煮8–10分钟直到柔软透明但不变褐——chowder是白色的，这里你不想要颜色、加入4瓣剁碎的大蒜，再煮1分钟、加入30克黄油并让其融化。在蔬菜上撒30克面粉，用木勺持续搅拌2分钟，煮掉生面粉味而不让其变深——这是白色roux、以缓慢稳定的流注入过滤后的蛤蜊汤，同时持续搅拌以防止结块、加入750克土豆方块+2片月桂叶+1茶匙百里香+0.5茶匙黑胡椒、煮至温和慢炖。不盖盖煮15–18分钟，偶尔搅拌，直到土豆变软但仍保持形状——用刀刺入一块应该无阻力地滑入、将火降至最低、搅入250毫升全脂牛奶和250毫升重奶油——加入乳制品后不要让其沸腾，否则奶油会凝结、加热3分钟。搅入切碎的蛤蜊肉和大部分培根（保留2汤匙培根和所有细香葱用于装饰）、再慢炖3分钟直到蛤蜊刚刚加热——过度烹饪使其变得坚硬和有橡胶感、取出月桂叶、品尝并用盐和一撮辣椒调整调味（如果你喜欢）。挖空4个小酸面包卷（或使用牡蛎饼干作为传统的更简单的选择）、将热chowder舀入面包碗或深汤盘中、每个上面放预留的脆培根、大量撒上的细香葱和欧芹，以及一圈新鲜的黑胡椒、立即配以柠檬楔上桌、新英格兰餐厅通常会为桌上带一小盘牡蛎饼干和辣酱配菜。","en":"Rinse 1.5 kg fresh clams in cold water 2-3 times to remove sand and discard any that are open and do not close when tapped, then place them in a wide pot with 250 ml water, cover and steam over high heat for 4-5 minutes until the shells just open, discarding any that stayed shut. Lift the clams out and strain the steaming liquid through a fine sieve lined with damp cheesecloth into a measuring cup, aiming for ~400-500 ml of clean clam broth, then pick the clam meat from the shells, roughly chop it, and set aside (if using canned clams, drain them reserving the juice and use the 500 ml fish stock plus the canned juice). In a heavy 5 L pot or Dutch oven over medium heat, add 150 g diced bacon and cook stirring often for 6-8 minutes until the bacon is deeply browned and most of the fat has rendered, then lift the crispy bacon onto a paper towel and set aside for garnish, leaving 3 tbsp of bacon fat in the pot. Add 250 g diced onion and 120 g diced celery to the bacon fat with a pinch of salt and cook stirring often for 8-10 minutes until soft and translucent but not browned (chowder is white, so you do not want colour here), then add 4 minced garlic cloves and cook 1 minute more. Add 30 g butter and let it melt, then sprinkle 30 g flour over the vegetables and stir constantly with a wooden spoon for 2 minutes, cooking out the raw flour taste without letting it darken to keep a white roux. Pour in the strained clam broth in a slow steady stream while whisking constantly to prevent lumps, add 750 g potato cubes, 2 bay leaves, 1 tsp thyme, and 0.5 tsp black pepper, bring to a gentle simmer, then cook uncovered for 15-18 minutes stirring occasionally until the potatoes are tender but still hold their shape and a knife slides in with no resistance. Lower the heat to its lowest setting and stir in 250 ml whole milk and 250 ml heavy cream, taking care not to let it boil after adding dairy or the cream will curdle, then warm through for 3 minutes before stirring in the chopped clam meat and most of the bacon (saving 2 tbsp of bacon and all the chives for garnish), and simmer 3 more minutes until the clams are just heated through (overcooking turns them tough and rubbery), then remove the bay leaves and taste, adjusting seasoning with salt and a pinch of cayenne if you like. Hollow out 4 small sourdough rolls (or use oyster crackers as a traditional simpler option), ladle the hot chowder into the bread bowls or deep soup plates, top each with the reserved crispy bacon, a generous scatter of chives and parsley, and a fresh twist of black pepper, and serve immediately with lemon wedges on the side, just as a New England restaurant typically brings a small dish of oyster crackers and a side of hot sauce to the table."}},{"id":173,"servings":2,"tipType":"meat","pairingsType":"meat","origin":{"zh":"德国","en":"Germany","ro":"Germania"},"name":{"zh":"咖喱香肠","en":"Currywurst","ro":"Currywurst"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["4根柏林风格猪肉Bratwurst香肠（每根约120克，总共约480克）——新鲜的，未预先烤过；如果没有Bratwurst可用，可用细Bockwurst或Frankfurter替代","2汤匙中性油（葵花籽）用于煎香肠","咖喱酱原料：200克优质番茄酱（Heinz或德国Hela）","100毫升passata或1汤匙番茄酱+80毫升水作为替代","2汤匙中辣咖喱粉（一种黄色Madras风格混合物）——Herta Heuwer的原版使用类似的英国殖民地咖喱粉","1茶匙匈牙利甜辣椒粉","0.5茶匙烟熏辣椒粉（可选，增添深度）","1汤匙伍斯特沙司（Heuwer原版的秘密——不可商量）","1汤匙苹果醋或白葡萄酒醋","1汤匙白糖（有助于平衡醋并突出番茄味）","0.5茶匙磨碎的多香果+0.5茶匙磨碎的姜（Heuwer添加的'秘密'温暖香料混合物）","0.5茶匙盐+一撮辣椒粉或辣椒粉","搭配：额外的咖喱粉用于撒在顶部+2份Pommes Frites（约400克来自烤箱或油炸锅的热脆薯条），或2个小Brötchen面包卷；2个小木叉（Pommespieker）以获得正宗的柏林体验"],"en":["4 Berliner-style Bratwurst pork sausages (~120 g each, total ~480 g) — fresh, not pre-grilled; or substitute fine Bockwurst or Frankfurter if Bratwurst unavailable","2 tbsp neutral oil (sunflower) for frying the sausages","For the curry sauce: 200 g good-quality tomato ketchup (Heinz or German Hela)","100 ml passata or 1 tbsp tomato paste + 80 ml water as substitute","2 tbsp medium-hot curry powder (a yellow Madras-style blend) — Herta Heuwer's original used a similar British colonial curry powder","1 tsp sweet Hungarian paprika","0.5 tsp smoked paprika (optional, adds depth)","1 tbsp Worcestershire sauce (the secret of Heuwer's original — not negotiable)","1 tbsp apple cider vinegar OR white wine vinegar","1 tbsp white sugar (helps balance the vinegar and brings out the tomato)","0.5 tsp ground allspice + 0.5 tsp ground ginger (the 'secret' warm-spice mix Heuwer added)","0.5 tsp salt + a pinch of cayenne or hot chili powder","To serve: extra curry powder for dusting on top + 2 portions of Pommes Frites (about 400 g hot crispy fries from the oven or fryer), or 2 small Brötchen rolls; 2 small wooden forks (Pommespieker) for the authentic Berlin experience"],"ro":["4 cârnați Bratwurst de Berlin din porc (~120 g fiecare, total ~480 g) — proaspeți, nu pre-grătar; sau substituție cu Bockwurst fin sau Frankfurter dacă Bratwurst nu este disponibil","2 linguri ulei neutru (floarea-soarelui) pentru prăjirea cârnaților","Pentru sosul de curry: 200 g ketchup de tomate de bună calitate (Heinz sau german Hela)","100 ml passata sau 1 lingură pastă de tomate + 80 ml apă ca substitut","2 linguri pudră de curry medie-iute (un amestec galben stil Madras) — originalul Herta Heuwer folosea o pudră de curry similară colonială britanică","1 linguriță paprika dulce maghiară","0,5 linguriță paprika afumată (opțional, adaugă profunzime)","1 lingură sos Worcestershire (secretul originalului Heuwer — nu este negociabil)","1 lingură oțet de cidru de mere SAU oțet de vin alb","1 lingură zahăr alb (ajută la echilibrarea oțetului și scoate în evidență tomatele)","0,5 linguriță piment ienibahar + 0,5 linguriță ghimbir măcinat (amestecul 'secret' de mirodenii calde pe care Heuwer le-a adăugat)","0,5 linguriță sare + un vârf de cayenne sau chili iute","Pentru servire: pudră de curry suplimentară pentru presărare deasupra + 2 porții de Pommes Frites (aproximativ 400 g cartofi prăjiți fierbinți și crocanți din cuptor sau friteuză), sau 2 Brötchen mici; 2 furculițe mici de lemn (Pommespieker) pentru experiența autentică berlineză"]},"howIsMade":{"zh":"戳香肠：在烹饪前15分钟从冰箱中取出4根Bratwurst，使其接近室温、用叉子在每根香肠上戳4–5次——这可以防止外皮在锅中爆裂，并让一些脂肪渗出。制作咖喱酱：在一个小平底锅中，将200克番茄酱+100毫升passata+2汤匙咖喱粉+1茶匙甜辣椒粉+0.5茶匙烟熏辣椒粉+1汤匙伍斯特沙司+1汤匙醋+1汤匙糖+0.5茶匙多香果+0.5茶匙磨碎的姜+0.5茶匙盐+一撮辣椒粉混合、搅拌均匀。慢炖酱汁：将咖喱酱在中低火下煮至温和慢炖、煮8–10分钟，用木勺经常搅拌，直到酱汁变得有光泽并稍微浓缩——它应该可以涂在勺背上、品尝并调整：如果太刺激，多加一撮糖；如果太甜，多加一点醋、在最小火上保温。煎香肠：在重煎锅中以中火加热2汤匙油、加入戳过的香肠，煎8–10分钟，每2分钟用夹子翻面，直到所有面都呈深金黄色，外皮酥脆、内部温度应达到70 °C——香肠必须完全煮熟。静置2分钟：将香肠转移到铺有纸巾的板上、让它们静置2分钟——这完成了烹饪，并让汁液重新分布，因此切片时它们不会喷出。切片：用锋利的刀，将每根香肠斜切成8块1.5厘米的片、斜切提供更多表面让酱汁附着，是标志性的柏林呈现方式。摆盘：将切片香肠分到2个深纸盘或浅碗（柏林Imbiss风格）、在顶部慷慨地浇上热咖喱酱，使其在切片周围积聚、在整个盘子上撒一撮额外慷慨的咖喱粉——粉尘状的顶部使其成为currywurst，而不仅仅是酱汁中的香肠。配Pommes上菜：将一个木制Pommespieker（小叉子）插入切片中，在托盘一侧放一堆金黄色的Pommes Frites和一小团蛋黄酱+番茄酱（德国的Pommes rot-weiß）、站着吃，最好在柏林街角、搭配冰镇Pilsner啤酒、最好在5分钟内食用——乐趣在于酥脆外皮、热酱、粉状咖喱和咸薯条的对比。","en":"PRICK THE SAUSAGES: take 4 Bratwurst out of the fridge 15 minutes before cooking to come closer to room temperature; prick each sausage 4–5 times with a fork — this prevents the skin from bursting open in the pan and lets some fat render out. MAKE THE CURRY SAUCE: in a small saucepan, combine 200 g ketchup + 100 ml passata + 2 tbsp curry powder + 1 tsp sweet paprika + 0.5 tsp smoked paprika + 1 tbsp Worcestershire + 1 tbsp vinegar + 1 tbsp sugar + 0.5 tsp allspice + 0.5 tsp ground ginger + 0.5 tsp salt + a pinch of cayenne; whisk to combine. SIMMER THE SAUCE: bring the curry sauce to a gentle simmer over medium-low heat; cook 8–10 minutes, stirring often with a wooden spoon, until the sauce is glossy and slightly reduced — it should coat the back of a spoon; taste and adjust: if too sharp, add a pinch more sugar; if too sweet, a splash more vinegar; keep warm on the lowest heat. FRY THE SAUSAGES: heat 2 tbsp oil in a heavy skillet over medium heat; add the pricked sausages and fry 8–10 minutes, turning every 2 minutes with tongs, until deeply golden brown on all sides and the skin is crisp; the internal temperature should reach 70 °C — sausages must be fully cooked through. REST 2 MINUTES: transfer the sausages onto a board lined with paper towel; let them rest 2 minutes — this finishes cooking and lets the juices redistribute, so they don't gush out when sliced. SLICE: with a sharp knife, slice each sausage diagonally into 8 pieces of 1.5 cm; the diagonal cut gives more surface for the sauce to cling to and is the iconic Berlin presentation. ASSEMBLE: divide the sliced sausages between 2 deep paper-tray plates or shallow bowls (the Berlin Imbiss style); ladle the hot curry sauce generously over the top so it pools around the slices; dust the whole plate with an extra generous pinch of curry powder — the dusty top is what makes it a currywurst, not just a sausage in sauce. SERVE WITH POMMES: stab a wooden Pommespieker (small fork) into the slices, set on the side of the tray a heap of golden Pommes Frites and a small dollop of mayonnaise + ketchup (the German Pommes rot-weiß); eat standing up, ideally on a Berlin street corner; pair with a cold Pilsner; best eaten within 5 minutes — the joy is in the contrast of crisp skin, hot sauce, dusty curry, and salty fries."}},{"id":174,"servings":4,"tipType":"meat","pairingsType":"thai","origin":{"zh":"泰国","en":"Thailand","ro":"Thailanda"},"name":{"zh":"冬阴椰鸡汤","en":"Tom Kha Gai","ro":"Tom Kha Gai"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["500克去骨去皮鸡腿肉（在这道精致的汤中比鸡胸肉更有风味），逆纹理薄切成5毫米条","400毫升不加糖的全脂椰奶（奶油层分离，见步骤2）","600毫升无盐鸡汤（自制或购买的低钠版）","1把新鲜高良姜（kha）——约50克，去皮切成5毫米硬币片；不要用生姜替代，风味完全不同","3根新鲜香茅（takrai）——去除外层叶子，下部10厘米用刀背拍裂并切成5厘米段","6片新鲜青柠叶（bai makrut），去叶脉撕开（不切碎——撕开时释放油脂）","4个小泰国鸟眼辣椒（prik kee noo）——整个轻轻拍裂，如果想要温和的辣味就不切片（切片会更辣）","4瓣大蒜，轻轻拍裂","2个小红葱（约80克），薄切","200克草菇（罐装，沥干），切成两半——或用新鲜平菇/香菇/口蘑替代","4汤匙泰国鱼露（nam pla）——Squid或Tiparos品牌风味最佳","1汤匙棕榈糖（或浅红糖）","60毫升新鲜青柠汁（来自2个青柠）——在最后加入，绝不煮沸","2汤匙泰国大豆油辣椒酱（nam prik pao）——增添标志性的烟熏深度（可选但传统）","1小束新鲜香菜叶，粗切，用作装饰","4根葱，斜切薄片，用作装饰","搭配：320克煮熟的茉莉香米（每份80克干米）+ 1个青柠切成楔形"],"en":["500 g boneless skinless chicken thighs (more flavour than breast in this delicate broth), thinly sliced across the grain into 5 mm strips","400 ml unsweetened full-fat coconut milk (the cream layer separated, see step 2)","600 ml unsalted chicken stock (low-sodium homemade or store-bought)","1 hand of fresh galangal (kha) — ~50 g, peeled and cut into 5 mm coin slices; do NOT substitute ginger, the flavour is completely different","3 stalks fresh lemongrass (takrai) — outer leaves removed, lower 10 cm bruised with the back of a knife and cut into 5 cm sections","6 fresh kaffir lime leaves (bai makrut), de-veined and torn (NOT chopped — they release oils when torn)","4 small Thai bird's eye chilies (prik kee noo) — lightly bruised whole, not sliced if you want gentle heat (sliced for hot)","4 garlic cloves, lightly bruised","2 small shallots (~80 g), thinly sliced","200 g straw mushrooms (canned, drained), halved — or fresh oyster/shiitake/button mushrooms as substitute","4 tbsp Thai fish sauce (nam pla) — Squid or Tiparos brand for best flavour","1 tbsp palm sugar (or light brown sugar)","60 ml fresh lime juice (from 2 limes) — added at the END, never boiled","2 tbsp Thai chili paste in soybean oil (nam prik pao) — adds the signature smoky depth (optional but traditional)","1 small bunch fresh cilantro (coriander) leaves, roughly chopped, to garnish","4 spring onions, thinly sliced on the diagonal, to garnish","To serve: 320 g cooked jasmine rice (80 g dry per serving) + 1 lime cut into wedges"],"ro":["500 g pulpe de pui dezosate și fără piele (mai aromate decât pieptul în acest bulion delicat), feliate subțire în benzi de 5 mm contra fibrei","400 ml lapte de cocos integral neîndulcit (cu stratul de smântână separat, vezi pasul 2)","600 ml supă de pui nesărată (de casă sau cumpărată cu conținut scăzut de sodiu)","1 mână de galangal proaspăt (kha) — ~50 g, curățat și tăiat în felii de 5 mm; NU înlocui cu ghimbir, aroma este complet diferită","3 tulpini de lemongrass proaspăt (takrai) — frunzele exterioare îndepărtate, partea inferioară de 10 cm zdrobită cu dosul cuțitului și tăiată în secțiuni de 5 cm","6 frunze de kaffir lime proaspete (bai makrut), cu vinele îndepărtate și rupte (NU tăiate — eliberează uleiurile când sunt rupte)","4 ardei iuți thailandezi mici (prik kee noo) — zdrobiți ușor întregi, nu feliați dacă vrei iuțeală blândă (feliați pentru iute)","4 căței de usturoi, zdrobiți ușor","2 șalote mici (~80 g), feliate subțire","200 g ciuperci de paie (la conservă, scurse), tăiate în jumătăți — sau ciuperci proaspete oyster/shiitake/champignon ca substitut","4 linguri sos de pește thailandez (nam pla) — marca Squid sau Tiparos pentru cea mai bună aromă","1 lingură zahăr de palmier (sau zahăr brun deschis)","60 ml suc de lime proaspăt (din 2 limete) — adăugat la SFÂRȘIT, niciodată fiert","2 linguri pastă thailandeză de ardei iute în ulei de soia (nam prik pao) — adaugă profunzimea afumată caracteristică (opțional dar tradițional)","1 mănunchi mic de coriandru proaspăt (frunze de cilantro), tocat grosier, pentru garnitură","4 cepe verzi, feliate subțire pe diagonală, pentru garnitură","Pentru servire: 320 g orez jasmin fiert (80 g uscat pe porție) + 1 lime tăiat în felii"]},"howIsMade":{"zh":"准备香料：将50克高良姜去皮切成5毫米硬币状、从3根香茅上去除坚韧的外层叶子，用重刀背拍打下部10厘米以释放精油——然后切成5厘米的段、撕开（不要切碎）6片青柠叶以释放精油、用刀的侧面轻轻拍碎4个辣椒+4瓣大蒜、这些香料是汤的灵魂——千万不要使用磨碎的替代品。分离椰奶：打开一罐400毫升的椰奶，不要摇晃、浓稠的奶油通常位于顶部——用勺子舀出约100毫升的浓稠奶油并放在一边（这是你的hua kati，即奶油）、其余的是较稀的奶（hang kati）。绽放奶油：在中号锅中以中火慢炖100毫升椰奶油3–4分钟，直到它分离，油开始明显分离——这浓缩了椰子风味，是传统的泰式开局、（如果你的椰奶分离不干净，可以跳过此步骤，直接将所有东西放入锅中开始、）。注入香料：将高良姜片、香茅段、撕开的青柠叶、拍碎的辣椒、大蒜和80克切片红葱头加入热的椰奶油中、搅拌1分钟直到香气浓郁、厨房应该有明显的泰国气味——明亮的柑橘、辛辣的高良姜和甜美的椰子。制作汤底：倒入剩余的300毫升椰奶+600毫升鸡汤+2汤匙nam prik pao（如使用）、将其煮至温和的慢炖（绝不能大火煮沸——如果用大火煮沸，椰奶会丑陋地分离）、不加盖慢炖8分钟，让香料充分浸入，汤底味道深沉而圆润。加入鸡肉：将500克切片鸡肉放入慢炖的汤底中，轻轻搅拌以分开碎片、慢炖4–5分钟直到鸡肉刚刚熟透并变白——煮过头会变硬、加入200克切半的草菇再慢炖2分钟。调味：关火、搅入4汤匙鱼露+1汤匙棕榈糖、品尝——汤底应该是咸的、微甜、温和的辣，并充满柑橘香气、如果需要，可加入更多鱼露或糖、关火在这里至关重要。最后一刻加青柠：只在上菜前搅入60毫升新鲜青柠汁——煮沸青柠汁会使其变苦变暗、舀入深碗中、顶部放上新鲜香菜+切片葱+对那些喜欢更辣的人，再加几片拍碎的辣椒、趁热搭配蒸好的茉莉香米和青柠角上菜、告诉客人：高良姜、香茅和青柠叶是香料，不可食用——把它们推到碗边。","en":"PREP THE AROMATICS: peel and slice 50 g galangal into 5 mm coins; remove the tough outer leaves from 3 lemongrass stalks and bruise the lower 10 cm with the back of a heavy knife to release the oils — then cut into 5 cm pieces; tear (don't chop) 6 kaffir lime leaves to release their oils; lightly bruise 4 chilies + 4 garlic cloves with the side of the knife; these aromatics are the soul of the broth — never use ground substitutes. SEPARATE THE COCONUT MILK: open a 400 ml can of coconut milk without shaking; the thick cream usually sits on top — spoon off about 100 ml of the thick cream and set aside (this is your hua kati, the cream); the rest is the thinner milk (hang kati). BLOOM THE CREAM: in a medium pot over medium heat, simmer the 100 ml coconut cream 3–4 minutes until it splits and the oil starts to separate visibly — this concentrates the coconut flavor and is the traditional Thai opening move; (If your coconut milk doesn't separate cleanly, skip this step and just start with everything in the pot.). INFUSE THE AROMATICS: add the galangal slices, lemongrass pieces, torn lime leaves, bruised chilies, garlic, and 80 g sliced shallots to the hot coconut cream; stir 1 minute until intensely aromatic; the kitchen should smell distinctly of Thai — bright citrus, peppery galangal, and sweet coconut. BUILD THE BROTH: pour in the remaining 300 ml coconut milk + 600 ml chicken stock + 2 tbsp nam prik pao (if using); bring to a gentle simmer (NEVER a hard boil — coconut milk separates ugly if boiled hard); simmer 8 minutes uncovered, so the aromatics infuse fully and the broth tastes deep and rounded. ADD THE CHICKEN: drop the 500 g sliced chicken into the simmering broth, stirring gently to separate the pieces; simmer 4–5 minutes until the chicken is just cooked through and white — overcooking turns it tough; add 200 g halved straw mushrooms and simmer 2 minutes more. SEASON: turn off the heat; stir in 4 tbsp fish sauce + 1 tbsp palm sugar; taste — the broth should be savoury, slightly sweet, mildly hot, and full of citrus aroma; add a splash more fish sauce or sugar if needed; off heat is critical here. LIME AT THE LAST MOMENT: stir in 60 ml fresh lime juice ONLY just before serving — boiling the lime juice turns it bitter and dull; ladle into deep bowls; top with fresh cilantro + sliced spring onions + a few extra slices of bruised chili for those who like more heat; serve hot with steamed jasmine rice on the side and lime wedges; tell guests: the galangal, lemongrass, and lime leaves are aromatics, not edible — fish them to the side of the bowl."}},{"id":175,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"zh":"佛得角","en":"Cape Verde","ro":"Capul Verde"},"name":{"zh":"卡丘帕炖菜","en":"Cachupa","ro":"Cachupa"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["400克milho cachupa（白色玉米粒，佛得角特有的破碎干燥品种）——在大量冷水中浸泡过夜（强制性）","200克干红芸豆——浸泡过夜","200克干黄油豆（利马豆）或鹰嘴豆——浸泡过夜（豆类的混合是佛得角的标志）","500克猪肩肉（cabidela），切成3厘米的方块","300克盐渍猪肋骨或猪肚肉（toucinho），切成块——在冷水中浸泡1小时以去除多余的盐","200克linguiça或chouriço portuguesa（葡萄牙烟熏香肠），切成1.5厘米的片","200克morcela（葡萄牙血肠）——可选，传统","2个大黄洋葱（约350克），一个切碎用于refogado，一个切成楔形","6瓣大蒜，切碎","2个中等成熟的番茄（约250克），去皮磨碎，或1罐200克的碎番茄","1汤匙番茄酱","2片月桂叶+1茶匙磨碎的孜然+1茶匙甜红椒粉+0.5茶匙干牛至+1茶匙盐+0.5茶匙黑胡椒","3汤匙红棕榈油或橄榄油（棕榈油在一些岛屿上更传统）","500克南瓜或胡桃南瓜，去皮切成4厘米的方块","300克红薯或山药，去皮切成4厘米的方块","200克皱叶甘蓝，切成4厘米的楔形（在最后阶段加入）","2升水（或猪肉汤）+1个piri-piri或scotch bonnet辣椒（可选，用于岛屿的淡淡辣味）","搭配：新鲜白面包块、几片额外的烤linguiça、辣piri-piri酱以及第二天的'cachupa guisada'——煎锅与鸡蛋一起煎"],"en":["400 g milho cachupa (white hominy corn, the cracked dried Cape Verdean variety) — soaked overnight in plenty of cold water (mandatory)","200 g dried red kidney beans — soaked overnight","200 g dried butter beans (lima beans) or chickpeas — soaked overnight (the mixture of legumes is the Cape Verdean signature)","500 g pork shoulder (cabidela), cut into 3 cm cubes","300 g salted pork ribs or pork belly (toucinho), cut into chunks — soak 1 hour in cold water to remove excess salt","200 g linguiça or chouriço portuguesa (Portuguese smoked sausage), cut into 1.5 cm slices","200 g morcela (Portuguese blood sausage) — optional, traditional","2 large yellow onions (~350 g), one finely diced for the refogado and one cut into wedges","6 garlic cloves, minced","2 medium ripe tomatoes (~250 g), peeled and grated, or 1 × 200 g can crushed tomatoes","1 tbsp tomato paste","2 bay leaves + 1 tsp ground cumin + 1 tsp sweet paprika + 0.5 tsp dried oregano + 1 tsp salt + 0.5 tsp black pepper","3 tbsp red palm oil OR olive oil (palm oil is more traditional in some islands)","500 g pumpkin or butternut squash, peeled and cut into 4 cm cubes","300 g sweet potato or yam, peeled and cut into 4 cm cubes","200 g savoy cabbage, cut into 4 cm wedges (added in the final stage)","2 L water (or pork stock) + 1 piri-piri or scotch bonnet chili (optional, for the islands' light heat)","To serve: chunks of fresh white bread, a few extra slices of grilled linguiça, hot piri-piri sauce, and the next-day pan-fried 'cachupa guisada' with eggs option mentioned"],"ro":["400 g milho cachupa (porumb hominy alb, varietatea crăpată uscată specifică Capului Verde) — înmuiat peste noapte în multă apă rece (obligatoriu)","200 g fasole roșie uscată — înmuiată peste noapte","200 g fasole untoasă uscată (lima) sau năut — înmuiată peste noapte (amestecul de leguminoase este semnătura capverdiană)","500 g spată de porc (cabidela), tăiată în cuburi de 3 cm","300 g coaste de porc sărate sau burtă de porc (toucinho), tăiate în bucăți — înmuiate 1 oră în apă rece pentru a îndepărta excesul de sare","200 g linguiça sau chouriço portuguesa (cârnat afumat portughez), tăiat în felii de 1.5 cm","200 g morcela (cârnat de sânge portughez) — opțional, tradițional","2 cepe galbene mari (~350 g), una tăiată mărunt pentru refogado și una tăiată în felii mari","6 căței de usturoi, tocați mărunt","2 roșii medii coapte (~250 g), decojite și răzuite, sau 1 cutie de 200 g de roșii zdrobite","1 lingură pastă de roșii","2 foi de dafin + 1 linguriță chimion măcinat + 1 linguriță boia dulce + 0.5 linguriță oregano uscat + 1 linguriță sare + 0.5 linguriță piper negru","3 linguri ulei roșu de palmier SAU ulei de măsline (uleiul de palmier este mai tradițional în unele insule)","500 g dovleac sau dovleac plăcintar, curățat și tăiat în cuburi de 4 cm","300 g cartof dulce sau ignamă, curățat și tăiat în cuburi de 4 cm","200 g varză de Milano, tăiată în felii mari de 4 cm (adăugată în etapa finală)","2 L apă (sau supă de porc) + 1 ardei iute piri-piri sau scotch bonnet (opțional, pentru iuțeala ușoară a insulelor)","Pentru servire: bucăți de pâine albă proaspătă, câteva felii suplimentare de linguiça la grătar, sos iute piri-piri și opțiunea 'cachupa guisada' a doua zi (prăjită în tigaie cu ouă)"]},"howIsMade":{"zh":"浸泡过夜：这一步不容商量、烹饪前一晚，将400克玉米粒+200克红芸豆+200克黄油豆/鹰嘴豆分别放入单独的碗中，盖上5厘米的冷水、至少浸泡12小时、第二天早上，沥干并冲洗、跳过浸泡会使玉米在数小时烹饪后仍然粗糙。预煮玉米粒：将沥干的玉米粒放入大锅中，加入1.5升新鲜冷水+1片月桂叶+1茶匙盐、煮沸，然后盖上盖子慢炖1小时、玉米应该部分变软但中心仍然坚硬——它将在炖菜中继续煮熟、沥干，保留500毫升烹饪液。预煮豆类：在第二个锅中，将沥干的红芸豆和黄油豆与新鲜冷水一起放入，水高出豆子3厘米、煮沸，撇去浮沫5分钟，然后慢炖45分钟直到al dente——它们将在炖菜中完成、沥干。REFOGADO：在大而重的8升锅中，用中火加热3汤匙棕榈油或橄榄油、加入200克切碎的洋葱+6瓣切碎的大蒜，煮8–10分钟直到变软变金、加入1汤匙番茄酱，煮1分钟直到变深色、加入250克磨碎的番茄+1茶匙红椒粉+1茶匙孜然+0.5茶匙牛至，煮4–5分钟，直到混合物减少并且油分离到表面。煎猪肉：将refogado推到一边、将火加大到中高火，加入500克猪肩肉块铺成单层、每面煎3分钟直到金黄，然后搅入refogado、加入沥干的盐渍猪肋骨/腩肉+1茶匙盐+0.5茶匙胡椒+1片剩余的月桂叶+可选的piri-piri辣椒。制作炖菜：加入部分煮熟的玉米粒+沥干的豆类+2升水（或猪肉汤）+保留的500毫升玉米烹饪液、煮至温和的慢炖。慢炖：不加盖慢炖2小时，每20–30分钟搅拌一次、1小时后，加入500克南瓜块+300克红薯块+linguiça片、1.5小时后，加入200克卷心菜楔+洋葱楔+morcela片（如使用）、炖菜应减少到浓稠的粥状稠度，其中玉米、豆类、蔬菜和肉类都很嫩、品尝并调整盐——盐渍猪肉和香肠加了很多。静置并上菜：关火，让cachupa静置10分钟——这是它增稠到完美稠度的时候、慷慨地舀入深碗中，所有颜色都可见：黄色玉米、红色豆类、橙色南瓜、绿色卷心菜、金色香肠和丰富的猪肉、搭配新鲜白面包块、桌上的辣piri-piri酱和一杯佛得角grogue或啤酒上菜、第二天的剩菜在煎锅中煎，上面加一个煎蛋作为'cachupa guisada'——被认为比第一天还要好。","en":"SOAK OVERNIGHT: this is non-negotiable; the night before cooking, place 400 g hominy corn + 200 g kidney beans + 200 g butter beans/chickpeas each in separate bowls covered by 5 cm of cold water; soak 12 hours minimum; the next morning, drain and rinse; skipping the soak gives a corn that stays gritty after hours of cooking. PRE-COOK THE HOMINY: place the drained hominy in a large pot with 1.5 L fresh cold water + 1 bay leaf + 1 tsp salt; bring to a boil, then simmer covered 1 hour; the corn should be partially tender but still firm at the centre — it will continue cooking in the stew; drain, reserving 500 ml of the cooking liquid. PRE-COOK THE BEANS: in a second pot, place the drained kidney beans and butter beans together with fresh cold water to cover by 3 cm; bring to a boil, skim foam for 5 min, then simmer 45 min until al dente — they will finish in the stew; drain. THE REFOGADO: in a large heavy 8 L pot, heat 3 tbsp palm or olive oil over medium heat; add 200 g finely diced onion + 6 minced garlic and cook 8–10 minutes until soft and golden; stir in 1 tbsp tomato paste and cook 1 min until darkened; add 250 g grated tomato + 1 tsp paprika + 1 tsp cumin + 0.5 tsp oregano and cook 4–5 min until the mixture reduces and the oil separates on the surface. SEAR THE PORK: push the refogado to the side; raise the heat to medium-high and add the 500 g pork shoulder cubes in a single layer; sear 3 minutes per side until golden brown, then stir into the refogado; add the drained salted pork ribs/belly + 1 tsp salt + 0.5 tsp pepper + 1 remaining bay leaf + the optional piri-piri chili. BUILD THE STEW: add the partially-cooked hominy + the drained beans + 2 L water (or pork stock) + the 500 ml reserved corn-cooking liquid; bring to a gentle simmer. SLOW SIMMER: simmer uncovered, stirring every 20–30 minutes, for 2 hours; after 1 hour, add the 500 g pumpkin cubes + 300 g sweet potato cubes + the linguiça slices; after 1.5 hours, add the 200 g cabbage wedges + the onion wedges + the morcela slices (if using); the stew should reduce to a thick, porridge-like consistency where the corn, beans, vegetables, and meats are all tender; taste and adjust salt — the saltpork and sausages add a lot. REST AND SERVE: turn off the heat and let the cachupa rest 10 minutes — this is when it thickens to the perfect consistency; ladle generously into deep bowls with all the colors visible: yellow corn, red beans, orange pumpkin, green cabbage, golden sausage, and rich pork; serve with chunks of fresh white bread, hot piri-piri sauce on the table, and a glass of Cape Verdean grogue or beer; the leftovers next day are pan-fried with a fried egg on top as 'cachupa guisada' — considered even better than the first day."}},{"id":176,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"zh":"印度","en":"India","ro":"India"},"name":{"zh":"帕夫巴吉","en":"Pav Bhaji","ro":"Pav Bhaji"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["500克粉质土豆，去皮切成3厘米方块","250克花椰菜小花（约1/2个小头）","100克青豌豆（新鲜或冷冻）","100克法国青豆，切成1厘米段","1根中等胡萝卜（约100克），切丁","100克无盐黄油（是的——这么多，这是街头小贩的黄油用量）——分用","2个大红洋葱（约300克）——一个切碎用于bhaji，一个生切碎用作配菜","1个大青甜椒或灯笼椒（约150克），切碎","4个成熟番茄（约500克），搅拌机打成泥","1汤匙姜蒜泥（或3厘米生姜+4瓣大蒜，一起磨碎）","2汤匙pav bhaji masala（Everest或MDH品牌）——特定的香料混合，不要用garam masala代替","1茶匙克什米尔红辣椒粉（为标志性的红色，温和辣度）","0.5茶匙姜黄+1.5茶匙盐+0.5茶匙黑胡椒粉","1个柠檬，切成4块+切碎的新鲜香菜（cilantro），慷慨地","8个小而软的pav面包（孟买风格ladi pav，或用brioche slider面包代替）","50克无盐黄油用于烤pav+额外的红辣椒粉用于撒","上菜配料：额外的生红洋葱、新鲜香菜、柠檬片、1个小青辣椒切碎（可选）"],"en":["500 g floury potatoes, peeled and cut into 3 cm cubes","250 g cauliflower florets (about 1/2 small head)","100 g green peas (fresh or frozen)","100 g French beans, cut into 1 cm pieces","1 medium carrot (~100 g), diced","100 g unsalted butter (yes — that much, this is street-vendor butter quantities) — divided","2 large red onions (~300 g) — one finely diced for the bhaji, one finely diced raw for the garnish","1 large green bell pepper or capsicum (~150 g), finely diced","4 ripe tomatoes (~500 g), pureed in a blender","1 tbsp ginger-garlic paste (or 3 cm ginger + 4 garlic cloves, grated together)","2 tbsp pav bhaji masala (Everest or MDH brand) — the specific spice blend, do not substitute with garam masala","1 tsp Kashmiri red chili powder (for the iconic red color, mild heat)","0.5 tsp turmeric + 1.5 tsp salt + 0.5 tsp ground black pepper","1 lemon, cut into 4 wedges + chopped fresh coriander (cilantro), generously","8 small soft pav buns (Mumbai-style ladi pav, or substitute with brioche slider buns)","50 g unsalted butter for toasting the pav + extra red chili powder for sprinkling","To serve: extra raw red onion, fresh coriander, lemon wedges, 1 small green chili finely chopped (optional)"],"ro":["500 g cartofi făinoși, curățați și tăiați în cuburi de 3 cm","250 g buchețele de conopidă (aproximativ 1/2 căpățână mică)","100 g mazăre verde (proaspătă sau congelată)","100 g fasole verde franceză, tăiată în bucăți de 1 cm","1 morcov mediu (~100 g), tăiat cubulețe","100 g unt nesărat (da — atât de mult, acestea sunt cantitățile de unt ale vânzătorilor de stradă) — împărțit","2 cepe roșii mari (~300 g) — una tăiată mărunt pentru bhaji, una tăiată mărunt crudă pentru garnitură","1 ardei capia verde mare sau capsicum (~150 g), tăiat mărunt","4 roșii coapte (~500 g), pasate în blender","1 lingură pastă de ghimbir-usturoi (sau 3 cm ghimbir + 4 căței usturoi, răzuiți împreună)","2 linguri pav bhaji masala (marca Everest sau MDH) — amestecul specific de condimente, nu înlocuiți cu garam masala","1 linguriță pudră de chili roșu Kashmiri (pentru culoarea roșie iconică, iuțeală blândă)","0.5 linguriță turmeric + 1.5 linguriță sare + 0.5 linguriță piper negru măcinat","1 lămâie, tăiată în 4 sferturi + coriandru proaspăt (cilantro) tocat, generos","8 chifle pav mici și moi (ladi pav stil Mumbai, sau înlocuiți cu chifle brioche slider)","50 g unt nesărat pentru prăjirea pavului + suplimentar pudră de chili roșu pentru presărat","Pentru servire: ceapă roșie crudă suplimentară, coriandru proaspăt, sferturi de lămâie, 1 ardei iute verde mic tocat mărunt (opțional)"]},"howIsMade":{"zh":"高压锅煮蔬菜：在高压锅（或大锅）中混合500克土豆方块+250克花椰菜+100克豌豆+100克法国青豆+100克胡萝卜丁+500毫升水+1茶匙盐、高压煮3声哨响，然后关火让压力自然释放（约15分钟）、如果使用普通锅，盖上盖子炖煮25–30分钟，直到所有蔬菜用叉子可以叉透、沥干，保留250毫升煮蔬菜的水。捣碎蔬菜：用土豆捣碎器，在锅中直接用力捣碎煮熟的蔬菜，直到呈现粗糙的泥状——应该保留一些质地，这不是顺滑的汤、放在一边。香料绽放：在大而厚的平底锅或kadhai中，中火加热50克黄油，直到融化起泡、加入150克切碎的红洋葱，经常翻炒5–6分钟，直到变软并边缘开始变金黄。姜蒜+甜椒：加入1汤匙姜蒜泥，搅拌1分钟直到生味消失、加入150克切丁的青甜椒，烹饪3–4分钟直到刚刚变软但仍然鲜绿。香料绽放：加入2汤匙pav bhaji masala+1茶匙克什米尔辣椒粉+0.5茶匙姜黄、搅拌30秒，直到香料浓郁芬芳——不要烧焦，必要时稍微降低火力。制作bhaji：倒入打好的番茄泥+0.5茶匙黑胡椒粉+0.5茶匙盐、经常翻炒6–8分钟，直到番茄变稠，黄油开始在锅边分离——这是masala准备好的视觉信号、加入保留的250毫升蔬菜水+捣碎的蔬菜、大力搅拌混合。慢煮+继续捣碎：将bhaji慢煮10–12分钟，经常搅拌并直接用土豆捣碎器在锅中进一步捣碎、bhaji应该变得浓稠、暗红色、有光泽且浓郁芬芳、调整调味——孟买街头小贩喜欢咸辣口味、再拌入30克黄油和1汤匙切碎的香菜、挤入半个柠檬的汁。烤pav并上桌：将8个pav面包水平切开但不完全切断（书本式）、中火加热宽煎锅、加入30克黄油+一撮pav bhaji masala+一撮克什米尔辣椒粉，旋转、将打开的pav面包压入热黄油中，每面烤30–60秒直到金黄芬芳、立即装盘：慷慨堆放的热bhaji上面放一块黄油、切碎的生红洋葱、切碎的香菜、一片柠檬和可选的切碎青辣椒、每人配2个烤pav、撕开pav，蘸入bhaji，每口挤柠檬——在家享用孟买街头美食。","en":"PRESSURE-COOK THE VEGETABLES: in a pressure cooker (or large pot) combine 500 g potato cubes + 250 g cauliflower + 100 g peas + 100 g French beans + 100 g diced carrot + 500 ml water + 1 tsp salt; pressure cook 3 whistles on high, then turn off and let the pressure release naturally (about 15 min); if using a regular pot, cover and simmer 25–30 minutes until everything is fork-tender; drain, RESERVING 250 ml of the cooking water. MASH THE VEGETABLES: with a potato masher, vigorously mash the boiled vegetables right in the pot until you have a coarse purée — some texture should remain, this is NOT a smooth soup; set aside. BLOOM THE AROMATICS: heat 50 g butter in a large heavy skillet or kadhai over medium heat until melted and foaming; add 150 g finely diced red onion and cook stirring often 5–6 minutes until soft and just turning golden at the edges. GINGER-GARLIC + BELL PEPPER: add 1 tbsp ginger-garlic paste and stir 1 minute until the raw smell disappears; add 150 g diced green bell pepper and cook 3–4 minutes until just softened but still bright green. SPICES BLOOM: add 2 tbsp pav bhaji masala + 1 tsp Kashmiri chili powder + 0.5 tsp turmeric; stir 30 seconds until the spices are intensely fragrant — do not burn, lower the heat slightly if needed. BUILD THE BHAJI: pour in the pureed tomatoes + 0.5 tsp ground pepper + 0.5 tsp salt; cook stirring often 6–8 minutes until the tomato has reduced and the butter starts to separate around the edges of the pan — this is the visual sign that the masala is ready; add the reserved 250 ml vegetable water + the mashed vegetables; stir vigorously to combine. SIMMER + MASH MORE: simmer the bhaji 10–12 minutes, stirring frequently and mashing more with a potato masher right in the pan; the bhaji should become thick, dark red, glossy, and intensely fragrant; adjust seasoning — Mumbai street vendors love it salty and spicy; stir in another 30 g butter and 1 tbsp chopped coriander; squeeze in juice of half a lemon. TOAST THE PAV AND SERVE: slice 8 pav buns horizontally without cutting all the way through (book-style); heat a wide skillet over medium heat; add 30 g butter + a pinch of pav bhaji masala + a pinch of Kashmiri chili powder, swirl; press the open pav buns into the hot butter and toast 30–60 seconds per side until golden and fragrant; plate immediately: a generous mound of hot bhaji topped with a knob of butter, chopped raw red onion, chopped coriander, a lemon wedge, and optional chopped green chili; serve with 2 toasted pav per person on the side; tear the pav, dip into the bhaji, squeeze the lemon over each bite — Mumbai street food at home."}},{"id":177,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"zh":"芬兰","en":"Finland","ro":"Finlanda"},"name":{"zh":"卡累利阿炖肉","en":"Karelian stew","ro":"Karjalanpaisti"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["400克牛肩肉（chuck），切成3厘米的方块","400克猪肩肉，切成3厘米的方块","400克羊肩肉，切成3厘米的方块（或拉普兰地区的驯鹿肉）","2个大黄洋葱（约400克），切成厚片","4根中等胡萝卜（约400克），切成3厘米的块","1茶匙整粒黑胡椒","4片月桂叶","6粒完整杜松子（芬兰的标志，略带松木味——不可妥协）","6粒完整多香果","2茶匙盐","1升冷水（或淡牛肉汤——传统上用水）","1汤匙中性油或50克黄油用于可选的煎制步骤","搭配：800克煮熟的新土豆配黄油和莳萝、腌黄瓜、越橘酱（puolukkahillo）、深色黑麦面包和一杯冷牛奶或啤酒"],"en":["400 g beef chuck, cubed 3 cm","400 g pork shoulder, cubed 3 cm","400 g lamb shoulder, cubed 3 cm (or reindeer in Lapland)","2 large yellow onions (~400 g), thickly sliced","4 medium carrots (~400 g), cut into 3 cm chunks","1 tsp whole black peppercorns","4 bay leaves","6 whole juniper berries (the Finnish signature, slightly piny — non-negotiable)","6 whole allspice berries","2 tsp salt","1 L cold water (or weak beef stock — traditional is water)","1 tbsp neutral oil OR 50 g butter for the optional searing step","To serve: 800 g boiled new potatoes with butter and dill, pickled cucumber, lingonberry jam (puolukkahillo), dark rye bread, and a glass of cold milk or beer"],"ro":["400 g pulpă de vită (chuck), tăiată în cuburi de 3 cm","400 g spată de porc, tăiată în cuburi de 3 cm","400 g spată de miel, tăiată în cuburi de 3 cm (sau ren în Laponia)","2 cepe galbene mari (~400 g), tăiate în felii groase","4 morcovi medii (~400 g), tăiați în bucăți de 3 cm","1 linguriță boabe întregi de piper negru","4 foi de dafin","6 boabe întregi de ienupăr (semnătura finlandeză, ușor rășinos — non-negociabil)","6 boabe întregi de ienibahar","2 lingurițe sare","1 L apă rece (sau supă slabă de vită — tradițional este apa)","1 lingură ulei neutru SAU 50 g unt pentru pasul opțional de rumenire","Pentru servire: 800 g cartofi noi fierți cu unt și mărar, castravete murat, gem de merișoare lingonberry (puolukkahillo), pâine neagră de secară și un pahar de lapte rece sau bere"]},"howIsMade":{"zh":"将烤箱预热至125°C——非常低的慢烤箱是Karjalanpaisti的标志，是定义其融化质感的菜肴。修整并切块：将400克牛肉+400克猪肉+400克羊肉的所有筋去除、切成均匀的3厘米方块——不要切得更小、这是一道5小时的烹饪，较大的方块能撑住；较小的片会溶解成丝。选择您的风格——传统：跳过褐变、将所有生食材叠放，让烤箱完成工作，就像卡累利阿祖母们几个世纪以来所做的那样、现代：在荷兰锅中用大火加热1汤匙油，分3批煎肉每面2分钟以增加美拉德风味，然后取出、两种方法都能产生出色的结果。给锅叠层：在大型荷兰锅或铸铁砂锅中，按以下顺序构建交替层：底部牛肉，切片洋葱，猪肉，胡萝卜块，顶部羊肉、在各层之间分布4片月桂叶+6粒杜松子+6粒多香果+1茶匙胡椒粒+2茶匙盐——不要只放在顶部。加入液体：倒入1升冷水（或淡牛肉汤），使其达到肉的一半高度——不要覆盖、肉类在长时间烹饪过程中会释放自己的汁液，酱汁自然会浓缩。密封并慢炖：盖上紧密的盖子、转移到125°C的烤箱中4-5小时——是的，五小时，这就是关键、不要打开盖子，除非每1.5小时检查一次液体；如果减少得太快，加一点热水、当叉子毫不费力地刺入时，肉就准备好了。在烤箱中休息：关闭烤箱，让karjalanpaisti在关闭的温暖烤箱中再休息30分钟——风味加深，肉在酱汁中放松。上菜：将嫩肉抬到温暖的深盘中、在上面舀上汤汁般浓缩的汁液、杜松子和多香果可以留给勇敢的人，或者捞出来、配以拌了黄油和莳萝的煮新土豆、旁边的腌黄瓜、一大勺越橘酱（甜酸的对比）、深色黑麦面包片和一杯冷牛奶或啤酒——传统的芬兰晚餐伴随。","en":"PREHEAT THE OVEN to 125 °C — the very low slow oven is the SIGNATURE of Karjalanpaisti, the dish that defines its melting texture. TRIM AND CUBE: trim 400 g beef + 400 g pork + 400 g lamb of any sinew; cut into uniform 3 cm cubes — DO NOT cut smaller; this is a 5 h cook and larger cubes hold up; smaller pieces dissolve into shreds. CHOOSE YOUR STYLE — TRADITIONAL: skip browning; layer everything raw and let the oven do the work, as Karelian grandmothers have done for centuries; mODERN: heat 1 tbsp oil in a Dutch oven over high heat, brown the meat in 3 batches 2 min per side for added Maillard flavour, then lift out; both methods produce excellent results. LAYER THE POT: in a large Dutch oven or cast-iron casserole, build alternating layers in this order: beef on the bottom, sliced onion, pork, carrot chunks, lamb on top; distribute 4 bay leaves + 6 juniper berries + 6 allspice + 1 tsp peppercorns + 2 tsp salt between the layers — never just on top. ADD LIQUID: pour in 1 L cold water (or weak beef stock) so it comes halfway up the meat — NOT covering; the meats release their own juices during the long cook and the sauce concentrates naturally. SEAL AND SLOW-COOK: cover with a tight-fitting lid; transfer to the 125 °C oven for 4–5 hours — yes, five hours, that is the point; do NOT open the lid except once every 1.5 hours to check the liquid; if reducing too fast, add a splash of hot water; the meat is ready when a fork sinks in effortlessly. REST IN THE OVEN: turn off the oven and let the karjalanpaisti rest in the closed warm oven another 30 minutes — the flavours deepen and the meat relaxes into the sauce. SERVE: lift the tender meat into warm deep plates; spoon over the brothy concentrated juices; the juniper berries and allspice can stay in for the brave, or be fished out; serve with boiled new potatoes tossed in butter and dill, pickled cucumber on the side, a generous dollop of lingonberry jam (the sweet-tart counterpoint), slices of dark rye bread, and a glass of cold milk or beer — the traditional Finnish dinner accompaniment."}},{"id":178,"servings":6,"tipType":"meat","pairingsType":"french","origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"红酒炖牛肉","en":"Boeuf Bourguignon","ro":"Boeuf Bourguignon"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["1.5公斤牛肩肉或牛腱，切成4厘米的方块（带一些大理石纹以增添浓郁感）","200克拉登（烟熏猪五花肉切1厘米×3厘米）或200克厚切培根丁","750毫升浓郁的勃艮第红葡萄酒（黑皮诺）——不要使用便宜的葡萄酒","200毫升牛肉汤","2汤匙番茄酱","1个大洋葱（约250克），切碎用于腌渍和炖煮","2个中等胡萝卜（约250克），切成2厘米的块","4瓣大蒜，切碎","30克无盐黄油+2汤匙橄榄油用于煎制","3汤匙通用面粉","1束香草束：3枝百里香+2片月桂叶+6根欧芹茎用厨房细绳绑在一起","250克珍珠洋葱（silverskin），去皮","250克蘑菇（cremini或纽扣蘑菇），切半或切四瓣","30克额外黄油用于蘑菇和珍珠洋葱配菜","1.5茶匙盐+1茶匙现磨黑胡椒","2汤匙干邑或白兰地用于可选的火焰烹饪","新鲜平叶欧芹+法棍+煮新土豆或黄油鸡蛋面用于上菜"],"en":["1.5 kg beef chuck or shin, cubed 4 cm (some marbling for richness)","200 g lardons (smoked pork belly cut 1 cm × 3 cm) OR 200 g thick-cut bacon diced","750 ml full-bodied Burgundy red wine (Pinot Noir) — DO NOT use cheap wine","200 ml beef stock","2 tbsp tomato paste","1 large onion (~250 g), finely diced for the marinade and braise","2 medium carrots (~250 g), cut into 2 cm chunks","4 garlic cloves, minced","30 g unsalted butter + 2 tbsp olive oil for searing","3 tbsp all-purpose flour","1 bouquet garni: 3 thyme sprigs + 2 bay leaves + 6 parsley stems tied with kitchen string","250 g pearl onions (silverskin), peeled","250 g cremini or button mushrooms, halved or quartered","30 g extra butter for the mushroom-and-pearl-onion garnish","1.5 tsp salt + 1 tsp freshly ground black pepper","2 tbsp Cognac OR brandy for optional flambé","Fresh flat-leaf parsley + baguette + boiled new potatoes or buttered egg noodles to serve"],"ro":["1.5 kg pulpă de vită (chuck) sau gambă, tăiată în cuburi de 4 cm (cu ceva marmurare pentru bogăție)","200 g lardoni (piept de porc afumat tăiat 1 cm × 3 cm) SAU 200 g bacon gros tăiat cubulețe","750 ml vin roșu Burgundia robust (Pinot Noir) — NU folosi vin ieftin","200 ml supă de vită","2 linguri pastă de roșii","1 ceapă mare (~250 g), tăiată mărunt pentru marinadă și pentru tocană","2 morcovi medii (~250 g), tăiați în bucăți de 2 cm","4 căței de usturoi, tocați mărunt","30 g unt nesărat + 2 linguri ulei de măsline pentru rumenire","3 linguri făină universală","1 buchet garni: 3 crenguțe cimbru + 2 foi de dafin + 6 cozi de pătrunjel legate cu sfoară de bucătărie","250 g ceapă perlată (silverskin), curățată","250 g ciuperci cremini sau champignon, tăiate în jumătăți sau sferturi","30 g unt suplimentar pentru garnitura de ciuperci și ceapă perlată","1.5 linguriță sare + 1 linguriță piper negru proaspăt măcinat","2 linguri Cognac SAU brandy pentru flambare opțională","Pătrunjel proaspăt cu frunza plată + baghetă + cartofi noi fierți sau tăiței cu unt pentru servire"]},"howIsMade":{"zh":"腌制牛肉（提前12-24小时，朱莉娅·查尔德不容妥协的步骤）：将1.5公斤牛肉块放入非反应性碗中，加入750毫升红勃艮第葡萄酒+1个切碎的洋葱+1根切碎的胡萝卜+4瓣大蒜+香草束+1茶匙胡椒、盖好并冷藏12-24小时、通过筛子滤出，保留葡萄酒、用纸巾将牛肉拍得非常干——湿肉只会蒸而不会煎。煸出拉登：在重型荷兰锅中以中火烹饪200克拉登6-8分钟，直到酥脆金黄，油脂完全融出、用漏勺取出放在盘子里、在锅中留2汤匙油脂、煎牛肉：将火调至高。加入1汤匙橄榄油+15克黄油、分3-4批工作而不拥挤，将干燥的牛肉块每面煎2-3分钟，直到所有面都深度变褐——每批约8分钟、将每批转移到托盘上、粘在锅底的深色焦糖是风味基础——保留它。索福里托+火焰：将火调至中、在锅中加入250克切丁洋葱+250克胡萝卜块、烹饪5分钟直到开始变软、搅入4瓣切碎的大蒜+2汤匙番茄酱并烹饪1分钟。倒入2汤匙干邑并小心点燃（火焰在30秒内熄灭）、或者跳过火焰，简单地将干邑作为脱釉添加、建立炖菜：在蔬菜上撒3汤匙面粉，搅拌1分钟煮出生味、慢慢倒入保留的葡萄酒，同时搅拌，刮锅底以提起焦糖。加入200毫升牛肉汤+香草束+1.5茶匙盐+1茶匙胡椒、将牛肉+拉登放回锅中——液体应该几乎覆盖所有东西、慢炖：煮至轻微沸腾、盖上稍微敞开的盖子并转移到160°C的烤箱中（或在炉灶上以最低热度炖煮）2.5-3小时，每45分钟搅拌一次，直到牛肉炖到散开，酱汁变稠到光亮的覆盖勺子的浓郁。丢弃香草束、珍珠洋葱+蘑菇配菜：在另一个煎锅中，在中火上融化15克黄油、加入250克去皮的珍珠洋葱+1汤匙水+1茶匙糖+一撮盐，盖上盖子煮15分钟，然后揭开盖子煎5分钟直到光亮金黄、在同一个煎锅中，再加入15克黄油和250克蘑菇，分2批煸炒6-8分钟直到深金棕色——绝不要使锅拥挤。组装和上菜：将珍珠洋葱+蘑菇拌入炖菜、一起加热5分钟、品尝并调整盐、让炖菜离火休息10分钟——风味会大大加深。在深盘中将丰盛的份量盛在煮熟的新土豆（或黄油鸡蛋面）上，配上酥脆的法棍以擦拭酱汁，撒上切碎的新鲜欧芹、第二天总是更好——风味在一夜之间结合、喝一瓶你用来烹饪的同样的勃艮第葡萄酒。","en":"Place 1.5 kg cubed beef in a non-reactive bowl with the 750 ml red Burgundy, 1 chopped onion, 1 chopped carrot, 4 garlic cloves, the bouquet garni and 1 tsp pepper, then cover and refrigerate for 12-24 hours; drain through a sieve while reserving the wine, and pat the beef very dry with paper towel so it sears rather than steams. In a heavy Dutch oven over medium heat, cook 200 g lardons for 6-8 minutes until crisp and golden and the fat is fully rendered, then lift them out with a slotted spoon and leave 2 tbsp of rendered fat behind in the pot. Raise the heat to high and add 1 tbsp olive oil plus 15 g butter, then sear the dried beef cubes in 3-4 uncrowded batches for 2-3 minutes per side (about 8 minutes per batch) until deeply browned on all sides; transfer each batch to a tray and leave the dark fond stuck to the pot as your flavour base. Reduce the heat to medium, add 250 g diced onion and 250 g carrot chunks and cook 5 minutes until starting to soften, then stir in 4 minced garlic cloves and 2 tbsp tomato paste and cook 1 minute; pour in 2 tbsp Cognac and ignite carefully (the flames die in 30 seconds), or skip the flambe and simply use the Cognac to deglaze. Sprinkle 3 tbsp flour over the vegetables and stir for 1 minute to cook out the raw taste, then pour in the reserved wine slowly while scraping the bottom to lift the fond, add 200 ml beef stock, the bouquet garni, 1.5 tsp salt and 1 tsp pepper, and return the beef and lardons to the pot so the liquid barely covers everything. Bring to a gentle simmer, cover with the lid slightly ajar and transfer to a 160 °C oven (or simmer on the lowest stovetop heat) for 2.5-3 hours, stirring every 45 minutes until the beef is fall-apart tender and the sauce has thickened to a glossy coats-the-spoon consistency; discard the bouquet garni. In a separate skillet, melt 15 g butter over medium heat, add 250 g peeled pearl onions with 1 tbsp water, 1 tsp sugar and a pinch of salt, cover and cook 15 minutes, then uncover and brown 5 minutes until glossy and golden; in the same skillet add another 15 g butter and 250 g mushrooms and saute 6-8 minutes in 2 batches until deeply golden brown, never crowding the pan. Fold the pearl onions and mushrooms into the braise and warm together 5 minutes, then taste and adjust the salt and let the braise rest 10 minutes off the heat so the flavours deepen; serve generous portions in deep plates over boiled new potatoes (or buttered egg noodles), scatter with chopped fresh flat-leaf parsley and offer crusty baguette to mop up the sauce -- it is always better the next day, and pairs perfectly with a bottle of the same Burgundy you cooked with."}},{"id":179,"servings":2,"tipType":"veg","pairingsType":"middle-eastern","origin":{"zh":"突尼斯","en":"Tunisia","ro":"Tunisia"},"name":{"zh":"突尼斯炒蛋","en":"Chakchouka","ro":"Chakchouka"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["4个常温的大鸡蛋","4汤匙特级初榨橄榄油（突尼斯或地中海）","1个中等黄洋葱（约150克），切细丁","2个温和的红甜椒（约300克），去籽并切成1厘米的方块","1个小红辣椒切碎或1茶匙突尼斯哈里萨酱（更传统的选择）","4瓣大蒜，切碎","1茶匙磨碎的孜然（kamoun）——温暖香料的基础","1茶匙磨碎的葛缕子（karwiya）——突尼斯标志性的温暖香料，尽管看起来相似但与孜然不同；如果没有，可用茴香籽代替","1茶匙甜红椒粉","0.5茶匙磨碎的香菜籽","400克罐装碎番茄（或4个去皮磨碎的成熟番茄）","1汤匙番茄酱以增加浓稠度","1茶匙盐+0.5茶匙现磨黑胡椒+一小撮糖以平衡酸度","60克菲达式奶酪（突尼斯或保加利亚式，捏碎，可选）+新鲜的平叶欧芹+香菜+柠檬角+新鲜的法式长棍面包或突尼斯khobz tabouna配餐"],"en":["4 large eggs at room temperature","4 tbsp extra-virgin olive oil (Tunisian or Mediterranean)","1 medium yellow onion (~150 g), finely diced","2 mild red bell peppers (~300 g), seeded and cut into 1 cm dice","1 small red chili finely chopped OR 1 tsp Tunisian harissa paste (the more traditional choice)","4 garlic cloves, minced","1 tsp ground cumin (kamoun) — the warm spice base","1 tsp ground caraway (karwiya) — Tunisia's DEFINING warm spice, NOT the same as cumin despite looking similar; substitute fennel seed if unavailable","1 tsp sweet paprika","0.5 tsp ground coriander","400 g can crushed tomatoes (or 4 ripe tomatoes peeled and grated)","1 tbsp tomato paste for body","1 tsp salt + 0.5 tsp freshly ground black pepper + a pinch of sugar to balance acidity","60 g feta-style cheese (Tunisian or Bulgarian-style, crumbled, optional) + fresh flat-leaf parsley + cilantro + lemon wedges + fresh baguette or Tunisian khobz tabouna to serve"],"ro":["4 ouă mari la temperatura camerei","4 linguri ulei de măsline extravirgin (tunisian sau mediteranean)","1 ceapă galbenă medie (~150 g), tăiată mărunt","2 ardei graşi roşii blânzi (~300 g), curăţaţi de seminţe şi tăiaţi în cuburi de 1 cm","1 ardei iute roşu mic tocat mărunt SAU 1 linguriţă pastă de harissa tunisiană (alegerea mai tradiţională)","4 căţei de usturoi, tocaţi mărunt","1 linguriţă chimion măcinat (kamoun) — baza de mirodenii calde","1 linguriţă chimen măcinat (karwiya) — mirodenia caldă DEFINITORIE a Tunisiei, NU acelaşi lucru cu chimionul deşi arată asemănător; înlocuieşte cu sămânţă de fenicul dacă nu este disponibil","1 linguriţă boia dulce","0.5 linguriţă coriandru măcinat","400 g roşii zdrobite la cutie (sau 4 roşii coapte decojite şi rase)","1 lingură pastă de roşii pentru corp","1 linguriţă sare + 0.5 linguriţă piper negru proaspăt măcinat + un vârf de zahăr pentru echilibrul acidităţii","60 g brânză tip feta (tunisiană sau bulgărească, sfărâmată, opţional) + pătrunjel proaspăt cu frunza lată + coriandru + felii de lămâie + baghetă proaspătă sau khobz tabouna tunisian pentru servire"]},"howIsMade":{"zh":"准备芳香食材：chakchouka烹饪很快——准备就绪是不容商量的、切丁150克洋葱+300克红甜椒+1个红辣椒、切碎4瓣大蒜、将四重香料——孜然+葛缕子+红椒粉+香菜籽——量入一个小碗中、葛缕子是使这道菜成为突尼斯而非以色列或黎凡特shakshuka的关键。加热油：在重24厘米煎锅（铸铁是理想的——陶土tagine是最传统的突尼斯选择）中以中火加热4汤匙橄榄油，直到闪闪发光。SOFFRITTO：加入150克切丁的洋葱和一小撮盐，煮6–8分钟，直到非常柔软和透明——不是棕色、突尼斯chakchouka想要慢慢出汗的洋葱的甜味，而不是焦糖化。甜椒+辣椒+大蒜：加入300克切丁的红甜椒+1个切碎的红辣椒（或1茶匙哈里萨）、煮6–8分钟，直到甜椒变软但仍鲜红、加入4瓣切碎的大蒜，煮1分钟直到芳香。让香料绽放：将香料混合物（1茶匙孜然+1茶匙葛缕子+1茶匙红椒粉+0.5茶匙香菜籽）直接加入热的油和蔬菜底料中、搅拌30秒直到强烈芳香——不要烧焦，否则菜会变苦。制作酱汁：搅入1汤匙番茄酱并煮1分钟、倒入400克碎番茄+1茶匙盐+0.5茶匙胡椒+一小撮糖、慢炖8–10分钟，偶尔搅拌，直到酱汁变稠——用勺子在表面拖动应留下一条清晰的痕迹，不会立即填回。加入鸡蛋：用勺子背面在慢炖的酱汁中做4个井、在每个井中打入1个鸡蛋——保持蛋黄完整、在蛋白上撒一小撮盐，在蛋黄上转一下胡椒、盖上锅盖，用中低火煮4–6分钟，直到蛋白刚刚凝固但蛋黄仍然流动——透过盖子查看；蛋白应该不透明，蛋黄仍然鲜橙色并颤动。完成并上菜：在顶部撒上60克碎菲达奶酪+一大把切碎的欧芹和香菜、直接将平底锅端到桌上——chakchouka总是共同分享的，从平底锅里吃、每个用餐者撕下一块新鲜的法棍或khobz tabouna，用它来蘸取酱汁并打破蛋黄、在自己的份上挤一片柠檬、烹饪后10分钟内最佳，此时蛋黄仍然熔融。","en":"PREP THE AROMATICS: chakchouka cooks fast — mise-en-place is non-negotiable; dice 150 g onion + 300 g red bell peppers + 1 red chili; mince 4 garlic; measure the spice quartet — cumin + caraway + paprika + coriander — into a small bowl; the caraway is what makes this Tunisian and not Israeli or Levantine shakshuka. WARM THE OIL: heat 4 tbsp olive oil in a heavy 24 cm skillet (cast iron is ideal — earthenware tagine is the most traditional Tunisian) over medium heat until shimmering. SOFFRITTO: add 150 g diced onion with a pinch of salt and cook 6–8 min until very soft and translucent — NOT browned; tunisian chakchouka wants the sweetness of slowly-sweated onions, not caramelization. PEPPERS + CHILI + GARLIC: add 300 g diced red bell peppers + 1 chopped red chili (or 1 tsp harissa); cook 6–8 min until peppers are softened but still bright red; add 4 minced garlic and cook 1 min until fragrant. BLOOM THE SPICES: add the spice mix (1 tsp cumin + 1 tsp caraway + 1 tsp paprika + 0.5 tsp coriander) directly into the hot oil-and-vegetable base; stir 30 seconds until intensely aromatic — do not burn, or the dish turns bitter. BUILD THE SAUCE: stir in 1 tbsp tomato paste and cook 1 min; pour in 400 g crushed tomatoes + 1 tsp salt + 0.5 tsp pepper + a pinch of sugar; simmer 8–10 min, stirring occasionally, until the sauce has thickened — a spoon dragged through the surface should leave a clear trail that does not immediately fill back in. ADD EGGS: with the back of a spoon, make 4 wells in the simmering sauce; crack 1 egg into each well — keep yolks intact; sprinkle a pinch of salt over the whites and a twist of pepper over the yolks; cover the skillet with a lid and cook over medium-low heat 4–6 min, until the whites are just set but the yolks remain runny — peek through the lid; the whites should be opaque and the yolks still bright orange and trembling. FINISH AND SERVE: scatter 60 g crumbled feta + a generous handful of chopped parsley and cilantro over the top; bring the pan straight to the table — chakchouka is always communal, eaten from the skillet; each diner tears off a piece of fresh baguette or khobz tabouna and uses it to mop up the sauce and break into a yolk; squeeze a lemon wedge over your own portion; best within 10 minutes of cooking, while the yolks are still molten."}},{"id":180,"origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"御好烧","en":"Okonomiyaki","ro":"Okonomiyaki"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"zh":["普通面粉（或低筋面粉）200克","冷鲣鱼汤（或水加鲣鱼粉1小勺）240毫升","大鸡蛋2个","白卷心菜400克，细丝切","五花肉薄片（猪腹肉）200克，切5厘米段","天妇罗碎（tenkasu）2大勺（可选）","泡打粉½小勺","日本蛋黄酱（丘比Kewpie）4大勺","御好烧酱（如Otafuku品牌）4大勺","伍斯特酱1小勺","鲣鱼花（柴鱼片）适量，装盘用","青海苔粉适量，装盘用"],"en":["200g plain flour (or cake flour)","240ml cold dashi stock (or water + 1 tsp dashi powder)","2 large eggs","400g white cabbage, finely shredded","200g thinly sliced pork belly (buta bara), cut into 5 cm pieces","2 tbsp tenkasu (tempura scraps, optional)","½ tsp baking powder","4 tbsp Japanese mayonnaise (Kewpie)","4 tbsp okonomiyaki sauce (e.g. Otafuku brand)","1 tsp Worcestershire sauce","katsuobushi (dried bonito flakes) to serve","aonori (powdered seaweed) to serve"],"ro":["200g făină albă simplă (sau făină pentru prăjituri)","240ml supă dashi (rece; sau apă + 1 linguriță pudră dashi)","2 ouă mari","400g varză albă, tăiată fin","200g burta de porc feliată subțire (buta bara), tăiată în bucăți de 5 cm","2 linguri tenkasu (firimituri de tempura, opțional)","½ linguriță praf de copt","4 linguri maioneză Kewpie (japoneză)","4 linguri sos okonomiyaki (ex. Otafuku)","1 linguriță sos Worcestershire","katsuobushi (fulgi de ton uscat), pentru servire","aonori (alge marine pudră), pentru servire"]},"howIsMade":{"zh":"大碗中将面粉、泡打粉、鸡蛋和冷高汤搅拌至刚好混合——不要过度搅拌。用铲子轻轻拌入卷心菜丝和天妇罗碎；面糊应该浓厚。中火加热不粘锅，薄涂一层油。倒入面糊摊成约2厘米厚的圆饼。将五花肉片铺满整个表面。中小火煎5–6分钟，直到边缘凝固、底部金黄。用两个铲子小心翻面，轻轻按压；再煎5–6分钟至猪肉酥脆、面饼熟透。在猪肉面刷御好烧酱，用丘比蛋黄酱画之字纹，撒柴鱼花和青海苔粉。立刻上桌。","en":"In a large bowl whisk together flour, baking powder, eggs, and cold dashi until just combined — do not overmix. Fold in shredded cabbage and tenkasu with a spatula; the batter should be thick and mounded with cabbage. Heat a non-stick pan over medium heat, brush with a thin layer of oil. Pour batter into the pan and shape into a disc about 2 cm thick. Lay pork belly slices over the entire top surface. Cook 5–6 minutes on medium-low until the edges look set and the underside is golden-brown. Flip carefully using two spatulas, pressing lightly; cook another 5–6 minutes until pork is crisp and batter is cooked through. Brush the pork side with okonomiyaki sauce, drizzle Kewpie in a zigzag, scatter katsuobushi and aonori. Serve immediately from the pan."}},{"id":181,"servings":2,"tipType":"meat","timeMins":{"total":780,"active":120},"pairingsType":"japanese","origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"猪骨拉面","en":"Tonkotsu Ramen","ro":"Ramen Tonkotsu"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["猪脊髓骨1.2千克，焯水","新鲜细拉面300克","深色酱油3大勺（做底汤调料）","味醂2大勺","叉烧猪腩200克，切1厘米厚片","溏心拉面蛋2个，对半切开","竹笋（孟宗笋）80克，沥干","海苔2片，对半切","葱2根，切薄圆片","大蒜4瓣，压碎","新鲜生姜30克，去皮切片","烤芝麻油1小勺"],"en":["1.2kg pork marrow bones, blanched","300g fresh thin ramen noodles","3 tbsp dark soy sauce (for tare)","2 tbsp mirin","200g chashu pork belly, sliced 1cm thick","2 soft-boiled ramen eggs, halved","80g bamboo shoots (menma), drained","2 sheets nori, halved","2 spring onions, thinly sliced","4 cloves garlic, crushed","30g fresh ginger, peeled and sliced","1 tsp toasted sesame oil"],"ro":["1,2 kg oase de porc (măduvă), opărite","300g tăiței ramen proaspeți subțiri","3 linguri sos de soia închis (pentru tare)","2 linguri mirin","200g burtă de porc chashu, feliată la 1 cm grosime","2 ouă ramen fierte moale, tăiate în jumătate","80g lăstari de bambus (menma), scurși","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate subțire","4 căței usturoi, zdrobiți","30g ghimbir proaspăt, curățat și feliat","1 linguriță ulei de susan prăjit"]},"howIsMade":{"zh":"猪骨放入沸水中焯10分钟，捞出冷水冲洗。转入大锅加3升冷水，大火烧开后保持沸腾状态10至12小时，不足时加水；持续大火沸腾能分解胶原蛋白使汤汁变白。五花肉紧卷捆好，干锅煎至四面上色，然后加3大勺酱油、2大勺味醂、1大勺清酒和100毫升水，最小火焖90分钟；静置20分钟后切成1厘米厚片。调底汤：酱油4大勺加味醂2大勺，小火煮3分钟晾凉。面条按袋装指示煮熟沥干。每碗放2大勺底汤，加入400毫升热汤，然后排上叉烧片、对半切蛋、笋干、海苔、葱花，淋几滴芝麻油。","en":"Blanch pork bones in boiling water for 10 minutes, drain and rinse under cold water. Transfer to a large pot with 3L cold water, bring to a rolling boil and hold it there — not a simmer — for 10 to 12 hours, topping up with water as needed; the hard boil breaks down collagen and turns the broth white. Roll pork belly tightly, tie with kitchen string, sear all sides in a dry pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on the lowest heat for 90 minutes; rest 20 minutes, slice 1cm thick. Make tare: 4 tbsp soy sauce + 2 tbsp mirin, simmer 3 minutes, cool. Cook noodles per packet, drain. Spoon 2 tbsp tare into each bowl, ladle 400ml hot broth, then top with chashu slices, halved egg, bamboo shoots, nori and spring onion. Finish with sesame oil."}},{"id":182,"servings":2,"tipType":"meat","timeMins":{"total":360,"active":90},"pairingsType":"japanese","origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"酱油拉面","en":"Shoyu Ramen","ro":"Ramen Shoyu"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["鸡骨高汤1.5升","酱油2大勺","味醂1大勺","清酒1大勺","猪五花肉400克，卷起并用棉线捆好","大鸡蛋4个","新鲜拉面条300克","笋干（孟宗笋）100克，冲洗","海苔4片","葱3根，切薄圆片","鸣门卷鱼饼4片","芝麻油1小勺"],"en":["1.5L chicken bone stock","2 tbsp soy sauce","1 tbsp mirin","1 tbsp sake","400g pork belly, rolled and tied with kitchen string","4 large eggs","300g fresh ramen noodles","100g bamboo shoots (menma), rinsed","4 sheets nori","3 spring onions, thinly sliced","4 slices narutomaki fish cake","1 tsp sesame oil"],"ro":["1,5 L supă de oase de pui","2 linguri sos de soia","1 lingură mirin","1 lingură sake","300g burtă de porc, rulată și legată","4 ouă mari","300g tăiței ramen proaspeți","100g lăstari de bambus (menma), clătiți","4 foi alge nori","3 cepe verzi, feliate subțire","4 felii pastă de pește narutomaki","1 linguriță ulei de susan"]},"howIsMade":{"zh":"鸡骨高汤加一块5厘米生姜、3瓣大蒜和2根葱熬煮3–4小时，过滤去渣。酱油、味醂和清酒在小锅中小火煮5分钟蒸发酒精——这就是酱油底汤（tare）。猪五花肉紧卷绑好，全面煎至上色，再加酱油3大勺、味醂2大勺、清酒1大勺和100毫升水，小火炖1.5小时；切片前静置15分钟。鸡蛋精确煮6.5分钟，冷水冷却剥壳，浸泡在剩余叉烧汁中至少4小时。面条按袋装说明煮熟沥干；热汤倒入碗中（每碗加2大勺tare），放入面条，依次摆上叉烧片、对切溏心蛋、笋干、海苔、葱花、鸣门卷，淋少许芝麻油。","en":"Simmer chicken bone stock with a 5cm piece of ginger, 3 garlic cloves and 2 spring onions for 3–4 hours, strain and discard solids. Mix soy sauce, mirin and sake in a small pan, simmer 5 minutes to cook off the alcohol — this is the shoyu tare. Roll pork belly tightly, tie with kitchen string, sear on all sides in a hot pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on low heat for 1.5 hours; rest 15 minutes before slicing into 1cm rounds. Soft-boil eggs exactly 6.5 minutes, cool in cold water, peel and submerge in the remaining chashu braising liquid for at least 4 hours. Cook noodles per packet, drain; ladle hot broth into bowls (2 tbsp shoyu tare per bowl), add noodles and top with sliced chashu, halved egg, bamboo shoots, nori, spring onions, narutomaki and a drizzle of sesame oil."}},{"id":183,"servings":2,"tipType":"def","pairingsType":"japanese","origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"味噌拉面","en":"Miso Ramen","ro":"Ramen Miso"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["鸡骨或猪骨高汤1.5升","红味噌或白味噌酱3大勺","新鲜拉面条300克","猪肉末150克","罐装玉米粒80克，沥干","无盐黄油1大勺","笋干60克，沥干切片","溏心腌制拉面蛋2个，对半切","海苔2片，对半切","葱2根，切圆片","烤芝麻1小勺","新鲜豆芽80克，焯水"],"en":["1.5L chicken or pork bone broth","3 tbsp red or white miso paste","300g fresh ramen noodles","150g ground pork","80g canned corn kernels, drained","1 tbsp unsalted butter","60g bamboo shoots, drained and sliced","2 soft-boiled ramen eggs, halved","2 sheets nori, halved","2 spring onions, sliced","1 tsp toasted sesame seeds","80g fresh bean sprouts, blanched"],"ro":["1,5L supă de oase de pui sau porc","3 linguri pastă miso roșu sau alb","300g tăiței ramen proaspeți","150g carne tocată de porc","80g porumb din conservă, scurs","1 lingură unt nesărat","60g lăstari de bambus, scurși și feliați","2 ouă fierte moale, marinate, tăiate în jumătate","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate","1 linguriță semințe de susan prăjit","80g muguri de fasole proaspeți, opăriți"]},"howIsMade":{"zh":"大火热锅，炒香蒜末和猪肉末，边炒边拨散，直至猪肉不再有粉红色。加入味噌酱翻炒60秒至颜色略深。倒入热汤，调至小火微沸——加入味噌后不可大火沸腾，否则发酵香气流失。加入黄油搅拌至融化。另锅煮面，沥干。将面条分入两碗，舀味噌汤汁浇上。摆上玉米、豆芽、腌制溏心蛋、笋干、海苔和葱花。最后撒芝麻。","en":"Sauté garlic and ground pork in a wok over high heat, breaking up the meat as it cooks, until no pink remains. Add miso paste and stir-fry 60 seconds until it darkens slightly. Pour in hot broth and bring to a low simmer — do not boil hard once miso is in or it loses its fermented edge. Add butter and stir until melted. Cook noodles per packet, drain. Divide noodles between two bowls, ladle miso broth over. Top with corn, bean sprouts, halved ramen egg, bamboo shoots, nori and spring onion. Scatter sesame seeds last."}},{"id":184,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":480,"prot":22,"carb":38,"fat":26,"fib":3},"origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"天妇罗","en":"Tempura","ro":"Tempura"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["400 克大虾（8–12 只带头，去壳留尾），去虾线后彻底擦干","1 个小日本红薯（约 200 克），削皮切 5 毫米厚圆片","200 克日本南瓜（kabocha），切 5 毫米半月形（带皮）","1 根日本茄子，斜切成 1 厘米厚片","6 朵新鲜香菇，去蒂，菇盖划十字花刀","100 克狮子椒或细长青椒，每只用叉子戳孔防爆裂","面糊（最后才调，下锅前才做）：1 个大鸡蛋、250 毫升冰镇气泡水、150 克过筛低筋面粉","30 克备用面粉，用于下锅前给食材薄薄拍粉","1.5 升中性油用于深炸（米糠油或植物油）","天妇罗蘸汁：200 毫升日式高汤、60 毫升酱油、60 毫升味淋","30 克白萝卜，细磨后稍微挤去汁水","10 克新鲜生姜，磨成细泥","细海盐和柠檬角，搭配食用"],"en":["400 g large prawns (8–12 head-on, peeled but tails on), deveined and patted bone-dry","1 small Japanese sweet potato (~200 g), peeled and cut into 5 mm rounds","200 g kabocha squash, cut into 5 mm half-moons (skin left on)","1 Japanese eggplant, cut on the bias into 1 cm slices","6 fresh shiitake mushrooms, stems trimmed, caps scored with an X","100 g shishito or thin green peppers, each pricked with a fork so they don't burst","For the batter (mix LAST, just before frying): 1 large egg, 250 ml ice-cold sparkling water, 150 g plain (cake) flour, sifted","30 g extra plain flour for dusting the pieces before dipping","1.5 L neutral oil for deep-frying (rice bran or vegetable)","For the tentsuyu dipping sauce: 200 ml dashi, 60 ml soy sauce, 60 ml mirin","30 g daikon, finely grated and lightly squeezed","10 g fresh ginger, finely grated","Fine sea salt and lemon wedges, to serve"],"ro":["400 g creveți mari (8–12 bucăți cu cap, decojiți dar cu coadă), curățați de vinișor și șterși bine de umiditate","1 cartof dulce japonez mic (~200 g), curățat și tăiat rondele de 5 mm","200 g dovleac kabocha, tăiat semilune de 5 mm (cu coajă)","1 vânătă japoneză, tăiată oblic în felii de 1 cm","6 ciuperci shiitake proaspete, fără picioare, capul crestat în X","100 g ardei shishito sau ardei verzi subțiri, fiecare înțepat cu furculița ca să nu plesnească","Pentru aluat (se amestecă LA FINAL, chiar înainte de prăjit): 1 ou mare, 250 ml apă minerală foarte rece, 150 g făină simplă cernută","30 g făină simplă suplimentară pentru pudrat bucățile înainte de înmuierea în aluat","1.5 L ulei neutru pentru prăjit (de orez sau vegetal)","Pentru sosul tentsuyu: 200 ml dashi, 60 ml sos de soia, 60 ml mirin","30 g daikon, ras fin și stors ușor","10 g ghimbir proaspăt, ras fin","Sare fină de mare și felii de lămâie, pentru servit"]},"howIsMade":{"zh":"把虾和蔬菜彻底擦干，再在每只虾的腹部斜划三刀，沿背脊轻轻按压，让它下锅后保持直挺而不卷曲。\n\n调天妇罗汁时，把日式高汤、酱油和味淋短暂煮沸让酒精挥发，分入小碟，磨好的萝卜泥和姜泥另放在旁边。\n\n在厚锅中将油加热至175°C，用探针温度计测量。\n\n下锅前才调面糊：在冰过的碗里把鸡蛋与冰镇气泡水拌匀，一次性倒入过筛的面粉，仅搅拌五到八下——面糊里应仍能看见干粉的痕迹。\n\n每件食材在备用面粉里轻轻一蘸，再裹上面糊，每次下油四到五件；虾和香菇约90秒，茄子和南瓜2分钟，红薯3分钟，狮子椒约1分钟，外壳应保持淡象牙色。\n\n捞起放在垫了纸的网架上，立刻上桌，搭配拌入萝卜泥和姜泥的天妇罗汁，或在蔬菜上撒一点细盐和挤几滴柠檬汁。","en":"Pat the prawns and vegetables completely dry, then make three shallow cuts on the underside of each prawn and press gently along the spine so they fry straight rather than curling.\n\nFor the tentsuyu, bring the dashi, soy sauce and mirin briefly to a simmer to cook off the alcohol, then divide between small dipping bowls and set the grated daikon and ginger alongside.\n\nHeat the oil in a heavy pot to 175°C, measured with a probe thermometer.\n\nJust before frying, beat the egg into the ice-cold sparkling water in a chilled bowl, tip in the sifted flour all at once and stir only five to eight strokes — the batter should still show streaks of dry flour.\n\nDust each piece lightly with the extra flour, dip into the batter, and slip into the oil four or five at a time; prawns and shiitake take about 90 seconds, eggplant and kabocha 2 minutes, sweet potato 3 minutes, shishito a minute, and the crust should stay pale ivory.\n\nLift onto a wire rack set over paper and serve straight away, with the tentsuyu, daikon and ginger to stir in, or the vegetables with a pinch of fine salt and a squeeze of lemon."}},{"id":185,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":280,"prot":7,"carb":52,"fat":4,"fib":2},"origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"饭团","en":"Onigiri","ro":"Onigiri"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["500 克日本短粒米（越光米或寿司米）","600 毫升新鲜冷水煮饭（米水比约1:1.1）","手粉水（tezu）：200 毫升温水 + 1.5 茶匙细海盐","4 张烤海苔，切成约 3 厘米宽 × 海苔长度的长条","馅料选项 1 — 金枪鱼蛋黄酱：80 克沥干金枪鱼罐头、1.5 大勺日式蛋黄酱、½ 茶匙酱油","馅料选项 2 — 梅干（umeboshi）：60 克去核盐渍梅干，用叉子轻轻压碎","馅料选项 3 — 盐烤鲑鱼（shiozake）：100 克烤熟鲑鱼片，去皮，撕成碎片","馅料选项 4 — okaka：8 克柴鱼花拌 1 茶匙酱油","无馅原味饭团：2 大勺furikake（饭料）裹在外层","可选：表面撒几粒芝麻"],"en":["500 g Japanese short-grain rice (Koshihikari or sushi rice)","600 ml fresh cold water for cooking (rice to water ratio ~1:1.1)","For the tezu (finger water): 200 ml warm water + 1.5 tsp fine sea salt","4 sheets toasted nori, cut into strips about 3 cm wide × the length of the sheet","Filling option 1 — tuna mayo: 80 g canned tuna (drained), 1.5 tbsp Japanese mayonnaise, ½ tsp soy sauce","Filling option 2 — umeboshi: 60 g pitted salted plums, lightly mashed with a fork","Filling option 3 — shiozake (grilled salted salmon): 100 g salmon fillet grilled and flaked, with the skin removed","Filling option 4 — okaka: 8 g bonito flakes mixed with 1 tsp soy sauce","For plain onigiri: 2 tbsp furikake (rice seasoning), to coat the outside","Optional: a few sesame seeds for the surface of plain ones"],"ro":["500 g orez japonez cu bobul scurt (Koshihikari sau orez pentru sushi)","600 ml apă rece proaspătă pentru fiert (raport orez:apă ~1:1.1)","Pentru tezu (apa de mâini): 200 ml apă caldă + 1.5 linguriță sare fină de mare","4 foi de nori prăjit, tăiate fâșii de ~3 cm lățime × lungimea foii","Umplutură opțiunea 1 — ton cu maioneză: 80 g ton la conservă (scurs), 1.5 lingură maioneză japoneză, ½ linguriță sos de soia","Umplutură opțiunea 2 — umeboshi: 60 g prune sărate fără sâmburi, ușor strivite cu furculița","Umplutură opțiunea 3 — shiozake (somon sărat la grătar): 100 g file de somon făcut la grătar, fără piele, fărâmițat","Umplutură opțiunea 4 — okaka: 8 g fulgi de bonito amestecați cu 1 linguriță sos de soia","Pentru onigiri simplu: 2 linguri furikake (condiment pentru orez), pentru exterior","Opțional: câteva semințe de susan pentru exterior"]},"howIsMade":{"zh":"把米在冷水里淘洗四到五次直到水近乎清澈，在筛网里沥水20分钟，再用600毫升新鲜水放进厚锅或电饭煲煮熟，煮好后离火盖盖再焖10分钟。\n\n米饭闷的时候，把梅干用叉子压碎，把金枪鱼和日式蛋黄酱拌成奶油状，把烤鲑鱼撕成小块——每个饭团只需要大约一汤匙馅料。\n\n把盐溶进温水里调成手粉水（tezu），它能让米饭不粘手，并在外皮留下一层淡淡的咸味。\n\n把热米饭倒在宽托盘上，用木饭勺轻轻翻松，等到刚好不烫手时再开始捏。\n\n手掌沾湿手粉水，取大约100克米饭在掌心，中间按出一个小坑，放进一汤匙馅料并把米饭包拢；手掌弯起，按成三个平面的三角形，紧实但别压实。\n\n要吃之前再在三角形底部围一条海苔，让海苔保持脆爽；没有馅料的原味饭团，外面裹一层furikake即可。常温下4小时内食用。","en":"Rinse the rice in cold water four or five times until the water runs almost clear, drain in a strainer for 20 minutes, then cook with the 600 ml of fresh water in a heavy pot or rice cooker; once cooked, rest off the heat with the lid on for 10 minutes.\n\nWhile the rice rests, mash the umeboshi with a fork, mix the tuna with the Japanese mayonnaise into a creamy paste, and flake the grilled salmon — each onigiri needs only about a tablespoon of filling.\n\nDissolve the salt in the warm water to make the tezu; this is the finger water that keeps the rice from sticking to your palms and lightly salts the outside.\n\nTip the hot rice onto a wide tray, fluff gently with a wooden paddle and let it cool until just warm enough to handle.\n\nWet your palms in the tezu, take about 100 g of rice in your palm, press a hollow in the centre, drop in a tablespoon of filling and gather the rice around it; cup your hand and press into a triangle with three flat faces, firm but not crushed.\n\nWrap a strip of nori around the base of each triangle just before eating so the seaweed stays crisp; for plain onigiri, roll the outside in furikake instead. Eat at room temperature within 4 hours."}},{"id":186,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":360,"prot":36,"carb":8,"fat":18,"fib":1},"origin":{"zh":"日本","en":"Japan","ro":"Japonia"},"name":{"zh":"日式烤鸡串","en":"Yakitori","ro":"Yakitori"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["去骨带皮鸡腿肉 600 克，切成 2.5 厘米方块","粗大葱 6 根（或 2 根 negi），白色和浅绿色部分切 3 厘米段（约 150 克）","短竹签 16 根（15 厘米），冷水浸泡 30 分钟","Tare 酱：120 毫升浓口酱油、120 毫升味淋、60 毫升清酒、30 克浅色红糖","细海盐，用于 shio 盐烤串","中性食用油 1 茶匙，用于烤架","七味唐辛子，搭配上桌","柠檬角，搭配上桌"],"en":["600 g boneless, skin-on chicken thighs, cut into 2.5 cm cubes","6 fat spring onions (or 2 negi), white and pale green parts cut into 3 cm pieces (~150 g total)","16 short bamboo skewers (15 cm), soaked in cold water for 30 minutes","For the tare: 120 ml dark soy sauce, 120 ml mirin, 60 ml sake, 30 g light brown sugar","Fine sea salt for the shio skewers","1 tsp neutral oil for the grate","Shichimi togarashi, to serve","Lemon wedges, to serve"],"ro":["600 g pulpe de pui dezosate cu piele, tăiate cuburi de 2.5 cm","6 cepe verzi mari (sau 2 negi), partea albă și verde-deschis tăiată bucățele de 3 cm (~150 g)","16 frigărui scurte de bambus (15 cm), înmuiate în apă rece 30 de minute","Pentru tare: 120 ml sos de soia închis, 120 ml mirin, 60 ml sake, 30 g zahăr brun deschis","Sare fină de mare pentru frigăruile shio","1 linguriță ulei neutru pentru grătar","Shichimi togarashi, pentru servit","Felii de lămâie, pentru servit"]},"howIsMade":{"zh":"把鸡腿肉切成 2.5 厘米方块，大葱的白色部分切成 3 厘米段，再把竹签放进冷水里浸泡 30 分钟，以免烧焦。\n\n做 tare 酱：把酱油、味淋、清酒和红糖放进小锅，小火煮约 10 分钟到略带浓稠的糖浆感，然后放凉至室温。\n\n串两种风格：negima 是鸡-葱-鸡-葱-鸡交替排列；momo 则全是鸡块，紧贴但不压扁。\n\n用大火加热炭火烤架或厚底烤盘，在烤架上薄薄刷一层油。\n\n带皮或带脂的一面朝下，烤 3–4 分钟至深金色，再翻面烤 2–3 分钟。\n\ntare 串先蘸一下凉酱，放回烤架 30 秒上釉，再蘸再烤一次；shio 串离火后撒一小撮细盐即可。立刻搭配七味唐辛子和柠檬上桌。","en":"Cut the chicken thigh into 2.5 cm cubes and the white parts of the spring onions into 3 cm pieces, then soak the bamboo skewers in cold water for 30 minutes so they don't burn on the grill.\n\nFor the tare, simmer the soy sauce, mirin, sake and brown sugar in a small pan for about 10 minutes until lightly syrupy, then let it cool to room temperature.\n\nThread the skewers in two styles: negima alternates chicken, scallion, chicken, scallion, chicken; momo is just chicken cubes packed close together but not squashed.\n\nHeat a charcoal grill or a heavy grill pan over high heat and lightly oil the grate.\n\nLay the skewers down with the skin or fattiest side first and grill for 3–4 minutes until deep golden, then flip and cook another 2–3 minutes.\n\nFor tare skewers, dip in the cooled sauce, return to the grill for 30 seconds to glaze, then dip and glaze once more; season the shio skewers with a pinch of salt straight off the heat. Serve at once with shichimi togarashi and lemon."}},{"id":187,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":520,"prot":38,"carb":22,"fat":28,"fib":6},"origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"波布拉诺莫蕾酱","en":"Mole Poblano","ro":"Mole Poblano"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["80 克混合干辣椒——3 个安丘 + 3 个穆拉托 + 2 个帕西利亚——去蒂去籽","阿斗波酱腌的奇波雷辣椒 1 个，外加 1 汤匙的酱汁","去皮杏仁 100 克，生花生 80 克","生白芝麻 30 克（另留少许装饰），葡萄干 60 克","成熟大番茄 2 个，切两半；白洋葱 1 小颗，切四瓣；带皮蒜瓣 3 颗","肉桂棒 1 根、丁香 2 粒、八角 1 颗、黑胡椒粒 6 粒","玉米饼 2 张，撕成小块——传统增稠剂","墨西哥巧克力 60 克，掰碎（或黑巧克力 50 克 + 1 茶匙肉桂 + 1 汤匙浅色红糖）","无盐鸡汤 1.2 升，保持温热","猪油（manteca）3 汤匙或中性食用油","带骨鸡腿 4 块，在加盐的水中煮 25 分钟后吸干水分","细海盐 1 茶匙，少许糖","搭配上桌：煮好的白米饭、温热的玉米饼、新鲜香菜叶"],"en":["80 g mixed dried chiles — 3 ancho + 3 mulato + 2 pasilla — stemmed and seeded","1 chipotle chile in adobo, plus 1 tbsp of its sauce","100 g blanched almonds and 80 g raw peanuts","30 g raw sesame seeds (plus extra to garnish) and 60 g raisins","2 large ripe tomatoes, halved; 1 small white onion, quartered; 3 garlic cloves, unpeeled","1 cinnamon stick, 2 cloves, 1 star anise and 6 black peppercorns","2 corn tortillas, torn into pieces — the traditional thickener","60 g Mexican chocolate, broken up (or 50 g dark chocolate + 1 tsp cinnamon + 1 tbsp light brown sugar)","1.2 L unsalted chicken stock, kept warm","3 tbsp lard (manteca) or neutral oil","4 bone-in chicken thighs, poached in salted water for 25 minutes and patted dry","1 tsp fine sea salt and a small pinch of sugar","To serve: cooked white rice, warm corn tortillas, fresh coriander leaves"],"ro":["80 g de ardei iuți uscați amestecați — 3 ancho + 3 mulato + 2 pasilla — fără codiță și seminţe","1 ardei chipotle în sos adobo, plus 1 lingură din sosul lui","100 g de migdale blanşate și 80 g de arahide crude","30 g de seminţe de susan crude (plus în plus pentru garnitură) și 60 g de stafide","2 roșii mari coapte, tăiate jumătăți; 1 ceapă albă mică, tăiată sferturi; 3 căţei de usturoi, necurăţaţi","1 baton de scorţișoară, 2 cuișoare, 1 stea de anason și 6 boabe de piper negru","2 tortilla de porumb, rupte în bucăţi — îngroșătorul tradiţional","60 g de ciocolată mexicană, fărâmiţată (sau 50 g de ciocolată neagră + 1 linguriţă de scorţișoară + 1 lingură de zahăr brun deschis)","1.2 L de supă de pui nesărată, ţinută caldă","3 linguri de untură (manteca) sau ulei neutru","4 pulpe de pui cu os, fierte în apă sărată 25 de minute și șterse","1 linguriţă de sare fină de mare și un vârf mic de zahăr","Pentru servit: orez alb fiert, tortilla de porumb calde, frunze de coriandru proaspăt"]},"howIsMade":{"zh":"把干辣椒放进干燥厚锅，中火每面约烤 30 秒至香气出来，倒进碗里用热水淹过，浸泡 20 分钟。\n\n同一只锅里，分小批把杏仁、花生、芝麻、葡萄干和整香料各自烤到刚刚变金黄——每批约 2 分钟——取出备用。\n\n直接将番茄、洋葱和带皮蒜放在明火上或热烤架下烤至局部焦黑，蒜稍凉后去皮。\n\n沥干辣椒（保留浸泡水），与烤过的蔬菜、奇波雷及其酱汁、烤过的坚果与种子、葡萄干、香料和撕碎的玉米饼一起放入搅拌机，加约 500 毫升温热鸡汤，打成顺滑的深色酱糊。\n\n将猪油放入厚锅中以中大火加热，倒入酱糊，持续搅拌 10–15 分钟；mole 会逐渐变深、变稠、变得发亮，香气与油脂炒在一起。\n\n再加入剩下的 700 毫升鸡汤和掰碎的巧克力，小火慢炖 30–40 分钟，期间常搅拌，直到酱汁能挂在勺背上；用盐和一小撮糖调味。\n\n把焯过的鸡腿放入 mole 中，再炖 10 分钟，让鸡肉吸味。\n\n把鸡块盛入深盘，淋上大量 mole，最后撒上预留的芝麻和香菜叶，搭配白米饭和温热的玉米饼上桌。","en":"Toast the dried chiles in a dry heavy pan over medium heat for about 30 seconds per side until fragrant, then transfer to a bowl, cover with hot water and soak for 20 minutes.\n\nIn the same pan, toast the almonds, peanuts, sesame seeds, raisins and whole spices in small batches until just golden — about 2 minutes each — and set aside.\n\nChar the tomato halves, onion quarters and unpeeled garlic directly over a flame or under a hot broiler until blackened in patches, then peel the garlic once cool enough to handle.\n\nDrain the chiles (keeping the soaking water) and blend them with the charred vegetables, chipotle and its sauce, toasted nuts and seeds, raisins, spices and torn tortillas, adding about 500 ml of warm chicken stock to make a smooth dark paste.\n\nHeat the lard in a heavy pot over medium-high heat, pour in the paste and stir constantly for 10–15 minutes; the mole will darken, thicken and turn glossy as the flavours fry together.\n\nStir in the remaining 700 ml of chicken stock and the broken chocolate, then simmer gently for 30–40 minutes, stirring often, until the sauce coats the back of a spoon; season with the salt and a small pinch of sugar.\n\nSlide the poached chicken thighs into the mole and simmer 10 minutes more so they take on the sauce.\n\nServe the chicken in shallow bowls, ladle generous mole over the top, and finish with the reserved sesame seeds, coriander leaves, white rice and warm corn tortillas on the side."}},{"id":188,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":480,"prot":18,"carb":38,"fat":28,"fib":6},"origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"墨西哥烩玉米片","en":"Chilaquiles","ro":"Chilaquiles"},"category":{"zh":"早餐","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"zh":["200 克放隔夜的玉米饼，切成八小块（或现成 totopos 玉米脆片）","中性食用油 500 毫升用于深炸（或 4 汤匙用于浅煎）","做 salsa roja：6 个成熟番茄（约 600 克）、2 个瓜希约辣椒 + 1 个 chile de árbol（去蒂去籽）、1 瓣大蒜、½ 个小白洋葱","细海盐 1 茶匙，做酱用中性油 1 汤匙","大鸡蛋 4 个，单面煎成糖心荷包蛋（可选但经典）","墨西哥酸奶酱 100 毫升（或用牛奶稀释的酸奶油）","墨西哥鲜奶酪 80 克掰碎（或淡味菲达）","小红洋葱 ½ 个，切极薄圈","新鲜香菜一小把，只取叶","成熟牛油果 1 个，上桌前才切片","腌墨西哥辣椒（jalapeños），按口味添加"],"en":["200 g day-old corn tortillas, cut into eighths (or store-bought totopos)","500 ml neutral oil for frying (or 4 tbsp for shallow-frying)","For the salsa roja: 6 ripe tomatoes (~600 g), 2 guajillo chiles + 1 chile de árbol (stemmed and seeded), 1 garlic clove, ½ small white onion","1 tsp fine sea salt and 1 tbsp neutral oil for the salsa","4 large eggs, fried sunny-side-up (optional but classic)","100 ml Mexican crema (or sour cream thinned with milk)","80 g queso fresco, crumbled (or mild feta)","½ small red onion, very thinly sliced","A small handful of fresh coriander, leaves picked","1 ripe avocado, sliced just before serving","Pickled jalapeños, to taste"],"ro":["200 g tortilla de porumb de o zi, tăiate în opt (sau totopos cumpărate)","500 ml ulei neutru pentru prăjit (sau 4 linguri pentru prăjit superficial)","Pentru salsa roja: 6 roșii coapte (~600 g), 2 ardei guajillo + 1 ardei de árbol (fără codiță și semințe), 1 cățel de usturoi, ½ ceapă albă mică","1 linguriță sare fină de mare și 1 lingură ulei neutru pentru salsa","4 ouă mari, ochiuri (opțional dar tradițional)","100 ml crema mexicană (sau smântână subțiată cu lapte)","80 g queso fresco, sfărâmat (sau feta blândă)","½ ceapă roșie mică, tăiată felii foarte subțiri","Un mic mănunchi de coriandru proaspăt, doar frunzele","1 avocado copt, feliat chiar înainte de servit","Jalapeños murați, după gust"]},"howIsMade":{"zh":"把隔夜的玉米饼切成八小块，油温 175°C 炸至金黄酥脆（每批约 90 秒），或者用 4 汤匙油浅煎；趁热在网架上沥油并撒一点细盐。\n\n做酱：把瓜希约和 árbol 辣椒在干锅里每面烤 20 秒至出香，然后用热水浸泡 10 分钟；同时把番茄、大蒜和洋葱放在热烤架下或直接明火上烤至局部焦黑。\n\n沥干辣椒，与烤过的蔬菜、1 茶匙盐和少许浸泡水一起打成顺滑的酱汁。\n\n在宽锅里热 1 汤匙油，倒入酱汁，边煮边搅约 5 分钟，颜色加深、表面发亮即可。\n\n放入炸好的玉米片，中火轻轻翻拌 1–2 分钟——让它们吸收酱汁但保留一些脆度。\n\n立刻装盘，如使用则叠上荷包蛋，淋上酸奶酱，撒上墨西哥鲜奶酪、红洋葱圈、香菜、牛油果和腌墨西哥辣椒。","en":"Cut the day-old tortillas into eighths and either deep-fry them at 175°C until golden and crisp, about 90 seconds per batch, or shallow-fry in 4 tablespoons of oil; drain on a rack and salt lightly while still warm.\n\nFor the salsa, toast the guajillo and árbol chiles in a dry pan for 20 seconds per side until fragrant, then soak in hot water for 10 minutes; meanwhile, char the tomatoes, garlic and onion under a hot broiler or directly over a flame until blackened in patches.\n\nDrain the chiles and blend with the charred vegetables, 1 teaspoon of salt and a splash of the chile-soaking water until smooth.\n\nHeat 1 tablespoon of oil in a wide pan, pour in the salsa and simmer for about 5 minutes, stirring, until it deepens in colour and looks glossy.\n\nTip in the crisp tortillas and gently fold them through the salsa over medium heat for a minute or two — they should soak up sauce while keeping some bite.\n\nPlate at once, top with the fried eggs if using, drizzle with crema, and scatter queso fresco, sliced red onion, coriander, avocado and pickled jalapeños over the top."}},{"id":189,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":9,"carb":70,"fat":24,"fib":1},"origin":{"zh":"墨西哥","en":"Mexico","ro":"Mexic"},"name":{"zh":"三奶蛋糕","en":"Tres Leches Cake","ro":"Tort Tres Leches"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["大鸡蛋 5 个，分离蛋黄蛋白，置于室温","细砂糖 200 克，另加 30 克给奶油用","中筋面粉 200 克与泡打粉 1 茶匙，一同过筛","蛋糕用香草精 1 茶匙，奶油用 ½ 茶匙","加糖炼乳 1 罐（397 克）","淡奶 1 罐（340 克，evaporated milk）","全脂牛奶 200 毫升与淡奶油 50 毫升（三奶混合液）","冷藏淡奶油 250 毫升（打发用），另备肉桂粉撒面"],"en":["5 large eggs, separated, at room temperature","200 g caster sugar, plus 30 g for the whipped cream","200 g plain flour and 1 tsp baking powder, sifted together","1 tsp vanilla extract for the sponge, plus ½ tsp for the cream","1 can (397 g) sweetened condensed milk","1 can (340 g) evaporated milk","200 ml whole milk and 50 ml heavy cream (the three-milk soak)","250 ml cold heavy cream for whipping, plus ground cinnamon for dusting"],"ro":["5 ouă mari, separate, la temperatura camerei","200 g zahăr tos, plus 30 g pentru frișcă","200 g făină albă și 1 linguriță praf de copt, cernute împreună","1 linguriță esență de vanilie pentru blat, plus ½ linguriță pentru frișcă","1 cutie (397 g) lapte condensat îndulcit","1 cutie (340 g) lapte evaporat","200 ml lapte integral și 50 ml smântână pentru frișcă (amestec pentru îmbibare)","250 ml smântână rece pentru frișcă (35% grăsime), plus scorțișoară măcinată pentru pudrat"]},"howIsMade":{"zh":"烤箱预热至 175°C，把 23×33 厘米的烤盘抹油撒粉，然后蛋白加一小撮盐打至湿性发泡，分次加入 100 克糖继续打至光亮硬性发泡。\n\n蛋黄、剩余 100 克糖与香草精一起打 3–4 分钟至颜色变浅、体积膨大三倍，面粉和泡打粉过筛到蛋黄糊上用刮刀轻轻翻拌，再分三次加入蛋白霜，尽量保留空气。\n\n倒入烤盘抹平，烤 25–30 分钟至表面金黄、按压回弹，然后在烤盘中静置至少 30 分钟。\n\n把炼乳、淡奶以及全脂牛奶与淡奶油的混合液在量壶中搅匀，用细签把放凉的蛋糕从表面到底密密扎透，再把三奶液分三至四次缓慢淋满整个表面——液体看似太多，但海绵会全部喝进去；盖好冷藏至少 4 小时，最好一夜。\n\n临上桌前，把冷藏的淡奶油与 30 克糖、余下的香草精打至湿性发泡，抹在冷藏好的蛋糕上，再大方地撒一层肉桂粉。","en":"Heat the oven to 175°C and butter and flour a 23×33 cm baking dish, then whisk the whites with a pinch of salt to soft peaks, beating in 100 g of the sugar a spoonful at a time until glossy and stiff.\n\nWhip the yolks with the remaining 100 g sugar and the vanilla for 3–4 minutes until pale and tripled, sift the flour and baking powder over them and fold in gently, then fold in the meringue in three additions, keeping as much air as you can.\n\nPour into the dish, level the top and bake 25–30 minutes until deep golden and springy at the centre, then cool in the dish for at least 30 minutes.\n\nWhisk the three milks together in a jug, pierce the cooled cake all over to the base with a thin skewer and pour the mixture across the surface in three or four slow passes — it looks like too much liquid, but the sponge drinks every drop; cover and refrigerate at least 4 hours, ideally overnight.\n\nJust before serving, whip the cold cream with the 30 g sugar and the remaining vanilla to soft peaks, spread it over the chilled cake and dust generously with ground cinnamon."}},{"id":190,"servings":6,"tipType":"fish","pairingsType":"french","nutrition":{"cal":480,"prot":50,"carb":30,"fat":18,"fib":4},"origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"马赛鱼汤","en":"Bouillabaisse","ro":"Bouillabaisse"},"category":{"zh":"海鲜","en":"Fish","ro":"Pește"},"ingredients":{"zh":["800 克地中海小型岩礁鱼（红鲉、海龙、海鲬——用作汤底），已去内脏","1.2 公斤紧实的地中海食用鱼切块（红鲉、安康鱼、海鲂、海鳗、红鲂——至少四种），带皮去鳞","大洋葱 1 个、韭葱 2 根（只取白色部分）、茴香球 1 个、成熟番茄 4 个、大蒜 6 瓣","香料束：百里香、月桂叶、欧芹梗、一条干橙皮、1 茶匙茴香籽","藏红花 1 克（满满一撮），最后倒入 2 汤匙 pastis（Pernod 茴香酒）","橄榄油 100 毫升，盐 1 茶匙，现磨黑胡椒","水 2 升（或清淡鱼骨高汤）","12–15 片烤过的隔夜法棍，配 rouille 酱（蒜瓣 3 个、藏红花 ½ 茶匙、卡宴辣椒粉 ¼ 茶匙、蛋黄 1 个、橄榄油 200 毫升、盐、一小块在鱼汤里浸过的面包）"],"en":["800 g small Mediterranean rockfish (rascasse, weever, wrasse — for the broth), gutted","1.2 kg firm Mediterranean fish in chunks (rascasse, monkfish, John Dory, conger, gurnard — at least four species), skin on, scaled","1 large onion, 2 leeks (white parts only), 1 fennel bulb, 4 ripe tomatoes, 6 garlic cloves","Bouquet garni: thyme, bay, parsley stalks, a strip of dried orange peel, a teaspoon of fennel seeds","1 g saffron threads (a generous pinch), 2 tbsp pastis (Pernod) stirred in at the end","100 ml olive oil, 1 tsp salt, freshly ground pepper","2 L water (or light fish fumet)","12–15 slices of toasted day-old baguette and rouille (3 garlic cloves, ½ tsp saffron, ¼ tsp cayenne, 1 egg yolk, 200 ml olive oil, salt, a small piece of bread soaked in the broth)"],"ro":["800 g pești mici mediteraneeni de stâncă (rascassa, năsărel, vrana — pentru fond), eviscerați","1,2 kg pește mediteranean ferm tăiat bucăți (rascassa, lotă, Saint-Pierre, congru, grondin — minim patru specii), cu piele, scuamat","1 ceapă mare, 2 praz (doar partea albă), 1 bulb de fenicul, 4 roșii coapte, 6 căței de usturoi","Buchet garni: cimbru, foi de dafin, codițe de pătrunjel, coajă uscată de portocală, o linguriță de semințe de fenicul","1 g șofran (un vârf bun), 2 linguri de pastis (Pernod) adăugat la final","100 ml ulei de măsline, 1 linguriță sare, piper proaspăt măcinat","2 l apă (sau fumet uşor de pește)","12–15 felii de baghetă uscată prăjită și rouille (3 căței usturoi, ½ linguriță șofran, ¼ linguriță cayenne, 1 gălbenuș, 200 ml ulei de măsline, sare, o bucată de pâine înmuiată în fond)"]},"howIsMade":{"zh":"把所有鱼刮鳞、去内脏、冲洗——大鱼切成 3 厘米的块，鱼头和鱼骨留着熬汤底，小型岩礁鱼整尾下锅。\n\n在一只大而厚的锅中，中火加热 4 汤匙橄榄油，把洋葱、韭葱白和茴香炒约 10 分钟至软而不上色，再加切碎的番茄和 5 瓣大蒜煮 5 分钟至化为浓泥。\n\n把小鱼连同大鱼的头骨一起入锅，倒入 2 升水，加入香料束（百里香、月桂、欧芹、橙皮、茴香籽），大火滚煮 30–40 分钟直到小鱼完全散开，然后用粗筛或食物研磨器使劲压出所有汁水——骨头、香料和残渣弃掉——把过滤后的汤再次大火沸腾，调好咸度，撒入藏红花。\n\n先下质地紧实的鱼块（安康鱼、海鳗）煮 5–6 分钟，再下细嫩的鱼（红鲉、海鲂）煮 3–4 分钟——鱼肉刚刚变白即可，绝不能煮散——离火后倒入 pastis。\n\n做 rouille 酱：将剩下的那瓣蒜与盐、藏红花在臼里捣碎，加入泡过鱼汤并挤干的面包，再加蛋黄，最后细流注入橄榄油不停搅打直到稠如美乃滋，随后分两道上菜：先把鱼汤淋在烤过的法棍片上、顶一勺 rouille；然后鱼单独上一盘，附上多余的 rouille。","en":"Scale, gut and rinse all the fish — cut the larger ones into 3 cm chunks and keep the heads and bones for the broth, while the small rockfish go whole into the pot.\n\nIn a large heavy pot, heat 4 tablespoons of olive oil over medium heat and sweat the chopped onion, leeks and fennel without colour for about 10 minutes, then add the chopped tomatoes and 5 garlic cloves and cook another 5 minutes to a pulp.\n\nTip in the small fish and the heads and bones of the larger ones, cover with the 2 L of water, drop in the bouquet garni (thyme, bay, parsley, orange peel, fennel seeds) and simmer hard for 30–40 minutes until the small fish completely break down, then pass everything through a coarse sieve or food mill, pressing hard to extract every drop — bones, herbs and pulp discarded — bring the strained broth back to a rolling boil, taste for salt and stir in the saffron.\n\nSlip the firm fish (monkfish, conger) into the broth first and poach 5–6 minutes, then add the more delicate ones (rascasse, John Dory) for another 3–4 — they should be just opaque, never falling apart — and off the heat, swirl in the pastis.\n\nFor the rouille, pound the last garlic clove with the salt and saffron in a mortar, work in the bread (dipped in broth and squeezed), then the yolk, then olive oil in a thin stream, whisking constantly until thick like mayonnaise, then serve in two courses: the broth first, ladled over toasted baguette with a spoonful of rouille on top; the fish after, on a separate plate, with more rouille alongside."}},{"id":191,"servings":4,"tipType":"meat","pairingsType":"french","nutrition":{"cal":650,"prot":30,"carb":40,"fat":38,"fib":2},"origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"克罗克先生三明治","en":"Croque Monsieur","ro":"Croque Monsieur"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["8 片厚切 pain de mie（细腻软质方包），放置一夜","无盐黄油 80 克，软化，另加 30 克用于贝夏梅酱","格鲁耶尔（Gruyère）或孔泰（Comté）奶酪 200 克，细擦丝","巴黎火腿 4 片（共约 120 克）","第戎芥末 2 茶匙","中筋面粉 30 克与全脂牛奶 300 毫升（做贝夏梅酱）","细海盐、白胡椒、现擦肉豆蔻一抹"],"en":["8 thick slices of pain de mie (soft white sandwich bread), one day old","80 g unsalted butter, softened, plus 30 g for the béchamel","200 g Gruyère or Comté, finely grated","4 slices of jambon de Paris (~120 g total)","2 tsp Dijon mustard","30 g plain flour and 300 ml whole milk (for the béchamel)","Fine sea salt, white pepper, a grating of nutmeg"],"ro":["8 felii groase de pain de mie (pâine albă fină de sandviș), o zi vechi","80 g unt nesărat, înmuiat, plus 30 g pentru béchamel","200 g Gruyère sau Comté, ras fin","4 felii de jambon de Paris (~120 g în total)","2 lingurițe muștar Dijon","30 g făină albă și 300 ml lapte integral (pentru béchamel)","Sare fină, piper alb, un sfert de nucușoară rasă"]},"howIsMade":{"zh":"做贝夏梅酱：小锅中火融化 30 克黄油，加入面粉边搅边煮 1–2 分钟不让上色，然后少量多次注入温牛奶并用打蛋器不断搅拌，转小火继续煮 4–5 分钟、常搅拌，直到稠到能在勺背挂出一道尖——以盐、白胡椒、肉豆蔻调味，保温备用。\n\n烤箱上火（broiler）开到最高温预热，用软化的黄油在每片面包的两面都抹一层，再在每个三明治内层的一面薄薄涂上 Dijon 芥末。\n\n把抹好黄油的 4 片面包放在铺了烘焙纸的烤盘上，每片上铺一薄层格鲁耶尔丝（留出 ~60 克给最上层）、一片火腿，再铺一薄层奶酪，用剩下的 4 片面包合盖（芥末面朝内）轻轻按压。\n\n每个三明治上铺 2 满匙贝夏梅酱铺到边缘，让面包完全被覆盖、酱汁稍稍流到侧面，把留出的格鲁耶尔均匀撒在最上面，然后把烤盘放进上火下方 4–6 分钟、盯紧，直到贝夏梅酱沸腾并出现深褐色斑点、奶酪完全融化——面包底部因为已被黄油“抓住”而变得酥脆。\n\n取出来静置 30 秒——不然奶酪会黏手——然后斜切；做 croque madame 时，在三明治烤的时候用一点黄油单面煎一个鸡蛋，上桌前盖在每个三明治上面。","en":"Melt the 30 g béchamel butter in a small saucepan over medium heat, whisk in the flour and cook 1–2 minutes without colouring, then pour the warm milk in gradually while whisking constantly and simmer gently 4–5 minutes, stirring often, until thick enough to hold a peak on the spoon — season with salt, white pepper and nutmeg and keep warm.\n\nPreheat the broiler (top grill) to high, butter both sides of every bread slice with the softened butter, then thinly spread Dijon on the inner face of one slice per sandwich.\n\nLay 4 buttered slices on a lined tray, top each with a thin layer of grated Gruyère (hold ~60 g back for the top), a slice of ham and another thin layer of cheese, then close with the remaining 4 slices, mustard side in, and press lightly.\n\nSpoon 2 heaped tablespoons of béchamel over each sandwich right to the edges so the bread is fully covered and the sauce runs a little down the sides, scatter the reserved Gruyère on top and slide the tray under the hot broiler for 4–6 minutes, watching closely, until the béchamel is bubbling and deeply browned in patches and the cheese is molten — the bread crisps from below from the butter already gripped to its underside.\n\nLift out, rest 30 seconds — the cheese would stick to you otherwise — and cut on the diagonal; for a croque madame, fry an egg in a little butter while the sandwiches are under the broiler and slip it on top just before serving."}},{"id":192,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":420,"prot":13,"carb":60,"fat":14,"fib":1},"origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"法式可丽饼","en":"Crêpes","ro":"Crêpes"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["中筋面粉 250 克（T45 或 T55），过筛","大鸡蛋 4 个，置于室温","全脂牛奶 500 毫升（或牛奶 350 毫升 + 水 150 毫升，做更轻盈的可丽饼）","无盐黄油 50 克，融化至呈榛子色（beurre noisette，焦香黄油）","细砂糖 30 克与一撮细盐","深色朗姆酒或橙花水 1 汤匙（或香草精 1 茶匙）","煎锅润锅用的额外黄油（约 30 克，用刷子刷上）","搭配上桌：细砂糖、柠檬角，可选果酱、Nutella 或香蕉片"],"en":["250 g plain flour (T45 or T55), sifted","4 large eggs, at room temperature","500 ml whole milk (or 350 ml milk + 150 ml water for lighter crêpes)","50 g unsalted butter, melted until it browns to beurre noisette","30 g sugar and a good pinch of fine salt","1 tbsp dark rum or orange-flower water (or 1 tsp vanilla extract)","Extra butter for the pan (~30 g, kept on a brush)","To serve: caster sugar, lemon wedges, optionally jam, Nutella or sliced banana"],"ro":["250 g făină albă (T45 sau T55), cernută","4 ouă mari, la temperatura camerei","500 ml lapte integral (sau 350 ml lapte + 150 ml apă pentru crêpes mai ușoare)","50 g unt nesărat, topit până devine beurre noisette (alunizat)","30 g zahăr și un vârf bun de sare fină","1 lingură de rom închis sau apă de flori de portocal (sau 1 linguriță extract de vanilie)","Unt în plus pentru ungerea tigăii (~30 g, ținut cu o pensulă)","Pentru servit: zahăr tos, felii de lămâie, opțional gem, Nutella sau banane"]},"howIsMade":{"zh":"把 50 克黄油放入小锅中火加热，让它继续煮，直到散出榛果香味、颜色变成深金色，再过筛倒入碗中、把深色沉淀留在锅里——这就是 beurre noisette（焦香黄油），糕点级可丽饼的灵魂香气。\n\n把面粉和盐过筛到大碗里，中间挖一个坑，磕入鸡蛋，并加入三分之一的牛奶与糖，再用打蛋器从中心向外打、逐步把面粉拢进来，直到形成浓稠、无颗粒、顺滑的稠糊，然后以细流注入剩下的牛奶，最后加入温热的焦香黄油和朗姆酒；最后的面糊稠度应像稀奶油。\n\n盖好碗放进冰箱里至少 30 分钟，最好 1 小时——面筋落定，煎出来的可丽饼会薄而柔软，而不是橡皮一样。\n\n把 22–24 厘米的不粘锅或 crêpière 中大火加热，用刷子在锅面刷上极薄的一层黄油，倒入约 50 毫升面糊，立即旋转锅让它在底部铺成一张薄薄的圆，然后煎 50–60 秒，直到边缘翘起、底面呈金黄蕾丝色，用薄铲翻面（或手腕一甩翻锅）再煎 25–30 秒，滑到盘子上、盖一块干净布巾——继续煎下一张，大约每一两张刷一次锅，直到面糊用完。\n\n趁热撒上细砂糖、挤几滴柠檬汁，折成四分之一——巴黎街头摊位的经典版本有：纯糖（sucre）、糖+柠檬（sucre-citron）、果酱、Nutella、或香蕉+Nutella。","en":"Melt the 50 g of butter in a small saucepan over medium heat and keep cooking until it smells nutty and turns deep gold, then strain into a bowl leaving the dark sediment behind — that's beurre noisette, the signature flavour of bakery-grade crêpes.\n\nSift the flour and salt into a large bowl, make a well in the middle, crack in the eggs and add a third of the milk with the sugar, then whisk from the centre outwards drawing in the flour until you have a thick smooth paste with no lumps, thin with the rest of the milk in a slow stream and finally add the cooled brown butter and the rum; the batter should be the consistency of single cream.\n\nCover and rest the batter in the fridge at least 30 minutes, ideally an hour — the gluten settles and the crêpes turn out thin and flexible rather than elastic.\n\nHeat a 22–24 cm non-stick pan or crêpière over medium-high heat, brush with a very thin film of butter and pour in about 50 ml of batter, immediately swirling so it covers the base in a thin disc, then cook 50–60 seconds until the edges lift and the underside is lacy golden, flip with a thin spatula (or a quick toss of the pan) for another 25–30 seconds, slide onto a plate and cover with a clean cloth — carry on, brushing the pan with a little butter every one or two crêpes, until the batter is gone.\n\nServe warm, scattered with caster sugar and a squeeze of lemon, folded into quarters — the Parisian street-stand alternatives are sucre, sucre-citron, fruit jam, Nutella, or banana with Nutella."}},{"id":193,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":5,"carb":65,"fat":28,"fib":3},"origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"翻转苹果挞","en":"Tarte Tatin","ro":"Tarte Tatin"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["8–10 个紧实带酸味的苹果（reine de reinette、Golden Delicious 或 Honeycrisp），削皮、对半、去核，约 1.5 公斤","无盐黄油 150 克，切丁，置于室温","白砂糖 200 克（经典 tatin 不用红糖）","新鲜柠檬汁 1 汤匙","酥皮（pâte feuilletée）一张约 250 克，擀至直径 26 厘米、厚 3 毫米","海盐之花一撮","搭配上桌：crème fraîche 浓酸奶油 200 毫升，不是冰激凌——索洛涅地区的传统"],"en":["8–10 firm tart apples (reine de reinette, golden delicious or honeycrisp), peeled, halved and cored — about 1.5 kg","150 g unsalted butter, cut into cubes, at room temperature","200 g white granulated sugar (do not use brown sugar for a classic tatin)","1 tbsp fresh lemon juice","1 round of puff pastry (pâte feuilletée), ~250 g, rolled to 26 cm and 3 mm thick","A pinch of fleur de sel","To serve: 200 ml crème fraîche, not ice cream — the Sologne tradition"],"ro":["8–10 mere ferme și ușor acrișoare (reine de reinette, golden delicious sau honeycrisp), curățate, înjumătățite și fără cotor — în jur de 1,5 kg","150 g unt nesărat, tăiat cuburi, la temperatura camerei","200 g zahăr alb tos (nu se folosește zahăr brun pentru un tatin clasic)","1 lingură suc proaspăt de lămâie","Un disc de aluat de foitaj (pâte feuilletée), ~250 g, rulat la 26 cm diametru și 3 mm grosime","Un vârf de fleur de sel","Pentru servit: 200 ml smântână grasă (crème fraîche), nu înghețată — tradiția din Sologne"]},"howIsMade":{"zh":"把苹果与柠檬汁拌一下防止氧化变色，在一只可入烤箱的厚底锅或专用 tatin 锅（22–24 厘米）中，中火融化 50 克黄油，将白砂糖均匀撒在上面、不要搅动，让它自行融化并焦糖化至深琥珀色——大约 8–10 分钟——因为浅色的焦糖进烤箱后会褪色，味道也变得寡淡。\n\n把锅离火，将剩下 100 克黄油切块撒在焦糖上——会剧烈嘶嘶响——转动锅子让黄油均匀融化为光亮的焦糖黄油酱，然后将苹果对半切面朝上紧紧排列、由中心向外旋成螺旋（放得下），重新中火加热不加盖煮 25–30 分钟，不时倾斜锅子把边缘的焦糖收回来，直到苹果底部吸饱焦糖、开始软化。\n\n同时烤箱预热至 200°C，将酥皮擀成略大于锅子的圆形，关火让苹果稍微凉一两分钟，再把酥皮盖在苹果上，把多余的边缘塞进锅子里、压在苹果和锅壁之间——翻转时皮会牢牢抓住苹果——并用叉子在酥皮上戳几个小孔。\n\n烤 25–30 分钟至酥皮完全金黄、焦糖在锅边沸腾，取出后正好静置 10 分钟——让焦糖稳定但又不至于凝固。\n\n把比锅口更大的服务盘扣在酥皮上，戴手套或用厚布抓稳锅子，一气呵成翻过来——如果有苹果留在锅里，用铲子放回挞上——撒一撮海盐之花在顶上，趁热与每盘一大勺 crème fraîche 一起上桌。","en":"Toss the apples with the lemon juice so they don't brown, melt 50 g of the butter in a heavy 22–24 cm oven-safe pan with an ovenproof handle (or a proper tatin pan), scatter the sugar over it in an even layer and leave on medium heat without stirring until the sugar dissolves and caramelises to a deep amber — about 8–10 minutes — because pale caramel bleeds out in the oven and tastes flat.\n\nTake the pan off the heat and drop the remaining 100 g butter in cubes onto the caramel — it will hiss hard — swirl until the butter melts evenly into a glossy buttery sauce, then pack the apple halves cut-side-up, tight against each other in a spiral from the centre outwards (they will fit), return to medium heat and cook uncovered for 25–30 minutes, tilting the pan now and then to catch the caramel from the edges, until the underside of the apples has drunk the caramel and they just start to soften.\n\nMeanwhile heat the oven to 200°C and roll the puff pastry to a disc a little larger than the pan, cut the heat under the apples and let them settle a minute, then drape the pastry over the top and tuck the edges down inside the pan between the apples and the wall — the crust will grip the fruit when you flip — and prick the pastry a few times with a fork.\n\nBake 25–30 minutes until the pastry is fully golden and the caramel bubbles around the edges, then rest exactly 10 minutes — long enough for the caramel to settle without setting hard.\n\nPlace a serving plate wider than the pan over the pastry, hold the pan with a thick cloth and invert in one decisive motion — if any apple stays stuck to the pan, lift it back onto the tart with a spatula — scatter a pinch of fleur de sel over the top and serve warm with a generous spoonful of crème fraîche on each plate."}},{"id":194,"servings":6,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":28,"carb":28,"fat":10,"fib":1},"origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"希腊蛋柠檬鸡汤","en":"Avgolemono","ro":"Avgolemono"},"category":{"zh":"汤","en":"Soup","ro":"Supă"},"ingredients":{"zh":["整鸡 1.5 公斤（或带骨鸡腿 1 公斤）","胡萝卜 2 根、洋葱 1 个、芹菜 2 根（用于熬汤）","月桂叶 1 片、欧芹梗一小把、黑胡椒粒 8 颗","长粒米 150 克（或换成 orzo 米粒面）","大鸡蛋 3 个，置于室温","柠檬 2 个的汁（约 80 毫升）","盐与白胡椒","新鲜莳萝或欧芹，最后撒上"],"en":["1.5 kg whole chicken (or 1 kg bone-in chicken thighs)","2 carrots, 1 onion, 2 celery stalks (for the broth)","1 bay leaf, a handful of parsley stems, 8 black peppercorns","150 g long-grain rice (or orzo if you prefer)","3 large eggs, at room temperature","Juice of 2 lemons (about 80 ml)","Salt and white pepper","Fresh dill or parsley to finish"],"ro":["1,5 kg pui întreg (sau 1 kg pulpe de pui cu os)","2 morcovi, 1 ceapă, 2 tulpini de țelină (pentru fond)","1 frunză de dafin, un mănunchi de codițe de pătrunjel, 8 boabe de piper negru","150 g orez cu bob lung (sau orzo, dacă preferi)","3 ouă mari, la temperatura camerei","Zeama de la 2 lămâi (aproximativ 80 ml)","Sare și piper alb","Mărar sau pătrunjel proaspăt pentru a încheia"]},"howIsMade":{"zh":"把整鸡放入厚底锅，加入胡萝卜、洋葱、芹菜、月桂叶、欧芹梗和黑胡椒粒，倒入 2.5 升冷水，慢慢加热到微沸。撇去浮沫，不盖盖煮约 90 分钟，直到肉一碰就脱骨。\n\n把鸡捞出，把汤过滤到干净的锅里，蔬菜弃去。把鸡肉从骨头上拆下来撕成小块再放回汤中，重新加热到微沸，倒入米；煮 15–18 分钟，至米粒柔软。\n\n把鸡蛋打到颜色变浅、起泡，再把柠檬汁打入。给蛋液回温：一边持续搅打，一边把一勺热汤慢慢淋到蛋液上，再加一勺，直到碗摸起来微温。\n\n离火，把回温后的蛋液以细而稳的水流倒回汤里，不停搅动 — 这之后汤不可再煮沸，否则鸡蛋会凝结成絮。用盐和白胡椒调味，立即上桌，撒上莳萝或欧芹。","en":"Simmer the chicken in 2.5 L cold water with the carrots, onion, celery, bay leaf, parsley stems and peppercorns. Skim any foam and cook uncovered for about 90 minutes, until the meat falls from the bones.\n\nLift the chicken out, strain the broth into a clean pot and discard the vegetables. Shred the meat off the bones, return it to the broth, bring back to a simmer and stir in the rice; cook 15–18 minutes until tender.\n\nWhisk the eggs in a bowl until light and foamy, then whisk in the lemon juice. Temper them by slowly ladling a cup of hot broth in while whisking, then another, until the bowl is warm to the touch.\n\nOff the heat, pour the tempered eggs back into the pot in a slow steady stream, stirring continuously — never let the soup boil again. Season with salt and white pepper and serve immediately, finished with dill or parsley."}},{"id":195,"servings":4,"tipType":"meat","pairingsType":"mediterranean","nutrition":{"cal":620,"prot":38,"carb":52,"fat":28,"fib":4},"origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"希腊烤肉卷","en":"Gyros","ro":"Gyros"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["猪肩肉 1 公斤，逆纹切成 1 厘米厚的条（或去骨鸡腿）","蒜瓣 4 个，剁末","希腊橄榄油 2 汤匙","红酒醋 1 汤匙","干牛至 1 汤匙（有希腊 rigani 最好）","甜红椒粉 1 茶匙","盐 1 茶匙、黑胡椒 ½ 茶匙","希腊大软面饼 4 张（不带袋子的扁面饼，不是开口 pita）","搭配：tzatziki 200 毫升、熟番茄 1 个切片、红洋葱 ½ 个切薄丝、牛至、柠檬角，可选薯条"],"en":["1 kg pork shoulder, sliced into 1 cm thick strips against the grain (or boneless chicken thighs)","4 garlic cloves, minced","2 tbsp Greek olive oil","1 tbsp red wine vinegar","1 tbsp dried oregano (Greek rigani if possible)","1 tsp sweet paprika","1 tsp salt, ½ tsp black pepper","4 large soft Greek pitas (the unfilled flatbread, not pocket pita)","To serve: 200 ml tzatziki, 1 ripe tomato sliced, ½ red onion thinly sliced, oregano, lemon wedges, optional French fries"],"ro":["1 kg ceafă de porc, tăiată în fâșii de 1 cm grosime contra fibrei (sau pulpe de pui dezosate)","4 căței de usturoi, tocați","2 linguri ulei de măsline grecesc","1 lingură oțet de vin roșu","1 lingură oregano uscat (rigani grecesc, dacă ai)","1 linguriță boia dulce","1 linguriță sare, ½ linguriță piper negru","4 lipii grecești mari și moi (turtă plată neumplută, nu pita cu buzunar)","Pentru servit: 200 ml tzatziki, 1 roșie coaptă feliată, ½ ceapă roșie tăiată subțire, oregano, felii de lămâie, opțional cartofi prăjiți"]},"howIsMade":{"zh":"把蒜末、橄榄油、醋、牛至、红椒粉、盐和胡椒在大碗里搅匀，加入猪肉条，拌至每一条都裹上腌料。盖好，至少腌 3 小时，最好过夜。\n\n把厚底煎锅或铁板加热至冒烟。把肉条平铺一层放下，必要时分批，每面不动地煎 2–3 分钟，直到边缘深棕、中心刚熟；不要堆挤，否则肉会蒸而不是焦化。每出一批，先放到盘里，再煎下一批。\n\n把皮塔饼一张一张放回同一只热锅上，每面加热 20 秒，到变柔软即可。每张饼中央铺一大勺 tzatziki，再放上热乎乎的猪肉，加几片番茄和红洋葱圈 — 如果要忠于雅典风格，再撒一小把炸薯条。\n\n用纸紧紧卷好，一端拧紧封口，立即上桌，旁边配多余的牛至、一角柠檬和剩下的 tzatziki。","en":"Whisk the garlic, olive oil, vinegar, oregano, paprika, salt and pepper in a large bowl, add the pork strips and toss until every piece is coated. Cover and marinate at least 3 hours, ideally overnight.\n\nHeat a large heavy skillet or griddle pan over high heat until smoking. Lay the strips down in a single layer, in batches if needed, and sear without moving for 2–3 minutes per side, until the edges are deeply browned and the centre just cooked through; don't crowd the pan or the meat will steam instead of caramelise. Rest each batch on a plate while you cook the next.\n\nWarm the pitas one at a time on the same hot skillet for 20 seconds per side, just until pliable. Spread a heaped tablespoon of tzatziki down the centre of each, lay the hot pork on top, add a few tomato slices and rings of red onion, and — if you're being faithful to Athens — a small handful of French fries on top.\n\nWrap tightly in paper with one end pinched closed, and serve immediately with extra oregano, a wedge of lemon, and the rest of the tzatziki on the side."}},{"id":196,"servings":8,"tipType":"pasta","pairingsType":"mediterranean","nutrition":{"cal":680,"prot":30,"carb":62,"fat":32,"fib":4},"origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"希腊烤通心粉","en":"Pastitsio","ro":"Pastitsio"},"category":{"zh":"意面","en":"Pasta","ro":"Paste"},"ingredients":{"zh":["Pastitsio 长管面 500 克（粗长筒状，2 号；用 bucatini 替代也可）","牛肉末 600 克（或一半牛、一半羊）","大洋葱 1 个，切细末","蒜瓣 3 个，剁末","罐装碎番茄 400 克","番茄膏 2 汤匙","干红葡萄酒 150 毫升","肉桂棒 1 根、整丁香 4 颗、月桂叶 1 片、干牛至 1 茶匙","Kefalotyri 或 Pecorino 奶酪 100 克，磨细（实在没有用 Parmesan 也行）","贝夏梅酱：黄油 100 克、面粉 100 克、全脂牛奶 1 升、蛋黄 4 个、肉豆蔻少许","盐、胡椒、橄榄油"],"en":["500 g pastitsio noodles (long, tubular #2; bucatini is a fair substitute)","600 g beef mince (or half beef, half lamb)","1 large onion, finely chopped","3 garlic cloves, minced","400 g chopped tomatoes (canned)","2 tbsp tomato paste","150 ml dry red wine","1 cinnamon stick, 4 whole cloves, 1 bay leaf, 1 tsp dried oregano","100 g Kefalotyri or Pecorino, finely grated (Parmesan works at a pinch)","For the béchamel: 100 g butter, 100 g flour, 1 L whole milk, 4 egg yolks, a grating of nutmeg","Salt and pepper, olive oil"],"ro":["500 g paste tip pastitsio (lungi, tubulare nr. 2; bucatini este o alternativă bună)","600 g carne tocată de vită (sau jumătate vită, jumătate miel)","1 ceapă mare, tocată mărunt","3 căței de usturoi, tocați","400 g roșii tocate (la conservă)","2 linguri pastă de roșii","150 ml vin roșu sec","1 baton de scorțișoară, 4 cuișoare întregi, 1 frunză de dafin, 1 linguriță oregano uscat","100 g Kefalotyri sau Pecorino, ras fin (Parmezan se poate la nevoie)","Pentru béchamel: 100 g unt, 100 g făină, 1 l lapte integral, 4 gălbenușuri, puțină nucușoară rasă","Sare, piper, ulei de măsline"]},"howIsMade":{"zh":"厚底锅里加入 3 汤匙橄榄油，把切碎的洋葱炒 8–10 分钟，加入蒜末 30 秒，再放入肉糜。用木勺压散，让它充分上色，约 10 分钟。加入番茄酱炒至砖红色，倒入红酒收浓一半，再加入番茄、肉桂棒、丁香、月桂叶和牛至。多放些盐和胡椒，不盖盖子小火炖至少 45 分钟；上桌组装前把整粒香料取出。\n\n炖肉的同时做白酱：宽口锅里融化黄油，加入面粉炒 1–2 分钟但不上色，缓缓倒入温热的牛奶并持续搅打，再小火煮 5–7 分钟，至能挂在勺背上。离火，逐颗加入蛋黄，加入肉豆蔻和一半磨碎的奶酪，调味。\n\n把意面在加了大量盐的水中煮至包装说明时间减 2 分钟（剩下的时间在烤箱里完成），沥干后拌入剩下的奶酪和一勺肉酱，防止粘连。\n\n取一个 25×35 厘米烤盘，把一半的意面朝同一方向铺好，均匀铺一层肉酱，再用剩下的意面以同样方向叠上一层。把白酱浇在最上面，抹平，180°C 烤 45–50 分钟，至金黄、轻轻冒泡。\n\n切之前先让它静置至少 20 分钟，否则层次会塌成一片。","en":"Heat 3 tablespoons of olive oil in a heavy pan and brown the chopped onion for 8–10 minutes, add the garlic for 30 seconds, then crumble in the mince. Break it up with a wooden spoon and let it brown deeply, about 10 minutes. Stir in the tomato paste, fry until brick-red, deglaze with the wine and let it reduce by half before adding the tomatoes, cinnamon stick, cloves, bay leaf and oregano. Season generously and simmer uncovered on low heat for at least 45 minutes; fish out the whole spices before assembling.\n\nWhile the meat cooks, make the béchamel: melt the butter in a wide saucepan, whisk in the flour for a couple of minutes without colour, pour in the warm milk in a slow stream while whisking, then simmer 5–7 minutes until it coats the back of a spoon. Off the heat, beat in the egg yolks one at a time, add the nutmeg and half the grated cheese, and season.\n\nBoil the pasta in well-salted water 2 minutes less than the package says — it'll finish in the oven — drain and toss with the remaining cheese and a ladle of meat sauce so the noodles don't stick.\n\nIn a 25×35 cm baking dish, lay half the pasta in one direction, spread the meat sauce evenly over it, then top with the rest of the pasta aligned the same way. Pour the béchamel over, smooth it level, and bake at 180°C for 45–50 minutes until golden and bubbling.\n\nLet it rest at least 20 minutes before cutting; sliced too hot, the layers collapse."}},{"id":197,"servings":6,"tipType":"veg","pairingsType":"mediterranean","nutrition":{"cal":280,"prot":5,"carb":35,"fat":14,"fib":3},"origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"希腊葡萄叶卷","en":"Dolmades","ro":"Dolmades"},"category":{"zh":"开胃菜","en":"Appetizer","ro":"Aperitiv"},"ingredients":{"zh":["罐装腌葡萄叶 1 罐（450 克），沥干冲洗（或新鲜叶片 60 片，焯过水）","长粒米 200 克（arborio 米也行）","大洋葱 1 个，切细末","葱 6 根，切薄片","新鲜莳萝一大把，切碎","新鲜薄荷一小把，切碎","平叶欧芹一小把，切碎","柠檬 2 个的汁","特级初榨橄榄油 150 毫升","盐 1 茶匙、现磨黑胡椒","可选但传统：番茄 1 个，擦泥"],"en":["1 jar (450 g) preserved grape leaves, drained and rinsed (or 60 fresh blanched leaves)","200 g long-grain rice (arborio works)","1 large onion, finely chopped","6 spring onions, thinly sliced","A large bunch of fresh dill, chopped","A small bunch of fresh mint, chopped","A small bunch of flat-leaf parsley, chopped","Juice of 2 lemons","150 ml extra-virgin olive oil","1 tsp salt, freshly ground black pepper","Optional but traditional: 1 grated tomato"],"ro":["1 borcan (450 g) de frunze de viță conservate, scurse și clătite (sau 60 de frunze proaspete opărite)","200 g orez cu bob lung (merge și arborio)","1 ceapă mare, tocată mărunt","6 fire de ceapă verde, tăiate subțire","Un mănunchi mare de mărar proaspăt, tocat","Un mănunchi mic de mentă proaspătă, tocată","Un mănunchi mic de pătrunjel cu frunza plată, tocat","Zeama de la 2 lămâi","150 ml ulei de măsline extravirgin","1 linguriță sare, piper negru proaspăt măcinat","Opțional dar tradițional: 1 roșie rasă"]},"howIsMade":{"zh":"把米用冷水浸泡 15 分钟后沥干。宽口锅里加 3 汤匙橄榄油，把切碎的洋葱低温炒 8 分钟至变透明、不上色。加入小葱、所有香草、沥干的米、一半柠檬汁和大量盐，搅一分钟让香气释放，然后倒到盘子上摊开，放至室温。\n\n把葡萄叶叶脉朝上、叶柄朝身放在工作台上。在靠近叶柄处放一茶匙满满的米馅，把底边往上折盖住馅，两侧向内折叠，再紧紧卷成一个小卷。不要塞得太满 — 米在烹煮时会膨胀，太紧的话 dolma 会裂开。\n\n用撕碎的或破损的叶子在厚底锅底铺一层，防止粘锅。把卷好的 dolmades 以同心圆方式排列，封口朝下，紧密相靠以互相支撑。倒入剩下的橄榄油和柠檬汁，再加冷水到与 dolmades 同高，上面压一只耐热盘子让它们一直浸在汤里。\n\n慢慢加热到微沸，盖好，最小火炖 50–60 分钟，直到米饭软糯、汁水几乎收干。让它们就在锅里冷却 — 这道菜可以冷食或常温食用，配一块柠檬和一碗浓稠酸奶。提前一天做好的更入味。","en":"Soak the rice in cold water for 15 minutes and drain. Heat 3 tablespoons of olive oil in a wide pan and sweat the chopped onion for 8 minutes until translucent, no colour. Add the spring onions, all the herbs, the drained rice, half the lemon juice and a generous pinch of salt; stir for a minute to bloom the aromas, then tip onto a plate to cool to room temperature.\n\nLay a grape leaf on the work surface vein-side up, stem at the bottom. Place a heaped teaspoon of the rice mixture near the stem, fold the bottom edge up and over, fold both sides in, and roll up tightly into a small cigar. Don't overfill — the rice swells as it cooks and packed too tightly the dolma will split.\n\nLine the bottom of a heavy pot with torn or broken leaves to prevent sticking. Pack the rolled dolmades in concentric circles, seam-side down, snug enough to hold each other in place. Pour over the remaining olive oil and lemon juice, add cold water just to the top of the dolmades, and press a heatproof plate directly on the surface to keep them submerged.\n\nBring slowly to a simmer, cover, and cook on the lowest heat for 50 minutes to an hour, until the rice is tender and the liquid mostly absorbed. Leave to cool in the pot — they're served cold or at room temperature, with a wedge of lemon and a bowl of thick yoghurt. Made the day before, they taste markedly better."}},{"id":198,"servings":12,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":380,"prot":7,"carb":48,"fat":18,"fib":1},"origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"希腊牛奶酥皮派","en":"Galaktoboureko","ro":"Galaktoboureko"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["酥皮（phyllo）500 克，解冻","无盐黄油 200 克，融化","全脂牛奶 1 升","细砂糖 200 克（用于卡仕达）","细粒粗粒小麦粉（semolina）150 克","大鸡蛋 4 个","香草精 1 茶匙","1 个柠檬的皮屑","糖浆：细砂糖 400 克、水 250 毫升、半个柠檬的汁、一条橙皮、肉桂棒 1 根"],"en":["500 g phyllo pastry, thawed","200 g unsalted butter, melted","1 L whole milk","200 g caster sugar (for the custard)","150 g fine semolina","4 large eggs","1 tsp vanilla extract","Zest of 1 lemon","For the syrup: 400 g caster sugar, 250 ml water, juice of half a lemon, a strip of orange peel, 1 stick of cinnamon"],"ro":["500 g foi de plăcintă (phyllo), dezghețate","200 g unt nesărat, topit","1 l lapte integral","200 g zahăr tos (pentru cremă)","150 g griș fin","4 ouă mari","1 linguriță extract de vanilie","Coaja rasă de la 1 lămâie","Pentru sirop: 400 g zahăr, 250 ml apă, zeama de la o jumătate de lămâie, o fâșie de coajă de portocală, 1 baton de scorțișoară"]},"howIsMade":{"zh":"提前很久就开始做糖浆——它必须在热的派出炉时已经是凉的——在小锅里把糖、水、柠檬汁、橙皮和肉桂混合，烧开后再小火炖 4 分钟，离火放凉至完全冷却。做卡仕达酱：在一只大锅里把牛奶、糖和柠檬皮屑加热到刚冒热气（不要让它沸腾），把粗麦粉以细而均匀的流撒入并不停搅打，然后继续在小火上打 5–6 分钟，直到稠到像松软的布丁；离火，把鸡蛋一个一个搅入（混合物应当是温热的但不能热到把蛋烫熟）然后加入香草，把保鲜膜直接贴在表面上以防结皮。在 22×30 cm 的烤盘上刷融化的黄油，在底部铺 7 张 phyllo 面皮，每一张都慷慨地刷上黄油，让边缘垂出盘子两侧（这些垂边稍后会折回到顶部上来），倒入还是温的卡仕达酱，把它抹平，把垂出来的边折回到馅料里面并刷上黄油，再盖上另外 7 张 phyllo 面皮（每张同样刷黄油），把边缘切齐或塞进去，让派完全封闭。用一把锋利的刀在顶层 phyllo 上切出菱形或方形——一定要切到底，这样糖浆稍后才能渗进去——把表面用最后的黄油慷慨地刷一遍，然后放进 170°C 的烤箱烤 45–55 分钟，直到顶部呈深金棕色。出炉的那一刻，把冷糖浆均匀地浇在热的派上——它会咝咝作响并冒蒸汽——让它静置至少 4 小时，最好一夜，然后再沿着切痕切开，在室温下享用。","en":"Start the syrup well in advance — it must be cold when the hot pie comes out of the oven — combine the sugar, water, lemon juice, orange peel and cinnamon in a small saucepan, bring to a boil then simmer 4 minutes, take off the heat and leave to cool completely. For the custard, heat the milk in a wide saucepan with the sugar and lemon zest until just steaming (do not let it boil), sprinkle the semolina in a fine even stream while whisking constantly, then keep whisking on low heat for 5–6 minutes until it thickens to a loose pudding; off the heat, beat in the eggs one at a time (the mixture should be warm but not hot enough to scramble them) and the vanilla, then press clingfilm directly onto the surface to stop a skin forming. Brush a 22×30 cm baking dish with melted butter, lay 7 sheets of phyllo across the bottom brushing each generously with butter and letting the edges hang over the sides (those flaps will fold back over the top later), pour in the still-warm custard, smooth it level, fold the overhanging flaps inward and brush them with butter, then cover with another 7 sheets of phyllo (again buttering each) and trim or tuck the edges so the pie is fully sealed. Score the top phyllo into diamonds or squares with a sharp knife — cut all the way through so the syrup can later penetrate — brush the surface lavishly with the last of the butter, and bake at 170°C for 45–55 minutes until the top is deeply golden brown. The moment it comes out of the oven, pour the cold syrup evenly over the hot pie — it will sizzle and steam — leave to settle at least 4 hours, ideally overnight, before cutting along the score lines and serving at room temperature."}},{"id":199,"servings":4,"tipType":"def","pairingsType":"italian","nutrition":{"cal":740,"prot":28,"carb":88,"fat":30,"fib":4},"origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"玛格丽特披萨","en":"Pizza Margherita","ro":"Pizza Margherita"},"category":{"zh":"披萨","en":"Pizza","ro":"Pizza"},"ingredients":{"zh":["面团（4 张披萨）：00 号面粉 500 克（或高筋面粉）、冷水 325 毫升、盐 10 克、鲜酵母 1 克（或干酵母 ¼ 茶匙）","每张披萨：San Marzano 罐头番茄 80 克（手捏碎）、一撮盐、一点橄榄油","每张披萨用 fior di latte 莫扎雷拉 100 克，手撕（或水牛奶莫扎雷拉）","每张披萨配几片新鲜罗勒","上桌前淋特级初榨橄榄油","整形和铲面用的粗粒小麦粉或面粉"],"en":["For the dough (4 pizzas): 500 g 00 flour (or bread flour), 325 ml cold water, 10 g salt, 1 g fresh yeast (or ¼ tsp dried)","For each pizza: 80 g San Marzano tomatoes (canned, hand-crushed), a pinch of salt, a drizzle of olive oil","100 g fior di latte mozzarella per pizza, torn into pieces (or buffalo mozzarella)","A few fresh basil leaves per pizza","Extra-virgin olive oil to finish","Semolina or flour for shaping and the peel"],"ro":["Pentru aluat (4 pizza): 500 g făină 00 (sau pentru pâine), 325 ml apă rece, 10 g sare, 1 g drojdie proaspătă (sau ¼ linguriță uscată)","Pentru fiecare pizza: 80 g roșii San Marzano (la conservă, sfărâmate cu mâna), un praf de sare, un fir de ulei de măsline","100 g mozzarella fior di latte per pizza, ruptă în bucățele (sau mozzarella de bivoliță)","Câteva frunze de busuioc proaspăt pentru fiecare pizza","Ulei de măsline extravirgin pentru finalizare","Griș sau făină pentru modelare și pentru lopată"]},"howIsMade":{"zh":"做面团：把酵母溶于冷水中，再混入面粉和盐，揉成一团粗糙的面团，手揉 10 分钟（或用厨师机带勾揉 6 分钟）至光滑有弹性，盖好在室温下醒发一小时，再放冰箱冷藏至少 24 小时，最好 48–72 小时——这种长时间的冷发酵正是给那不勒斯面团带来那种起泡焦化的边缘和蓬松结构的关键。烤之前两小时，把面团拿出来，分成四个 210 g 的小球，撒上面粉，盖湿布让它们回到室温；同时把烤箱开到最高档（250°C 或更高），里面放一块披萨石或厚钢板预热至少 45 分钟；没有真正的高温从下面顶住披萨，面饼就来不及成型。在撒了大量面粉的台面上手工拉一个面球——用指尖压平中心，留出隆起的边，然后轻轻把面饼拉伸到约 28 cm——千万不要用擀面杖，那会压碎面边里的气孔——把它移到撒了面粉的披萨铲上。在中心放上 80 g 压碎的番茄，用勺子背面以螺旋状抹开，留出离边 2 cm 的边缘不抹，番茄上撒一点盐，淋一点橄榄油，再把撕碎的莫扎瑞拉撒在上面（不要太多，否则披萨会被淹没）。把披萨滑到石板上烤，直到面边鼓起、有焦黑斑点，奶酪化成一汪汪，边缘呈深金色——家用烤箱满火 4 到 6 分钟，那不勒斯柴火炉 90 秒——拿出来，把罗勒叶撕碎撒上去（放进烤箱会被烤焦），最后再淋一线橄榄油，立刻趁热吃。","en":"For the dough, dissolve the yeast in the cold water then mix in the flour and salt until you have a shaggy mass, knead by hand for 10 minutes (or 6 minutes with a stand mixer and dough hook) until smooth and elastic, cover and rest at room temperature for an hour, then refrigerate for at least 24 hours and ideally 48 to 72 — the long cold proof is what gives Neapolitan dough its blistered char and airy structure. Two hours before baking, take the dough out, divide into four 210 g balls, dust with flour, cover with a damp cloth and let them come to room temperature, meanwhile heat the oven as hot as it goes (250°C or above) with a pizza stone or heavy steel sheet inside for at least 45 minutes; without serious heat under the pizza, the crust will never set in time. Hand-stretch one ball on a well-floured surface — press the centre flat with your fingertips leaving a raised lip, then gently pull and stretch the disc to about 28 cm across — never use a rolling pin, which collapses the gas pockets in the crust — and slide it onto a floured peel. Spoon 80 g of crushed tomato into the centre and spread it in a spiral with the back of the spoon stopping 2 cm from the edge, salt the tomato lightly, drizzle a little olive oil, and scatter the torn mozzarella over the top (not too much, or the pizza floods). Slide the pizza onto the stone and bake until the crust is puffed and charred in spots, the cheese has melted into pools and the rim is dark gold — 4 to 6 minutes in a domestic oven at full blast, 90 seconds in a wood-fired Neapolitan oven — pull it out, tear over the basil leaves (which would scorch in the oven), drizzle a final thread of olive oil, and eat immediately."}},{"id":200,"servings":6,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":720,"prot":36,"carb":58,"fat":36,"fib":4},"origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"波隆纳千层面","en":"Lasagne alla Bolognese","ro":"Lasagne alla Bolognese"},"category":{"zh":"意面","en":"Pasta","ro":"Paste"},"ingredients":{"zh":["意式肉酱：牛肉末 400 克、猪肉末 200 克、意式培根 80 克切细丁、洋葱 1 个 + 胡萝卜 1 根 + 芹菜 1 根全部切细末、干红葡萄酒 200 毫升、passata 番茄酱或番茄碎 400 克、全脂牛奶 250 毫升、月桂叶 1 片、盐和胡椒、橄榄油","贝夏梅酱：黄油 80 克、面粉 80 克、全脂牛奶 1 升、盐、肉豆蔻屑少许","新鲜鸡蛋千层面皮 300 克（或干款 250 克，焯过水）","Parmigiano Reggiano 150 克，磨细","烤盘抹用的黄油"],"en":["For the ragù: 400 g beef mince, 200 g pork mince, 80 g pancetta finely diced, 1 onion + 1 carrot + 1 celery stalk all finely diced, 200 ml dry red wine, 400 g passata or chopped tomatoes, 250 ml whole milk, 1 bay leaf, salt and pepper, olive oil","For the béchamel: 80 g butter, 80 g flour, 1 L whole milk, salt, a grating of nutmeg","300 g fresh egg lasagne sheets (or 250 g dried, blanched)","150 g Parmigiano Reggiano, finely grated","Butter for the dish"],"ro":["Pentru ragù: 400 g vită tocată, 200 g porc tocat, 80 g pancetta tăiată cubulețe, 1 ceapă + 1 morcov + 1 țelină — toate tocate mărunt, 200 ml vin roșu sec, 400 g passata sau roșii tocate, 250 ml lapte integral, 1 frunză de dafin, sare și piper, ulei de măsline","Pentru béchamel: 80 g unt, 80 g făină, 1 l lapte integral, sare, puțină nucușoară rasă","300 g foi proaspete de lasagne cu ou (sau 250 g uscate, opărite)","150 g Parmigiano Reggiano, ras fin","Unt pentru vasul de copt"]},"howIsMade":{"zh":"把意式咸猪肉（pancetta）在厚锅里加一点橄榄油，以中小火慢慢出油 5 分钟，直到油变清，加入切碎的 soffritto（洋葱、胡萝卜、芹菜），煮 10 分钟，直到变软、边缘微微发金，再把两种肉都掰碎放进去煎香——耐心：前 3 分钟不要动它，再用铲子把肉打散，再煎 10 分钟，直到锅底深深焦化。倒入葡萄酒，用木勺把锅底的 fond 刮起来，收汁到一半，然后加入番茄、牛奶（这就是 Bolognese 的标志——它能圆润酸度、收紧口感）、月桂叶和 1 茶匙盐；煮到刚冒泡的程度，半盖，以最小可能的火炖至少 2 小时，最好 3 小时，时不时搅一下，如果有干掉的迹象就加一点水——成品 ragù 应当是有光泽的、深红棕色的，几乎像一团酱，绝不是汤。ragù 快好的时候做 béchamel：把黄油融化，加入面粉打 2 分钟但不要让它上色，倒入温热的牛奶，一边慢慢倒一边打，煮 5 分钟到变稠，最后用盐和大量现磨肉豆蔻调味。如果用干的千层面皮，在加盐的沸水里焯 1 分钟，然后摊在湿的茶巾上——鲜面皮直接生用——把烤箱加热到 180°C，给一只 25×35 cm 的烤盘抹上黄油，在底部铺一层薄薄的 béchamel，然后一层面皮、一层 ragù、一层 béchamel、再撒一层雪一样的 Parmigiano，重复这个动作直到所有材料用完（6–7 层是 Bolognese 的目标），最上面以 béchamel 收尾，再撒上更厚的一层 Parmigiano。烤 35–40 分钟，直到表面变得古铜色并冒泡，然后静置 20 分钟再切——刚出炉就切的千层面会散开，静置过的能保持层次。","en":"Render the pancetta gently in a heavy pot with a splash of olive oil over medium-low heat for 5 minutes until the fat runs clear, add the chopped soffritto (onion, carrot, celery) and cook 10 minutes until soft and just gilded at the edges, then crumble in both meats and brown them properly — patience: do not stir for the first 3 minutes, then break them up and cook 10 more minutes until the pan bottom is deeply caramelised. Pour in the wine, scrape the fond from the pan with a wooden spoon and reduce by half, then add the tomatoes, the milk (the Bolognese signature — it rounds the acid and tightens the texture), the bay leaf and a teaspoon of salt; bring to a bare simmer, partially cover, and cook on the lowest possible heat for at least 2 hours and ideally 3, stirring occasionally and adding a splash of water if it threatens to dry — the finished ragù should be glossy, deep brown-red and almost a paste, never a soup. While the ragù finishes, make the béchamel: melt the butter, whisk in the flour for 2 minutes without colour, pour in the warm milk in a slow stream while whisking and simmer 5 minutes until thick, then season with salt and a generous grating of nutmeg. If using dried lasagne sheets blanch them in salted boiling water for a minute and lay on damp tea towels — fresh sheets go in raw — heat the oven to 180°C and butter a 25×35 cm baking dish, then spread a thin layer of béchamel on the bottom, then a layer of pasta, then ragù, then béchamel, then a snowy dusting of Parmigiano, and repeat until you have used everything (six to seven layers is the Bolognese target), finishing with béchamel and a heavier shower of Parmigiano. Bake 35–40 minutes until the top is bronzed and bubbling, then rest 20 minutes before cutting — lasagne sliced hot slides apart, lasagne rested holds its layers."}},{"id":201,"servings":4,"tipType":"meat","pairingsType":"italian","nutrition":{"cal":580,"prot":42,"carb":18,"fat":32,"fib":3},"origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"米兰式烩小牛膝","en":"Osso Buco alla Milanese","ro":"Osso Buco alla Milanese"},"category":{"zh":"主菜","en":"Main","ro":"Fel principal"},"ingredients":{"zh":["4 块厚切小牛胫（3–4 厘米厚，每块约 350 克），用厨用棉绳沿圆周捆好","盐和现磨黑胡椒","撒粉用中筋面粉","无盐黄油 4 汤匙、橄榄油 2 汤匙","洋葱 1 个 + 胡萝卜 1 根 + 芹菜 1 根，全部切细末","干白葡萄酒 200 毫升","罐装碎番茄 400 克","小牛或鸡高汤 500 毫升","月桂叶 1 片、几枝百里香","Gremolata：1 个柠檬的皮屑、2 瓣大蒜剁极细、一小把平叶欧芹切细"],"en":["4 thick-cut veal shanks (3–4 cm thick, about 350 g each), tied around the circumference with kitchen string","Salt and freshly ground black pepper","Plain flour for dusting","4 tbsp unsalted butter, 2 tbsp olive oil","1 onion + 1 carrot + 1 celery stalk, all finely diced","200 ml dry white wine","400 g chopped tomatoes","500 ml veal or chicken stock","1 bay leaf, a few sprigs of thyme","For the gremolata: zest of 1 lemon, 2 garlic cloves finely minced, a small bunch of flat-leaf parsley finely chopped"],"ro":["4 rasoluri groase de vițel (3–4 cm grosime, aproximativ 350 g fiecare), legate cu sfoară de bucătărie pe circumferință","Sare și piper negru proaspăt măcinat","Făină albă pentru tăvălit","4 linguri unt nesărat, 2 linguri ulei de măsline","1 ceapă + 1 morcov + 1 țelină, toate tocate mărunt","200 ml vin alb sec","400 g roșii tocate","500 ml fond de vițel sau pui","1 frunză de dafin, câteva fire de cimbru","Pentru gremolata: coaja rasă de la 1 lămâie, 2 căței de usturoi tocați fin, un mănunchi mic de pătrunjel cu frunza plată, tocat fin"]},"howIsMade":{"zh":"把小牛胫骨用纸巾拍干——湿肉会蒸而不是煎——大量地用盐和胡椒调味，再轻轻撒上面粉，把多余的拍掉，然后在厚锅中以中高火加热一半黄油和所有油，直到起泡，把胫骨放进去，4 分钟不要动它，直到底部煎成深棕色，翻面煎另一面，再夹到盘子上。把火调到中火，加入剩下的黄油和 soffritto，温和地煮 10 分钟，直到变软、边缘发金，然后倒入葡萄酒，调大火力，收汁到一半，同时把锅底焦化的部分刮起来。加入番茄、月桂叶和百里香，把胫骨单层放回锅里，再倒入足够的高汤，刚好淹到肉的三分之二——骨头必须露在汤面之上，骨髓才不会流出来——然后烧到微微冒泡。盖盖以最小火或放进 160°C 的烤箱炖 2 至 2½ 小时，每 30 分钟轻轻翻一次胫骨，让它们均匀受热——当用勺子一压肉就从骨头上滑下、酱汁收成发亮的浓汁时，就好了——然后小心夹出，因为此时骨头和骨髓都很脆弱。胫骨歇着的时候，把柠檬皮、大蒜和欧芹拌在一起做 gremolata，每盘放一块胫骨，浇上大量酱汁，再顶上一小撮生 gremolata——它的尖锐酸味切开浓厚，正是让这道菜成为「米兰式 osso buco」而不只是普通炖小牛肉的关键——配 risotto alla milanese、polenta 或一块面包蘸骨髓食用。","en":"Pat the shanks dry — wet meat steams instead of searing — season aggressively with salt and pepper and dust lightly in flour knocking off the excess, then heat half the butter and all the oil in a heavy braising pan over medium-high heat until foaming, lay the shanks in and do not touch them for 4 minutes until the bottom is deeply browned, flip and do the second side, then lift onto a plate. Lower the heat to medium, add the rest of the butter and the soffritto, and cook gently for 10 minutes until soft and golden at the edges, then pour in the wine, raise the heat, and reduce by half while scraping up the caramelised bits from the bottom of the pan. Stir in the tomatoes, bay leaf and thyme, return the shanks to the pan in a single layer, and pour in just enough stock to come about two-thirds of the way up the meat — the bones should stay exposed so the marrow stays in — and bring to a bare simmer. Cover and braise on the lowest heat or in a 160°C oven for 2 to 2½ hours, turning the shanks gently every 30 minutes so they cook evenly — they are done when the meat slumps off the bone at the press of a spoon and the sauce has thickened to a glossy gravy — then lift them out carefully because the bones and marrow are fragile at this point. While the shanks rest, stir together the lemon zest, garlic and parsley to make the gremolata, place a shank on each plate, spoon over plenty of sauce, and crown with a generous pinch of the raw gremolata — its sharpness cuts the richness and is what makes osso buco Milanese rather than just braised veal — serve with risotto alla milanese, polenta, or a piece of bread for the marrow."}},{"id":202,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":540,"prot":9,"carb":42,"fat":36,"fib":1},"origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"提拉米苏","en":"Tiramisu","ro":"Tiramisu"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["马斯卡彭奶酪 500 克，置于室温","大鸡蛋 5 个，分离蛋黄蛋白，置于室温","细砂糖 100 克","冷的浓缩咖啡 250 毫升（约 5 杯 espresso）","甜马沙拉酒（Marsala）或深色朗姆酒 2 汤匙（可选，特雷维索传统配方）","意大利手指饼干 savoiardi 300 克（结实的那种，不是软的）","无糖可可粉用于撒面","黑巧克力一小块，用来刨碎（可选）","一撮盐给蛋白"],"en":["500 g mascarpone, at room temperature","5 large eggs, separated, at room temperature","100 g caster sugar","250 ml strong cold espresso (about 5 shots)","2 tbsp Marsala (sweet) or dark rum (optional, traditional in Treviso)","300 g savoiardi (Italian ladyfingers — the firm kind, not the soft kind)","Unsweetened cocoa powder for dusting","A small piece of dark chocolate for shaving (optional)","Pinch of salt for the egg whites"],"ro":["500 g mascarpone, la temperatura camerei","5 ouă mari, separate, la temperatura camerei","100 g zahăr tos","250 ml espresso tare rece (aproximativ 5 ceșcuțe)","2 linguri Marsala dulce sau rom închis (opțional, tradițional la Treviso)","300 g savoiardi (pișcoturi italiene — cele ferme, nu cele moi)","Cacao amară pentru pudrare","O bucățică de ciocolată neagră pentru ras (opțional)","Un praf de sare pentru albușuri"]},"howIsMade":{"zh":"在大碗里把蛋黄和糖一起搅打 4–5 分钟——用手或电动打蛋器——直到颜色变浅、起泡、体积夸张地涨到三倍；糖必须完全溶解（在手指间搓一点试试），这里搅打不足会让你后面得到一份颗粒状的提拉米苏。把马斯卡彭分三次加入，每次都温和地搅匀，让奶油变得顺滑而光亮，再在另一只干净的碗里把蛋白和一小撮盐打到坚挺、光亮的尖角，提起打蛋器时能保持形状，然后用大刮刀分三次把蛋白翻拌入马斯卡彭中——从中心向外翻折，把空气留在里面——最终的奶油应当轻盈、近乎可倒，但仍能挂住柔软的尖。把冷的浓缩咖啡和玛萨拉酒在一只浅盘里调匀，然后把萨沃伊亚迪一根一根地蘸——只是短暂地蘸，每面最多 2 秒——它们是海绵，泡过头的女士手指饼会化成糊并把奶油哭穿，把它们紧密地铺成一层放进 22×30 cm 的盘底。在女士手指饼上铺一层均匀的一半马斯卡彭奶油，然后重复一次——再铺一层紧密蘸过的萨沃伊亚迪，再把剩下的奶油铺在上面，用刮刀刮平。盖上保鲜膜，至少冷藏 6 小时，最好一夜——当天吃的提拉米苏吃起来像它的各个部分；放过一夜的提拉米苏吃起来像一道甜点——上桌前用细筛把可可粉慷慨地撒在表面，喜欢的话再刨一点黑巧克力，切的时候用热刀，每切一片就擦一次。","en":"Whisk the egg yolks with the sugar in a large bowl for 4–5 minutes — by hand or with an electric beater — until pale, foamy and dramatically tripled in volume; the sugar should be completely dissolved when you rub a little between your fingers, undermixing here gives you a grainy tiramisu later. Add the mascarpone in three batches, whisking gently after each, until the cream is smooth and glossy, then in a separate clean bowl whisk the egg whites with a pinch of salt to firm glossy peaks that hold their shape when the whisk is lifted, and fold the whites into the mascarpone in three additions with a large spatula, folding from the centre outwards to keep the air in — the finished cream should be light, almost pourable but holding soft peaks. Mix the cold espresso and Marsala in a shallow dish, then dip the savoiardi one at a time — just briefly, 2 seconds per side at most — they are sponges, and oversoaked ladyfingers turn to mush and weep through the cream, and lay them in a tight single layer in the bottom of a 22×30 cm dish. Spread half the mascarpone cream over the ladyfingers in an even layer, then repeat — another tight layer of dipped savoiardi, then the rest of the cream on top, smoothed level with the spatula. Cover with clingfilm and refrigerate at least 6 hours, ideally overnight — tiramisu eaten the same day tastes like its parts, tiramisu rested overnight tastes like one dessert — just before serving dust the top generously with cocoa pushed through a fine sieve, shave over a little dark chocolate if you like, and cut with a hot knife wiped between slices."}},{"id":203,"servings":4,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":520,"prot":22,"carb":76,"fat":14,"fib":3},"origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"罗马奶酪黑胡椒意面","en":"Cacio e Pepe","ro":"Cacio e Pepe"},"category":{"zh":"意面","en":"Pasta","ro":"Paste"},"ingredients":{"zh":["tonnarelli 或粗款意大利面 400 克","Pecorino Romano 200 克，用细擦丝器（microplane）擦极细（不要用 Parmesan，融化方式不同）","整粒黑胡椒满满 1 汤匙，临用前在臼里现压（不要预先磨好的胡椒粉）","煮面用海盐（比平时稍少，奶酪本身就咸）"],"en":["400 g tonnarelli or thick spaghetti","200 g Pecorino Romano, finely grated on a microplane (no Parmesan — it doesn't melt the same way)","1 heaped tablespoon whole black peppercorns, freshly cracked in a mortar (not pre-ground)","Sea salt for the pasta water (less than usual, since the cheese is salty)"],"ro":["400 g tonnarelli sau spaghete groase","200 g Pecorino Romano, ras fin pe microplane (fără Parmezan — nu se topește la fel)","1 lingură plină de boabe întregi de piper negru, proaspăt zdrobite în mojaru (nu măcinat în prealabil)","Sare de mare pentru apa pastelor (mai puțină decât de obicei, fiindcă brânza este sărată)"]},"howIsMade":{"zh":"把现压的黑胡椒粒放在一只宽大的干锅里中火烘 30 秒——直到鼻子能尖锐地闻到它的香气——加入半勺冷水让烘焙停下，让胡椒形成一勺辛辣的稠汁。离火备用。\n\n烧开 3 升轻盐水，把意面煮到比 al dente 还差一点点，比包装上少煮约 1 分钟；在罗马，意面是在酱汁里完成的，不是在锅里。\n\n趁面煮的时候，从锅里舀一大马克杯的高淀粉煮面水。在一只宽口碗里，把擦细的 Pecorino 与大约 4 汤匙煮面水拌打——先让水稍冷却几秒，因为开水浇在奶酪上会立刻让它结成块——直到形成像 ricotta 一样浓稠的奶酪糊；如果太硬，再加一汤匙水稀释。\n\n用夹子把面直接从锅里夹到带胡椒的平底锅里（不要倒掉水），淋上一勺煮面水，小火不停地翻拌 30 秒，直到面条油亮、均匀挂上一层。\n\n把锅离火——Pecorino 一旦超过沸点就会瞬间抱团成纤维状——把奶酪糊倒进去再快速翻拌，必要时一汤匙一汤匙地加煮面水，直到酱汁变成一层乳化的奶油，挂住每一根面条。立刻装盘，顶部再现磨一些黑胡椒；cacio e pepe 凉得极快，所以盘子要预热，食客要坐在桌前。","en":"Toast the cracked pepper in a wide dry pan over medium heat for 30 seconds — until you can smell it sharply — and add half a ladle of cold water to stop the cooking and create a peppery slurry. Set aside off the heat.\n\nBring 3 L of lightly salted water to a boil and cook the pasta until just shy of al dente, about a minute less than the package says; in Rome the pasta finishes cooking in the sauce, not in the pot.\n\nWhile the pasta cooks, scoop out a mug of starchy water from the pot. In a wide bowl, whisk the grated Pecorino with about 4 tablespoons of the hot pasta water — let it cool a few seconds first, since boiling water on cheese clumps it instantly — until you have a thick, ricotta-like paste; loosen with another spoonful of water if it's too stiff.\n\nLift the pasta from the pot with tongs straight into the peppered pan (don't drain it), splash in a ladle of starchy water, and toss vigorously over low heat for 30 seconds, until the pasta is glossy and well coated.\n\nTake the pan off the heat — Pecorino above boiling point seizes into stringy clumps — pour over the cheese paste and toss again, fast, adding more pasta water by the spoonful if needed, until the sauce becomes a creamy emulsion that clings to every strand. Plate immediately with another crack of pepper on top; cacio e pepe cools quickly, so plates should be warm and diners at the table."}},{"id":204,"servings":4,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":720,"prot":42,"carb":28,"fat":48,"fib":4},"origin":{"zh":"印度","en":"India","ro":"India"},"name":{"zh":"黄油鸡 (Murgh Makhani)","en":"Butter Chicken (Murgh Makhani)","ro":"Butter Chicken (Murgh Makhani)"},"category":{"zh":"咖喱","en":"Curry","ro":"Curry"},"ingredients":{"zh":["去骨鸡腿肉 800 克，切成 4 厘米的块","腌料：全脂酸奶 200 克、姜蒜泥 2 汤匙、克什米尔红辣椒粉 1 茶匙、garam masala 1 茶匙、半个柠檬的汁、中性油 2 汤匙、盐 1 茶匙","酱底：成熟番茄 800 克（或大罐 chopped tomatoes 1 罐）、生腰果 60 克、大洋葱 1 个切四瓣、蒜瓣 4 个、姜 3 厘米、绿豆蔻荚 4 颗、肉桂棒 1 根、丁香 4 颗、月桂叶 1 片","无盐黄油 80 克、淡奶油 200 毫升","kasoori methi（干胡芦巴叶）1 汤匙","克什米尔红辣椒粉 1 茶匙、garam masala 1 茶匙、糖 1 茶匙、盐","新鲜香菜，最后撒上"],"en":["800 g boneless chicken thighs, cut into 4 cm pieces","For the marinade: 200 g full-fat yoghurt, 2 tbsp ginger-garlic paste, 1 tsp Kashmiri red chilli powder, 1 tsp garam masala, juice of half a lemon, 2 tbsp neutral oil, 1 tsp salt","For the gravy: 800 g ripe tomatoes (or 1 large can chopped tomatoes), 60 g raw cashews, 1 large onion quartered, 4 garlic cloves, 3 cm piece of ginger, 4 green cardamom pods, 1 cinnamon stick, 4 cloves, 1 bay leaf","80 g unsalted butter, 200 ml double cream","1 tbsp kasoori methi (dried fenugreek leaves)","1 tsp Kashmiri red chilli powder, 1 tsp garam masala, 1 tsp sugar, salt","Fresh coriander to finish"],"ro":["800 g pulpe de pui dezosate, tăiate în bucăți de 4 cm","Pentru marinadă: 200 g iaurt gras, 2 linguri pastă de ghimbir-usturoi, 1 linguriță boia Kashmiri, 1 linguriță garam masala, zeama de la o jumătate de lămâie, 2 linguri ulei neutru, 1 linguriță sare","Pentru sosul de bază: 800 g roșii coapte (sau o cutie mare de roșii tocate), 60 g caju crud, 1 ceapă mare în sferturi, 4 căței de usturoi, 3 cm bucată de ghimbir, 4 capsule de cardamom verde, 1 baton de scorțișoară, 4 cuișoare, 1 frunză de dafin","80 g unt nesărat, 200 ml smântână grasă","1 lingură kasoori methi (frunze uscate de schinduf)","1 linguriță boia Kashmiri, 1 linguriță garam masala, 1 linguriță zahăr, sare","Coriandru proaspăt pentru a încheia"]},"howIsMade":{"zh":"在一只宽碗里调匀腌料，加入鸡肉，将每块翻匀，盖好放入冰箱冷藏至少 4 小时，最好一夜。做酱汁：腰果用 100 毫升热水泡 20 分钟；把番茄、洋葱、大蒜、生姜和整粒香料放进一只厚锅，加 200 毫升水，烧至微沸，盖盖煮 20–25 分钟，直到番茄塌陷、洋葱完全软，然后捞出肉桂、豆蔻、丁香和月桂叶，把剩下的所有材料——包括泡过的腰果和泡水——一起打成丝滑顺滑的酱，过筛回锅。把烤箱开到最高档，烤盘铺锡纸，把腌好的鸡肉单层铺开、块与块之间留空隙，放在距热源 5–6 cm 的位置每面烤 6–8 分钟，直到边缘焦黑、肉刚好熟透——让边缘真正变深。把黄油在宽锅里中火融化，倒入过筛的酱汁，加辣椒粉、糖和 1 茶匙盐，小火慢煮 10 分钟，常搅拌，直到颜色加深为浓郁的砖橙色；倒入奶油，搅拌至酱汁变为天鹅绒般顺滑，再把烤好的鸡肉连同烤盘里的汁滑入锅中，一起再咕嘟咕嘟 4–5 分钟。在锅上把卡苏里葛缕子在手心揉碎撒入，拌入葛兰玛萨拉，尝咸甜，撒上香菜叶，配 naan 或 basmati 米饭享用。","en":"Mix the marinade in a wide bowl, add the chicken and turn each piece until well coated, then cover and chill at least 4 hours, ideally overnight. For the gravy, soak the cashews in 100 ml of hot water for 20 minutes; put the tomatoes, onion, garlic, ginger and whole spices into a heavy pan with 200 ml of water, bring to a simmer and cook covered for 20–25 minutes until the tomatoes have collapsed and the onion is fully soft, then fish out the cinnamon, cardamom, cloves and bay leaf, and blend everything — including the soaked cashews and their water — to a velvety purée and pass through a sieve. Heat the broiler high, line a tray with foil, spread the marinated chicken in a single layer with space between the pieces and broil 5–6 cm from the heat for 6–8 minutes per side, until the edges are charred and the meat is just cooked through — let the edges go genuinely dark. Melt the butter in a wide pan over medium heat, pour in the strained gravy and add the chilli powder, sugar and a teaspoon of salt, simmer gently for 10 minutes stirring often until the colour deepens to a rich brick-orange; pour in the cream, stir until the gravy turns velvet, then slide in the charred chicken with any juices from the tray and let everything bubble together for 4–5 minutes more. Crush the kasoori methi between your palms over the pan, stir in the garam masala and taste for salt and sugar, scatter coriander leaves on top, and serve with naan or basmati rice."}},{"id":205,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":780,"prot":38,"carb":78,"fat":32,"fib":3},"origin":{"zh":"印度","en":"India","ro":"India"},"name":{"zh":"海得拉巴风味羊肉香饭","en":"Hyderabadi Lamb Biryani","ro":"Biryani de miel din Hyderabad"},"category":{"zh":"主菜","en":"Main","ro":"Fel principal"},"ingredients":{"zh":["带骨羊肩或羊腿 800 克，切成 4 厘米的块","巴斯马蒂米 500 克，冷水浸泡 30 分钟后沥干","大洋葱 4 个，切极薄（约 600 克）","全脂酸奶 200 克","酥油（ghee）50 克 + 中性油 80 毫升","姜蒜泥 3 汤匙","青辣椒 2 根，纵向划开","克什米尔红辣椒粉 2 茶匙、姜黄 1 茶匙、盐 1 茶匙","整粒香料：肉桂棒 1 根、绿豆蔻 4 颗 + 黑豆蔻 2 颗、丁香 4 颗、月桂叶 1 片、shahi jeera（皇家孜然）1 茶匙、黑胡椒粒 1 茶匙","一撮藏红花用 60 毫升温热全脂牛奶浸泡","柠檬 1 个的汁","切碎薄荷 2 汤匙、切碎香菜 2 汤匙","玫瑰水 1 汤匙（可选，传统配方）","封口用的软面团一小块或厚锡纸一张"],"en":["800 g bone-in lamb shoulder or leg, cut into 4 cm pieces","500 g basmati rice, soaked 30 minutes in cold water and drained","4 large onions, very thinly sliced (about 600 g)","200 g full-fat yoghurt","50 g ghee + 80 ml neutral oil","3 tbsp ginger-garlic paste","2 green chillies, slit lengthwise","2 tsp Kashmiri red chilli powder, 1 tsp turmeric, 1 tsp salt","Whole spices: 1 cinnamon stick, 4 green cardamom + 2 black cardamom, 4 cloves, 1 bay leaf, 1 tsp shahi jeera, 1 tsp black peppercorns","A pinch of saffron infused in 60 ml warm whole milk","Juice of 1 lemon","2 tbsp chopped mint and 2 tbsp chopped coriander","1 tbsp rose water (optional, traditional)","A piece of soft dough or a sheet of heavy foil for sealing"],"ro":["800 g spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","500 g orez basmati, înmuiat 30 de minute în apă rece și scurs","4 cepe mari, tăiate foarte subțire (aproximativ 600 g)","200 g iaurt gras","50 g ghee + 80 ml ulei neutru","3 linguri pastă de ghimbir-usturoi","2 ardei iuți verzi, despicați pe lungime","2 lingurițe boia Kashmiri, 1 linguriță turmeric, 1 linguriță sare","Mirodenii întregi: 1 baton de scorțișoară, 4 capsule cardamom verde + 2 cardamom negru, 4 cuișoare, 1 frunză de dafin, 1 linguriță shahi jeera, 1 linguriță boabe de piper negru","Un vârf de șofran infuzat în 60 ml lapte cald","Sucul de la 1 lămâie","2 linguri mentă tocată și 2 linguri coriandru tocat","1 lingură apă de trandafiri (opțional, tradițional)","O bucată de aluat moale sau o folie groasă pentru sigilare"]},"howIsMade":{"zh":"在一只宽厚的锅中以中火加热酥油和油，慢慢地把切片洋葱炒 25–30 分钟，频繁搅拌，直到颜色变得深金棕色（birista），然后捞出在纸上沥干，把油留在锅里，留一半洋葱用于分层。把羊肉与酸奶、姜蒜泥、用手捏碎的一半炸洋葱、辣椒粉、姜黄、盐、柠檬汁和 1 茶匙 shahi jeera 混合，充分搅拌，腌制至少 2 小时或一夜放冰箱；把腌好的羊肉放回保留的洋葱油中，加入肉桂、豆蔻、丁香和月桂叶，盖盖小火炖 1 小时到 1 小时 15 分钟，直到羊肉变嫩、酱汁收浓成厚厚一层。把一只深锅的咸水大火烧开，加入其余的整粒香料和 1 汤匙油，倒入泡好的 basmati 米，只煮 4–5 分钟，直到米粒变长、大约七分熟——剩下的会在蒸汽中完成——然后迅速、轻柔地沥干。在同一只锅中羊肉上方，把米均匀铺开，在顶上撒上剩下的炸洋葱、切碎的薄荷和香菜以及青辣椒，然后将藏红花牛奶以缓慢的细线浇过表面，玫瑰水若用也是。用湿面团条或紧密的铝箔密封锅盖，放在最小火上 25–30 分钟，然后不掀盖关火，密封再静置 10 分钟——在餐桌上打开密封，把一只长勺插到锅底直直舀起，让每份都同时带米和肉，绝不搅拌在一起。","en":"Heat the ghee and oil in a wide heavy pan over medium heat and fry the sliced onions slowly for 25–30 minutes, stirring often, until deeply golden brown (birista), then drain on paper, reserve the oil in the pan and keep half the onions for layering. Combine the lamb with the yoghurt, ginger-garlic paste, half of the fried onions crushed in your hand, chilli powder, turmeric, salt, lemon juice and a teaspoon of the shahi jeera, mix thoroughly and rest at least 2 hours or overnight in the fridge; tip the marinated lamb back into the reserved onion oil, add the cinnamon, cardamom, cloves and bay leaf, and cook covered over low heat for an hour to an hour and a quarter, until the lamb is tender and the gravy has reduced to a thick coating. Bring a deep pot of well-salted water to a rolling boil with the rest of the whole spices and a tablespoon of oil, add the soaked basmati and cook just 4–5 minutes until the grains have lengthened and are about three-quarters done — they finish in the steam — then drain quickly and gently. In the same pan over the lamb, spread the rice evenly, scatter the remaining fried onions, chopped mint and coriander, and the green chillies on top, then drizzle the saffron milk in slow streaks across the surface and the rose water if using. Seal the lid with a strip of wet dough or a tight wrap of foil, set on the lowest heat for 25–30 minutes, then turn off the flame without lifting the lid and rest sealed for another 10 minutes — break the seal at the table and plunge a long spoon to the bottom to lift straight up, so each portion comes out with both rice and meat, never stirred together."}},{"id":206,"servings":4,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":480,"prot":22,"carb":18,"fat":36,"fib":5},"origin":{"zh":"印度","en":"India","ro":"India"},"name":{"zh":"印度菠菜奶酪","en":"Palak Paneer","ro":"Palak Paneer"},"category":{"zh":"咖喱","en":"Curry","ro":"Curry"},"ingredients":{"zh":["新鲜菠菜 500 克（或冷冻 250 克，解冻后用）","印度奶酪 paneer 250 克，切 2 厘米方块","大洋葱 1 个，切细末","成熟番茄 2 个，切碎（或罐装碎番茄 200 克）","蒜瓣 3 个与 2 厘米姜，一起剁泥","青辣椒 2 根","孜然籽 1 茶匙","香菜粉 1 茶匙、克什米尔红辣椒粉 1 茶匙、姜黄 ½ 茶匙、garam masala 1 茶匙","kasoori methi（干胡芦巴叶）1 汤匙","淡奶油 80 毫升、酥油（ghee）3 汤匙","盐适量","上桌时撒一小撮切丝的鲜姜"],"en":["500 g fresh spinach (or 250 g frozen, defrosted)","250 g paneer, cut into 2 cm cubes","1 large onion, finely chopped","2 ripe tomatoes, chopped (or 200 g chopped tomatoes)","3 garlic cloves and 2 cm piece of ginger, minced together","2 green chillies","1 tsp cumin seeds","1 tsp coriander powder, 1 tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp garam masala","1 tbsp kasoori methi (dried fenugreek leaves)","80 ml double cream, 3 tbsp ghee","Salt to taste","A small piece of fresh ginger, julienned, to finish"],"ro":["500 g spanac proaspăt (sau 250 g congelat, dezghețat)","250 g paneer, tăiat cuburi de 2 cm","1 ceapă mare, tocată mărunt","2 roșii coapte, tocate (sau 200 g roșii tocate)","3 căței de usturoi și o bucată de 2 cm de ghimbir, tocate împreună","2 ardei iuți verzi","1 linguriță semințe de chimion","1 linguriță coriandru pudră, 1 linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță garam masala","1 lingură kasoori methi (frunze uscate de schinduf)","80 ml smântână grasă, 3 linguri ghee","Sare după gust","O bucățică mică de ghimbir proaspăt, tăiată julien, pentru finisat"]},"howIsMade":{"zh":"把一大锅水烧开，将菠菜焯 90 秒后立刻转入一碗冰水中，沥干、轻轻挤干水分，再与其中一根青辣椒和几汤匙凉水一起打成顺滑的菠菜泥。在一只宽锅中烧热一汤匙酥油，把帕尼尔奶酪小块在中火上每面煎 2–3 分钟至浅金色，捞出放在纸上，或者把它们泡进一碗温盐水里，等其他配料煮好再说。同一只锅里加入剩下的酥油和孜然籽，让它们爆香 30 秒，下洋葱炒 8–10 分钟，至变软且边缘金黄，再加入姜蒜泥和第二根剖开的青辣椒，再炒一分钟。加入切碎的番茄、香菜末、辣椒粉、姜黄和一茶匙盐，炒 6–8 分钟，直到马萨拉变得果酱般浓稠、油从边缘开始析出，然后倒入菠菜泥和 100 毫升水，搅匀，轻火炖 5 分钟。把帕尼尔小块滑入酱汁中，淋入奶油，把卡苏里葛缕子在掌心揉碎撒入锅里，再撒上葛兰玛萨拉，再加热 2 分钟，尝咸淡，最后顶上摆一小把姜丝，配上 naan、paratha 或巴斯马蒂米饭享用。","en":"Bring a large pot of water to a boil, blanch the spinach for 90 seconds and transfer immediately to a bowl of ice water, then drain, squeeze gently and blend to a smooth purée with one of the green chillies and a few tablespoons of cold water. Heat a tablespoon of ghee in a wide pan and fry the paneer cubes over medium heat for 2–3 minutes per side until lightly gold, then lift onto paper or slip them into a bowl of warm salted water while everything else cooks. In the same pan add the remaining ghee and the cumin seeds and let them sizzle for 30 seconds, tip in the onion and cook 8–10 minutes until soft and golden at the edges, then add the ginger-garlic paste and the second slit green chilli and cook a minute more. Stir in the chopped tomato with the coriander, chilli powder, turmeric and a teaspoon of salt and cook 6–8 minutes until the masala is jammy and the oil starts to separate at the edges, then pour in the spinach purée and 100 ml of water, stir well and simmer gently for 5 minutes. Slide the paneer cubes into the gravy, swirl in the cream, crush the kasoori methi between your palms over the pan and sprinkle the garam masala, heat through for another 2 minutes, taste for salt, finish with julienned ginger on top, and serve with naan, paratha or basmati."}},{"id":207,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":620,"prot":40,"carb":12,"fat":44,"fib":2},"origin":{"zh":"印度","en":"India","ro":"India"},"name":{"zh":"克什米尔咖喱羊肉","en":"Rogan Josh","ro":"Rogan Josh"},"category":{"zh":"咖喱","en":"Curry","ro":"Curry"},"ingredients":{"zh":["1 公斤带骨羊肩或羊腿肉，切成 4 厘米的块","4 汤匙芥末油","200 克全脂酸奶，搅打顺滑","克什米尔干红辣椒 4 根，温水浸泡 20 分钟后磨成糊（或 2 汤匙克什米尔红辣椒粉）","1 茶匙茴香粉","1 茶匙干姜粉（sonth）","½ 茶匙阿魏（hing）","整粒香料：绿豆蔻 8 颗 + 黑豆蔻 2 颗、肉桂棒 1 根、丁香 6 颗、月桂叶 1 片","1 茶匙盐","一撮藏红花，用 2 汤匙温牛奶浸泡"],"en":["1 kg bone-in lamb shoulder or leg, cut into 4 cm pieces","4 tbsp mustard oil","200 g full-fat yoghurt, whisked smooth","4 dried Kashmiri red chillies, soaked in warm water 20 minutes and ground to a paste (or 2 tbsp Kashmiri chilli powder)","1 tsp fennel powder","1 tsp dried ginger powder (sonth)","½ tsp asafoetida (hing)","Whole spices: 8 green cardamom + 2 black cardamom, 1 cinnamon stick, 6 cloves, 1 bay leaf","1 tsp salt","A pinch of saffron, soaked in 2 tbsp warm milk"],"ro":["1 kg spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","4 linguri ulei de muștar","200 g iaurt gras, bătut neted","4 ardei roșii Kashmiri uscați, înmuiați 20 de minute în apă caldă și pisați pastă (sau 2 linguri boia Kashmiri)","1 linguriță pudră de fenicul","1 linguriță pudră de ghimbir uscat (sonth)","½ linguriță asafoetida (hing)","Mirodenii întregi: 8 capsule cardamom verde + 2 cardamom negru, 1 baton de scorțișoară, 6 cuișoare, 1 frunză de dafin","1 linguriță sare","Un vârf de șofran, infuzat în 2 linguri lapte cald"]},"howIsMade":{"zh":"在厚重的锅里把芥末油烧到刚刚开始冒烟，然后离火片刻——冒烟可以让油的辛辣味变温和，又不会烧焦——再放回中火上，加入整粒香料和月桂叶，让它们在油里飘香 30 秒。把羊肉单层下锅，把每一面都好好煎 8–10 分钟（这是整道菜唯一一次煎色，所以请让颜色真正出来），加入阿魏、姜粉和茴香粉，让它们在热油里包裹羊肉再 1 分钟。把酸奶与克什米尔辣椒糊和 1 汤匙冷水一起搅打，然后一勺一勺地加入锅里，每加一勺都不停搅拌——慢慢加，酸奶就不会分离——加盐，调小火，盖盖煮 10 分钟，直到酸奶融化成发亮的红色基底。倒入 500 毫升热水，再煮至微沸，然后转最小火盖盖炖 1 小时 20 分钟，每 20 分钟搅一次，直到羊肉一压就散、酱汁稀薄发亮、呈深红木色；最后 5 分钟把藏红花牛奶轻轻拌入，只是稍稍带过即可。离火静置 10 分钟，再配蒸 basmati 米饭上桌——Rogan Josh 应当像一碗轻盈的汤，颜色鲜亮、香气浓郁，而不是辣味突出，辣味来自羊肉本身，颜色来自辣椒，香气来自其余一切。","en":"Heat the mustard oil in a heavy pan until it just begins to smoke, then pull it off the heat for a moment — letting it smoke neutralises the raw pungency without scorching — and return to medium heat, add the whole spices and bay leaf, and let them perfume the oil for 30 seconds. Add the lamb in a single layer and brown well on all sides for 8–10 minutes (this is the only browning the dish gets, so let the colour develop properly), then stir in the asafoetida, ginger powder and fennel powder and let them coat the meat in the hot oil for another minute. Whisk the yoghurt with the Kashmiri chilli paste and a tablespoon of cold water, then add it to the pan a ladleful at a time stirring continuously after each addition — going slowly keeps the yoghurt from splitting — add the salt, lower the heat and cook covered for 10 minutes until the yoghurt has melted into a glossy red base. Pour in 500 ml of hot water, bring back to a simmer, then drop the heat to its lowest and braise covered for an hour and 20 minutes, stirring every 20 minutes, until the lamb yields to a spoon and the gravy is thin, glossy and a deep mahogany red; swirl the saffron milk through 5 minutes before the end without fully stirring it out. Rest off the heat for 10 minutes before serving with steamed basmati — Rogan Josh is meant to be soup-like, brilliantly coloured and aromatic rather than spicy hot, the heat supplied by the meat, the colour by the chillies, and the perfume by everything else."}},{"id":208,"servings":8,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":280,"prot":6,"carb":32,"fat":14,"fib":3},"origin":{"zh":"印度","en":"India","ro":"India"},"name":{"zh":"印度三角咖喱角","en":"Samosa","ro":"Samosa"},"category":{"zh":"小吃","en":"Snack","ro":"Gustare"},"ingredients":{"zh":["面团：中筋面粉 300 克、ajwain（藏茴香）籽 1 茶匙、盐 ½ 茶匙、酥油（ghee）或中性油 60 毫升、冷水 120 毫升","馅料：粉糯的土豆 500 克、冷冻豌豆 100 克、中性油 2 汤匙、孜然籽 1 茶匙、青辣椒 1 根剁末、2 厘米姜剁末","香菜粉 1 茶匙、garam masala 1 茶匙、克什米尔辣椒粉 ½ 茶匙、姜黄 ½ 茶匙、amchur（干芒果粉）1 茶匙、盐 1 茶匙","新鲜香菜一小把，切碎","用于深炸的中性油约 1 升","搭配上桌：罗望子甜酸 chutney 与薄荷-香菜 chutney"],"en":["For the pastry: 300 g plain flour, 1 tsp ajwain (carom) seeds, ½ tsp salt, 60 ml ghee or neutral oil, 120 ml cold water","For the filling: 500 g floury potatoes (Maris Piper or Russet), 100 g frozen peas, 2 tbsp neutral oil, 1 tsp cumin seeds, 1 green chilli minced, 2 cm piece of ginger minced","1 tsp coriander powder, 1 tsp garam masala, ½ tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp amchur (dried mango powder), 1 tsp salt","A handful of fresh coriander, chopped","About 1 L neutral oil for deep-frying","To serve: tamarind chutney and mint-coriander chutney"],"ro":["Pentru aluat: 300 g făină albă, 1 linguriță semințe de ajwain (chimen-aristotel), ½ linguriță sare, 60 ml ghee sau ulei neutru, 120 ml apă rece","Pentru umplutură: 500 g cartofi făinoși (Maris Piper sau Russet), 100 g mazăre congelată, 2 linguri ulei neutru, 1 linguriță semințe de chimion, 1 ardei iute verde tocat, 2 cm bucată de ghimbir tocat","1 linguriță coriandru pudră, 1 linguriță garam masala, ½ linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță amchur (pudră de mango uscat), 1 linguriță sare","Un mănunchi de coriandru proaspăt, tocat","Aproximativ 1 l ulei neutru pentru prăjit","Pentru servit: chutney de tamarind și chutney de mentă-coriandru"]},"howIsMade":{"zh":"用指尖把酥油搓进面粉、ajwain 和盐里，直到混合物像粗面包屑——这层油脂的份量正是给 samosa 外壳那种带气泡、像饼干一样酥脆的关键——冷水一汤匙一汤匙地加，揉成一团硬而光滑的面团（比 chapati 软、比面包面团硬），盖好醒 30 分钟。带皮把土豆煮到刚熟，捞出剥皮，用叉背粗略地碾碎（要的是颗粒，不是泥）；在宽锅中热油，下孜然籽爆香，再下姜和青辣椒炒 30 秒，加入干性香料快速炒一下，倒入土豆、豌豆、盐、amchur 和切碎的香菜，翻拌 4–5 分钟，让每一块都裹上香料——冷却到室温再开始包。面团分成 8 个小球，把一个擀成一个长约 18 厘米的薄椭圆，再从中间一切两半得到两个半圆；取一个半圆，在直边上刷一条细水线，将直边的两个角合到一起、交叠 1 厘米折成一个圆锥，把接缝用力捏紧封死。一只手托住圆锥，把土豆馅填到三分之二满，再把开口处的一边折一个小褶，用湿手指把口完全封死——这一小折就是 samosa 标志性的侧棱，也让它在油里能立得住——其余照做。把油加热到 150°C（比想象中低，但慢慢升温正是外壳起泡的关键），每次下 3–4 个 samosa 炸 6–7 分钟，轻轻翻动，让它呈淡金色，然后把油温升到 180°C 再炸 3–4 分钟，直到呈深金色、真正酥脆，沥在网架上，趁热配上罗望子和薄荷-香菜 chutney 享用。","en":"Rub the ghee into the flour, ajwain and salt with your fingertips until the mixture resembles coarse breadcrumbs — the amount of fat is what gives samosa pastry its blistered, biscuit-crisp shell — then add the cold water a tablespoon at a time, mixing into a stiff smooth dough (softer than chapati but firmer than bread dough) and rest it covered for 30 minutes. Boil the potatoes in their skins until just tender, drain, peel and crush coarsely with the back of a fork (you want texture, not mash); heat the oil in a wide pan, add the cumin seeds and let them sizzle, then the ginger and green chilli for 30 seconds, stir in the dry spices and fry briefly, tip in the potato, peas, salt, amchur and coriander, and cook 4–5 minutes turning everything until the spices coat every piece — cool to room temperature before shaping. Divide the dough into 8 balls, roll one into a thin oval about 18 cm long and cut across the middle to make two half-circles; take one half, brush a thin line of water along the straight edge, and fold into a cone by bringing the two corners of the straight edge together so they overlap by 1 cm, pinching the seam tightly to seal. Hold the cone in one hand, fill it three-quarters with potato, then pleat the open edge by folding a small tuck on one side and sealing the rim shut with a damp finger — the tucked pleat creates the samosa's signature side ridge and helps it sit upright while cooking — and repeat with the rest. Heat the frying oil to 150°C (lower than you might expect, but the slow climb is what gives the shell its blisters), slip in the samosas in batches of 3 or 4 and fry 6–7 minutes turning gently until pale gold, then raise the heat to 180°C and fry another 3–4 minutes until deep golden and properly crisp, draining on a rack and serving hot with tamarind and mint chutneys."}},{"id":209,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":620,"prot":32,"carb":22,"fat":44,"fib":5},"origin":{"zh":"泰国","en":"Thailand","ro":"Thailanda"},"name":{"zh":"泰式青咖喱 (Gaeng Khiao Wan)","en":"Green Curry (Gaeng Khiao Wan)","ro":"Curry verde (Gaeng Khiao Wan)"},"category":{"zh":"咖喱","en":"Curry","ro":"Curry"},"ingredients":{"zh":["青咖喱酱 4 汤匙（自制或泰国好品牌如 Mae Ploy）","全脂椰奶 400 毫升（Aroy-D 最佳）","椰浆 200 毫升（罐顶那层浓稠部分，或 100 毫升加撇起的浓部分）","鸡腿肉 500 克，切成 3 厘米的块","泰国茄子 4 个，切四瓣（或亚洲小茄子 1 个切块）","豌豆茄子一小把（主要装饰，可选）","竹笋片 100 克","卡菲尔青柠叶 4 片，撕碎（去叶柄）","长红辣椒 2 根，斜切薄片","棕榈糖 1 汤匙（或浅红糖）","泰国鱼露 2 汤匙","泰国罗勒（horapha）一小把","茉莉香米饭，配菜"],"en":["4 tbsp green curry paste (homemade, or a good Thai brand like Mae Ploy)","400 ml full-fat coconut milk (Aroy-D is ideal)","200 ml coconut cream (the thick top layer from the can, or 100 ml plus the skimmed cream)","500 g chicken thighs, cut into 3 cm pieces","4 Thai eggplants, quartered (or 1 small Asian eggplant cubed)","A small handful of pea eggplants (mainly garnish, optional)","100 g bamboo shoots, sliced","4 kaffir lime leaves, torn (stem removed)","2 long red chillies, sliced thinly on the bias","1 tbsp palm sugar (or light brown sugar)","2 tbsp Thai fish sauce","A small handful of Thai basil leaves (horapha)","Jasmine rice to serve"],"ro":["4 linguri pastă curry verde (de casă sau o marcă thailandeză bună precum Mae Ploy)","400 ml lapte de cocos gras (ideal Aroy-D)","200 ml smântână de cocos (stratul gros de deasupra cutiei, sau 100 ml plus crema rămasă)","500 g pulpe de pui, tăiate în bucăți de 3 cm","4 vinete thailandeze, tăiate în sferturi (sau 1 vânătă asiatică mică, cuburi)","Un mic mănunchi de vinete-mazăre (în principal pentru garnitură, opțional)","100 g vârfuri de bambus, feliate","4 frunze de lămâi kaffir, rupte (codița înlăturată)","2 ardei roșii lungi, feliați subțire în diagonală","1 lingură zahăr de palmier (sau zahăr brun deschis)","2 linguri sos de pește thailandez","Un mic mănunchi de busuioc thailandez (horapha)","Orez iasomie pentru servit"]},"howIsMade":{"zh":"在中火上的炒锅或厚锅里舀入椰浆，让它煮 4–5 分钟、间或搅拌，直到油从浆里裂出、浆面泛起油亮的光泽——这一步打底，正是把泰国餐厅的青咖喱与家里清汤寡水的版本区分开来的关键。把青咖喱酱加入裂开的椰浆中，不停搅拌炒 2–3 分钟，直到酱色变深、释放出南姜、香茅和泰国罗勒的香气，油泛起鲜亮的青绿色——整个厨房会闻起来像曼谷的一条小街。下鸡肉，在酱里翻动每一块至完全裹上，炒 3–4 分钟到肉半熟，再倒入椰奶，慢慢加热到微微沸腾；加入茄子、竹笋和撕碎的卡菲尔青柠叶，不盖锅煮 10–12 分钟，直到茄子变软、鸡肉刚刚熟透。用鱼露和棕榈糖调味，边尝边加——这锅咖喱应当同时打中咸、甜、清新的草本香、和那种干净利落的青辣椒辣味——最后撒上红辣椒丝和泰国罗勒，把锅晃一下，30 秒后离火，这样罗勒在碗里还能保持翠绿。用浅口碗盛装，旁边配一碗茉莉香米饭。","en":"In a wok or heavy pan over medium heat, spoon in the coconut cream and let it cook for 4–5 minutes, stirring occasionally, until the oil cracks out and the cream takes on a slick sheen — this foundation step is what separates Thai-restaurant green curry from the watery home version. Add the green curry paste to the split cream and fry for 2–3 minutes, stirring constantly, until the paste darkens, releases its perfume of galangal, lemongrass and Thai basil, and the oil turns a vivid green — the kitchen will smell like a Bangkok back street. Slide in the chicken and turn the pieces in the paste until coated, cook 3–4 minutes until the meat is half-sealed, then pour in the coconut milk and bring to a gentle simmer; add the eggplants, bamboo shoots and torn kaffir lime leaves, and simmer uncovered for 10–12 minutes until the eggplants are tender and the chicken is just cooked through. Season with the fish sauce and palm sugar, tasting as you go — the curry should hit salty, sweet, herbaceous and a clean green chilli heat all at once — then stir in the sliced red chillies and Thai basil, swirl the pan once and take it off the heat after 30 seconds so the basil stays bright in the bowl. Serve in shallow bowls with jasmine rice on the side."}},{"id":210,"servings":6,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":680,"prot":36,"carb":38,"fat":42,"fib":6},"origin":{"zh":"泰国","en":"Thailand","ro":"Thailanda"},"name":{"zh":"玛沙曼咖喱牛肉","en":"Massaman Curry","ro":"Massaman"},"category":{"zh":"咖喱","en":"Curry","ro":"Curry"},"ingredients":{"zh":["玛沙曼咖喱酱 4 汤匙（Mae Ploy 是稳妥的选择）","牛腱或牛肩肉 1 公斤，切成 5 厘米方块","全脂椰奶 800 毫升","椰浆 200 毫升","蜡质土豆（Charlotte 或 Yukon Gold）500 克，去皮切 4 厘米块","小洋葱 2 个，去皮切四瓣","烤过的无盐花生 100 克（取几粒拍碎作点缀）","整粒香料：豆蔻荚 5 颗、肉桂棒 1 根、丁香 4 颗、八角 1 颗、月桂叶 1 片","罗望子膏 3 汤匙（或 1 个青柠的汁作替代）","棕榈糖 3 汤匙","泰国鱼露 3 汤匙","卡菲尔青柠叶 4 片，撕碎","茉莉香米饭，配菜"],"en":["4 tbsp Massaman curry paste (Mae Ploy is reliable)","1 kg beef shin or chuck, cut into 5 cm cubes","800 ml full-fat coconut milk","200 ml coconut cream","500 g waxy potatoes (Charlotte or Yukon Gold), peeled and cut into 4 cm chunks","2 small onions, peeled and quartered","100 g roasted unsalted peanuts (a few crushed for garnish)","Whole spices: 5 cardamom pods, 1 cinnamon stick, 4 cloves, 1 star anise, 1 bay leaf","3 tbsp tamarind paste (or juice of 1 lime as a back-up)","3 tbsp palm sugar","3 tbsp Thai fish sauce","4 kaffir lime leaves, torn","Jasmine rice to serve"],"ro":["4 linguri pastă Massaman (Mae Ploy este o alegere sigură)","1 kg rasol sau pulpă de vită, tăiată în cuburi de 5 cm","800 ml lapte de cocos gras","200 ml smântână de cocos","500 g cartofi cu textură fermă (Charlotte sau Yukon Gold), curățați și tăiați în bucăți de 4 cm","2 cepe mici, curățate și tăiate în sferturi","100 g arahide prăjite nesărate (câteva zdrobite pentru ornat)","Mirodenii întregi: 5 capsule cardamom, 1 baton de scorțișoară, 4 cuișoare, 1 anason stelat, 1 frunză de dafin","3 linguri pastă de tamarind (sau zeama de la 1 lime de rezervă)","3 linguri zahăr de palmier","3 linguri sos de pește thailandez","4 frunze de lămâi kaffir, rupte","Orez iasomie pentru servit"]},"howIsMade":{"zh":"把椰浆放入厚锅中火加热，煮 5 分钟、间或搅拌，直到油分离、椰浆变得油亮、略呈颗粒。加入玛沙曼咖喱酱和整粒香料，炒 3 分钟——咖喱酱会变深，整个厨房会飘出肉桂、豆蔻和烤孜然的香气；这一步早早“激活”香料，正是玛沙曼那种带波斯气息厚度的来源。加入牛肉块，在酱里翻动，让每一块都裹上深红色，倒入椰奶、罗望子膏和卡菲尔青柠叶，慢慢加热到刚刚冒泡，盖子半盖小火炖 1 小时 30 分钟，每 20 分钟搅一次——当一压就开但还能保持形状时，牛肉就好了。加入土豆块、洋葱和花生，不盖锅继续煮 30 分钟，直到土豆软透、酱汁收成油亮的深棕色；最后加入鱼露和棕榈糖，慢慢平衡咸-甜-酸的三角，直到味道既深又圆，不过甜也不刺。离火静置 10 分钟，然后盛在浅口碗里配茉莉香米饭，顶上撒一点拍碎的花生——玛沙曼是泰国咖喱里那种隔夜更好吃的版本，剩下的明天会更香。","en":"Spoon the coconut cream into a heavy pot over medium heat and let it cook for 5 minutes, stirring, until the oil separates and the cream looks glossy and slightly grainy. Add the Massaman paste and the whole spices and fry for 3 minutes — the paste will darken and the kitchen should smell of cinnamon, cardamom and roasted cumin; this early bloom of the spices is what gives Massaman its Persian-inflected depth. Add the beef and turn it in the paste until every piece is dark red, pour in the coconut milk, tamarind paste and kaffir lime leaves, bring to a bare simmer and braise gently with the lid ajar for an hour and a half, stirring every 20 minutes — the beef is ready when it gives easily to a spoon but still holds its shape. Slide in the potatoes, onions and peanuts and continue cooking uncovered for another 30 minutes until the potatoes are tender and the gravy has thickened to a glossy rich brown; stir in the fish sauce and palm sugar at the end, balancing the salt-sweet-sour triangle until it tastes deep and round, neither too sweet nor too sharp. Rest off the heat for 10 minutes, then serve in shallow bowls with jasmine rice, scattered with a few crushed peanuts on top — Massaman is the Thai curry that gains depth overnight, and any leftovers taste better the next day."}},{"id":211,"servings":4,"tipType":"veg","pairingsType":"thai","nutrition":{"cal":180,"prot":6,"carb":28,"fat":6,"fib":4},"origin":{"zh":"泰国","en":"Thailand","ro":"Thailanda"},"name":{"zh":"泰式青木瓜沙拉","en":"Som Tam","ro":"Som Tam"},"category":{"zh":"沙拉","en":"Salad","ro":"Salată"},"ingredients":{"zh":["青木瓜（未熟）400 克，去皮、切极细丝","圣女果 4 颗，对半切","长豇豆 2 根（yardlong）或四季豆 4 根，切 4 厘米段","蒜瓣 2 个，去皮","鸟眼椒 2 颗（或按口味）","棕榈糖 2 汤匙","泰国鱼露 2 汤匙","青柠 1 个的汁","罗望子膏 1 汤匙","干虾米 1 汤匙","烤花生 2 汤匙（部分拍碎、部分保留整粒）","搭配的西生菜或卷心菜叶（可选，传统配法）"],"en":["400 g green (unripe) papaya, peeled and finely julienned","4 cherry tomatoes, halved","2 long beans (yardlong) or 4 green beans, cut into 4 cm lengths","2 garlic cloves, peeled","2 bird's eye chillies (or to taste)","2 tbsp palm sugar","2 tbsp Thai fish sauce","Juice of 1 lime","1 tbsp tamarind concentrate","1 tbsp dried shrimp","2 tbsp roasted peanuts (some crushed, some whole)","Iceberg lettuce or cabbage leaves to serve (optional, traditional)"],"ro":["400 g papaya verde (necoaptă), curățată și tăiată julienne foarte fin","4 roșii cherry, tăiate în jumătăți","2 fasole lungă (yardlong) sau 4 fire de fasole verde, tăiate în bucăți de 4 cm","2 căței de usturoi, curățați","2 ardei iuți bird's eye (sau după gust)","2 linguri zahăr de palmier","2 linguri sos de pește thailandez","Sucul de la 1 lime","1 lingură concentrat de tamarind","1 lingură creveți uscați","2 linguri arahide prăjite (unele zdrobite, altele întregi)","Frunze de salată iceberg sau varză pentru servit (opțional, tradițional)"]},"howIsMade":{"zh":"在陶杵臼（krok）或一只结实的石臼里，把蒜瓣和辣椒一起捣开——不要捣成粉，只要把它们打开就好——再加入棕榈糖，捣几下让它在辣椒油里散开。倒入鱼露、青柠汁和罗望子，用杵搅拌让糖溶化，再放入干虾米，轻捣两下让它们压扁、融进调味汁里。放入长豆和切半的小番茄，轻轻地捣——每样五六下，刚好把它们打软、把汁水带进调料里——在这里，杵是用来调味的，不是用来摧毁的。把擦丝的青木瓜分两次倒入，捣几下、用勺子翻几下、再捣几下，直到每根丝都裹满调味汁但仍然脆，再加入花生（整粒带来口感，碎粒带来厚度），最后再翻一次。尝一下——Som Tam 应该同时打中四种味道：酸、咸、甜、和凶猛的辣——然后盛进浅口碗里或放在生菜叶上，配糯米饭或烤鸡立即享用。","en":"In a clay krok or sturdy stone mortar, pound the garlic and chillies together until bruised — not pulverised, just opened up — then add the palm sugar and pound a few more times to dissolve it into the chilli oil. Pour in the fish sauce, lime juice and tamarind, stir with the pestle until the sugar dissolves, then tip in the dried shrimp and pound a couple of times to flatten them into the dressing. Add the long beans and tomato halves and pound gently — five or six taps each, just enough to bruise them and release their juices into the dressing — the pestle here is a tool of seasoning, not destruction. Tip in the shredded papaya in two batches, alternating light pounding with turning everything with a spoon until each strand is glossy with the dressing but still crisp, then add the peanuts (whole for crunch, crushed for body) and toss one last time. Taste — Som Tam should hit four flavours at once: sour, salty, sweet and chilli-fierce — then pile into shallow bowls or onto lettuce leaves and eat immediately with sticky rice or grilled chicken."}},{"id":212,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":720,"prot":32,"carb":60,"fat":38,"fib":4},"origin":{"zh":"泰国","en":"Thailand","ro":"Thailanda"},"name":{"zh":"清迈金黄咖喱面","en":"Khao Soi","ro":"Khao Soi"},"category":{"zh":"面汤","en":"Noodle soup","ro":"Tăiței în supă"},"ingredients":{"zh":["泰北 khao soi 咖喱酱 4 汤匙（或红咖喱酱 3 汤匙 + 咖喱粉 1 茶匙 + 姜黄粉 1 茶匙）","带骨鸡腿肉 500 克或整鸡腿切块","全脂椰奶 800 毫升","椰浆 200 毫升","鸡高汤 500 毫升","泰国鱼露 2 汤匙","棕榈糖 1 汤匙","鲜鸡蛋面 400 克（或干款 300 克）","炸面用中性油（取一小把面来炸）","上桌时挤入 2 个青柠的汁","配菜：红葱头切片、腌芥菜、新鲜香菜、青柠角、辣椒油"],"en":["4 tbsp Northern Thai khao soi curry paste (or 3 tbsp red curry paste + 1 tsp curry powder + 1 tsp ground turmeric)","500 g bone-in chicken thighs or chicken legs cut into pieces","800 ml full-fat coconut milk","200 ml coconut cream","500 ml chicken stock","2 tbsp Thai fish sauce","1 tbsp palm sugar","400 g fresh egg noodles (or 300 g dried)","Neutral oil for deep-frying a handful of noodles","Juice of 2 limes, added at the table","Garnishes: sliced shallots, pickled mustard greens, fresh coriander, lime wedges, chilli oil"],"ro":["4 linguri pastă de curry Khao Soi din nordul Thailandei (sau 3 linguri pastă curry roșu + 1 linguriță curry pudră + 1 linguriță turmeric)","500 g pulpe de pui cu os sau pulpe întregi tăiate în bucăți","800 ml lapte de cocos gras","200 ml smântână de cocos","500 ml fond de pui","2 linguri sos de pește thailandez","1 lingură zahăr de palmier","400 g tăiței de ouă proaspeți (sau 300 g uscați)","Ulei neutru pentru a prăji o mână de tăiței","Sucul de la 2 lime, adăugat la masă","Garnituri: șalote feliate, frunze de muștar murate, coriandru proaspăt, felii de lime, ulei de chili"]},"howIsMade":{"zh":"在厚锅里中火加热椰浆 4–5 分钟，让油从浆里裂出、浆面发亮，然后加入 khao soi 咖喱酱炒 2–3 分钟，让它颜色变深、释放出深沉而焙烤的香气——比泰国中部的咖喱更厚重、更带土气，因为这款酱是靠干香料堆出来的。下鸡块在酱里翻一翻让每块都裹上酱，倒入椰奶和鸡汤，小火慢慢沸腾，盖子半盖煮 30–35 分钟，直到鸡肉酥软离骨、汤汁微微收浓；靠近收尾时再用鱼露和棕榈糖调味，让汤底醇厚、带温柔的甜，并因咖喱酱本身带一丝若有若无的酸。咖喱炖着的时候，拿一小把鲜面，把多余的水甩掉，下到 180°C 的油锅炸 30–45 秒，让它膨起、变金黄——这就是每一碗顶上那顶酥脆的“皇冠”——然后捞出沥油。把剩下的鸡蛋面在清水里煮到刚刚熟，迅速沥干，分到几只深口碗里，每碗淋上热咖喱汤，至少一块鸡，上面铺炸面。把配菜传到餐桌上——红葱头丝、腌芥菜、香菜、最后挤的青柠角、一勺辣椒油——这道菜活在对比里（丝绸般的汤、底下的软面、上面的酥面、生葱的辛辣咬感、酱菜的酸、青柠的亮），每一碗 khao soi 都是在餐桌上完成的。","en":"Heat the coconut cream in a heavy pot over medium heat for 4–5 minutes until the oil cracks out and the cream looks slick, then stir in the khao soi paste and fry for 2–3 minutes until it darkens and smells deeply toasted — heavier and earthier than central-Thai curries because the paste leans on dry spices. Add the chicken pieces and turn them in the paste until coated, pour in the coconut milk and stock, bring to a gentle simmer and cook with the lid ajar for 30–35 minutes until the chicken is meltingly tender and the broth has reduced a little; season with fish sauce and palm sugar towards the end so the broth is rich, gently sweet and faintly sour from the curry paste itself. While the curry simmers, take a small handful of the fresh egg noodles, shake off any excess water, and deep-fry in 180°C oil for 30–45 seconds until puffed and golden — the crispy crown for every bowl — then drain on paper. Boil the remaining noodles in plain water until just tender, drain quickly and divide between deep bowls, ladle over the hot curry with at least one piece of chicken per portion, and top with the fried noodles. Pass the garnishes round the table — sliced shallots, pickled mustard greens, coriander, a lime wedge to squeeze in last, and a spoon of chilli oil — the dish lives on contrast (silky soup, soft noodles below, crisp on top, raw shallot bite, pickle tang, lime brightness) and each bowl is built at the table."}},{"id":213,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":520,"prot":6,"carb":92,"fat":16,"fib":4},"origin":{"zh":"泰国","en":"Thailand","ro":"Thailanda"},"name":{"zh":"芒果糯米饭 (Khao Niao Mamuang)","en":"Mango Sticky Rice (Khao Niao Mamuang)","ro":"Orez glutinos cu mango (Khao Niao Mamuang)"},"category":{"zh":"甜点","en":"Dessert","ro":"Desert"},"ingredients":{"zh":["泰国糯米 300 克，用冷水浸泡至少 4 小时或过夜","全脂椰奶 400 毫升","棕榈糖 80 克（或浅红糖）","盐 ½ 茶匙","斑斓叶（pandan）1 片，打个结（可选，传统配料）","成熟黄芒果 2 个（Nam Dok Mai 或 Ataulfo 品种），去皮切片","烤芝麻或去壳绿豆 2 汤匙，作装饰","米粉 1 茶匙（可选，用来稠化咸味椰奶顶料）"],"en":["300 g Thai glutinous (sticky) rice, soaked in cold water at least 4 hours or overnight","400 ml full-fat coconut milk","80 g palm sugar (or light brown sugar)","½ tsp salt","1 pandan leaf, tied in a knot (optional, traditional)","2 ripe yellow mangoes (Nam Dok Mai or Ataulfo), peeled and sliced","2 tbsp toasted sesame seeds or split mung beans, for garnish","1 tsp rice flour (optional, for thickening the salty topping)"],"ro":["300 g orez glutinos thailandez (lipicios), pus la înmuiat în apă rece minim 4 ore sau peste noapte","400 ml lapte de cocos gras","80 g zahăr de palmier (sau zahăr brun deschis)","½ linguriță sare","1 frunză de pandan, legată în nod (opțional, tradițional)","2 mango galbene coapte (Nam Dok Mai sau Ataulfo), curățate și feliate","2 linguri semințe de susan prăjite sau mazăre mungo decorticată, pentru garnitură","1 linguriță făină de orez (opțional, pentru a îngroșa topping-ul sărat)"]},"howIsMade":{"zh":"把泡好的糯米沥干。在蒸笼里铺一层纱布或香蕉叶，倒入糯米，盖好在中等火候的水蒸气上蒸 20–25 分钟，蒸到一半时掀起纱布把整堆米翻过来让它均匀受热——米粒呈半透明、有光泽、从外到内都软而有嚼劲时即成。蒸米的同时，把 300 毫升椰奶、棕榈糖、盐和打结的斑斓叶放入小锅加热，只需搅到糖化即可，不要烧开；剩下的 100 毫升留作咸味顶料。米蒸好后趁热倒入宽口碗中，把三分之二的温热甜椰奶用刮刀轻轻拌入，直到每粒发亮，盖好静置 15–20 分钟，让米把椰奶喝进去，膨胀至柔软的珍珠布丁般质感。咸味顶料：把剩下的 100 毫升椰奶、慷慨一撮盐和 1 茶匙米粉小火煮 2 分钟，刚刚开始变稠即可。把热腾腾的椰香糯米堆在盘子上，旁边摆放芒果片，淋上咸椰浆，再撒一把烤香的白芝麻或去壳绿豆，用勺子吃，每一口都带一点糯米和一点芒果——热的椰香甜与凉的果酸利之间那种对照，本身就是这道菜。","en":"Drain the soaked rice; line a steamer basket with cheesecloth or banana leaf, tip in the rice and steam covered over a moderate boil for 20–25 minutes, lifting the cloth halfway to flip the mound so it cooks evenly — done when the grains are translucent, glossy and chewy-tender all the way through. While the rice steams, warm 300 ml of the coconut milk in a small saucepan with the palm sugar, salt and pandan leaf, stirring just enough to dissolve the sugar without bringing it to a boil; reserve the remaining 100 ml for the salty topping. When the rice comes hot off the steamer, tip it into a wide bowl, fold through two-thirds of the warm sweet coconut milk with a spatula until each grain glistens, then cover and rest 15–20 minutes so the rice drinks the milk and swells to a soft pearl-pudding consistency. For the salty topping, simmer the remaining 100 ml coconut milk with a generous pinch of salt and the teaspoon of rice flour for 2 minutes, just until it thickens lightly. Mound the warm coconut rice on a plate with the mango slices alongside, drizzle the salty coconut cream across the top, scatter toasted sesame seeds or split mung beans, and eat with a spoon, a little rice and a little mango in every bite — warm coconut-sweet against cool fruit-sharp is the dish itself."}},{"id":214,"tipType":"meat","pairingsType":"meat","origin":{"zh":"国际","en":"International","ro":"Internațional"},"name":{"zh":"炖羊肉","en":"Lamb Stew","ro":"Tocăniță de miel"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["羊肩肉800克，切块","洋葱2个","胡萝卜3根","土豆3个","大蒜2瓣","番茄酱2汤匙","牛肉高汤500毫升","百里香、月桂叶","盐、胡椒、橄榄油"],"en":["800 g lamb shoulder, cubed","2 onions","3 carrots","3 potatoes","2 garlic cloves","2 tbsp tomato paste","500 ml beef stock","thyme, bay leaf","salt, pepper, olive oil"],"ro":["800 g pulpă de miel, cuburi","2 cepe","3 morcovi","3 cartofi","2 căței usturoi","2 linguri pastă de tomate","500 ml supă de carne","frunze de cimbru, dafin","sare, piper, ulei de măsline"]},"howIsMade":{"zh":"羊肩切成约4厘米见方的肉块——足够大，能在长时间慢炖中保持嫩滑而不散开。彻底擦干水分，撒足量盐与胡椒，再轻轻拍上一层薄面粉，帮助酱汁勾芡。一只厚重的铸铁锅烧热，加薄薄一层油至闪光，分三到四批煎羊肉，不要挤满锅——挤满了肉就变成蒸的，失去深色焦壳。每批盛到盘里。同一锅油中下切得很细的洋葱和蒜，炒到透明，加番茄膏炒约一分钟，直到香味变圆润。把羊肉与其汁水放回锅，倒入热高汤刚好没过，加几枝百里香和一片月桂叶，烧到微沸后转最小火。盖盖炖九十分钟——不要让它沸腾，只要轻微冒泡——中间搅一次。加入斜切的胡萝卜和大块的蜡质土豆，再炖三十到四十分钟，直到羊肉用叉子一碰就散，土豆仍保持形状。试咸淡，捞掉月桂叶。盛入深盘配脆皮面包，先离火静置十分钟让汤汁收拢。","en":"Cut the lamb shoulder into roughly 4 cm cubes — large enough to stay tender through a long simmer without falling apart. Pat them completely dry and season generously with salt and pepper, then dust very lightly with flour to help the sauce thicken. Heat a heavy casserole or Dutch oven with a film of oil until it shimmers, and brown the lamb in three or four batches without crowding the pan — crowding steams the meat and you lose the deep crust. Set each batch aside on a plate. In the same fat, sweat finely chopped onion and garlic until translucent, then stir in tomato paste and let it cook a minute until it smells rounder. Return the lamb with any resting juices, pour in enough hot stock to just cover, add a few sprigs of thyme and a bay leaf, bring to a gentle simmer and lower the heat to the smallest possible. Cover and cook for ninety minutes — never let it boil, only bubble — stirring once. Add carrots cut on the bias and waxy potatoes in large chunks and cook another thirty to forty minutes, until the lamb pulls apart at the touch of a fork and the potatoes hold their shape. Taste, adjust salt, and lift out the bay. Serve in deep bowls with crusty bread, after letting the stew rest off the heat for ten minutes so the broth pulls together."}},{"id":215,"tipType":"salad","pairingsType":"salad","origin":{"zh":"希腊","en":"Greece","ro":"Grecia"},"name":{"zh":"希腊沙拉","en":"Greek Salad","ro":"Salată grecească"},"category":{"zh":"沙拉","en":"Salad","ro":"Salate"},"ingredients":{"zh":["熟番茄4个，切厚片","大黄瓜1根，切片","青椒1个","红洋葱1个，切薄圈","菲达奶酪200克，整块","卡拉马塔橄榄100克","特级初榨橄榄油2汤匙","干希腊牛至1茶匙","粗盐"],"en":["4 ripe tomatoes, thickly sliced","1 large cucumber, sliced","1 green pepper","1 red onion, thinly ringed","200 g block feta","100 g Kalamata olives","2 tbsp extra-virgin olive oil","1 tsp dried Greek oregano","coarse salt"],"ro":["4 roșii coapte, tăiate felii groase","1 castravete mare, tăiat felii","1 ardei verde","1 ceapă roșie, tăiată rondele subțiri","200 g feta în bloc","100 g măsline Kalamata","2 linguri ulei de măsline extravirgin","1 linguriță oregano grecesc uscat","sare grunjoasă"]},"howIsMade":{"zh":"将熟透的番茄切厚——至少手指厚——切成厚片或角块，让汁水留住而不化为泥。黄瓜切半月片、青椒切细圈、红洋葱切到极薄；若洋葱较辣，将洋葱圈浸入冰水十分钟，可缓和辛辣同时保留爽脆。所有食材放入宽而浅的大碗，撒少许粗盐，不要搅拌——希腊人是分层堆放，从不翻动。撒入整颗带核的卡拉马塔橄榄。把整块菲达原封不动地放在最上面，正如克里特小酒馆里端上来的样子。慷慨地淋上特级初榨橄榄油，再将干牛至在掌心间揉搓释香后撒满整盘。立刻配脆皮面包蘸汁端上桌。","en":"Slice ripe tomatoes thick — at least a finger across — into wedges or rounds, so they hold their juice rather than collapse into purée. Cut the cucumber into half-moons, the green pepper into thin rings, and the red onion paper-thin; if sharp, soak the rings in iced water for ten minutes to soften the bite while keeping the crunch. Combine in a wide, shallow bowl with a pinch of coarse salt and resist tossing — Greeks build this salad in layers, never mixed. Scatter the Kalamata olives whole, with their stones. Lay the feta on top as a single uncut slab, exactly as you'd be served in a Cretan taverna. Drizzle generously with extra-virgin olive oil, then shower with dried oregano rubbed between your palms to release the aroma. Serve immediately with crusty bread for mopping the juices."}},{"id":216,"tipType":"salad","pairingsType":"italian","origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"卡普雷塞沙拉","en":"Caprese Salad","ro":"Salată Caprese"},"category":{"zh":"沙拉","en":"Salad","ro":"Salate"},"ingredients":{"zh":["熟番茄3个，切片","水牛奶马苏里拉250克","新鲜罗勒叶","特级初榨橄榄油","粗盐","现磨黑胡椒","巴萨米克醋（可选）"],"en":["3 ripe tomatoes, sliced","250 g buffalo mozzarella","fresh basil leaves","extra-virgin olive oil","coarse salt","freshly ground black pepper","balsamic vinegar (optional)"],"ro":["3 roșii coapte, tăiate felii","250 g mozzarella di bufala","frunze de busuioc proaspăt","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt măcinat","oțet balsamic (opțional)"]},"howIsMade":{"zh":"上桌前至少三十分钟把马苏里拉从冰箱拿出来——冷藏会让奶香消失、味道变平。挑选熟透香气足的番茄——从Cuore di Bue到樱桃番茄都可——只要闻起来像夏天，切成约一厘米厚的圆片。马苏里拉也切成同样厚度的圆片。在大盘子上交替排列番茄片和马苏里拉片成一排，略微重叠，每两片之间夹入一整片新鲜罗勒，让绿色露出来。淋上特级初榨橄榄油，让油在盘底汇成一池，撒上几片海盐花和现磨黑胡椒。立刻常温端上桌，配脆皮面包。正统派绝不加香醋——卡普里沙拉本来就没有，这样最好。","en":"Take the mozzarella out of the fridge at least thirty minutes before serving — fridge-cold it loses its creaminess and the flavour stays flat. Choose ripe, fragrant tomatoes — anything from Cuore di Bue to cherries on the vine, as long as they smell of summer — and slice them about a centimetre thick. Cut the mozzarella into slices of the same thickness. On a large flat plate, alternate one slice of tomato with one of mozzarella in a single, slightly overlapping row, tucking a whole basil leaf between each pair so the green shows. Drizzle with extra-virgin olive oil until it pools at the base, season with a few flakes of sea salt and a turn of freshly cracked black pepper. Serve immediately at room temperature, with crusty bread. Purists refuse balsamic vinegar — Caprese was born without it and works best that way."}},{"id":217,"tipType":"pasta","pairingsType":"italian","origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"千层面","en":"Lasagna","ro":"Lasagna"},"category":{"zh":"意面","en":"Pasta","ro":"Paste"},"ingredients":{"zh":["千层面皮300克","牛肉末500克","洋葱1个","大蒜2瓣","番茄酱400克","贝夏梅酱300毫升","Parmigiano磨碎150克","马苏里拉150克","盐、胡椒、橄榄油"],"en":["300 g lasagna sheets","500 g beef mince","1 onion","2 garlic cloves","400 g tomato sauce","300 ml béchamel sauce","150 g Parmigiano grated","150 g mozzarella","salt, pepper, olive oil"],"ro":["300 g foi de lasagna","500 g vită tocată","1 ceapă","2 căței usturoi","400 g sos de roșii","300 ml sos béchamel","150 g Parmigiano ras","150 g mozzarella","sare, piper, ulei de măsline"]},"howIsMade":{"zh":"先做肉酱：橄榄油和一块黄油中小火慢炒切得极细的洋葱、胡萝卜与西芹十分钟——这就是soffritto，是所有味道的根基。转大火，下牛肉碎，用勺背压散并煎至深褐色。倒入一杯红酒，让其挥发，加入番茄passata、一小撮盐与一点新鲜磨入的肉豆蔻。开口、最小火慢炖至少一小时——有时间的话两小时——偶尔搅拌。同时做béchamel：黄油融化后加面粉，搅一分钟，慢慢倒入温牛奶并不停搅打，直到顺滑浓稠；用盐和少许肉豆蔻调味。烤箱预热180°C。在深烤盘底铺一层薄薄的béchamel防粘连，再按这个顺序铺：面皮、肉酱、béchamel、一层慷慨的Parmigiano。至少叠五层，最上面以béchamel和最后一层Parmigiano收尾。烤35–40分钟，直至表面金黄、边缘冒泡。切之前必须静置十五分钟——否则层就会滑开。","en":"Start with the ragù: gently soften finely chopped onion, carrot and celery in olive oil and a knob of butter for ten minutes — the soffritto is the base of all the flavour. Raise the heat, add the minced beef and brown it deeply, breaking it up with the back of a spoon. Pour in a glass of red wine and let it evaporate, then add the tomato passata, a pinch of salt and a grating of nutmeg. Cook uncovered on the lowest flame for at least one hour — two if you have time — stirring every so often. Meanwhile, make the béchamel: melt butter, whisk in flour, cook a minute, then gradually pour in warm milk while whisking until smooth and thickened; season with salt and a touch of nutmeg. Heat the oven to 180°C. Spoon a thin layer of béchamel into the base of a deep dish to prevent sticking, then layer in this order: pasta sheets, ragù, béchamel, a generous grating of Parmigiano. Repeat for at least five layers, ending with béchamel and a final shower of Parmigiano. Bake 35–40 minutes until the top is golden and the edges bubble. Rest fifteen minutes before cutting — this is non-negotiable, or the layers slide."}},{"id":218,"tipType":"salad","pairingsType":"salad","origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"尼斯沙拉","en":"Salade Niçoise","ro":"Salată Niçoise"},"category":{"zh":"沙拉","en":"Salad","ro":"Salate"},"ingredients":{"zh":["油浸金枪鱼罐头200克","水煮蛋4个","青豆200克","小土豆300克","尼斯橄榄12颗","凤尾鱼柳4条","番茄2个","橄榄油2汤匙","酒醋、盐、胡椒"],"en":["200 g tinned tuna in oil","4 hard-boiled eggs","200 g green beans","300 g new potatoes","12 Niçoise olives","4 anchovy fillets","2 tomatoes","2 tbsp olive oil","wine vinegar, salt, pepper"],"ro":["200 g ton la conservă în ulei","4 ouă fierte tari","200 g fasole verde","300 g cartofi noi","12 măsline Niçoise","4 file de hamsii","2 roșii","2 linguri ulei de măsline","oțet de vin, sare, piper"]},"howIsMade":{"zh":"鸡蛋从冷水开始煮八分钟，立刻投入冰水中止熟化，让蛋黄刚好凝固。新土豆整颗用盐水煮到刀尖能轻松插入，约十五分钟，趁温热对半切开，好吸附调味汁。青豆在大量盐水中焯三分钟，再投入冰水保持脆度与翠绿。在大平盘上铺一层嫩叶，将所有食材分组摆放——切四瓣的鸡蛋、对半土豆、青豆、番茄角、撕开的金枪鱼块、橄榄、鳀鱼片斜放在最上。橄榄油与少许酒醋搅打成乳化汁，调味，临上桌前才淋上。端上时凉而不冰。","en":"Boil the eggs eight minutes from cold, then plunge straight into iced water to stop the cooking and keep the yolk just set. Cook the new potatoes whole in salted water until a knife tip slides in cleanly, around fifteen minutes, then halve them while still warm so they soak up the dressing. Blanch the green beans for three minutes in plenty of boiling salted water, then refresh in iced water so they stay snappy and bright. On a wide, flat plate, lay a bed of greens and arrange everything in groups rather than tossing — quartered eggs, potato halves, beans, tomato wedges, the tuna broken into chunks, olives, anchovy fillets draped across the top. Whisk olive oil with a splash of wine vinegar, season, and spoon over only just before serving. Bring to the table cool, not fridge-cold."}},{"id":219,"tipType":"meat","pairingsType":"meat","origin":{"zh":"俄罗斯","en":"Russia","ro":"Rusia"},"name":{"zh":"俄式酸奶炖牛肉","en":"Beef Stroganoff","ro":"Boeuf Stroganoff"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["牛里脊600克，切条","白蘑菇300克","洋葱1个","大蒜2瓣","酸奶油200毫升","芥末2汤匙","牛肉高汤200毫升","黄油2汤匙","盐、胡椒、欧芹"],"en":["600 g beef tenderloin, sliced into strips","300 g button mushrooms","1 onion","2 garlic cloves","200 ml sour cream","2 tbsp mustard","200 ml beef stock","2 tbsp butter","salt, pepper, parsley"],"ro":["600 g mușchi de vită, tăiat fâșii","300 g ciuperci champignon","1 ceapă","2 căței usturoi","200 ml smântână","2 linguri muștar","200 ml supă de vită","2 linguri unt","sare, piper, pătrunjel"]},"howIsMade":{"zh":"牛里脊横向逆纹切成不超过铅笔粗的细条——切得太厚，在这段短暂的煎制时间里会发硬。彻底擦干水分，撒盐与胡椒，再轻轻沾一层面粉。宽口锅烧得极热，下一块黄油与少许油，分两到三次煎牛肉，不要挤满锅，每面只煎三十秒，至外焦内粉嫩。移到盘中静置。同一锅转小火，用黄油炒切得极细的洋葱，再下蘑菇，让其在头三分钟里不要翻动，自然煎出焦糖色。倒入牛肉高汤与一点白兰地（若有），将锅底所有焦色刮起，收汁至一半。把锅完全离火——这是关键的一步——再拌入酸奶油与芥末搅至顺滑；此刻若沸腾，奶油会分离。把牛肉与流出的肉汁倒回，轻轻翻匀加热，试咸淡，撒上欧芹碎。立即配黄油宽面、土豆泥或蒸米饭上桌。","en":"Cut the beef tenderloin into strips against the grain, no thicker than a pencil — thicker pieces stay tough in the short cook time. Pat them completely dry, season with salt and pepper, then dust lightly with flour. Heat a wide pan very hot, add a knob of butter and oil, and sear the beef in two or three batches without crowding the pan, just thirty seconds a side, until browned outside and still pink within. Lift onto a plate and rest. In the same pan, lower the heat and soften finely sliced onion in butter, then add the mushrooms and let them brown deeply without stirring for the first three minutes. Pour in the beef stock and a splash of brandy if you have it, scrape up every brown bit from the base, and reduce by half. Take the pan completely off the heat — the critical step — and stir in the sour cream and the mustard until smooth; if it boils now, the cream splits. Return the beef and any resting juices to the pan, swirl through to warm, taste for salt, and shower with chopped parsley. Serve immediately over buttered noodles, mash, or steamed rice."}},{"id":222,"tipType":"meat","pairingsType":"meat","origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"红酒炖鸡","en":"Coq au Vin","ro":"Coq au vin"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["整鸡1只，切8块","意式培根或培根200克","白蘑菇250克","珍珠洋葱200克","勃艮第红葡萄酒1瓶","大蒜2瓣","胡萝卜2根","百里香、月桂叶","黄油、面粉、盐、胡椒、欧芹"],"en":["1 whole chicken, cut into 8 pieces","200 g pancetta or bacon","250 g button mushrooms","200 g pearl onions","1 bottle red Burgundy wine","2 garlic cloves","2 carrots","thyme, bay leaf","butter, flour, salt, pepper, parsley"],"ro":["1 pui întreg, tăiat în 8 bucăți","200 g pancetta sau bacon","250 g ciuperci champignon","200 g ceapă mică","1 sticlă vin roșu Burgundia","2 căței usturoi","2 morcovi","cimbru, dafin","unt, făină, sare, piper, pătrunjel"]},"howIsMade":{"zh":"前一晚，将整鸡切成八块，浸入勃艮第红酒中，加入月桂叶、百里香、半颗洋葱和几粒黑胡椒；盖好放冰箱过夜，让红酒渗入肉里，腌料也吸取禽类的香气。第二天，把鸡取出，每块都彻底擦干——湿皮无法上色，这是这道菜的大忌。腌料保留。一只重铸铁锅中，把切丁的pancetta煎至酥脆，盛出；用煎出的油把鸡肉分两批煎到深红木色，先煎皮面。盛出备用。同锅中下切得很细的洋葱、蒜与胡萝卜炒软，撒上一满勺面粉炒一分钟，倒入保留的腌料和一勺浓鸡高汤，把锅底所有焦色刮起。把鸡肉与pancetta放回，转最小火慢炖——或入160°C烤箱——六十分钟，至肉嫩但仍贴着骨头。同时另起两口锅，分别用黄油把珍珠洋葱煎至琥珀色、把蘑菇煎至深褐色——千万不要同锅，否则会互相焖蒸。在最后十五分钟将两者放入主锅，试咸淡，离火后加一小块冷黄油摇匀，撒上欧芹。配马铃薯泥或黄油宽面，把每一滴酱汁都接住。","en":"The night before, joint the chicken into eight pieces and submerge in red Burgundy with bay, thyme, a halved onion and a few peppercorns; cover and refrigerate overnight so the wine penetrates the flesh and the marinade takes on the bird's perfume. Next day, lift the chicken out and pat each piece bone-dry — wet skin will not brown, which is the cardinal sin here. Reserve the marinade. In a heavy cast-iron pot, render diced pancetta until crisp; lift it out and brown the chicken in the rendered fat in two batches, skin-side first, until each piece is mahogany. Set aside. In the same pot, sweat finely chopped onion, garlic and carrot, scatter a heaped spoonful of flour over and stir for a minute, then pour in the reserved marinade and a ladle of dark chicken stock, scraping every brown trace from the bottom. Return the chicken and pancetta, bring to a gentle simmer, cover and cook on the lowest flame — or in a 160°C oven — for sixty minutes, until the meat is tender but still clings to the bone. While it cooks, sauté the pearl onions in butter until amber and the mushrooms in a separate pan until deeply browned — never together, or they steam each other. Slip both into the pot for the last fifteen minutes, taste for salt, finish with a knob of cold butter swirled in off the heat and a shower of parsley. Serve with mashed potato or buttered noodles to catch every drop of sauce."}},{"id":223,"tipType":"meat","pairingsType":"meat","origin":{"zh":"波兰","en":"Poland","ro":"Polonia"},"name":{"zh":"猎人炖菜","en":"Bigos","ro":"Bigos"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["酸菜500克，沥干","新鲜卷心菜300克，切丝","猪肩肉400克，切块","熏肠（kielbasa）200克","培根150克","洋葱1个","大蒜2瓣","干西梅3颗","多香果、月桂叶、辣椒粉、盐、胡椒"],"en":["500 g sauerkraut, drained","300 g fresh cabbage, shredded","400 g pork shoulder, cubed","200 g smoked sausage (kielbasa)","150 g bacon","1 onion","2 garlic cloves","3 dried prunes","allspice, bay leaf, paprika, salt, pepper"],"ro":["500 g varză murată, scurtă","300 g varză proaspătă, tăiată","400 g porc (umăr), cuburi","200 g cârnați afumați (kielbasa)","150 g bacon","1 ceapă","2 căței usturoi","3 prune uscate","ienibahar, dafin, boia, sare, piper"]},"howIsMade":{"zh":"Bigos是层层构筑的——每位波兰厨师都有自己的顺序，但原则只有一个：耐心。在一口厚重的锅中，将切丁的培根中火慢慢出油，待油渗出、肉粒酥脆时盛出备用。猪肩肉切大块，在培根油中分两批煎到每面深金色，不要挤满锅，盛出。同样的油中下切得很细的洋葱与蒜末炒软，把肉与培根都放回。德式酸菜稍稍冲洗（若太酸），与切丝的鲜白菜、切片的kielbasa、去核西梅干、几片月桂叶、用掌心碾碎的几粒杜松子、多香果与甜椒粉一同入锅。加水恰好略没过食材，烧到微沸后转最小火，盖盖焖煮两到三小时，每半小时搅一次并把白菜按入汤汁。最后试咸淡。Bigos诚实的秘密：冷藏过夜，第二天慢慢回温——香味彼此联姻，烟熏味更加深沉，汤汁更加浓郁。","en":"Bigos is built in layers — every cook in Poland has their own order, but the principle is patience. In a heavy pot, render diced bacon over medium heat until the fat runs and the pieces crisp, then lift them out and reserve. Brown the cubed pork shoulder in the bacon fat in two batches without crowding, until each side is deeply golden, and remove. Soften finely chopped onion and garlic in the same fat, then return the meat with the bacon. Drain and rinse the sauerkraut briefly if very sour, and pile it in with the shredded fresh cabbage, the sliced kielbasa, the pitted prunes, a few bay leaves, several juniper berries crushed in the palm, allspice and sweet paprika. Pour in just enough water to barely cover, bring to a gentle simmer, then lower the heat right down, cover, and forget about it for two to three hours, stirring every half hour and pushing the cabbage down into the liquor. Taste and adjust salt at the end. The honest secret of bigos: cool it overnight in the fridge, then warm slowly the next day — the flavours marry, the smoke deepens, the broth concentrates."}},{"id":226,"tipType":"asian","pairingsType":"asian","origin":{"zh":"越南","en":"Vietnam","ro":"Vietnam"},"name":{"zh":"越南春卷","en":"Vietnamese Spring Rolls","ro":"Rulouri vietnameze proaspete"},"category":{"zh":"午餐","en":"Lunch","ro":"Prânz"},"ingredients":{"zh":["米纸（bánh tráng）12张","煮熟去壳虾200克","煮熟切片五花肉200克","煮熟米粉100克","黄瓜1根","生菜叶","新鲜薄荷叶","新鲜香菜叶","海鲜酱或越南鱼露蘸料"],"en":["12 rice paper wrappers (bánh tráng)","200 g cooked prawns, peeled","200 g cooked pork belly, sliced","100 g cooked rice vermicelli","1 cucumber","lettuce leaves","fresh mint leaves","fresh coriander leaves","hoisin or nước chấm sauce for dipping"],"ro":["12 foi de orez (bánh tráng)","200 g creveți fierți, decojiți","200 g piept de porc fiert, feliat","100 g tăiței de orez fierți","1 castravete","frunze de salată","frunze de mentă proaspătă","frunze de coriandru","sos hoisin sau nước chấm pentru servit"]},"howIsMade":{"zh":"卷之前先把所有食材准备好——一旦开始卷，就不能停。米粉按包装煮熟，过冷水至完全凉透，沥干。煮熟的五花肉切薄片；将熟虾纵向对剖，让粉色的一面朝米纸放，更好看。黄瓜切细丝。把香草、去掉根茎的生菜叶、米粉、黄瓜和蛋白质都摆在伸手可及的托盘上。浅碗中放温水——不要热水。米纸在水中只浸五秒钟；放到略湿的厨房巾上时还应是硬的，会在你卷的过程中自己继续变软。把米纸最靠近你的三分之一处放一小片生菜、几片薄荷与香菜、一小撮米粉、黄瓜丝和一片猪肉。把下缘往上盖过馅料，把两侧折进去，在开始最后一卷之前，将两半熟虾粉色面朝下放在米纸上，让它们透过外皮显出来。紧紧卷好封口。卷好的春卷用湿布盖着以免变干，搭配hoisin-花生酱或nước chấm端上桌。","en":"Prep everything before you start rolling — once you begin you can't pause. Cook the rice vermicelli per the packet, rinse under cold water until completely cool, and drain well. Slice the cooked pork belly thinly; have the cooked prawns split lengthwise so the pink side faces the wrapper for presentation. Cut the cucumber into matchsticks. Pile the herbs, lettuce leaves with their stems removed, vermicelli, cucumber and proteins on a tray within easy reach. Fill a shallow bowl with warm — not hot — water. Dip one rice paper for just five seconds; it should still feel firm when you lay it on a slightly damp tea towel, and it will finish softening as you build the roll. On the third closest to you, lay a small lettuce leaf, then a few mint and coriander leaves, a pinch of vermicelli, cucumber matchsticks and a slice of pork. Fold the bottom edge up over the filling, then fold the two sides in, and as you start the final roll lay two prawn halves pink-side-down on the wrapper so they show through the finished roll. Roll tightly to seal. Cover finished rolls with a damp cloth so they don't dry, and serve with hoisin-peanut sauce or nước chấm."}},{"id":227,"tipType":"fish","pairingsType":"seafood","origin":{"zh":"地中海","en":"Mediterranean","ro":"Mediterana"},"name":{"zh":"烤鲷鱼","en":"Grilled Sea Bream","ro":"Dorada la grătar"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["整条鲷鱼2条（每条约500克）","柠檬2个","大蒜4瓣","新鲜莳萝和欧芹","百里香","特级初榨橄榄油","粗盐","现磨黑胡椒"],"en":["2 whole sea bream (about 500 g each)","2 lemons","4 garlic cloves","fresh dill and parsley","thyme","extra-virgin olive oil","coarse salt","freshly ground black pepper"],"ro":["2 dorade întregi (cca 500 g fiecare)","2 lămâi","4 căței usturoi","mărar și pătrunjel proaspăt","cimbru","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt"]},"howIsMade":{"zh":"买到最新鲜的鲷鱼——眼睛清亮，鳃部鲜红，肉质按下后能立刻回弹。如果店家没处理，先去鳞、去内脏，保留头尾。用锋利的刀在两侧鱼皮上各划三道斜口，几乎到骨——让热力均匀渗透，也防止鱼皮在烤架上卷曲。烤前二十分钟，在腹腔与外皮上撒足量盐，让盐有时间渗入肉中并令表皮干燥，便于煎出酥脆色泽。鱼腹塞入柠檬片、拍碎的蒜瓣、莳萝、欧芹和几枝百里香。外皮刷上特级初榨橄榄油。生起一炉旺旺的炭火，每面烤6–8分钟，等鱼自然脱离烤架再翻面——强翻会撕破鱼皮。叉尖能将鱼肉从骨头上轻轻挑起时即熟。离火静置两分钟，再将整条鱼放在木板上端上桌，配额外的柠檬角、一勺新榨橄榄油，旁边搭一盘希腊沙拉。","en":"Buy the freshest sea bream you can find — clear eyes, bright red gills, firm flesh that springs back when pressed. Scale and gut the fish if your fishmonger hasn't, leaving head and tail on. With a sharp knife, score three diagonal slashes through the skin on each side, almost to the bone — they let the heat penetrate evenly and stop the skin from curling on the grill. Salt generously inside the cavity and on the skin, twenty minutes before cooking, so the salt has time to season the flesh and dry the surface for crisp browning. Stuff the belly with lemon slices, smashed garlic cloves, dill, parsley and a few sprigs of thyme. Brush the outside with extra-virgin olive oil. Build a hot charcoal fire and grill 6–8 minutes per side, flipping only when the fish releases cleanly from the grate — force it and the skin tears. The flesh is ready when it lifts off the bone with the tip of a fork. Rest two minutes off the heat, then carry the whole fish to the table on a board with extra lemon wedges, a drizzle of new olive oil, and a Greek salad alongside."}},{"id":228,"tipType":"fish","pairingsType":"seafood","origin":{"zh":"法国","en":"France","ro":"Franța"},"name":{"zh":"普罗旺斯鲈鱼","en":"Sea Bass Provençal","ro":"Lup de mare provensal"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["鲈鱼柳2片（每片约200克）","樱桃番茄400克","黑橄榄12颗","大蒜2瓣","酸豆1汤匙","迷迭香1枝","新鲜百里香","橄榄油、干白葡萄酒","盐、胡椒、罗勒"],"en":["2 sea bass fillets (about 200 g each)","400 g cherry tomatoes","12 black Niçoise olives","2 garlic cloves","1 tbsp capers","1 sprig rosemary","fresh thyme","olive oil, dry white wine","salt, pepper, basil"],"ro":["2 fileuri de lup de mare (cca 200 g fiecare)","400 g roșii cherry","12 măsline negre Niçoise","2 căței usturoi","1 lingură capere","1 ramură rozmarin","cimbru proaspăt","ulei de măsline, vin alb sec","sare, piper, busuioc"]},"howIsMade":{"zh":"先处理鱼：如果用带皮的鱼柳，提前三十分钟从冰箱取出回温，每片都用厨房纸彻底擦干——冷而湿的鱼会受热不均，也无法上色。两面薄薄撒盐，放一旁备用。烤箱预热200°C。一只宽口烤盘里抹上橄榄油，铺上对半切开、切面朝上的樱桃番茄，整颗的尼斯黑橄榄、冲洗过的酸豆、几瓣切薄片的蒜、百里香枝与一枝迷迭香。再淋足量橄榄油，倒入一杯干白葡萄酒，撒盐与现磨黑胡椒。烤十分钟——番茄需要爆开释出汁水、白酒收至一半、大蒜失去辛辣感；这就是承接鱼柳的香气底床。取出烤盘，把鱼柳带皮的一面朝上放进番茄之间，用盘底汁水浇淋鱼身。再烤八到十分钟，至鱼肉变得不透明、叉子尖一拨就开片，皮面出现几处金黄。用刀尖戳入鱼身中心：若毫无阻力，就熟了。静置两分钟，把手撕的罗勒叶撒在上面，连同脆皮面包一起端上桌，蘸普罗旺斯酱汁吃——少了它，半道菜就留在盘里。","en":"Start with the fish: if using skin-on fillets, take them out of the fridge thirty minutes ahead to temper, and pat each piece bone-dry with kitchen paper — cold, wet fish cooks unevenly and won't brown. Salt lightly on both sides and set aside. Heat the oven to 200°C. In a wide oiled dish, lay halved cherry tomatoes cut-side up, whole Niçoise olives, rinsed capers, a few thinly sliced garlic cloves, thyme sprigs and a single sprig of rosemary. Drizzle generously with more olive oil, pour in a glass of dry white wine, season with salt and freshly cracked pepper. Slide into the oven for ten minutes — the tomatoes need to burst and release their juices, the wine reduces by half, and the garlic loses its sharpness; this is how the aromatic bed for the fish is built. Pull the dish out, lay the fillets skin-up among the tomatoes and spoon some of the pan juices over them. Return for eight to ten minutes, until the flesh turns opaque and flakes at the tip of a fork, and the skin takes on a few golden patches. Check the centre with a knife tip: if it slides in without resistance, it is done. Rest two minutes, scatter torn basil leaves on top, and bring the dish to the table with crusty bread to mop the Provençal sauce — without it, half the meal stays in the pan."}},{"id":229,"tipType":"meat","pairingsType":"italian","origin":{"zh":"意大利","en":"Italy","ro":"Italia"},"name":{"zh":"魔鬼烤鸡","en":"Roast Chicken Diavola","ro":"Pui la cuptor alla diavola"},"category":{"zh":"晚餐","en":"Dinner","ro":"Cină"},"ingredients":{"zh":["整鸡1只，剖开压平（spatchcock）","压碎大蒜4瓣","碎辣椒片2汤匙（peperoncino）","烟熏甜椒粉1茶匙","柠檬1个（汁与皮屑）","橄榄油3汤匙","百里香和迷迭香","粗盐、黑胡椒"],"en":["1 whole chicken, spatchcocked","4 garlic cloves, crushed","2 tbsp crushed chilli flakes (peperoncino)","1 tsp smoked paprika","1 lemon (juice and zest)","3 tbsp olive oil","thyme and rosemary","coarse salt, black pepper"],"ro":["1 pui întreg, despicat (spatchcocked)","4 căței usturoi zdrobiți","2 linguri ardei iute zdrobit (peperoncino)","1 linguriță boia afumată","1 lămâie (suc și coajă)","3 linguri ulei de măsline","cimbru și rozmarin","sare grunjoasă, piper negru"]},"howIsMade":{"zh":"若肉贩没有做，自己将整鸡剖开摊平（spatchcock）：将鸡胸朝下放置，用厨房剪刀沿两侧剪掉脊骨，翻面后用力按压胸骨，直到骨头咔嚓一声响，整鸡平铺。在大碗中搅打橄榄油、压碎的蒜瓣、烟熏甜椒粉、粗盐、柠檬汁与皮、以及大胆量的辣椒碎——这是整道菜的灵魂。将腌料均匀涂抹到鸡的两面和每一处皮褶里，至少在室温静置一小时，或加盖冷藏一夜以更深入入味。烤箱预热至220°C，里面放一只厚重的烤盘同时加热，让鸡一放上去就发出滋滋声。将鸡皮朝上放在热烤盘上，再用另一只重锅或裹好锡纸的砖头压在上面——这就是正宗的diavola压具，将鸡皮紧贴热源，达到极致酥脆。烤35–40分钟，直到皮呈深红木色，鸡腿近骨处插入温度计读75°C。盖上锡纸轻松松地静置十分钟，沿关节切开，配额外的柠檬角，将盘底烤汁淋上桌。","en":"Spatchcock the chicken if your butcher hasn't: lay it breast-down, snip out the backbone along both sides with sturdy kitchen shears, flip and press firmly on the breastbone until it cracks and the bird lies flat. In a wide bowl whisk olive oil, crushed garlic, smoked paprika, coarse salt, lemon juice and zest, and a defiant amount of crushed chilli flakes — the dish's whole personality. Rub the marinade into both sides and into every fold of the skin, then leave the bird at least one hour at room temperature, or overnight covered in the fridge for deeper penetration. Heat the oven to 220°C with a heavy roasting tray inside, so the chicken hits a sizzling surface. Lay the chicken skin-up on the hot tray and weigh it down with a second heavy pan or a foil-wrapped brick — the authentic diavola press, which forces the skin into contact with the heat for maximum crispness. Roast 35–40 minutes until the skin is mahogany and a probe in the thigh near the bone reads 75°C. Rest ten minutes loosely tented with foil, carve through the joints, and serve with extra lemon wedges and the pan juices spooned over."}}];export default recipes;